fn builtin_fill(args: &[Value], fill: f64) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Ok(Value::Scalar(fill));
    }
    let dims = fill_dimensions(args, "zeros/ones")?;
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        dims,
        vec![Value::Scalar(fill); rows * cols],
    )?))
}

fn builtin_constant_scalar(
    args: &[Value],
    builtin_name: &str,
    value: Value,
) -> Result<Value, RuntimeError> {
    match args {
        [] => Ok(value),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports only the zero-argument constant form"
        ))),
    }
}

fn builtin_fill_value(
    args: &[Value],
    builtin_name: &str,
    fill: Value,
) -> Result<Value, RuntimeError> {
    let dims = match args {
        [] => return Ok(fill),
        _ => fill_dimensions(args, builtin_name)?,
    };
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        dims,
        vec![fill; rows * cols],
    )?))
}

fn builtin_eye(args: &[Value]) -> Result<Value, RuntimeError> {
    let (rows, cols) = match args {
        [] => return Ok(Value::Scalar(1.0)),
        [size] => {
            match size {
                Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0 => (0, 0),
                Value::Matrix(matrix) => {
                    let dims = matrix
                        .iter()
                        .map(parse_eye_dimension)
                        .collect::<Result<Vec<_>, _>>()?;
                    match dims.as_slice() {
                        [size] => (*size, *size),
                        [rows, cols] => (*rows, *cols),
                        _ => return Err(RuntimeError::Unsupported(
                            "eye currently supports `eye`, `eye(n)`, `eye(n, m)`, or `eye([m n])`"
                                .to_string(),
                        )),
                    }
                }
                _ => {
                    let size = parse_eye_dimension(size)?;
                    (size, size)
                }
            }
        }
        [rows, cols] => (parse_eye_dimension(rows)?, parse_eye_dimension(cols)?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "eye currently supports `eye`, `eye(n)`, `eye(n, m)`, or `eye([m n])`".to_string(),
            ))
        }
    };

    let mut elements = Vec::with_capacity(rows * cols);
    for row in 0..rows {
        for col in 0..cols {
            elements.push(Value::Scalar(if row == col { 1.0 } else { 0.0 }));
        }
    }
    Ok(Value::Matrix(MatrixValue::new(rows, cols, elements)?))
}

fn parse_eye_dimension(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(
            "eye dimensions must be finite integer values".to_string(),
        ));
    }
    Ok(scalar.max(0.0) as usize)
}

fn builtin_logical_fill(args: &[Value], fill: bool) -> Result<Value, RuntimeError> {
    let logical = logical_scalar(fill);
    let dims = match args {
        [] => return Ok(logical),
        _ => fill_dimensions(args, "true/false")?,
    };
    let (rows, cols) = storage_shape_from_dimensions(&dims);

    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        dims,
        vec![logical; rows * cols],
    )?))
}

fn builtin_logical(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "logical currently supports exactly one argument".to_string(),
        ));
    };
    match value {
        Value::Scalar(number) => Ok(logical_scalar(*number != 0.0)),
        Value::Int64(number) => Ok(logical_scalar(*number != 0)),
        Value::UInt64(number) => Ok(logical_scalar(*number != 0)),
        Value::Logical(flag) => Ok(logical_scalar(*flag)),
        Value::Complex(number) => Ok(logical_scalar(number.real != 0.0 || number.imag != 0.0)),
        Value::CharArray(text) if text.is_empty() => build_scalar_matrix_result(0, 0, Vec::new()),
        Value::CharArray(text) => build_scalar_matrix_result(
            1,
            text.chars().count(),
            text.chars().map(|ch| logical_scalar(ch != '\0')).collect(),
        ),
        Value::Matrix(matrix) => build_scalar_matrix_result_with_dimensions(
            matrix.dims.clone(),
            matrix
                .elements()
                .iter()
                .map(|element| logical_value_from_operand(element, "logical"))
                .collect::<Result<Vec<_>, _>>()?,
        ),
        other => Err(RuntimeError::TypeError(format!(
            "logical currently expects numeric, logical, complex, or char array input, found {}",
            other.kind_name()
        ))),
    }
}

fn logical_value_from_operand(value: &Value, builtin_name: &str) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(logical_scalar(*number != 0.0)),
        Value::Int64(number) => Ok(logical_scalar(*number != 0)),
        Value::UInt64(number) => Ok(logical_scalar(*number != 0)),
        Value::Logical(flag) => Ok(logical_scalar(*flag)),
        Value::Complex(number) => Ok(logical_scalar(number.real != 0.0 || number.imag != 0.0)),
        Value::CharArray(text)
            if text
                .chars()
                .nth(1)
                .is_none()
                && text.chars().next().is_some() =>
        {
            Ok(logical_scalar(text.chars().next().expect("single-char guard") != '\0'))
        }
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric, logical, complex, integer, or single-character char matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_double(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "double currently supports exactly one argument".to_string(),
        ));
    };
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Int64(number) => Ok(Value::Scalar(*number as f64)),
        Value::UInt64(number) => Ok(Value::Scalar(*number as f64)),
        Value::Logical(flag) => Ok(Value::Scalar(if *flag { 1.0 } else { 0.0 })),
        Value::Complex(number) => Ok(Value::Complex(number.clone())),
        Value::CharArray(text) if text.is_empty() => build_scalar_matrix_result(0, 0, Vec::new()),
        Value::CharArray(text) => numeric_values_to_row_matrix(
            text.chars().map(|ch| ch as u32 as f64).collect::<Vec<_>>(),
        ),
        Value::Matrix(matrix) => build_scalar_matrix_result_with_dimensions(
            matrix.dims.clone(),
            matrix
                .elements()
                .iter()
                .map(|element| double_value_from_operand(element))
                .collect::<Result<Vec<_>, _>>()?,
        ),
        other => Err(RuntimeError::TypeError(format!(
            "double currently expects numeric, logical, complex, or char array input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_integer_cast(
    args: &[Value],
    class: IntegerClass,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports exactly one argument"
        )));
    };
    match value {
        Value::Scalar(number) => Ok(saturating_integer_value(
            class,
            scalar_to_integer_raw(*number, class),
        )),
        Value::Int64(number) => Ok(saturating_integer_value(class, *number as i128)),
        Value::UInt64(number) => Ok(saturating_integer_value(class, *number as i128)),
        Value::Logical(flag) => Ok(saturating_integer_value(class, if *flag { 1 } else { 0 })),
        Value::Complex(number) if number.imag == 0.0 => Ok(saturating_integer_value(
            class,
            scalar_to_integer_raw(number.real, class),
        )),
        Value::Matrix(matrix) => build_scalar_matrix_result_with_dimensions(
            matrix.dims.clone(),
            matrix
                .elements()
                .iter()
                .map(|element| integer_value_from_operand(element, class, builtin_name))
                .collect::<Result<Vec<_>, _>>()?,
        ),
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric, logical, or integer input, found {}",
            other.kind_name()
        ))),
    }
}

fn double_value_from_operand(value: &Value) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Int64(number) => Ok(Value::Scalar(*number as f64)),
        Value::UInt64(number) => Ok(Value::Scalar(*number as f64)),
        Value::Logical(flag) => Ok(Value::Scalar(if *flag { 1.0 } else { 0.0 })),
        Value::Complex(number) => Ok(Value::Complex(number.clone())),
        Value::CharArray(text)
            if text
                .chars()
                .nth(1)
                .is_none()
                && text.chars().next().is_some() =>
        {
            Ok(Value::Scalar(text.chars().next().expect("single-char guard") as u32 as f64))
        }
        other => Err(RuntimeError::TypeError(format!(
            "double currently expects numeric, logical, complex, integer, or single-character char matrix elements, found {}",
            other.kind_name()
        ))),
    }
}

fn integer_value_from_operand(
    value: &Value,
    class: IntegerClass,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(saturating_integer_value(
            class,
            scalar_to_integer_raw(*number, class),
        )),
        Value::Int64(number) => Ok(saturating_integer_value(class, *number as i128)),
        Value::UInt64(number) => Ok(saturating_integer_value(class, *number as i128)),
        Value::Logical(flag) => Ok(saturating_integer_value(
            class,
            if *flag { 1 } else { 0 },
        )),
        Value::Complex(number) if number.imag == 0.0 => Ok(saturating_integer_value(
            class,
            scalar_to_integer_raw(number.real, class),
        )),
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric, logical, integer, or real-valued complex matrix elements, found {}",
            other.kind_name()
        ))),
    }
}

fn scalar_to_integer_raw(value: f64, class: IntegerClass) -> i128 {
    if value.is_nan() {
        return 0;
    }
    if value.is_infinite() {
        return match (class, value.is_sign_positive()) {
            (IntegerClass::Int64, true) => i64::MAX as i128,
            (IntegerClass::Int64, false) => i64::MIN as i128,
            (IntegerClass::UInt64, true) => u64::MAX as i128,
            (IntegerClass::UInt64, false) => 0,
        };
    }
    let truncated = value.trunc();
    if truncated >= i128::MAX as f64 {
        i128::MAX
    } else if truncated <= i128::MIN as f64 {
        i128::MIN
    } else {
        truncated as i128
    }
}

fn integer_class_bounds(class: IntegerClass) -> (i128, i128) {
    match class {
        IntegerClass::Int64 => (i64::MIN as i128, i64::MAX as i128),
        IntegerClass::UInt64 => (0, u64::MAX as i128),
    }
}

fn clamp_integer_raw(class: IntegerClass, raw: i128) -> i128 {
    let (min, max) = integer_class_bounds(class);
    raw.clamp(min, max)
}

fn saturating_integer_add(class: IntegerClass, lhs: i128, rhs: i128) -> i128 {
    match lhs.checked_add(rhs) {
        Some(raw) => clamp_integer_raw(class, raw),
        None => {
            let (_, max) = integer_class_bounds(class);
            let (min, _) = integer_class_bounds(class);
            if rhs >= 0 {
                max
            } else {
                min
            }
        }
    }
}

fn saturating_integer_mul(class: IntegerClass, lhs: i128, rhs: i128) -> i128 {
    match lhs.checked_mul(rhs) {
        Some(raw) => clamp_integer_raw(class, raw),
        None => {
            let sign_positive = (lhs >= 0 && rhs >= 0) || (lhs < 0 && rhs < 0);
            let (min, max) = integer_class_bounds(class);
            if sign_positive {
                max
            } else {
                min
            }
        }
    }
}

fn builtin_sum(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, selection, missing_flag, outtype) = parse_sum_prod_args(args, "sum")?;
    let char_input = numeric_sum_input_from_char(value)?;
    if char_input.is_some() {
        if matches!(outtype, ReductionOuttype::Native) {
            return Err(RuntimeError::Unsupported(
                "sum does not support outtype \"native\" for char inputs".to_string(),
            ));
        }
    }
    let value = char_input.as_ref().unwrap_or(value);
    if let Some(operand) = integer_operand(value) {
        let result = reduce_integer_value(
            &operand,
            &canonical_size_vector(&value_dimensions(value)),
            &selection,
            "sum",
            |values, class| {
                values.iter().copied().fold(0i128, |total, value| {
                    saturating_integer_add(class, total, value)
                })
            },
            0,
        )?;
        return apply_reduction_outtype(result, value, outtype);
    }
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
    let promote = |result| {
        if let Some(ref reduce_dims) = vecdim_shape_promotion {
            promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
        } else {
            Ok(result)
        }
    };
    let reducer = |values: &[ComplexParts]| {
        complex_reduce_with_missing(
            values,
            missing_flag,
            ComplexParts::zero(),
            complex_parts_sum,
        )
    };
    let result = match selection {
        StatisticSelection::Default => {
            reduce_numeric_or_complex_value(value, "sum", Value::Scalar(0.0), reducer)
        }
        _ => match collapsed_statistic_selection(&selection, mean_default_dimension(value)?) {
            CollapsedStatisticSelection::All => promote(reduce_numeric_or_complex_value_all(
                value,
                "sum",
                Value::Scalar(0.0),
                reducer,
            )?),
            CollapsedStatisticSelection::Dim(dim) => {
                promote(reduce_numeric_or_complex_value_along_dimension(
                    value,
                    "sum",
                    dim,
                    Value::Scalar(0.0),
                    reducer,
                )?)
            }
        },
    }?;
    apply_reduction_outtype(result, value, outtype)
}

