fn builtin_log2(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match output_arity {
        0 | 1 => {
            let [value] = args else {
                return Err(RuntimeError::Unsupported(
                    "log2 currently supports `log2(x)` or `[f, e] = log2(x)`".to_string(),
                ));
            };
            let ln2 = std::f64::consts::LN_2;
            Ok(vec![map_numeric_or_complex_unary(
                value,
                "log2",
                |value| {
                    numeric_or_complex_value(normalize_complex_parts(value.ln().scale(1.0 / ln2)))
                },
            )?])
        }
        2 => {
            let [value] = args else {
                return Err(RuntimeError::Unsupported(
                    "log2 currently supports `log2(x)` or `[f, e] = log2(x)`".to_string(),
                ));
            };
            let operand = real_numeric_operand(value, "log2")?;
            let fractions = operand
                .values
                .iter()
                .map(|&entry| Value::Scalar(log2_fraction_exponent(entry).0))
                .collect::<Vec<_>>();
            let exponents = operand
                .values
                .iter()
                .map(|&entry| Value::Scalar(log2_fraction_exponent(entry).1 as f64))
                .collect::<Vec<_>>();
            Ok(vec![
                build_scalar_matrix_result(operand.rows, operand.cols, fractions)?,
                build_scalar_matrix_result(operand.rows, operand.cols, exponents)?,
            ])
        }
        _ => Err(RuntimeError::Unsupported(
            "log2 currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_pow2(args: &[Value]) -> Result<Value, RuntimeError> {
    match args {
        [value] => {
            let base = ComplexParts {
                real: 2.0,
                imag: 0.0,
            };
            map_numeric_or_complex_unary(value, "pow2", |value| {
                numeric_or_complex_value(normalize_complex_parts(base.pow(value)))
            })
        }
        [value, exponent] => map_real_numeric_binary(value, exponent, "pow2", |value, exponent| {
            value * 2f64.powf(exponent.trunc())
        }),
        _ => Err(RuntimeError::Unsupported(
            "pow2 currently supports `pow2(e)` or `pow2(x, e)`".to_string(),
        )),
    }
}

fn builtin_sind(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "sind currently supports exactly one argument".to_string(),
        ));
    };
    map_numeric_or_complex_unary(value, "sind", |value| {
        let computed = value.scale(std::f64::consts::PI / 180.0).sin();
        let value = if value.imag == 0.0 {
            degree_special_sine(value.real)
                .map(|real| ComplexParts { real, imag: 0.0 })
                .unwrap_or(computed)
        } else {
            computed
        };
        numeric_or_complex_value(normalize_complex_parts(value))
    })
}

