fn builtin_unwrap(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, tolerance, dimension) = parse_unwrap_args(args)?;
    let operand = real_numeric_nd_operand(value, "unwrap")?;
    let dimension =
        dimension.unwrap_or_else(|| default_reduction_dimension_from_dims(&operand.dims));
    if dimension == 0 || dimension > operand.dims.len() {
        return build_scalar_matrix_result_with_dimensions(
            operand.dims,
            operand
                .values
                .into_iter()
                .map(Value::Scalar)
                .collect::<Vec<_>>(),
        );
    }

    let values =
        unwrap_numeric_values_along_dimension(&operand.values, &operand.dims, dimension, tolerance);
    build_scalar_matrix_result_with_dimensions(
        operand.dims,
        values.into_iter().map(Value::Scalar).collect::<Vec<_>>(),
    )
}

