fn parse_unwrap_args(args: &[Value]) -> Result<(&Value, f64, Option<usize>), RuntimeError> {
    match args {
        [value] => Ok((value, std::f64::consts::PI, None)),
        [value, tolerance] => Ok((value, parse_unwrap_tolerance(tolerance)?, None)),
        [value, tolerance, dimension] => Ok((
            value,
            parse_unwrap_tolerance(tolerance)?,
            Some(positive_dimension(dimension, "unwrap")?),
        )),
        _ => Err(RuntimeError::Unsupported(
            "unwrap currently supports unwrap(P), unwrap(P,tol), unwrap(P,[],dim), and unwrap(P,tol,dim)"
                .to_string(),
        )),
    }
}

fn parse_unwrap_tolerance(value: &Value) -> Result<f64, RuntimeError> {
    if is_empty_matrix_placeholder(value) {
        return Ok(std::f64::consts::PI);
    }
    let tolerance = value.as_scalar()?;
    if !tolerance.is_finite() {
        return Err(RuntimeError::TypeError(
            "unwrap currently expects tol to be a finite scalar".to_string(),
        ));
    }
    Ok(tolerance.max(std::f64::consts::PI))
}

fn unwrap_numeric_values_along_dimension(
    input_values: &[f64],
    input_dims: &[usize],
    dimension: usize,
    tolerance: f64,
) -> Vec<f64> {
    if input_values.is_empty() || dimension == 0 || dimension > input_dims.len() {
        return input_values.to_vec();
    }
    let axis = dimension - 1;
    let axis_len = input_dims[axis];
    if axis_len <= 1 {
        return input_values.to_vec();
    }

    let mut output = input_values.to_vec();
    let mut slice_dims = input_dims.to_vec();
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();
    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let sequence = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                input_values[row_major_linear_index(&index, input_dims)]
            })
            .collect::<Vec<_>>();
        let unwrapped = unwrap_phase_values_with_tolerance(sequence, tolerance);
        for (axis_index, value) in unwrapped.into_iter().enumerate() {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            output[offset] = value;
        }
    }
    output
}

