fn builtin_complex(args: &[Value]) -> Result<Value, RuntimeError> {
    match args {
        [real] => map_numeric_or_complex_unary(real, "complex", |value| {
            complex_scalar_value(value.real, value.imag)
        }),
        [real, imag] => {
            let real = numeric_or_complex_operand(real, "complex")?;
            let imag = numeric_or_complex_operand(imag, "complex")?;
            let rows = real.rows.max(imag.rows);
            let cols = real.cols.max(imag.cols);
            let real_matches =
                (real.rows == rows && real.cols == cols) || (real.rows == 1 && real.cols == 1);
            let imag_matches =
                (imag.rows == rows && imag.cols == cols) || (imag.rows == 1 && imag.cols == 1);
            if !real_matches || !imag_matches {
                return Err(RuntimeError::ShapeError(
                    "complex currently expects matching matrix shapes or scalar expansion"
                        .to_string(),
                ));
            }

            let values = (0..rows * cols)
                .map(|offset| {
                    let real_part = real.values[broadcast_offset(&real, rows, cols, offset)];
                    let imag_part = imag.values[broadcast_offset(&imag, rows, cols, offset)];
                    if real_part.imag != 0.0 || imag_part.imag != 0.0 {
                        return Err(RuntimeError::Unsupported(
                            "complex(x, y) currently expects real numeric inputs".to_string(),
                        ));
                    }
                    Ok(complex_scalar_value(real_part.real, imag_part.real))
                })
                .collect::<Result<Vec<_>, _>>()?;

            if rows == 1 && cols == 1 {
                Ok(values.into_iter().next().expect("scalar complex value"))
            } else {
                Ok(Value::Matrix(MatrixValue::new(rows, cols, values)?))
            }
        }
        _ => Err(RuntimeError::Unsupported(
            "complex currently supports `complex(x)` or `complex(x, y)`".to_string(),
        )),
    }
}

