fn builtin_bounds(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "bounds currently supports one or two outputs".to_string(),
        ));
    }

    let (value, selection, missing_flag) = parse_bounds_args(args)?;

    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        _ => coerce_matrix(value)?,
    };
    if !(matrix_is_numeric(&matrix)
        || matrix_is_numeric_or_complex(&matrix)
        || matrix_is_logical(&matrix))
    {
        return Err(RuntimeError::TypeError(
            "bounds currently expects numeric or logical scalar/matrix input".to_string(),
        ));
    }
    if let Some((lower, upper)) = empty_bounds_result(&matrix, &selection) {
        let mut outputs = vec![lower];
        if output_arity == 2 {
            outputs.push(upper);
        }
        return Ok(outputs);
    }

    let logical_output = matrix_is_logical(&matrix);
    let complex_input = matrix_is_numeric_or_complex(&matrix) && !matrix_is_numeric(&matrix);
    let input_dims = canonical_size_vector(&matrix.dims);
    let (mut lower, mut upper) = match selection {
        BoundsSelection::Default => {
            let dim = default_reduction_dimension_from_dims(&input_dims);
            if complex_input {
                if input_dims.len() > 2 {
                    bounds_value_and_range_over_dimensions_complex(&matrix, &[dim], missing_flag)?
                } else {
                    bounds_value_and_range_complex(&matrix, dim, missing_flag)?
                }
            } else if input_dims.len() > 2 {
                bounds_value_and_range_over_dimensions(&matrix, &[dim], missing_flag)?
            } else {
                bounds_value_and_range(&matrix, dim, missing_flag)?
            }
        }
        BoundsSelection::Dim(dim) => {
            if complex_input {
                if input_dims.len() > 2 || dim > 2 {
                    bounds_value_and_range_over_dimensions_complex(&matrix, &[dim], missing_flag)?
                } else {
                    bounds_value_and_range_complex(&matrix, dim, missing_flag)?
                }
            } else if input_dims.len() > 2 || dim > 2 {
                bounds_value_and_range_over_dimensions(&matrix, &[dim], missing_flag)?
            } else {
                bounds_value_and_range(&matrix, dim, missing_flag)?
            }
        }
        BoundsSelection::All => {
            let operating_dims = (1..=input_dims.len()).collect::<Vec<_>>();
            if complex_input {
                bounds_value_and_range_over_dimensions_complex(
                    &matrix,
                    &operating_dims,
                    missing_flag,
                )?
            } else {
                bounds_value_and_range_over_dimensions(&matrix, &operating_dims, missing_flag)?
            }
        }
        BoundsSelection::VecDim(dims) => {
            if complex_input {
                bounds_value_and_range_over_dimensions_complex(&matrix, &dims, missing_flag)?
            } else {
                bounds_value_and_range_over_dimensions(&matrix, &dims, missing_flag)?
            }
        }
    };
    if logical_output {
        lower = logicalize_numeric_result(lower)?;
        upper = logicalize_numeric_result(upper)?;
    }
    let mut outputs = vec![lower];
    if output_arity == 2 {
        outputs.push(upper);
    }
    Ok(outputs)
}

fn logicalize_numeric_result(value: Value) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Logical(number != 0.0)),
        Value::Matrix(matrix) => Ok(Value::Matrix(MatrixValue::with_dimensions(
            matrix.rows,
            matrix.cols,
            matrix.dims.clone(),
            matrix
                .iter()
                .map(|element| Ok(Value::Logical(element.as_scalar()? != 0.0)))
                .collect::<Result<Vec<_>, RuntimeError>>()?,
        )?)),
        other => Ok(other),
    }
}

enum BoundsSelection {
    Default,
    Dim(usize),
    All,
    VecDim(Vec<usize>),
}

#[derive(Clone, Copy)]
enum BoundsMissingFlag {
    OmitNan,
    IncludeNan,
}

fn parse_bounds_args(
    args: &[Value],
) -> Result<(&Value, BoundsSelection, BoundsMissingFlag), RuntimeError> {
    match args {
        [value] => Ok((value, BoundsSelection::Default, BoundsMissingFlag::OmitNan)),
        [value, option] => {
            if let Ok(missing_flag) = parse_bounds_missing_flag(option) {
                Ok((value, BoundsSelection::Default, missing_flag))
            } else {
                Ok((value, parse_bounds_selection(option)?, BoundsMissingFlag::OmitNan))
            }
        }
        [value, selection, missing_flag] => Ok((
            value,
            parse_bounds_selection(selection)?,
            parse_bounds_missing_flag(missing_flag)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "bounds currently supports `bounds(a)`, `bounds(a, missingflag)`, `bounds(a, \"all\")`, `bounds(a, dim)`, `bounds(a, vecdim)`, and `bounds(___, missingflag)`".to_string(),
        )),
    }
}

fn parse_bounds_selection(value: &Value) -> Result<BoundsSelection, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("all") => {
            Ok(BoundsSelection::All)
        }
        _ => {
            let dims = meshgrid_vector(value)?
                .into_iter()
                .map(|dimension| {
                    if !dimension.is_finite() || dimension < 1.0 || dimension.fract() != 0.0 {
                        return Err(RuntimeError::TypeError(
                            "bounds currently expects dimensions to be positive integers"
                                .to_string(),
                        ));
                    }
                    Ok(dimension as usize)
                })
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            if dims.is_empty() {
                return Err(RuntimeError::TypeError(
                    "bounds currently expects a nonempty dimension selector".to_string(),
                ));
            }
            if dims.len() == 1 {
                return Ok(BoundsSelection::Dim(dims[0]));
            }
            let mut dims = dims;
            dims.sort_unstable();
            dims.dedup();
            Ok(BoundsSelection::VecDim(dims))
        }
    }
}

fn parse_bounds_missing_flag(value: &Value) -> Result<BoundsMissingFlag, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "omitnan" | "omitmissing" => Ok(BoundsMissingFlag::OmitNan),
        "includenan" | "includemissing" => Ok(BoundsMissingFlag::IncludeNan),
        other => Err(RuntimeError::Unsupported(format!(
            "bounds missingflag `{other}` is not implemented; expected omitnan/omitmissing or includenan/includemissing"
        ))),
    }
}

fn empty_bounds_result(
    matrix: &MatrixValue,
    selection: &BoundsSelection,
) -> Option<(Value, Value)> {
    let dims = canonical_size_vector(&matrix.dims);
    let operating_dims = match selection {
        BoundsSelection::Default => vec![if matrix.rows == 1 && matrix.cols > 1 {
            2
        } else {
            1
        }],
        BoundsSelection::Dim(dim) => vec![*dim],
        BoundsSelection::All => (1..=dims.len()).collect(),
        BoundsSelection::VecDim(dims) => dims.clone(),
    };

    if operating_dims
        .iter()
        .any(|&dim| dimension_length(&dims, dim) == 0)
    {
        let value = Value::Matrix(matrix.clone());
        Some((value.clone(), value))
    } else {
        None
    }
}

fn builtin_maxk(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    builtin_topk(args, output_arity, "maxk", true)
}

fn builtin_mink(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    builtin_topk(args, output_arity, "mink", false)
}

fn builtin_topk(
    args: &[Value],
    output_arity: usize,
    builtin_name: &str,
    descending: bool,
) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports one or two outputs"
        )));
    }

    let (value, count, requested_dim, comparison_method) = match args {
        [value, count] => (value, count, None, ComparisonMethod::Auto),
        [value, count, dim] => (
            value,
            count,
            Some(positive_dimension(dim, builtin_name)?),
            ComparisonMethod::Auto,
        ),
        [value, count, option, method]
            if matches!(option, Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("ComparisonMethod")) =>
        {
            (value, count, None, parse_comparison_method(method, builtin_name)?)
        }
        [value, count, dim, option, method]
            if matches!(option, Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("ComparisonMethod")) =>
        {
            (
                value,
                count,
                Some(positive_dimension(dim, builtin_name)?),
                parse_comparison_method(method, builtin_name)?,
            )
        }
        _ => {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports `{builtin_name}(a, k)`, `{builtin_name}(a, k, dim)`, and those forms with trailing `'ComparisonMethod', method`"
            )))
        }
    };

    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        _ => coerce_matrix(value)?,
    };
    if !(matrix_is_numeric_or_complex(&matrix)
        || matrix_is_logical(&matrix)
        || integer_operand(value).is_some())
    {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric, logical, complex, or integer scalar/matrix input"
        )));
    }
    let count =
        nonnegative_integer_scalar_with_label(count, builtin_name, "a nonnegative integer k")?;
    let input_dims = canonical_size_vector(&matrix.dims);
    let dim = requested_dim.unwrap_or_else(|| {
        input_dims
            .iter()
            .position(|&extent| extent != 1)
            .map(|index| index + 1)
            .unwrap_or(1)
    });
    let length_along_dim = dimension_length(&input_dims, dim);
    let count = count.min(length_along_dim);

    let integer_class = integer_class_from_reduction_value(value);
    let (mut values, indices) =
        topk_value_and_indices(&matrix, count, dim, descending, comparison_method)?;
    if let Some(class) = integer_class {
        values = integerize_output_value(values, class)?;
    }
    let mut outputs = vec![values];
    if output_arity == 2 {
        outputs.push(indices);
    }
    Ok(outputs)
}

fn builtin_extreme(
    args: &[Value],
    output_arity: usize,
    name: &str,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<Vec<Value>, RuntimeError> {
    match parse_extreme_args(args, name)? {
        ExtremeArgs::Reduction {
            value,
            selection,
            index_mode,
        } => {
            let input_dims = canonical_size_vector(&value_dimensions(value));
            let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
            let promote = |result| {
                if let Some(ref reduce_dims) = vecdim_shape_promotion {
                    promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
                } else {
                    Ok(result)
                }
            };
            if let Some(outputs) = extreme_empty_reduction_outputs(value, &selection, output_arity)?
            {
                return Ok(outputs);
            }
            match selection {
                StatisticSelection::Default => {
                    let (extreme_value, index_value) =
                        extreme_value_and_index(value, name, prefer_candidate)?;
                    match output_arity {
                        0 | 1 => Ok(vec![promote(extreme_value)?]),
                        2 => Ok(vec![promote(extreme_value)?, promote(index_value)?]),
                        _ => Err(RuntimeError::Unsupported(format!(
                            "{name} currently supports one or two outputs"
                        ))),
                    }
                }
                _ => {
                    match collapsed_statistic_selection(
                        &selection,
                        variance_default_dimension(value, name)?,
                    ) {
                        CollapsedStatisticSelection::All => {
                            if output_arity > 1 && index_mode != ExtremeIndexMode::Linear {
                                return Err(RuntimeError::Unsupported(format!(
                                    "{name} currently supports `[],'all'` and `[],vecdim` with two outputs only when the trailing index mode is \"linear\""
                                )));
                            }
                            let extreme_value = extreme_value_all(value, name, prefer_candidate)?;
                            if output_arity == 2 {
                                Ok(vec![
                                    promote(extreme_value)?,
                                    promote(extreme_linear_index_all(
                                        value,
                                        name,
                                        prefer_candidate,
                                    )?)?,
                                ])
                            } else {
                                Ok(vec![promote(extreme_value)?])
                            }
                        }
                        CollapsedStatisticSelection::Dim(dim) => {
                            let (extreme_value, index_value) =
                                if index_mode == ExtremeIndexMode::Linear {
                                    extreme_value_and_linear_index_along_dimension(
                                        value,
                                        name,
                                        dim,
                                        prefer_candidate,
                                    )?
                                } else {
                                    extreme_value_and_index_along_dimension(
                                        value,
                                        name,
                                        dim,
                                        prefer_candidate,
                                    )?
                                };
                            match output_arity {
                                0 | 1 => Ok(vec![promote(extreme_value)?]),
                                2 => Ok(vec![promote(extreme_value)?, promote(index_value)?]),
                                _ => Err(RuntimeError::Unsupported(format!(
                                    "{name} currently supports one or two outputs"
                                ))),
                            }
                        }
                    }
                }
            }
        }
        ExtremeArgs::Elementwise { lhs, rhs } => {
            if output_arity > 1 {
                return Err(RuntimeError::Unsupported(format!(
                    "{name} currently supports only one output for `{name}(a, b)`"
                )));
            }
            Ok(vec![map_real_numeric_binary_with_output(
                lhs,
                rhs,
                name,
                value_is_logical_like(lhs) && value_is_logical_like(rhs),
                |lhs, rhs| {
                    if prefer_candidate(lhs, rhs) {
                        lhs
                    } else {
                        rhs
                    }
                },
            )?])
        }
    }
}

fn split_trailing_comparison_method<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a [Value], ComparisonMethod), RuntimeError> {
    if args.len() >= 2
        && matches!(
            &args[args.len() - 2],
            Value::CharArray(text) | Value::String(text)
                if text.eq_ignore_ascii_case("ComparisonMethod")
        )
    {
        return Ok((
            &args[..args.len() - 2],
            parse_comparison_method(&args[args.len() - 1], builtin_name)?,
        ));
    }
    Ok((args, ComparisonMethod::Auto))
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ExtremeMissingFlag {
    OmitNan,
    IncludeNan,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum CumulativeDirection {
    Forward,
    Reverse,
}

fn parse_extreme_missing_flag(
    value: &Value,
    builtin_name: &str,
) -> Result<ExtremeMissingFlag, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "omitnan" | "omitmissing" => Ok(ExtremeMissingFlag::OmitNan),
        "includenan" | "includemissing" => Ok(ExtremeMissingFlag::IncludeNan),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} missingflag `{other}` is not implemented; expected omitnan/omitmissing or includenan/includemissing"
        ))),
    }
}

fn parse_cumulative_direction(
    value: &Value,
    builtin_name: &str,
) -> Result<CumulativeDirection, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "forward" => Ok(CumulativeDirection::Forward),
        "reverse" => Ok(CumulativeDirection::Reverse),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} direction `{other}` is not implemented; expected forward or reverse"
        ))),
    }
}

fn split_trailing_extreme_options<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a [Value], ComparisonMethod, Option<ExtremeMissingFlag>), RuntimeError> {
    let mut core_args = args;
    let mut comparison_method = ComparisonMethod::Auto;
    let mut missing_flag = None;

    loop {
        if comparison_method == ComparisonMethod::Auto
            && core_args.len() >= 2
            && matches!(
                &core_args[core_args.len() - 2],
                Value::CharArray(text) | Value::String(text)
                    if text.eq_ignore_ascii_case("ComparisonMethod")
            )
        {
            comparison_method =
                parse_comparison_method(&core_args[core_args.len() - 1], builtin_name)?;
            core_args = &core_args[..core_args.len() - 2];
            continue;
        }
        if missing_flag.is_none() && !core_args.is_empty() {
            if let Ok(parsed_missing) =
                parse_extreme_missing_flag(&core_args[core_args.len() - 1], builtin_name)
            {
                missing_flag = Some(parsed_missing);
                core_args = &core_args[..core_args.len() - 1];
                continue;
            }
        }
        break;
    }

    Ok((core_args, comparison_method, missing_flag))
}

fn comparison_prefers_candidate(
    candidate: ComplexParts,
    best: ComplexParts,
    prefer_max: bool,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> bool {
    compare_sorted_complex_values(
        candidate,
        best,
        prefer_max,
        SortMissingPlacement::Auto,
        comparison_method,
        auto_complex,
    ) == std::cmp::Ordering::Less
}

fn builtin_extreme_by_comparison(
    args: &[Value],
    output_arity: usize,
    name: &str,
    comparison_method: ComparisonMethod,
    prefer_max: bool,
) -> Result<Vec<Value>, RuntimeError> {
    let auto_complex = args.iter().any(value_contains_complex_entries);
    let integer_class = match parse_extreme_args(args, name)? {
        ExtremeArgs::Reduction { value, .. } => integer_class_from_reduction_value(value),
        ExtremeArgs::Elementwise { lhs, rhs } => match (integer_operand(lhs), integer_operand(rhs))
        {
            (Some(lhs_operand), Some(rhs_operand)) if lhs_operand.class == rhs_operand.class => {
                Some(lhs_operand.class)
            }
            _ => None,
        },
    };
    if !auto_complex && comparison_method != ComparisonMethod::Abs {
        let mut outputs = builtin_extreme(args, output_arity, name, move |candidate, best| {
            if prefer_max {
                candidate > best
            } else {
                candidate < best
            }
        })?;
        if let Some(class) = integer_class {
            let first = outputs.remove(0);
            outputs.insert(0, integerize_output_value(first, class)?);
        }
        return Ok(outputs);
    }
    let prefer_candidate = |candidate: ComplexParts, best: ComplexParts| {
        comparison_prefers_candidate(candidate, best, prefer_max, comparison_method, auto_complex)
    };
    let logical_output = matches!(parse_extreme_args(args, name)?, ExtremeArgs::Reduction { value, .. } if value_is_logical_like(value))
        || matches!(parse_extreme_args(args, name)?, ExtremeArgs::Elementwise { lhs, rhs } if value_is_logical_like(lhs) && value_is_logical_like(rhs));
    let mut outputs = builtin_extreme_complex(args, output_arity, name, prefer_candidate)?;
    if logical_output {
        outputs = outputs
            .into_iter()
            .enumerate()
            .map(|(index, value)| {
                if index == 0 {
                    logicalize_numeric_result(value)
                } else {
                    Ok(value)
                }
            })
            .collect::<Result<Vec<_>, RuntimeError>>()?;
    }
    if let Some(class) = integer_class {
        let first = outputs.remove(0);
        outputs.insert(0, integerize_output_value(first, class)?);
    }
    Ok(outputs)
}

fn nan_extreme_prefers_candidate_real(candidate: f64, best: f64, prefer_max: bool) -> bool {
    if candidate.is_nan() {
        return false;
    }
    if best.is_nan() {
        return true;
    }
    if prefer_max {
        candidate > best
    } else {
        candidate < best
    }
}

fn nan_extreme_prefers_candidate_complex(
    candidate: ComplexParts,
    best: ComplexParts,
    prefer_max: bool,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> bool {
    if candidate.is_nan() {
        return false;
    }
    if best.is_nan() {
        return true;
    }
    comparison_prefers_candidate(candidate, best, prefer_max, comparison_method, auto_complex)
}

fn builtin_nan_extreme_by_comparison(
    args: &[Value],
    output_arity: usize,
    name: &str,
    comparison_method: ComparisonMethod,
    prefer_max: bool,
) -> Result<Vec<Value>, RuntimeError> {
    let auto_complex = args.iter().any(value_contains_complex_entries);
    let integer_class = match parse_extreme_args(args, name)? {
        ExtremeArgs::Reduction { value, .. } => integer_class_from_reduction_value(value),
        ExtremeArgs::Elementwise { lhs, rhs } => match (integer_operand(lhs), integer_operand(rhs))
        {
            (Some(lhs_operand), Some(rhs_operand)) if lhs_operand.class == rhs_operand.class => {
                Some(lhs_operand.class)
            }
            _ => None,
        },
    };
    if !auto_complex && comparison_method != ComparisonMethod::Abs {
        let mut outputs = builtin_extreme(args, output_arity, name, move |candidate, best| {
            nan_extreme_prefers_candidate_real(candidate, best, prefer_max)
        })?;
        if let Some(class) = integer_class {
            let first = outputs.remove(0);
            outputs.insert(0, integerize_output_value(first, class)?);
        }
        return Ok(outputs);
    }
    let prefer_candidate = |candidate: ComplexParts, best: ComplexParts| {
        nan_extreme_prefers_candidate_complex(
            candidate,
            best,
            prefer_max,
            comparison_method,
            auto_complex,
        )
    };
    let logical_output = matches!(parse_extreme_args(args, name)?, ExtremeArgs::Reduction { value, .. } if value_is_logical_like(value))
        || matches!(parse_extreme_args(args, name)?, ExtremeArgs::Elementwise { lhs, rhs } if value_is_logical_like(lhs) && value_is_logical_like(rhs));
    let mut outputs = builtin_extreme_complex(args, output_arity, name, prefer_candidate)?;
    if logical_output {
        outputs = outputs
            .into_iter()
            .enumerate()
            .map(|(index, value)| {
                if index == 0 {
                    logicalize_numeric_result(value)
                } else {
                    Ok(value)
                }
            })
            .collect::<Result<Vec<_>, RuntimeError>>()?;
    }
    if let Some(class) = integer_class {
        let first = outputs.remove(0);
        outputs.insert(0, integerize_output_value(first, class)?);
    }
    Ok(outputs)
}

fn builtin_extreme_complex(
    args: &[Value],
    output_arity: usize,
    name: &str,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<Vec<Value>, RuntimeError> {
    match parse_extreme_args(args, name)? {
        ExtremeArgs::Reduction {
            value,
            selection,
            index_mode,
        } => {
            let input_dims = canonical_size_vector(&value_dimensions(value));
            let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
            let promote = |result| {
                if let Some(ref reduce_dims) = vecdim_shape_promotion {
                    promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
                } else {
                    Ok(result)
                }
            };
            if let Some(outputs) = extreme_empty_reduction_outputs(value, &selection, output_arity)?
            {
                return Ok(outputs);
            }
            match selection {
                StatisticSelection::Default => {
                    let (extreme_value, index_value) =
                        extreme_value_and_index_complex(value, name, prefer_candidate)?;
                    match output_arity {
                        0 | 1 => Ok(vec![promote(extreme_value)?]),
                        2 => Ok(vec![promote(extreme_value)?, promote(index_value)?]),
                        _ => Err(RuntimeError::Unsupported(format!(
                            "{name} currently supports one or two outputs"
                        ))),
                    }
                }
                _ => match collapsed_statistic_selection(
                    &selection,
                    variance_default_dimension(value, name)?,
                ) {
                    CollapsedStatisticSelection::All => {
                        if output_arity > 1 && index_mode != ExtremeIndexMode::Linear {
                            return Err(RuntimeError::Unsupported(format!(
                                "{name} currently supports `[],'all'` and `[],vecdim` with two outputs only when the trailing index mode is \"linear\""
                            )));
                        }
                        let extreme_value =
                            extreme_value_all_complex(value, name, prefer_candidate)?;
                        if output_arity == 2 {
                            Ok(vec![
                                promote(extreme_value)?,
                                promote(extreme_linear_index_all_complex(
                                    value,
                                    name,
                                    prefer_candidate,
                                )?)?,
                            ])
                        } else {
                            Ok(vec![promote(extreme_value)?])
                        }
                    }
                    CollapsedStatisticSelection::Dim(dim) => {
                        let (extreme_value, index_value) = if index_mode == ExtremeIndexMode::Linear
                        {
                            extreme_value_and_linear_index_along_dimension_complex(
                                value,
                                name,
                                dim,
                                prefer_candidate,
                            )?
                        } else {
                            extreme_value_and_index_along_dimension_complex(
                                value,
                                name,
                                dim,
                                prefer_candidate,
                            )?
                        };
                        match output_arity {
                            0 | 1 => Ok(vec![promote(extreme_value)?]),
                            2 => Ok(vec![promote(extreme_value)?, promote(index_value)?]),
                            _ => Err(RuntimeError::Unsupported(format!(
                                "{name} currently supports one or two outputs"
                            ))),
                        }
                    }
                },
            }
        }
        ExtremeArgs::Elementwise { lhs, rhs } => {
            if output_arity > 1 {
                return Err(RuntimeError::Unsupported(format!(
                    "{name} currently supports only one output for `{name}(a, b)`"
                )));
            }
            Ok(vec![map_numeric_or_complex_binary(
                lhs,
                rhs,
                name,
                |lhs, rhs| {
                    if prefer_candidate(lhs, rhs) {
                        lhs
                    } else {
                        rhs
                    }
                },
            )?])
        }
    }
}

fn extreme_empty_reduction_outputs(
    value: &Value,
    selection: &StatisticSelection,
    output_arity: usize,
) -> Result<Option<Vec<Value>>, RuntimeError> {
    let Value::Matrix(matrix) = value else {
        return Ok(None);
    };
    if matrix.rows != 0 && matrix.cols != 0 {
        return Ok(None);
    }

    let input_dims = canonical_size_vector(matrix.dims());
    let default_dim = if matrix.rows != 1 {
        1
    } else if matrix.cols != 1 {
        2
    } else {
        1
    };
    let output_dims = extreme_empty_output_dims(&input_dims, selection, default_dim);
    let value_output = empty_numeric_matrix_with_dimensions(output_dims.clone())?;
    if output_arity == 2 {
        Ok(Some(vec![
            value_output,
            empty_numeric_matrix_with_dimensions(output_dims)?,
        ]))
    } else {
        Ok(Some(vec![value_output]))
    }
}

fn extreme_empty_output_dims(
    input_dims: &[usize],
    selection: &StatisticSelection,
    default_dim: usize,
) -> Vec<usize> {
    let mut dims = canonical_size_vector(input_dims);
    match selection {
        StatisticSelection::Default => {
            if dimension_length(&dims, default_dim) == 0 {
                dims
            } else {
                set_dimension_length(&mut dims, default_dim, 1);
                dims
            }
        }
        StatisticSelection::Dim(dim) => {
            if dimension_length(&dims, *dim) == 0 {
                dims
            } else {
                set_dimension_length(&mut dims, *dim, 1);
                dims
            }
        }
        StatisticSelection::All => dims,
        StatisticSelection::VecDim(vecdim) => {
            if vecdim.iter().any(|&dim| dimension_length(&dims, dim) == 0) {
                dims
            } else {
                for &dim in vecdim {
                    set_dimension_length(&mut dims, dim, 1);
                }
                dims
            }
        }
    }
}

fn set_dimension_length(dims: &mut Vec<usize>, dim: usize, length: usize) {
    while dims.len() < dim {
        dims.push(1);
    }
    dims[dim - 1] = length;
}

fn empty_numeric_matrix_with_dimensions(dims: Vec<usize>) -> Result<Value, RuntimeError> {
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        dims,
        Vec::new(),
    )?))
}

fn builtin_mean(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, selection, missing_flag, outtype) = parse_mean_args(args)?;
    let original_value = value;
    let mean_input = numeric_mean_input_value(value, outtype)?;
    let value = mean_input.as_ref().unwrap_or(value);
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
    let promote = |result| {
        if let Some(ref reduce_dims) = vecdim_shape_promotion {
            promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
        } else {
            Ok(result)
        }
    };
    let reducer = |values: &[ComplexParts]| {
        complex_reduce_with_missing(
            values,
            missing_flag,
            ComplexParts {
                real: f64::NAN,
                imag: 0.0,
            },
            complex_parts_mean,
        )
    };
    let result = match collapsed_statistic_selection(&selection, mean_default_dimension(value)?) {
        CollapsedStatisticSelection::All => promote(reduce_numeric_or_complex_value_all(
            value,
            "mean",
            Value::Scalar(f64::NAN),
            reducer,
        )?),
        CollapsedStatisticSelection::Dim(dim) => {
            promote(reduce_numeric_or_complex_value_along_dimension(
                value,
                "mean",
                dim,
                Value::Scalar(f64::NAN),
                reducer,
            )?)
        }
    }?;
    apply_mean_outtype(result, original_value, outtype)
}

fn builtin_mean2(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "mean2 currently supports exactly one input argument".to_string(),
        ));
    };
    numeric_operand(value, "mean2")?;
    builtin_mean(&[value.clone(), Value::String("all".to_string())])
}

fn builtin_median(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, selection, missing_flag) =
        parse_statistic_selection_with_missing_args(args, "median")?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
    let promote = |result| {
        if let Some(ref reduce_dims) = vecdim_shape_promotion {
            promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
        } else {
            Ok(result)
        }
    };
    let reducer = |values: &[f64]| {
        numeric_reduce_with_missing(values, missing_flag, f64::NAN, median_of_values)
    };
    match selection {
        StatisticSelection::Default => {
            reduce_numeric_value(value, "median", Value::Scalar(f64::NAN), reducer)
        }
        _ => match collapsed_statistic_selection(
            &selection,
            variance_default_dimension(value, "median")?,
        ) {
            CollapsedStatisticSelection::All => promote(reduce_numeric_value_all(
                value,
                "median",
                Value::Scalar(f64::NAN),
                reducer,
            )?),
            CollapsedStatisticSelection::Dim(dim) => promote(reduce_numeric_value_along_dimension(
                value,
                "median",
                dim,
                Value::Scalar(f64::NAN),
                reducer,
            )?),
        },
    }
}

fn builtin_mode(args: &[Value]) -> Result<Value, RuntimeError> {
    first_output_or_error(builtin_mode_outputs(args, 1)?)
}

#[derive(Debug, Clone)]
struct ModeSummary {
    mode: f64,
    frequency: f64,
    ties: Vec<f64>,
}

fn builtin_mode_outputs(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "mode currently supports one, two, or three outputs".to_string(),
        ));
    }
    let (value, selection) = parse_sum_like_args(args, "mode")?;
    let operand = numeric_operand(value, "mode")?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
    let promote = |result| {
        if let Some(ref reduce_dims) = vecdim_shape_promotion {
            promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
        } else {
            Ok(result)
        }
    };
    let (output_dims, summaries) = mode_summaries_for_selection(
        &operand.values,
        &input_dims,
        &selection,
        variance_default_dimension(value, "mode")?,
    )?;
    let mode_values = summaries
        .iter()
        .map(|summary| Value::Scalar(summary.mode))
        .collect::<Vec<_>>();
    let freq_values = summaries
        .iter()
        .map(|summary| Value::Scalar(summary.frequency))
        .collect::<Vec<_>>();
    let cell_values = summaries
        .iter()
        .map(|summary| mode_preserve_input_type(mode_tie_cell_value(&summary.ties)?, value))
        .collect::<Result<Vec<_>, _>>()?;

    let mode_output = mode_preserve_input_type(
        build_scalar_matrix_result_with_dimensions(output_dims.clone(), mode_values)?,
        value,
    )?;
    let mut outputs = vec![promote(mode_output)?];
    if output_arity >= 2 {
        outputs.push(promote(build_scalar_matrix_result_with_dimensions(
            output_dims.clone(),
            freq_values,
        )?)?);
    }
    if output_arity == 3 {
        let (rows, cols) = storage_shape_from_dimensions(&output_dims);
        outputs.push(Value::Cell(CellValue::with_dimensions(
            rows,
            cols,
            output_dims,
            cell_values,
        )?));
    }
    Ok(outputs)
}

fn builtin_mad(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, flag, selection) = parse_mad_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let vecdim_shape_promotion = vecdim_shape_promotion_dims(&input_dims, &selection);
    let promote = |result| {
        if let Some(ref reduce_dims) = vecdim_shape_promotion {
            promote_value_for_vecdim_shape(result, &input_dims, reduce_dims)
        } else {
            Ok(result)
        }
    };
    let reducer = |values: &[f64]| mad_of_values_with_flag(values, flag);
    if let StatisticSelection::VecDim(dims) = &selection {
        let mut reduce_dims = dims.clone();
        reduce_dims.sort_unstable();
        reduce_dims.dedup();
        if input_dims.len() > 2 || vecdim_requires_nd_path(&reduce_dims) {
            let rank = input_dims
                .len()
                .max(reduce_dims.iter().copied().max().unwrap_or(0));
            if reduce_dims == (1..=rank).collect::<Vec<_>>() {
                return Ok(Value::Scalar(reducer(
                    &numeric_operand(value, "mad")?.values,
                )));
            }
            let (output_dims, values) = reduce_numeric_vecdim_values(
                &numeric_operand(value, "mad")?.values,
                &input_dims,
                &reduce_dims,
                1,
                |sample| vec![reducer(sample)],
            );
            return numeric_matrix_result_with_dimensions(output_dims, values);
        }
    }
    match selection {
        StatisticSelection::Default => {
            if input_dims.len() > 2 {
                let operand = numeric_operand(value, "mad")?;
                mad_numeric_value_with_dimensions(
                    &operand.values,
                    &input_dims,
                    default_statistic_dimension(&operand),
                    flag,
                )
            } else {
                reduce_numeric_value(value, "mad", Value::Scalar(f64::NAN), reducer)
            }
        }
        _ => match collapsed_statistic_selection(
            &selection,
            variance_default_dimension(value, "mad")?,
        ) {
            CollapsedStatisticSelection::All => promote(reduce_numeric_value_all(
                value,
                "mad",
                Value::Scalar(f64::NAN),
                reducer,
            )?),
            CollapsedStatisticSelection::Dim(dim) => {
                if input_dims.len() > 2 || dim > 2 {
                    promote(mad_numeric_value_with_dimensions(
                        &numeric_operand(value, "mad")?.values,
                        &input_dims,
                        dim,
                        flag,
                    )?)
                } else {
                    promote(reduce_numeric_value_along_dimension(
                        value,
                        "mad",
                        dim,
                        Value::Scalar(f64::NAN),
                        reducer,
                    )?)
                }
            }
        },
    }
}

fn builtin_geomean(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, selection, missing_flag) =
        parse_statistic_selection_with_missing_args(args, "geomean")?;
    let data = geomean_real_dataset(value)?;
    validate_geomean_values(&data.values)?;
    let input_dims = canonical_size_vector(&data.dims);
    let reducer = |sample: &[f64]| geomean_of_values(sample, missing_flag);
    if let StatisticSelection::VecDim(dims) = &selection {
        let mut reduce_dims = dims.clone();
        reduce_dims.sort_unstable();
        reduce_dims.dedup();
        if input_dims.len() > 2 || vecdim_requires_nd_path(&reduce_dims) {
            let rank = input_dims
                .len()
                .max(reduce_dims.iter().copied().max().unwrap_or(0));
            if reduce_dims == (1..=rank).collect::<Vec<_>>() {
                return Ok(Value::Scalar(reducer(&data.values)));
            }
            let (output_dims, values) = reduce_numeric_vecdim_values(
                &data.values,
                &input_dims,
                &reduce_dims,
                1,
                |sample| vec![reducer(sample)],
            );
            return numeric_matrix_result_with_dimensions(output_dims, values);
        }
    }
    match collapsed_statistic_selection(
        &selection,
        default_reduction_dimension_from_dims(&input_dims),
    ) {
        CollapsedStatisticSelection::All => Ok(Value::Scalar(reducer(&data.values))),
        CollapsedStatisticSelection::Dim(dim) => {
            geomean_numeric_value_with_dimensions(&data.values, &input_dims, dim, missing_flag)
        }
    }
}

