fn builtin_corr2(args: &[Value]) -> Result<Value, RuntimeError> {
    let [lhs, rhs] = args else {
        return Err(RuntimeError::Unsupported(
            "corr2 currently supports exactly two input arguments".to_string(),
        ));
    };
    let lhs_dims = canonical_size_vector(&value_dimensions(lhs));
    let rhs_dims = canonical_size_vector(&value_dimensions(rhs));
    if lhs_dims != rhs_dims {
        return Err(RuntimeError::ShapeError(
            "corr2 currently expects both inputs to have the same size".to_string(),
        ));
    }
    let lhs = numeric_operand(lhs, "corr2")?;
    let rhs = numeric_operand(rhs, "corr2")?;
    if lhs.values.is_empty() {
        return Ok(Value::Scalar(f64::NAN));
    }

    let count = lhs.values.len() as f64;
    let mean_lhs = lhs.values.iter().sum::<f64>() / count;
    let mean_rhs = rhs.values.iter().sum::<f64>() / count;
    let mut numerator = 0.0;
    let mut lhs_sq = 0.0;
    let mut rhs_sq = 0.0;
    for (lhs_value, rhs_value) in lhs.values.iter().zip(rhs.values.iter()) {
        let lhs_centered = *lhs_value - mean_lhs;
        let rhs_centered = *rhs_value - mean_rhs;
        numerator += lhs_centered * rhs_centered;
        lhs_sq += lhs_centered * lhs_centered;
        rhs_sq += rhs_centered * rhs_centered;
    }
    let denominator = (lhs_sq * rhs_sq).sqrt();
    if denominator == 0.0 {
        return Ok(Value::Scalar(f64::NAN));
    }
    Ok(Value::Scalar(numerator / denominator))
}

fn builtin_xcorr2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (lhs, rhs) = match args {
        [value] => (
            numeric_or_complex_operand(value, "xcorr2")?,
            numeric_or_complex_operand(value, "xcorr2")?,
        ),
        [lhs, rhs] => (
            numeric_or_complex_operand(lhs, "xcorr2")?,
            numeric_or_complex_operand(rhs, "xcorr2")?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "xcorr2 currently supports `xcorr2(A)` and `xcorr2(A,B)`".to_string(),
            ))
        }
    };
    if lhs.values.is_empty() || rhs.values.is_empty() {
        return Err(RuntimeError::ShapeError(
            "xcorr2 currently expects nonempty matrix inputs".to_string(),
        ));
    }
    let rhs = conjugate_numeric_or_complex_operand(&rotate_kernel_180(&rhs));
    let result = full_complex_convolution_matrix(&lhs, &rhs);
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_normxcorr2(args: &[Value]) -> Result<Value, RuntimeError> {
    let [template, image] = args else {
        return Err(RuntimeError::Unsupported(
            "normxcorr2 currently supports exactly two input arguments".to_string(),
        ));
    };
    let template = real_numeric_operand(template, "normxcorr2")?;
    let image = real_numeric_operand(image, "normxcorr2")?;
    if template.rows == 0 || template.cols == 0 || image.rows == 0 || image.cols == 0 {
        return Err(RuntimeError::ShapeError(
            "normxcorr2 currently expects nonempty 2-D numeric inputs".to_string(),
        ));
    }
    if template.rows > image.rows || template.cols > image.cols {
        return Err(RuntimeError::ShapeError(
            "normxcorr2 currently expects the template to be no larger than the image".to_string(),
        ));
    }
    let values = normxcorr2_values(&template, &image);
    build_scalar_matrix_result(
        image.rows + template.rows - 1,
        image.cols + template.cols - 1,
        values.into_iter().map(Value::Scalar).collect(),
    )
}

fn builtin_xcorr(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "xcorr currently supports one or two outputs".to_string(),
        ));
    }
    let parsed = parse_xcorr_args(args, "xcorr")?;
    if parsed.lhs.is_empty() || parsed.rhs.as_ref().is_some_and(|rhs| rhs.is_empty()) {
        return Err(RuntimeError::ShapeError(
            "xcorr currently expects nonempty vector inputs".to_string(),
        ));
    }
    if parsed.scale != XcorrScale::None
        && parsed.rhs.is_some()
        && parsed.lhs.sequence_len() != parsed.rhs.as_ref().expect("rhs checked").len()
    {
        return Err(RuntimeError::Unsupported(
            "xcorr currently supports scale options for cross-correlation only when inputs have equal length"
                .to_string(),
        ));
    }
    let max_len = parsed
        .lhs
        .sequence_len()
        .max(parsed.rhs.as_ref().map(|rhs| rhs.len()).unwrap_or(0));
    let maxlag = parsed.maxlag.unwrap_or(max_len.saturating_sub(1));
    let mut outputs = vec![xcorr_output_value(&parsed, maxlag)?];
    if output_arity == 2 {
        let lags = (-(maxlag as isize)..=(maxlag as isize))
            .map(|lag| Value::Scalar(lag as f64))
            .collect::<Vec<_>>();
        outputs.push(build_scalar_matrix_result(
            if parsed.row_output { 1 } else { lags.len() },
            if parsed.row_output { lags.len() } else { 1 },
            lags,
        )?);
    }
    Ok(outputs)
}

