struct XcorrArgs {
    lhs: XcorrInput,
    rhs: Option<Vec<ComplexParts>>,
    row_output: bool,
    maxlag: Option<usize>,
    scale: XcorrScale,
}

enum XcorrInput {
    Vector {
        values: Vec<ComplexParts>,
    },
    Matrix {
        rows: usize,
        cols: usize,
        values: Vec<ComplexParts>,
    },
}

impl XcorrInput {
    fn is_empty(&self) -> bool {
        match self {
            Self::Vector { values } => values.is_empty(),
            Self::Matrix { rows, cols, .. } => *rows == 0 || *cols == 0,
        }
    }

    fn sequence_len(&self) -> usize {
        match self {
            Self::Vector { values } => values.len(),
            Self::Matrix { rows, .. } => *rows,
        }
    }
}

#[derive(Clone, Copy, PartialEq, Eq)]
enum XcorrScale {
    None,
    Biased,
    Unbiased,
    Coeff,
}

fn parse_xcorr_args(args: &[Value], builtin_name: &str) -> Result<XcorrArgs, RuntimeError> {
    let Some(first) = args.first() else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects at least one input argument"
        )));
    };
    let mut index = 1usize;
    let mut rhs = None;
    let mut has_rhs = false;
    if let Some(second) = args.get(index) {
        if !xcorr_value_is_scale_option(second, builtin_name) {
            let treat_as_maxlag = (args.len() == 2
                && parse_xcorr_maxlag(second, builtin_name).is_ok())
                || (args.len() == 3
                    && xcorr_value_is_scale_option(&args[2], builtin_name)
                    && parse_xcorr_maxlag(second, builtin_name).is_ok());
            if !treat_as_maxlag {
                let (rhs_values, _rhs_row) = numeric_or_complex_set_vector(second, builtin_name)?;
                rhs = Some(rhs_values);
                has_rhs = true;
                index += 1;
            }
        }
    }
    let (lhs, row_output) = if has_rhs {
        let (values, row_output) = numeric_or_complex_set_vector(first, builtin_name)?;
        (XcorrInput::Vector { values }, row_output)
    } else {
        xcorr_input(first, builtin_name)?
    };
    let mut maxlag = None;
    let mut scale = XcorrScale::None;
    while index < args.len() {
        let value = &args[index];
        if xcorr_value_is_scale_option(value, builtin_name) {
            scale = parse_xcorr_scale(value, builtin_name)?;
        } else if maxlag.is_none() {
            maxlag = Some(parse_xcorr_maxlag(value, builtin_name)?);
        } else {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports at most one maxlag argument"
            )));
        }
        index += 1;
    }
    Ok(XcorrArgs {
        lhs,
        rhs,
        row_output,
        maxlag,
        scale,
    })
}

fn xcorr_value_is_scale_option(value: &Value, builtin_name: &str) -> bool {
    matches!(value, Value::CharArray(_) | Value::String(_))
        && parse_xcorr_scale(value, builtin_name).is_ok()
}

fn parse_xcorr_scale(value: &Value, builtin_name: &str) -> Result<XcorrScale, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "none" => Ok(XcorrScale::None),
        "biased" => Ok(XcorrScale::Biased),
        "unbiased" => Ok(XcorrScale::Unbiased),
        "coeff" | "normalized" => Ok(XcorrScale::Coeff),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} scale option `{other}` is not implemented; expected none, biased, unbiased, coeff, or normalized"
        ))),
    }
}

fn parse_xcorr_maxlag(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects maxlag to be a nonnegative finite integer"
        )));
    }
    Ok(scalar as usize)
}

fn xcorr_input(value: &Value, builtin_name: &str) -> Result<(XcorrInput, bool), RuntimeError> {
    match value {
        Value::Matrix(matrix) if matrix.rows > 1 && matrix.cols > 1 => {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, builtin_name))
                .collect::<Result<Vec<_>, _>>()?;
            Ok((
                XcorrInput::Matrix {
                    rows: matrix.rows,
                    cols: matrix.cols,
                    values,
                },
                false,
            ))
        }
        _ => {
            let (values, row_output) = numeric_or_complex_set_vector(value, builtin_name)?;
            Ok((XcorrInput::Vector { values }, row_output))
        }
    }
}

fn xcorr_output_value(parsed: &XcorrArgs, maxlag: usize) -> Result<Value, RuntimeError> {
    match &parsed.lhs {
        XcorrInput::Vector { values } => {
            let rhs = parsed.rhs.as_ref().unwrap_or(values);
            numeric_or_complex_vector_output(
                xcorr_values(values, rhs, maxlag, parsed.scale),
                parsed.row_output,
            )
        }
        XcorrInput::Matrix { rows, cols, values } => {
            let lag_count = (2 * maxlag) + 1;
            let mut pair_values = Vec::with_capacity(cols * cols);
            for lhs_col in 0..*cols {
                let lhs = matrix_column_complex(values, *rows, *cols, lhs_col);
                for rhs_col in 0..*cols {
                    let rhs = matrix_column_complex(values, *rows, *cols, rhs_col);
                    pair_values.push(xcorr_values(&lhs, &rhs, maxlag, parsed.scale));
                }
            }
            xcorr_matrix_output(pair_values, lag_count, *cols)
        }
    }
}

fn xcov_output_value(parsed: &XcorrArgs, maxlag: usize) -> Result<Value, RuntimeError> {
    match &parsed.lhs {
        XcorrInput::Vector { values } => {
            let lhs = xcov_centered_values(values);
            let rhs = parsed
                .rhs
                .as_ref()
                .map(|rhs| xcov_centered_values(rhs))
                .unwrap_or_else(|| lhs.clone());
            numeric_or_complex_vector_output(
                xcorr_values(&lhs, &rhs, maxlag, parsed.scale),
                parsed.row_output,
            )
        }
        XcorrInput::Matrix { rows, cols, values } => {
            let lag_count = (2 * maxlag) + 1;
            let columns = (0..*cols)
                .map(|col| xcov_centered_values(&matrix_column_complex(values, *rows, *cols, col)))
                .collect::<Vec<_>>();
            let mut pair_values = Vec::with_capacity(cols * cols);
            for lhs in &columns {
                for rhs in &columns {
                    pair_values.push(xcorr_values(lhs, rhs, maxlag, parsed.scale));
                }
            }
            xcorr_matrix_output(pair_values, lag_count, *cols)
        }
    }
}

fn xcorr_matrix_output(
    pair_values: Vec<Vec<ComplexParts>>,
    lag_count: usize,
    cols: usize,
) -> Result<Value, RuntimeError> {
    let mut output = Vec::with_capacity(lag_count * cols * cols);
    for lag_index in 0..lag_count {
        for pair in &pair_values {
            output.push(numeric_or_complex_value(pair[lag_index]));
        }
    }
    build_scalar_matrix_result(lag_count, cols * cols, output)
}

fn matrix_column_complex(
    values: &[ComplexParts],
    rows: usize,
    cols: usize,
    col: usize,
) -> Vec<ComplexParts> {
    (0..rows).map(|row| values[row * cols + col]).collect()
}

fn normxcorr2_values(template: &RealNumericOperand, image: &RealNumericOperand) -> Vec<f64> {
    let out_rows = image.rows + template.rows - 1;
    let out_cols = image.cols + template.cols - 1;
    let template_count = (template.rows * template.cols) as f64;
    let template_mean = template.values.iter().sum::<f64>() / template_count;
    let template_centered = template
        .values
        .iter()
        .map(|value| value - template_mean)
        .collect::<Vec<_>>();
    let template_norm_sq = template_centered
        .iter()
        .map(|value| value * value)
        .sum::<f64>();
    let mut output = vec![0.0; out_rows * out_cols];
    for out_row in 0..out_rows {
        for out_col in 0..out_cols {
            let top = out_row as isize - (template.rows as isize - 1);
            let left = out_col as isize - (template.cols as isize - 1);
            let mut patch = Vec::with_capacity(template.rows * template.cols);
            for template_row in 0..template.rows {
                for template_col in 0..template.cols {
                    let image_row = top + template_row as isize;
                    let image_col = left + template_col as isize;
                    if image_row >= 0
                        && image_row < image.rows as isize
                        && image_col >= 0
                        && image_col < image.cols as isize
                    {
                        patch.push(
                            image.values[image_row as usize * image.cols + image_col as usize],
                        );
                    } else {
                        patch.push(0.0);
                    }
                }
            }
            let patch_mean = patch.iter().sum::<f64>() / template_count;
            let mut numerator = 0.0;
            let mut patch_norm_sq = 0.0;
            for (template_value, patch_value) in template_centered.iter().zip(patch.iter()) {
                let patch_centered = patch_value - patch_mean;
                numerator += template_value * patch_centered;
                patch_norm_sq += patch_centered * patch_centered;
            }
            let denominator = (template_norm_sq * patch_norm_sq).sqrt();
            output[out_row * out_cols + out_col] = if denominator <= 1e-12 {
                0.0
            } else {
                normalize_polynomial_scalar(numerator / denominator)
            };
        }
    }
    output
}

fn xcov_centered_values(values: &[ComplexParts]) -> Vec<ComplexParts> {
    let mean = values
        .iter()
        .copied()
        .fold(ComplexParts::zero(), |total, value| total.plus(value))
        .scale(1.0 / values.len() as f64);
    values.iter().map(|value| value.minus(mean)).collect()
}

fn xcorr_values(
    lhs: &[ComplexParts],
    rhs: &[ComplexParts],
    maxlag: usize,
    scale: XcorrScale,
) -> Vec<ComplexParts> {
    let max_len = lhs.len().max(rhs.len());
    let coeff_norm = lhs
        .iter()
        .map(|value| value.magnitude().powi(2))
        .sum::<f64>()
        .sqrt()
        * rhs
            .iter()
            .map(|value| value.magnitude().powi(2))
            .sum::<f64>()
            .sqrt();
    (-(maxlag as isize)..=(maxlag as isize))
        .map(|lag| {
            let mut total = ComplexParts::zero();
            for rhs_index in 0..rhs.len() {
                let lhs_index = rhs_index as isize + lag;
                if lhs_index < 0 || lhs_index >= lhs.len() as isize {
                    continue;
                }
                total = total.plus(lhs[lhs_index as usize].times(rhs[rhs_index].conjugate()));
            }
            let scaled = match scale {
                XcorrScale::None => total,
                XcorrScale::Biased => total.scale(1.0 / max_len as f64),
                XcorrScale::Unbiased => {
                    let denominator = (max_len as isize - lag.abs()).max(1) as f64;
                    total.scale(1.0 / denominator)
                }
                XcorrScale::Coeff => {
                    if coeff_norm == 0.0 {
                        ComplexParts::nan()
                    } else {
                        total.scale(1.0 / coeff_norm)
                    }
                }
            };
            normalize_complex_parts(scaled)
        })
        .collect()
}

fn builtin_immse(args: &[Value]) -> Result<Value, RuntimeError> {
    let [lhs, rhs] = args else {
        return Err(RuntimeError::Unsupported(
            "immse currently supports exactly two input arguments".to_string(),
        ));
    };
    Ok(Value::Scalar(immse_value(lhs, rhs, "immse")?))
}

fn builtin_psnr(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "psnr currently supports one or two outputs".to_string(),
        ));
    }
    let (signal, reference, options) = parse_psnr_args(args)?;
    let signal_dims = canonical_size_vector(&value_dimensions(signal));
    let reference_dims = canonical_size_vector(&value_dimensions(reference));
    if signal_dims != reference_dims {
        return Err(RuntimeError::ShapeError(
            "psnr currently expects both inputs to have the same size".to_string(),
        ));
    }
    let signal_operand = numeric_operand(signal, "psnr")?;
    let reference_operand = numeric_operand(reference, "psnr")?;

    let layout = match &options.data_format {
        Some(data_format) => Some(parse_psnr_data_format(&signal_dims, data_format)?),
        None => None,
    };
    if let Some(layout) = layout {
        let canonical_signal = reorder_values_by_axis_order(
            &signal_operand.values,
            &signal_dims,
            &layout.canonical_axes,
        );
        let canonical_reference = reorder_values_by_axis_order(
            &reference_operand.values,
            &signal_dims,
            &layout.canonical_axes,
        );
        let peakval = options
            .peakval
            .unwrap_or_else(|| default_psnr_peak_value(signal));
        let mut peaksnr_values = vec![0.0; layout.slice_count];
        let mut snr_values = vec![0.0; layout.slice_count];
        for slice_index in 0..layout.slice_count {
            let trailing_index = multissim_trailing_index(slice_index, &layout.trailing_dims);
            let signal_slice = extract_numeric_slice(
                &canonical_signal,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let reference_slice = extract_numeric_slice(
                &canonical_reference,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let mse = psnr_mse_of_values(&signal_slice, &reference_slice);
            let peaksnr = if mse == 0.0 {
                f64::INFINITY
            } else {
                10.0 * (peakval * peakval / mse).log10()
            };
            peaksnr_values[slice_index] = peaksnr;
            let signal_power = reference_slice
                .iter()
                .map(|value| value * value)
                .sum::<f64>()
                / reference_slice.len() as f64;
            snr_values[slice_index] = if mse == 0.0 {
                f64::INFINITY
            } else if signal_power == 0.0 {
                f64::NEG_INFINITY
            } else {
                10.0 * (signal_power / mse).log10()
            };
        }
        let peaksnr_output_values = reorder_values_by_axis_order(
            &peaksnr_values,
            &layout.canonical_output_dims,
            &layout.output_axes,
        );
        let peaksnr_output = build_scalar_matrix_result_with_dimensions(
            layout.output_dims.clone(),
            peaksnr_output_values
                .into_iter()
                .map(Value::Scalar)
                .collect::<Vec<_>>(),
        )?;
        let mut outputs = vec![peaksnr_output];
        if output_arity == 2 {
            let snr_output_values = reorder_values_by_axis_order(
                &snr_values,
                &layout.canonical_output_dims,
                &layout.output_axes,
            );
            outputs.push(build_scalar_matrix_result_with_dimensions(
                layout.output_dims,
                snr_output_values
                    .into_iter()
                    .map(Value::Scalar)
                    .collect::<Vec<_>>(),
            )?);
        }
        return Ok(outputs);
    }

    let mse = psnr_mse_of_values(&signal_operand.values, &reference_operand.values);
    if mse == 0.0 {
        let mut outputs = vec![Value::Scalar(f64::INFINITY)];
        if output_arity == 2 {
            outputs.push(Value::Scalar(f64::INFINITY));
        }
        return Ok(outputs);
    }

    let peakval = options
        .peakval
        .unwrap_or_else(|| default_psnr_peak_value(signal));
    let peaksnr = 10.0 * (peakval * peakval / mse).log10();

    let mut outputs = vec![Value::Scalar(peaksnr)];
    if output_arity == 2 {
        let signal_power = reference_operand
            .values
            .iter()
            .map(|value| value * value)
            .sum::<f64>()
            / reference_operand.values.len() as f64;
        let snr = if signal_power == 0.0 {
            f64::NEG_INFINITY
        } else {
            10.0 * (signal_power / mse).log10()
        };
        outputs.push(Value::Scalar(snr));
    }
    Ok(outputs)
}

fn builtin_ssim(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "ssim currently supports one or two outputs".to_string(),
        ));
    }
    let (signal_value, reference_value, options) = parse_ssim_args(args)?;
    let signal_dims = canonical_size_vector(&value_dimensions(signal_value));
    let reference_dims = canonical_size_vector(&value_dimensions(reference_value));
    if signal_dims != reference_dims {
        return Err(RuntimeError::ShapeError(
            "ssim currently expects both inputs to have the same size".to_string(),
        ));
    }
    if options.data_format.is_none() && signal_dims.len() > 3 {
        return Err(RuntimeError::Unsupported(
            "ssim currently expects `DataFormat` for inputs with more than three dimensions"
                .to_string(),
        ));
    }
    let signal = real_numeric_operand(signal_value, "ssim")?;
    let reference = real_numeric_operand(reference_value, "ssim")?;
    let dynamic_range = options
        .dynamic_range
        .unwrap_or_else(|| default_ssim_dynamic_range(signal_value));
    let layout = if let Some(data_format) = &options.data_format {
        ssim_data_layout(&signal_dims, data_format)?
    } else if signal_dims.len() >= 3 {
        SsimLayout::volume_default(&signal_dims)
    } else {
        SsimLayout::plane_default(&signal_dims)
    };
    let canonical_signal =
        reorder_values_by_axis_order(&signal.values, &signal_dims, &layout.canonical_axes);
    let canonical_reference =
        reorder_values_by_axis_order(&reference.values, &signal_dims, &layout.canonical_axes);

    let mut score_values = vec![0.0; layout.slice_count];
    let mut canonical_map_values = vec![0.0; layout.canonical_map_dims.iter().product::<usize>()];
    if layout.spatial_rank == 3 {
        for slice_index in 0..layout.slice_count {
            let trailing_index = multissim_trailing_index(slice_index, &layout.trailing_dims);
            let signal_volume = multissim3_extract_volume(
                &canonical_signal,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let reference_volume = multissim3_extract_volume(
                &canonical_reference,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let (ssim, map, _) = ssim_core_3d(
                &signal_volume,
                &reference_volume,
                layout.spatial_dims[0],
                layout.spatial_dims[1],
                layout.spatial_dims[2],
                dynamic_range,
                &options,
            );
            score_values[slice_index] = ssim;
            multissim3_store_volume(
                &mut canonical_map_values,
                &layout.canonical_map_dims,
                &trailing_index,
                &map,
            );
        }
    } else {
        for slice_index in 0..layout.slice_count {
            let trailing_index = multissim_trailing_index(slice_index, &layout.trailing_dims);
            let signal_plane = multissim_extract_plane(
                &canonical_signal,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let reference_plane = multissim_extract_plane(
                &canonical_reference,
                &layout.canonical_input_dims,
                &trailing_index,
            );
            let (ssim, map, _) = ssim_core(
                &signal_plane,
                &reference_plane,
                layout.spatial_dims[0],
                layout.spatial_dims[1],
                dynamic_range,
                &options,
            );
            score_values[slice_index] = ssim;
            multissim_store_plane(
                &mut canonical_map_values,
                &layout.canonical_map_dims,
                &trailing_index,
                &map,
            );
        }
    }

    let score_output_values = reorder_values_by_axis_order(
        &score_values,
        &layout.canonical_score_dims,
        &layout.output_axes,
    );
    let score_value = build_scalar_matrix_result_with_dimensions(
        layout.score_output_dims.clone(),
        score_output_values
            .into_iter()
            .map(Value::Scalar)
            .collect::<Vec<_>>(),
    )?;
    let mut outputs = vec![score_value];
    if output_arity == 2 {
        let map_output_values = reorder_values_by_axis_order(
            &canonical_map_values,
            &layout.canonical_map_dims,
            &layout.output_axes,
        );
        let (map_rows, map_cols) = storage_shape_from_dimensions(&layout.map_output_dims);
        outputs.push(Value::Matrix(MatrixValue::with_dimensions(
            map_rows,
            map_cols,
            layout.map_output_dims,
            map_output_values.into_iter().map(Value::Scalar).collect(),
        )?));
    }
    Ok(outputs)
}

fn builtin_multissim(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "multissim currently supports one or two outputs".to_string(),
        ));
    }
    let (signal_value, reference_value, options) = parse_multissim_args(args)?;
    let signal_dims = canonical_size_vector(&value_dimensions(signal_value));
    let reference_dims = canonical_size_vector(&value_dimensions(reference_value));
    if signal_dims != reference_dims {
        return Err(RuntimeError::ShapeError(
            "multissim currently expects both inputs to have the same size".to_string(),
        ));
    }
    let signal = real_numeric_operand(signal_value, "multissim")?;
    let reference = real_numeric_operand(reference_value, "multissim")?;
    let rows = signal_dims.first().copied().unwrap_or(signal.rows);
    let cols = signal_dims.get(1).copied().unwrap_or(signal.cols);
    let trailing_dims = signal_dims.iter().skip(2).copied().collect::<Vec<_>>();
    let slice_count = multissim_slice_count(&trailing_dims);
    let max_scales = multissim_max_scales(rows, cols);
    if options.num_scales > max_scales {
        return Err(RuntimeError::Unsupported(format!(
            "multissim currently supports at most {max_scales} scales for inputs of size {}x{}",
            rows, cols
        )));
    }
    let dynamic_range = options
        .dynamic_range
        .unwrap_or_else(|| default_ssim_dynamic_range(signal_value));
    let mut scale_weights = options
        .scale_weights
        .unwrap_or_else(|| default_multissim_scale_weights(options.num_scales));
    normalize_multissim_scale_weights(&mut scale_weights);
    let scale_shapes = multissim_scale_shapes(rows, cols, options.num_scales);
    let quality_map_dims = scale_shapes
        .iter()
        .map(|&(scale_rows, scale_cols)| {
            multissim_output_dims(scale_rows, scale_cols, &trailing_dims)
        })
        .collect::<Vec<_>>();
    let mut quality_map_values = quality_map_dims
        .iter()
        .map(|dims| vec![0.0; dims.iter().product::<usize>()])
        .collect::<Vec<_>>();
    let mut score_values = vec![0.0; slice_count];

    for slice_index in 0..slice_count {
        let trailing_index = multissim_trailing_index(slice_index, &trailing_dims);
        let mut current_signal =
            multissim_extract_plane(&signal.values, &signal_dims, &trailing_index);
        let mut current_reference =
            multissim_extract_plane(&reference.values, &signal_dims, &trailing_index);
        let mut score = 1.0;

        for (scale_index, &(current_rows, current_cols)) in scale_shapes.iter().enumerate() {
            let scale_options = SsimOptions {
                data_format: None,
                dynamic_range: Some(dynamic_range),
                radius: options.sigma,
                exponents: [1.0, 1.0, 1.0],
                regularization_constants: None,
            };
            let (ssim_score, ssim_map, cs_map) = ssim_core(
                &current_signal,
                &current_reference,
                current_rows,
                current_cols,
                dynamic_range,
                &scale_options,
            );
            if scale_index + 1 == options.num_scales {
                score *= ssim_score.powf(scale_weights[scale_index]);
                multissim_store_plane(
                    &mut quality_map_values[scale_index],
                    &quality_map_dims[scale_index],
                    &trailing_index,
                    &ssim_map,
                );
            } else {
                let cs_score = cs_map.iter().sum::<f64>() / cs_map.len() as f64;
                score *= cs_score.powf(scale_weights[scale_index]);
                multissim_store_plane(
                    &mut quality_map_values[scale_index],
                    &quality_map_dims[scale_index],
                    &trailing_index,
                    &cs_map,
                );
                let (down_signal, _, _) =
                    multissim_downsample(&current_signal, current_rows, current_cols);
                let (down_reference, _, _) =
                    multissim_downsample(&current_reference, current_rows, current_cols);
                current_signal = down_signal;
                current_reference = down_reference;
            }
        }
        score_values[slice_index] = score;
    }
    let score_dims = multissim_output_dims(1, 1, &trailing_dims);
    let score_value = build_scalar_matrix_result_with_dimensions(
        score_dims,
        score_values.into_iter().map(Value::Scalar).collect(),
    )?;
    let mut outputs = vec![score_value];
    if output_arity == 2 {
        let quality_maps = quality_map_values
            .into_iter()
            .zip(quality_map_dims)
            .map(|(values, dims)| {
                let (map_rows, map_cols) = storage_shape_from_dimensions(&dims);
                Ok(Value::Matrix(MatrixValue::with_dimensions(
                    map_rows,
                    map_cols,
                    dims,
                    values.into_iter().map(Value::Scalar).collect(),
                )?))
            })
            .collect::<Result<Vec<_>, RuntimeError>>()?;
        outputs.push(Value::Cell(CellValue::new(
            1,
            quality_maps.len(),
            quality_maps,
        )?));
    }
    Ok(outputs)
}

fn builtin_multissim3(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "multissim3 currently supports one or two outputs".to_string(),
        ));
    }
    let (signal_value, reference_value, options) = parse_multissim3_args(args)?;
    let signal_dims = canonical_size_vector(&value_dimensions(signal_value));
    let reference_dims = canonical_size_vector(&value_dimensions(reference_value));
    if signal_dims != reference_dims {
        return Err(RuntimeError::ShapeError(
            "multissim3 currently expects both inputs to have the same size".to_string(),
        ));
    }
    if signal_dims.len() < 3 {
        return Err(RuntimeError::Unsupported(
            "multissim3 currently expects a 3-D grayscale volume or higher-dimensional volume batch"
                .to_string(),
        ));
    }
    let signal = real_numeric_operand(signal_value, "multissim3")?;
    let reference = real_numeric_operand(reference_value, "multissim3")?;
    let rows = signal_dims[0];
    let cols = signal_dims[1];
    let pages = signal_dims[2];
    let trailing_dims = signal_dims.iter().skip(3).copied().collect::<Vec<_>>();
    let slice_count = multissim_slice_count(&trailing_dims);
    let max_scales = multissim3_max_scales(rows, cols, pages);
    if options.num_scales > max_scales {
        return Err(RuntimeError::Unsupported(format!(
            "multissim3 currently supports at most {max_scales} scales for inputs of size {}x{}x{}",
            rows, cols, pages
        )));
    }
    let dynamic_range = options
        .dynamic_range
        .unwrap_or_else(|| default_ssim_dynamic_range(signal_value));
    let mut scale_weights = options
        .scale_weights
        .unwrap_or_else(|| default_multissim_scale_weights(options.num_scales));
    normalize_multissim_scale_weights(&mut scale_weights);
    let scale_shapes = multissim3_scale_shapes(rows, cols, pages, options.num_scales);
    let quality_map_dims = scale_shapes
        .iter()
        .map(|&(scale_rows, scale_cols, scale_pages)| {
            multissim3_output_dims(scale_rows, scale_cols, scale_pages, &trailing_dims)
        })
        .collect::<Vec<_>>();
    let mut quality_map_values = quality_map_dims
        .iter()
        .map(|dims| vec![0.0; dims.iter().product::<usize>()])
        .collect::<Vec<_>>();
    let mut score_values = vec![0.0; slice_count];

    for slice_index in 0..slice_count {
        let trailing_index = multissim_trailing_index(slice_index, &trailing_dims);
        let mut current_signal =
            multissim3_extract_volume(&signal.values, &signal_dims, &trailing_index);
        let mut current_reference =
            multissim3_extract_volume(&reference.values, &signal_dims, &trailing_index);
        let mut score = 1.0;

        for (scale_index, &(current_rows, current_cols, current_pages)) in
            scale_shapes.iter().enumerate()
        {
            let scale_options = SsimOptions {
                data_format: None,
                dynamic_range: Some(dynamic_range),
                radius: options.sigma,
                exponents: [1.0, 1.0, 1.0],
                regularization_constants: None,
            };
            let (ssim_score, ssim_map, cs_map) = ssim_core_3d(
                &current_signal,
                &current_reference,
                current_rows,
                current_cols,
                current_pages,
                dynamic_range,
                &scale_options,
            );
            if scale_index + 1 == options.num_scales {
                score *= ssim_score.powf(scale_weights[scale_index]);
                multissim3_store_volume(
                    &mut quality_map_values[scale_index],
                    &quality_map_dims[scale_index],
                    &trailing_index,
                    &ssim_map,
                );
            } else {
                let cs_score = cs_map.iter().sum::<f64>() / cs_map.len() as f64;
                score *= cs_score.powf(scale_weights[scale_index]);
                multissim3_store_volume(
                    &mut quality_map_values[scale_index],
                    &quality_map_dims[scale_index],
                    &trailing_index,
                    &cs_map,
                );
                let (down_signal, _, _, _) = multissim3_downsample(
                    &current_signal,
                    current_rows,
                    current_cols,
                    current_pages,
                );
                let (down_reference, _, _, _) = multissim3_downsample(
                    &current_reference,
                    current_rows,
                    current_cols,
                    current_pages,
                );
                current_signal = down_signal;
                current_reference = down_reference;
            }
        }
        score_values[slice_index] = score;
    }

    let score_dims = multissim3_output_dims(1, 1, 1, &trailing_dims);
    let score_value = build_scalar_matrix_result_with_dimensions(
        score_dims,
        score_values.into_iter().map(Value::Scalar).collect(),
    )?;
    let mut outputs = vec![score_value];
    if output_arity == 2 {
        let quality_maps = quality_map_values
            .into_iter()
            .zip(quality_map_dims)
            .map(|(values, dims)| {
                let (map_rows, map_cols) = storage_shape_from_dimensions(&dims);
                Ok(Value::Matrix(MatrixValue::with_dimensions(
                    map_rows,
                    map_cols,
                    dims,
                    values.into_iter().map(Value::Scalar).collect(),
                )?))
            })
            .collect::<Result<Vec<_>, RuntimeError>>()?;
        outputs.push(Value::Cell(CellValue::new(
            1,
            quality_maps.len(),
            quality_maps,
        )?));
    }
    Ok(outputs)
}

fn multissim_slice_count(trailing_dims: &[usize]) -> usize {
    if trailing_dims.is_empty() {
        1
    } else {
        trailing_dims.iter().product()
    }
}

fn multissim_trailing_index(slice_index: usize, trailing_dims: &[usize]) -> Vec<usize> {
    if trailing_dims.is_empty() {
        Vec::new()
    } else {
        row_major_multi_index(slice_index, trailing_dims)
    }
}

fn multissim_extract_plane(values: &[f64], dims: &[usize], trailing_index: &[usize]) -> Vec<f64> {
    let rows = dims.first().copied().unwrap_or(1);
    let cols = dims.get(1).copied().unwrap_or(1);
    let mut plane = Vec::with_capacity(rows * cols);
    for row in 0..rows {
        for col in 0..cols {
            let mut full_index = vec![row, col];
            full_index.extend_from_slice(trailing_index);
            plane.push(values[row_major_linear_index(&full_index, dims)]);
        }
    }
    plane
}

fn multissim_store_plane(
    output: &mut [f64],
    output_dims: &[usize],
    trailing_index: &[usize],
    plane: &[f64],
) {
    let rows = output_dims.first().copied().unwrap_or(1);
    let cols = output_dims.get(1).copied().unwrap_or(1);
    for row in 0..rows {
        for col in 0..cols {
            let mut full_index = vec![row, col];
            full_index.extend_from_slice(trailing_index);
            let output_linear = row_major_linear_index(&full_index, output_dims);
            output[output_linear] = plane[row * cols + col];
        }
    }
}

fn multissim_output_dims(rows: usize, cols: usize, trailing_dims: &[usize]) -> Vec<usize> {
    let mut dims = vec![rows, cols];
    dims.extend_from_slice(trailing_dims);
    canonical_size_vector(&dims)
}

fn multissim3_output_dims(
    rows: usize,
    cols: usize,
    pages: usize,
    trailing_dims: &[usize],
) -> Vec<usize> {
    let mut dims = vec![rows, cols, pages];
    dims.extend_from_slice(trailing_dims);
    let mut kept = dims.len().max(3);
    while kept > 3 && dims[kept - 1] == 1 {
        kept -= 1;
    }
    dims[..kept].to_vec()
}

fn multissim_scale_shapes(rows: usize, cols: usize, num_scales: usize) -> Vec<(usize, usize)> {
    let mut shapes = Vec::with_capacity(num_scales);
    let mut current_rows = rows;
    let mut current_cols = cols;
    for _ in 0..num_scales {
        shapes.push((current_rows, current_cols));
        current_rows = current_rows.div_ceil(2);
        current_cols = current_cols.div_ceil(2);
    }
    shapes
}

fn multissim3_scale_shapes(
    rows: usize,
    cols: usize,
    pages: usize,
    num_scales: usize,
) -> Vec<(usize, usize, usize)> {
    let mut shapes = Vec::with_capacity(num_scales);
    let mut current_rows = rows;
    let mut current_cols = cols;
    let mut current_pages = pages;
    for _ in 0..num_scales {
        shapes.push((current_rows, current_cols, current_pages));
        current_rows = current_rows.div_ceil(2);
        current_cols = current_cols.div_ceil(2);
        current_pages = current_pages.div_ceil(2);
    }
    shapes
}

fn normalize_multissim_scale_weights(weights: &mut [f64]) {
    let sum = weights.iter().sum::<f64>();
    if sum > 0.0 {
        for weight in weights {
            *weight /= sum;
        }
    }
}

fn multissim3_max_scales(rows: usize, cols: usize, pages: usize) -> usize {
    let mut min_dim = rows.min(cols).min(pages);
    let mut scales = 0usize;
    while min_dim > 0 {
        scales += 1;
        if min_dim == 1 {
            break;
        }
        min_dim = min_dim.div_ceil(2);
    }
    scales
}

fn multissim3_extract_volume(values: &[f64], dims: &[usize], trailing_index: &[usize]) -> Vec<f64> {
    let rows = dims[0];
    let cols = dims[1];
    let pages = dims[2];
    let mut volume = Vec::with_capacity(rows * cols * pages);
    for page in 0..pages {
        for row in 0..rows {
            for col in 0..cols {
                let mut full_index = vec![row, col, page];
                full_index.extend_from_slice(trailing_index);
                volume.push(values[row_major_linear_index(&full_index, dims)]);
            }
        }
    }
    volume
}

fn multissim3_store_volume(
    output: &mut [f64],
    output_dims: &[usize],
    trailing_index: &[usize],
    volume: &[f64],
) {
    let rows = output_dims[0];
    let cols = output_dims[1];
    let pages = output_dims[2];
    for page in 0..pages {
        for row in 0..rows {
            for col in 0..cols {
                let mut full_index = vec![row, col, page];
                full_index.extend_from_slice(trailing_index);
                let output_linear = row_major_linear_index(&full_index, output_dims);
                let source_linear = (page * rows * cols) + (row * cols) + col;
                output[output_linear] = volume[source_linear];
            }
        }
    }
}

fn multissim3_downsample(
    input: &[f64],
    rows: usize,
    cols: usize,
    pages: usize,
) -> (Vec<f64>, usize, usize, usize) {
    let out_rows = rows.div_ceil(2);
    let out_cols = cols.div_ceil(2);
    let out_pages = pages.div_ceil(2);
    let mut output = Vec::with_capacity(out_rows * out_cols * out_pages);
    for page in 0..out_pages {
        for row in 0..out_rows {
            for col in 0..out_cols {
                let mut total = 0.0;
                let mut count = 0.0;
                for page_offset in 0..2 {
                    for row_offset in 0..2 {
                        for col_offset in 0..2 {
                            let source_page = (page * 2 + page_offset).min(pages - 1);
                            let source_row = (row * 2 + row_offset).min(rows - 1);
                            let source_col = (col * 2 + col_offset).min(cols - 1);
                            let source_linear =
                                (source_page * rows * cols) + (source_row * cols) + source_col;
                            total += input[source_linear];
                            count += 1.0;
                        }
                    }
                }
                output.push(total / count);
            }
        }
    }
    (output, out_rows, out_cols, out_pages)
}

struct SsimLayout {
    spatial_rank: usize,
    spatial_dims: Vec<usize>,
    trailing_dims: Vec<usize>,
    slice_count: usize,
    canonical_axes: Vec<usize>,
    output_axes: Vec<usize>,
    canonical_input_dims: Vec<usize>,
    canonical_score_dims: Vec<usize>,
    canonical_map_dims: Vec<usize>,
    score_output_dims: Vec<usize>,
    map_output_dims: Vec<usize>,
}

impl SsimLayout {
    fn plane_default(input_dims: &[usize]) -> Self {
        let rows = input_dims.first().copied().unwrap_or(1);
        let cols = input_dims.get(1).copied().unwrap_or(1);
        let trailing_dims = input_dims.iter().skip(2).copied().collect::<Vec<_>>();
        let canonical_axes = (0..input_dims.len()).collect::<Vec<_>>();
        let output_axes = (0..input_dims.len()).collect::<Vec<_>>();
        Self {
            spatial_rank: 2,
            spatial_dims: vec![rows, cols],
            trailing_dims: trailing_dims.clone(),
            slice_count: multissim_slice_count(&trailing_dims),
            canonical_axes,
            output_axes,
            canonical_input_dims: multissim_output_dims(rows, cols, &trailing_dims),
            canonical_score_dims: multissim_output_dims(1, 1, &trailing_dims),
            canonical_map_dims: multissim_output_dims(rows, cols, &trailing_dims),
            score_output_dims: multissim_output_dims(1, 1, &trailing_dims),
            map_output_dims: multissim_output_dims(rows, cols, &trailing_dims),
        }
    }

    fn volume_default(input_dims: &[usize]) -> Self {
        let rows = input_dims[0];
        let cols = input_dims[1];
        let pages = input_dims[2];
        let trailing_dims = input_dims.iter().skip(3).copied().collect::<Vec<_>>();
        let canonical_axes = (0..input_dims.len()).collect::<Vec<_>>();
        let output_axes = (0..input_dims.len()).collect::<Vec<_>>();
        Self {
            spatial_rank: 3,
            spatial_dims: vec![rows, cols, pages],
            trailing_dims: trailing_dims.clone(),
            slice_count: multissim_slice_count(&trailing_dims),
            canonical_axes,
            output_axes,
            canonical_input_dims: multissim3_output_dims(rows, cols, pages, &trailing_dims),
            canonical_score_dims: multissim3_output_dims(1, 1, 1, &trailing_dims),
            canonical_map_dims: multissim3_output_dims(rows, cols, pages, &trailing_dims),
            score_output_dims: multissim3_output_dims(1, 1, 1, &trailing_dims),
            map_output_dims: multissim3_output_dims(rows, cols, pages, &trailing_dims),
        }
    }
}

fn ssim_data_layout(input_dims: &[usize], data_format: &str) -> Result<SsimLayout, RuntimeError> {
    let normalized = data_format.trim().to_ascii_uppercase();
    let labels = normalized.chars().collect::<Vec<_>>();
    if labels.len() != input_dims.len() {
        return Err(RuntimeError::ShapeError(
            "ssim currently expects DataFormat to have one label per input dimension".to_string(),
        ));
    }
    let mut spatial_axes = Vec::new();
    let mut trailing_axes = Vec::new();
    let mut channel_count = 0usize;
    let mut batch_count = 0usize;
    for (axis, label) in labels.iter().copied().enumerate() {
        match label {
            'S' => spatial_axes.push(axis),
            'C' => {
                channel_count += 1;
                trailing_axes.push(axis);
            }
            'B' => {
                batch_count += 1;
                trailing_axes.push(axis);
            }
            _ => {
                return Err(RuntimeError::TypeError(
                    "ssim currently expects DataFormat labels drawn from 'S', 'C', and 'B'"
                        .to_string(),
                ));
            }
        }
    }
    if channel_count > 1 || batch_count > 1 {
        return Err(RuntimeError::TypeError(
            "ssim currently expects at most one channel label and one batch label in DataFormat"
                .to_string(),
        ));
    }
    if spatial_axes.len() != 2 && spatial_axes.len() != 3 {
        return Err(RuntimeError::Unsupported(
            "ssim currently supports DataFormat with exactly two or three spatial dimensions"
                .to_string(),
        ));
    }
    let canonical_axes = spatial_axes
        .iter()
        .chain(trailing_axes.iter())
        .copied()
        .collect::<Vec<_>>();
    let mut output_axes = vec![0usize; canonical_axes.len()];
    for (canonical_axis, original_axis) in canonical_axes.iter().copied().enumerate() {
        output_axes[original_axis] = canonical_axis;
    }
    let spatial_dims = spatial_axes
        .iter()
        .map(|&axis| input_dims[axis])
        .collect::<Vec<_>>();
    let trailing_dims = trailing_axes
        .iter()
        .map(|&axis| input_dims[axis])
        .collect::<Vec<_>>();
    let spatial_rank = spatial_dims.len();
    let canonical_input_dims = if spatial_rank == 3 {
        multissim3_output_dims(
            spatial_dims[0],
            spatial_dims[1],
            spatial_dims[2],
            &trailing_dims,
        )
    } else {
        multissim_output_dims(spatial_dims[0], spatial_dims[1], &trailing_dims)
    };
    let canonical_score_dims = if spatial_rank == 3 {
        multissim3_output_dims(1, 1, 1, &trailing_dims)
    } else {
        multissim_output_dims(1, 1, &trailing_dims)
    };
    let canonical_map_dims = canonical_input_dims.clone();
    let mut score_output_dims = input_dims.to_vec();
    for &axis in &spatial_axes {
        score_output_dims[axis] = 1;
    }
    Ok(SsimLayout {
        spatial_rank,
        spatial_dims,
        trailing_dims: trailing_dims.clone(),
        slice_count: multissim_slice_count(&trailing_dims),
        canonical_axes,
        output_axes,
        canonical_input_dims,
        canonical_score_dims,
        canonical_map_dims,
        score_output_dims: canonical_size_vector(&score_output_dims),
        map_output_dims: canonical_size_vector(input_dims),
    })
}

fn reorder_values_by_axis_order(
    values: &[f64],
    source_dims: &[usize],
    axis_order: &[usize],
) -> Vec<f64> {
    if axis_order.is_empty() {
        return values.to_vec();
    }
    let dest_dims = axis_order
        .iter()
        .map(|&source_axis| source_dims[source_axis])
        .collect::<Vec<_>>();
    let mut output = vec![0.0; values.len()];
    for (source_linear, &value) in values.iter().enumerate() {
        let source_index = row_major_multi_index(source_linear, source_dims);
        let dest_index = axis_order
            .iter()
            .map(|&source_axis| source_index[source_axis])
            .collect::<Vec<_>>();
        let dest_linear = row_major_linear_index(&dest_index, &dest_dims);
        output[dest_linear] = value;
    }
    output
}

fn ssim_core_3d(
    signal: &[f64],
    reference: &[f64],
    rows: usize,
    cols: usize,
    pages: usize,
    dynamic_range: f64,
    options: &SsimOptions,
) -> (f64, Vec<f64>, Vec<f64>) {
    let kernel = ssim_gaussian_kernel_3d(options.radius);
    let signal_mean = ssim_filter_replicate_3d(signal, rows, cols, pages, &kernel);
    let reference_mean = ssim_filter_replicate_3d(reference, rows, cols, pages, &kernel);
    let signal_sq = signal.iter().map(|value| value * value).collect::<Vec<_>>();
    let reference_sq = reference
        .iter()
        .map(|value| value * value)
        .collect::<Vec<_>>();
    let cross = signal
        .iter()
        .zip(reference.iter())
        .map(|(lhs, rhs)| lhs * rhs)
        .collect::<Vec<_>>();
    let signal_sq_mean = ssim_filter_replicate_3d(&signal_sq, rows, cols, pages, &kernel);
    let reference_sq_mean = ssim_filter_replicate_3d(&reference_sq, rows, cols, pages, &kernel);
    let cross_mean = ssim_filter_replicate_3d(&cross, rows, cols, pages, &kernel);
    let [c1, c2, c3] = options.regularization_constants.unwrap_or([
        (0.01 * dynamic_range).powi(2),
        (0.03 * dynamic_range).powi(2),
        ((0.03 * dynamic_range).powi(2)) / 2.0,
    ]);
    let mut ssim_map = Vec::with_capacity(signal.len());
    let mut cs_map = Vec::with_capacity(signal.len());
    for index in 0..signal.len() {
        let mu_x = signal_mean[index];
        let mu_y = reference_mean[index];
        let sigma_x_sq = (signal_sq_mean[index] - mu_x * mu_x).max(0.0);
        let sigma_y_sq = (reference_sq_mean[index] - mu_y * mu_y).max(0.0);
        let sigma_xy = cross_mean[index] - mu_x * mu_y;
        let sigma_x = sigma_x_sq.sqrt();
        let sigma_y = sigma_y_sq.sqrt();
        let luminance = (2.0 * mu_x * mu_y + c1) / (mu_x * mu_x + mu_y * mu_y + c1);
        let contrast = (2.0 * sigma_x * sigma_y + c2) / (sigma_x_sq + sigma_y_sq + c2);
        let structure_denominator = sigma_x * sigma_y + c3;
        let structure = if structure_denominator == 0.0 {
            1.0
        } else {
            (sigma_xy + c3) / structure_denominator
        };
        let cs = contrast * structure;
        cs_map.push(cs);
        ssim_map.push(
            ssim_term_for_exponent(luminance, options.exponents[0])
                * ssim_term_for_exponent(contrast, options.exponents[1])
                * ssim_term_for_exponent(structure, options.exponents[2]),
        );
    }
    let ssim = ssim_map.iter().sum::<f64>() / ssim_map.len() as f64;
    (ssim, ssim_map, cs_map)
}

fn ssim_core(
    signal: &[f64],
    reference: &[f64],
    rows: usize,
    cols: usize,
    dynamic_range: f64,
    options: &SsimOptions,
) -> (f64, Vec<f64>, Vec<f64>) {
    let kernel = ssim_gaussian_kernel(options.radius);
    let signal_mean = ssim_filter_replicate(signal, rows, cols, &kernel);
    let reference_mean = ssim_filter_replicate(reference, rows, cols, &kernel);
    let signal_sq = signal.iter().map(|value| value * value).collect::<Vec<_>>();
    let reference_sq = reference
        .iter()
        .map(|value| value * value)
        .collect::<Vec<_>>();
    let cross = signal
        .iter()
        .zip(reference.iter())
        .map(|(lhs, rhs)| lhs * rhs)
        .collect::<Vec<_>>();
    let signal_sq_mean = ssim_filter_replicate(&signal_sq, rows, cols, &kernel);
    let reference_sq_mean = ssim_filter_replicate(&reference_sq, rows, cols, &kernel);
    let cross_mean = ssim_filter_replicate(&cross, rows, cols, &kernel);
    let [c1, c2, c3] = options.regularization_constants.unwrap_or([
        (0.01 * dynamic_range).powi(2),
        (0.03 * dynamic_range).powi(2),
        ((0.03 * dynamic_range).powi(2)) / 2.0,
    ]);
    let mut ssim_map = Vec::with_capacity(signal.len());
    let mut cs_map = Vec::with_capacity(signal.len());
    for index in 0..signal.len() {
        let mu_x = signal_mean[index];
        let mu_y = reference_mean[index];
        let sigma_x_sq = (signal_sq_mean[index] - mu_x * mu_x).max(0.0);
        let sigma_y_sq = (reference_sq_mean[index] - mu_y * mu_y).max(0.0);
        let sigma_xy = cross_mean[index] - mu_x * mu_y;
        let sigma_x = sigma_x_sq.sqrt();
        let sigma_y = sigma_y_sq.sqrt();
        let luminance = (2.0 * mu_x * mu_y + c1) / (mu_x * mu_x + mu_y * mu_y + c1);
        let contrast = (2.0 * sigma_x * sigma_y + c2) / (sigma_x_sq + sigma_y_sq + c2);
        let structure_denominator = sigma_x * sigma_y + c3;
        let structure = if structure_denominator == 0.0 {
            1.0
        } else {
            (sigma_xy + c3) / structure_denominator
        };
        let cs = contrast * structure;
        let value = ssim_term_for_exponent(luminance, options.exponents[0])
            * ssim_term_for_exponent(contrast, options.exponents[1])
            * ssim_term_for_exponent(structure, options.exponents[2]);
        cs_map.push(cs);
        ssim_map.push(value);
    }
    let ssim = ssim_map.iter().sum::<f64>() / ssim_map.len() as f64;
    (ssim, ssim_map, cs_map)
}

fn ssim_term_for_exponent(term: f64, exponent: f64) -> f64 {
    let base = if exponent.fract() != 0.0 {
        term.max(0.0)
    } else {
        term
    };
    base.powf(exponent)
}

struct MultissimOptions {
    num_scales: usize,
    scale_weights: Option<Vec<f64>>,
    sigma: f64,
    dynamic_range: Option<f64>,
}

fn parse_multissim_args(
    args: &[Value],
) -> Result<(&Value, &Value, MultissimOptions), RuntimeError> {
    let [signal, reference, remainder @ ..] = args else {
        return Err(RuntimeError::Unsupported(
            "multissim currently supports `multissim(a, ref)` and selected name-value options"
                .to_string(),
        ));
    };
    if remainder.len() % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "multissim currently expects name-value options to appear in pairs".to_string(),
        ));
    }
    let mut options = MultissimOptions {
        num_scales: 5,
        scale_weights: None,
        sigma: 1.5,
        dynamic_range: None,
    };
    for pair in remainder.chunks(2) {
        let [name, value] = pair else {
            unreachable!("chunked in pairs")
        };
        match text_value(name)?.to_ascii_lowercase().as_str() {
            "dataformat" => {
                return Err(RuntimeError::Unsupported(
                    "multissim currently does not support a `DataFormat` option for numeric arrays"
                        .to_string(),
                ))
            }
            "numscales" => {
                options.num_scales = positive_integer_scalar(value, "multissim")?;
            }
            "sigma" => {
                let sigma = positive_real_scalar(value, "multissim")?;
                if sigma == 0.0 {
                    return Err(RuntimeError::TypeError(
                        "multissim currently expects Sigma to be a positive finite scalar".to_string(),
                    ));
                }
                options.sigma = sigma;
            }
            "dynamicrange" => {
                options.dynamic_range = Some(positive_real_scalar(value, "multissim")?);
            }
            "scaleweights" => {
                let operand = numeric_operand(value, "multissim")?;
                if operand.values.is_empty() || operand.values.iter().any(|w| !w.is_finite() || *w <= 0.0) {
                    return Err(RuntimeError::TypeError(
                        "multissim currently expects ScaleWeights to be a vector of positive finite values".to_string(),
                    ));
                }
                options.scale_weights = Some(operand.values);
            }
            other => {
                return Err(RuntimeError::Unsupported(format!(
                    "multissim option `{other}` is not implemented; expected NumScales, ScaleWeights, Sigma, or DynamicRange"
                )))
            }
        }
    }
    if options.num_scales == 0 {
        return Err(RuntimeError::TypeError(
            "multissim currently expects NumScales to be a positive integer".to_string(),
        ));
    }
    if let Some(weights) = &options.scale_weights {
        if weights.len() != options.num_scales {
            return Err(RuntimeError::ShapeError(
                "multissim currently expects ScaleWeights to have length NumScales".to_string(),
            ));
        }
    }
    Ok((signal, reference, options))
}

