fn builtin_ordfilt2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, order, domain, offsets, padopt) = parse_ordfilt2_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    if input_dims.len() != 2 {
        return Err(RuntimeError::ShapeError(
            "ordfilt2 currently expects a 2-D numeric or logical matrix".to_string(),
        ));
    }
    let operand = real_numeric_operand(value, "ordfilt2")?;
    let domain = parse_order_filter_domain(domain, offsets)?;
    if order > domain.active_offsets.len() {
        return Err(RuntimeError::ShapeError(format!(
            "ordfilt2 order {order} exceeds the number of nonzero domain elements"
        )));
    }
    let output_values = ordfilt2_values(
        &operand.values,
        input_dims[0],
        input_dims[1],
        order,
        &domain,
        padopt,
    );
    let output_elements = if value_is_logical_like(value) {
        output_values
            .into_iter()
            .map(|value| Value::Logical(value != 0.0))
            .collect::<Vec<_>>()
    } else {
        output_values
            .into_iter()
            .map(Value::Scalar)
            .collect::<Vec<_>>()
    };
    build_scalar_matrix_result_with_dimensions(input_dims, output_elements)
}

fn builtin_medfilt2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, filter_size, padopt) = parse_medfilt2_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    if input_dims.len() != 2 {
        return Err(RuntimeError::ShapeError(
            "medfilt2 currently expects a 2-D numeric or logical matrix".to_string(),
        ));
    }
    let operand = real_numeric_operand(value, "medfilt2")?;
    let indexed_pad_value = if value_is_logical_like(value) {
        0.0
    } else {
        1.0
    };
    let output_values = medfilt2_values(
        &operand.values,
        input_dims[0],
        input_dims[1],
        filter_size,
        padopt,
        indexed_pad_value,
    );
    let output_elements = if value_is_logical_like(value) {
        output_values
            .into_iter()
            .map(|value| Value::Logical(value != 0.0))
            .collect::<Vec<_>>()
    } else {
        output_values
            .into_iter()
            .map(Value::Scalar)
            .collect::<Vec<_>>()
    };
    build_scalar_matrix_result_with_dimensions(input_dims, output_elements)
}

fn builtin_medfilt3(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, filter_size, padopt) = parse_medfilt3_args(args)?;
    let input = medfilt3_input(value)?;
    if input.dims.len() != 3 {
        return Err(RuntimeError::ShapeError(
            "medfilt3 currently expects a 3-D numeric or logical array".to_string(),
        ));
    }
    let output_values = medfilt3_values(
        &input.values,
        input.dims[0],
        input.dims[1],
        input.dims[2],
        filter_size,
        padopt,
    );
    build_scalar_matrix_result_with_dimensions(
        input.dims,
        output_values
            .into_iter()
            .map(|value| match input.output_kind {
                Medfilt3OutputKind::Double => Value::Scalar(value),
                Medfilt3OutputKind::Logical => Value::Logical(value != 0.0),
                Medfilt3OutputKind::Int64 => {
                    rounded_integer_output_value(value, IntegerClass::Int64)
                }
                Medfilt3OutputKind::UInt64 => {
                    rounded_integer_output_value(value, IntegerClass::UInt64)
                }
            })
            .collect(),
    )
}

fn builtin_wiener2(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "wiener2 currently supports one or two outputs".to_string(),
        ));
    }
    let (value, window_size, noise) = parse_wiener2_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    if input_dims.len() != 2 {
        return Err(RuntimeError::ShapeError(
            "wiener2 currently expects a 2-D numeric matrix".to_string(),
        ));
    }
    let operand = real_numeric_operand(value, "wiener2")?;
    let (local_mean, local_variance) =
        wiener2_local_statistics(&operand.values, input_dims[0], input_dims[1], window_size);
    let noise_power = match noise {
        Some(noise) => noise,
        None if local_variance.is_empty() => f64::NAN,
        None => local_variance.iter().sum::<f64>() / local_variance.len() as f64,
    };
    let output_values =
        wiener2_filter_values(&operand.values, &local_mean, &local_variance, noise_power);
    let mut outputs = vec![build_scalar_matrix_result_with_dimensions(
        input_dims,
        output_values.into_iter().map(Value::Scalar).collect(),
    )?];
    if output_arity == 2 {
        outputs.push(Value::Scalar(noise_power));
    }
    Ok(outputs)
}

fn builtin_modefilt(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, filter_size, padopt) = parse_modefilt_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    if input_dims.len() != 2 {
        return Err(RuntimeError::ShapeError(
            "modefilt currently expects a 2-D numeric or logical array".to_string(),
        ));
    }
    let operand = real_numeric_operand(value, "modefilt")?;
    let output_values = modefilt_values(
        &operand.values,
        input_dims[0],
        input_dims[1],
        filter_size,
        padopt,
    );
    let output_elements = if value_is_logical_like(value) {
        output_values
            .into_iter()
            .map(|value| Value::Logical(value != 0.0))
            .collect::<Vec<_>>()
    } else {
        output_values
            .into_iter()
            .map(Value::Scalar)
            .collect::<Vec<_>>()
    };
    build_scalar_matrix_result_with_dimensions(input_dims, output_elements)
}

fn builtin_padarray(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, pad_size, pad_value, direction) = parse_padarray_args(args)?;
    let (input_dims, input_elements, pad_prototype) = padarray_input(value)?;
    if input_elements.is_empty() {
        if !matches!(pad_value, PadarrayPadValue::Constant(_)) {
            return Err(RuntimeError::Unsupported(
                "padarray currently supports empty inputs only for constant padding".to_string(),
            ));
        }
    }
    let mut normalized_input_dims = input_dims;
    while normalized_input_dims.len() < pad_size.len() {
        normalized_input_dims.push(1);
    }
    let mut normalized_pad_size = pad_size;
    while normalized_pad_size.len() < normalized_input_dims.len() {
        normalized_pad_size.push(0);
    }
    let output_dims = padarray_output_dims(&normalized_input_dims, &normalized_pad_size, direction);
    let output_count = output_dims.iter().product::<usize>();
    let mut output = Vec::with_capacity(output_count);
    for linear in 0..output_count {
        let output_index = row_major_multi_index(linear, &output_dims);
        let source_index = padarray_source_index(
            &output_index,
            &normalized_input_dims,
            &normalized_pad_size,
            direction,
        );
        let value = match source_index {
            Some(index) => {
                let linear = row_major_linear_index(&index, &normalized_input_dims);
                input_elements[linear].clone()
            }
            None => match pad_value {
                PadarrayPadValue::Constant(value) => typed_padarray_value(&pad_prototype, value),
                PadarrayPadValue::Replicate => {
                    let index = padarray_boundary_index(
                        &output_index,
                        &normalized_input_dims,
                        &normalized_pad_size,
                        direction,
                        |candidate, len| candidate.clamp(0, len as isize - 1) as usize,
                    );
                    input_elements[row_major_linear_index(&index, &normalized_input_dims)].clone()
                }
                PadarrayPadValue::Symmetric => {
                    let index = padarray_boundary_index(
                        &output_index,
                        &normalized_input_dims,
                        &normalized_pad_size,
                        direction,
                        symmetric_padded_index,
                    );
                    input_elements[row_major_linear_index(&index, &normalized_input_dims)].clone()
                }
                PadarrayPadValue::Circular => {
                    let index = padarray_boundary_index(
                        &output_index,
                        &normalized_input_dims,
                        &normalized_pad_size,
                        direction,
                        |candidate, len| candidate.rem_euclid(len as isize) as usize,
                    );
                    input_elements[row_major_linear_index(&index, &normalized_input_dims)].clone()
                }
            },
        };
        output.push(value);
    }
    build_scalar_matrix_result_with_dimensions(output_dims, output)
}

fn builtin_imboxfilt(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, filter_size, options) = parse_imboxfilt_args(args)?;
    let input = imboxfilt_input(value)?;
    let trailing_dims = input.dims.iter().skip(2).copied().collect::<Vec<_>>();
    let slice_count = multissim_slice_count(&trailing_dims);
    let normalization = options
        .normalization_factor
        .unwrap_or_else(|| 1.0 / (filter_size[0] * filter_size[1]) as f64);
    let kernel = box_filter_kernel(filter_size, normalization);
    let mut output_values = vec![0.0; input.values.len()];
    for slice_index in 0..slice_count {
        let trailing_index = multissim_trailing_index(slice_index, &trailing_dims);
        let plane = multissim_extract_plane(&input.values, &input.dims, &trailing_index);
        let filtered = imfilter_2d(
            &NumericOrComplexOperand {
                rows: input.dims[0],
                cols: input.dims.get(1).copied().unwrap_or(1),
                values: plane
                    .into_iter()
                    .map(|value| ComplexParts {
                        real: value,
                        imag: 0.0,
                    })
                    .collect(),
            },
            &kernel,
            ImfilterOptions {
                padding: options.padding,
                shape: ConvolutionShape::Same,
                mode: ImfilterMode::Corr,
            },
        );
        let plane_values = filtered
            .values
            .into_iter()
            .map(|value| normalize_polynomial_scalar(value.real))
            .collect::<Vec<_>>();
        multissim_store_plane(
            &mut output_values,
            &input.dims,
            &trailing_index,
            &plane_values,
        );
    }
    build_scalar_matrix_result_with_dimensions(
        input.dims,
        output_values
            .into_iter()
            .map(|value| match input.output_kind {
                ImboxfiltOutputKind::Double => Value::Scalar(value),
                ImboxfiltOutputKind::Int64 => {
                    rounded_integer_output_value(value, IntegerClass::Int64)
                }
                ImboxfiltOutputKind::UInt64 => {
                    rounded_integer_output_value(value, IntegerClass::UInt64)
                }
            })
            .collect(),
    )
}

