impl FilterNeighborhood {
    fn default_for_dims(dims: Vec<usize>) -> Self {
        let active_offsets = filter_neighborhood_offsets(&dims, &vec![true; dims.iter().product()]);
        Self {
            dims,
            active_offsets,
        }
    }

    fn default_plane(size: usize) -> Self {
        Self::default_for_dims(vec![size, size])
    }

    fn default_for_rank(rank: usize) -> Self {
        Self::default_for_dims(vec![3; rank.max(2)])
    }
}

fn parse_filter_neighborhood(
    value: &Value,
    builtin_name: &str,
) -> Result<FilterNeighborhood, RuntimeError> {
    let dims = canonical_size_vector(&value_dimensions(value));
    if dims.iter().any(|dim| *dim == 0) {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a nonempty neighborhood"
        )));
    }
    if dims.iter().any(|dim| dim % 2 == 0) {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects odd neighborhood dimensions"
        )));
    }
    let operand = numeric_operand(value, builtin_name)?;
    let active = operand
        .values
        .iter()
        .map(|value| *value != 0.0)
        .collect::<Vec<_>>();
    Ok(FilterNeighborhood {
        active_offsets: filter_neighborhood_offsets(&dims, &active),
        dims,
    })
}

fn parse_plane_filter_neighborhood(
    value: &Value,
    builtin_name: &str,
) -> Result<FilterNeighborhood, RuntimeError> {
    let nhood = parse_filter_neighborhood(value, builtin_name)?;
    if nhood.dims.len() != 2 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a 2-D neighborhood"
        )));
    }
    Ok(nhood)
}

fn parse_ordfilt2_args(
    args: &[Value],
) -> Result<(&Value, usize, &Value, Option<&Value>, Ordfilt2PadOption), RuntimeError> {
    match args {
        [value, order, domain] => Ok((
            value,
            positive_integer_scalar_with_label(order, "ordfilt2", "a positive integer order")?,
            domain,
            None,
            Ordfilt2PadOption::Zeros,
        )),
        [value, order, domain, fourth] if is_ordfilt2_pad_option(fourth) => Ok((
            value,
            positive_integer_scalar_with_label(order, "ordfilt2", "a positive integer order")?,
            domain,
            None,
            parse_ordfilt2_pad_option(fourth)?,
        )),
        [value, order, domain, offsets] => Ok((
            value,
            positive_integer_scalar_with_label(order, "ordfilt2", "a positive integer order")?,
            domain,
            Some(offsets),
            Ordfilt2PadOption::Zeros,
        )),
        [value, order, domain, offsets, padopt] => Ok((
            value,
            positive_integer_scalar_with_label(order, "ordfilt2", "a positive integer order")?,
            domain,
            Some(offsets),
            parse_ordfilt2_pad_option(padopt)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "ordfilt2 currently supports `ordfilt2(A,order,domain)`, `ordfilt2(A,order,domain,S)`, and optional `padopt`".to_string(),
        )),
    }
}

fn parse_medfilt2_args(
    args: &[Value],
) -> Result<(&Value, [usize; 2], Medfilt2PadOption), RuntimeError> {
    match args {
        [value] => Ok((value, [3, 3], Medfilt2PadOption::Zeros)),
        [value, padopt] if is_medfilt2_pad_option(padopt) => {
            Ok((value, [3, 3], parse_medfilt2_pad_option(padopt)?))
        }
        [value, filter_size] => Ok((
            value,
            positive_integer_pair(filter_size, "medfilt2")?,
            Medfilt2PadOption::Zeros,
        )),
        [value, filter_size, padopt] => Ok((
            value,
            positive_integer_pair(filter_size, "medfilt2")?,
            parse_medfilt2_pad_option(padopt)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "medfilt2 currently supports `medfilt2(A)`, `medfilt2(A,[m n])`, and optional `padopt`"
                .to_string(),
        )),
    }
}

fn parse_medfilt3_args(
    args: &[Value],
) -> Result<(&Value, [usize; 3], Medfilt3PadOption), RuntimeError> {
    match args {
        [value] => Ok((value, [3, 3, 3], Medfilt3PadOption::Symmetric)),
        [value, padopt] if is_medfilt3_pad_option(padopt) => {
            Ok((value, [3, 3, 3], parse_medfilt3_pad_option(padopt)?))
        }
        [value, filter_size] => Ok((
            value,
            positive_odd_integer_triple(filter_size, "medfilt3")?,
            Medfilt3PadOption::Symmetric,
        )),
        [value, filter_size, padopt] => Ok((
            value,
            positive_odd_integer_triple(filter_size, "medfilt3")?,
            parse_medfilt3_pad_option(padopt)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "medfilt3 currently supports `medfilt3(A)`, `medfilt3(A,[m n p])`, and optional `padopt`"
                .to_string(),
        )),
    }
}

fn parse_wiener2_args(args: &[Value]) -> Result<(&Value, [usize; 2], Option<f64>), RuntimeError> {
    match args {
        [value] => Ok((value, [3, 3], None)),
        [value, window_size] => Ok((value, positive_integer_pair(window_size, "wiener2")?, None)),
        [value, window_size, noise] => {
            let noise = real_numeric_scalar(noise, "wiener2")?;
            if !noise.is_finite() || noise < 0.0 {
                return Err(RuntimeError::TypeError(
                    "wiener2 currently expects noise to be a nonnegative finite scalar"
                        .to_string(),
                ));
            }
            Ok((
                value,
                positive_integer_pair(window_size, "wiener2")?,
                Some(noise),
            ))
        }
        _ => Err(RuntimeError::Unsupported(
            "wiener2 currently supports `wiener2(I)`, `wiener2(I,[m n])`, and `wiener2(I,[m n],noise)`"
                .to_string(),
        )),
    }
}

fn parse_modefilt_args(
    args: &[Value],
) -> Result<(&Value, [usize; 2], ModefiltPadOption), RuntimeError> {
    match args {
        [value] => Ok((value, [3, 3], ModefiltPadOption::Symmetric)),
        [value, padopt] if is_modefilt_pad_option(padopt) => {
            Ok((value, [3, 3], parse_modefilt_pad_option(padopt)?))
        }
        [value, filter_size] => Ok((
            value,
            positive_odd_integer_pair(filter_size, "modefilt")?,
            ModefiltPadOption::Symmetric,
        )),
        [value, filter_size, padopt] => Ok((
            value,
            positive_odd_integer_pair(filter_size, "modefilt")?,
            parse_modefilt_pad_option(padopt)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "modefilt currently supports `modefilt(A)`, `modefilt(A,[m n])`, and optional `padopt`"
                .to_string(),
        )),
    }
}

fn parse_padarray_args(
    args: &[Value],
) -> Result<(&Value, Vec<usize>, PadarrayPadValue, PadarrayDirection), RuntimeError> {
    match args {
        [value, pad_size] => Ok((
            value,
            parse_padarray_pad_size(pad_size)?,
            PadarrayPadValue::Constant(0.0),
            PadarrayDirection::Both,
        )),
        [value, pad_size, third] => {
            if let Ok(direction) = parse_padarray_direction(third) {
                return Ok((
                    value,
                    parse_padarray_pad_size(pad_size)?,
                    PadarrayPadValue::Constant(0.0),
                    direction,
                ));
            }
            Ok((
                value,
                parse_padarray_pad_size(pad_size)?,
                parse_padarray_pad_value(third)?,
                PadarrayDirection::Both,
            ))
        }
        [value, pad_size, pad_value, direction] => Ok((
            value,
            parse_padarray_pad_size(pad_size)?,
            parse_padarray_pad_value(pad_value)?,
            parse_padarray_direction(direction)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "padarray currently supports `padarray(A,padsize)`, `padarray(A,padsize,padval)`, and optional `direction`"
                .to_string(),
        )),
    }
}

fn parse_imboxfilt_args(
    args: &[Value],
) -> Result<(&Value, [usize; 2], ImboxfiltOptions), RuntimeError> {
    let Some((value, tail)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "imboxfilt currently expects at least one input argument".to_string(),
        ));
    };
    let mut filter_size = [3, 3];
    let mut index = 0usize;
    if let Some(candidate) = tail.first() {
        if !is_imboxfilt_option_name(candidate) {
            filter_size = parse_imboxfilt_filter_size(candidate)?;
            index = 1;
        }
    }
    if (tail.len() - index) % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "imboxfilt currently expects name-value options to appear in pairs".to_string(),
        ));
    }
    let mut options = ImboxfiltOptions {
        padding: ImfilterPadding::Replicate,
        normalization_factor: None,
    };
    while index < tail.len() {
        let name = text_value(&tail[index])?;
        let value = &tail[index + 1];
        if name.eq_ignore_ascii_case("Padding") {
            options.padding = parse_imboxfilt_padding(value)?;
        } else if name.eq_ignore_ascii_case("NormalizationFactor") {
            let normalization = value.as_scalar()?;
            if !normalization.is_finite() {
                return Err(RuntimeError::TypeError(
                    "imboxfilt currently expects NormalizationFactor to be a finite scalar"
                        .to_string(),
                ));
            }
            options.normalization_factor = Some(normalization);
        } else {
            return Err(RuntimeError::Unsupported(format!(
                "imboxfilt currently does not support the `{name}` option"
            )));
        }
        index += 2;
    }
    Ok((value, filter_size, options))
}

fn parse_imboxfilt3_args(
    args: &[Value],
) -> Result<(&Value, [usize; 3], ImboxfiltOptions), RuntimeError> {
    let Some((value, tail)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "imboxfilt3 currently expects at least one input argument".to_string(),
        ));
    };
    let mut filter_size = [3, 3, 3];
    let mut index = 0usize;
    if let Some(candidate) = tail.first() {
        if !is_imboxfilt_option_name(candidate) {
            filter_size = parse_imboxfilt3_filter_size(candidate)?;
            index = 1;
        }
    }
    if (tail.len() - index) % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "imboxfilt3 currently expects name-value options to appear in pairs".to_string(),
        ));
    }
    let mut options = ImboxfiltOptions {
        padding: ImfilterPadding::Replicate,
        normalization_factor: None,
    };
    while index < tail.len() {
        let name = text_value(&tail[index])?;
        let option_value = &tail[index + 1];
        if name.eq_ignore_ascii_case("Padding") {
            options.padding = parse_imboxfilt_padding(option_value)?;
        } else if name.eq_ignore_ascii_case("NormalizationFactor") {
            let normalization = option_value.as_scalar()?;
            if !normalization.is_finite() {
                return Err(RuntimeError::TypeError(
                    "imboxfilt3 currently expects NormalizationFactor to be a finite scalar"
                        .to_string(),
                ));
            }
            options.normalization_factor = Some(normalization);
        } else {
            return Err(RuntimeError::Unsupported(format!(
                "imboxfilt3 currently does not support the `{name}` option"
            )));
        }
        index += 2;
    }
    Ok((value, filter_size, options))
}

fn is_imboxfilt_option_name(value: &Value) -> bool {
    matches!(
        value,
        Value::CharArray(text) | Value::String(text)
            if text.eq_ignore_ascii_case("Padding")
                || text.eq_ignore_ascii_case("NormalizationFactor")
    )
}

fn parse_imgaussfilt_args(
    args: &[Value],
) -> Result<(&Value, [f64; 2], ImgaussfiltOptions), RuntimeError> {
    let Some((value, tail)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "imgaussfilt currently expects at least one input argument".to_string(),
        ));
    };
    let mut sigma = [0.5, 0.5];
    let mut index = 0usize;
    if let Some(candidate) = tail.first() {
        if !is_imgaussfilt_option_name(candidate) {
            sigma = parse_imgaussfilt_sigma(candidate)?;
            index = 1;
        }
    }
    if (tail.len() - index) % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "imgaussfilt currently expects name-value options to appear in pairs".to_string(),
        ));
    }
    let mut options = ImgaussfiltOptions {
        padding: ImfilterPadding::Replicate,
        filter_size: None,
    };
    while index < tail.len() {
        let name = text_value(&tail[index])?;
        let option_value = &tail[index + 1];
        if name.eq_ignore_ascii_case("Padding") {
            options.padding = parse_imboxfilt_padding(option_value)?;
        } else if name.eq_ignore_ascii_case("FilterSize") {
            options.filter_size = Some(parse_imgaussfilt_filter_size(option_value)?);
        } else if name.eq_ignore_ascii_case("FilterDomain") {
            parse_imgaussfilt_filter_domain(option_value)?;
        } else {
            return Err(RuntimeError::Unsupported(format!(
                "imgaussfilt currently does not support the `{name}` option"
            )));
        }
        index += 2;
    }
    Ok((value, sigma, options))
}

