fn imgaussfilt_default_filter_size(sigma: [f64; 2]) -> [usize; 2] {
    [
        (2.0 * (2.0 * sigma[0]).ceil() + 1.0) as usize,
        (2.0 * (2.0 * sigma[1]).ceil() + 1.0) as usize,
    ]
}

fn imgaussfilt3_default_filter_size(sigma: [f64; 3]) -> [usize; 3] {
    [
        (2.0 * (2.0 * sigma[0]).ceil() + 1.0) as usize,
        (2.0 * (2.0 * sigma[1]).ceil() + 1.0) as usize,
        (2.0 * (2.0 * sigma[2]).ceil() + 1.0) as usize,
    ]
}

fn gaussian_filter_kernel(filter_size: [usize; 2], sigma: [f64; 2]) -> NumericOrComplexOperand {
    let center_row = ((filter_size[0] as isize + 1) / 2) - 1;
    let center_col = ((filter_size[1] as isize + 1) / 2) - 1;
    let mut values = Vec::with_capacity(filter_size[0] * filter_size[1]);
    let mut total = 0.0;
    for row in 0..filter_size[0] {
        for col in 0..filter_size[1] {
            let row_offset = row as isize - center_row;
            let col_offset = col as isize - center_col;
            let exponent = -((row_offset * row_offset) as f64 / (2.0 * sigma[0] * sigma[0])
                + (col_offset * col_offset) as f64 / (2.0 * sigma[1] * sigma[1]));
            let weight = exponent.exp();
            values.push(weight);
            total += weight;
        }
    }
    NumericOrComplexOperand {
        rows: filter_size[0],
        cols: filter_size[1],
        values: values
            .into_iter()
            .map(|value| ComplexParts {
                real: value / total,
                imag: 0.0,
            })
            .collect(),
    }
}

fn gaussian_filter_kernel_3d(filter_size: [usize; 3], sigma: [f64; 3]) -> Vec<f64> {
    let center_row = ((filter_size[0] as isize + 1) / 2) - 1;
    let center_col = ((filter_size[1] as isize + 1) / 2) - 1;
    let center_page = ((filter_size[2] as isize + 1) / 2) - 1;
    let mut values = Vec::with_capacity(filter_size[0] * filter_size[1] * filter_size[2]);
    let mut total = 0.0;
    for page in 0..filter_size[2] {
        for row in 0..filter_size[0] {
            for col in 0..filter_size[1] {
                let row_offset = row as isize - center_row;
                let col_offset = col as isize - center_col;
                let page_offset = page as isize - center_page;
                let exponent = -((row_offset * row_offset) as f64 / (2.0 * sigma[0] * sigma[0])
                    + (col_offset * col_offset) as f64 / (2.0 * sigma[1] * sigma[1])
                    + (page_offset * page_offset) as f64 / (2.0 * sigma[2] * sigma[2]));
                let weight = exponent.exp();
                values.push(weight);
                total += weight;
            }
        }
    }
    values.into_iter().map(|value| value / total).collect()
}

fn parse_imboxfilt_filter_size(value: &Value) -> Result<[usize; 2], RuntimeError> {
    let elements = match value {
        Value::Matrix(matrix) if matrix.rows == 1 || matrix.cols == 1 => matrix.elements().to_vec(),
        Value::Matrix(_) => {
            return Err(RuntimeError::ShapeError(
                "imboxfilt currently expects filterSize to be a positive odd integer or a two-element vector of positive odd integers"
                    .to_string(),
            ))
        }
        other => vec![other.clone()],
    };
    match elements.as_slice() {
        [only] => {
            let size = positive_odd_integer_scalar(only, "imboxfilt", "filterSize")?;
            Ok([size, size])
        }
        [rows, cols] => Ok([
            positive_odd_integer_scalar(rows, "imboxfilt", "filterSize")?,
            positive_odd_integer_scalar(cols, "imboxfilt", "filterSize")?,
        ]),
        _ => Err(RuntimeError::ShapeError(
            "imboxfilt currently expects filterSize to be a positive odd integer or a two-element vector of positive odd integers"
                .to_string(),
        )),
    }
}

fn parse_imboxfilt3_filter_size(value: &Value) -> Result<[usize; 3], RuntimeError> {
    let elements = match value {
        Value::Matrix(matrix) if matrix.rows == 1 || matrix.cols == 1 => matrix.elements().to_vec(),
        Value::Matrix(_) => {
            return Err(RuntimeError::ShapeError(
                "imboxfilt3 currently expects filterSize to be a positive odd integer or a three-element vector of positive odd integers"
                    .to_string(),
            ))
        }
        other => vec![other.clone()],
    };
    match elements.as_slice() {
        [only] => {
            let size = positive_odd_integer_scalar(only, "imboxfilt3", "filterSize")?;
            Ok([size, size, size])
        }
        [rows, cols, pages] => Ok([
            positive_odd_integer_scalar(rows, "imboxfilt3", "filterSize")?,
            positive_odd_integer_scalar(cols, "imboxfilt3", "filterSize")?,
            positive_odd_integer_scalar(pages, "imboxfilt3", "filterSize")?,
        ]),
        _ => Err(RuntimeError::ShapeError(
            "imboxfilt3 currently expects filterSize to be a positive odd integer or a three-element vector of positive odd integers"
                .to_string(),
        )),
    }
}

fn positive_odd_integer_scalar(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<usize, RuntimeError> {
    let value = match value {
        Value::Scalar(number) => *number,
        Value::Int64(number) => *number as f64,
        Value::UInt64(number) => *number as f64,
        _ => value.as_scalar()?,
    };
    if !value.is_finite() || value < 1.0 || value.fract() != 0.0 || (value as usize) % 2 == 0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects {label} to contain positive odd integers"
        )));
    }
    Ok(value as usize)
}

fn parse_imboxfilt_padding(value: &Value) -> Result<ImfilterPadding, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Int64(_) | Value::UInt64(_) => {
            let value = match value {
                Value::Scalar(number) => *number,
                Value::Int64(number) => *number as f64,
                Value::UInt64(number) => *number as f64,
                _ => unreachable!("guarded scalar cases"),
            };
            if !value.is_finite() {
                return Err(RuntimeError::TypeError(
                    "imboxfilt currently expects Padding to be a finite scalar or padding mode"
                        .to_string(),
                ));
            }
            Ok(ImfilterPadding::Constant(value))
        }
        _ => match text_value(value)?.to_ascii_lowercase().as_str() {
            "replicate" => Ok(ImfilterPadding::Replicate),
            "symmetric" => Ok(ImfilterPadding::Symmetric),
            "circular" => Ok(ImfilterPadding::Circular),
            _ => Err(RuntimeError::Unsupported(
                "imboxfilt currently supports only scalar, `replicate`, `symmetric`, or `circular` padding"
                    .to_string(),
            )),
        },
    }
}

fn imboxfilt_input(value: &Value) -> Result<ImboxfiltInput, RuntimeError> {
    if value_is_logical_like(value) {
        return Err(RuntimeError::TypeError(
            "imboxfilt currently expects numeric input and does not support logical arrays"
                .to_string(),
        ));
    }
    if let Some(operand) = integer_operand(value) {
        return Ok(ImboxfiltInput {
            dims: canonical_size_vector(&value_dimensions(value)),
            values: operand.values.iter().map(|value| *value as f64).collect(),
            output_kind: match operand.class {
                IntegerClass::Int64 => ImboxfiltOutputKind::Int64,
                IntegerClass::UInt64 => ImboxfiltOutputKind::UInt64,
            },
        });
    }
    let operand = real_numeric_operand(value, "imboxfilt")?;
    Ok(ImboxfiltInput {
        dims: canonical_size_vector(&value_dimensions(value)),
        values: operand.values,
        output_kind: ImboxfiltOutputKind::Double,
    })
}

fn box_filter_kernel(filter_size: [usize; 2], scale: f64) -> NumericOrComplexOperand {
    NumericOrComplexOperand {
        rows: filter_size[0],
        cols: filter_size[1],
        values: vec![
            ComplexParts {
                real: scale,
                imag: 0.0,
            };
            filter_size[0] * filter_size[1]
        ],
    }
}

fn imboxfilt3_values(
    values: &[f64],
    rows: usize,
    cols: usize,
    pages: usize,
    filter_size: [usize; 3],
    padding: ImfilterPadding,
    scale: f64,
) -> Vec<f64> {
    let mut output = vec![0.0; values.len()];
    let center_row = ((filter_size[0] as isize + 1) / 2) - 1;
    let center_col = ((filter_size[1] as isize + 1) / 2) - 1;
    let center_page = ((filter_size[2] as isize + 1) / 2) - 1;
    for page in 0..pages {
        for row in 0..rows {
            for col in 0..cols {
                let mut total = 0.0;
                for kernel_page in 0..filter_size[2] {
                    for kernel_row in 0..filter_size[0] {
                        for kernel_col in 0..filter_size[1] {
                            let source_page = page as isize + kernel_page as isize - center_page;
                            let source_row = row as isize + kernel_row as isize - center_row;
                            let source_col = col as isize + kernel_col as isize - center_col;
                            total += imfilter_sample_3d(
                                values,
                                rows,
                                cols,
                                pages,
                                source_row,
                                source_col,
                                source_page,
                                padding,
                            )
                            .real
                                * scale;
                        }
                    }
                }
                output[(page * rows * cols) + (row * cols) + col] =
                    normalize_polynomial_scalar(total);
            }
        }
    }
    output
}

fn imgaussfilt3_values(
    values: &[f64],
    rows: usize,
    cols: usize,
    pages: usize,
    filter_size: [usize; 3],
    kernel: &[f64],
    padding: ImfilterPadding,
) -> Vec<f64> {
    let mut output = vec![0.0; values.len()];
    let center_row = ((filter_size[0] as isize + 1) / 2) - 1;
    let center_col = ((filter_size[1] as isize + 1) / 2) - 1;
    let center_page = ((filter_size[2] as isize + 1) / 2) - 1;
    for page in 0..pages {
        for row in 0..rows {
            for col in 0..cols {
                let mut total = 0.0;
                let mut kernel_index = 0usize;
                for kernel_page in 0..filter_size[2] {
                    for kernel_row in 0..filter_size[0] {
                        for kernel_col in 0..filter_size[1] {
                            let source_page = page as isize + kernel_page as isize - center_page;
                            let source_row = row as isize + kernel_row as isize - center_row;
                            let source_col = col as isize + kernel_col as isize - center_col;
                            total += imfilter_sample_3d(
                                values,
                                rows,
                                cols,
                                pages,
                                source_row,
                                source_col,
                                source_page,
                                padding,
                            )
                            .real
                                * kernel[kernel_index];
                            kernel_index += 1;
                        }
                    }
                }
                output[(page * rows * cols) + (row * cols) + col] =
                    normalize_polynomial_scalar(total);
            }
        }
    }
    output
}

fn imfilter_sample_3d(
    values: &[f64],
    rows: usize,
    cols: usize,
    pages: usize,
    row: isize,
    col: isize,
    page: isize,
    padding: ImfilterPadding,
) -> ComplexParts {
    if row >= 0
        && row < rows as isize
        && col >= 0
        && col < cols as isize
        && page >= 0
        && page < pages as isize
    {
        return ComplexParts {
            real: values[(page as usize * rows * cols) + (row as usize * cols) + col as usize],
            imag: 0.0,
        };
    }
    match padding {
        ImfilterPadding::Constant(value) => ComplexParts {
            real: value,
            imag: 0.0,
        },
        ImfilterPadding::Symmetric => {
            let row = symmetric_padded_index(row, rows);
            let col = symmetric_padded_index(col, cols);
            let page = symmetric_padded_index(page, pages);
            ComplexParts {
                real: values[(page * rows * cols) + (row * cols) + col],
                imag: 0.0,
            }
        }
        ImfilterPadding::Replicate => {
            let row = row.clamp(0, rows as isize - 1) as usize;
            let col = col.clamp(0, cols as isize - 1) as usize;
            let page = page.clamp(0, pages as isize - 1) as usize;
            ComplexParts {
                real: values[(page * rows * cols) + (row * cols) + col],
                imag: 0.0,
            }
        }
        ImfilterPadding::Circular => {
            let row = row.rem_euclid(rows as isize) as usize;
            let col = col.rem_euclid(cols as isize) as usize;
            let page = page.rem_euclid(pages as isize) as usize;
            ComplexParts {
                real: values[(page * rows * cols) + (row * cols) + col],
                imag: 0.0,
            }
        }
    }
}

fn rounded_integer_output_value(value: f64, class: IntegerClass) -> Value {
    saturating_integer_value(class, scalar_to_integer_raw(value.round(), class))
}

fn parse_padarray_pad_size(value: &Value) -> Result<Vec<usize>, RuntimeError> {
    let values = meshgrid_vector(value)?;
    if values.is_empty() {
        return Err(RuntimeError::ShapeError(
            "padarray currently expects a nonempty padsize vector".to_string(),
        ));
    }
    values
        .into_iter()
        .map(|value| {
            if !value.is_finite() || value < 0.0 || value.fract() != 0.0 {
                return Err(RuntimeError::TypeError(
                    "padarray currently expects padsize to contain nonnegative integers"
                        .to_string(),
                ));
            }
            Ok(value as usize)
        })
        .collect()
}

fn parse_padarray_pad_value(value: &Value) -> Result<PadarrayPadValue, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => match text.to_ascii_lowercase().as_str() {
            "replicate" => Ok(PadarrayPadValue::Replicate),
            "symmetric" => Ok(PadarrayPadValue::Symmetric),
            "circular" => Ok(PadarrayPadValue::Circular),
            _ => Err(RuntimeError::Unsupported(
                "padarray currently supports only numeric, `replicate`, `symmetric`, or `circular` pad values"
                    .to_string(),
            )),
        },
        _ => {
            let value = value.as_scalar()?;
            if !value.is_finite() {
                return Err(RuntimeError::TypeError(
                    "padarray currently expects a finite numeric scalar pad value".to_string(),
                ));
            }
            Ok(PadarrayPadValue::Constant(value))
        }
    }
}

fn parse_padarray_direction(value: &Value) -> Result<PadarrayDirection, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "both" => Ok(PadarrayDirection::Both),
        "pre" => Ok(PadarrayDirection::Pre),
        "post" => Ok(PadarrayDirection::Post),
        _ => Err(RuntimeError::Unsupported(
            "padarray currently supports only `both`, `pre`, or `post` directions".to_string(),
        )),
    }
}

fn padarray_input(value: &Value) -> Result<(Vec<usize>, Vec<Value>, Value), RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Int64(_) | Value::UInt64(_) | Value::Logical(_) => {
            Ok((value_dimensions(value), vec![value.clone()], value.clone()))
        }
        Value::Matrix(matrix)
            if matrix_is_numeric(matrix)
                || matrix_is_logical(matrix)
                || integer_operand(value).is_some() =>
        {
            Ok((
                value_dimensions(value),
                matrix.elements().to_vec(),
                matrix
                    .elements()
                    .first()
                    .cloned()
                    .unwrap_or(Value::Scalar(0.0)),
            ))
        }
        other => Err(RuntimeError::TypeError(format!(
            "padarray currently expects numeric or logical scalar/matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn typed_padarray_value(prototype: &Value, value: f64) -> Value {
    match prototype {
        Value::Logical(_) => Value::Logical(value != 0.0),
        Value::Int64(_) => saturating_integer_value(
            IntegerClass::Int64,
            scalar_to_integer_raw(value, IntegerClass::Int64),
        ),
        Value::UInt64(_) => saturating_integer_value(
            IntegerClass::UInt64,
            scalar_to_integer_raw(value, IntegerClass::UInt64),
        ),
        _ => Value::Scalar(value),
    }
}

fn padarray_output_dims(
    input_dims: &[usize],
    pad_size: &[usize],
    direction: PadarrayDirection,
) -> Vec<usize> {
    input_dims
        .iter()
        .zip(pad_size.iter())
        .map(|(dim, pad)| match direction {
            PadarrayDirection::Both => dim + 2 * pad,
            PadarrayDirection::Pre | PadarrayDirection::Post => dim + pad,
        })
        .collect()
}

fn padarray_source_index(
    output_index: &[usize],
    input_dims: &[usize],
    pad_size: &[usize],
    direction: PadarrayDirection,
) -> Option<Vec<usize>> {
    let mut source = Vec::with_capacity(output_index.len());
    for axis in 0..output_index.len() {
        let candidate = match direction {
            PadarrayDirection::Both | PadarrayDirection::Pre => {
                output_index[axis] as isize - pad_size[axis] as isize
            }
            PadarrayDirection::Post => output_index[axis] as isize,
        };
        if candidate < 0 || candidate >= input_dims[axis] as isize {
            return None;
        }
        source.push(candidate as usize);
    }
    Some(source)
}

fn padarray_boundary_index(
    output_index: &[usize],
    input_dims: &[usize],
    pad_size: &[usize],
    direction: PadarrayDirection,
    map_axis: impl Fn(isize, usize) -> usize,
) -> Vec<usize> {
    (0..output_index.len())
        .map(|axis| {
            let candidate = match direction {
                PadarrayDirection::Both | PadarrayDirection::Pre => {
                    output_index[axis] as isize - pad_size[axis] as isize
                }
                PadarrayDirection::Post => output_index[axis] as isize,
            };
            map_axis(candidate, input_dims[axis])
        })
        .collect()
}

