fn builtin_strlength(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "strlength currently supports exactly one argument".to_string(),
        ));
    };

    if let Value::Cell(cell) = value {
        let lengths = cell
            .elements
            .iter()
            .map(|element| Ok(text_value(element)?.chars().count() as f64))
            .collect::<Result<Vec<_>, RuntimeError>>()?;
        if cell.rows == 1 && cell.cols == 1 && lengths.len() == 1 {
            return Ok(Value::Scalar(lengths[0]));
        }
        return numeric_matrix_result_with_dimensions(canonical_size_vector(&cell.dims), lengths);
    }

    map_text_unary_numeric(value, |text| text.chars().count() as f64)
}

