fn builtin_dec2bin(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, min_digits) = match args {
        [value] => (value, 0usize),
        [value, min_digits] => (value, base_conversion_min_digits(min_digits, "dec2bin")?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "dec2bin currently supports `dec2bin(d)` or `dec2bin(d, n)`".to_string(),
            ))
        }
    };
    builtin_decimal_to_base(value, 2, min_digits, "dec2bin")
}

fn builtin_dec2base(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, base, min_digits) = match args {
        [value, base] => (value, base_conversion_radix(base, "dec2base")?, 0usize),
        [value, base, min_digits] => (
            value,
            base_conversion_radix(base, "dec2base")?,
            base_conversion_min_digits(min_digits, "dec2base")?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "dec2base currently supports `dec2base(d, base)` or `dec2base(d, base, n)`"
                    .to_string(),
            ))
        }
    };
    builtin_decimal_to_base(value, base, min_digits, "dec2base")
}

fn builtin_base_text_to_double_value(
    value: &Value,
    base: u32,
    builtin_name: &str,
    allow_signed_suffix: bool,
) -> Result<Value, RuntimeError> {
    let (values, dims) = base_text_operand(value, builtin_name)?;
    let parts = values
        .iter()
        .map(|text| parse_base_text_value(text, base, builtin_name, allow_signed_suffix))
        .collect::<Result<Vec<_>, RuntimeError>>()?;
    build_scalar_matrix_result_with_dimensions(dims, parts.into_iter().map(Value::Scalar).collect())
}

fn base_text_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<String>, Vec<usize>), RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => Ok((vec![text.clone()], vec![1, 1])),
        Value::Matrix(matrix) if matrix_is_text(matrix) => Ok((
            matrix
                .elements()
                .iter()
                .map(|element| text_value(element).map(str::to_string))
                .collect::<Result<Vec<_>, _>>()?,
            canonical_size_vector(matrix.dims()),
        )),
        Value::Cell(cell) => Ok((
            cell.elements()
                .iter()
                .map(|element| match element {
                    Value::CharArray(text) | Value::String(text) => Ok(text.clone()),
                    other => Err(RuntimeError::TypeError(format!(
                        "{builtin_name} currently expects cell array inputs to contain char or string values, found {}",
                        other.kind_name()
                    ))),
                })
                .collect::<Result<Vec<_>, _>>()?,
            canonical_size_vector(cell.dims()),
        )),
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects text scalars, text arrays, or cell arrays of text, found {}",
            other.kind_name()
        ))),
    }
}

fn parse_base_text_value(
    text: &str,
    base: u32,
    builtin_name: &str,
    allow_signed_suffix: bool,
) -> Result<f64, RuntimeError> {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects nonempty text values"
        )));
    }

    let lower = trimmed.to_ascii_lowercase();
    let without_prefix = match base {
        16 => lower.strip_prefix("0x").unwrap_or(&lower),
        2 => lower.strip_prefix("0b").unwrap_or(&lower),
        _ => &lower,
    };
    let (digits, signed_bits) = if allow_signed_suffix {
        parse_base_literal_suffix(without_prefix, base, builtin_name)?
    } else {
        (without_prefix, None)
    };
    if digits.is_empty() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects at least one base-{base} digit"
        )));
    }
    let unsigned = u64::from_str_radix(digits, base).map_err(|error| {
        RuntimeError::TypeError(format!(
            "{builtin_name} could not parse `{text}` as a base-{base} integer: {error}"
        ))
    })?;

    if let Some(bits) = signed_bits {
        if bits == 0 || bits > 64 {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} signed suffix width `{bits}` is not supported"
            )));
        }
        let sign_bit = 1u64 << (bits - 1);
        let mask = if bits == 64 {
            u64::MAX
        } else {
            (1u64 << bits) - 1
        };
        let value = unsigned & mask;
        if value & sign_bit != 0 {
            let signed = (value as i128) - ((mask as i128) + 1);
            Ok(signed as f64)
        } else {
            Ok(value as f64)
        }
    } else {
        Ok(unsigned as f64)
    }
}

fn parse_base_literal_suffix<'a>(
    text: &'a str,
    base: u32,
    builtin_name: &str,
) -> Result<(&'a str, Option<u32>), RuntimeError> {
    let Some(suffix_index) = text.find(['s', 'u']) else {
        return Ok((text, None));
    };
    let (digits, suffix) = text.split_at(suffix_index);
    if digits.is_empty() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects at least one base-{base} digit"
        )));
    }
    let signed = suffix.starts_with('s');
    let bits = suffix[1..].parse::<u32>().map_err(|error| {
        RuntimeError::TypeError(format!(
            "{builtin_name} could not parse signedness suffix `{suffix}`: {error}"
        ))
    })?;
    if signed {
        Ok((digits, Some(bits)))
    } else {
        Ok((digits, None))
    }
}

fn base_conversion_radix(value: &Value, builtin_name: &str) -> Result<u32, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects an integer scalar base"
        )));
    }
    if !(2.0..=36.0).contains(&scalar) {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports bases from 2 through 36"
        )));
    }
    Ok(scalar as u32)
}

fn base_conversion_min_digits(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    nonnegative_integer_scalar_with_label(
        value,
        builtin_name,
        "a nonnegative integer minimum digit count",
    )
}

fn builtin_decimal_to_base(
    value: &Value,
    base: u32,
    min_digits: usize,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let (numbers, dims) = decimal_base_operand(value, builtin_name)?;
    let mut rendered = numbers
        .into_iter()
        .map(|number| format_unsigned_integer_in_base(number, base))
        .collect::<Vec<_>>();
    let width = rendered
        .iter()
        .map(|text| text.chars().count())
        .max()
        .unwrap_or(0)
        .max(min_digits);
    for text in &mut rendered {
        if text.chars().count() < width {
            *text = format!("{}{}", "0".repeat(width - text.chars().count()), text);
        }
    }

    let (rows, cols) = storage_shape_from_dimensions(&dims);
    if rows == 1 && cols == 1 && rendered.len() == 1 {
        return Ok(Value::CharArray(rendered.into_iter().next().unwrap()));
    }

    build_text_result_with_dimensions(
        dims,
        rendered,
        vec![TextPrototype::String; rows * cols],
        false,
    )
}

fn decimal_base_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<u64>, Vec<usize>), RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) => Ok((
            vec![decimal_base_scalar(value, builtin_name)?],
            vec![1, 1],
        )),
        Value::Matrix(matrix) if matrix_is_numeric(matrix) || matrix_is_logical(matrix) => Ok((
            matrix
                .elements()
                .iter()
                .map(|element| decimal_base_scalar(element, builtin_name))
                .collect::<Result<Vec<_>, _>>()?,
            canonical_size_vector(matrix.dims()),
        )),
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects real numeric or logical scalar/matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn decimal_base_scalar(value: &Value, builtin_name: &str) -> Result<u64, RuntimeError> {
    let scalar = real_numeric_scalar(value, builtin_name)?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects nonnegative integer-valued real numeric or logical inputs"
        )));
    }
    if scalar > u64::MAX as f64 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently received an out-of-range integer value {scalar}"
        )));
    }
    Ok(scalar as u64)
}

fn format_unsigned_integer_in_base(mut value: u64, base: u32) -> String {
    const DIGITS: &[u8; 36] = b"0123456789ABCDEFGHIJKLMNOPQRSTUVWXYZ";
    if value == 0 {
        return "0".to_string();
    }

    let mut rendered = Vec::new();
    let radix = u64::from(base);
    while value > 0 {
        rendered.push(DIGITS[(value % radix) as usize] as char);
        value /= radix;
    }
    rendered.into_iter().rev().collect()
}

fn builtin_mat2str(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, precision) = match args {
        [value] => (value, None),
        [value, precision] => (value, Some(mat2str_precision(precision)?)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "mat2str currently supports `mat2str(x)` or `mat2str(x, n)`".to_string(),
            ))
        }
    };

    let text = match value {
        Value::Scalar(number) => mat2str_number(*number, precision),
        Value::Logical(flag) => render_logical(*flag),
        Value::Complex(number) => mat2str_complex(number.real, number.imag, precision),
        Value::Matrix(matrix)
            if matrix_is_numeric_or_complex(matrix) || matrix_is_logical(matrix) =>
        {
            if canonical_size_vector(matrix.dims()).len() > 2 {
                return Err(RuntimeError::Unsupported(
                    "mat2str currently expects scalar or 2-D numeric/logical/complex input"
                        .to_string(),
                ));
            }
            mat2str_matrix(matrix, precision)?
        }
        other => {
            return Err(RuntimeError::TypeError(format!(
            "mat2str currently expects numeric, logical, or complex scalar/matrix input, found {}",
            other.kind_name()
        )))
        }
    };
    Ok(Value::CharArray(text))
}

fn mat2str_precision(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 || scalar < 0.0 {
        return Err(RuntimeError::TypeError(
            "mat2str precision currently expects a nonnegative integer scalar".to_string(),
        ));
    }
    Ok(scalar as usize)
}

fn mat2str_matrix(matrix: &MatrixValue, precision: Option<usize>) -> Result<String, RuntimeError> {
    if matrix.rows == 0 || matrix.cols == 0 {
        return Ok("[]".to_string());
    }

    let rows = (0..matrix.rows)
        .map(|row| {
            (0..matrix.cols)
                .map(|col| mat2str_element(matrix.get(row, col), precision))
                .collect::<Result<Vec<_>, _>>()
                .map(|parts| parts.join(" "))
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok(format!("[{}]", rows.join(";")))
}

fn mat2str_element(value: &Value, precision: Option<usize>) -> Result<String, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(mat2str_number(*number, precision)),
        Value::Logical(flag) => Ok(render_logical(*flag)),
        Value::Complex(number) => Ok(mat2str_complex(number.real, number.imag, precision)),
        other => Err(RuntimeError::TypeError(format!(
            "mat2str currently expects numeric, logical, or complex matrix elements, found {}",
            other.kind_name()
        ))),
    }
}

fn mat2str_number(number: f64, precision: Option<usize>) -> String {
    if number.is_nan() {
        return "NaN".to_string();
    }
    if number == f64::INFINITY {
        return "Inf".to_string();
    }
    if number == f64::NEG_INFINITY {
        return "-Inf".to_string();
    }
    match precision {
        Some(precision) => format_general(number, precision.max(1), false, FormatFlags::default()),
        None => format_general(number, 15, false, FormatFlags::default()),
    }
}

fn mat2str_complex(real: f64, imag: f64, precision: Option<usize>) -> String {
    if imag == 0.0 {
        return mat2str_number(real, precision);
    }
    if real == 0.0 {
        return format!("{}i", mat2str_number(imag, precision));
    }

    let sign = if imag.is_sign_negative() { "-" } else { "+" };
    format!(
        "{}{}{}i",
        mat2str_number(real, precision),
        sign,
        mat2str_number(imag.abs(), precision)
    )
}

fn builtin_upper(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "upper currently supports exactly one argument".to_string(),
        ));
    };
    map_text_value(value, |text| text.to_uppercase())
}

fn builtin_lower(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "lower currently supports exactly one argument".to_string(),
        ));
    };
    map_text_value(value, |text| text.to_lowercase())
}

fn builtin_starts_with(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, patterns, ignore_case) = parse_text_search_args(args, "startsWith")?;
    map_text_value_logical(value, |value| {
        text_matches_any_pattern(value, &patterns, ignore_case, |value, pattern| {
            value.starts_with(pattern)
        })
    })
}

fn builtin_ends_with(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, patterns, ignore_case) = parse_text_search_args(args, "endsWith")?;
    map_text_value_logical(value, |value| {
        text_matches_any_pattern(value, &patterns, ignore_case, |value, pattern| {
            value.ends_with(pattern)
        })
    })
}

fn builtin_append(args: &[Value]) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Err(RuntimeError::Unsupported(
            "append currently expects at least one argument".to_string(),
        ));
    }

    map_text_variadic(args, true)
}

fn builtin_erase(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, pattern] = args else {
        return Err(RuntimeError::Unsupported(
            "erase currently supports exactly two arguments".to_string(),
        ));
    };

    let (patterns, _prototypes) = text_sequence_parts(pattern, "erase")?;
    map_text_value(value, |text| {
        apply_text_replacements(text, &patterns, &vec![String::new(); patterns.len()])
    })
}

fn builtin_replace(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, pattern, replacement] = args else {
        return Err(RuntimeError::Unsupported(
            "replace currently supports exactly three arguments".to_string(),
        ));
    };

    let (patterns, _prototypes) = text_sequence_parts(pattern, "replace")?;
    let (replacements, _replacement_prototypes) = text_sequence_parts(replacement, "replace")?;
    if replacements.len() != 1 && replacements.len() != patterns.len() {
        return Err(RuntimeError::ShapeError(
            "replace currently expects the replacement text to be scalar or match the number of patterns"
                .to_string(),
        ));
    }
    let replacements = if replacements.len() == 1 && patterns.len() > 1 {
        vec![replacements[0].clone(); patterns.len()]
    } else {
        replacements
    };
    map_text_value(value, |text| {
        apply_text_replacements(text, &patterns, &replacements)
    })
}

fn builtin_strrep(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, old, new] = args else {
        return Err(RuntimeError::Unsupported(
            "strrep currently supports exactly three arguments".to_string(),
        ));
    };
    map_text_ternary_text(value, old, new, |text, old, new| {
        Ok(apply_strrep(text, old, new))
    })
}

fn builtin_strcat(args: &[Value]) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Err(RuntimeError::Unsupported(
            "strcat currently expects at least one argument".to_string(),
        ));
    }

    map_text_variadic(args, false)
}

fn builtin_split_outputs(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (value, delimiter, dim) = match args {
        [value] => (value, None, None),
        [value, delimiter] => (value, Some(delimiter), None),
        [value, delimiter, dim] => (value, Some(delimiter), Some(positive_dimension(dim, "split")?)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "split currently supports `split(str)`, `split(str, delimiter)`, or `split(str, delimiter, dim)`"
                    .to_string(),
            ))
        }
    };

    let (operand, input_dims) = split_text_operand(value)?;
    let split_dim =
        dim.unwrap_or_else(|| default_split_dimension(&input_dims, operand.values.len()));
    let delimiter = parse_split_delimiter(delimiter)?;

    let split_results = operand
        .values
        .iter()
        .map(|text| split_text_parts_and_matches(text, &delimiter))
        .collect::<Result<Vec<_>, _>>()?;
    let split_parts = split_results
        .iter()
        .map(|(parts, _)| parts.clone())
        .collect::<Vec<_>>();
    let split_count = split_parts.first().map(|parts| parts.len()).unwrap_or(0);
    if split_parts.iter().any(|parts| parts.len() != split_count) {
        return Err(RuntimeError::ShapeError(
            "split currently expects every input element to produce the same number of substrings"
                .to_string(),
        ));
    }

    let parts_output =
        build_split_text_output(operand.clone(), input_dims.clone(), split_dim, split_parts)?;
    match output_arity {
        0 | 1 => Ok(vec![parts_output]),
        2 => {
            let match_parts = split_results
                .into_iter()
                .map(|(_, matches)| matches)
                .collect::<Vec<_>>();
            let matches_output =
                build_split_text_output(operand, input_dims, split_dim, match_parts)?;
            Ok(vec![parts_output, matches_output])
        }
        _ => Err(RuntimeError::Unsupported(
            "split currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_split(args: &[Value]) -> Result<Value, RuntimeError> {
    first_output_or_error(builtin_split_outputs(args, 1)?)
}

fn split_text_operand(value: &Value) -> Result<(TextOperand, Vec<usize>), RuntimeError> {
    match value {
        Value::Cell(cell) => {
            let mut values = Vec::with_capacity(cell.elements.len());
            let mut prototypes = Vec::with_capacity(cell.elements.len());
            for element in &cell.elements {
                let Some(prototype) = text_prototype(element) else {
                    return Err(RuntimeError::TypeError(
                        "split currently expects cell array inputs to contain char or string values"
                            .to_string(),
                    ));
                };
                values.push(text_value(element)?.to_string());
                prototypes.push(prototype);
            }
            Ok((
                TextOperand {
                    rows: cell.rows,
                    cols: cell.cols,
                    values,
                    prototypes,
                },
                canonical_size_vector(&cell.dims),
            ))
        }
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            Ok((text_operand(value)?, canonical_size_vector(&matrix.dims)))
        }
        _ => {
            let operand = text_operand(value)?;
            Ok((operand.clone(), vec![operand.rows, operand.cols]))
        }
    }
}

fn builtin_splitlines(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "splitlines currently supports exactly one argument".to_string(),
        ));
    };

    let (operand, input_dims) = split_text_operand(value)?;
    let split_dim = default_split_dimension(&input_dims, operand.values.len());
    let split_parts = operand
        .values
        .iter()
        .map(|text| splitlines_parts(text))
        .collect::<Vec<_>>();
    let split_count = split_parts.first().map(|parts| parts.len()).unwrap_or(0);
    if split_parts.iter().any(|parts| parts.len() != split_count) {
        return Err(RuntimeError::ShapeError(
            "splitlines currently expects every input element to produce the same number of lines"
                .to_string(),
        ));
    }
    build_split_text_output(operand, input_dims, split_dim, split_parts)
}

fn parse_split_delimiter(delimiter: Option<&Value>) -> Result<SplitDelimiterSpec, RuntimeError> {
    match delimiter {
        None => Ok(SplitDelimiterSpec::Whitespace),
        Some(value) => {
            let (delimiters, _prototypes) = text_sequence_parts(value, "split delimiter")?;
            if delimiters.iter().any(|delimiter| delimiter.is_empty()) {
                return Err(RuntimeError::Unsupported(
                    "split does not yet support an empty delimiter".to_string(),
                ));
            }
            Ok(SplitDelimiterSpec::Literals(delimiters))
        }
    }
}

fn split_text_parts_and_matches(
    text: &str,
    delimiter: &SplitDelimiterSpec,
) -> Result<(Vec<String>, Vec<String>), RuntimeError> {
    Ok(match delimiter {
        SplitDelimiterSpec::Whitespace => split_text_on_whitespace(text),
        SplitDelimiterSpec::Literals(delimiters) => {
            split_text_with_multiple_delimiters(text, delimiters)
        }
        SplitDelimiterSpec::RegularExpressions(_) => {
            return Err(RuntimeError::Unsupported(
                "split currently supports only literal delimiters".to_string(),
            ))
        }
    })
}

fn strsplit_parts_and_matches(
    text: &str,
    delimiter: &SplitDelimiterSpec,
    collapse_delimiters: bool,
) -> Result<(Vec<String>, Vec<String>), RuntimeError> {
    Ok(match (delimiter, collapse_delimiters) {
        (SplitDelimiterSpec::Whitespace, true) => split_text_on_whitespace_collapsed(text),
        (SplitDelimiterSpec::Whitespace, false) => split_text_on_whitespace(text),
        (SplitDelimiterSpec::Literals(delimiters), true) => {
            split_text_with_multiple_delimiters_collapsed(text, delimiters)
        }
        (SplitDelimiterSpec::Literals(delimiters), false) => {
            split_text_with_multiple_delimiters(text, delimiters)
        }
        (SplitDelimiterSpec::RegularExpressions(delimiters), true) => {
            split_text_with_multiple_regex_delimiters(text, delimiters, true)
        }
        (SplitDelimiterSpec::RegularExpressions(delimiters), false) => {
            split_text_with_multiple_regex_delimiters(text, delimiters, false)
        }
    })
}

fn split_text_on_whitespace(text: &str) -> (Vec<String>, Vec<String>) {
    let mut parts = Vec::new();
    let mut matches = Vec::new();
    let mut current = String::new();
    for ch in text.chars() {
        if ch.is_whitespace() {
            parts.push(current);
            current = String::new();
            matches.push(ch.to_string());
        } else {
            current.push(ch);
        }
    }
    parts.push(current);
    (parts, matches)
}

fn split_text_on_whitespace_collapsed(text: &str) -> (Vec<String>, Vec<String>) {
    let mut parts = Vec::new();
    let mut matches = Vec::new();
    let mut current = String::new();
    let mut whitespace = String::new();

    for ch in text.chars() {
        if ch.is_whitespace() {
            whitespace.push(ch);
            continue;
        }
        if !whitespace.is_empty() {
            parts.push(current);
            current = String::new();
            matches.push(std::mem::take(&mut whitespace));
        }
        current.push(ch);
    }

    if !whitespace.is_empty() {
        parts.push(current);
        current = String::new();
        matches.push(whitespace);
    }
    parts.push(current);
    (parts, matches)
}

fn split_text_with_multiple_delimiters(
    text: &str,
    delimiters: &[String],
) -> (Vec<String>, Vec<String>) {
    if delimiters.is_empty() {
        return (vec![text.to_string()], Vec::new());
    }

    let mut parts = Vec::new();
    let mut matches = Vec::new();
    let mut current = String::new();
    let mut index = 0usize;
    while index < text.len() {
        let remaining = &text[index..];
        if let Some(delimiter) = delimiters
            .iter()
            .find(|delimiter| remaining.starts_with(delimiter.as_str()))
        {
            parts.push(current);
            current = String::new();
            matches.push(delimiter.clone());
            index += delimiter.len();
            continue;
        }

        let ch = remaining
            .chars()
            .next()
            .expect("remaining slice has a char");
        current.push(ch);
        index += ch.len_utf8();
    }
    parts.push(current);
    (parts, matches)
}

fn split_text_with_multiple_delimiters_collapsed(
    text: &str,
    delimiters: &[String],
) -> (Vec<String>, Vec<String>) {
    if delimiters.is_empty() {
        return (vec![text.to_string()], Vec::new());
    }

    let mut parts = Vec::new();
    let mut matches = Vec::new();
    let mut current = String::new();
    let mut index = 0usize;
    while index < text.len() {
        let remaining = &text[index..];
        if let Some(delimiter) = delimiters
            .iter()
            .find(|delimiter| remaining.starts_with(delimiter.as_str()))
        {
            parts.push(current);
            current = String::new();
            let mut collapsed = delimiter.clone();
            index += delimiter.len();

            while index < text.len() {
                let remaining = &text[index..];
                if let Some(next_delimiter) = delimiters
                    .iter()
                    .find(|delimiter| remaining.starts_with(delimiter.as_str()))
                {
                    collapsed.push_str(next_delimiter);
                    index += next_delimiter.len();
                } else {
                    break;
                }
            }

            matches.push(collapsed);
            continue;
        }

        let ch = remaining
            .chars()
            .next()
            .expect("remaining slice has a char");
        current.push(ch);
        index += ch.len_utf8();
    }
    parts.push(current);
    (parts, matches)
}

fn split_text_with_multiple_regex_delimiters(
    text: &str,
    delimiters: &[Regex],
    collapse_delimiters: bool,
) -> (Vec<String>, Vec<String>) {
    if delimiters.is_empty() {
        return (vec![text.to_string()], Vec::new());
    }

    let mut parts = Vec::new();
    let mut matches = Vec::new();
    let mut current = String::new();
    let mut index = 0usize;
    while index < text.len() {
        let remaining = &text[index..];
        if let Some(delimiter) = regex_delimiter_match_at_start(remaining, delimiters) {
            parts.push(current);
            current = String::new();
            index += delimiter.len();
            if collapse_delimiters {
                let mut collapsed = delimiter;
                while index < text.len() {
                    let remaining = &text[index..];
                    if let Some(next_delimiter) =
                        regex_delimiter_match_at_start(remaining, delimiters)
                    {
                        index += next_delimiter.len();
                        collapsed.push_str(&next_delimiter);
                    } else {
                        break;
                    }
                }
                matches.push(collapsed);
            } else {
                matches.push(delimiter);
            }
            continue;
        }

        let ch = remaining
            .chars()
            .next()
            .expect("remaining slice has a char");
        current.push(ch);
        index += ch.len_utf8();
    }
    parts.push(current);
    (parts, matches)
}

fn regex_delimiter_match_at_start(text: &str, delimiters: &[Regex]) -> Option<String> {
    delimiters.iter().find_map(|delimiter| {
        delimiter.find(text).and_then(|matched| {
            (matched.start() == 0 && matched.end() > 0).then(|| matched.as_str().to_string())
        })
    })
}

fn splitlines_parts(text: &str) -> Vec<String> {
    text.replace("\r\n", "\n")
        .replace('\r', "\n")
        .split('\n')
        .map(|part| part.to_string())
        .collect()
}

fn strtok_parts(text: &str, delimiters: &Option<Vec<char>>) -> (String, String) {
    let chars = text.chars().collect::<Vec<_>>();
    let is_delimiter = |ch: char| match delimiters {
        Some(delimiters) => delimiters.contains(&ch),
        None => ch.is_whitespace(),
    };

    let mut start = 0usize;
    while start < chars.len() && is_delimiter(chars[start]) {
        start += 1;
    }
    if start >= chars.len() {
        return (String::new(), String::new());
    }

    let mut end = start;
    while end < chars.len() && !is_delimiter(chars[end]) {
        end += 1;
    }

    let token = chars[start..end].iter().collect::<String>();
    let remain = chars[end..].iter().collect::<String>();
    (token, remain)
}

fn default_split_dimension(input_dims: &[usize], element_count: usize) -> usize {
    if element_count <= 1 {
        return 1;
    }
    let canonical = canonical_size_vector(input_dims);
    let last = canonical.last().copied().unwrap_or(1);
    if last == 1 {
        canonical.len()
    } else {
        canonical.len() + 1
    }
}

fn split_output_dimensions(input_dims: &[usize], dim: usize, split_count: usize) -> Vec<usize> {
    let mut dims = canonical_size_vector(input_dims);
    while dims.len() < dim.saturating_sub(1) {
        dims.push(1);
    }
    dims.insert(dim - 1, split_count);
    canonical_size_vector(&dims)
}

fn split_output_linear_index(
    input_index: &[usize],
    dim: usize,
    part_index: usize,
    output_dims: &[usize],
) -> usize {
    let mut output_index = input_index.to_vec();
    while output_index.len() < dim.saturating_sub(1) {
        output_index.push(0);
    }
    output_index.insert(dim - 1, part_index);
    while output_index.len() > output_dims.len() {
        output_index.pop();
    }
    row_major_linear_index(&output_index, output_dims)
}

fn build_split_text_output(
    operand: TextOperand,
    input_dims: Vec<usize>,
    split_dim: usize,
    split_parts: Vec<Vec<String>>,
) -> Result<Value, RuntimeError> {
    let split_count = split_parts.first().map(|parts| parts.len()).unwrap_or(0);
    let output_dims = split_output_dimensions(&input_dims, split_dim, split_count);
    let element_count = output_dims.iter().product::<usize>();
    if operand
        .prototypes
        .iter()
        .all(|prototype| *prototype == TextPrototype::Char)
    {
        let mut elements = vec![Value::CharArray(String::new()); element_count];
        for (input_linear, parts) in split_parts.into_iter().enumerate() {
            let input_index = row_major_multi_index(input_linear, &input_dims);
            for (part_index, part) in parts.into_iter().enumerate() {
                let linear =
                    split_output_linear_index(&input_index, split_dim, part_index, &output_dims);
                elements[linear] = Value::CharArray(part);
            }
        }
        let (rows, cols) = storage_shape_from_dimensions(&output_dims);
        return Ok(Value::Cell(CellValue::with_dimensions(
            rows,
            cols,
            output_dims,
            elements,
        )?));
    }

    let mut elements = vec![Value::String(String::new()); element_count];
    for (input_linear, parts) in split_parts.into_iter().enumerate() {
        let input_index = row_major_multi_index(input_linear, &input_dims);
        for (part_index, part) in parts.into_iter().enumerate() {
            let linear =
                split_output_linear_index(&input_index, split_dim, part_index, &output_dims);
            elements[linear] = Value::String(part);
        }
    }
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        output_dims,
        elements,
    )?))
}

fn builtin_strip(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "strip currently supports exactly one argument".to_string(),
        ));
    };

    map_text_value(value, |text| text.trim().to_string())
}

fn builtin_strtrim(args: &[Value]) -> Result<Value, RuntimeError> {
    builtin_strip(args)
}

fn builtin_deblank(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "deblank currently supports exactly one argument".to_string(),
        ));
    };

    map_text_value(value, |text| text.trim_end().to_string())
}

fn builtin_strjoin(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, delimiter) = match args {
        [value] => (value, " "),
        [value, delimiter] => (value, text_value(delimiter)?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "strjoin currently supports `strjoin(str)` or `strjoin(str, delimiter)`"
                    .to_string(),
            ))
        }
    };
    strjoin_value(value, delimiter, "strjoin")
}

fn builtin_strsplit_outputs(
    args: &[Value],
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (value, delimiter, collapse_delimiters) = parse_strsplit_arguments(args)?;
    let (parts, matches) =
        strsplit_parts_and_matches(text_value(value)?, &delimiter, collapse_delimiters)?;
    let part_count = parts.len();
    let match_count = matches.len();

    let (parts_output, matches_output) = match value {
        Value::CharArray(_) => (
            build_text_result_with_dimensions(
                vec![1, part_count],
                parts,
                vec![TextPrototype::Char; part_count],
                true,
            )?,
            build_text_result_with_dimensions(
                vec![1, match_count],
                matches,
                vec![TextPrototype::Char; match_count],
                true,
            )?,
        ),
        Value::String(_) => (
            build_text_result_with_dimensions(
                vec![1, part_count],
                parts,
                vec![TextPrototype::String; part_count],
                false,
            )?,
            build_text_result_with_dimensions(
                vec![1, match_count],
                matches,
                vec![TextPrototype::String; match_count],
                false,
            )?,
        ),
        other => {
            return Err(RuntimeError::TypeError(format!(
                "strsplit currently expects a character vector or string scalar input, found {}",
                other.kind_name()
            )))
        }
    };

    match output_arity {
        0 | 1 => Ok(vec![parts_output]),
        2 => Ok(vec![parts_output, matches_output]),
        _ => Err(RuntimeError::Unsupported(
            "strsplit currently supports one or two outputs".to_string(),
        )),
    }
}

#[derive(Clone, Copy)]
enum StrsplitDelimiterType {
    Simple,
    RegularExpression,
}

fn builtin_strtok_outputs(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let [value, delimiter @ ..] = args else {
        return Err(RuntimeError::Unsupported(
            "strtok currently supports `strtok(str)` or `strtok(str, delimiter)`".to_string(),
        ));
    };
    if delimiter.len() > 1 {
        return Err(RuntimeError::Unsupported(
            "strtok currently supports at most one delimiter argument".to_string(),
        ));
    }
    let delimiters = parse_strtok_delimiters(delimiter.first())?;
    let (operand, input_dims) = split_text_operand(value)?;
    let cell_array_output = matches!(value, Value::Cell(_));
    let mut tokens = Vec::with_capacity(operand.values.len());
    let mut remains = Vec::with_capacity(operand.values.len());
    for text in &operand.values {
        let (token, remain) = strtok_parts(text, &delimiters);
        tokens.push(token);
        remains.push(remain);
    }

    let token_value = build_text_result_with_dimensions(
        input_dims.clone(),
        tokens,
        operand.prototypes.clone(),
        cell_array_output,
    )?;
    let remain_value = build_text_result_with_dimensions(
        input_dims,
        remains,
        operand.prototypes,
        cell_array_output,
    )?;
    match output_arity {
        0 | 1 => Ok(vec![token_value]),
        2 => Ok(vec![token_value, remain_value]),
        _ => Err(RuntimeError::Unsupported(
            "strtok currently supports one or two outputs".to_string(),
        )),
    }
}

fn parse_strsplit_arguments(
    args: &[Value],
) -> Result<(&Value, SplitDelimiterSpec, bool), RuntimeError> {
    let Some((value, rest)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "strsplit currently supports `strsplit(str)`, `strsplit(str, delimiter)`, and common name/value forms"
                .to_string(),
        ));
    };

    let mut collapse_delimiters = true;
    let mut delimiter = None;
    let mut delimiter_type = StrsplitDelimiterType::Simple;
    let mut index = 0usize;
    while index < rest.len() {
        let remaining = rest.len() - index;
        if remaining >= 2 {
            if let Ok(option_name) = text_value(&rest[index]) {
                if option_name.eq_ignore_ascii_case("CollapseDelimiters") {
                    collapse_delimiters =
                        parse_ignore_case_flag(&rest[index + 1], "strsplit CollapseDelimiters")?;
                    index += 2;
                    continue;
                }
                if option_name.eq_ignore_ascii_case("DelimiterType") {
                    let delimiter_type_name = text_value(&rest[index + 1])?;
                    if delimiter_type_name.eq_ignore_ascii_case("Simple") {
                        delimiter_type = StrsplitDelimiterType::Simple;
                    } else if delimiter_type_name.eq_ignore_ascii_case("RegularExpression") {
                        delimiter_type = StrsplitDelimiterType::RegularExpression;
                    } else {
                        return Err(RuntimeError::Unsupported(format!(
                            "strsplit DelimiterType `{delimiter_type_name}` is not implemented; expected Simple or RegularExpression"
                        )));
                    }
                    index += 2;
                    continue;
                }
            }
        }

        if delimiter.is_none() {
            delimiter = Some(&rest[index]);
            index += 1;
            continue;
        }

        return Err(RuntimeError::Unsupported(
            "strsplit currently supports one delimiter plus common name/value options".to_string(),
        ));
    }

    Ok((
        value,
        parse_strsplit_delimiter(delimiter, delimiter_type)?,
        collapse_delimiters,
    ))
}

fn parse_strsplit_delimiter(
    delimiter: Option<&Value>,
    delimiter_type: StrsplitDelimiterType,
) -> Result<SplitDelimiterSpec, RuntimeError> {
    match delimiter_type {
        StrsplitDelimiterType::Simple => parse_split_delimiter(delimiter),
        StrsplitDelimiterType::RegularExpression => match delimiter {
            None => Ok(SplitDelimiterSpec::Whitespace),
            Some(value) => {
                let (patterns, _prototypes) = text_sequence_parts(value, "strsplit delimiter")?;
                if patterns.iter().any(|pattern| pattern.is_empty()) {
                    return Err(RuntimeError::Unsupported(
                        "strsplit does not yet support an empty regular expression delimiter"
                            .to_string(),
                    ));
                }
                let regexes = patterns
                    .into_iter()
                    .map(|pattern| {
                        let regex = Regex::new(&pattern).map_err(|error| {
                            RuntimeError::Unsupported(format!(
                                "strsplit regular expression delimiter `{pattern}` is invalid: {error}"
                            ))
                        })?;
                        if regex.is_match("") {
                            return Err(RuntimeError::Unsupported(
                                "strsplit does not yet support regular expression delimiters that match empty text"
                                    .to_string(),
                            ));
                        }
                        Ok(regex)
                    })
                    .collect::<Result<Vec<_>, RuntimeError>>()?;
                Ok(SplitDelimiterSpec::RegularExpressions(regexes))
            }
        },
    }
}

fn parse_strtok_delimiters(delimiter: Option<&Value>) -> Result<Option<Vec<char>>, RuntimeError> {
    match delimiter {
        None => Ok(None),
        Some(value) => {
            let (parts, _) = text_sequence_parts(value, "strtok delimiter")?;
            Ok(Some(
                parts
                    .into_iter()
                    .flat_map(|part| part.chars().collect::<Vec<_>>())
                    .collect(),
            ))
        }
    }
}

fn join_delimiter_scalar(delimiter: &str) -> JoinDelimiterOperand {
    JoinDelimiterOperand {
        dims: vec![1, 1],
        values: vec![delimiter.to_string()],
    }
}

fn parse_join_delimiter_operand(value: &Value) -> Result<JoinDelimiterOperand, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => Ok(join_delimiter_scalar(text)),
        Value::Matrix(matrix) if matrix_is_text(matrix) => Ok(JoinDelimiterOperand {
            dims: canonical_size_vector(&matrix.dims),
            values: matrix
                .elements
                .iter()
                .map(|element| text_value(element).map(|text| text.to_string()))
                .collect::<Result<Vec<_>, _>>()?,
        }),
        Value::Cell(cell) => Ok(JoinDelimiterOperand {
            dims: canonical_size_vector(&cell.dims),
            values: cell
                .elements
                .iter()
                .map(|element| text_value(element).map(|text| text.to_string()))
                .collect::<Result<Vec<_>, _>>()?,
        }),
        other => Err(RuntimeError::TypeError(format!(
            "join currently expects the delimiter to be text scalar/array input, found {}",
            other.kind_name()
        ))),
    }
}

fn strjoin_value(
    value: &Value,
    delimiter: &str,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let (parts, prototypes) = text_sequence_parts(value, builtin_name)?;
    let joined = parts.join(delimiter);
    if prototypes
        .iter()
        .all(|prototype| *prototype == TextPrototype::Char)
    {
        Ok(Value::CharArray(joined))
    } else {
        Ok(Value::String(joined))
    }
}

fn builtin_join(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, delimiter, requested_dim) = match args {
        [value] => (value, join_delimiter_scalar(" "), None),
        [value, second] => {
            if let Ok(dim) = positive_dimension(second, "join") {
                (value, join_delimiter_scalar(" "), Some(dim))
            } else {
                (value, parse_join_delimiter_operand(second)?, None)
            }
        }
        [value, delimiter, dim] => (
            value,
            parse_join_delimiter_operand(delimiter)?,
            Some(positive_dimension(dim, "join")?),
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "join currently supports `join(str)`, `join(str, delimiter)`, `join(str, dim)`, or `join(str, delimiter, dim)`"
                    .to_string(),
            ))
        }
    };
    match value {
        Value::Cell(cell) => {
            let dims = canonical_size_vector(&cell.dims);
            let join_dim = requested_dim.unwrap_or_else(|| {
                dims.iter()
                    .rposition(|&size| size != 1)
                    .map(|index| index + 1)
                    .unwrap_or(1)
            });
            if dimension_length(&dims, join_dim) == 1 {
                return Ok(Value::Cell(cell.clone()));
            }
            join_text_elements(&cell.elements, &dims, join_dim, &delimiter, true)
        }
        Value::CharArray(_) | Value::String(_) => {
            strjoin_value(value, &delimiter.values[0], "join")
        }
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            let input_dims = canonical_size_vector(&matrix.dims);
            let join_dim = requested_dim.unwrap_or_else(|| {
                input_dims
                    .iter()
                    .rposition(|&size| size != 1)
                    .map(|index| index + 1)
                    .unwrap_or(1)
            });
            if dimension_length(&input_dims, join_dim) == 1 {
                return Ok(Value::Matrix(matrix.clone()));
            }
            join_text_elements(&matrix.elements, &input_dims, join_dim, &delimiter, false)
        }
        other => Err(RuntimeError::TypeError(format!(
            "join currently expects a text cell array or text matrix, found {}",
            other.kind_name()
        ))),
    }
}

fn join_text_elements(
    elements: &[Value],
    dims: &[usize],
    join_dim: usize,
    delimiter: &JoinDelimiterOperand,
    cell_output: bool,
) -> Result<Value, RuntimeError> {
    let canonical_dims = canonical_size_vector(dims);
    let mut output_dims = canonical_dims.clone();
    output_dims[join_dim - 1] = 1;
    let delimiter_dims = broadcast_join_delimiter_dims(delimiter, &canonical_dims, join_dim)?;
    let sequence_dims = canonical_dims
        .iter()
        .enumerate()
        .filter_map(|(axis, &size)| (axis + 1 != join_dim).then_some(size))
        .collect::<Vec<_>>();
    let output_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let mut outputs = Vec::with_capacity(output_count);
    for linear in 0..output_count {
        let reduced_index = row_major_multi_index(linear, &sequence_dims);
        let mut parts = Vec::with_capacity(canonical_dims[join_dim - 1]);
        let mut all_char = true;
        for axis_value in 0..canonical_dims[join_dim - 1] {
            let mut input_index = Vec::with_capacity(canonical_dims.len());
            let mut reduced_offset = 0usize;
            for axis in 0..canonical_dims.len() {
                if axis + 1 == join_dim {
                    input_index.push(axis_value);
                } else {
                    input_index.push(reduced_index[reduced_offset]);
                    reduced_offset += 1;
                }
            }
            let element = &elements[row_major_linear_index(&input_index, &canonical_dims)];
            if !matches!(element, Value::CharArray(_)) {
                all_char = false;
            }
            parts.push(text_value(element)?.to_string());
            if axis_value + 1 < canonical_dims[join_dim - 1] {
                let delimiter_index = join_delimiter_index(
                    &reduced_index,
                    axis_value,
                    join_dim,
                    &canonical_dims,
                    &delimiter_dims,
                );
                parts.push(
                    delimiter.values[row_major_linear_index(&delimiter_index, &delimiter_dims)]
                        .clone(),
                );
            }
        }
        let joined = parts.concat();
        outputs.push(if all_char {
            Value::CharArray(joined)
        } else {
            Value::String(joined)
        });
    }

    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    if cell_output {
        Ok(Value::Cell(CellValue::with_dimensions(
            rows,
            cols,
            output_dims,
            outputs,
        )?))
    } else if output_dims.iter().all(|&size| size == 1) {
        Ok(outputs.into_iter().next().expect("single joined output"))
    } else if output_dims.len() > 2 {
        Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            output_dims,
            outputs,
        )?))
    } else {
        Ok(Value::Matrix(MatrixValue::new(rows, cols, outputs)?))
    }
}

fn broadcast_join_delimiter_dims(
    delimiter: &JoinDelimiterOperand,
    input_dims: &[usize],
    join_dim: usize,
) -> Result<Vec<usize>, RuntimeError> {
    let rank = input_dims.len().max(join_dim).max(delimiter.dims.len());
    let mut dims = delimiter.dims.clone();
    while dims.len() < rank {
        dims.push(1);
    }
    let join_len = input_dims[join_dim - 1];
    for axis in 0..rank {
        let input_len = input_dims.get(axis).copied().unwrap_or(1);
        let delimiter_len = dims[axis];
        if axis + 1 == join_dim {
            if delimiter_len != 1 && delimiter_len != join_len.saturating_sub(1) {
                return Err(RuntimeError::ShapeError(format!(
                    "join delimiter size along dimension {join_dim} must be 1 or {}",
                    join_len.saturating_sub(1)
                )));
            }
        } else if delimiter_len != 1 && delimiter_len != input_len {
            return Err(RuntimeError::ShapeError(format!(
                "join delimiter size {} is incompatible with input size {} along dimension {}",
                delimiter_len,
                input_len,
                axis + 1
            )));
        }
    }
    Ok(dims)
}

fn join_delimiter_index(
    reduced_index: &[usize],
    join_offset: usize,
    join_dim: usize,
    input_dims: &[usize],
    delimiter_dims: &[usize],
) -> Vec<usize> {
    let rank = delimiter_dims.len();
    let mut index = Vec::with_capacity(rank);
    let mut reduced_offset = 0usize;
    for axis in 0..rank {
        if axis + 1 == join_dim {
            index.push(if delimiter_dims[axis] == 1 {
                0
            } else {
                join_offset
            });
        } else {
            let input_len = input_dims.get(axis).copied().unwrap_or(1);
            let source = if input_len == 1 {
                0
            } else {
                let value = reduced_index.get(reduced_offset).copied().unwrap_or(0);
                reduced_offset += 1;
                value
            };
            index.push(if delimiter_dims[axis] == 1 { 0 } else { source });
        }
    }
    index
}

fn builtin_extract_before(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, marker] = args else {
        return Err(RuntimeError::Unsupported(
            "extractBefore currently supports exactly two arguments".to_string(),
        ));
    };

    if is_text_position_operand(marker) {
        return map_text_position_text(value, marker, "extractBefore", |value, position| {
            Ok(text_before_position(value, position))
        });
    }

    map_text_binary_text(value, marker, |value, marker| {
        let end = find_marker(value, marker)?;
        Ok(value[..end].to_string())
    })
}

fn builtin_extract_after(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, marker] = args else {
        return Err(RuntimeError::Unsupported(
            "extractAfter currently supports exactly two arguments".to_string(),
        ));
    };

    if is_text_position_operand(marker) {
        return map_text_position_text(value, marker, "extractAfter", |value, position| {
            Ok(text_after_position(value, position))
        });
    }

    map_text_binary_text(value, marker, |value, marker| {
        let start = find_marker(value, marker)? + marker.len();
        Ok(value[start..].to_string())
    })
}

fn builtin_extract_between(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, start_marker, end_marker, boundaries) = parse_between_args(args, "extractBetween")?;

    if is_text_position_operand(start_marker) && is_text_position_operand(end_marker) {
        return map_text_position_pair_text(
            value,
            start_marker,
            end_marker,
            "extractBetween",
            |value, start, end| {
                Ok(text_between_positions_with_mode(
                    value, start, end, boundaries,
                ))
            },
        );
    }

    map_text_ternary_text(
        value,
        start_marker,
        end_marker,
        |value, start_marker, end_marker| {
            extract_between_with_mode(value, start_marker, end_marker, boundaries)
        },
    )
}

fn builtin_replace_before(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, marker, replacement] = args else {
        return Err(RuntimeError::Unsupported(
            "replaceBefore currently supports exactly three arguments".to_string(),
        ));
    };

    if is_text_position_operand(marker) {
        return map_text_position_and_text(
            value,
            marker,
            replacement,
            "replaceBefore",
            |value, position, replacement| {
                Ok(replace_before_position(value, position, replacement))
            },
        );
    }

    map_text_ternary_text(value, marker, replacement, |value, marker, replacement| {
        let marker_start = find_marker(value, marker)?;
        let mut result = String::with_capacity(replacement.len() + value.len());
        result.push_str(replacement);
        result.push_str(&value[marker_start..]);
        Ok(result)
    })
}

fn builtin_replace_after(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, marker, replacement] = args else {
        return Err(RuntimeError::Unsupported(
            "replaceAfter currently supports exactly three arguments".to_string(),
        ));
    };

    if is_text_position_operand(marker) {
        return map_text_position_and_text(
            value,
            marker,
            replacement,
            "replaceAfter",
            |value, position, replacement| Ok(replace_after_position(value, position, replacement)),
        );
    }

    map_text_ternary_text(value, marker, replacement, |value, marker, replacement| {
        let marker_end = find_marker(value, marker)? + marker.len();
        let mut result = String::with_capacity(value.len() + replacement.len());
        result.push_str(&value[..marker_end]);
        result.push_str(replacement);
        Ok(result)
    })
}

fn builtin_replace_between(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, start_marker, end_marker, replacement, boundaries) =
        parse_replace_between_args(args)?;

    if is_text_position_operand(start_marker) && is_text_position_operand(end_marker) {
        return map_text_position_pair_and_text(
            value,
            start_marker,
            end_marker,
            replacement,
            "replaceBetween",
            |value, start, end, replacement| {
                Ok(replace_between_positions_with_mode(
                    value,
                    start,
                    end,
                    replacement,
                    boundaries,
                ))
            },
        );
    }

    map_text_quaternary_text(
        value,
        start_marker,
        end_marker,
        replacement,
        |value, start_marker, end_marker, replacement| {
            let (start, end) =
                between_bounds_with_mode(value, start_marker, end_marker, boundaries)?;
            let mut result = String::with_capacity(value.len() + replacement.len());
            result.push_str(&value[..start]);
            result.push_str(replacement);
            result.push_str(&value[end..]);
            Ok(result)
        },
    )
}

fn builtin_pad(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, width, direction, pad_character) = parse_pad_args(args)?;
    let (operand, _input_dims) = split_text_operand(value)?;
    let width = width.unwrap_or_else(|| {
        operand
            .values
            .iter()
            .map(|text| text.chars().count())
            .max()
            .unwrap_or(0)
    });

    let values = operand
        .values
        .iter()
        .map(|text| {
            let current = text.chars().count();
            if current >= width {
                return text.to_string();
            }

            let missing = width - current;
            let (left, right) = match direction {
                PadDirection::Left => (missing, 0),
                PadDirection::Right => (0, missing),
                PadDirection::Both => {
                    let left = missing / 2;
                    (left, missing - left)
                }
            };

            let mut result = String::with_capacity(width);
            result.push_str(&pad_character.repeat(left));
            result.push_str(text);
            result.push_str(&pad_character.repeat(right));
            result
        })
        .collect::<Vec<_>>();

    if let Value::Cell(cell) = value {
        return Ok(Value::Cell(CellValue::with_dimensions(
            cell.rows,
            cell.cols,
            cell.dims.clone(),
            values.into_iter().map(Value::CharArray).collect(),
        )?));
    }

    build_text_result(operand.rows, operand.cols, values, operand.prototypes)
}

fn builtin_compose(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((format, values)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "compose currently expects at least a format string".to_string(),
        ));
    };

    if values.is_empty() {
        return compose_literal_text(format);
    }

    compose_formatted_value(format, values)
}

fn compose_literal_text(value: &Value) -> Result<Value, RuntimeError> {
    match value {
        Value::String(text) => Ok(Value::String(translate_compose_escapes(text, "compose")?)),
        Value::CharArray(text) => Ok(Value::Cell(CellValue::new(
            1,
            1,
            vec![Value::CharArray(translate_compose_escapes(
                text, "compose",
            )?)],
        )?)),
        Value::Matrix(matrix) if matrix_is_string(matrix) => {
            let elements = matrix
                .elements
                .iter()
                .map(|element| {
                    Ok(Value::String(translate_compose_escapes(
                        text_value(element)?,
                        "compose",
                    )?))
                })
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                matrix.rows,
                matrix.cols,
                matrix.dims.clone(),
                elements,
            )?))
        }
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            let elements = matrix
                .elements
                .iter()
                .map(|element| {
                    Ok(Value::CharArray(translate_compose_escapes(
                        text_value(element)?,
                        "compose",
                    )?))
                })
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            Ok(Value::Cell(CellValue::with_dimensions(
                matrix.rows,
                matrix.cols,
                matrix.dims.clone(),
                elements,
            )?))
        }
        Value::Cell(cell) => {
            let elements = cell
                .elements
                .iter()
                .map(|element| {
                    Ok(Value::CharArray(translate_compose_escapes(
                        text_value(element)?,
                        "compose",
                    )?))
                })
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            Ok(Value::Cell(CellValue::with_dimensions(
                cell.rows,
                cell.cols,
                cell.dims.clone(),
                elements,
            )?))
        }
        other => Err(RuntimeError::TypeError(format!(
            "compose(txt) currently expects text input, found {}",
            other.kind_name()
        ))),
    }
}

fn translate_compose_escapes(text: &str, builtin_name: &str) -> Result<String, RuntimeError> {
    let mut result = String::with_capacity(text.len());
    let mut chars = text.chars().peekable();
    while let Some(ch) = chars.next() {
        if ch != '\\' {
            result.push(ch);
            continue;
        }

        match chars.next() {
            Some('a') => result.push('\x07'),
            Some('b') => result.push('\x08'),
            Some('f') => result.push('\x0c'),
            Some('n') => result.push('\n'),
            Some('r') => result.push('\r'),
            Some('t') => result.push('\t'),
            Some('v') => result.push('\x0b'),
            Some('\\') => result.push('\\'),
            Some('x') => {
                let mut digits = String::new();
                while let Some(peek) = chars.peek() {
                    if peek.is_ascii_hexdigit() {
                        digits.push(*peek);
                        chars.next();
                    } else {
                        break;
                    }
                }
                if digits.is_empty() {
                    result.push('\\');
                    result.push('x');
                    continue;
                }
                let code = u32::from_str_radix(&digits, 16).map_err(|error| {
                    RuntimeError::Unsupported(format!(
                        "{builtin_name} could not parse hexadecimal escape `\\x{digits}`: {error}"
                    ))
                })?;
                let Some(codepoint) = char::from_u32(code) else {
                    return Err(RuntimeError::TypeError(format!(
                        "{builtin_name} received an invalid Unicode code point {code} from `\\x{digits}`"
                    )));
                };
                result.push(codepoint);
            }
            Some(digit @ '0'..='7') => {
                let mut digits = String::from(digit);
                for _ in 0..2 {
                    let Some(peek) = chars.peek() else {
                        break;
                    };
                    if ('0'..='7').contains(peek) {
                        digits.push(*peek);
                        chars.next();
                    } else {
                        break;
                    }
                }
                let code = u32::from_str_radix(&digits, 8).map_err(|error| {
                    RuntimeError::Unsupported(format!(
                        "{builtin_name} could not parse octal escape `\\{digits}`: {error}"
                    ))
                })?;
                let Some(codepoint) = char::from_u32(code) else {
                    return Err(RuntimeError::TypeError(format!(
                        "{builtin_name} received an invalid Unicode code point {code} from `\\{digits}`"
                    )));
                };
                result.push(codepoint);
            }
            Some(other) => {
                result.push('\\');
                result.push(other);
            }
            None => result.push('\\'),
        }
    }
    Ok(result)
}

fn builtin_sprintf(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((format, values)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "sprintf currently expects at least a format string".to_string(),
        ));
    };

    Ok(Value::CharArray(format_text_builtin(
        text_value(format)?,
        values,
        "sprintf",
    )?))
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum PadDirection {
    Left,
    Right,
    Both,
}

#[derive(Debug, Clone)]
struct ComposeInput {
    rows: usize,
    cols: usize,
    values: Vec<Value>,
}

#[derive(Debug, Clone)]
enum FormatToken {
    Literal(String),
    Placeholder {
        specifier: char,
        flags: FormatFlags,
        width: Option<usize>,
        precision: Option<usize>,
        raw: String,
    },
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum MissingFormatValueBehavior {
    Error,
    KeepSpecifier,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ComposeOutputKind {
    StringArray,
    CellArray,
}

#[derive(Debug, Clone, Copy, Default)]
struct FormatFlags {
    left_justify: bool,
    always_sign: bool,
    leading_space: bool,
    zero_pad: bool,
    alternate_form: bool,
}

fn parse_pad_direction(value: &Value) -> Result<PadDirection, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "left" => Ok(PadDirection::Left),
        "right" => Ok(PadDirection::Right),
        "both" => Ok(PadDirection::Both),
        other => Err(RuntimeError::Unsupported(format!(
            "pad direction `{other}` is not implemented; expected left, right, or both"
        ))),
    }
}

fn parse_pad_character(value: &Value) -> Result<String, RuntimeError> {
    let text = text_value(value)?;
    if text.chars().count() != 1 {
        return Err(RuntimeError::TypeError(
            "pad currently expects padCharacter to contain exactly one character".to_string(),
        ));
    }
    Ok(text.to_string())
}

fn parse_pad_args(
    args: &[Value],
) -> Result<(&Value, Option<usize>, PadDirection, String), RuntimeError> {
    match args {
        [value] => Ok((value, None, PadDirection::Right, " ".to_string())),
        [value, second] => {
            if let Ok(direction) = parse_pad_direction(second) {
                Ok((value, None, direction, " ".to_string()))
            } else {
                match second {
                    Value::CharArray(_) | Value::String(_) => {
                        Ok((value, None, PadDirection::Right, parse_pad_character(second)?))
                    }
                    _ => Ok((value, Some(scalar_dimension(second)?), PadDirection::Right, " ".to_string())),
                }
            }
        }
        [value, second, third] => {
            if let Ok(direction) = parse_pad_direction(second) {
                return Ok((value, None, direction, parse_pad_character(third)?));
            }

            let width = scalar_dimension(second)?;
            if let Ok(direction) = parse_pad_direction(third) {
                return Ok((value, Some(width), direction, " ".to_string()));
            }
            Ok((value, Some(width), PadDirection::Right, parse_pad_character(third)?))
        }
        [value, width, direction, pad_character] => Ok((
            value,
            Some(scalar_dimension(width)?),
            parse_pad_direction(direction)?,
            parse_pad_character(pad_character)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "pad currently supports `pad(str)`, `pad(str, width)`, `pad(str, side)`, `pad(str, width, side)`, `pad(___, padCharacter)`, `pad(str, side, padCharacter)`, and `pad(str, width, side, padCharacter)`".to_string(),
        )),
    }
}

fn compose_fragment(
    value: &Value,
    builtin_name: &str,
    specifier: char,
    flags: FormatFlags,
    width: Option<usize>,
    precision: Option<usize>,
) -> Result<String, RuntimeError> {
    let rendered = match specifier {
        's' => text_or_scalar_value(value, builtin_name, specifier),
        'd' | 'i' => Ok(format!(
            "{}",
            apply_sign_prefix(
                signed_integer_scalar(value, builtin_name, specifier)?,
                &flags,
            )
        )),
        'f' => {
            let scalar = compose_numeric_scalar(value, builtin_name, specifier)?;
            Ok(format_fixed_point(scalar, precision.unwrap_or(6), flags))
        }
        'e' => Ok(format_scientific(
            compose_numeric_scalar(value, builtin_name, specifier)?,
            precision.unwrap_or(6),
            false,
            flags,
        )),
        'E' => Ok(format_scientific(
            compose_numeric_scalar(value, builtin_name, specifier)?,
            precision.unwrap_or(6),
            true,
            flags,
        )),
        'g' => Ok(format_general(
            compose_numeric_scalar(value, builtin_name, specifier)?,
            precision.unwrap_or(6),
            false,
            flags,
        )),
        'G' => Ok(format_general(
            compose_numeric_scalar(value, builtin_name, specifier)?,
            precision.unwrap_or(6),
            true,
            flags,
        )),
        'c' => format_character_fragment(value, builtin_name),
        'u' => format_unsigned_integer_fragment(value, builtin_name, specifier, 10, flags),
        'o' => format_unsigned_integer_fragment(value, builtin_name, specifier, 8, flags),
        'x' => format_unsigned_integer_fragment(value, builtin_name, specifier, 16, flags),
        'X' => Ok(
            format_unsigned_integer_fragment(value, builtin_name, specifier, 16, flags)?
                .to_ascii_uppercase(),
        ),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} format `%{other}` is not implemented"
        ))),
    }?;
    Ok(apply_format_width(rendered, flags, width, specifier))
}

fn format_scientific(number: f64, precision: usize, uppercase: bool, flags: FormatFlags) -> String {
    let exponent_marker = if uppercase { 'E' } else { 'e' };
    let raw = if uppercase {
        format!("{number:.precision$E}")
    } else {
        format!("{number:.precision$e}")
    };
    let Some((mantissa, exponent)) = raw.split_once(exponent_marker) else {
        return raw;
    };
    let exponent_value = exponent.parse::<i32>().unwrap_or(0);
    let exponent_sign = if exponent_value.is_negative() {
        '-'
    } else {
        '+'
    };
    let exponent_magnitude = exponent_value.abs();
    let exponent_digits = if exponent_magnitude < 10 {
        format!("0{exponent_magnitude}")
    } else {
        exponent_magnitude.to_string()
    };
    let mut mantissa = mantissa.to_string();
    if flags.alternate_form && precision == 0 && !mantissa.contains('.') {
        mantissa.push('.');
    }
    if number.is_sign_positive() && !number.is_nan() {
        if flags.always_sign {
            mantissa.insert(0, '+');
        } else if flags.leading_space {
            mantissa.insert(0, ' ');
        }
    }
    format!("{mantissa}{exponent_marker}{exponent_sign}{exponent_digits}")
}

fn compose_numeric_scalar(
    value: &Value,
    builtin_name: &str,
    specifier: char,
) -> Result<f64, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(*number),
        Value::Complex(number) => Ok(number.real),
        Value::Logical(flag) => Ok(if *flag { 1.0 } else { 0.0 }),
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} `%{specifier}` expects a numeric, logical, or complex scalar, found {}",
            other.kind_name()
        ))),
    }
}

fn apply_sign_prefix(value: i64, flags: &FormatFlags) -> String {
    if value < 0 {
        value.to_string()
    } else if flags.always_sign {
        format!("+{value}")
    } else if flags.leading_space {
        format!(" {value}")
    } else {
        value.to_string()
    }
}

fn format_fixed_point(number: f64, precision: usize, flags: FormatFlags) -> String {
    let mut rendered = format!("{number:.precision$}");
    if flags.alternate_form && precision == 0 && !rendered.contains('.') {
        rendered.push('.');
    }
    if number.is_sign_positive() && !number.is_nan() {
        if flags.always_sign {
            rendered.insert(0, '+');
        } else if flags.leading_space {
            rendered.insert(0, ' ');
        }
    }
    rendered
}

fn format_general(
    number: f64,
    significant_digits: usize,
    uppercase: bool,
    flags: FormatFlags,
) -> String {
    if !number.is_finite() {
        let mut rendered = if uppercase {
            render_scalar(number).replace("inf", "INF")
        } else {
            render_scalar(number)
        };
        if number.is_sign_positive() && !number.is_nan() {
            if flags.always_sign {
                rendered.insert(0, '+');
            } else if flags.leading_space {
                rendered.insert(0, ' ');
            }
        }
        return rendered;
    }

    let significant_digits = significant_digits.max(1);
    if number == 0.0 {
        let decimals = significant_digits.saturating_sub(1);
        let mut rendered = if flags.alternate_form {
            format_fixed_point(number, decimals, flags)
        } else {
            trim_trailing_zeros(format_fixed_point(number, decimals, flags))
        };
        if uppercase {
            rendered = rendered.replace('e', "E");
        }
        return rendered;
    }

    let exponent = number.abs().log10().floor() as i32;
    let use_scientific = exponent < -4 || exponent >= significant_digits as i32;
    let mut rendered = if use_scientific {
        let precision = significant_digits.saturating_sub(1);
        let scientific = format_scientific(number, precision, uppercase, flags);
        if flags.alternate_form {
            scientific
        } else {
            trim_scientific_trailing_zeros(scientific)
        }
    } else {
        let decimals = (significant_digits as i32 - exponent - 1).max(0) as usize;
        let fixed = format_fixed_point(number, decimals, flags);
        if flags.alternate_form {
            fixed
        } else {
            trim_trailing_zeros(fixed)
        }
    };
    if uppercase {
        rendered = rendered.replace('e', "E");
    }
    rendered
}

fn trim_trailing_zeros(mut rendered: String) -> String {
    let sign_prefix =
        if rendered.starts_with('+') || rendered.starts_with('-') || rendered.starts_with(' ') {
            rendered.remove(0).to_string()
        } else {
            String::new()
        };
    if let Some(dot_index) = rendered.find('.') {
        while rendered.ends_with('0') {
            rendered.pop();
        }
        if rendered.len() == dot_index + 1 {
            rendered.pop();
        }
    }
    format!("{sign_prefix}{rendered}")
}

fn trim_scientific_trailing_zeros(rendered: String) -> String {
    let Some(exponent_index) = rendered.find(['e', 'E']) else {
        return trim_trailing_zeros(rendered);
    };
    let mantissa = trim_trailing_zeros(rendered[..exponent_index].to_string());
    format!("{mantissa}{}", &rendered[exponent_index..])
}

fn signed_integer_scalar(
    value: &Value,
    builtin_name: &str,
    specifier: char,
) -> Result<i64, RuntimeError> {
    let scalar = compose_numeric_scalar(value, builtin_name, specifier)?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} `%{specifier}` expects an integer-valued scalar, found {scalar}"
        )));
    }
    if scalar < i64::MIN as f64 || scalar > i64::MAX as f64 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} `%{specifier}` received an out-of-range integer scalar {scalar}"
        )));
    }
    Ok(scalar as i64)
}

fn unsigned_integer_scalar(
    value: &Value,
    builtin_name: &str,
    specifier: char,
) -> Result<u64, RuntimeError> {
    let scalar = compose_numeric_scalar(value, builtin_name, specifier)?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} `%{specifier}` expects a nonnegative integer-valued scalar, found {scalar}"
        )));
    }
    if scalar > u64::MAX as f64 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} `%{specifier}` received an out-of-range integer scalar {scalar}"
        )));
    }
    Ok(scalar as u64)
}

fn format_character_fragment(value: &Value, builtin_name: &str) -> Result<String, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => {
            text.chars().next().map(|ch| ch.to_string()).ok_or_else(|| {
                RuntimeError::TypeError(format!(
                    "{builtin_name} `%c` expects nonempty text or an integer-valued scalar"
                ))
            })
        }
        _ => {
            let code = unsigned_integer_scalar(value, builtin_name, 'c')?;
            let Some(ch) = char::from_u32(code as u32) else {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} `%c` received an invalid character code {code}"
                )));
            };
            Ok(ch.to_string())
        }
    }
}

fn format_unsigned_integer_fragment(
    value: &Value,
    builtin_name: &str,
    specifier: char,
    base: u32,
    flags: FormatFlags,
) -> Result<String, RuntimeError> {
    let scalar = unsigned_integer_scalar(value, builtin_name, specifier)?;
    let body = match base {
        8 => format!("{scalar:o}"),
        10 => scalar.to_string(),
        16 => format!("{scalar:x}"),
        _ => unreachable!("unsupported integer base"),
    };
    Ok(match (flags.alternate_form, base) {
        (true, 8) if !body.starts_with('0') => format!("0{body}"),
        (true, 16) => format!("0x{body}"),
        _ => body,
    })
}

fn apply_format_width(
    rendered: String,
    flags: FormatFlags,
    width: Option<usize>,
    specifier: char,
) -> String {
    let Some(width) = width else {
        return rendered;
    };
    let current = rendered.chars().count();
    if current >= width {
        return rendered;
    }

    let pad_count = width - current;
    let is_numeric = matches!(
        specifier,
        'd' | 'i' | 'f' | 'e' | 'E' | 'g' | 'G' | 'u' | 'o' | 'x' | 'X'
    );
    let pad_char = if flags.zero_pad && !flags.left_justify && is_numeric {
        '0'
    } else {
        ' '
    };
    let padding = pad_char.to_string().repeat(pad_count);

    if flags.left_justify {
        return format!("{rendered}{padding}");
    }

    if pad_char == '0' {
        if let Some(rest) = rendered.strip_prefix('+') {
            return format!("+{padding}{rest}");
        }
        if let Some(rest) = rendered.strip_prefix('-') {
            return format!("-{padding}{rest}");
        }
        if let Some(rest) = rendered.strip_prefix(' ') {
            return format!(" {padding}{rest}");
        }
        if let Some(rest) = rendered.strip_prefix("0x") {
            return format!("0x{padding}{rest}");
        }
        if let Some(rest) = rendered.strip_prefix("0X") {
            return format!("0X{padding}{rest}");
        }
    }

    format!("{padding}{rendered}")
}

fn parse_format_precision(
    chars: &mut std::iter::Peekable<std::str::Chars<'_>>,
    builtin_name: &str,
) -> Result<Option<usize>, RuntimeError> {
    if chars.peek() != Some(&'.') {
        return Ok(None);
    }

    chars.next();
    let mut digits = String::new();
    while let Some(next) = chars.peek() {
        if next.is_ascii_digit() {
            digits.push(*next);
            chars.next();
        } else {
            break;
        }
    }
    if digits.is_empty() {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} precision currently requires decimal digits after `.`"
        )));
    }
    Ok(Some(digits.parse::<usize>().map_err(|error| {
        RuntimeError::Unsupported(format!("invalid {builtin_name} precision: {error}"))
    })?))
}

fn parse_format_flags(chars: &mut std::iter::Peekable<std::str::Chars<'_>>) -> FormatFlags {
    let mut flags = FormatFlags::default();
    loop {
        match chars.peek().copied() {
            Some('-') => {
                flags.left_justify = true;
                chars.next();
            }
            Some('+') => {
                flags.always_sign = true;
                chars.next();
            }
            Some(' ') => {
                flags.leading_space = true;
                chars.next();
            }
            Some('0') => {
                flags.zero_pad = true;
                chars.next();
            }
            Some('#') => {
                flags.alternate_form = true;
                chars.next();
            }
            _ => break,
        }
    }
    flags
}

fn parse_format_width(chars: &mut std::iter::Peekable<std::str::Chars<'_>>) -> Option<usize> {
    let mut digits = String::new();
    while let Some(next) = chars.peek() {
        if next.is_ascii_digit() {
            digits.push(*next);
            chars.next();
        } else {
            break;
        }
    }
    if digits.is_empty() {
        None
    } else {
        digits.parse::<usize>().ok()
    }
}

fn parse_format_tokens(format: &str, builtin_name: &str) -> Result<Vec<FormatToken>, RuntimeError> {
    let translated = translate_compose_escapes(format, builtin_name)?;
    let mut tokens = Vec::new();
    let mut literal = String::new();
    let mut chars = translated.chars().peekable();

    while let Some(ch) = chars.next() {
        if ch != '%' {
            literal.push(ch);
            continue;
        }

        if chars.peek() == Some(&'%') {
            literal.push('%');
            chars.next();
            continue;
        }

        if !literal.is_empty() {
            tokens.push(FormatToken::Literal(std::mem::take(&mut literal)));
        }

        let flags = parse_format_flags(&mut chars);
        let width = parse_format_width(&mut chars);
        let precision = parse_format_precision(&mut chars, builtin_name)?;
        let Some(specifier) = chars.next() else {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} format cannot end with an incomplete `%` sequence"
            )));
        };
        let mut raw = String::from("%");
        if flags.left_justify {
            raw.push('-');
        }
        if flags.always_sign {
            raw.push('+');
        }
        if flags.leading_space {
            raw.push(' ');
        }
        if flags.zero_pad {
            raw.push('0');
        }
        if flags.alternate_form {
            raw.push('#');
        }
        if let Some(width) = width {
            raw.push_str(&width.to_string());
        }
        if let Some(precision) = precision {
            raw.push('.');
            raw.push_str(&precision.to_string());
        }
        raw.push(specifier);
        tokens.push(FormatToken::Placeholder {
            specifier,
            flags,
            width,
            precision,
            raw,
        });
    }

    if !literal.is_empty() {
        tokens.push(FormatToken::Literal(literal));
    }

    Ok(tokens)
}

fn render_format_tokens(
    tokens: &[FormatToken],
    values: &[Value],
    builtin_name: &str,
    missing_behavior: MissingFormatValueBehavior,
) -> Result<String, RuntimeError> {
    let mut rendered = String::new();
    let mut value_index = 0usize;
    for token in tokens {
        match token {
            FormatToken::Literal(text) => rendered.push_str(text),
            FormatToken::Placeholder {
                specifier,
                flags,
                width,
                precision,
                raw,
            } => {
                let Some(value) = values.get(value_index) else {
                    if missing_behavior == MissingFormatValueBehavior::KeepSpecifier {
                        rendered.push_str(raw);
                        continue;
                    }
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} expected at least {} value(s) for the format string",
                        value_index + 1
                    )));
                };
                value_index += 1;
                rendered.push_str(&compose_fragment(
                    value,
                    builtin_name,
                    *specifier,
                    *flags,
                    *width,
                    *precision,
                )?);
            }
        }
    }

    if value_index != values.len() {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} used {value_index} value(s) but received {}",
            values.len()
        )));
    }

    Ok(rendered)
}

fn compose_input_from_value(value: &Value) -> ComposeInput {
    match value {
        Value::Matrix(matrix) => ComposeInput {
            rows: matrix.rows,
            cols: matrix.cols,
            values: matrix.elements.clone(),
        },
        _ => ComposeInput {
            rows: 1,
            cols: 1,
            values: vec![value.clone()],
        },
    }
}

fn compose_broadcast_rows(inputs: &[ComposeInput]) -> Result<usize, RuntimeError> {
    let mut rows = 1usize;
    for input in inputs {
        if input.rows == 1 {
            continue;
        }
        if rows == 1 {
            rows = input.rows;
            continue;
        }
        if input.rows != rows {
            return Err(RuntimeError::ShapeError(
                "compose currently expects inputs to have matching row counts or be scalar-expandable"
                    .to_string(),
            ));
        }
    }
    Ok(rows)
}

fn compose_value_at_virtual_column<'a>(
    inputs: &'a [ComposeInput],
    row: usize,
    virtual_col: usize,
) -> &'a Value {
    let mut remaining = virtual_col;
    for input in inputs {
        if remaining < input.cols {
            let source_row = if input.rows == 1 { 0 } else { row };
            return &input.values[source_row * input.cols + remaining];
        }
        remaining -= input.cols;
    }
    unreachable!("compose virtual column is in bounds")
}

fn compose_output_kind(format: &Value) -> ComposeOutputKind {
    match format {
        Value::String(_) => ComposeOutputKind::StringArray,
        Value::CharArray(_) => ComposeOutputKind::CellArray,
        _ => unreachable!("compose format is validated as scalar text"),
    }
}

fn build_compose_output(
    rows: usize,
    cols: usize,
    values: Vec<String>,
    output_kind: ComposeOutputKind,
) -> Result<Value, RuntimeError> {
    match output_kind {
        ComposeOutputKind::StringArray => {
            build_text_result(rows, cols, values, vec![TextPrototype::String; rows * cols])
        }
        ComposeOutputKind::CellArray => Ok(Value::Cell(CellValue::new(
            rows,
            cols,
            values.into_iter().map(Value::CharArray).collect(),
        )?)),
    }
}

fn compose_formatted_value(format: &Value, values: &[Value]) -> Result<Value, RuntimeError> {
    let format_text = text_value(format)?;
    let output_kind = compose_output_kind(format);
    let tokens = parse_format_tokens(format_text, "compose")?;
    let placeholder_count = tokens
        .iter()
        .filter(|token| matches!(token, FormatToken::Placeholder { .. }))
        .count();
    let inputs = values
        .iter()
        .map(compose_input_from_value)
        .collect::<Vec<_>>();
    let rows = compose_broadcast_rows(&inputs)?;

    if placeholder_count == 0 {
        let element_count = rows;
        let values = vec![translate_compose_escapes(format_text, "compose")?; element_count];
        return build_compose_output(rows, 1, values, output_kind);
    }

    let virtual_cols = inputs.iter().map(|input| input.cols).sum::<usize>();
    let output_cols = (virtual_cols + placeholder_count - 1) / placeholder_count;
    let mut rendered = Vec::with_capacity(rows * output_cols);
    for row in 0..rows {
        for output_col in 0..output_cols {
            let start_col = output_col * placeholder_count;
            let end_col = virtual_cols.min(start_col + placeholder_count);
            let chunk = (start_col..end_col)
                .map(|virtual_col| {
                    compose_value_at_virtual_column(&inputs, row, virtual_col).clone()
                })
                .collect::<Vec<_>>();
            rendered.push(render_format_tokens(
                &tokens,
                &chunk,
                "compose",
                MissingFormatValueBehavior::KeepSpecifier,
            )?);
        }
    }
    build_compose_output(rows, output_cols, rendered, output_kind)
}

pub fn format_text_builtin(
    format: &str,
    values: &[Value],
    builtin_name: &str,
) -> Result<String, RuntimeError> {
    let tokens = parse_format_tokens(format, builtin_name)?;
    render_format_tokens(
        &tokens,
        values,
        builtin_name,
        MissingFormatValueBehavior::Error,
    )
}

fn looks_like_error_identifier(text: &str) -> bool {
    text.contains(':') && !text.chars().any(char::is_whitespace)
}

fn builtin_isfield(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, field] = args else {
        return Err(RuntimeError::Unsupported(
            "isfield currently supports exactly two arguments".to_string(),
        ));
    };

    let (field_names, field_dims) = field_name_operand(field, "isfield")?;
    let results = field_names
        .iter()
        .map(|field_name| Ok(logical_scalar(struct_value_has_field(value, field_name)?)))
        .collect::<Result<Vec<_>, RuntimeError>>()?;
    build_logical_field_result(field_dims, results)
}

fn builtin_fieldnames(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "fieldnames currently supports exactly one argument".to_string(),
        ));
    };

    let Some(struct_value) = struct_fields(value, "fieldnames")? else {
        return Ok(Value::Cell(CellValue::new(0, 1, Vec::new())?));
    };

    let elements = struct_value
        .field_names()
        .iter()
        .cloned()
        .map(Value::CharArray)
        .collect::<Vec<_>>();
    Ok(Value::Cell(CellValue::new(elements.len(), 1, elements)?))
}

fn builtin_orderfields(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let [value, rest @ ..] = args else {
        return Err(RuntimeError::Unsupported(
            "orderfields currently supports `orderfields(S)` and common `orderfields(S, order)` forms"
                .to_string(),
        ));
    };
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "orderfields currently supports one or two outputs".to_string(),
        ));
    }

    let (ordered_value, permutation) = match value {
        Value::Struct(struct_value) => {
            let target_order = orderfields_target_order(struct_value, rest)?;
            let (ordered, permutation) = order_struct_fields(struct_value, target_order)?;
            (Value::Struct(ordered), permutation)
        }
        Value::Matrix(matrix) if matrix_is_struct(matrix) => {
            let Some(Value::Struct(first)) = matrix.elements().first() else {
                return Ok(vec![Value::Matrix(matrix.clone())]);
            };
            let target_order = orderfields_target_order(first, rest)?;
            let (_, permutation) = order_struct_fields(first, target_order.clone())?;
            let elements = matrix
                .elements()
                .iter()
                .map(|element| {
                    let Value::Struct(struct_value) = element else {
                        unreachable!("matrix_is_struct checked every element");
                    };
                    Ok(Value::Struct(
                        order_struct_fields(struct_value, target_order.clone())?.0,
                    ))
                })
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            (
                Value::Matrix(MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    matrix.dims().to_vec(),
                    elements,
                )?),
                permutation,
            )
        }
        other => {
            return Err(RuntimeError::TypeError(format!(
                "orderfields expects a struct or struct-array input, found {}",
                other.kind_name()
            )))
        }
    };

    if output_arity == 2 {
        Ok(vec![ordered_value, numeric_row_vector(permutation)?])
    } else {
        Ok(vec![ordered_value])
    }
}

fn builtin_rmfield(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, field] = args else {
        return Err(RuntimeError::Unsupported(
            "rmfield currently supports exactly two arguments".to_string(),
        ));
    };

    let (field_names, _) = field_name_operand(field, "rmfield")?;
    match value {
        Value::Struct(struct_value) => {
            let mut struct_value = struct_value.clone();
            for field_name in &field_names {
                struct_value.remove_field(field_name);
            }
            Ok(Value::Struct(struct_value))
        }
        Value::Matrix(matrix) if matrix_is_struct(matrix) => {
            let mut elements = Vec::with_capacity(matrix.elements.len());
            for element in &matrix.elements {
                let Value::Struct(struct_value) = element else {
                    unreachable!("matrix_is_struct checked every element");
                };
                let mut struct_value = struct_value.clone();
                for field_name in &field_names {
                    struct_value.remove_field(field_name);
                }
                elements.push(Value::Struct(struct_value));
            }
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                matrix.rows,
                matrix.cols,
                matrix.dims.clone(),
                elements,
            )?))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "rmfield expects a struct or struct-array input, found {}",
            value.kind_name()
        ))),
    }
}

fn builtin_getfield(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((value, path_values)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "getfield currently expects a struct input plus at least one field or index selector"
                .to_string(),
        ));
    };
    if path_values.is_empty() {
        return Err(RuntimeError::Unsupported(
            "getfield currently expects at least one field or index selector".to_string(),
        ));
    }
    let steps = path_values
        .iter()
        .map(|value| struct_field_step(value, "getfield"))
        .collect::<Result<Vec<_>, _>>()?;
    apply_getfield_steps(value, &steps)
}

fn builtin_setfield(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, path_values @ .., replacement] = args else {
        return Err(RuntimeError::Unsupported(
            "setfield currently expects a struct input, one or more selectors, and a replacement value"
                .to_string(),
        ));
    };
    if path_values.is_empty() {
        return Err(RuntimeError::Unsupported(
            "setfield currently expects at least one field or index selector".to_string(),
        ));
    }
    let steps = path_values
        .iter()
        .map(|value| struct_field_step(value, "setfield"))
        .collect::<Result<Vec<_>, _>>()?;
    apply_setfield_steps(value, &steps, replacement.clone())
}

#[derive(Debug, Clone)]
enum StructFieldStep {
    Field(String),
    Index(Vec<usize>),
}

fn struct_field_step(value: &Value, builtin_name: &str) -> Result<StructFieldStep, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => Ok(StructFieldStep::Field(text.clone())),
        Value::Scalar(_) => Ok(StructFieldStep::Index(vec![positive_integer_scalar(
            value,
            builtin_name,
        )?])),
        Value::Matrix(matrix) if matrix_is_numeric(matrix) && matrix.rows == 1 && matrix.cols == 1 => {
            Ok(StructFieldStep::Index(vec![positive_integer_scalar(
                value,
                builtin_name,
            )?]))
        }
        Value::Cell(cell) => {
            if cell.element_count() == 0 {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects nonempty cell index selectors"
                )));
            }
            Ok(StructFieldStep::Index(
                cell.elements()
                    .iter()
                    .map(|element| positive_integer_scalar(element, builtin_name))
                    .collect::<Result<Vec<_>, _>>()?,
            ))
        }
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects text field names and positive integer index selectors, found {}",
            other.kind_name()
        ))),
    }
}

fn struct_array_subscript_index(
    matrix: &MatrixValue,
    subscripts: &[usize],
    builtin_name: &str,
) -> Result<usize, RuntimeError> {
    let dims = canonical_size_vector(matrix.dims());
    let element_count = dims.iter().product::<usize>();
    if subscripts.len() == 1 {
        let index = subscripts[0];
        if index == 0 || index > element_count {
            return Err(RuntimeError::InvalidIndex(format!(
                "{builtin_name} index {} is out of range 1..{}",
                index, element_count
            )));
        }
        let column_index = column_major_multi_index(index - 1, &dims);
        return Ok(row_major_linear_index(&column_index, &dims));
    }

    if dims.len() > subscripts.len() && dims[subscripts.len()..].iter().any(|&dim| dim != 1) {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects selector cells to name every non-singleton struct-array dimension"
        )));
    }

    let mut normalized_dims = dims.clone();
    while normalized_dims.len() < subscripts.len() {
        normalized_dims.push(1);
    }

    let zero_based = subscripts
        .iter()
        .enumerate()
        .map(|(axis, &subscript)| {
            let extent = normalized_dims[axis];
            if subscript == 0 || subscript > extent {
                Err(RuntimeError::InvalidIndex(format!(
                    "{builtin_name} subscript {} for dimension {} is out of range 1..{}",
                    subscript,
                    axis + 1,
                    extent
                )))
            } else {
                Ok(subscript - 1)
            }
        })
        .collect::<Result<Vec<_>, _>>()?;
    Ok(row_major_linear_index(&zero_based, &normalized_dims))
}

fn apply_getfield_steps(value: &Value, steps: &[StructFieldStep]) -> Result<Value, RuntimeError> {
    let Some((first, rest)) = steps.split_first() else {
        return Ok(value.clone());
    };
    let next = match first {
        StructFieldStep::Field(field_name) => match value {
            Value::Struct(struct_value) => struct_value
                .fields
                .get(field_name)
                .cloned()
                .ok_or_else(|| {
                    RuntimeError::MissingVariable(format!(
                        "getfield field `{field_name}` is not defined"
                    ))
                })?,
            Value::Matrix(matrix) if matrix_is_struct(matrix) && matrix.element_count() == 1 => {
                let Value::Struct(struct_value) = &matrix.elements()[0] else {
                    unreachable!("matrix_is_struct checked every element");
                };
                struct_value
                    .fields
                    .get(field_name)
                    .cloned()
                    .ok_or_else(|| {
                        RuntimeError::MissingVariable(format!(
                            "getfield field `{field_name}` is not defined"
                        ))
                    })?
            }
            other => {
                return Err(RuntimeError::TypeError(format!(
                    "getfield field access expects a struct value, found {}",
                    other.kind_name()
                )))
            }
        },
        StructFieldStep::Index(subscripts) => match value {
            Value::Matrix(matrix) if matrix_is_struct(matrix) => matrix.elements()
                [struct_array_subscript_index(matrix, subscripts, "getfield")?]
            .clone(),
            other => {
                return Err(RuntimeError::TypeError(format!(
                    "getfield index selectors expect a struct array value, found {}",
                    other.kind_name()
                )))
            }
        },
    };
    apply_getfield_steps(&next, rest)
}

fn apply_setfield_steps(
    value: &Value,
    steps: &[StructFieldStep],
    replacement: Value,
) -> Result<Value, RuntimeError> {
    let Some((first, rest)) = steps.split_first() else {
        return Ok(replacement);
    };

    match first {
        StructFieldStep::Field(field_name) => match value {
            Value::Struct(struct_value) => {
                let mut struct_value = struct_value.clone();
                let next = if rest.is_empty() {
                    replacement.clone()
                } else {
                    let existing = struct_value
                        .fields
                        .get(field_name)
                        .cloned()
                        .unwrap_or_else(|| Value::Struct(StructValue::default()));
                    apply_setfield_steps(&existing, rest, replacement)?
                };
                struct_value.insert_field(field_name.clone(), next);
                Ok(Value::Struct(struct_value))
            }
            Value::Matrix(matrix) if matrix_is_struct(matrix) && matrix.element_count() == 1 => {
                let updated = apply_setfield_steps(&matrix.elements()[0], steps, replacement)?;
                let Value::Struct(updated_struct) = updated else {
                    unreachable!("setting a struct field should keep struct type");
                };
                Ok(Value::Matrix(MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    matrix.dims().to_vec(),
                    vec![Value::Struct(updated_struct)],
                )?))
            }
            other => Err(RuntimeError::TypeError(format!(
                "setfield field access expects a struct value, found {}",
                other.kind_name()
            ))),
        },
        StructFieldStep::Index(subscripts) => match value {
            Value::Matrix(matrix) if matrix_is_struct(matrix) => {
                let mut elements = matrix.elements().to_vec();
                let linear = struct_array_subscript_index(matrix, subscripts, "setfield")?;
                let updated = apply_setfield_steps(&elements[linear], rest, replacement)?;
                elements[linear] = updated;
                Ok(Value::Matrix(MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    matrix.dims().to_vec(),
                    elements,
                )?))
            }
            other => Err(RuntimeError::TypeError(format!(
                "setfield index selectors expect a struct array value, found {}",
                other.kind_name()
            ))),
        },
    }
}

fn orderfields_target_order(
    struct_value: &StructValue,
    rest: &[Value],
) -> Result<Vec<String>, RuntimeError> {
    match rest {
        [] => {
            let mut names = struct_value.field_names().to_vec();
            names.sort_unstable();
            Ok(names)
        }
        [order] => match order {
            Value::Struct(template) => Ok(template.field_names().to_vec()),
            Value::Matrix(matrix) if matrix_is_struct(matrix) => {
                let Some(Value::Struct(template)) = matrix.elements().first() else {
                    return Ok(Vec::new());
                };
                Ok(template.field_names().to_vec())
            }
            _ => {
                if let Ok((field_names, _)) = field_name_operand(order, "orderfields") {
                    Ok(field_names)
                } else {
                    orderfields_permutation_names(struct_value, order)
                }
            }
        },
        _ => Err(RuntimeError::Unsupported(
            "orderfields currently supports at most one ordering input".to_string(),
        )),
    }
}

fn orderfields_permutation_names(
    struct_value: &StructValue,
    order: &Value,
) -> Result<Vec<String>, RuntimeError> {
    let matrix = coerce_matrix(order)?;
    let count = struct_value.fields.len();
    let mut names = Vec::with_capacity(matrix.element_count());
    let mut seen = BTreeSet::new();
    for element in matrix.elements() {
        let index = element.as_scalar()?;
        if !index.is_finite() || index < 1.0 || index.fract() != 0.0 {
            return Err(RuntimeError::TypeError(
                "orderfields permutation input currently expects positive integer indices"
                    .to_string(),
            ));
        }
        let index = index as usize;
        if index == 0 || index > count {
            return Err(RuntimeError::ShapeError(format!(
                "orderfields permutation index {} is out of range 1..{}",
                index, count
            )));
        }
        if !seen.insert(index) {
            return Err(RuntimeError::ShapeError(
                "orderfields permutation input currently expects unique indices".to_string(),
            ));
        }
        names.push(struct_value.field_names()[index - 1].clone());
    }
    Ok(names)
}

fn order_struct_fields(
    struct_value: &StructValue,
    target_order: Vec<String>,
) -> Result<(StructValue, Vec<f64>), RuntimeError> {
    if target_order.len() != struct_value.fields.len() {
        return Err(RuntimeError::ShapeError(format!(
            "orderfields expects {} field name(s), found {}",
            struct_value.fields.len(),
            target_order.len()
        )));
    }

    let mut permutation = Vec::with_capacity(target_order.len());
    let mut seen = BTreeSet::new();
    for field_name in &target_order {
        let Some(position) = struct_value
            .field_names()
            .iter()
            .position(|candidate| candidate == field_name)
        else {
            return Err(RuntimeError::MissingVariable(format!(
                "orderfields field `{field_name}` is not defined"
            )));
        };
        if !seen.insert(position) {
            return Err(RuntimeError::ShapeError(
                "orderfields currently expects each field exactly once".to_string(),
            ));
        }
        permutation.push((position + 1) as f64);
    }

    Ok((
        StructValue::with_field_order(struct_value.fields.clone(), target_order),
        permutation,
    ))
}

fn field_name_operand(
    value: &Value,
    name: &str,
) -> Result<(Vec<String>, Vec<usize>), RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) => Ok((vec![text.clone()], vec![1, 1])),
        Value::Cell(cell) => {
            let field_names = cell
                .elements
                .iter()
                .map(|element| text_value(element).map(str::to_string))
                .collect::<Result<Vec<_>, RuntimeError>>()?;
            Ok((field_names, canonical_size_vector(&cell.dims)))
        }
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            let operand = text_operand(value)?;
            Ok((operand.values, canonical_size_vector(&matrix.dims)))
        }
        other => Err(RuntimeError::TypeError(format!(
            "{name} currently expects a text field name, text array, or cell array of text field names, found {}",
            other.kind_name()
        ))),
    }
}

fn struct_value_has_field(value: &Value, field_name: &str) -> Result<bool, RuntimeError> {
    match value {
        Value::Struct(struct_value) => Ok(struct_value.fields.contains_key(field_name)),
        Value::Matrix(matrix) if matrix_is_struct(matrix) => Ok(matrix.iter().all(|element| {
            let Value::Struct(struct_value) = element else {
                return false;
            };
            struct_value.fields.contains_key(field_name)
        })),
        Value::Object(_) => Ok(false),
        Value::Matrix(matrix)
            if matrix
                .elements()
                .iter()
                .all(|element| matches!(element, Value::Object(_))) =>
        {
            Ok(false)
        }
        _ => Err(RuntimeError::TypeError(format!(
            "isfield expects a struct or struct-array input, found {}",
            value.kind_name()
        ))),
    }
}

fn build_logical_field_result(
    field_dims: Vec<usize>,
    values: Vec<Value>,
) -> Result<Value, RuntimeError> {
    if field_dims.iter().product::<usize>() == 1 {
        return Ok(values.into_iter().next().expect("scalar isfield result"));
    }
    let (rows, cols) = storage_shape_from_dimensions(&field_dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows, cols, field_dims, values,
    )?))
}

fn builtin_size(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let Some((value, query_dims)) = parse_size_arguments(args)? else {
        return Err(RuntimeError::Unsupported(
            "size currently supports `size(A)`, `size(A, dim)`/`size(A, [dims])`, or `size(A, dim1, dim2, ...)`".to_string(),
        ));
    };

    let dims = value_dimensions(value);
    let canonical_dims = canonical_size_vector(&dims);
    if let Some(query_dims) = query_dims {
        let queried = query_dims
            .iter()
            .map(|&dim| Value::Scalar(dimension_length(&dims, dim) as f64))
            .collect::<Vec<_>>();
        return match output_arity {
            0 | 1 => Ok(vec![build_scalar_matrix_result(1, queried.len(), queried)?]),
            arity if arity == queried.len() => Ok(queried),
            _ => Err(RuntimeError::Unsupported(
                "size with explicit dimension queries currently expects one output or one output per queried dimension".to_string(),
            )),
        };
    }

    let values = canonical_dims
        .iter()
        .copied()
        .map(|dim| Value::Scalar(dim as f64))
        .collect::<Vec<_>>();
    match output_arity {
        0 | 1 => Ok(vec![build_scalar_matrix_result(
            1,
            canonical_dims.len(),
            values[..canonical_dims.len()].to_vec(),
        )?]),
        arity => {
            let mut outputs = values[..canonical_dims.len()].to_vec();
            while outputs.len() < arity {
                outputs.push(Value::Scalar(1.0));
            }
            Ok(outputs)
        }
    }
}

fn builtin_deal(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match output_arity {
        0 => Ok(Vec::new()),
        1 if args.len() == 1 => Ok(vec![args[0].clone()]),
        _ if args.len() == 1 => Ok(vec![args[0].clone(); output_arity]),
        _ if args.len() == output_arity => Ok(args.to_vec()),
        _ => Err(RuntimeError::Unsupported(format!(
            "deal currently expects the number of inputs to match the requested outputs (requested {output_arity}, got {})",
            args.len()
        ))),
    }
}

fn builtin_struct(args: &[Value]) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Ok(Value::Struct(StructValue::default()));
    }

    if args.len() % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "struct currently expects field/value pairs".to_string(),
        ));
    }

    let mut field_names = Vec::new();
    let mut field_values = Vec::new();
    let mut array_dims = None;
    for pair in args.chunks_exact(2) {
        let field_name = text_value(&pair[0])?.to_string();
        match &pair[1] {
            Value::Cell(cell) => {
                let cell_dims = canonical_size_vector(cell.dims());
                match &array_dims {
                    Some(existing_dims) if *existing_dims != cell_dims => {
                        return Err(RuntimeError::ShapeError(
                            "struct cell-valued fields must share the same shape".to_string(),
                        ))
                    }
                    None => array_dims = Some(cell_dims),
                    Some(_) => {}
                }
            }
            _ => {}
        }
        field_names.push(field_name);
        field_values.push(pair[1].clone());
    }

    let Some(array_dims) = array_dims else {
        let order = field_names.clone();
        let fields = field_names.into_iter().zip(field_values).collect();
        return Ok(Value::Struct(StructValue::with_field_order(fields, order)));
    };

    let (rows, cols) = storage_shape_from_dimensions(&array_dims);
    let element_count = array_dims.iter().product::<usize>();
    let mut elements = Vec::with_capacity(element_count);
    for offset in 0..element_count {
        let mut fields = std::collections::BTreeMap::new();
        for (field_name, field_value) in field_names.iter().zip(field_values.iter()) {
            let value = match field_value {
                Value::Cell(cell) => cell.elements[offset].clone(),
                other => other.clone(),
            };
            fields.insert(field_name.clone(), value);
        }
        elements.push(Value::Struct(StructValue::with_field_order(
            fields,
            field_names.clone(),
        )));
    }

    if array_dims.iter().all(|&size| size == 1) {
        Ok(elements.into_iter().next().expect("single struct"))
    } else {
        Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows, cols, array_dims, elements,
        )?))
    }
}

fn builtin_char(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "char currently supports exactly one argument".to_string(),
        ));
    };

    match value {
        Value::CharArray(text) | Value::String(text) => Ok(Value::CharArray(text.clone())),
        Value::Scalar(number) => Ok(Value::CharArray(char_code_text(
            std::iter::once(*number),
            "char",
        )?)),
        Value::Matrix(matrix) if matrix_is_numeric(matrix) && matrix.rows <= 1 => {
            Ok(Value::CharArray(char_code_text(
                matrix.elements().iter().map(|element| match element {
                    Value::Scalar(number) => *number,
                    _ => unreachable!("matrix_is_numeric checked every element"),
                }),
                "char",
            )?))
        }
        other => Err(RuntimeError::TypeError(format!(
            "char currently expects text, a scalar numeric code point, or a 1xN numeric vector, found {}",
            other.kind_name()
        ))),
    }
}

fn char_code_text(
    codes: impl IntoIterator<Item = f64>,
    builtin_name: &str,
) -> Result<String, RuntimeError> {
    let mut text = String::new();
    for code in codes {
        if !code.is_finite() || code.fract() != 0.0 || code < 0.0 || code > u32::MAX as f64 {
            return Err(RuntimeError::TypeError(format!(
                "{builtin_name} currently expects integer Unicode code points"
            )));
        }
        let Some(ch) = char::from_u32(code as u32) else {
            return Err(RuntimeError::TypeError(format!(
                "{builtin_name} currently expects valid Unicode code points"
            )));
        };
        text.push(ch);
    }
    Ok(text)
}

fn builtin_str2double(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "str2double currently supports exactly one argument".to_string(),
        ));
    };

    let (operand, dims) = split_text_operand(value)?;
    let values = operand
        .values
        .iter()
        .map(|text| parse_str2double_text(text))
        .collect::<Vec<_>>();
    build_scalar_matrix_result_with_dimensions(dims, values)
}

fn parse_str2double_text(text: &str) -> Value {
    let trimmed = text.trim();
    if trimmed.is_empty() {
        return Value::Scalar(f64::NAN);
    }

    if let Some(real) = parse_str2double_real(trimmed) {
        return Value::Scalar(real);
    }

    if let Some(complex) = parse_str2double_complex(trimmed) {
        return numeric_or_complex_value(complex);
    }

    Value::Scalar(f64::NAN)
}

fn parse_str2double_real(text: &str) -> Option<f64> {
    let lower = text.to_ascii_lowercase();
    match lower.as_str() {
        "inf" | "+inf" | "infinity" | "+infinity" => Some(f64::INFINITY),
        "-inf" | "-infinity" => Some(f64::NEG_INFINITY),
        "nan" | "+nan" | "-nan" => Some(f64::NAN),
        _ => text.parse::<f64>().ok(),
    }
}

fn parse_str2double_complex(text: &str) -> Option<ComplexParts> {
    let compact = text
        .chars()
        .filter(|ch| !ch.is_whitespace())
        .collect::<String>();
    let lower = compact.to_ascii_lowercase();
    if !(lower.ends_with('i') || lower.ends_with('j')) {
        return None;
    }

    let body = &compact[..compact.len() - 1];
    if body.is_empty() || body == "+" || body == "-" {
        return Some(ComplexParts {
            real: 0.0,
            imag: if body == "-" { -1.0 } else { 1.0 },
        });
    }

    if let Some(imag) = parse_str2double_real(body) {
        return Some(ComplexParts { real: 0.0, imag });
    }

    let split = split_str2double_complex_parts(body)?;
    let real = parse_str2double_real(split.0)?;
    let imag = if split.1.is_empty() || split.1 == "+" || split.1 == "-" {
        if split.1 == "-" {
            -1.0
        } else {
            1.0
        }
    } else {
        parse_str2double_real(split.1)?
    };
    Some(ComplexParts { real, imag })
}

fn split_str2double_complex_parts(text: &str) -> Option<(&str, &str)> {
    let chars = text.char_indices().collect::<Vec<_>>();
    for (offset, ch) in chars.iter().copied().skip(1).rev() {
        if (ch == '+' || ch == '-')
            && !matches!(
                chars
                    .iter()
                    .take_while(|(index, _)| *index < offset)
                    .last()
                    .map(|(_, prev)| *prev),
                Some('e' | 'E')
            )
        {
            return Some((&text[..offset], &text[offset..]));
        }
    }
    None
}

fn builtin_cellstr(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "cellstr currently supports exactly one argument".to_string(),
        ));
    };

    match value {
        Value::CharArray(text) | Value::String(text) => Ok(Value::Cell(CellValue::new(
            1,
            1,
            vec![Value::CharArray(text.clone())],
        )?)),
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            if matrix_is_char_matrix(matrix) && canonical_size_vector(matrix.dims()).len() <= 2 {
                let mut rows = Vec::with_capacity(matrix.rows);
                for row in 0..matrix.rows {
                    let text = (0..matrix.cols)
                        .map(|col| {
                            single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                                RuntimeError::TypeError(
                                    "cellstr currently expects char matrices to contain single-character elements"
                                        .to_string(),
                                )
                            })
                        })
                        .collect::<Result<String, _>>()?;
                    rows.push(Value::CharArray(text.trim_end().to_string()));
                }
                return Ok(Value::Cell(CellValue::new(matrix.rows, 1, rows)?));
            }
            Ok(Value::Cell(CellValue::with_dimensions(
                matrix.rows,
                matrix.cols,
                matrix.dims().to_vec(),
                matrix
                    .elements()
                    .iter()
                    .map(|element| Ok(Value::CharArray(text_value(element)?.to_string())))
                    .collect::<Result<Vec<_>, RuntimeError>>()?,
            )?))
        }
        other => Err(RuntimeError::TypeError(format!(
            "cellstr currently expects char, string, or a text matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_error(args: &[Value]) -> Result<Vec<Value>, RuntimeError> {
    let (identifier, format, format_values) = match args {
        [message] => ("MATC:UserError".to_string(), text_value(message)?, &[][..]),
        [first, rest @ ..] => {
            let first_text = text_value(first)?;
            if looks_like_error_identifier(first_text) {
                let Some((message, values)) = rest.split_first() else {
                    return Err(RuntimeError::Unsupported(
                        "error currently expects a message or format after the identifier"
                            .to_string(),
                    ));
                };
                (first_text.to_string(), text_value(message)?, values)
            } else {
                ("MATC:UserError".to_string(), first_text, rest)
            }
        }
        [] => {
            return Err(RuntimeError::Unsupported(
                "error currently expects at least one message or format argument".to_string(),
            ))
        }
    };

    let message = if format_values.is_empty() {
        format.to_string()
    } else {
        format_text_builtin(format, format_values, "error")?
    };

    Err(RuntimeError::UserDefined {
        identifier,
        message,
        stack: Vec::new(),
        cause: Vec::new(),
    })
}

fn builtin_mexception(args: &[Value]) -> Result<Value, RuntimeError> {
    let [identifier, format, format_values @ ..] = args else {
        return Err(RuntimeError::Unsupported(
            "MException currently expects an identifier plus a message or format string"
                .to_string(),
        ));
    };

    let message = if format_values.is_empty() {
        text_value(format)?.to_string()
    } else {
        format_text_builtin(text_value(format)?, format_values, "MException")?
    };

    Ok(runtime_error_struct_value(&RuntimeError::UserDefined {
        identifier: text_value(identifier)?.to_string(),
        message,
        stack: Vec::new(),
        cause: Vec::new(),
    }))
}

fn builtin_add_cause(args: &[Value]) -> Result<Value, RuntimeError> {
    let [base, cause] = args else {
        return Err(RuntimeError::Unsupported(
            "addCause currently supports exactly two error-struct arguments".to_string(),
        ));
    };

    let base = runtime_error_from_value(base, "addCause")?;
    let cause = runtime_error_from_value(cause, "addCause")?;
    Ok(runtime_error_struct_value(&base.with_cause(cause)))
}

fn builtin_get_report(args: &[Value]) -> Result<Value, RuntimeError> {
    let (error_value, mode) = match args {
        [error_value] => (error_value, GetReportMode::Extended),
        [error_value, mode] => (error_value, parse_get_report_mode(mode)?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "getReport currently supports one error-struct argument plus an optional basic/extended mode"
                    .to_string(),
            ))
        }
    };

    let error = runtime_error_from_value(error_value, "getReport")?;
    Ok(Value::CharArray(render_runtime_error_report_with_mode(
        &error, 0, mode,
    )))
}

fn builtin_throw(args: &[Value]) -> Result<Vec<Value>, RuntimeError> {
    let [error_value] = args else {
        return Err(RuntimeError::Unsupported(
            "throw currently supports exactly one error-struct argument".to_string(),
        ));
    };

    Err(runtime_error_from_value(error_value, "throw")?)
}

fn builtin_rethrow(args: &[Value]) -> Result<Vec<Value>, RuntimeError> {
    let [error_value] = args else {
        return Err(RuntimeError::Unsupported(
            "rethrow currently supports exactly one error-struct argument".to_string(),
        ));
    };

    Err(runtime_error_from_value(error_value, "rethrow")?)
}

fn builtin_throw_as_caller(args: &[Value]) -> Result<Vec<Value>, RuntimeError> {
    let [error_value] = args else {
        return Err(RuntimeError::Unsupported(
            "throwAsCaller currently supports exactly one error-struct argument".to_string(),
        ));
    };

    Err(runtime_error_from_value(error_value, "throwAsCaller")?
        .clear_stack()
        .throw_as_caller())
}

fn builtin_string(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "string currently supports exactly one argument".to_string(),
        ));
    };

    match value {
        Value::Scalar(number) => Ok(Value::String(render_scalar(*number))),
        Value::Logical(flag) => Ok(Value::String(render_logical(*flag))),
        Value::CharArray(text) | Value::String(text) => Ok(Value::String(text.clone())),
        Value::Matrix(matrix) => {
            let mut elements = Vec::with_capacity(matrix.elements.len());
            for element in &matrix.elements {
                let text = match element {
                    Value::Scalar(number) => render_scalar(*number),
                    Value::Logical(flag) => render_logical(*flag),
                    Value::CharArray(text) | Value::String(text) => text.clone(),
                    other => {
                        return Err(RuntimeError::TypeError(format!(
                            "string currently expects scalar/logical/text matrix elements, found {}",
                            other.kind_name()
                        )))
                    }
                };
                elements.push(Value::String(text));
            }
            Ok(Value::Matrix(MatrixValue::new(
                matrix.rows,
                matrix.cols,
                elements,
            )?))
        }
        Value::Cell(cell) => {
            let mut elements = Vec::with_capacity(cell.element_count());
            for element in cell.elements() {
                let text = match element {
                    Value::Scalar(number) => render_scalar(*number),
                    Value::Logical(flag) => render_logical(*flag),
                    Value::CharArray(text) | Value::String(text) => text.clone(),
                    other => {
                        return Err(RuntimeError::TypeError(format!(
                            "string currently expects scalar/logical/text cell elements, found {}",
                            other.kind_name()
                        )))
                    }
                };
                elements.push(Value::String(text));
            }
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                cell.rows,
                cell.cols,
                cell.dims().to_vec(),
                elements,
            )?))
        }
        other => Err(RuntimeError::TypeError(format!(
            "string currently expects scalar, logical, text, a compatible matrix, or a compatible cell array input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_diag(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, offset) = match args {
        [value] => (value, 0isize),
        [value, offset] => (value, diagonal_offset(offset, "diag")?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "diag currently supports `diag(a)` or `diag(a, k)`".to_string(),
            ))
        }
    };

    match value {
        Value::Scalar(number) => diag_build_from_values(
            vec![ComplexParts {
                real: *number,
                imag: 0.0,
            }],
            offset,
        ),
        Value::Complex(number) => diag_build_from_values(
            vec![ComplexParts {
                real: number.real,
                imag: number.imag,
            }],
            offset,
        ),
        Value::CharArray(text) => diag_build_from_chars(text.chars().collect(), offset),
        Value::Matrix(matrix) => {
            if matrix_is_char_matrix(matrix) {
                if matrix.rows == 1 || matrix.cols == 1 {
                    let diagonal = matrix
                        .iter()
                        .map(|element| {
                            single_char_text_value(element).ok_or_else(|| {
                                RuntimeError::TypeError(
                                    "diag currently expects char matrices to contain single-character elements"
                                        .to_string(),
                                )
                            })
                        })
                        .collect::<Result<Vec<_>, _>>()?;
                    return diag_build_from_chars(diagonal, offset);
                }

                let start_row = if offset < 0 { offset.unsigned_abs() } else { 0 };
                let start_col = if offset > 0 { offset as usize } else { 0 };
                let size = matrix
                    .rows
                    .saturating_sub(start_row)
                    .min(matrix.cols.saturating_sub(start_col));
                let chars = (0..size)
                    .map(|index| {
                        single_char_text_value(matrix.get(start_row + index, start_col + index))
                            .ok_or_else(|| {
                                RuntimeError::TypeError(
                                    "diag currently expects char matrices to contain single-character elements"
                                        .to_string(),
                                )
                            })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(vec![size, 1], chars);
            }
            if !matrix_is_numeric_or_complex(matrix) {
                return Err(RuntimeError::TypeError(
                    "diag currently expects numeric, complex, or char scalar or matrix input"
                        .to_string(),
                ));
            }
            if matrix.rows == 1 || matrix.cols == 1 {
                let diagonal = matrix
                    .iter()
                    .map(|element| numeric_or_complex_scalar(element, "diag"))
                    .collect::<Result<Vec<_>, _>>()?;
                diag_build_from_values(diagonal, offset)
            } else {
                let start_row = if offset < 0 { offset.unsigned_abs() } else { 0 };
                let start_col = if offset > 0 { offset as usize } else { 0 };
                let size = matrix
                    .rows
                    .saturating_sub(start_row)
                    .min(matrix.cols.saturating_sub(start_col));
                let elements = (0..size)
                    .map(|index| Ok(matrix.get(start_row + index, start_col + index).clone()))
                    .collect::<Result<Vec<_>, RuntimeError>>()?;
                Ok(Value::Matrix(MatrixValue::new(size, 1, elements)?))
            }
        }
        _ => Err(RuntimeError::TypeError(
            "diag currently expects numeric, complex, or char scalar or matrix input".to_string(),
        )),
    }
}

fn diag_build_from_values(values: Vec<ComplexParts>, offset: isize) -> Result<Value, RuntimeError> {
    let size = values.len() + offset.unsigned_abs();
    let row_offset = if offset < 0 { offset.unsigned_abs() } else { 0 };
    let col_offset = if offset > 0 { offset as usize } else { 0 };
    let mut elements = vec![Value::Scalar(0.0); size * size];
    for (index, value) in values.into_iter().enumerate() {
        let row = row_offset + index;
        let col = col_offset + index;
        elements[row * size + col] = numeric_or_complex_value(value);
    }
    Ok(Value::Matrix(MatrixValue::new(size, size, elements)?))
}

fn diag_build_from_chars(values: Vec<char>, offset: isize) -> Result<Value, RuntimeError> {
    let size = values.len() + offset.unsigned_abs();
    let row_offset = if offset < 0 { offset.unsigned_abs() } else { 0 };
    let col_offset = if offset > 0 { offset as usize } else { 0 };
    let mut chars = vec!['\0'; size * size];
    for (index, value) in values.into_iter().enumerate() {
        let row = row_offset + index;
        let col = col_offset + index;
        chars[row * size + col] = value;
    }
    char_value_with_dimensions(vec![size, size], chars)
}

