fn builtin_repmat(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((value, repetitions)) = parse_repmat_arguments(args)? else {
        return Err(RuntimeError::Unsupported(
            "repmat currently supports `repmat(A, n)`, `repmat(A, rows, cols, ...)`, or `repmat(A, [repetitions])`".to_string(),
        ));
    };

    match value {
        Value::Scalar(_) | Value::Matrix(_) | Value::Object(_) => {
            let matrix = coerce_matrix(value)?;
            let tiled = tile_matrix_nd(&matrix, &repetitions)?;
            if matrix_is_char_matrix(&matrix) {
                let chars = tiled
                    .elements()
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(
                                "repmat currently expects char matrices to contain single-character elements"
                                    .to_string(),
                            )
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(tiled.dims().to_vec(), chars);
            }
            Ok(Value::Matrix(tiled))
        }
        Value::Cell(cell) => Ok(Value::Cell(tile_cell_nd(cell, &repetitions)?)),
        Value::CharArray(text) => tile_char_array(text, &repetitions),
        _ => Err(RuntimeError::TypeError(
            "repmat currently expects scalar, object, matrix, cell, or row-char input".to_string(),
        )),
    }
}

fn builtin_reshape(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((value, dims)) = parse_reshape_arguments(args)? else {
        return Err(RuntimeError::Unsupported(
            "reshape currently supports `reshape(A, m, n, ...)`, `reshape(A, m, [])`, or `reshape(A, [dims])`".to_string(),
        ));
    };
    let dims = finalize_reshape_dimensions(value, dims)?;
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    let target_len = dims.iter().product::<usize>();

    match value {
        Value::Scalar(number) => {
            if target_len != 1 {
                return Err(RuntimeError::ShapeError(format!(
                    "cannot reshape scalar into {}x{} result",
                    rows, cols
                )));
            }
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                1,
                1,
                dims.clone(),
                vec![Value::Scalar(*number)],
            )?))
        }
        Value::Object(object) => {
            if target_len != 1 {
                return Err(RuntimeError::ShapeError(format!(
                    "cannot reshape scalar object into {}x{} result",
                    rows, cols
                )));
            }
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                1,
                1,
                dims.clone(),
                vec![Value::Object(object.clone())],
            )?))
        }
        Value::CharArray(text) => {
            let chars = text.chars().collect::<Vec<_>>();
            if chars.len() != target_len {
                return Err(RuntimeError::ShapeError(format!(
                    "reshape target {}x{} does not match {} element(s)",
                    rows,
                    cols,
                    chars.len()
                )));
            }
            let elements = reshape_elements_column_major(&chars, &value_dimensions(value), &dims);
            char_value_with_dimensions(dims, elements)
        }
        Value::Matrix(matrix) => {
            if matrix.element_count() != target_len {
                return Err(RuntimeError::ShapeError(format!(
                    "reshape target {}x{} does not match {} element(s)",
                    rows,
                    cols,
                    matrix.element_count()
                )));
            }
            let elements = reshape_elements_column_major(matrix.elements(), matrix.dims(), &dims);
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                dims.clone(),
                elements,
            )?))
        }
        Value::Cell(cell) => {
            if cell.element_count() != target_len {
                return Err(RuntimeError::ShapeError(format!(
                    "reshape target {}x{} does not match {} element(s)",
                    rows,
                    cols,
                    cell.element_count()
                )));
            }
            let elements = reshape_elements_column_major(cell.elements(), cell.dims(), &dims);
            Ok(Value::Cell(CellValue::with_dimensions(
                rows, cols, dims, elements,
            )?))
        }
        _ => Err(RuntimeError::TypeError(
            "reshape currently expects scalar, object, char, matrix, or cell input".to_string(),
        )),
    }
}

