fn builtin_trace(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "trace currently supports exactly one argument".to_string(),
        ));
    };

    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Logical(flag) => Ok(Value::Scalar(if *flag { 1.0 } else { 0.0 })),
        Value::Complex(number) => Ok(Value::Complex(number.clone())),
        Value::Matrix(matrix) => {
            if !matrix_is_numeric_or_complex(matrix) {
                return Err(RuntimeError::TypeError(
                    "trace currently expects numeric or complex scalar or matrix input".to_string(),
                ));
            }
            let operand = numeric_or_complex_operand(value, "trace")?;
            let size = operand.rows.min(operand.cols);
            let total = (0..size).fold(ComplexParts::zero(), |total, index| {
                total.plus(operand.values[index * operand.cols + index])
            });
            Ok(numeric_or_complex_value(normalize_complex_parts(total)))
        }
        _ => Err(RuntimeError::TypeError(
            "trace currently expects numeric or complex scalar or matrix input".to_string(),
        )),
    }
}

fn builtin_rank(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, tolerance) = match args {
        [value] => (value, None),
        [value, tolerance] => (value, Some(tolerance)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "rank currently supports `rank(a)` or `rank(a, tol)`".to_string(),
            ))
        }
    };

    let operand = numeric_or_complex_operand(value, "rank")?;
    let tol = match tolerance {
        Some(tolerance) => {
            let tol = tolerance.as_scalar()?;
            if !tol.is_finite() || tol < 0.0 {
                return Err(RuntimeError::TypeError(
                    "rank currently expects a nonnegative finite scalar tolerance".to_string(),
                ));
            }
            tol
        }
        None => default_rank_tolerance(&operand)?,
    };

    let singular_values = singular_values_and_right_vectors_with_tolerance(&operand, tol)?;
    Ok(Value::Scalar(singular_values.len() as f64))
}

fn builtin_rref(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "rref currently supports one or two outputs".to_string(),
        ));
    }

    let (value, tolerance) = match args {
        [value] => (value, None),
        [value, tolerance] => (value, Some(tolerance)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "rref currently supports `rref(a)` and `rref(a, tol)`".to_string(),
            ))
        }
    };

    let operand = numeric_or_complex_operand(value, "rref")?;
    let tol = match tolerance {
        Some(tolerance) => {
            let tol = tolerance.as_scalar()?;
            if !tol.is_finite() || tol < 0.0 {
                return Err(RuntimeError::TypeError(
                    "rref currently expects a nonnegative finite scalar tolerance".to_string(),
                ));
            }
            tol
        }
        None => default_rref_tolerance(&operand)?,
    };

    let reduced = reduced_row_echelon_form(&operand, tol);
    let result_values = reduced
        .values
        .into_iter()
        .map(|value| {
            if value.magnitude() <= tol {
                ComplexParts::zero()
            } else {
                value
            }
        })
        .collect::<Vec<_>>();
    let result = numeric_or_complex_operand_to_value(&NumericOrComplexOperand {
        rows: operand.rows,
        cols: operand.cols,
        values: result_values,
    })?;
    if output_arity <= 1 {
        return Ok(vec![result]);
    }

    Ok(vec![
        result,
        numeric_values_to_row_matrix(
            reduced
                .pivot_columns
                .into_iter()
                .map(|column| (column + 1) as f64)
                .collect::<Vec<_>>(),
        )?,
    ])
}

