fn builtin_norm(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, kind_value) = match args {
        [value] => (value, None),
        [value, kind] => (value, Some(kind)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "norm currently supports `norm(a)` or `norm(a, p)`".to_string(),
            ))
        }
    };

    let operand = numeric_or_complex_operand(value, "norm")?;
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(Value::Scalar(0.0));
    }

    let is_vector = operand.rows == 1 || operand.cols == 1;
    let kind = parse_norm_kind(kind_value, is_vector)?;
    let result = if operand.rows == 1 && operand.cols == 1 {
        operand.values[0].magnitude()
    } else if is_vector {
        vector_norm(&operand.values, kind)
    } else {
        matrix_norm(&operand, kind)?
    };

    Ok(Value::Scalar(normalize_polynomial_scalar(result)))
}

