fn builtin_inv(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "inv currently supports exactly one argument".to_string(),
        ));
    };

    let operand = numeric_or_complex_operand(value, "inv")?;
    if operand.rows == 1 && operand.cols == 1 {
        if operand.values[0].is_approximately_zero() {
            return Err(RuntimeError::ShapeError(
                "inv currently does not support singular scalar input".to_string(),
            ));
        }
        return Ok(numeric_or_complex_value(normalize_complex_parts(
            ComplexParts::one().rdivide(operand.values[0]),
        )));
    }

    if operand.rows != operand.cols {
        return Err(RuntimeError::ShapeError(format!(
            "inv currently expects a square matrix input, found {}x{}",
            operand.rows, operand.cols
        )));
    }

    let inverse = solve_square_linear_system(
        &operand,
        &identity_numeric_or_complex_operand(operand.rows),
        "inv",
    )?;
    numeric_or_complex_operand_to_value(&inverse)
}

