fn builtin_funm(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "funm currently supports one or two outputs".to_string(),
        ));
    }

    let [value, fun] = args else {
        return Err(RuntimeError::Unsupported(
            "funm currently supports exactly two arguments".to_string(),
        ));
    };

    let operand = numeric_or_complex_operand(value, "funm")?;
    if operand.rows != operand.cols {
        return Err(RuntimeError::ShapeError(format!(
            "funm currently expects a square matrix input, found {}x{}",
            operand.rows, operand.cols
        )));
    }

    let function_name = matrix_function_name(fun)?;
    let result = apply_supported_matrix_function(&operand, &function_name)?;
    let mut outputs = vec![numeric_or_complex_operand_to_value(&result)?];
    if output_arity == 2 {
        outputs.push(Value::Scalar(0.0));
    }
    Ok(outputs)
}

