fn builtin_linspace(args: &[Value]) -> Result<Value, RuntimeError> {
    let (start, end, count) = match args {
        [start, end] => (start.as_scalar()?, end.as_scalar()?, 100usize),
        [start, end, count] => (
            start.as_scalar()?,
            end.as_scalar()?,
            scalar_dimension(count)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "linspace currently supports start,end or start,end,count forms".to_string(),
            ))
        }
    };

    let values = match count {
        0 => Vec::new(),
        1 => vec![Value::Scalar(end)],
        _ => {
            let step = (end - start) / (count - 1) as f64;
            (0..count)
                .map(|index| Value::Scalar(start + step * index as f64))
                .collect::<Vec<_>>()
        }
    };
    Ok(Value::Matrix(MatrixValue::new(1, count, values)?))
}

fn builtin_meshgrid(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match args {
        [x] => {
            let vector = meshgrid_vector(x)?;
            let (x_grid, y_grid) = meshgrid_outputs(&vector, &vector)?;
            match output_arity {
                0 | 1 => Ok(vec![x_grid]),
                2 => Ok(vec![x_grid, y_grid]),
                3 => {
                    let (x_grid, y_grid, z_grid) =
                        meshgrid_outputs_3d(&vector, &vector, &vector)?;
                    Ok(vec![x_grid, y_grid, z_grid])
                }
                _ => Err(RuntimeError::Unsupported(
                    "meshgrid currently supports at most three outputs for one-input forms"
                        .to_string(),
                )),
            }
        }
        [x, y] => {
            let x = meshgrid_vector(x)?;
            let y = meshgrid_vector(y)?;
            let (x_grid, y_grid) = meshgrid_outputs(&x, &y)?;
            match output_arity {
                0 | 1 => Ok(vec![x_grid]),
                2 => Ok(vec![x_grid, y_grid]),
                _ => Err(RuntimeError::Unsupported(
                    "meshgrid currently supports at most two outputs for two-input forms"
                        .to_string(),
                )),
            }
        }
        [x, y, z] => {
            let x = meshgrid_vector(x)?;
            let y = meshgrid_vector(y)?;
            let z = meshgrid_vector(z)?;
            let (x_grid, y_grid, z_grid) = meshgrid_outputs_3d(&x, &y, &z)?;
            match output_arity {
                0 | 1 => Ok(vec![x_grid]),
                2 => Ok(vec![x_grid, y_grid]),
                3 => Ok(vec![x_grid, y_grid, z_grid]),
                _ => Err(RuntimeError::Unsupported(
                    "meshgrid currently supports at most three outputs for three-input forms"
                        .to_string(),
                )),
            }
        }
        values if values.len() >= 2 => {
            let vectors = values
                .iter()
                .map(meshgrid_vector)
                .collect::<Result<Vec<_>, _>>()?;
            let outputs = meshgrid_outputs_nd(&vectors)?;
            match output_arity {
                0 | 1 => Ok(vec![outputs[0].clone()]),
                arity if arity <= outputs.len() => Ok(outputs.into_iter().take(arity).collect()),
                _ => Err(RuntimeError::Unsupported(format!(
                    "meshgrid currently supports at most {} outputs for {} input vectors",
                    outputs.len(),
                    vectors.len()
                ))),
            }
        }
        _ => Err(RuntimeError::Unsupported(
            "meshgrid currently supports `meshgrid(x)`, `meshgrid(x, y)`, or `meshgrid(x, y, z, ...)` with numeric vectors"
                .to_string(),
        )),
    }
}

fn builtin_ndgrid(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match args {
        [x] => {
            let vector = meshgrid_vector(x)?;
            match output_arity {
                0 | 1 => Ok(vec![numeric_values_to_column_matrix(vector)?]),
                arity => {
                    let vectors = vec![vector; arity];
                    let outputs = ndgrid_outputs_nd(&vectors)?;
                    Ok(outputs)
                }
            }
        }
        [x, y] => {
            let x = meshgrid_vector(x)?;
            let y = meshgrid_vector(y)?;
            let (x_grid, y_grid) = ndgrid_outputs(&x, &y)?;
            match output_arity {
                0 | 1 => Ok(vec![x_grid]),
                2 => Ok(vec![x_grid, y_grid]),
                _ => Err(RuntimeError::Unsupported(
                    "ndgrid currently supports at most two outputs".to_string(),
                )),
            }
        }
        [x, y, z] => {
            let x = meshgrid_vector(x)?;
            let y = meshgrid_vector(y)?;
            let z = meshgrid_vector(z)?;
            let (x_grid, y_grid, z_grid) = ndgrid_outputs_3d(&x, &y, &z)?;
            match output_arity {
                0 | 1 => Ok(vec![x_grid]),
                2 => Ok(vec![x_grid, y_grid]),
                3 => Ok(vec![x_grid, y_grid, z_grid]),
                _ => Err(RuntimeError::Unsupported(
                    "ndgrid currently supports at most three outputs".to_string(),
                )),
            }
        }
        values if values.len() >= 2 => {
            let vectors = values
                .iter()
                .map(meshgrid_vector)
                .collect::<Result<Vec<_>, _>>()?;
            let outputs = ndgrid_outputs_nd(&vectors)?;
            match output_arity {
                0 | 1 => Ok(vec![outputs[0].clone()]),
                arity if arity <= outputs.len() => Ok(outputs.into_iter().take(arity).collect()),
                _ => Err(RuntimeError::Unsupported(format!(
                    "ndgrid currently supports at most {} outputs for {} input vectors",
                    outputs.len(),
                    vectors.len()
                ))),
            }
        }
        _ => Err(RuntimeError::Unsupported(
            "ndgrid currently supports `ndgrid(x)`, `ndgrid(x, y)`, or `ndgrid(x, y, z)` with up to three outputs and numeric vector inputs".to_string(),
        )),
    }
}

fn meshgrid_outputs(x: &[f64], y: &[f64]) -> Result<(Value, Value), RuntimeError> {
    let rows = y.len();
    let cols = x.len();
    let mut x_elements = Vec::with_capacity(rows * cols);
    let mut y_elements = Vec::with_capacity(rows * cols);
    for y_value in y {
        for x_value in x {
            x_elements.push(Value::Scalar(*x_value));
            y_elements.push(Value::Scalar(*y_value));
        }
    }
    Ok((
        Value::Matrix(MatrixValue::new(rows, cols, x_elements)?),
        Value::Matrix(MatrixValue::new(rows, cols, y_elements)?),
    ))
}

fn builtin_histcounts(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let histogram = histogram_counts_and_edges(args, "histcounts")?;
    let counts = numeric_values_to_row_matrix(normalize_histogram_counts(
        histogram.counts,
        &histogram.edges,
        histogram.sample_count,
        histogram.normalization,
    ))?;
    let edges = numeric_values_to_row_matrix(histogram.edges.clone())?;
    let bins = build_scalar_matrix_result_with_dimensions(
        histogram.output_dims,
        histogram
            .bins
            .into_iter()
            .map(|bin| Value::Scalar(bin as f64))
            .collect::<Vec<_>>(),
    )?;

    match output_arity {
        0 | 1 => Ok(vec![counts]),
        2 => Ok(vec![counts, edges]),
        3 => Ok(vec![counts, edges, bins]),
        _ => Err(RuntimeError::Unsupported(
            "histcounts currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn builtin_histcounts2(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let histogram = histogram2_counts_and_edges(args, "histcounts2")?;
    let counts = Value::Matrix(MatrixValue::new(
        histogram.x_edges.len().saturating_sub(1),
        histogram.y_edges.len().saturating_sub(1),
        normalize_histogram2_counts(
            histogram.counts,
            &histogram.x_edges,
            &histogram.y_edges,
            histogram.sample_count,
            histogram.normalization,
        )
        .into_iter()
        .map(Value::Scalar)
        .collect(),
    )?);
    let x_edges = numeric_values_to_row_matrix(histogram.x_edges.clone())?;
    let y_edges = numeric_values_to_row_matrix(histogram.y_edges.clone())?;
    let x_bins = build_scalar_matrix_result_with_dimensions(
        histogram.output_dims.clone(),
        histogram
            .x_bins
            .into_iter()
            .map(|bin| Value::Scalar(bin as f64))
            .collect::<Vec<_>>(),
    )?;
    let y_bins = build_scalar_matrix_result_with_dimensions(
        histogram.output_dims,
        histogram
            .y_bins
            .into_iter()
            .map(|bin| Value::Scalar(bin as f64))
            .collect::<Vec<_>>(),
    )?;

    match output_arity {
        0 | 1 => Ok(vec![counts]),
        2 => Ok(vec![counts, x_edges]),
        3 => Ok(vec![counts, x_edges, y_edges]),
        4 => Ok(vec![counts, x_edges, y_edges, x_bins]),
        5 => Ok(vec![counts, x_edges, y_edges, x_bins, y_bins]),
        _ => Err(RuntimeError::Unsupported(
            "histcounts2 currently supports at most five outputs".to_string(),
        )),
    }
}

fn builtin_interp1(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, v, xq, method, extrapolation) = parse_interp1_args(args)?;
    let (x, reverse_samples) = normalized_interp_axis(x, "interp1", "X")?;
    let query_dims = interp1_query_output_dims(&xq, interp1_series_count(&v));
    let mut output_dims = query_dims;
    if interp1_series_count(&v) > 1 {
        output_dims.extend(interp1_trailing_dims(&v));
    }
    let nan_output = if v.complex_output {
        ComplexParts::nan()
    } else {
        ComplexParts {
            real: f64::NAN,
            imag: 0.0,
        }
    };
    let series = (0..interp1_series_count(&v))
        .map(|series_index| interp1_series_values(&v, series_index, reverse_samples))
        .collect::<Vec<_>>();
    let mut outputs = Vec::with_capacity(xq.values.len() * series.len().max(1));
    for query in &xq.values {
        for values in &series {
            outputs.push(interp1_value(
                *query,
                &x,
                values,
                method,
                extrapolation,
                nan_output,
            ));
        }
    }
    numeric_or_complex_matrix_result_with_dimensions(output_dims, outputs)
}

fn builtin_interp2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, y, v, complex_output, xq, yq, method, extrapolation) = parse_interp2_args(args)?;
    let (x, y, v) = normalized_interp2_samples(x, y, v)?;
    if method == InterpolationMethod::Cubic && (x.len() < 4 || y.len() < 4) {
        return Err(RuntimeError::ShapeError(
            "interp2 cubic currently requires at least four sample points along both X and Y"
                .to_string(),
        ));
    }
    if method == InterpolationMethod::Cubic
        && (!interp_axis_is_uniform(&x) || !interp_axis_is_uniform(&y))
    {
        return Err(RuntimeError::ShapeError(
            "interp2 cubic currently expects uniform spacing along both X and Y; use spline for irregular grids"
                .to_string(),
        ));
    }
    let (xq, yq) = broadcast_interp2_queries(xq, yq)?;
    let nan_output = if complex_output {
        ComplexParts::nan()
    } else {
        ComplexParts {
            real: f64::NAN,
            imag: 0.0,
        }
    };
    let outputs = xq
        .values
        .iter()
        .zip(yq.values.iter())
        .map(|(x_query, y_query)| {
            interp2_value(
                *x_query,
                *y_query,
                &x,
                &y,
                &v,
                method,
                extrapolation,
                nan_output,
            )
        })
        .collect::<Vec<_>>();
    numeric_or_complex_matrix_result_with_dimensions(xq.dims, outputs)
}

fn builtin_interp3(args: &[Value]) -> Result<Value, RuntimeError> {
    if let Some(result) = builtin_interp_nd_refinement(args, "interp3", Some(3))? {
        return Ok(result);
    }
    let (axes, values, queries, method, extrapolation) = parse_interp3_args(args)?;
    let nan_output = if values.complex_output {
        ComplexParts::nan()
    } else {
        ComplexParts {
            real: f64::NAN,
            imag: 0.0,
        }
    };
    let query_dims = queries
        .first()
        .map(|query| query.dims.clone())
        .unwrap_or_else(|| vec![1, 1]);
    let outputs = (0..queries[0].values.len())
        .map(|index| {
            let point = queries
                .iter()
                .map(|query| query.values[index])
                .collect::<Vec<_>>();
            interpn_tensor_value(
                &point,
                &axes,
                &values.values,
                &values.dims,
                method,
                interp_nd_extrapolation_to_interp1(method, extrapolation),
                nan_output,
            )
        })
        .collect::<Vec<_>>();
    numeric_or_complex_matrix_result_with_dimensions(query_dims, outputs)
}

