fn builtin_interp_nd_refinement(
    args: &[Value],
    builtin_name: &str,
    required_dims: Option<usize>,
) -> Result<Option<Value>, RuntimeError> {
    let Some((values, refinement, method, extrapolation)) =
        parse_interp_nd_refinement_args(args, builtin_name, required_dims)?
    else {
        return Ok(None);
    };
    if refinement == 0 {
        return Ok(Some(numeric_or_complex_matrix_result_with_dimensions(
            values.dims,
            values.values,
        )?));
    }
    if values.dims.iter().any(|&extent| extent == 0) {
        return Ok(Some(numeric_or_complex_matrix_result_with_dimensions(
            values.dims,
            values.values,
        )?));
    }

    let sample_axes = interp_nd_default_axes(&values.dims);
    let axes = refined_interp_nd_default_axes(&values.dims, refinement);
    let output_dims = axes.iter().map(Vec::len).collect::<Vec<_>>();
    let output_len = output_dims.iter().product::<usize>();
    let nan_output = if values.complex_output {
        ComplexParts::nan()
    } else {
        ComplexParts {
            real: f64::NAN,
            imag: 0.0,
        }
    };
    let interp_extrapolation = interp_nd_extrapolation_to_interp1(method, extrapolation);
    let outputs = (0..output_len)
        .map(|linear| {
            let index = row_major_multi_index(linear, &output_dims);
            let point = axes
                .iter()
                .zip(index.iter())
                .map(|(axis, position)| axis[*position])
                .collect::<Vec<_>>();
            interpn_tensor_value(
                &point,
                &sample_axes,
                &values.values,
                &values.dims,
                method,
                interp_extrapolation,
                nan_output,
            )
        })
        .collect::<Vec<_>>();
    Ok(Some(numeric_or_complex_matrix_result_with_dimensions(
        output_dims,
        outputs,
    )?))
}

fn parse_interp_nd_refinement_args(
    args: &[Value],
    builtin_name: &str,
    required_dims: Option<usize>,
) -> Result<
    Option<(
        InterpNdSampleOperand,
        usize,
        InterpolationMethod,
        Interp2Extrapolation,
    )>,
    RuntimeError,
> {
    let parsed = match args {
        [value] => Some((
            value,
            1usize,
            InterpolationMethod::Linear,
            Interp2Extrapolation::Nan,
        )),
        [value, second] => {
            if let Some(refinement) = try_nonnegative_integer_scalar(second) {
                Some((
                    value,
                    refinement,
                    InterpolationMethod::Linear,
                    Interp2Extrapolation::Nan,
                ))
            } else if is_interpolation_method_value_for_builtin(second, builtin_name) {
                Some((
                    value,
                    1usize,
                    parse_interpolation_method(second, builtin_name)?,
                    Interp2Extrapolation::Nan,
                ))
            } else {
                None
            }
        }
        [value, second, third] => {
            if let Some(refinement) = try_nonnegative_integer_scalar(second) {
                if is_interpolation_method_value_for_builtin(third, builtin_name) {
                    Some((
                        value,
                        refinement,
                        parse_interpolation_method(third, builtin_name)?,
                        Interp2Extrapolation::Nan,
                    ))
                } else {
                    None
                }
            } else if is_interpolation_method_value_for_builtin(second, builtin_name) {
                Some((
                    value,
                    1usize,
                    parse_interpolation_method(second, builtin_name)?,
                    parse_interp2_extrapolation(third)?,
                ))
            } else {
                None
            }
        }
        [value, second, third, fourth] => {
            if let Some(refinement) = try_nonnegative_integer_scalar(second) {
                if is_interpolation_method_value_for_builtin(third, builtin_name) {
                    Some((
                        value,
                        refinement,
                        parse_interpolation_method(third, builtin_name)?,
                        parse_interp2_extrapolation(fourth)?,
                    ))
                } else {
                    None
                }
            } else {
                None
            }
        }
        _ => None,
    };

    let Some((value, refinement, method, extrapolation)) = parsed else {
        return Ok(None);
    };
    let values = interp_nd_sample_operand(value, builtin_name)?;
    if let Some(required_dims) = required_dims {
        if values.dims.len() != required_dims {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently expects V to be a {required_dims}-D array for refinement forms"
            )));
        }
    }
    if method == InterpolationMethod::Cubic
        && values.dims.iter().any(|&extent| extent > 1 && extent < 4)
    {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} cubic refinement currently requires at least four sample points along each nonsingleton dimension"
        )));
    }
    Ok(Some((values, refinement, method, extrapolation)))
}

fn builtin_accumarray(args: &[Value]) -> Result<Value, RuntimeError> {
    let (subscripts, values, requested_size, reducer, fill_value) = parse_accumarray_args(args)?;

    let subs = parse_accumarray_subscripts(subscripts)?;
    let values = parse_accumarray_values(values, subs.entries.len())?;
    let output_dims = accumarray_size(&subs, requested_size)?;
    let element_count = output_dims.iter().product::<usize>();
    let mut buckets = vec![Vec::new(); element_count];

    for (subscript, value) in subs.entries.iter().zip(values) {
        let mut offset_index = vec![0usize; output_dims.len()];
        for (axis, &component) in subscript.iter().enumerate() {
            if component == 0 || component > output_dims[axis] {
                return Err(RuntimeError::ShapeError(
                    "accumarray subscript exceeds the requested output size".to_string(),
                ));
            }
            offset_index[axis] = component - 1;
        }
        if subscript.len() < output_dims.len()
            && output_dims[subscript.len()..].iter().any(|&dim| dim != 1)
        {
            return Err(RuntimeError::ShapeError(
                "accumarray subscript exceeds the requested output size".to_string(),
            ));
        }
        let offset = row_major_linear_index(&offset_index, &output_dims);
        buckets[offset].push(value);
    }

    let elements = buckets
        .into_iter()
        .map(|bucket| {
            let reduced = reducer.reduce(&bucket, fill_value);
            if reducer.logical_output() {
                Value::Logical(reduced != 0.0)
            } else {
                Value::Scalar(reduced)
            }
        })
        .collect::<Vec<_>>();
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        output_dims,
        elements,
    )?))
}

fn builtin_diff(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, order, requested_dim) = match args {
        [value] => (value, 1usize, None),
        [value, order] => (value, scalar_dimension(order)?, None),
        [value, order, dim] => (
            value,
            scalar_dimension(order)?,
            Some(scalar_dimension(dim)?),
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "diff currently supports `diff(x)`, `diff(x, n)`, or `diff(x, n, dim)`".to_string(),
            ))
        }
    };

    let mut operand = numeric_or_complex_operand(value, "diff")?;
    if order == 0 {
        return Ok(value.clone());
    }

    let input_dims = canonical_size_vector(&value_dimensions(value));
    let dim = requested_dim.unwrap_or_else(|| {
        input_dims
            .iter()
            .position(|&size| size != 1)
            .map(|index| index + 1)
            .unwrap_or(1)
    });
    let mut diff_dims = input_dims.clone();
    while diff_dims.len() < dim {
        diff_dims.push(1);
    }

    if diff_dims.len() > 2 || dim > 2 {
        for _ in 0..order {
            let (next, next_dims) =
                diff_numeric_or_complex_operand_once_with_dimensions(&operand, &diff_dims, dim);
            operand = next;
            diff_dims = next_dims;
        }
        let result = numeric_or_complex_operand_to_value(&operand)?;
        return relabel_value_dimensions(&result, diff_dims);
    }

    for _ in 0..order {
        operand = diff_numeric_or_complex_operand_once(&operand, dim);
    }
    let result = numeric_or_complex_operand_to_value(&operand)?;
    if dim == 1 && canonical_size_vector(&value_dimensions(value)).len() > 2 {
        let mut output_dims = canonical_size_vector(&value_dimensions(value));
        output_dims[0] = output_dims[0].saturating_sub(order);
        return relabel_value_dimensions(&result, output_dims);
    }
    Ok(result)
}

fn builtin_conv(args: &[Value]) -> Result<Value, RuntimeError> {
    let (lhs, rhs, shape) = match args {
        [lhs, rhs] => (lhs, rhs, ConvolutionShape::Full),
        [lhs, rhs, shape] => (lhs, rhs, parse_convolution_shape(shape, "conv")?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "conv currently supports `conv(a, b)` or `conv(a, b, shape)`".to_string(),
            ))
        }
    };

    let (lhs, lhs_is_row) = convolution_vector_operand(lhs, "conv")?;
    let (rhs, rhs_is_row) = convolution_vector_operand(rhs, "conv")?;
    if lhs.values.is_empty() || rhs.values.is_empty() {
        let values = match shape {
            ConvolutionShape::Same => vec![ComplexParts::zero(); lhs.values.len()],
            ConvolutionShape::Valid => {
                let len = if rhs.values.is_empty() {
                    lhs.values.len()
                } else {
                    0
                };
                vec![ComplexParts::zero(); len]
            }
            ConvolutionShape::Full => return Err(RuntimeError::Unsupported(
                "conv currently supports empty vector inputs only for `same` and `valid` shapes"
                    .to_string(),
            )),
        };
        let (rows, cols) = if lhs_is_row {
            (1, values.len())
        } else {
            (values.len(), 1)
        };
        return build_numeric_or_complex_matrix_result(rows, cols, values);
    }

    let full = full_complex_convolution_vector(&lhs.values, &rhs.values);
    let values = crop_complex_convolution_vector(&full, lhs.values.len(), rhs.values.len(), shape);
    let (rows, cols) = if lhs_is_row && rhs_is_row {
        (1, values.len())
    } else {
        (values.len(), 1)
    };

    build_numeric_or_complex_matrix_result(rows, cols, values)
}

fn builtin_cconv(args: &[Value]) -> Result<Value, RuntimeError> {
    let (lhs, lhs_is_row, rhs, rhs_is_row, requested_len) = parse_cconv_args(args)?;
    if lhs.is_empty() || rhs.is_empty() {
        return Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?));
    }
    let output_len = requested_len.unwrap_or_else(|| lhs.len().max(rhs.len()));
    if output_len == 0 {
        return Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?));
    }
    let values = circular_convolution_values(&lhs, &rhs, output_len);
    numeric_or_complex_vector_output(values, lhs_is_row || rhs_is_row)
}

fn parse_cconv_args(
    args: &[Value],
) -> Result<
    (
        Vec<ComplexParts>,
        bool,
        Vec<ComplexParts>,
        bool,
        Option<usize>,
    ),
    RuntimeError,
> {
    match args {
        [lhs, rhs] => {
            let (lhs, lhs_is_row) = numeric_or_complex_set_vector(lhs, "cconv")?;
            let (rhs, rhs_is_row) = numeric_or_complex_set_vector(rhs, "cconv")?;
            Ok((lhs, lhs_is_row, rhs, rhs_is_row, None))
        }
        [lhs, rhs, len] => {
            let (lhs, lhs_is_row) = numeric_or_complex_set_vector(lhs, "cconv")?;
            let (rhs, rhs_is_row) = numeric_or_complex_set_vector(rhs, "cconv")?;
            Ok((
                lhs,
                lhs_is_row,
                rhs,
                rhs_is_row,
                Some(parse_cconv_length(len)?),
            ))
        }
        _ => Err(RuntimeError::Unsupported(
            "cconv currently supports `cconv(a,b)` and `cconv(a,b,n)`".to_string(),
        )),
    }
}

fn parse_cconv_length(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(
            "cconv currently expects n to be a nonnegative finite integer".to_string(),
        ));
    }
    Ok(scalar as usize)
}

fn circular_convolution_values(
    lhs: &[ComplexParts],
    rhs: &[ComplexParts],
    output_len: usize,
) -> Vec<ComplexParts> {
    let mut lhs_padded = vec![ComplexParts::zero(); output_len];
    let mut rhs_padded = vec![ComplexParts::zero(); output_len];
    for (index, value) in lhs.iter().copied().take(output_len).enumerate() {
        lhs_padded[index] = value;
    }
    for (index, value) in rhs.iter().copied().take(output_len).enumerate() {
        rhs_padded[index] = value;
    }
    let mut values = vec![ComplexParts::zero(); output_len];
    for out_index in 0..output_len {
        let mut total = ComplexParts::zero();
        for lhs_index in 0..output_len {
            let rhs_index = (out_index + output_len - lhs_index) % output_len;
            total = total.plus(lhs_padded[lhs_index].times(rhs_padded[rhs_index]));
        }
        values[out_index] = normalize_complex_parts(total);
    }
    values
}

fn builtin_convmtx(args: &[Value]) -> Result<Value, RuntimeError> {
    let [kernel, len] = args else {
        return Err(RuntimeError::Unsupported(
            "convmtx currently supports `convmtx(h,n)`".to_string(),
        ));
    };
    let (kernel, kernel_is_row) = numeric_or_complex_set_vector(kernel, "convmtx")?;
    if kernel.is_empty() {
        return Err(RuntimeError::ShapeError(
            "convmtx currently expects a nonempty vector input".to_string(),
        ));
    }
    let n = positive_integer_scalar_with_label(
        len,
        "convmtx",
        "a positive integer convolution length",
    )?;
    let m = kernel.len();
    if kernel_is_row {
        let rows = n;
        let cols = m + n - 1;
        let mut values = vec![ComplexParts::zero(); rows * cols];
        for row in 0..rows {
            for kernel_index in 0..m {
                values[row * cols + row + kernel_index] = kernel[kernel_index];
            }
        }
        build_numeric_or_complex_matrix_result(rows, cols, values)
    } else {
        let rows = m + n - 1;
        let cols = n;
        let mut values = vec![ComplexParts::zero(); rows * cols];
        for col in 0..cols {
            for kernel_index in 0..m {
                values[(col + kernel_index) * cols + col] = kernel[kernel_index];
            }
        }
        build_numeric_or_complex_matrix_result(rows, cols, values)
    }
}

fn builtin_corrmtx(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "corrmtx currently supports one or two outputs".to_string(),
        ));
    }
    let (input, order) = parse_corrmtx_args(args)?;
    let h = corrmtx_autocorrelation_matrix(&input, order);
    let h_value = numeric_or_complex_operand_to_value(&h)?;
    if output_arity == 2 {
        let r = corrmtx_autocorrelation_estimate(&h);
        Ok(vec![h_value, numeric_or_complex_operand_to_value(&r)?])
    } else {
        Ok(vec![h_value])
    }
}

fn builtin_toeplitz(args: &[Value]) -> Result<Value, RuntimeError> {
    match args {
        [row] => {
            let (row, _row_output) = numeric_or_complex_set_vector(row, "toeplitz")?;
            let col = row
                .iter()
                .enumerate()
                .map(|(index, value)| {
                    if index == 0 {
                        *value
                    } else {
                        value.conjugate()
                    }
                })
                .collect::<Vec<_>>();
            toeplitz_matrix(&col, &row)
        }
        [col, row] => {
            let (col, _col_output) = numeric_or_complex_set_vector(col, "toeplitz")?;
            let (row, _row_output) = numeric_or_complex_set_vector(row, "toeplitz")?;
            toeplitz_matrix(&col, &row)
        }
        _ => Err(RuntimeError::Unsupported(
            "toeplitz currently supports `toeplitz(r)` and `toeplitz(c,r)`".to_string(),
        )),
    }
}

fn builtin_hankel(args: &[Value]) -> Result<Value, RuntimeError> {
    match args {
        [col] => {
            let (col, _col_output) = numeric_or_complex_set_vector(col, "hankel")?;
            let row = std::iter::once(*col.last().ok_or_else(|| {
                RuntimeError::ShapeError("hankel currently expects a nonempty vector".to_string())
            })?)
            .chain(std::iter::repeat(ComplexParts::zero()).take(col.len().saturating_sub(1)))
            .collect::<Vec<_>>();
            hankel_matrix(&col, &row)
        }
        [col, row] => {
            let (col, _col_output) = numeric_or_complex_set_vector(col, "hankel")?;
            let (row, _row_output) = numeric_or_complex_set_vector(row, "hankel")?;
            hankel_matrix(&col, &row)
        }
        _ => Err(RuntimeError::Unsupported(
            "hankel currently supports `hankel(c)` and `hankel(c,r)`".to_string(),
        )),
    }
}

fn hankel_matrix(col: &[ComplexParts], row: &[ComplexParts]) -> Result<Value, RuntimeError> {
    if col.is_empty() || row.is_empty() {
        return Err(RuntimeError::ShapeError(
            "hankel currently expects nonempty vector inputs".to_string(),
        ));
    }
    let mut anti_diagonals = Vec::with_capacity(col.len() + row.len() - 1);
    anti_diagonals.extend_from_slice(col);
    anti_diagonals.extend(row.iter().copied().skip(1));
    for value in &mut anti_diagonals {
        *value = normalize_complex_parts(*value);
    }
    let mut values = Vec::with_capacity(col.len() * row.len());
    for output_row in 0..col.len() {
        for output_col in 0..row.len() {
            values.push(anti_diagonals[output_row + output_col]);
        }
    }
    build_numeric_or_complex_matrix_result(col.len(), row.len(), values)
}

fn builtin_vander(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "vander currently supports exactly one input argument".to_string(),
        ));
    };
    let (input, _row_output) = numeric_or_complex_set_vector(value, "vander")?;
    if input.is_empty() {
        return Err(RuntimeError::ShapeError(
            "vander currently expects a nonempty vector input".to_string(),
        ));
    }
    let n = input.len();
    let mut values = Vec::with_capacity(n * n);
    for value in input {
        for exponent in (0..n).rev() {
            values.push(normalize_complex_parts(complex_integer_power(
                value, exponent,
            )));
        }
    }
    build_numeric_or_complex_matrix_result(n, n, values)
}

fn builtin_hilb(args: &[Value]) -> Result<Value, RuntimeError> {
    let [len] = args else {
        return Err(RuntimeError::Unsupported(
            "hilb currently supports exactly one input argument".to_string(),
        ));
    };
    let n = nonnegative_integer_scalar_with_label(len, "hilb", "a nonnegative integer size")?;
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            values.push(Value::Scalar(1.0 / ((row + col + 1) as f64)));
        }
    }
    build_scalar_matrix_result(n, n, values)
}

fn builtin_invhilb(args: &[Value]) -> Result<Value, RuntimeError> {
    let [len] = args else {
        return Err(RuntimeError::Unsupported(
            "invhilb currently supports exactly one input argument".to_string(),
        ));
    };
    let n = nonnegative_integer_scalar_with_label(len, "invhilb", "a nonnegative integer size")?;
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            values.push(Value::Scalar(invhilb_entry(row + 1, col + 1, n)));
        }
    }
    build_scalar_matrix_result(n, n, values)
}

fn builtin_pascal(args: &[Value]) -> Result<Value, RuntimeError> {
    let (n, kind) = match args {
        [len] => (
            nonnegative_integer_scalar_with_label(len, "pascal", "a nonnegative integer size")?,
            0usize,
        ),
        [len, kind] => (
            nonnegative_integer_scalar_with_label(len, "pascal", "a nonnegative integer size")?,
            positive_integer_scalar_with_label(kind, "pascal", "a matrix kind 1 or 2")?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "pascal currently supports `pascal(n)`, `pascal(n,1)`, and `pascal(n,2)`"
                    .to_string(),
            ))
        }
    };
    match kind {
        0 => pascal_symmetric_matrix(n),
        1 => pascal_lower_factor_matrix(n),
        2 => pascal_cube_root_matrix(n),
        _ => Err(RuntimeError::TypeError(
            "pascal currently expects kind to be 1 or 2".to_string(),
        )),
    }
}

fn pascal_symmetric_matrix(n: usize) -> Result<Value, RuntimeError> {
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            values.push(Value::Scalar(binomial_f64(row + col, row)));
        }
    }
    build_scalar_matrix_result(n, n, values)
}

fn pascal_lower_factor_matrix(n: usize) -> Result<Value, RuntimeError> {
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            let value = if col <= row {
                let sign = if col % 2 == 0 { 1.0 } else { -1.0 };
                sign * binomial_f64(row, col)
            } else {
                0.0
            };
            values.push(Value::Scalar(value));
        }
    }
    build_scalar_matrix_result(n, n, values)
}

fn builtin_compan(args: &[Value]) -> Result<Value, RuntimeError> {
    let [coefficients] = args else {
        return Err(RuntimeError::Unsupported(
            "compan currently supports exactly one input argument".to_string(),
        ));
    };
    let (coefficients, _row_output) = numeric_or_complex_set_vector(coefficients, "compan")?;
    if coefficients.len() < 2 {
        return Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?));
    }
    if coefficients[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "compan currently expects the leading polynomial coefficient to be nonzero".to_string(),
        ));
    }
    let degree = coefficients.len() - 1;
    let leading = coefficients[0];
    let mut values = vec![ComplexParts::zero(); degree * degree];
    for col in 0..degree {
        values[col] = normalize_complex_parts(coefficients[col + 1].scale(-1.0).rdivide(leading));
    }
    for row in 1..degree {
        values[row * degree + row - 1] = ComplexParts::one();
    }
    build_numeric_or_complex_matrix_result(degree, degree, values)
}

fn pascal_cube_root_matrix(n: usize) -> Result<Value, RuntimeError> {
    let sign = if n % 2 == 0 { -1.0 } else { 1.0 };
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            let source_row = n - 1 - col;
            let source_col = row;
            let value = if source_col <= source_row {
                let source_sign = if source_col % 2 == 0 { 1.0 } else { -1.0 };
                sign * source_sign * binomial_f64(source_row, source_col)
            } else {
                0.0
            };
            values.push(Value::Scalar(value));
        }
    }
    build_scalar_matrix_result(n, n, values)
}

fn invhilb_entry(row: usize, col: usize, n: usize) -> f64 {
    let sign = if (row + col) % 2 == 0 { 1.0 } else { -1.0 };
    sign * ((row + col - 1) as f64)
        * binomial_f64(n + row - 1, n - col)
        * binomial_f64(n + col - 1, n - row)
        * binomial_f64(row + col - 2, row - 1).powi(2)
}

fn binomial_f64(n: usize, k: usize) -> f64 {
    if k > n {
        return 0.0;
    }
    let k = k.min(n - k);
    let mut result = 1.0;
    for step in 1..=k {
        result *= (n - k + step) as f64;
        result /= step as f64;
    }
    result
}

fn complex_integer_power(value: ComplexParts, exponent: usize) -> ComplexParts {
    let mut result = ComplexParts::one();
    for _ in 0..exponent {
        result = result.times(value);
    }
    result
}

fn toeplitz_matrix(col: &[ComplexParts], row: &[ComplexParts]) -> Result<Value, RuntimeError> {
    if col.is_empty() || row.is_empty() {
        return Err(RuntimeError::ShapeError(
            "toeplitz currently expects nonempty vector inputs".to_string(),
        ));
    }
    let mut values = Vec::with_capacity(col.len() * row.len());
    for output_row in 0..col.len() {
        for output_col in 0..row.len() {
            let value = if output_col >= output_row {
                row[output_col - output_row]
            } else {
                col[output_row - output_col]
            };
            values.push(normalize_complex_parts(value));
        }
    }
    build_numeric_or_complex_matrix_result(col.len(), row.len(), values)
}

fn parse_corrmtx_args(args: &[Value]) -> Result<(Vec<ComplexParts>, usize), RuntimeError> {
    match args {
        [input, order] => {
            let (input, _row) = numeric_or_complex_set_vector(input, "corrmtx")?;
            let order = positive_integer_scalar_with_label(
                order,
                "corrmtx",
                "a positive integer prediction model order",
            )?;
            Ok((input, order))
        }
        [input, order, method] => {
            let method = text_value(method)?.to_ascii_lowercase();
            if method != "autocorrelation" {
                return Err(RuntimeError::Unsupported(
                    "corrmtx currently supports only the `autocorrelation` method".to_string(),
                ));
            }
            let (input, _row) = numeric_or_complex_set_vector(input, "corrmtx")?;
            let order = positive_integer_scalar_with_label(
                order,
                "corrmtx",
                "a positive integer prediction model order",
            )?;
            Ok((input, order))
        }
        _ => Err(RuntimeError::Unsupported(
            "corrmtx currently supports `corrmtx(x,m)` and `corrmtx(x,m,\"autocorrelation\")`"
                .to_string(),
        )),
    }
}

fn corrmtx_autocorrelation_matrix(input: &[ComplexParts], order: usize) -> NumericOrComplexOperand {
    let rows = input.len() + order;
    let cols = order + 1;
    let scale = 1.0 / (input.len() as f64).sqrt();
    let mut values = vec![ComplexParts::zero(); rows * cols];
    for row in 0..rows {
        for col in 0..cols {
            let Some(input_index) = row.checked_sub(col) else {
                continue;
            };
            if input_index < input.len() {
                values[row * cols + col] = input[input_index].scale(scale);
            }
        }
    }
    NumericOrComplexOperand { rows, cols, values }
}

fn corrmtx_autocorrelation_estimate(h: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = vec![ComplexParts::zero(); h.cols * h.cols];
    for row in 0..h.cols {
        for col in 0..h.cols {
            let mut total = ComplexParts::zero();
            for sample in 0..h.rows {
                let lhs = h.values[sample * h.cols + row].conjugate();
                let rhs = h.values[sample * h.cols + col];
                total = total.plus(lhs.times(rhs));
            }
            values[row * h.cols + col] = normalize_complex_parts(total);
        }
    }
    NumericOrComplexOperand {
        rows: h.cols,
        cols: h.cols,
        values,
    }
}

fn builtin_conv2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (lhs, rhs, shape) = parse_conv2_args(args)?;
    if lhs.values.is_empty() || rhs.values.is_empty() {
        return match shape {
            ConvolutionShape::Same => numeric_or_complex_operand_to_value(
                &zero_numeric_or_complex_operand(lhs.rows, lhs.cols),
            ),
            _ => Err(RuntimeError::Unsupported(
                "conv2 currently supports empty matrix inputs only for `same` shape".to_string(),
            )),
        };
    }

    let full = full_complex_convolution_matrix(&lhs, &rhs);
    let result = crop_complex_convolution_matrix(&full, &lhs, &rhs, shape);
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_convn(args: &[Value]) -> Result<Value, RuntimeError> {
    let (lhs_value, rhs_value, shape) = parse_convn_args(args)?;
    let mut lhs = numeric_or_complex_nd_operand(lhs_value, "convn")?;
    let mut rhs = numeric_or_complex_nd_operand(rhs_value, "convn")?;
    let rank = lhs.dims.len().max(rhs.dims.len());
    if rank <= 2 {
        let lhs_2d = numeric_or_complex_operand(lhs_value, "convn")?;
        let rhs_2d = numeric_or_complex_operand(rhs_value, "convn")?;
        let full = full_complex_convolution_matrix(&lhs_2d, &rhs_2d);
        let cropped = crop_complex_convolution_matrix(&full, &lhs_2d, &rhs_2d, shape);
        return numeric_or_complex_operand_to_value(&cropped);
    }
    lhs.dims.resize(rank, 1);
    rhs.dims.resize(rank, 1);
    if lhs.dims.iter().any(|dim| *dim == 0) || rhs.dims.iter().any(|dim| *dim == 0) {
        return Err(RuntimeError::ShapeError(
            "convn currently expects nonempty N-D inputs".to_string(),
        ));
    }
    let full = full_complex_convolution_nd(&lhs, &rhs);
    let cropped = crop_complex_convolution_nd(&full, &lhs, &rhs, shape);
    build_numeric_or_complex_matrix_result_with_dimensions(cropped.dims, cropped.values)
}

fn builtin_filter2(args: &[Value]) -> Result<Value, RuntimeError> {
    let (kernel, input, shape) = parse_filter2_args(args)?;
    if kernel.values.is_empty() || input.values.is_empty() {
        return match shape {
            ConvolutionShape::Same => numeric_or_complex_operand_to_value(
                &zero_numeric_or_complex_operand(input.rows, input.cols),
            ),
            _ => Err(RuntimeError::Unsupported(
                "filter2 currently supports empty matrix inputs only for `same` shape".to_string(),
            )),
        };
    }
    let flipped_kernel = rotate_kernel_180(&kernel);
    let full = full_complex_convolution_matrix(&input, &flipped_kernel);
    let result = crop_complex_convolution_matrix(&full, &input, &flipped_kernel, shape);
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_imfilter(args: &[Value]) -> Result<Value, RuntimeError> {
    let [input_value, kernel_value, tail @ ..] = args else {
        return Err(RuntimeError::Unsupported(
            "imfilter currently supports `imfilter(A,h)` and `imfilter(A,h,options...)`"
                .to_string(),
        ));
    };
    let options = parse_imfilter_options(tail)?;
    let input_dims = canonical_size_vector(&value_dimensions(input_value));
    let kernel_dims = canonical_size_vector(&value_dimensions(kernel_value));
    if input_dims.len() > 2 || kernel_dims.len() > 2 {
        return builtin_imfilter_nd(input_value, kernel_value, input_dims, kernel_dims, options);
    }
    let input = numeric_or_complex_operand(input_value, "imfilter")?;
    let kernel = numeric_or_complex_operand(kernel_value, "imfilter")?;
    if input.rows == 0 || input.cols == 0 || kernel.rows == 0 || kernel.cols == 0 {
        return match options.shape {
            ConvolutionShape::Same => numeric_or_complex_operand_to_value(
                &zero_numeric_or_complex_operand(input.rows, input.cols),
            ),
            ConvolutionShape::Full => {
                numeric_or_complex_operand_to_value(&zero_numeric_or_complex_operand(
                    input.rows + kernel.rows.saturating_sub(1),
                    input.cols + kernel.cols.saturating_sub(1),
                ))
            }
            ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
        };
    }
    let kernel = match options.mode {
        ImfilterMode::Corr => kernel,
        ImfilterMode::Conv => rotate_kernel_180(&kernel),
    };
    let result = imfilter_2d(&input, &kernel, options);
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_imfilter_nd(
    input_value: &Value,
    kernel_value: &Value,
    input_dims: Vec<usize>,
    kernel_dims: Vec<usize>,
    options: ImfilterOptions,
) -> Result<Value, RuntimeError> {
    let rank = input_dims.len().max(kernel_dims.len());
    let mut input = numeric_or_complex_nd_operand(input_value, "imfilter")?;
    let mut kernel = numeric_or_complex_nd_operand(kernel_value, "imfilter")?;
    input.dims.resize(rank, 1);
    kernel.dims.resize(rank, 1);
    if input.dims.iter().any(|dim| *dim == 0) || kernel.dims.iter().any(|dim| *dim == 0) {
        return Err(RuntimeError::ShapeError(
            "imfilter currently expects nonempty N-D input and kernel arrays".to_string(),
        ));
    }
    let kernel = match options.mode {
        ImfilterMode::Corr => kernel,
        ImfilterMode::Conv => rotate_kernel_nd(&kernel),
    };
    let result = imfilter_nd(&input, &kernel, options)?;
    build_numeric_or_complex_matrix_result_with_dimensions(result.dims, result.values)
}

fn parse_conv2_args(
    args: &[Value],
) -> Result<
    (
        NumericOrComplexOperand,
        NumericOrComplexOperand,
        ConvolutionShape,
    ),
    RuntimeError,
> {
    match args {
        [lhs, rhs] => Ok((
            numeric_or_complex_operand(lhs, "conv2")?,
            numeric_or_complex_operand(rhs, "conv2")?,
            ConvolutionShape::Full,
        )),
        [lhs, rhs, third] => {
            if let Ok(shape) = parse_convolution_shape(third, "conv2") {
                return Ok((
                    numeric_or_complex_operand(lhs, "conv2")?,
                    numeric_or_complex_operand(rhs, "conv2")?,
                    shape,
                ));
            }
            let (u, _u_row) = numeric_or_complex_set_vector(lhs, "conv2")?;
            let (v, _v_row) = numeric_or_complex_set_vector(rhs, "conv2")?;
            let a = numeric_or_complex_operand(third, "conv2")?;
            Ok((a, separable_conv2_kernel(&u, &v), ConvolutionShape::Full))
        }
        [lhs, rhs, value, shape] => Ok((
            numeric_or_complex_operand(value, "conv2")?,
            separable_conv2_kernel(
                &numeric_or_complex_set_vector(lhs, "conv2")?.0,
                &numeric_or_complex_set_vector(rhs, "conv2")?.0,
            ),
            parse_convolution_shape(shape, "conv2")?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "conv2 currently supports `conv2(a, b)`, `conv2(a, b, shape)`, `conv2(u, v, a)`, and `conv2(u, v, a, shape)`".to_string(),
        )),
    }
}

fn parse_convn_args(args: &[Value]) -> Result<(&Value, &Value, ConvolutionShape), RuntimeError> {
    match args {
        [lhs, rhs] => Ok((lhs, rhs, ConvolutionShape::Full)),
        [lhs, rhs, shape] => Ok((lhs, rhs, parse_convolution_shape(shape, "convn")?)),
        _ => Err(RuntimeError::Unsupported(
            "convn currently supports `convn(A,B)` or `convn(A,B,shape)`".to_string(),
        )),
    }
}

fn parse_imfilter_options(tail: &[Value]) -> Result<ImfilterOptions, RuntimeError> {
    let mut options = ImfilterOptions {
        padding: ImfilterPadding::Constant(0.0),
        shape: ConvolutionShape::Same,
        mode: ImfilterMode::Corr,
    };
    for option in tail {
        if let Ok(padding) = parse_imfilter_padding(option) {
            options.padding = padding;
            continue;
        }
        if let Ok(shape) = parse_imfilter_shape(option) {
            options.shape = shape;
            continue;
        }
        if let Ok(mode) = parse_imfilter_mode(option) {
            options.mode = mode;
            continue;
        }
        return Err(RuntimeError::Unsupported(
            "imfilter currently supports padding, `same`/`full`, and `corr`/`conv` options"
                .to_string(),
        ));
    }
    Ok(options)
}

fn parse_imfilter_padding(value: &Value) -> Result<ImfilterPadding, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) => Ok(ImfilterPadding::Constant(real_numeric_scalar(
            value, "imfilter",
        )?)),
        _ => match text_value(value)?.to_ascii_lowercase().as_str() {
            "zeros" => Ok(ImfilterPadding::Constant(0.0)),
            "symmetric" => Ok(ImfilterPadding::Symmetric),
            "replicate" => Ok(ImfilterPadding::Replicate),
            "circular" => Ok(ImfilterPadding::Circular),
            _ => Err(RuntimeError::Unsupported(
                "imfilter currently supports only constant, `symmetric`, `replicate`, or `circular` padding".to_string(),
            )),
        },
    }
}

fn parse_imfilter_shape(value: &Value) -> Result<ConvolutionShape, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "same" => Ok(ConvolutionShape::Same),
        "full" => Ok(ConvolutionShape::Full),
        _ => Err(RuntimeError::Unsupported(
            "imfilter currently supports only `same` or `full` output sizes".to_string(),
        )),
    }
}

fn parse_imfilter_mode(value: &Value) -> Result<ImfilterMode, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "corr" => Ok(ImfilterMode::Corr),
        "conv" => Ok(ImfilterMode::Conv),
        _ => Err(RuntimeError::Unsupported(
            "imfilter currently supports only `corr` or `conv` modes".to_string(),
        )),
    }
}

fn parse_filter2_args(
    args: &[Value],
) -> Result<
    (
        NumericOrComplexOperand,
        NumericOrComplexOperand,
        ConvolutionShape,
    ),
    RuntimeError,
> {
    match args {
        [kernel, input] => Ok((
            numeric_or_complex_operand(kernel, "filter2")?,
            numeric_or_complex_operand(input, "filter2")?,
            ConvolutionShape::Same,
        )),
        [kernel, input, shape] => Ok((
            numeric_or_complex_operand(kernel, "filter2")?,
            numeric_or_complex_operand(input, "filter2")?,
            parse_convolution_shape(shape, "filter2")?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "filter2 currently supports `filter2(H, A)` or `filter2(H, A, shape)`".to_string(),
        )),
    }
}

fn separable_conv2_kernel(u: &[ComplexParts], v: &[ComplexParts]) -> NumericOrComplexOperand {
    let rows = u.len();
    let cols = v.len();
    let mut values = Vec::with_capacity(rows * cols);
    for u_value in u {
        for v_value in v {
            values.push(normalize_complex_parts(u_value.times(*v_value)));
        }
    }
    NumericOrComplexOperand { rows, cols, values }
}

fn rotate_kernel_180(kernel: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = vec![ComplexParts::zero(); kernel.values.len()];
    for row in 0..kernel.rows {
        for col in 0..kernel.cols {
            let source = row * kernel.cols + col;
            let target_row = kernel.rows - 1 - row;
            let target_col = kernel.cols - 1 - col;
            let target = target_row * kernel.cols + target_col;
            values[target] = kernel.values[source];
        }
    }
    NumericOrComplexOperand {
        rows: kernel.rows,
        cols: kernel.cols,
        values,
    }
}

fn conjugate_numeric_or_complex_operand(
    operand: &NumericOrComplexOperand,
) -> NumericOrComplexOperand {
    NumericOrComplexOperand {
        rows: operand.rows,
        cols: operand.cols,
        values: operand
            .values
            .iter()
            .copied()
            .map(ComplexParts::conjugate)
            .collect(),
    }
}

fn rotate_kernel_nd(kernel: &NumericOrComplexNdOperand) -> NumericOrComplexNdOperand {
    let mut values = vec![ComplexParts::zero(); kernel.values.len()];
    for source in 0..kernel.values.len() {
        let source_index = row_major_multi_index(source, &kernel.dims);
        let target_index = source_index
            .iter()
            .enumerate()
            .map(|(axis, &index)| kernel.dims[axis] - 1 - index)
            .collect::<Vec<_>>();
        let target = row_major_linear_index(&target_index, &kernel.dims);
        values[target] = kernel.values[source];
    }
    NumericOrComplexNdOperand {
        dims: kernel.dims.clone(),
        values,
    }
}

fn imfilter_2d(
    input: &NumericOrComplexOperand,
    kernel: &NumericOrComplexOperand,
    options: ImfilterOptions,
) -> NumericOrComplexOperand {
    let anchor_row = kernel.rows / 2;
    let anchor_col = kernel.cols / 2;
    let (rows, cols) = match options.shape {
        ConvolutionShape::Same => (input.rows, input.cols),
        ConvolutionShape::Full => (input.rows + kernel.rows - 1, input.cols + kernel.cols - 1),
        ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
    };
    let mut values = vec![ComplexParts::zero(); rows * cols];
    for out_row in 0..rows {
        for out_col in 0..cols {
            let base_row = match options.shape {
                ConvolutionShape::Same => out_row as isize,
                ConvolutionShape::Full => {
                    out_row as isize - (kernel.rows as isize - 1 - anchor_row as isize)
                }
                ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
            };
            let base_col = match options.shape {
                ConvolutionShape::Same => out_col as isize,
                ConvolutionShape::Full => {
                    out_col as isize - (kernel.cols as isize - 1 - anchor_col as isize)
                }
                ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
            };
            let mut total = ComplexParts::zero();
            for kernel_row in 0..kernel.rows {
                for kernel_col in 0..kernel.cols {
                    let source_row = base_row + kernel_row as isize - anchor_row as isize;
                    let source_col = base_col + kernel_col as isize - anchor_col as isize;
                    let sample = imfilter_sample(input, source_row, source_col, options.padding);
                    total = total
                        .plus(sample.times(kernel.values[kernel_row * kernel.cols + kernel_col]));
                }
            }
            values[out_row * cols + out_col] = normalize_complex_parts(total);
        }
    }
    NumericOrComplexOperand { rows, cols, values }
}

fn imfilter_nd(
    input: &NumericOrComplexNdOperand,
    kernel: &NumericOrComplexNdOperand,
    options: ImfilterOptions,
) -> Result<NumericOrComplexNdOperand, RuntimeError> {
    let anchors = kernel.dims.iter().map(|dim| dim / 2).collect::<Vec<_>>();
    let dims = match options.shape {
        ConvolutionShape::Same => input.dims.clone(),
        ConvolutionShape::Full => input
            .dims
            .iter()
            .zip(kernel.dims.iter())
            .map(|(input_dim, kernel_dim)| input_dim + kernel_dim - 1)
            .collect(),
        ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
    };
    let mut values = vec![ComplexParts::zero(); dims.iter().product()];
    for (output_linear, value) in values.iter_mut().enumerate() {
        let output_index = row_major_multi_index(output_linear, &dims);
        let base_index = output_index
            .iter()
            .enumerate()
            .map(|(axis, &index)| match options.shape {
                ConvolutionShape::Same => index as isize,
                ConvolutionShape::Full => {
                    index as isize - (kernel.dims[axis] as isize - 1 - anchors[axis] as isize)
                }
                ConvolutionShape::Valid => unreachable!("imfilter parser rejects valid"),
            })
            .collect::<Vec<_>>();
        let mut total = ComplexParts::zero();
        for kernel_linear in 0..kernel.values.len() {
            let kernel_index = row_major_multi_index(kernel_linear, &kernel.dims);
            let source_index = kernel_index
                .iter()
                .enumerate()
                .map(|(axis, &index)| base_index[axis] + index as isize - anchors[axis] as isize)
                .collect::<Vec<_>>();
            let sample = imfilter_sample_complex_nd(input, &source_index, options.padding);
            total = total.plus(sample.times(kernel.values[kernel_linear]));
        }
        *value = normalize_complex_parts(total);
    }
    Ok(NumericOrComplexNdOperand { dims, values })
}

fn imfilter_sample(
    input: &NumericOrComplexOperand,
    row: isize,
    col: isize,
    padding: ImfilterPadding,
) -> ComplexParts {
    if row >= 0 && row < input.rows as isize && col >= 0 && col < input.cols as isize {
        return input.values[row as usize * input.cols + col as usize];
    }
    match padding {
        ImfilterPadding::Constant(value) => ComplexParts {
            real: value,
            imag: 0.0,
        },
        ImfilterPadding::Symmetric => {
            let row = symmetric_padded_index(row, input.rows);
            let col = symmetric_padded_index(col, input.cols);
            input.values[row * input.cols + col]
        }
        ImfilterPadding::Replicate => {
            let row = row.clamp(0, input.rows as isize - 1) as usize;
            let col = col.clamp(0, input.cols as isize - 1) as usize;
            input.values[row * input.cols + col]
        }
        ImfilterPadding::Circular => {
            let row = row.rem_euclid(input.rows as isize) as usize;
            let col = col.rem_euclid(input.cols as isize) as usize;
            input.values[row * input.cols + col]
        }
    }
}

fn imfilter_sample_complex_nd(
    input: &NumericOrComplexNdOperand,
    index: &[isize],
    padding: ImfilterPadding,
) -> ComplexParts {
    if index
        .iter()
        .enumerate()
        .all(|(axis, &value)| value >= 0 && value < input.dims[axis] as isize)
    {
        let normalized = index
            .iter()
            .map(|value| *value as usize)
            .collect::<Vec<_>>();
        return input.values[row_major_linear_index(&normalized, &input.dims)];
    }
    match padding {
        ImfilterPadding::Constant(value) => ComplexParts {
            real: value,
            imag: 0.0,
        },
        ImfilterPadding::Symmetric => {
            let normalized = index
                .iter()
                .enumerate()
                .map(|(axis, &value)| symmetric_padded_index(value, input.dims[axis]))
                .collect::<Vec<_>>();
            input.values[row_major_linear_index(&normalized, &input.dims)]
        }
        ImfilterPadding::Replicate => {
            let normalized = index
                .iter()
                .enumerate()
                .map(|(axis, &value)| value.clamp(0, input.dims[axis] as isize - 1) as usize)
                .collect::<Vec<_>>();
            input.values[row_major_linear_index(&normalized, &input.dims)]
        }
        ImfilterPadding::Circular => {
            let normalized = index
                .iter()
                .enumerate()
                .map(|(axis, &value)| value.rem_euclid(input.dims[axis] as isize) as usize)
                .collect::<Vec<_>>();
            input.values[row_major_linear_index(&normalized, &input.dims)]
        }
    }
}

fn builtin_deconv(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let [y, h] = args else {
        return Err(RuntimeError::Unsupported(
            "deconv currently supports exactly two vector inputs".to_string(),
        ));
    };

    let (y, y_is_row) = numeric_or_complex_set_vector(y, "deconv")?;
    let (h, _h_is_row) = numeric_or_complex_set_vector(h, "deconv")?;
    if h.is_empty() {
        return Err(RuntimeError::Unsupported(
            "deconv currently expects a nonempty divisor vector".to_string(),
        ));
    }
    if h[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "deconv requires the leading divisor coefficient to be nonzero".to_string(),
        ));
    }

    let (quotient, remainder) = deconvolution_long_division(&y, &h);
    let quotient = numeric_or_complex_vector_output(quotient, y_is_row)?;
    let remainder = numeric_or_complex_vector_output(remainder, y_is_row)?;
    match output_arity {
        0 | 1 => Ok(vec![quotient]),
        2 => Ok(vec![quotient, remainder]),
        _ => Err(RuntimeError::Unsupported(
            "deconv currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_filter(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (b, a, x, zi, requested_dim) = parse_filter_args(args)?;
    let (b, _b_is_row) = numeric_or_complex_set_vector(b, "filter")?;
    let (a, _a_is_row) = numeric_or_complex_set_vector(a, "filter")?;
    if b.is_empty() || a.is_empty() {
        return Err(RuntimeError::ShapeError(
            "filter currently expects nonempty coefficient vectors".to_string(),
        ));
    }
    if a[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "filter requires a(1) to be nonzero".to_string(),
        ));
    }

    let input_dims = canonical_size_vector(&value_dimensions(x));
    let x = numeric_or_complex_operand(x, "filter")?;
    let dim = requested_dim.unwrap_or_else(|| {
        input_dims
            .iter()
            .position(|&size| size != 1)
            .map(|index| index + 1)
            .unwrap_or(1)
    });

    let (b, a) = normalized_filter_coefficients(&b, &a);
    let state_len = b.len().max(a.len()).saturating_sub(1);
    let sequence_count = filter_sequence_count(&input_dims, dim);
    let mut state = parse_filter_initial_conditions(zi, state_len, sequence_count)?;
    let result = filter_numeric_operand(&x, &input_dims, &b, &a, dim, &mut state);
    let mut y = numeric_or_complex_operand_to_value(&result)?;
    if input_dims.len() > 2 {
        y = relabel_value_dimensions(&y, input_dims.clone())?;
    }

    match output_arity {
        0 | 1 => Ok(vec![y]),
        2 => Ok(vec![
            y,
            filter_state_value(&state, state_len, sequence_count)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "filter currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_filtfilt(args: &[Value]) -> Result<Value, RuntimeError> {
    let (core_args, options) = split_trailing_filtfilt_options(args)?;
    let (sections, value) = parse_filtfilt_sections(core_args)?;
    let input = numeric_or_complex_nd_operand(value, "filtfilt")?;
    let dim = default_reduction_dimension_from_dims(&input.dims);
    let mut values = input.values;
    for section in sections {
        values = filtfilt_numeric_or_complex_nd(
            &values,
            &input.dims,
            &section.numerator,
            &section.denominator,
            dim,
            options,
        )?;
    }
    build_numeric_or_complex_matrix_result_with_dimensions(input.dims, values)
}

fn builtin_sos2ctf(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "sos2ctf currently supports one or two outputs".to_string(),
        ));
    }
    let (sos, scale_values) = match args {
        [sos] => (sos, None),
        [sos, scale_values] => (sos, Some(scale_values)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "sos2ctf currently supports sos2ctf(sos) and sos2ctf(sos, g)".to_string(),
            ))
        }
    };
    let operand = numeric_or_complex_operand(sos, "sos2ctf")?;
    if operand.cols != 6 {
        return Err(RuntimeError::ShapeError(
            "sos2ctf currently expects sos to be an L-by-6 matrix".to_string(),
        ));
    }
    let section_scales = distributed_section_scales(scale_values, operand.rows, "sos2ctf")?;
    let mut numerator = Vec::with_capacity(operand.rows * 3);
    let mut denominator = Vec::with_capacity(operand.rows * 3);
    for row in 0..operand.rows {
        let start = row * operand.cols;
        for col in 0..3 {
            numerator.push(normalize_complex_parts(
                operand.values[start + col].scale(section_scales[row]),
            ));
            denominator.push(normalize_complex_parts(operand.values[start + 3 + col]));
        }
    }
    let b = build_numeric_or_complex_matrix_result(operand.rows, 3, numerator)?;
    let a = build_numeric_or_complex_matrix_result(operand.rows, 3, denominator)?;
    match output_arity {
        1 => Ok(vec![b]),
        2 => Ok(vec![b, a]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_sos2zp(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "sos2zp currently supports one, two, or three outputs".to_string(),
        ));
    }
    let (sos, gain_value) = match args {
        [sos] => (sos, 1.0),
        [sos, gain] => {
            let gain = gain.as_scalar()?;
            if !gain.is_finite() {
                return Err(RuntimeError::TypeError(
                    "sos2zp currently expects g to be a finite real scalar".to_string(),
                ));
            }
            (sos, gain)
        }
        _ => {
            return Err(RuntimeError::Unsupported(
                "sos2zp currently supports sos2zp(sos) and sos2zp(sos, g)".to_string(),
            ))
        }
    };
    let operand = numeric_or_complex_operand(sos, "sos2zp")?;
    if operand.cols != 6 {
        return Err(RuntimeError::ShapeError(
            "sos2zp currently expects sos to be an L-by-6 matrix".to_string(),
        ));
    }

    let mut zeros = Vec::with_capacity(operand.rows * 2);
    let mut poles = Vec::with_capacity(operand.rows * 2);
    let mut gain = ComplexParts {
        real: gain_value,
        imag: 0.0,
    };
    for row in 0..operand.rows {
        let start = row * operand.cols;
        let numerator = operand.values[start..start + 3].to_vec();
        let denominator = operand.values[start + 3..start + 6].to_vec();
        if denominator[0].is_approximately_zero() {
            return Err(RuntimeError::TypeError(
                "sos2zp currently expects each section denominator to have a nonzero leading coefficient".to_string(),
            ));
        }
        zeros.extend(complex_polynomial_roots(&numerator));
        poles.extend(complex_polynomial_roots(&denominator));
        gain = normalize_complex_parts(gain.times(numerator[0].rdivide(denominator[0])));
    }

    let mut outputs = vec![complex_roots_column_output(zeros)?];
    if output_arity >= 2 {
        outputs.push(complex_roots_column_output(poles)?);
    }
    if output_arity >= 3 {
        outputs.push(numeric_or_complex_value(gain));
    }
    Ok(outputs)
}

fn builtin_sos2tf(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "sos2tf currently supports one or two outputs".to_string(),
        ));
    }
    let (sos, scale_values) = match args {
        [sos] => (sos, None),
        [sos, scale_values] => (sos, Some(scale_values)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "sos2tf currently supports sos2tf(sos) and sos2tf(sos, g)".to_string(),
            ))
        }
    };
    let sections = parse_sos_sections(sos, scale_values.unwrap_or(&Value::Scalar(1.0)), "sos2tf")?;
    let (numerator, denominator) = equivalent_filter_sections_transfer_function(&sections);
    let b = complex_polynomial_degree_preserving_output(numerator)?;
    match output_arity {
        1 => Ok(vec![b]),
        2 => Ok(vec![
            b,
            complex_polynomial_degree_preserving_output(denominator)?,
        ]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_sos2ss(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 4 {
        return Err(RuntimeError::Unsupported(
            "sos2ss currently supports one to four outputs".to_string(),
        ));
    }
    let tf = builtin_sos2tf(args, 2)?;
    builtin_tf2ss(&tf, output_arity)
}

fn builtin_tf2ss(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 4 {
        return Err(RuntimeError::Unsupported(
            "tf2ss currently supports one to four outputs".to_string(),
        ));
    }
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "tf2ss currently supports tf2ss(b, a)".to_string(),
        ));
    };

    let (numerator_rows, denominator) =
        normalized_transfer_function_rows(numerator, denominator, "tf2ss")?;
    let state_count = denominator.len().saturating_sub(1);
    let output_count = numerator_rows.len();

    let mut a_values = vec![ComplexParts::zero(); state_count * state_count];
    if state_count > 0 {
        for (column, coefficient) in denominator.iter().copied().enumerate().skip(1) {
            a_values[column - 1] = normalize_complex_parts(ComplexParts::zero().minus(coefficient));
        }
        for row in 1..state_count {
            a_values[row * state_count + row - 1] = ComplexParts::one();
        }
    }

    let mut b_values = vec![ComplexParts::zero(); state_count];
    if state_count > 0 {
        b_values[0] = ComplexParts::one();
    }

    let mut c_values = Vec::with_capacity(output_count * state_count);
    let mut d_values = Vec::with_capacity(output_count);
    for row in &numerator_rows {
        let feedthrough = row[0];
        d_values.push(normalize_complex_parts(feedthrough));
        for index in 0..state_count {
            c_values.push(normalize_complex_parts(
                row[index + 1].minus(denominator[index + 1].times(feedthrough)),
            ));
        }
    }

    let mut outputs = vec![build_numeric_or_complex_matrix_result(
        state_count,
        state_count,
        a_values,
    )?];
    if output_arity >= 2 {
        outputs.push(build_numeric_or_complex_matrix_result(
            state_count,
            1,
            b_values,
        )?);
    }
    if output_arity >= 3 {
        outputs.push(build_numeric_or_complex_matrix_result(
            output_count,
            state_count,
            c_values,
        )?);
    }
    if output_arity >= 4 {
        outputs.push(build_numeric_or_complex_matrix_result(
            output_count,
            1,
            d_values,
        )?);
    }
    Ok(outputs)
}

fn builtin_ctffilt(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "ctffilt currently supports one or two outputs".to_string(),
        ));
    }
    let (sections, value, zi, requested_dim) = parse_ctffilt_args(args)?;
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let x = numeric_or_complex_operand(value, "ctffilt")?;
    let dim = requested_dim.unwrap_or_else(|| {
        input_dims
            .iter()
            .position(|&size| size != 1)
            .map(|index| index + 1)
            .unwrap_or(1)
    });
    let sequence_count = filter_sequence_count(&input_dims, dim);
    let section_state_len = sections
        .iter()
        .map(|section| {
            section
                .numerator
                .len()
                .max(section.denominator.len())
                .saturating_sub(1)
        })
        .max()
        .unwrap_or(0);
    let state_dims = ctffilt_state_dims(sections.len() * section_state_len, &input_dims, dim);
    let mut state = parse_ctffilt_initial_conditions(
        zi,
        section_state_len,
        sections.len(),
        sequence_count,
        &state_dims,
    )?;

    let normalized_sections = sections
        .into_iter()
        .map(|mut section| {
            section
                .numerator
                .resize(section_state_len + 1, ComplexParts::zero());
            section
                .denominator
                .resize(section_state_len + 1, ComplexParts::zero());
            section
        })
        .collect::<Vec<_>>();

    let mut current = x;
    for (section_index, section) in normalized_sections.iter().enumerate() {
        let start = section_index * section_state_len * sequence_count;
        let end = start + section_state_len * sequence_count;
        current = filter_numeric_operand(
            &current,
            &input_dims,
            &section.numerator,
            &section.denominator,
            dim,
            &mut state[start..end],
        );
    }

    let mut y = numeric_or_complex_operand_to_value(&current)?;
    if input_dims.len() > 2 {
        y = relabel_value_dimensions(&y, input_dims.clone())?;
    }
    match output_arity {
        0 | 1 => Ok(vec![y]),
        2 => Ok(vec![
            y,
            build_numeric_or_complex_matrix_result_with_dimensions(state_dims, state)?,
        ]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_scale_filter_sections(args: &[Value]) -> Result<Value, RuntimeError> {
    let [numerators, scale_values] = args else {
        return Err(RuntimeError::Unsupported(
            "scaleFilterSections currently supports scaleFilterSections(B, g)".to_string(),
        ));
    };
    let operand = numeric_or_complex_operand(numerators, "scaleFilterSections")?;
    if operand.rows == 0 || operand.cols == 0 {
        return numeric_or_complex_operand_to_value(&operand);
    }
    let section_scales =
        scale_filter_sections_scales(scale_values, operand.rows, "scaleFilterSections")?;
    let mut values = operand.values;
    for row in 0..operand.rows {
        for col in 0..operand.cols {
            values[row * operand.cols + col] = normalize_complex_parts(
                values[row * operand.cols + col].scale(section_scales[row]),
            );
        }
    }
    numeric_or_complex_operand_to_value(&NumericOrComplexOperand {
        rows: operand.rows,
        cols: operand.cols,
        values,
    })
}

#[derive(Debug, Clone)]
struct FiltfiltSection {
    numerator: Vec<ComplexParts>,
    denominator: Vec<ComplexParts>,
}

#[derive(Debug, Clone, Copy)]
enum FiltfiltInitialStatesMethod {
    Const,
    Gustafsson,
    Zero,
}

#[derive(Debug, Clone, Copy)]
enum FiltfiltTransientLength {
    Filtord,
    Stepzlen,
    Explicit(usize),
}

#[derive(Debug, Clone, Copy)]
enum FiltfiltPaddingPattern {
    Linear,
    Reflect,
    None,
}

#[derive(Debug, Clone, Copy)]
struct FiltfiltOptions {
    initial_states_method: FiltfiltInitialStatesMethod,
    transient_length: FiltfiltTransientLength,
    padding_pattern: FiltfiltPaddingPattern,
}

impl Default for FiltfiltOptions {
    fn default() -> Self {
        Self {
            initial_states_method: FiltfiltInitialStatesMethod::Const,
            transient_length: FiltfiltTransientLength::Filtord,
            padding_pattern: FiltfiltPaddingPattern::Linear,
        }
    }
}

fn split_trailing_filtfilt_options(
    args: &[Value],
) -> Result<(&[Value], FiltfiltOptions), RuntimeError> {
    if matches!(args.last(), Some(value) if is_filtfilt_option_name(value)) {
        return Err(RuntimeError::Unsupported(
            "filtfilt currently expects name-value options to appear in pairs".to_string(),
        ));
    }
    let mut end = args.len();
    let mut options = FiltfiltOptions::default();
    while end >= 2 && is_filtfilt_option_name(&args[end - 2]) {
        let name = text_value(&args[end - 2])?;
        let value = &args[end - 1];
        if name.eq_ignore_ascii_case("InitialStatesMethod") {
            options.initial_states_method = parse_filtfilt_initial_states_method(value)?;
        } else if name.eq_ignore_ascii_case("TransientLength") {
            options.transient_length = parse_filtfilt_transient_length(value)?;
        } else if name.eq_ignore_ascii_case("PaddingPattern") {
            options.padding_pattern = parse_filtfilt_padding_pattern(value)?;
        } else {
            return Err(RuntimeError::Unsupported(format!(
                "filtfilt does not support the `{name}` option"
            )));
        }
        end -= 2;
    }
    Ok((&args[..end], options))
}

fn parse_ctffilt_args<'a>(
    args: &'a [Value],
) -> Result<
    (
        Vec<FiltfiltSection>,
        &'a Value,
        Option<&'a Value>,
        Option<usize>,
    ),
    RuntimeError,
> {
    let (core_args, requested_dim) = split_trailing_ctffilt_options(args)?;
    match core_args {
        [ctf, value] if matches!(ctf, Value::Cell(_)) => Ok((
            parse_digital_filter_ctf_cell_sections(ctf, "ctffilt")?,
            value,
            None,
            requested_dim,
        )),
        [ctf, value, zi] if matches!(ctf, Value::Cell(_)) => Ok((
            parse_digital_filter_ctf_cell_sections(ctf, "ctffilt")?,
            value,
            Some(zi),
            requested_dim,
        )),
        [numerators, denominators, value] => Ok((
            parse_ctf_sections(numerators, denominators, None, "ctffilt")?,
            value,
            None,
            requested_dim,
        )),
        [numerators, denominators, value, zi] => Ok((
            parse_ctf_sections(numerators, denominators, None, "ctffilt")?,
            value,
            Some(zi),
            requested_dim,
        )),
        _ => Err(RuntimeError::Unsupported(
            "ctffilt currently supports ctffilt(B, A, x), ctffilt(B, A, x, zi), ctffilt({B, A, g}, x), ctffilt({B, A, g}, x, zi), and those forms with trailing \"Dimension\", dim".to_string(),
        )),
    }
}

fn split_trailing_ctffilt_options(
    args: &[Value],
) -> Result<(&[Value], Option<usize>), RuntimeError> {
    if args.len() >= 1 && matches!(args.last(), Some(value) if is_ctffilt_option_name(value)) {
        return Err(RuntimeError::Unsupported(
            "ctffilt currently expects option/value pairs at the end of the argument list"
                .to_string(),
        ));
    }
    if args.len() >= 2 && is_ctffilt_option_name(&args[args.len() - 2]) {
        let name = text_value(&args[args.len() - 2])?;
        if !name.eq_ignore_ascii_case("Dimension") {
            return Err(RuntimeError::Unsupported(format!(
                "ctffilt does not support the `{name}` option"
            )));
        }
        return Ok((
            &args[..args.len() - 2],
            Some(positive_dimension(&args[args.len() - 1], "ctffilt")?),
        ));
    }
    Ok((args, None))
}

fn is_ctffilt_option_name(value: &Value) -> bool {
    matches!(
        value,
        Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("Dimension")
    )
}

fn is_filtfilt_option_name(value: &Value) -> bool {
    matches!(
        value,
        Value::CharArray(text) | Value::String(text)
            if text.eq_ignore_ascii_case("InitialStatesMethod")
                || text.eq_ignore_ascii_case("TransientLength")
                || text.eq_ignore_ascii_case("PaddingPattern")
    )
}

fn parse_filtfilt_initial_states_method(
    value: &Value,
) -> Result<FiltfiltInitialStatesMethod, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "const" => Ok(FiltfiltInitialStatesMethod::Const),
        "gustafsson" => Ok(FiltfiltInitialStatesMethod::Gustafsson),
        "zero" => Ok(FiltfiltInitialStatesMethod::Zero),
        other => Err(RuntimeError::Unsupported(format!(
            "filtfilt InitialStatesMethod `{other}` is not implemented; expected \"const\", \"zero\", or \"gustafsson\""
        ))),
    }
}

fn parse_filtfilt_transient_length(value: &Value) -> Result<FiltfiltTransientLength, RuntimeError> {
    if matches!(value, Value::CharArray(_) | Value::String(_)) {
        return match text_value(value)?.to_ascii_lowercase().as_str() {
            "filtord" => Ok(FiltfiltTransientLength::Filtord),
            "stepzlen" => Ok(FiltfiltTransientLength::Stepzlen),
            other => Err(RuntimeError::Unsupported(format!(
                "filtfilt TransientLength `{other}` is not implemented; expected \"filtord\", \"stepzlen\", or a nonnegative integer"
            ))),
        };
    }
    Ok(FiltfiltTransientLength::Explicit(
        nonnegative_integer_scalar_with_label(value, "filtfilt", "a nonnegative transient length")?,
    ))
}

fn parse_filtfilt_padding_pattern(value: &Value) -> Result<FiltfiltPaddingPattern, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "linear" => Ok(FiltfiltPaddingPattern::Linear),
        "reflect" => Ok(FiltfiltPaddingPattern::Reflect),
        "none" => Ok(FiltfiltPaddingPattern::None),
        other => Err(RuntimeError::Unsupported(format!(
            "filtfilt PaddingPattern `{other}` is not implemented; expected \"linear\", \"reflect\", or \"none\""
        ))),
    }
}

fn parse_filtfilt_sections<'a>(
    args: &'a [Value],
) -> Result<(Vec<FiltfiltSection>, &'a Value), RuntimeError> {
    match args {
        [sections, scale_values, value] if filtfilt_sos_signature(sections) => {
            Ok((parse_sos_sections(sections, scale_values, "filtfilt")?, value))
        }
        [numerator, denominator, value] => Ok((
            vec![parse_transfer_function_section(
                numerator,
                denominator,
                "filtfilt",
            )?],
            value,
        )),
        [numerators, denominators, value, mode]
            if text_value(mode)?.eq_ignore_ascii_case("ctf") =>
        {
            Ok((
                parse_ctf_sections(numerators, denominators, None, "filtfilt")?,
                value,
            ))
        }
        [ctf, value] => {
            let Value::Cell(cell) = ctf else {
                return Err(RuntimeError::Unsupported(
                    "filtfilt currently supports filtfilt(b, a, x), filtfilt(sos, g, x), filtfilt(B, A, x, \"ctf\"), and filtfilt({B, A, g}, x)".to_string(),
                ));
            };
            if cell.element_count() != 3 || (cell.rows != 1 && cell.cols != 1) {
                return Err(RuntimeError::Unsupported(
                    "filtfilt currently expects {B, A, g} cell inputs to contain exactly three elements".to_string(),
                ));
            }
            Ok((
                parse_ctf_sections(
                    &cell.elements()[0],
                    &cell.elements()[1],
                    Some(&cell.elements()[2]),
                    "filtfilt",
                )?,
                value,
            ))
        }
        _ => Err(RuntimeError::Unsupported(
            "filtfilt currently supports filtfilt(b, a, x), filtfilt(sos, g, x), filtfilt(B, A, x, \"ctf\"), and filtfilt({B, A, g}, x)".to_string(),
        )),
    }
}

fn parse_transfer_function_section(
    numerator: &Value,
    denominator: &Value,
    builtin_name: &str,
) -> Result<FiltfiltSection, RuntimeError> {
    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, builtin_name)?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator, builtin_name)?;
    normalized_filter_section(numerator, denominator, builtin_name)
}

fn parse_ctf_sections(
    numerators: &Value,
    denominators: &Value,
    scale_values: Option<&Value>,
    builtin_name: &str,
) -> Result<Vec<FiltfiltSection>, RuntimeError> {
    let (numerator_sections, denominator_sections) =
        numeric_or_complex_ctf_section_rows(numerators, denominators, builtin_name)?;
    if numerator_sections.len() != denominator_sections.len() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects CTF numerator and denominator inputs to have matching section counts"
        )));
    }
    let section_scales =
        distributed_section_scales(scale_values, numerator_sections.len(), builtin_name)?;
    numerator_sections
        .into_iter()
        .zip(denominator_sections)
        .zip(section_scales)
        .map(|((numerator, denominator), scale)| {
            normalized_filter_section(
                numerator
                    .into_iter()
                    .map(|coefficient| normalize_complex_parts(coefficient.scale(scale)))
                    .collect(),
                denominator,
                builtin_name,
            )
        })
        .collect()
}

fn parse_sos_sections(
    sections: &Value,
    scale_values: &Value,
    builtin_name: &str,
) -> Result<Vec<FiltfiltSection>, RuntimeError> {
    let operand = numeric_or_complex_operand(sections, builtin_name)?;
    if operand.rows < 2 || operand.cols != 6 {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects sos to be an L-by-6 matrix with at least two sections"
        )));
    }
    let section_scales =
        distributed_section_scales(Some(scale_values), operand.rows, builtin_name)?;
    (0..operand.rows)
        .map(|row| {
            let start = row * operand.cols;
            let row_values = &operand.values[start..start + operand.cols];
            let numerator = row_values[..3]
                .iter()
                .copied()
                .map(|coefficient| normalize_complex_parts(coefficient.scale(section_scales[row])))
                .collect::<Vec<_>>();
            let denominator = row_values[3..].to_vec();
            normalized_filter_section(numerator, denominator, builtin_name)
        })
        .collect()
}

fn numeric_or_complex_ctf_section_rows(
    numerators: &Value,
    denominators: &Value,
    builtin_name: &str,
) -> Result<(Vec<Vec<ComplexParts>>, Vec<Vec<ComplexParts>>), RuntimeError> {
    let numerator_operand = numeric_or_complex_operand(numerators, builtin_name)?;
    let denominator_operand = numeric_or_complex_operand(denominators, builtin_name)?;
    let numerator_is_vector = ctf_operand_is_vector(&numerator_operand);
    let denominator_is_vector = ctf_operand_is_vector(&denominator_operand);
    if numerator_is_vector
        && denominator_is_vector
        && !(numerator_operand.rows > 1
            && denominator_operand.rows > 1
            && numerator_operand.rows == denominator_operand.rows)
    {
        return Ok((
            vec![numerator_operand.values],
            vec![denominator_operand.values],
        ));
    }

    if numerator_operand.rows != denominator_operand.rows {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects CTF numerator and denominator inputs to have matching section counts"
        )));
    }

    Ok((
        ctf_operand_row_sections(&numerator_operand),
        ctf_operand_row_sections(&denominator_operand),
    ))
}

fn ctf_operand_is_vector(operand: &NumericOrComplexOperand) -> bool {
    operand.rows == 1 || operand.cols == 1
}

fn ctf_operand_row_sections(operand: &NumericOrComplexOperand) -> Vec<Vec<ComplexParts>> {
    let mut sections = Vec::with_capacity(operand.rows);
    for row in 0..operand.rows {
        let start = row * operand.cols;
        sections.push(operand.values[start..start + operand.cols].to_vec());
    }
    sections
}

fn normalized_filter_section(
    numerator: Vec<ComplexParts>,
    denominator: Vec<ComplexParts>,
    builtin_name: &str,
) -> Result<FiltfiltSection, RuntimeError> {
    if numerator.is_empty() || denominator.is_empty() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects nonempty coefficient vectors"
        )));
    }
    if denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects each denominator section to start with a nonzero coefficient"
        )));
    }
    let (numerator, denominator) = normalized_filter_coefficients(&numerator, &denominator);
    Ok(FiltfiltSection {
        numerator,
        denominator,
    })
}

fn distributed_section_scales(
    scale_values: Option<&Value>,
    section_count: usize,
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    if section_count == 0 {
        return Ok(Vec::new());
    }
    let Some(scale_values) = scale_values else {
        return Ok(vec![1.0; section_count]);
    };
    let (values, _row_output, _logical_output) = numeric_set_vector(scale_values, builtin_name)?;
    if values.is_empty() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects nonempty scale values"
        )));
    }
    if values.iter().any(|value| !value.is_finite()) {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects finite real scale values"
        )));
    }
    if values.len() == 1 {
        return Ok(uniformly_distributed_section_gain(values[0], section_count));
    }
    if values.len() != section_count + 1 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects scale vectors to have length {} for {} sections",
            section_count + 1,
            section_count
        )));
    }
    let uniform = uniformly_distributed_section_gain(values[section_count], section_count);
    Ok((0..section_count)
        .map(|index| values[index] * uniform[index])
        .collect())
}

fn scale_filter_sections_scales(
    scale_values: &Value,
    section_count: usize,
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    let (values, _row_output, _logical_output) = numeric_set_vector(scale_values, builtin_name)?;
    if values.is_empty() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects nonempty scale values"
        )));
    }
    if values.iter().any(|value| !value.is_finite()) {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects finite real scale values"
        )));
    }
    if section_count == 0 {
        return Ok(Vec::new());
    }
    if values.len() == 1 {
        let root = values[0].abs().powf(1.0 / section_count as f64);
        let mut scales = vec![root; section_count];
        scales[section_count - 1] *= values[0].signum();
        return Ok(scales);
    }
    if values.len() != section_count + 1 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects g to be a scalar or a vector of length {} for {} sections",
            section_count + 1,
            section_count
        )));
    }
    let root = values[section_count].abs().powf(1.0 / section_count as f64);
    let mut scales = (0..section_count)
        .map(|index| values[index] * root)
        .collect::<Vec<_>>();
    scales[section_count - 1] *= values[section_count].signum();
    Ok(scales)
}

fn uniformly_distributed_section_gain(gain: f64, section_count: usize) -> Vec<f64> {
    let sign = if gain.is_sign_negative() { -1.0 } else { 1.0 };
    let root = gain.abs().powf(1.0 / section_count as f64);
    let mut scales = vec![root; section_count];
    scales[0] *= sign;
    scales
}

fn filtfilt_sos_signature(value: &Value) -> bool {
    matches!(value, Value::Matrix(matrix) if matrix.rows >= 2 && matrix.cols == 6)
}

