fn builtin_fft_along_dimension(
    args: &[Value],
    inverse: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let (value, requested_len, requested_dim) = parse_fft_args(args, builtin_name)?;
    let operand = numeric_or_complex_nd_operand(value, builtin_name)?;
    let dim = requested_dim.unwrap_or_else(|| default_reduction_dimension_from_dims(&operand.dims));
    let mut dims = operand.dims.clone();
    while dims.len() < dim {
        dims.push(1);
    }
    let len = requested_len.unwrap_or(dims[dim - 1]);
    let (dims, values) = fft_along_dimension_values(&operand.values, &dims, dim, len, inverse);
    build_numeric_or_complex_matrix_result_with_dimensions(dims, values)
}

fn builtin_fft2_value(
    args: &[Value],
    inverse: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let (value, requested_shape) = parse_fft2_args(args, builtin_name)?;
    let operand = numeric_or_complex_nd_operand(value, builtin_name)?;
    let mut dims = operand.dims.clone();
    while dims.len() < 2 {
        dims.push(1);
    }
    let shape = requested_shape.unwrap_or([dims[0], dims[1]]);
    let (dims, values) = fft_along_dimension_values(&operand.values, &dims, 1, shape[0], inverse);
    let (dims, values) = fft_along_dimension_values(&values, &dims, 2, shape[1], inverse);
    build_numeric_or_complex_matrix_result_with_dimensions(dims, values)
}

fn builtin_fftn_value(
    args: &[Value],
    inverse: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let (value, requested_shape) = parse_fftn_args(args, builtin_name)?;
    let operand = numeric_or_complex_nd_operand(value, builtin_name)?;
    let mut target_dims = requested_shape.unwrap_or_else(|| operand.dims.clone());
    while target_dims.len() < operand.dims.len() {
        target_dims.push(operand.dims[target_dims.len()]);
    }
    let mut dims = operand.dims.clone();
    while dims.len() < target_dims.len() {
        dims.push(1);
    }
    let mut values = operand.values;
    for (axis, &len) in target_dims.iter().enumerate() {
        let result = fft_along_dimension_values(&values, &dims, axis + 1, len, inverse);
        dims = result.0;
        values = result.1;
    }
    build_numeric_or_complex_matrix_result_with_dimensions(target_dims, values)
}

fn builtin_dftmtx(args: &[Value]) -> Result<Value, RuntimeError> {
    let [len] = args else {
        return Err(RuntimeError::Unsupported(
            "dftmtx currently supports exactly one input argument".to_string(),
        ));
    };
    let n = positive_integer_scalar_with_label(len, "dftmtx", "a positive integer size")?;
    let mut values = Vec::with_capacity(n * n);
    for row in 0..n {
        for col in 0..n {
            let angle = -2.0 * std::f64::consts::PI * (row as f64) * (col as f64) / (n as f64);
            values.push(normalize_complex_parts(ComplexParts {
                real: angle.cos(),
                imag: angle.sin(),
            }));
        }
    }
    build_numeric_or_complex_matrix_result(n, n, values)
}

