fn builtin_zerophase(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "zerophase currently supports one, two, or three outputs".to_string(),
        ));
    }
    let (numerator, denominator, selection) = parse_freqz_args(args, "zerophase")?;

    let (responses, frequencies, _evaluation_frequencies, row_output) =
        digital_filter_frequency_selection_response(
            &numerator,
            &denominator,
            selection,
            "zerophase",
        )?;
    let phases = unwrap_phase_values(
        responses
            .iter()
            .map(|response| response.argument())
            .collect::<Vec<_>>(),
    );
    let zero_phase = responses
        .into_iter()
        .zip(phases.iter().copied())
        .map(|(response, phase)| {
            let rotated = normalize_complex_parts(response.times(ComplexParts {
                real: phase.cos(),
                imag: -phase.sin(),
            }));
            normalize_polynomial_scalar(rotated.real)
        })
        .collect::<Vec<_>>();
    let mut outputs = vec![numeric_set_output(zero_phase, row_output, false)?];
    if output_arity >= 2 {
        outputs.push(numeric_set_output(frequencies, row_output, false)?);
    }
    if output_arity >= 3 {
        outputs.push(numeric_set_output(phases, row_output, false)?);
    }
    Ok(outputs)
}

