fn builtin_phasedelay(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "phasedelay currently supports one or two outputs".to_string(),
        ));
    }
    let (numerator, denominator, selection) = parse_freqz_args(args, "phasedelay")?;

    let (responses, frequencies, evaluation_frequencies, row_output) =
        digital_filter_frequency_selection_response(
            &numerator,
            &denominator,
            selection,
            "phasedelay",
        )?;
    let phases = unwrap_phase_values(
        responses
            .into_iter()
            .map(|response| response.argument())
            .collect::<Vec<_>>(),
    );
    let delays = phases
        .iter()
        .zip(evaluation_frequencies.iter())
        .map(|(phase, frequency)| {
            if frequency.abs() <= 1e-12 {
                group_delay_sample(&numerator, &denominator, *frequency)
            } else {
                normalize_polynomial_scalar(-phase / frequency)
            }
        })
        .collect::<Vec<_>>();
    let mut outputs = vec![numeric_set_output(delays, row_output, false)?];
    if output_arity >= 2 {
        outputs.push(numeric_set_output(frequencies, row_output, false)?);
    }
    Ok(outputs)
}

fn builtin_isstable(args: &[Value]) -> Result<Value, RuntimeError> {
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "isstable currently supports isstable(b, a)".to_string(),
        ));
    };
    let (_numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "isstable")?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator, "isstable")?;
    let denominator = complex_polynomial_compact_coefficients(&denominator);
    if denominator.is_empty() || denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "isstable currently expects a denominator vector with nonzero leading coefficient"
                .to_string(),
        ));
    }
    let stable = complex_polynomial_roots(&denominator)
        .into_iter()
        .all(|root| root.magnitude() < 1.0 - 1e-12);
    Ok(Value::Logical(stable))
}

