fn builtin_isminphase(args: &[Value]) -> Result<Value, RuntimeError> {
    let (numerator, denominator, tolerance) = parse_phase_property_filter_args(args, "isminphase")?;
    let poles = filter_denominator_roots(&denominator, tolerance, "isminphase")?;
    let zeros = filter_numerator_roots(&numerator, tolerance);
    let stable = poles.iter().all(|pole| pole.magnitude() <= 1.0 + tolerance);
    let minimum_phase = zeros.iter().all(|zero| zero.magnitude() <= 1.0 + tolerance);
    Ok(Value::Logical(stable && minimum_phase))
}

fn builtin_ismaxphase(args: &[Value]) -> Result<Value, RuntimeError> {
    let (numerator, denominator, tolerance) = parse_phase_property_filter_args(args, "ismaxphase")?;
    let poles = filter_denominator_roots(&denominator, tolerance, "ismaxphase")?;
    let zeros = filter_numerator_roots(&numerator, tolerance);
    let stable = poles.iter().all(|pole| pole.magnitude() <= 1.0 + tolerance);
    let maximum_phase = zeros.iter().all(|zero| zero.magnitude() >= 1.0 - tolerance);
    Ok(Value::Logical(stable && maximum_phase))
}

fn builtin_isallpass(args: &[Value]) -> Result<Value, RuntimeError> {
    let (numerator, denominator, tolerance) = parse_phase_property_filter_args(args, "isallpass")?;
    let denominator = trim_filter_trailing_zeros(&denominator, tolerance);
    if denominator.is_empty() || denominator[0].magnitude() <= tolerance {
        return Err(RuntimeError::TypeError(
            "isallpass currently expects a denominator vector with nonzero leading coefficient"
                .to_string(),
        ));
    }
    let numerator = trim_filter_trailing_zeros(&numerator, tolerance);
    if numerator.len() < denominator.len() {
        return Ok(Value::Logical(false));
    }

    let delay = numerator.len() - denominator.len();
    if numerator[..delay]
        .iter()
        .any(|value| value.magnitude() > tolerance)
    {
        return Ok(Value::Logical(false));
    }

    let expected = denominator
        .iter()
        .rev()
        .copied()
        .map(ComplexParts::conjugate)
        .collect::<Vec<_>>();
    let actual = numerator[delay..].to_vec();
    let Some((actual_ref, expected_ref)) = actual
        .iter()
        .copied()
        .zip(expected.iter().copied())
        .find(|(actual, expected)| {
            expected.magnitude() > tolerance || actual.magnitude() > tolerance
        })
    else {
        return Ok(Value::Logical(true));
    };
    if actual_ref.magnitude() <= tolerance || expected_ref.magnitude() <= tolerance {
        return Ok(Value::Logical(false));
    }
    let scale = actual_ref.rdivide(expected_ref);
    if (scale.magnitude() - 1.0).abs() > tolerance {
        return Ok(Value::Logical(false));
    }
    let matched = actual
        .iter()
        .zip(expected.iter())
        .all(|(actual, expected)| actual.minus(expected.times(scale)).magnitude() <= tolerance);
    Ok(Value::Logical(matched))
}

fn builtin_eqtflength(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 3 || output_arity > 4 {
        return Err(RuntimeError::Unsupported(
            "eqtflength currently supports one, two, or four outputs".to_string(),
        ));
    }
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "eqtflength currently supports eqtflength(num, den)".to_string(),
        ));
    };
    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "eqtflength")?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator, "eqtflength")?;
    let (numerator, denominator) = equalized_transfer_function_lengths(numerator, denominator);
    let numerator_order = transfer_function_order(&numerator);
    let denominator_order = transfer_function_order(&denominator);
    let numerator = complex_row_output(numerator)?;
    let denominator = complex_row_output(denominator)?;
    match output_arity {
        0 | 1 => Ok(vec![numerator]),
        2 => Ok(vec![numerator, denominator]),
        4 => Ok(vec![
            numerator,
            denominator,
            Value::Scalar(numerator_order as f64),
            Value::Scalar(denominator_order as f64),
        ]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_filtord(args: &[Value]) -> Result<Value, RuntimeError> {
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "filtord currently supports filtord(b, a)".to_string(),
        ));
    };
    let tolerance = default_phase_property_tolerance();
    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "filtord")?;
    let (denominator, _denominator_is_row) = numeric_or_complex_set_vector(denominator, "filtord")?;
    let denominator = trim_filter_trailing_zeros(&denominator, tolerance);
    if denominator.is_empty() || denominator[0].magnitude() <= tolerance {
        return Err(RuntimeError::TypeError(
            "filtord currently expects a denominator vector with nonzero leading coefficient"
                .to_string(),
        ));
    }
    let numerator = trim_filter_trailing_zeros(&numerator, tolerance);
    Ok(Value::Scalar(
        transfer_function_order(&numerator).max(transfer_function_order(&denominator)) as f64,
    ))
}

fn builtin_impzlength(args: &[Value]) -> Result<Value, RuntimeError> {
    let (numerator, denominator, tolerance) = parse_impzlength_args(args)?;
    let numerator_len = numerator.len().max(1);
    let denominator = trim_filter_trailing_zeros(&denominator, default_phase_property_tolerance());
    if denominator.is_empty() || denominator[0].magnitude() <= default_phase_property_tolerance() {
        return Err(RuntimeError::TypeError(
            "impzlength currently expects a denominator vector with nonzero leading coefficient"
                .to_string(),
        ));
    }
    if denominator.len() <= 1 {
        return Ok(Value::Scalar(numerator_len as f64));
    }

    let poles = complex_polynomial_roots(&denominator);
    let root_tolerance = default_phase_property_tolerance();
    let unstable_radius = poles
        .iter()
        .map(|pole| pole.magnitude())
        .filter(|radius| *radius > 1.0 + root_tolerance)
        .fold(0.0_f64, f64::max);
    if unstable_radius > 0.0 {
        return Ok(Value::Scalar(
            impzlength_growth_length(unstable_radius, 1e6) as f64,
        ));
    }

    let oscillatory_length = impzlength_oscillation_length(&poles, root_tolerance);
    let stable_radius = poles
        .iter()
        .map(|pole| pole.magnitude())
        .filter(|radius| *radius < 1.0 - root_tolerance)
        .fold(0.0_f64, f64::max);
    let damped_length = if stable_radius > 0.0 {
        impzlength_decay_length(stable_radius, tolerance)
    } else {
        0
    };

    let length = oscillatory_length.max(damped_length).max(1);
    Ok(Value::Scalar(length as f64))
}

fn builtin_filtic(args: &[Value]) -> Result<Value, RuntimeError> {
    let (b_value, a_value, y_value, x_value) = match args {
        [b, a, y] => (b, a, y, None),
        [b, a, y, x] => (b, a, y, Some(x)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "filtic currently supports filtic(b, a, y) and filtic(b, a, y, x)".to_string(),
            ))
        }
    };

    let (b, _b_is_row) = numeric_or_complex_set_vector(b_value, "filtic")?;
    let (a, _a_is_row) = numeric_or_complex_set_vector(a_value, "filtic")?;
    if b.is_empty() || a.is_empty() {
        return Err(RuntimeError::ShapeError(
            "filtic currently expects nonempty coefficient vectors".to_string(),
        ));
    }
    if a[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "filtic currently expects a(1) to be nonzero".to_string(),
        ));
    }

    let (b, a) = normalized_filter_coefficients(&b, &a);
    let state_len = b.len().max(a.len()).saturating_sub(1);
    if state_len == 0 {
        return Ok(Value::Matrix(MatrixValue::new(0, 1, Vec::new())?));
    }

    let y_history = filtic_history(
        y_value,
        a.len().saturating_sub(1),
        state_len,
        "filtic",
        "past output",
    )?;
    let x_history = match x_value {
        Some(x_value) => filtic_history(
            x_value,
            b.len().saturating_sub(1),
            state_len,
            "filtic",
            "past input",
        )?,
        None => vec![ComplexParts::zero(); state_len],
    };

    let state = filtic_state_values(&b, &a, &y_history, &x_history);
    complex_column_output(state)
}

fn filtic_history(
    value: &Value,
    relevant_len: usize,
    state_len: usize,
    builtin_name: &str,
    label: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let (values, _is_row) = numeric_or_complex_set_vector(value, builtin_name)?;
    let mut history = vec![ComplexParts::zero(); state_len];
    for (index, value) in values.into_iter().take(relevant_len).enumerate() {
        history[index] = value;
    }
    let _ = label;
    Ok(history)
}

fn filtic_state_values(
    b: &[ComplexParts],
    a: &[ComplexParts],
    y_history: &[ComplexParts],
    x_history: &[ComplexParts],
) -> Vec<ComplexParts> {
    let state_len = b.len().max(a.len()).saturating_sub(1);
    let mut b_padded = vec![ComplexParts::zero(); state_len + 1];
    let mut a_padded = vec![ComplexParts::zero(); state_len + 1];
    for (index, coefficient) in b.iter().copied().enumerate() {
        b_padded[index] = coefficient;
    }
    for (index, coefficient) in a.iter().copied().enumerate() {
        a_padded[index] = coefficient;
    }

    (0..state_len)
        .map(|delay| {
            let mut total = ComplexParts::zero();
            for coefficient_index in (delay + 1)..=state_len {
                let history_index = coefficient_index - delay - 1;
                total = total.plus(
                    b_padded[coefficient_index]
                        .times(x_history[history_index])
                        .minus(a_padded[coefficient_index].times(y_history[history_index])),
                );
            }
            normalize_complex_parts(total)
        })
        .collect()
}

fn parse_impzlength_args(
    args: &[Value],
) -> Result<(Vec<ComplexParts>, Vec<ComplexParts>, f64), RuntimeError> {
    let (numerator_value, denominator_value, tolerance) = match args {
        [numerator, denominator] => (numerator, denominator, 5e-5),
        [numerator, denominator, tolerance] => (
            numerator,
            denominator,
            parse_impzlength_tolerance(tolerance)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "impzlength currently supports impzlength(b, a) and impzlength(b, a, tol)"
                    .to_string(),
            ))
        }
    };
    let (numerator, _numerator_is_row) =
        numeric_or_complex_set_vector(numerator_value, "impzlength")?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator_value, "impzlength")?;
    Ok((numerator, denominator, tolerance))
}

fn parse_impzlength_tolerance(value: &Value) -> Result<f64, RuntimeError> {
    let tolerance = value.as_scalar()?;
    if !tolerance.is_finite() || tolerance <= 0.0 {
        return Err(RuntimeError::TypeError(
            "impzlength currently expects tol to be a positive finite scalar".to_string(),
        ));
    }
    Ok(tolerance)
}

fn impzlength_decay_length(radius: f64, tolerance: f64) -> usize {
    if radius <= 0.0 {
        return 1;
    }
    (tolerance.ln() / radius.ln()).floor().max(1.0) as usize
}

fn impzlength_growth_length(radius: f64, growth: f64) -> usize {
    if radius <= 1.0 {
        return 1;
    }
    (growth.ln() / radius.ln()).ceil().max(1.0) as usize
}

fn impzlength_oscillation_length(poles: &[ComplexParts], tolerance: f64) -> usize {
    let slowest_angle = poles
        .iter()
        .filter_map(|pole| {
            let radius = pole.magnitude();
            if (radius - 1.0).abs() > tolerance {
                return None;
            }
            let mut angle = pole.argument().abs();
            if angle > std::f64::consts::PI {
                angle = 2.0 * std::f64::consts::PI - angle;
            }
            if angle <= tolerance {
                None
            } else {
                Some(angle)
            }
        })
        .fold(None, |best: Option<f64>, angle| match best {
            Some(current) => Some(current.min(angle)),
            None => Some(angle),
        });
    slowest_angle
        .map(|angle| (5.0 * 2.0 * std::f64::consts::PI / angle).ceil().max(1.0) as usize)
        .unwrap_or(0)
}

fn parse_islinphase_args(args: &[Value]) -> Result<(&Value, &Value, f64), RuntimeError> {
    match args {
        [numerator, denominator] => {
            Ok((numerator, denominator, default_phase_property_tolerance()))
        }
        [numerator, denominator, tolerance] => Ok((
            numerator,
            denominator,
            parse_phase_property_tolerance(tolerance, "islinphase")?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "islinphase currently supports islinphase(b, a) and islinphase(b, a, tol)".to_string(),
        )),
    }
}

fn parse_phase_property_filter_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(Vec<ComplexParts>, Vec<ComplexParts>, f64), RuntimeError> {
    let (numerator_value, denominator_value, tolerance) = match args {
        [numerator, denominator] => (numerator, denominator, default_phase_property_tolerance()),
        [numerator, denominator, tolerance] => (
            numerator,
            denominator,
            parse_phase_property_tolerance(tolerance, builtin_name)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports {builtin_name}(b, a) and {builtin_name}(b, a, tol)"
        )))
        }
    };
    let (numerator, _numerator_is_row) =
        numeric_or_complex_set_vector(numerator_value, builtin_name)?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator_value, builtin_name)?;
    Ok((numerator, denominator, tolerance))
}

fn default_phase_property_tolerance() -> f64 {
    f64::EPSILON.powf(2.0 / 3.0)
}

fn parse_phase_property_tolerance(value: &Value, builtin_name: &str) -> Result<f64, RuntimeError> {
    let tolerance = value.as_scalar()?;
    if !tolerance.is_finite() || tolerance <= 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects tol to be a positive finite scalar"
        )));
    }
    Ok(tolerance)
}

fn trim_filter_trailing_zeros(values: &[ComplexParts], tolerance: f64) -> Vec<ComplexParts> {
    let last_nonzero = values
        .iter()
        .rposition(|value| value.magnitude() > tolerance)
        .unwrap_or(0);
    values[..=last_nonzero]
        .iter()
        .copied()
        .map(normalize_complex_parts)
        .collect()
}

fn equalized_transfer_function_lengths(
    mut numerator: Vec<ComplexParts>,
    mut denominator: Vec<ComplexParts>,
) -> (Vec<ComplexParts>, Vec<ComplexParts>) {
    while numerator.len() > 1
        && denominator.len() > 1
        && numerator
            .last()
            .is_some_and(|value| value.is_approximately_zero())
        && denominator
            .last()
            .is_some_and(|value| value.is_approximately_zero())
    {
        numerator.pop();
        denominator.pop();
    }
    let len = numerator.len().max(denominator.len());
    numerator.resize(len, ComplexParts::zero());
    denominator.resize(len, ComplexParts::zero());
    (numerator, denominator)
}

fn transfer_function_order(values: &[ComplexParts]) -> usize {
    values
        .iter()
        .rposition(|value| !value.is_approximately_zero())
        .unwrap_or(0)
}

fn filter_denominator_roots(
    values: &[ComplexParts],
    tolerance: f64,
    builtin_name: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let values = trim_filter_trailing_zeros(values, tolerance);
    if values.is_empty() || values[0].magnitude() <= tolerance {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a denominator vector with nonzero leading coefficient"
        )));
    }
    Ok(complex_polynomial_roots(&values))
}

fn filter_numerator_roots(values: &[ComplexParts], tolerance: f64) -> Vec<ComplexParts> {
    let values = trim_filter_trailing_zeros(values, tolerance);
    let values = trim_filter_endpoint_zeros(&values, tolerance);
    complex_polynomial_roots(&values)
}

fn trim_filter_endpoint_zeros(values: &[ComplexParts], tolerance: f64) -> Vec<ComplexParts> {
    let Some(first_nonzero) = values
        .iter()
        .position(|value| value.magnitude() > tolerance)
    else {
        return vec![ComplexParts::zero()];
    };
    let last_nonzero = values
        .iter()
        .rposition(|value| value.magnitude() > tolerance)
        .expect("first_nonzero guarantees last_nonzero");
    values[first_nonzero..=last_nonzero]
        .iter()
        .copied()
        .map(normalize_complex_parts)
        .collect()
}

fn is_linear_phase_fir(values: &[ComplexParts], tolerance: f64) -> bool {
    linear_phase_fir_type(values, tolerance).is_some()
}

fn linear_phase_fir_type(values: &[ComplexParts], tolerance: f64) -> Option<usize> {
    let Some(reference) = values
        .iter()
        .copied()
        .find(|value| value.magnitude() > tolerance)
    else {
        return Some(1);
    };
    let phase = reference.argument();
    let rotation = ComplexParts {
        real: (-phase).cos(),
        imag: (-phase).sin(),
    };
    let rotated = values
        .iter()
        .copied()
        .map(|value| normalize_complex_parts(value.times(rotation)))
        .collect::<Vec<_>>();
    if rotated.iter().any(|value| value.imag.abs() > tolerance) {
        return None;
    }
    let reals = rotated.iter().map(|value| value.real).collect::<Vec<_>>();
    let symmetric = reals
        .iter()
        .zip(reals.iter().rev())
        .all(|(lhs, rhs)| (*lhs - *rhs).abs() <= tolerance);
    let antisymmetric = reals
        .iter()
        .zip(reals.iter().rev())
        .all(|(lhs, rhs)| (*lhs + *rhs).abs() <= tolerance);
    if !symmetric && !antisymmetric {
        return None;
    }
    let order = reals.len().saturating_sub(1);
    Some(match (symmetric, order % 2 == 0) {
        (true, true) => 1,
        (true, false) => 2,
        (false, true) => 3,
        (false, false) => 4,
    })
}

fn parse_freqz_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<
    (
        Vec<ComplexParts>,
        Vec<ComplexParts>,
        DigitalFrequencySelection<'a>,
    ),
    RuntimeError,
> {
    let (sections, selection) = match args {
        [ctf, mode] if is_ctf_mode(mode) => (
            parse_digital_filter_ctf_cell_sections(ctf, builtin_name)?,
            default_digital_frequency_selection(),
        ),
        [ctf, mode, tail @ ..] if is_ctf_mode(mode) => (
            parse_digital_filter_ctf_cell_sections(ctf, builtin_name)?,
            parse_digital_frequency_selection_tail(tail, builtin_name)?,
        ),
        [sections] if filtfilt_sos_signature(sections) => (
            parse_sos_sections(sections, &Value::Scalar(1.0), builtin_name)?,
            default_digital_frequency_selection(),
        ),
        [sections, tail @ ..] if filtfilt_sos_signature(sections) => (
            parse_sos_sections(sections, &Value::Scalar(1.0), builtin_name)?,
            parse_digital_frequency_selection_tail(tail, builtin_name)?,
        ),
        [numerators, denominators, mode] if is_ctf_mode(mode) => (
            parse_ctf_sections(numerators, denominators, None, builtin_name)?,
            default_digital_frequency_selection(),
        ),
        [numerators, denominators, mode, tail @ ..] if is_ctf_mode(mode) => (
            parse_ctf_sections(numerators, denominators, None, builtin_name)?,
            parse_digital_frequency_selection_tail(tail, builtin_name)?,
        ),
        [numerator, denominator] => (
            vec![parse_transfer_function_section(
                numerator,
                denominator,
                builtin_name,
            )?],
            default_digital_frequency_selection(),
        ),
        [numerator, denominator, tail @ ..] => (
            vec![parse_transfer_function_section(
                numerator,
                denominator,
                builtin_name,
            )?],
            parse_digital_frequency_selection_tail(tail, builtin_name)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports transfer-function, CTF, and SOS digital filter forms with optional point-count, frequency-vector, \"whole\", and sample-rate arguments"
            )))
        }
    };
    let (numerator, denominator) = equivalent_filter_sections_transfer_function(&sections);
    Ok((numerator, denominator, selection))
}

fn default_digital_frequency_selection() -> DigitalFrequencySelection<'static> {
    DigitalFrequencySelection::Grid {
        count: DEFAULT_DIGITAL_FREQUENCY_POINT_COUNT,
        whole: false,
        sample_rate: None,
    }
}

fn parse_digital_frequency_selection_tail<'a>(
    tail: &'a [Value],
    builtin_name: &str,
) -> Result<DigitalFrequencySelection<'a>, RuntimeError> {
    match tail {
        [] => Ok(default_digital_frequency_selection()),
        [selection] => parse_digital_frequency_selection(selection, false, None, builtin_name),
        [first, second] => {
            if is_whole_mode(first) {
                Ok(DigitalFrequencySelection::Grid {
                    count: DEFAULT_DIGITAL_FREQUENCY_POINT_COUNT,
                    whole: true,
                    sample_rate: Some(parse_digital_sample_rate(second, builtin_name)?),
                })
            } else if is_whole_mode(second) {
                parse_digital_frequency_selection(first, true, None, builtin_name)
            } else {
                parse_digital_frequency_selection(
                    first,
                    false,
                    Some(parse_digital_sample_rate(second, builtin_name)?),
                    builtin_name,
                )
            }
        }
        [first, second, third] => {
            if is_whole_mode(first) {
                parse_digital_frequency_selection(
                    second,
                    true,
                    Some(parse_digital_sample_rate(third, builtin_name)?),
                    builtin_name,
                )
            } else if is_whole_mode(second) {
                parse_digital_frequency_selection(
                    first,
                    true,
                    Some(parse_digital_sample_rate(third, builtin_name)?),
                    builtin_name,
                )
            } else if is_whole_mode(third) {
                parse_digital_frequency_selection(
                    first,
                    true,
                    Some(parse_digital_sample_rate(second, builtin_name)?),
                    builtin_name,
                )
            } else {
                Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently expects the optional third trailing frequency-selection argument to be \"whole\""
                )))
            }
        }
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports at most three trailing frequency-selection arguments"
        ))),
    }
}

fn is_ctf_mode(value: &Value) -> bool {
    matches!(
        value,
        Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("ctf")
    )
}

fn parse_digital_filter_ctf_cell_sections(
    value: &Value,
    builtin_name: &str,
) -> Result<Vec<FiltfiltSection>, RuntimeError> {
    let Value::Cell(cell) = value else {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a {{B, A, g}} cell input for CTF cell syntax"
        )));
    };
    if cell.element_count() != 3 || (cell.rows != 1 && cell.cols != 1) {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects {{B, A, g}} cell inputs to contain exactly three elements"
        )));
    }
    parse_ctf_sections(
        &cell.elements()[0],
        &cell.elements()[1],
        Some(&cell.elements()[2]),
        builtin_name,
    )
}

fn equivalent_filter_sections_transfer_function(
    sections: &[FiltfiltSection],
) -> (Vec<ComplexParts>, Vec<ComplexParts>) {
    let mut numerator = vec![ComplexParts::one()];
    let mut denominator = vec![ComplexParts::one()];
    for section in sections {
        numerator = full_complex_convolution_vector(&numerator, &section.numerator);
        denominator = full_complex_convolution_vector(&denominator, &section.denominator);
    }
    (numerator, denominator)
}

fn zp2ctf_sections_from_roots(
    zeros: &[ComplexParts],
    poles: &[ComplexParts],
) -> Vec<FiltfiltSection> {
    let zero_sections = pair_roots_into_ctf_sections(zeros);
    let pole_sections = pair_roots_into_ctf_sections(poles);
    let section_count = zero_sections.len().max(pole_sections.len());
    let mut sections = Vec::with_capacity(section_count);
    for index in 0..section_count {
        sections.push(FiltfiltSection {
            numerator: ctf_section_coefficients_from_roots(
                zero_sections.get(index).map(Vec::as_slice).unwrap_or(&[]),
            ),
            denominator: ctf_section_coefficients_from_roots(
                pole_sections.get(index).map(Vec::as_slice).unwrap_or(&[]),
            ),
        });
    }
    sections
}

fn pair_roots_into_ctf_sections(roots: &[ComplexParts]) -> Vec<Vec<ComplexParts>> {
    let tolerance = 1e-9;
    let mut used = vec![false; roots.len()];
    let mut sections = Vec::new();
    for index in 0..roots.len() {
        if used[index] {
            continue;
        }
        used[index] = true;
        let root = roots[index];
        let partner = if root.imag.abs() > tolerance {
            (index + 1..roots.len()).find(|candidate| {
                !used[*candidate]
                    && roots[*candidate].minus(root.conjugate()).magnitude() <= tolerance
            })
        } else {
            (index + 1..roots.len())
                .find(|candidate| !used[*candidate] && roots[*candidate].imag.abs() <= tolerance)
        }
        .or_else(|| (index + 1..roots.len()).find(|candidate| !used[*candidate]));
        if let Some(partner) = partner {
            used[partner] = true;
            sections.push(vec![root, roots[partner]]);
        } else {
            sections.push(vec![root]);
        }
    }
    sections
}

fn ctf_section_coefficients_from_roots(roots: &[ComplexParts]) -> Vec<ComplexParts> {
    let mut coefficients = complex_polynomial_coefficients_from_roots(roots);
    coefficients.resize(3, ComplexParts::zero());
    coefficients
}

fn is_whole_mode(value: &Value) -> bool {
    matches!(
        value,
        Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("whole")
    )
}

fn parse_digital_frequency_selection<'a>(
    value: &'a Value,
    whole: bool,
    sample_rate: Option<f64>,
    builtin_name: &str,
) -> Result<DigitalFrequencySelection<'a>, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) => Ok(DigitalFrequencySelection::Grid {
            count: nonnegative_integer_scalar_with_label(
                value,
                builtin_name,
                "a nonnegative point count",
            )?,
            whole,
            sample_rate,
        }),
        Value::Matrix(matrix) if matrix.rows == 1 && matrix.cols == 1 => {
            Ok(DigitalFrequencySelection::Grid {
                count: nonnegative_integer_scalar_with_label(
                    value,
                    builtin_name,
                    "a nonnegative point count",
                )?,
                whole,
                sample_rate,
            })
        }
        Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0 => {
            Ok(DigitalFrequencySelection::Grid {
                count: DEFAULT_DIGITAL_FREQUENCY_POINT_COUNT,
                whole,
                sample_rate,
            })
        }
        Value::Matrix(matrix) if matrix.rows == 1 || matrix.cols == 1 => {
            if whole {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports \"whole\" only with a point count"
                )));
            }
            if matrix.element_count() < 2 {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} currently expects explicit frequency vectors to have at least two elements"
                )));
            }
            Ok(DigitalFrequencySelection::Explicit {
                frequencies: value,
                sample_rate,
            })
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a point count or a frequency vector"
        ))),
    }
}

fn parse_digital_sample_rate(value: &Value, builtin_name: &str) -> Result<f64, RuntimeError> {
    let sample_rate = value.as_scalar()?;
    if !sample_rate.is_finite() || sample_rate <= 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects fs to be a positive finite scalar"
        )));
    }
    Ok(sample_rate)
}

fn digital_frequency_response_outputs(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    selection: DigitalFrequencySelection<'_>,
    output_arity: usize,
    builtin_name: &str,
) -> Result<Vec<Value>, RuntimeError> {
    let (responses, frequencies, _evaluation_frequencies, row_output) =
        digital_filter_frequency_selection_response(
            numerator,
            denominator,
            selection,
            builtin_name,
        )?;
    let mut outputs = vec![numeric_or_complex_vector_output(responses, row_output)?];
    if output_arity >= 2 {
        outputs.push(numeric_set_output(frequencies, row_output, false)?);
    }
    Ok(outputs)
}

fn digital_filter_frequency_selection_response(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    selection: DigitalFrequencySelection<'_>,
    builtin_name: &str,
) -> Result<(Vec<ComplexParts>, Vec<f64>, Vec<f64>, bool), RuntimeError> {
    let (evaluation_frequencies, output_frequencies, row_output) =
        digital_frequency_selection_values(selection, builtin_name)?;
    let responses =
        digital_filter_response_at_frequencies(numerator, denominator, &evaluation_frequencies);
    Ok((
        responses,
        output_frequencies,
        evaluation_frequencies,
        row_output,
    ))
}

fn digital_frequency_selection_values(
    selection: DigitalFrequencySelection<'_>,
    builtin_name: &str,
) -> Result<(Vec<f64>, Vec<f64>, bool), RuntimeError> {
    match selection {
        DigitalFrequencySelection::Grid {
            count,
            whole,
            sample_rate,
        } => {
            let evaluation_frequencies = digital_frequency_grid(count, whole);
            let output_frequencies = if let Some(sample_rate) = sample_rate {
                evaluation_frequencies
                    .iter()
                    .map(|frequency| frequency * sample_rate / (2.0 * std::f64::consts::PI))
                    .collect::<Vec<_>>()
            } else {
                evaluation_frequencies.clone()
            };
            Ok((evaluation_frequencies, output_frequencies, false))
        }
        DigitalFrequencySelection::Explicit {
            frequencies,
            sample_rate,
        } => {
            let (frequencies, row_output, _logical_output) =
                numeric_set_vector(frequencies, builtin_name)?;
            let evaluation_frequencies = if let Some(sample_rate) = sample_rate {
                frequencies
                    .iter()
                    .map(|frequency| frequency * (2.0 * std::f64::consts::PI) / sample_rate)
                    .collect::<Vec<_>>()
            } else {
                frequencies.clone()
            };
            Ok((evaluation_frequencies, frequencies, row_output))
        }
    }
}

fn digital_filter_response_at_frequencies(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    frequencies: &[f64],
) -> Vec<ComplexParts> {
    let mut responses = Vec::with_capacity(frequencies.len());
    for frequency in frequencies {
        let sample = ComplexParts {
            real: frequency.cos(),
            imag: -frequency.sin(),
        };
        let numerator_value = evaluate_filter_response_polynomial(numerator, sample);
        let denominator_value = evaluate_filter_response_polynomial(denominator, sample);
        responses.push(normalize_complex_parts(
            numerator_value.rdivide(denominator_value),
        ));
    }
    responses
}

fn digital_frequency_grid(count: usize, whole: bool) -> Vec<f64> {
    let scale = if whole {
        2.0 * std::f64::consts::PI
    } else {
        std::f64::consts::PI
    };
    let mut frequencies = Vec::with_capacity(count);
    for index in 0..count {
        let frequency = if count == 0 {
            0.0
        } else {
            scale * (index as f64) / (count as f64)
        };
        frequencies.push(frequency);
    }
    frequencies
}

fn unwrap_phase_values(values: Vec<f64>) -> Vec<f64> {
    unwrap_phase_values_with_tolerance(values, std::f64::consts::PI)
}

fn unwrap_phase_values_with_tolerance(values: Vec<f64>, tolerance: f64) -> Vec<f64> {
    let mut unwrapped = Vec::with_capacity(values.len());
    let mut offset = 0.0;
    let mut previous: Option<f64> = None;
    for value in values {
        if let Some(previous_value) = previous {
            let delta = value - previous_value;
            if delta.abs() >= tolerance {
                let correction =
                    -2.0 * std::f64::consts::PI * (delta / (2.0 * std::f64::consts::PI)).round();
                offset += correction;
            }
        }
        unwrapped.push(normalize_polynomial_scalar(value + offset));
        previous = Some(value);
    }
    unwrapped
}

fn group_delay_sample(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    frequency: f64,
) -> f64 {
    let sample = ComplexParts {
        real: frequency.cos(),
        imag: -frequency.sin(),
    };
    let numerator_value = evaluate_filter_response_polynomial(numerator, sample);
    let denominator_value = evaluate_filter_response_polynomial(denominator, sample);
    if numerator_value.is_approximately_zero() || denominator_value.is_approximately_zero() {
        return f64::NAN;
    }
    let numerator_delay =
        evaluate_filter_response_weighted_polynomial(numerator, sample).rdivide(numerator_value);
    let denominator_delay = evaluate_filter_response_weighted_polynomial(denominator, sample)
        .rdivide(denominator_value);
    normalize_polynomial_scalar(numerator_delay.real - denominator_delay.real)
}

fn evaluate_filter_response_polynomial(
    coefficients: &[ComplexParts],
    sample: ComplexParts,
) -> ComplexParts {
    let mut total = ComplexParts::zero();
    let mut power = ComplexParts::one();
    for coefficient in coefficients {
        total = normalize_complex_parts(total.plus(coefficient.times(power)));
        power = normalize_complex_parts(power.times(sample));
    }
    total
}

fn evaluate_filter_response_weighted_polynomial(
    coefficients: &[ComplexParts],
    sample: ComplexParts,
) -> ComplexParts {
    let mut total = ComplexParts::zero();
    let mut power = ComplexParts::one();
    for (index, coefficient) in coefficients.iter().enumerate() {
        total = normalize_complex_parts(total.plus(coefficient.times(power).scale(index as f64)));
        power = normalize_complex_parts(power.times(sample));
    }
    total
}

fn builtin_freqs(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "freqs currently supports one or two outputs".to_string(),
        ));
    }
    let [numerator, denominator, frequencies] = args else {
        return Err(RuntimeError::Unsupported(
            "freqs currently supports freqs(b, a, w) with an explicit frequency vector".to_string(),
        ));
    };

    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "freqs")?;
    let (denominator, _denominator_is_row) = numeric_or_complex_set_vector(denominator, "freqs")?;
    if denominator.is_empty() || denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "freqs currently expects a denominator vector with nonzero leading coefficient"
                .to_string(),
        ));
    }
    let (frequencies, frequencies_are_row, frequencies_are_logical) =
        numeric_set_vector(frequencies, "freqs")?;

    let responses = frequencies
        .iter()
        .copied()
        .map(|frequency| {
            let sample = ComplexParts {
                real: 0.0,
                imag: frequency,
            };
            let numerator_value = evaluate_complex_polynomial(&numerator, sample);
            let denominator_value = evaluate_complex_polynomial(&denominator, sample);
            normalize_complex_parts(numerator_value.rdivide(denominator_value))
        })
        .collect::<Vec<_>>();

    let mut outputs = vec![numeric_or_complex_vector_output(
        responses,
        frequencies_are_row,
    )?];
    if output_arity >= 2 {
        outputs.push(numeric_set_output(
            frequencies,
            frequencies_are_row,
            frequencies_are_logical,
        )?);
    }
    Ok(outputs)
}

fn builtin_impz(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "impz currently supports one or two outputs".to_string(),
        ));
    }
    let [numerator, denominator, sample_count] = args else {
        return Err(RuntimeError::Unsupported(
            "impz currently supports impz(b, a, n)".to_string(),
        ));
    };

    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "impz")?;
    let (denominator, _denominator_is_row) = numeric_or_complex_set_vector(denominator, "impz")?;
    if denominator.is_empty() || denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "impz currently expects a denominator vector with nonzero first coefficient"
                .to_string(),
        ));
    }
    let sample_count =
        positive_integer_scalar_with_label(sample_count, "impz", "a positive sample count")?;
    let response = impulse_response_samples(&numerator, &denominator, sample_count);
    let time = (0..sample_count)
        .map(|index| index as f64)
        .collect::<Vec<_>>();
    let mut outputs = vec![complex_column_output(response)?];
    if output_arity >= 2 {
        outputs.push(numeric_column_output(time)?);
    }
    Ok(outputs)
}

