fn impulse_response_samples(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    sample_count: usize,
) -> Vec<ComplexParts> {
    let mut response = vec![ComplexParts::zero(); sample_count];
    for sample in 0..sample_count {
        let mut total = numerator
            .get(sample)
            .copied()
            .unwrap_or_else(ComplexParts::zero);
        for denominator_index in 1..denominator.len() {
            if sample >= denominator_index {
                total = total.minus(
                    denominator[denominator_index].times(response[sample - denominator_index]),
                );
            }
        }
        response[sample] = normalize_complex_parts(total.rdivide(denominator[0]));
    }
    response
}

fn step_response_samples(
    numerator: &[ComplexParts],
    denominator: &[ComplexParts],
    sample_count: usize,
) -> Vec<ComplexParts> {
    let impulse = impulse_response_samples(numerator, denominator, sample_count);
    let mut total = ComplexParts::zero();
    impulse
        .into_iter()
        .map(|sample| {
            total = normalize_complex_parts(total.plus(sample));
            total
        })
        .collect()
}

fn parse_fft_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, Option<usize>, Option<usize>), RuntimeError> {
    match args {
        [value] => Ok((value, None, None)),
        [value, len] => Ok((value, parse_optional_fft_length(len, builtin_name)?, None)),
        [value, len, dim] => Ok((
            value,
            parse_optional_fft_length(len, builtin_name)?,
            Some(positive_dimension(dim, builtin_name)?),
        )),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)`, `{builtin_name}(x,n)`, and `{builtin_name}(x,n,dim)`"
        ))),
    }
}

fn parse_fft2_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, Option<[usize; 2]>), RuntimeError> {
    match args {
        [value] => Ok((value, None)),
        [value, rows, cols] => Ok((
            value,
            Some([
                parse_fft_length(rows, builtin_name)?,
                parse_fft_length(cols, builtin_name)?,
            ]),
        )),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)` and `{builtin_name}(x,m,n)`"
        ))),
    }
}

fn parse_fftn_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, Option<Vec<usize>>), RuntimeError> {
    match args {
        [value] => Ok((value, None)),
        [value, shape] if is_empty_matrix_placeholder(shape) => Ok((value, None)),
        [value, shape] => Ok((value, Some(parse_fft_size_vector(shape, builtin_name)?))),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)` and `{builtin_name}(x,sz)`"
        ))),
    }
}

fn parse_optional_fft_length(
    value: &Value,
    builtin_name: &str,
) -> Result<Option<usize>, RuntimeError> {
    if is_empty_matrix_placeholder(value) {
        Ok(None)
    } else {
        Ok(Some(parse_fft_length(value, builtin_name)?))
    }
}

fn parse_fft_length(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects transform lengths to be nonnegative integers"
        )));
    }
    Ok(scalar as usize)
}

fn parse_fft_size_vector(value: &Value, builtin_name: &str) -> Result<Vec<usize>, RuntimeError> {
    let shape = meshgrid_vector(value)?;
    if shape.is_empty() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a nonempty size vector"
        )));
    }
    shape
        .into_iter()
        .map(|dim| {
            if !dim.is_finite() || dim < 0.0 || dim.fract() != 0.0 {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects size vector entries to be nonnegative integers"
                )));
            }
            Ok(dim as usize)
        })
        .collect()
}

fn fft_along_dimension_values(
    values: &[ComplexParts],
    input_dims: &[usize],
    dimension: usize,
    transform_len: usize,
    inverse: bool,
) -> (Vec<usize>, Vec<ComplexParts>) {
    let mut normalized_input_dims = input_dims.to_vec();
    while normalized_input_dims.len() < dimension {
        normalized_input_dims.push(1);
    }
    let axis = dimension - 1;
    let input_extent = normalized_input_dims[axis];
    let mut output_dims = normalized_input_dims.clone();
    output_dims[axis] = transform_len;
    let output_len = output_dims.iter().product::<usize>();
    if output_len == 0 {
        return (output_dims, Vec::new());
    }
    let mut output = Vec::with_capacity(output_len);
    let sign = if inverse { 1.0 } else { -1.0 };
    for linear in 0..output_len {
        let mut output_index = row_major_multi_index(linear, &output_dims);
        let frequency = output_index[axis];
        let mut total = ComplexParts::zero();
        for sample_index in 0..transform_len {
            let sample = if sample_index < input_extent {
                output_index[axis] = sample_index;
                values[row_major_linear_index(&output_index, &normalized_input_dims)]
            } else {
                ComplexParts::zero()
            };
            let angle =
                sign * 2.0 * std::f64::consts::PI * (frequency as f64) * (sample_index as f64)
                    / (transform_len as f64);
            let twiddle = ComplexParts {
                real: angle.cos(),
                imag: angle.sin(),
            };
            total = total.plus(sample.times(twiddle));
        }
        if inverse {
            total = total.scale(1.0 / transform_len as f64);
        }
        output.push(normalize_complex_parts(total));
    }
    (output_dims, output)
}

fn builtin_poly(args: &[Value]) -> Result<Value, RuntimeError> {
    let [roots] = args else {
        return Err(RuntimeError::Unsupported(
            "poly currently supports exactly one scalar/vector or square-matrix input".to_string(),
        ));
    };

    let roots = coerce_matrix(roots)?;
    if roots.rows > 1 && roots.cols > 1 {
        if roots.rows != roots.cols {
            return Err(RuntimeError::ShapeError(
                "poly currently expects a square matrix when given matrix input".to_string(),
            ));
        }
        let matrix = numeric_or_complex_operand(&Value::Matrix(roots), "poly")?;
        return complex_polynomial_degree_preserving_output(
            complex_characteristic_polynomial_coefficients(&matrix)?,
        );
    }
    let roots = roots
        .iter()
        .map(|element| numeric_or_complex_scalar(element, "poly"))
        .collect::<Result<Vec<_>, _>>()
        .map_err(|_| {
            RuntimeError::TypeError(
                "poly currently expects numeric or complex scalar or vector inputs".to_string(),
            )
        })?;
    let coefficients = complex_polynomial_coefficients_from_roots(&roots);
    complex_polynomial_coefficient_output(coefficients)
}

fn builtin_roots(args: &[Value]) -> Result<Value, RuntimeError> {
    let [coefficients] = args else {
        return Err(RuntimeError::Unsupported(
            "roots currently supports exactly one coefficient vector".to_string(),
        ));
    };

    let (coefficients, _row_output) = numeric_or_complex_set_vector(coefficients, "roots")?;
    let roots = complex_polynomial_roots(&coefficients);
    complex_roots_column_output(roots)
}

fn builtin_residue(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match args {
        [numerator, denominator] => residue_expand(numerator, denominator, output_arity),
        [residues, poles, direct] => residue_recompose(residues, poles, direct, output_arity),
        _ => Err(RuntimeError::Unsupported(
            "residue currently supports residue(b, a) or residue(r, p, k)".to_string(),
        )),
    }
}

fn residue_expand(
    numerator: &Value,
    denominator: &Value,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "residue currently supports one, two, or three outputs for residue(b, a)".to_string(),
        ));
    }

    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "residue")?;
    let (denominator, _denominator_is_row) = numeric_or_complex_set_vector(denominator, "residue")?;
    let numerator = complex_polynomial_compact_coefficients(&numerator);
    let denominator = complex_polynomial_compact_coefficients(&denominator);
    if denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "residue currently expects a nonzero denominator polynomial".to_string(),
        ));
    }

    if denominator.len() == 1 {
        let direct = numerator
            .iter()
            .copied()
            .map(|coefficient| normalize_complex_parts(coefficient.rdivide(denominator[0])))
            .collect::<Vec<_>>();
        let residues = Vec::new();
        let poles = Vec::new();
        return residue_outputs(residues, poles, direct, output_arity);
    }

    let (direct, remainder) = if numerator.len() >= denominator.len() {
        deconvolution_long_division(&numerator, &denominator)
    } else {
        (Vec::new(), numerator)
    };
    let poles = complex_polynomial_roots(&denominator);
    for lhs in 0..poles.len() {
        for rhs in (lhs + 1)..poles.len() {
            if poles[lhs].minus(poles[rhs]).magnitude() <= 1e-8 {
                return Err(RuntimeError::Unsupported(
                    "residue currently supports distinct denominator poles".to_string(),
                ));
            }
        }
    }

    let derivative = complex_polynomial_derivative_coefficients(&denominator);
    let mut residues = Vec::with_capacity(poles.len());
    for pole in &poles {
        let denominator_value = evaluate_complex_polynomial(&derivative, *pole);
        if denominator_value.is_approximately_zero() {
            return Err(RuntimeError::Unsupported(
                "residue currently supports distinct denominator poles".to_string(),
            ));
        }
        let numerator_value = evaluate_complex_polynomial(&remainder, *pole);
        residues.push(normalize_complex_parts(
            numerator_value.rdivide(denominator_value),
        ));
    }

    residue_outputs(residues, poles, direct, output_arity)
}

fn residue_recompose(
    residues: &Value,
    poles: &Value,
    direct: &Value,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "residue currently supports one or two outputs for residue(r, p, k)".to_string(),
        ));
    }
    let (residues, _residues_are_row) = numeric_or_complex_set_vector(residues, "residue")?;
    let (poles, _poles_are_row) = numeric_or_complex_set_vector(poles, "residue")?;
    if residues.len() != poles.len() {
        return Err(RuntimeError::ShapeError(
            "residue requires r and p to have the same number of elements".to_string(),
        ));
    }
    for lhs in 0..poles.len() {
        for rhs in (lhs + 1)..poles.len() {
            if poles[lhs].minus(poles[rhs]).magnitude() <= 1e-8 {
                return Err(RuntimeError::Unsupported(
                    "residue currently supports distinct poles for residue(r, p, k)".to_string(),
                ));
            }
        }
    }

    let direct = residue_direct_vector(direct)?;
    let denominator = complex_polynomial_coefficients_from_roots(&poles);
    let mut proper = vec![ComplexParts::zero(); residues.len()];
    for (index, residue) in residues.iter().copied().enumerate() {
        let remaining_poles = poles
            .iter()
            .enumerate()
            .filter_map(|(pole_index, pole)| {
                if pole_index == index {
                    None
                } else {
                    Some(*pole)
                }
            })
            .collect::<Vec<_>>();
        let factor = complex_polynomial_coefficients_from_roots(&remaining_poles);
        for (target, coefficient) in proper.iter_mut().zip(factor) {
            *target = normalize_complex_parts(target.plus(coefficient.times(residue)));
        }
    }
    let direct_product = if direct.is_empty() {
        Vec::new()
    } else {
        full_complex_convolution_vector(&direct, &denominator)
    };
    let numerator =
        complex_polynomial_compact_coefficients(&complex_polynomial_add(&proper, &direct_product));
    let denominator = complex_polynomial_compact_coefficients(&denominator);
    let mut outputs = vec![complex_polynomial_degree_preserving_output(numerator)?];
    if output_arity >= 2 {
        outputs.push(complex_polynomial_degree_preserving_output(denominator)?);
    }
    Ok(outputs)
}

fn residue_direct_vector(value: &Value) -> Result<Vec<ComplexParts>, RuntimeError> {
    match value {
        Value::Matrix(matrix) if matrix.element_count() == 0 => Ok(Vec::new()),
        _ => numeric_or_complex_set_vector(value, "residue").map(|(values, _is_row)| values),
    }
}

fn builtin_tf2zp(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "tf2zp currently supports one, two, or three outputs".to_string(),
        ));
    }
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "tf2zp currently supports tf2zp(b, a)".to_string(),
        ));
    };

    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, "tf2zp")?;
    let (denominator, _denominator_is_row) = numeric_or_complex_set_vector(denominator, "tf2zp")?;
    let numerator = complex_polynomial_compact_coefficients(&numerator);
    let denominator = complex_polynomial_compact_coefficients(&denominator);
    if denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(
            "tf2zp currently expects a nonzero denominator polynomial".to_string(),
        ));
    }

    let zeros = complex_polynomial_roots(&numerator);
    let poles = complex_polynomial_roots(&denominator);
    let gain = normalize_complex_parts(numerator[0].rdivide(denominator[0]));
    let mut outputs = vec![complex_roots_column_output(zeros)?];
    if output_arity >= 2 {
        outputs.push(complex_roots_column_output(poles)?);
    }
    if output_arity >= 3 {
        outputs.push(numeric_or_complex_value(gain));
    }
    Ok(outputs)
}

fn builtin_zp2tf(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "zp2tf currently supports one or two outputs".to_string(),
        ));
    }
    let [zeros, poles, gain] = args else {
        return Err(RuntimeError::Unsupported(
            "zp2tf currently supports zp2tf(z, p, k)".to_string(),
        ));
    };

    let zeros = numeric_or_complex_vector_allow_empty(zeros, "zp2tf")?;
    let poles = numeric_or_complex_vector_allow_empty(poles, "zp2tf")?;
    let gain = numeric_or_complex_scalar(gain, "zp2tf")?;
    let numerator = complex_polynomial_coefficients_from_roots(&zeros)
        .into_iter()
        .map(|coefficient| normalize_complex_parts(coefficient.times(gain)))
        .collect::<Vec<_>>();
    let denominator = complex_polynomial_coefficients_from_roots(&poles);
    let mut outputs = vec![complex_polynomial_degree_preserving_output(numerator)?];
    if output_arity >= 2 {
        outputs.push(complex_polynomial_degree_preserving_output(denominator)?);
    }
    Ok(outputs)
}

fn builtin_tf2sos(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "tf2sos currently supports one or two outputs".to_string(),
        ));
    }
    let [numerator, denominator] = args else {
        return Err(RuntimeError::Unsupported(
            "tf2sos currently supports tf2sos(b, a)".to_string(),
        ));
    };
    let (zeros, poles, gain) = zpk_from_transfer_function_values(numerator, denominator, "tf2sos")?;
    zp2sos_outputs(zeros, poles, gain, output_arity)
}

fn builtin_zp2ctf(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "zp2ctf currently supports one, two, or three outputs".to_string(),
        ));
    }
    let (zeros, poles, gain) = match args {
        [zeros, poles] => (
            numeric_or_complex_vector_allow_empty(zeros, "zp2ctf")?,
            numeric_or_complex_vector_allow_empty(poles, "zp2ctf")?,
            ComplexParts::one(),
        ),
        [zeros, poles, gain] => (
            numeric_or_complex_vector_allow_empty(zeros, "zp2ctf")?,
            numeric_or_complex_vector_allow_empty(poles, "zp2ctf")?,
            numeric_or_complex_scalar(gain, "zp2ctf")?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "zp2ctf currently supports zp2ctf(z, p) and zp2ctf(z, p, k)".to_string(),
            ))
        }
    };

    let mut sections = zp2ctf_sections_from_roots(&zeros, &poles);
    if output_arity < 3 {
        if gain.imag.abs() > 1e-12 && !gain.imag.is_nan() {
            return Err(RuntimeError::Unsupported(
                "zp2ctf currently expects a real gain scalar when distributing gain across sections"
                    .to_string(),
            ));
        }
        let section_scales = uniformly_distributed_section_gain(gain.real, sections.len());
        for (section, scale) in sections.iter_mut().zip(section_scales) {
            for coefficient in &mut section.numerator {
                *coefficient = normalize_complex_parts(coefficient.scale(scale));
            }
        }
    }

    let rows = sections.len().max(1);
    let mut numerator = Vec::with_capacity(rows * 3);
    let mut denominator = Vec::with_capacity(rows * 3);
    if sections.is_empty() {
        numerator.extend_from_slice(&[gain, ComplexParts::zero(), ComplexParts::zero()]);
        denominator.extend_from_slice(&[
            ComplexParts::one(),
            ComplexParts::zero(),
            ComplexParts::zero(),
        ]);
    } else {
        for section in &sections {
            numerator.extend_from_slice(&section.numerator);
            denominator.extend_from_slice(&section.denominator);
        }
    }

    let b = build_numeric_or_complex_matrix_result(rows, 3, numerator)?;
    match output_arity {
        1 => Ok(vec![b]),
        2 => Ok(vec![
            b,
            build_numeric_or_complex_matrix_result(rows, 3, denominator)?,
        ]),
        3 => Ok(vec![
            b,
            build_numeric_or_complex_matrix_result(rows, 3, denominator)?,
            numeric_or_complex_value(gain),
        ]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_zp2sos(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "zp2sos currently supports one or two outputs".to_string(),
        ));
    }
    let (zeros, poles, gain) = match args {
        [zeros, poles] => (
            numeric_or_complex_vector_allow_empty(zeros, "zp2sos")?,
            numeric_or_complex_vector_allow_empty(poles, "zp2sos")?,
            ComplexParts::one(),
        ),
        [zeros, poles, gain] => (
            numeric_or_complex_vector_allow_empty(zeros, "zp2sos")?,
            numeric_or_complex_vector_allow_empty(poles, "zp2sos")?,
            numeric_or_complex_scalar(gain, "zp2sos")?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "zp2sos currently supports zp2sos(z, p) and zp2sos(z, p, k)".to_string(),
            ))
        }
    };
    zp2sos_outputs(zeros, poles, gain, output_arity)
}

fn builtin_ctf2zp(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "ctf2zp currently supports one, two, or three outputs".to_string(),
        ));
    }
    let sections = match args {
        [numerators, denominators] => parse_ctf_sections(numerators, denominators, None, "ctf2zp")?,
        [numerators, denominators, gain] => {
            parse_ctf_sections(numerators, denominators, Some(gain), "ctf2zp")?
        }
        _ => {
            return Err(RuntimeError::Unsupported(
                "ctf2zp currently supports ctf2zp(B, A) and ctf2zp(B, A, g)".to_string(),
            ))
        }
    };

    let (numerator, denominator) = equivalent_filter_sections_transfer_function(&sections);
    let zeros = complex_polynomial_roots(&numerator);
    let poles = complex_polynomial_roots(&denominator);
    let gain = if denominator.is_empty() || denominator[0].is_approximately_zero() {
        ComplexParts::zero()
    } else {
        normalize_complex_parts(numerator[0].rdivide(denominator[0]))
    };

    let mut outputs = vec![complex_roots_column_output(zeros)?];
    if output_arity >= 2 {
        outputs.push(complex_roots_column_output(poles)?);
    }
    if output_arity >= 3 {
        outputs.push(numeric_or_complex_value(gain));
    }
    Ok(outputs)
}

fn builtin_ss2tf(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "ss2tf currently supports one or two outputs".to_string(),
        ));
    }
    let (a, b, c, d, input_index) = match args {
        [a, b, c, d] => (a, b, c, d, 0usize),
        [a, b, c, d, ni] => (
            a,
            b,
            c,
            d,
            positive_integer_scalar_with_label(ni, "ss2tf", "a positive input index")?
                .saturating_sub(1),
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "ss2tf currently supports ss2tf(A, B, C, D) and ss2tf(A, B, C, D, ni)".to_string(),
            ))
        }
    };

    let a = numeric_or_complex_operand(a, "ss2tf")?;
    let b = numeric_or_complex_operand(b, "ss2tf")?;
    let c = numeric_or_complex_operand(c, "ss2tf")?;
    let d = numeric_or_complex_operand(d, "ss2tf")?;

    if a.rows != a.cols {
        return Err(RuntimeError::ShapeError(
            "ss2tf currently expects A to be square".to_string(),
        ));
    }
    if b.rows != a.rows {
        return Err(RuntimeError::ShapeError(format!(
            "ss2tf currently expects B to have {} rows, found {}",
            a.rows, b.rows
        )));
    }
    if c.cols != a.cols {
        return Err(RuntimeError::ShapeError(format!(
            "ss2tf currently expects C to have {} columns, found {}",
            a.cols, c.cols
        )));
    }
    if d.rows != c.rows || d.cols != b.cols {
        return Err(RuntimeError::ShapeError(format!(
            "ss2tf currently expects D to be {}x{}, found {}x{}",
            c.rows, b.cols, d.rows, d.cols
        )));
    }
    if input_index >= b.cols {
        return Err(RuntimeError::ShapeError(format!(
            "ss2tf currently expects ni to be between 1 and {}, found {}",
            b.cols,
            input_index + 1
        )));
    }

    let denominator = complex_characteristic_polynomial_coefficients(&a)?;
    let state_count = a.rows;
    let output_count = c.rows;
    let b_column = operand_column_values(&b, input_index);
    let d_column = operand_column_values(&d, input_index);

    let mut markov = Vec::with_capacity(state_count);
    let mut state = b_column.clone();
    for _ in 0..state_count {
        markov.push(matrix_vector_product(&c, &state));
        state = matrix_vector_product(&a, &state);
    }

    let mut numerator = vec![ComplexParts::zero(); output_count * (state_count + 1)];
    for row in 0..output_count {
        numerator[row * (state_count + 1)] = normalize_complex_parts(d_column[row]);
    }
    for degree in 1..=state_count {
        for row in 0..output_count {
            let mut total = markov[degree - 1][row];
            for coefficient_index in 1..degree {
                total = total.plus(
                    denominator[coefficient_index]
                        .times(markov[degree - 1 - coefficient_index][row]),
                );
            }
            total = total.plus(denominator[degree].times(d_column[row]));
            numerator[row * (state_count + 1) + degree] = normalize_complex_parts(total);
        }
    }

    let mut outputs = vec![build_numeric_or_complex_matrix_result(
        output_count,
        state_count + 1,
        numerator,
    )?];
    if output_arity >= 2 {
        outputs.push(complex_polynomial_degree_preserving_output(denominator)?);
    }
    Ok(outputs)
}

fn builtin_ss2sos(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 2 {
        return Err(RuntimeError::Unsupported(
            "ss2sos currently supports one or two outputs".to_string(),
        ));
    }
    let (tf_args, order) = parse_ss2sos_args(args)?;
    let c = numeric_or_complex_operand(&tf_args[2], "ss2sos")?;
    if c.rows != 1 {
        return Err(RuntimeError::Unsupported(
            "ss2sos currently supports single-output state-space systems".to_string(),
        ));
    }
    let d = numeric_or_complex_operand(&tf_args[3], "ss2sos")?;
    if d.rows != 1 {
        return Err(RuntimeError::Unsupported(
            "ss2sos currently supports single-output state-space systems".to_string(),
        ));
    }
    let tf = builtin_ss2tf(&tf_args, 2)?;
    let outputs = builtin_tf2sos(&tf, 2)?;
    let (sos_rows, gain) = match outputs.as_slice() {
        [sos, gain] => (reordered_ss2sos_value(sos, order, "ss2sos")?, gain.clone()),
        _ => unreachable!("tf2sos returned unexpected arity"),
    };
    if output_arity == 1 {
        let gain_value = numeric_or_complex_scalar(&gain, "ss2sos")?;
        return Ok(vec![embed_sos_gain_in_first_section(
            sos_rows, gain_value, "ss2sos",
        )?]);
    }
    Ok(vec![sos_rows, gain])
}

fn builtin_ss2zp(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 3 {
        return Err(RuntimeError::Unsupported(
            "ss2zp currently supports one, two, or three outputs".to_string(),
        ));
    }
    let tf = builtin_ss2tf(args, 2)?;
    let (numerator_rows, denominator) = normalized_transfer_function_rows(&tf[0], &tf[1], "ss2zp")?;
    let poles = complex_polynomial_roots(&denominator);
    let output_count = numerator_rows.len();
    let zero_count = denominator.len().saturating_sub(1);
    let mut zeros_matrix = vec![
        ComplexParts {
            real: f64::INFINITY,
            imag: 0.0
        };
        zero_count * output_count
    ];
    let mut gains = Vec::with_capacity(output_count);
    for (column, row) in numerator_rows.iter().enumerate() {
        let compact_row = complex_polynomial_compact_coefficients(row);
        let zeros = complex_polynomial_roots(&compact_row);
        for (row_index, zero) in zeros.into_iter().enumerate() {
            zeros_matrix[row_index * output_count + column] = zero;
        }
        gains.push(numeric_or_complex_value(
            compact_row
                .first()
                .copied()
                .unwrap_or_else(ComplexParts::zero),
        ));
    }

    let mut outputs = vec![build_numeric_or_complex_matrix_result(
        zero_count,
        output_count,
        zeros_matrix,
    )?];
    if output_arity >= 2 {
        outputs.push(complex_roots_column_output(poles)?);
    }
    if output_arity >= 3 {
        outputs.push(if output_count == 1 {
            gains.into_iter().next().expect("single ss2zp gain")
        } else {
            Value::Matrix(MatrixValue::new(output_count, 1, gains)?)
        });
    }
    Ok(outputs)
}

fn parse_ss2sos_args(args: &[Value]) -> Result<(Vec<Value>, Ss2SosOrder), RuntimeError> {
    let (a, b, c, d, input_index, order, scale) = match args {
        [a, b, c, d] => (a, b, c, d, None, Ss2SosOrder::Up, None),
        [a, b, c, d, fifth] => {
            if let Ok(order) = parse_ss2sos_order(fifth) {
                (a, b, c, d, None, order, None)
            } else {
                (
                    a,
                    b,
                    c,
                    d,
                    Some(positive_integer_scalar_with_label(
                        fifth,
                        "ss2sos",
                        "a positive input index",
                    )?),
                    Ss2SosOrder::Up,
                    None,
                )
            }
        }
        [a, b, c, d, fifth, sixth] => {
            if let Ok(order) = parse_ss2sos_order(fifth) {
                (a, b, c, d, None, order, Some(sixth))
            } else {
                (
                    a,
                    b,
                    c,
                    d,
                    Some(positive_integer_scalar_with_label(
                        fifth,
                        "ss2sos",
                        "a positive input index",
                    )?),
                    parse_ss2sos_order(sixth)?,
                    None,
                )
            }
        }
        [a, b, c, d, fifth, sixth, seventh] => (
            a,
            b,
            c,
            d,
            Some(positive_integer_scalar_with_label(
                fifth,
                "ss2sos",
                "a positive input index",
            )?),
            parse_ss2sos_order(sixth)?,
            Some(seventh),
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "ss2sos currently supports ss2sos(A, B, C, D), ss2sos(A, B, C, D, order), ss2sos(A, B, C, D, iu), ss2sos(A, B, C, D, iu, order), and ss2sos(A, B, C, D, iu, order, scale)"
                    .to_string(),
            ))
        }
    };

    if let Some(scale) = scale {
        parse_ss2sos_scale(scale)?;
    }

    let mut tf_args = vec![a.clone(), b.clone(), c.clone(), d.clone()];
    if let Some(input_index) = input_index {
        tf_args.push(Value::Scalar(input_index as f64));
    }
    Ok((tf_args, order))
}

fn parse_ss2sos_order(value: &Value) -> Result<Ss2SosOrder, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "up" => Ok(Ss2SosOrder::Up),
        "down" => Ok(Ss2SosOrder::Down),
        other => Err(RuntimeError::Unsupported(format!(
            "ss2sos currently expects order to be \"up\" or \"down\", found `{other}`"
        ))),
    }
}

fn parse_ss2sos_scale(value: &Value) -> Result<(), RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "none" => Ok(()),
        other => Err(RuntimeError::Unsupported(format!(
            "ss2sos currently supports only scale=\"none\", found `{other}`"
        ))),
    }
}

fn reordered_ss2sos_value(
    sos: &Value,
    order: Ss2SosOrder,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let operand = numeric_or_complex_operand(sos, builtin_name)?;
    if operand.rows == 0 || operand.cols != 6 {
        return Ok(sos.clone());
    }
    let mut rows = (0..operand.rows)
        .map(|row| {
            let start = row * operand.cols;
            let values = operand.values[start..start + operand.cols].to_vec();
            let closeness = ss2sos_section_closeness(&values);
            (row, closeness, values)
        })
        .collect::<Vec<_>>();
    rows.sort_by(|lhs, rhs| {
        let order_cmp = match order {
            Ss2SosOrder::Up => rhs.1.total_cmp(&lhs.1),
            Ss2SosOrder::Down => lhs.1.total_cmp(&rhs.1),
        };
        order_cmp.then_with(|| lhs.0.cmp(&rhs.0))
    });
    let values = rows
        .into_iter()
        .flat_map(|(_, _, values)| values)
        .collect::<Vec<_>>();
    build_numeric_or_complex_matrix_result(operand.rows, operand.cols, values)
}

fn ss2sos_section_closeness(section: &[ComplexParts]) -> f64 {
    let poles = complex_polynomial_roots(&section[3..6]);
    if poles.is_empty() {
        return f64::INFINITY;
    }
    poles
        .into_iter()
        .map(|pole| (pole.magnitude() - 1.0).abs())
        .fold(f64::INFINITY, f64::min)
}

fn embed_sos_gain_in_first_section(
    sos: Value,
    gain: ComplexParts,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    let mut operand = numeric_or_complex_operand(&sos, builtin_name)?;
    if operand.rows == 0 {
        return Ok(sos);
    }
    for coefficient in &mut operand.values[..3] {
        *coefficient = normalize_complex_parts(coefficient.times(gain));
    }
    numeric_or_complex_operand_to_value(&operand)
}

fn zpk_from_transfer_function_values(
    numerator: &Value,
    denominator: &Value,
    builtin_name: &str,
) -> Result<(Vec<ComplexParts>, Vec<ComplexParts>, ComplexParts), RuntimeError> {
    let (numerator, _numerator_is_row) = numeric_or_complex_set_vector(numerator, builtin_name)?;
    let (denominator, _denominator_is_row) =
        numeric_or_complex_set_vector(denominator, builtin_name)?;
    let numerator = complex_polynomial_compact_coefficients(&numerator);
    let denominator = complex_polynomial_compact_coefficients(&denominator);
    if denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a nonzero denominator polynomial"
        )));
    }
    Ok((
        complex_polynomial_roots(&numerator),
        complex_polynomial_roots(&denominator),
        normalize_complex_parts(numerator[0].rdivide(denominator[0])),
    ))
}

fn normalized_transfer_function_rows(
    numerator: &Value,
    denominator: &Value,
    builtin_name: &str,
) -> Result<(Vec<Vec<ComplexParts>>, Vec<ComplexParts>), RuntimeError> {
    let mut denominator = complex_polynomial_compact_coefficients(
        &numeric_or_complex_vector_allow_empty(denominator, builtin_name)?,
    );
    if denominator.is_empty() || denominator[0].is_approximately_zero() {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a nonzero denominator polynomial"
        )));
    }
    let leading = denominator[0];
    denominator = denominator
        .into_iter()
        .map(|value| normalize_complex_parts(value.rdivide(leading)))
        .collect::<Vec<_>>();

    let mut numerator_rows = Vec::new();
    for row in transfer_function_numerator_rows(numerator, builtin_name)? {
        let row = complex_polynomial_compact_coefficients(&row);
        if row.len() > denominator.len() {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports proper transfer functions with numerator length at most the denominator length"
            )));
        }

        let mut padded = vec![ComplexParts::zero(); denominator.len() - row.len()];
        padded.extend(
            row.into_iter()
                .map(|value| normalize_complex_parts(value.rdivide(leading))),
        );
        numerator_rows.push(padded);
    }
    Ok((numerator_rows, denominator))
}

fn transfer_function_numerator_rows(
    value: &Value,
    builtin_name: &str,
) -> Result<Vec<Vec<ComplexParts>>, RuntimeError> {
    let operand = numeric_or_complex_operand(value, builtin_name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(vec![vec![ComplexParts::zero()]]);
    }
    if operand.rows == 1 || operand.cols == 1 {
        return Ok(vec![operand.values]);
    }

    let mut rows = Vec::with_capacity(operand.rows);
    for row in 0..operand.rows {
        let start = row * operand.cols;
        rows.push(operand.values[start..start + operand.cols].to_vec());
    }
    Ok(rows)
}

fn operand_column_values(operand: &NumericOrComplexOperand, column: usize) -> Vec<ComplexParts> {
    (0..operand.rows)
        .map(|row| operand.values[row * operand.cols + column])
        .collect()
}

fn matrix_vector_product(
    matrix: &NumericOrComplexOperand,
    vector: &[ComplexParts],
) -> Vec<ComplexParts> {
    let mut values = Vec::with_capacity(matrix.rows);
    for row in 0..matrix.rows {
        let mut total = ComplexParts::zero();
        for col in 0..matrix.cols {
            total = total.plus(matrix.values[row * matrix.cols + col].times(vector[col]));
        }
        values.push(normalize_complex_parts(total));
    }
    values
}

fn builtin_zp2ss(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    if output_arity == 0 || output_arity > 4 {
        return Err(RuntimeError::Unsupported(
            "zp2ss currently supports one to four outputs".to_string(),
        ));
    }
    let [zeros, poles, gains] = args else {
        return Err(RuntimeError::Unsupported(
            "zp2ss currently supports zp2ss(z, p, k)".to_string(),
        ));
    };
    let poles = numeric_or_complex_vector_allow_empty(poles, "zp2ss")?;
    let output_count = zp2ss_zero_output_count(zeros);
    let gains = parse_zp2ss_gains(gains, output_count, "zp2ss")?;
    let zeros_by_output = parse_zp2ss_zero_columns(zeros, gains.len(), "zp2ss")?;
    if zeros_by_output.len() != gains.len() {
        return Err(RuntimeError::ShapeError(format!(
            "zp2ss currently expects z and k to describe the same number of outputs, found {} and {}",
            zeros_by_output.len(),
            gains.len()
        )));
    }

    let degree = poles.len() + 1;
    let mut numerator_rows = Vec::with_capacity(zeros_by_output.len() * degree.max(1));
    for (zeros, gain) in zeros_by_output.iter().zip(gains.iter().copied()) {
        if zeros.len() > poles.len() {
            return Err(RuntimeError::Unsupported(
                "zp2ss currently supports proper transfer functions with at most as many zeros as poles"
                    .to_string(),
            ));
        }
        let coefficients = complex_polynomial_coefficients_from_roots(zeros)
            .into_iter()
            .map(|coefficient| normalize_complex_parts(coefficient.times(gain)))
            .collect::<Vec<_>>();
        let mut row = vec![ComplexParts::zero(); degree.saturating_sub(coefficients.len())];
        row.extend(coefficients);
        numerator_rows.extend(row);
    }

    let numerator =
        build_numeric_or_complex_matrix_result(zeros_by_output.len(), degree, numerator_rows)?;
    let denominator = complex_polynomial_degree_preserving_output(
        complex_polynomial_coefficients_from_roots(&poles),
    )?;
    let tf = vec![numerator, denominator];
    builtin_tf2ss(&tf, output_arity)
}

fn zp2ss_zero_output_count(zeros: &Value) -> usize {
    match zeros {
        Value::Matrix(matrix) if matrix.rows > 1 && matrix.cols > 1 => matrix.cols,
        Value::Matrix(matrix) if matrix.rows == 0 => matrix.cols.max(1),
        _ => 1,
    }
}

fn parse_zp2ss_gains(
    value: &Value,
    output_count: usize,
    builtin_name: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let (values, _is_row) = numeric_or_complex_set_vector(value, builtin_name)?;
    if values.iter().any(|value| !complex_parts_are_finite(*value)) {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects finite gain values"
        )));
    }
    if output_count == 1 {
        if values.len() != 1 {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently expects a scalar gain for single-output zero inputs"
            )));
        }
        return Ok(values);
    }
    if values.len() != output_count {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects {output_count} gain values, found {}",
            values.len()
        )));
    }
    Ok(values)
}

fn parse_zp2ss_zero_columns(
    value: &Value,
    output_count: usize,
    builtin_name: &str,
) -> Result<Vec<Vec<ComplexParts>>, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => {
            let zero = numeric_or_complex_scalar(value, builtin_name)?;
            Ok(vec![if complex_parts_is_infinite_placeholder(zero) {
                Vec::new()
            } else if complex_parts_are_finite(zero) {
                vec![zero]
            } else {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects z entries to be finite values or Inf placeholders"
                )));
            }])
        }
        Value::Matrix(matrix) => {
            if !matrix_is_numeric_or_complex(matrix) {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects numeric or complex zero locations"
                )));
            }
            if matrix.rows == 0 || matrix.cols == 0 {
                return Ok(vec![Vec::new(); output_count.max(matrix.cols.max(1))]);
            }
            if matrix.rows == 1 || matrix.cols == 1 {
                let mut values = Vec::new();
                for element in matrix.iter() {
                    let value = numeric_or_complex_scalar(element, builtin_name)?;
                    if complex_parts_is_infinite_placeholder(value) {
                        continue;
                    }
                    if !complex_parts_are_finite(value) {
                        return Err(RuntimeError::TypeError(format!(
                            "{builtin_name} currently expects z entries to be finite values or Inf placeholders"
                        )));
                    }
                    values.push(value);
                }
                return Ok(vec![values]);
            }
            if matrix.cols != output_count {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} currently expects z to have {output_count} columns, found {}",
                    matrix.cols
                )));
            }
            let mut columns = vec![Vec::new(); matrix.cols];
            for row in 0..matrix.rows {
                for (col, values) in columns.iter_mut().enumerate() {
                    let value = numeric_or_complex_scalar(matrix.get(row, col), builtin_name)?;
                    if complex_parts_is_infinite_placeholder(value) {
                        continue;
                    }
                    if !complex_parts_are_finite(value) {
                        return Err(RuntimeError::TypeError(format!(
                            "{builtin_name} currently expects z entries to be finite values or Inf placeholders"
                        )));
                    }
                    values.push(value);
                }
            }
            Ok(columns)
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or complex scalar/vector/matrix zero inputs"
        ))),
    }
}

fn complex_parts_are_finite(value: ComplexParts) -> bool {
    value.real.is_finite() && value.imag.is_finite()
}

fn complex_parts_is_infinite_placeholder(value: ComplexParts) -> bool {
    value.imag == 0.0 && value.real.is_infinite()
}

fn zp2sos_outputs(
    zeros: Vec<ComplexParts>,
    poles: Vec<ComplexParts>,
    gain: ComplexParts,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let mut sections = zp2ctf_sections_from_roots(&zeros, &poles);
    if sections.is_empty() {
        sections.push(FiltfiltSection {
            numerator: vec![
                ComplexParts::one(),
                ComplexParts::zero(),
                ComplexParts::zero(),
            ],
            denominator: vec![
                ComplexParts::one(),
                ComplexParts::zero(),
                ComplexParts::zero(),
            ],
        });
    }
    if output_arity == 1 {
        for coefficient in &mut sections[0].numerator {
            *coefficient = normalize_complex_parts(coefficient.times(gain));
        }
    }
    let mut sos_values = Vec::with_capacity(sections.len() * 6);
    for section in &sections {
        sos_values.extend_from_slice(&section.numerator[..3]);
        sos_values.extend_from_slice(&section.denominator[..3]);
    }
    let sos = build_numeric_or_complex_matrix_result(sections.len(), 6, sos_values)?;
    match output_arity {
        1 => Ok(vec![sos]),
        2 => Ok(vec![sos, numeric_or_complex_value(gain)]),
        _ => unreachable!("checked output arity above"),
    }
}

fn builtin_polyfit(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let [x, y, degree] = args else {
        return Err(RuntimeError::Unsupported(
            "polyfit currently supports exactly three inputs".to_string(),
        ));
    };

    let (x, _x_is_row, _x_is_logical) = numeric_set_vector(x, "polyfit")?;
    let (y, _y_is_row) = numeric_or_complex_set_vector(y, "polyfit")?;
    if x.len() != y.len() {
        return Err(RuntimeError::ShapeError(
            "polyfit requires x and y to have the same number of elements".to_string(),
        ));
    }
    if x.is_empty() {
        return Err(RuntimeError::ShapeError(
            "polyfit currently expects at least one sample point".to_string(),
        ));
    }

    let degree = nonnegative_integer_scalar_with_label(
        degree,
        "polyfit",
        "a nonnegative integer degree scalar",
    )?;
    if x.len() < degree + 1 {
        return Err(RuntimeError::ShapeError(format!(
            "polyfit requires at least {} sample points for degree {}",
            degree + 1,
            degree
        )));
    }

    match output_arity {
        0 | 1 => {
            let fit = polynomial_least_squares_fit(&x, &y, degree)?;
            Ok(vec![complex_polynomial_degree_preserving_output(
                fit.coefficients,
            )?])
        }
        2 => {
            let fit = polynomial_least_squares_fit(&x, &y, degree)?;
            let summary = polynomial_fit_summary_output(&fit)?;
            Ok(vec![
                complex_polynomial_degree_preserving_output(fit.coefficients)?,
                summary,
            ])
        }
        3 => {
            let mean = x.iter().sum::<f64>() / x.len() as f64;
            let std = sample_variance(&x).sqrt();
            if approx_equal(std, 0.0) {
                return Err(RuntimeError::Unsupported(
                    "polyfit with three outputs currently requires x to have nonzero sample standard deviation"
                        .to_string(),
                ));
            }
            let scaled_x = x
                .iter()
                .map(|value| (*value - mean) / std)
                .collect::<Vec<_>>();
            let fit = polynomial_least_squares_fit(&scaled_x, &y, degree)?;
            let summary = polynomial_fit_summary_output(&fit)?;
            Ok(vec![
                complex_polynomial_degree_preserving_output(fit.coefficients)?,
                summary,
                numeric_values_to_row_matrix(vec![
                    normalize_polynomial_scalar(mean),
                    normalize_polynomial_scalar(std),
                ])?,
            ])
        }
        _ => Err(RuntimeError::Unsupported(
            "polyfit currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn builtin_polyder(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match args {
        [p] => {
            let (coefficients, _is_row) = numeric_or_complex_set_vector(p, "polyder")?;
            let derivative = complex_polynomial_derivative_coefficients(&coefficients);
            let value = complex_polynomial_coefficient_output(derivative)?;
            match output_arity {
                0 | 1 => Ok(vec![value]),
                _ => Err(RuntimeError::Unsupported(
                    "polyder(p) currently supports one output".to_string(),
                )),
            }
        }
        [a, b] => {
            let (a, _a_is_row) = numeric_or_complex_set_vector(a, "polyder")?;
            let (b, _b_is_row) = numeric_or_complex_set_vector(b, "polyder")?;
            let da = complex_polynomial_derivative_coefficients(&a);
            let db = complex_polynomial_derivative_coefficients(&b);
            match output_arity {
                0 | 1 => {
                    let product = complex_polynomial_compact_coefficients(
                        &full_complex_convolution_vector(&da, &b),
                    );
                    let other = complex_polynomial_compact_coefficients(
                        &full_complex_convolution_vector(&a, &db),
                    );
                    let derivative = complex_polynomial_compact_coefficients(
                        &complex_polynomial_add(&product, &other),
                    );
                    Ok(vec![complex_polynomial_coefficient_output(derivative)?])
                }
                2 => {
                    let numerator_left = full_complex_convolution_vector(&da, &b);
                    let numerator_right = full_complex_convolution_vector(&a, &db);
                    let numerator = complex_polynomial_compact_coefficients(&complex_polynomial_subtract(
                        &numerator_left,
                        &numerator_right,
                    ));
                    let denominator = complex_polynomial_compact_coefficients(
                        &full_complex_convolution_vector(&b, &b),
                    );
                    Ok(vec![
                        complex_polynomial_coefficient_output(numerator)?,
                        complex_polynomial_coefficient_output(denominator)?,
                    ])
                }
                _ => Err(RuntimeError::Unsupported(
                    "polyder(a, b) currently supports one output for product derivatives or two outputs for quotient derivatives".to_string(),
                )),
            }
        }
        _ => Err(RuntimeError::Unsupported(
            "polyder currently supports `polyder(p)` or `polyder(a, b)`".to_string(),
        )),
    }
}

fn builtin_polyint(args: &[Value]) -> Result<Value, RuntimeError> {
    let (coefficients, constant) = match args {
        [p] => (p, ComplexParts::zero()),
        [p, k] => (p, numeric_or_complex_scalar(k, "polyint")?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "polyint currently supports `polyint(p)` or `polyint(p, k)`".to_string(),
            ))
        }
    };

    let (coefficients, _is_row) = numeric_or_complex_set_vector(coefficients, "polyint")?;
    let coefficients = complex_polynomial_compact_coefficients(&coefficients);
    let degree = coefficients.len();
    let mut integral = Vec::with_capacity(degree + 1);
    for (index, coefficient) in coefficients.iter().copied().enumerate() {
        integral.push(coefficient.scale(1.0 / (degree - index) as f64));
    }
    integral.push(constant);
    complex_polynomial_coefficient_output(integral)
}

fn builtin_polyval(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (coefficients, x, _error_estimate, mu) = match args {
        [coefficients, x] => (coefficients, x, None, None),
        [coefficients, x, error_estimate] => (coefficients, x, Some(error_estimate), None),
        [coefficients, x, error_estimate, mu] => (coefficients, x, Some(error_estimate), Some(mu)),
        _ => {
            return Err(RuntimeError::Unsupported(
                "polyval currently supports `polyval(p, x)`, `polyval(p, x, s)`, or `polyval(p, x, s, mu)`"
                    .to_string(),
            ))
        }
    };

    let (coefficients, _coefficients_are_row) =
        numeric_or_complex_set_vector(coefficients, "polyval")?;
    if coefficients.is_empty() {
        return Err(RuntimeError::ShapeError(
            "polyval currently expects a nonempty coefficient vector".to_string(),
        ));
    }

    if output_arity <= 1 {
        if let Some(error_estimate) = _error_estimate {
            match error_estimate {
                Value::Struct(_) => {}
                Value::Matrix(matrix) if matrix.rows == 0 && matrix.cols == 0 => {}
                _ => {
                    return Err(RuntimeError::TypeError(
                        "polyval currently expects the third input to be a struct or []"
                            .to_string(),
                    ))
                }
            }
        }
    }
    let error_estimate = match _error_estimate {
        Some(error_estimate) if output_arity >= 2 => parse_polyval_error_summary(error_estimate)?,
        _ => None,
    };

    let x = numeric_or_complex_operand(x, "polyval")?;
    let scaled_points = match mu {
        Some(mu) => {
            let (mu, _is_row, _is_logical) = numeric_set_vector(mu, "polyval")?;
            if mu.len() != 2 {
                return Err(RuntimeError::TypeError(
                    "polyval currently expects mu to be a two-element numeric vector".to_string(),
                ));
            }
            if approx_equal(mu[1], 0.0) {
                return Err(RuntimeError::TypeError(
                    "polyval currently expects mu(2) to be nonzero".to_string(),
                ));
            }
            x.values
                .iter()
                .map(|point| {
                    point
                        .minus(ComplexParts {
                            real: mu[0],
                            imag: 0.0,
                        })
                        .scale(1.0 / mu[1])
                })
                .collect::<Vec<_>>()
        }
        None => x.values.clone(),
    };
    let values = scaled_points
        .iter()
        .map(|point| evaluate_complex_polynomial(coefficients.as_slice(), *point))
        .collect::<Vec<_>>();
    let y = build_numeric_or_complex_matrix_result(x.rows, x.cols, values)?;

    match output_arity {
        0 | 1 => Ok(vec![y]),
        2 => {
            let Some(error_estimate) = error_estimate else {
                return Err(RuntimeError::Unsupported(
                    "polyval currently requires a fitted `S` struct as the third input when requesting two outputs"
                        .to_string(),
                ));
            };
            let delta = polynomial_error_bounds(
                &error_estimate,
                &scaled_points
                    .iter()
                    .map(|value| value.real)
                    .collect::<Vec<_>>(),
                coefficients.len().saturating_sub(1),
            )?;
            Ok(vec![
                y,
                build_scalar_matrix_result(
                    x.rows,
                    x.cols,
                    delta.into_iter().map(Value::Scalar).collect::<Vec<_>>(),
                )?,
            ])
        }
        _ => Err(RuntimeError::Unsupported(
            "polyval currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_polyvalm(args: &[Value]) -> Result<Value, RuntimeError> {
    let [coefficients, x] = args else {
        return Err(RuntimeError::Unsupported(
            "polyvalm currently supports exactly two inputs".to_string(),
        ));
    };

    let (coefficients, _coefficients_are_row) =
        numeric_or_complex_set_vector(coefficients, "polyvalm")?;
    if coefficients.is_empty() {
        return Err(RuntimeError::ShapeError(
            "polyvalm currently expects a nonempty coefficient vector".to_string(),
        ));
    }

    let matrix = numeric_or_complex_operand(x, "polyvalm")?;
    if matrix.rows != matrix.cols {
        return Err(RuntimeError::ShapeError(
            "polyvalm currently expects a square numeric or complex matrix input".to_string(),
        ));
    }

    let result = evaluate_complex_matrix_polynomial(coefficients.as_slice(), &matrix, "polyvalm")?;
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_del2(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, ..] = args else {
        return Err(RuntimeError::Unsupported(
            "del2 currently supports vector or matrix inputs".to_string(),
        ));
    };

    let operand = numeric_operand(value, "del2")?;
    if operand.rows == 1 || operand.cols == 1 {
        let spacing = parse_del2_vector_spacing(args)?;
        let values = del2_vector_values(&operand.values, spacing);
        return build_scalar_matrix_result(
            operand.rows,
            operand.cols,
            values.into_iter().map(Value::Scalar).collect::<Vec<_>>(),
        );
    }

    let (x_spacing, y_spacing) = parse_del2_matrix_spacing(args)?;
    let result = del2_matrix_result(&operand, x_spacing, y_spacing);
    build_scalar_matrix_result(
        result.rows,
        result.cols,
        result
            .values
            .into_iter()
            .map(Value::Scalar)
            .collect::<Vec<_>>(),
    )
}

fn builtin_divergence(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, y, u, v) = parse_divergence_args(args)?;
    let (x, y, u, v) = normalized_divergence_axes(x, y, u, v)?;
    let du_dx = derivative_along_x(&u, &x);
    let dv_dy = derivative_along_y(&v, &y);
    let values = du_dx
        .values
        .into_iter()
        .zip(dv_dy.values)
        .map(|(du_dx, dv_dy)| Value::Scalar(du_dx + dv_dy))
        .collect::<Vec<_>>();
    build_scalar_matrix_result(u.rows, u.cols, values)
}

fn builtin_curl(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, y, u, v) = parse_divergence_args(args)?;
    let (x, y, u, v) = normalized_divergence_axes(x, y, u, v)?;
    let dv_dx = derivative_along_x(&v, &x);
    let du_dy = derivative_along_y(&u, &y);
    let values = dv_dx
        .values
        .into_iter()
        .zip(du_dy.values)
        .map(|(dv_dx, du_dy)| Value::Scalar(dv_dx - du_dy))
        .collect::<Vec<_>>();
    build_scalar_matrix_result(u.rows, u.cols, values)
}

fn builtin_gradient(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let [value, ..] = args else {
        return Err(RuntimeError::Unsupported(
            "gradient currently supports vector or matrix inputs".to_string(),
        ));
    };

    let input_dims = canonical_size_vector(&value_dimensions(value));
    let operand = numeric_operand(value, "gradient")?;
    let component_dims = gradient_component_dimensions(&input_dims);
    if operand.values.is_empty() {
        return gradient_empty_outputs(&input_dims, component_dims.len(), output_arity);
    }

    if component_dims.len() <= 1 {
        if output_arity > 1 {
            return Err(RuntimeError::Unsupported(
                "gradient currently supports only one output for vector inputs".to_string(),
            ));
        }

        let positions = parse_gradient_vector_positions(args, operand.values.len())?;
        let result = gradient_vector_result(&operand, positions)?;
        let mut output = build_scalar_matrix_result(
            result.rows,
            result.cols,
            result
                .values
                .into_iter()
                .map(Value::Scalar)
                .collect::<Vec<_>>(),
        )?;
        if input_dims.len() > 2 {
            output = relabel_value_dimensions(&output, input_dims)?;
        }
        return Ok(vec![output]);
    }

    let spacings = parse_gradient_component_spacings(args, component_dims.len())?;
    let outputs = gradient_nd_results(&operand.values, &input_dims, &component_dims, &spacings)?
        .into_iter()
        .map(|values| numeric_matrix_result_with_dimensions(input_dims.clone(), values))
        .collect::<Result<Vec<_>, _>>()?;

    match output_arity {
        0 | 1 => Ok(vec![outputs[0].clone()]),
        arity if arity <= outputs.len() => Ok(outputs.into_iter().take(arity).collect()),
        _ => Err(RuntimeError::Unsupported(format!(
            "gradient currently supports at most {} output(s) for this input shape",
            outputs.len()
        ))),
    }
}

fn builtin_trapz(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, y, dim) = parse_trapezoid_args(args, "trapz")?;
    let positions = trapezoid_positions(x, integration_axis_len(&y, dim), "trapz")?;
    let result = integrate_trapezoid_reduction(&y, &positions, dim);
    numeric_or_complex_operand_to_value(&result)
}

fn builtin_cumtrapz(args: &[Value]) -> Result<Value, RuntimeError> {
    let (x, y, dim) = parse_trapezoid_args(args, "cumtrapz")?;
    let positions = trapezoid_positions(x, integration_axis_len(&y, dim), "cumtrapz")?;
    let result = cumulative_trapezoid(&y, &positions, dim);
    numeric_or_complex_operand_to_value(&result)
}

fn meshgrid_vector(value: &Value) -> Result<Vec<f64>, RuntimeError> {
    let matrix = coerce_matrix(value)?;
    if matrix.rows != 1 && matrix.cols != 1 {
        return Err(RuntimeError::TypeError(
            "meshgrid currently expects scalar or vector numeric inputs".to_string(),
        ));
    }
    matrix
        .iter()
        .map(Value::as_scalar)
        .collect::<Result<Vec<_>, _>>()
}

fn ndgrid_outputs(x: &[f64], y: &[f64]) -> Result<(Value, Value), RuntimeError> {
    let rows = x.len();
    let cols = y.len();
    let mut x_elements = Vec::with_capacity(rows * cols);
    let mut y_elements = Vec::with_capacity(rows * cols);
    for x_value in x {
        for y_value in y {
            x_elements.push(Value::Scalar(*x_value));
            y_elements.push(Value::Scalar(*y_value));
        }
    }
    Ok((
        Value::Matrix(MatrixValue::new(rows, cols, x_elements)?),
        Value::Matrix(MatrixValue::new(rows, cols, y_elements)?),
    ))
}

fn meshgrid_outputs_3d(
    x: &[f64],
    y: &[f64],
    z: &[f64],
) -> Result<(Value, Value, Value), RuntimeError> {
    let dims = vec![y.len(), x.len(), z.len()];
    let len = dims.iter().product::<usize>();
    let mut x_elements = vec![Value::Scalar(0.0); len];
    let mut y_elements = vec![Value::Scalar(0.0); len];
    let mut z_elements = vec![Value::Scalar(0.0); len];
    for (y_index, y_value) in y.iter().enumerate() {
        for (x_index, x_value) in x.iter().enumerate() {
            for (z_index, z_value) in z.iter().enumerate() {
                let linear = row_major_linear_index(&[y_index, x_index, z_index], &dims);
                x_elements[linear] = Value::Scalar(*x_value);
                y_elements[linear] = Value::Scalar(*y_value);
                z_elements[linear] = Value::Scalar(*z_value);
            }
        }
    }
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok((
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            dims.clone(),
            x_elements,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            dims.clone(),
            y_elements,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(rows, cols, dims, z_elements)?),
    ))
}

fn meshgrid_outputs_nd(vectors: &[Vec<f64>]) -> Result<Vec<Value>, RuntimeError> {
    let Some(first) = vectors.first() else {
        return Ok(Vec::new());
    };
    let mut dims = Vec::with_capacity(vectors.len());
    dims.push(vectors.get(1).unwrap_or(first).len());
    dims.push(first.len());
    for vector in vectors.iter().skip(2) {
        dims.push(vector.len());
    }

    let len = dims.iter().product::<usize>();
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    let mut elements = vectors
        .iter()
        .map(|_| vec![Value::Scalar(0.0); len])
        .collect::<Vec<_>>();

    for linear in 0..len {
        let index = row_major_multi_index(linear, &dims);
        elements[0][linear] = Value::Scalar(vectors[0][index[1]]);
        if vectors.len() > 1 {
            elements[1][linear] = Value::Scalar(vectors[1][index[0]]);
        }
        for axis in 2..vectors.len() {
            elements[axis][linear] = Value::Scalar(vectors[axis][index[axis]]);
        }
    }

    elements
        .into_iter()
        .map(|values| {
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                dims.clone(),
                values,
            )?))
        })
        .collect()
}

fn ndgrid_outputs_3d(
    x: &[f64],
    y: &[f64],
    z: &[f64],
) -> Result<(Value, Value, Value), RuntimeError> {
    let dims = vec![x.len(), y.len(), z.len()];
    let len = dims.iter().product::<usize>();
    let mut x_elements = vec![Value::Scalar(0.0); len];
    let mut y_elements = vec![Value::Scalar(0.0); len];
    let mut z_elements = vec![Value::Scalar(0.0); len];
    for (x_index, x_value) in x.iter().enumerate() {
        for (y_index, y_value) in y.iter().enumerate() {
            for (z_index, z_value) in z.iter().enumerate() {
                let linear = row_major_linear_index(&[x_index, y_index, z_index], &dims);
                x_elements[linear] = Value::Scalar(*x_value);
                y_elements[linear] = Value::Scalar(*y_value);
                z_elements[linear] = Value::Scalar(*z_value);
            }
        }
    }
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok((
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            dims.clone(),
            x_elements,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            dims.clone(),
            y_elements,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(rows, cols, dims, z_elements)?),
    ))
}

fn ndgrid_outputs_nd(vectors: &[Vec<f64>]) -> Result<Vec<Value>, RuntimeError> {
    let dims = vectors.iter().map(Vec::len).collect::<Vec<_>>();
    let len = dims.iter().product::<usize>();
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    let mut elements = vectors
        .iter()
        .map(|_| vec![Value::Scalar(0.0); len])
        .collect::<Vec<_>>();

    for linear in 0..len {
        let index = row_major_multi_index(linear, &dims);
        for axis in 0..vectors.len() {
            elements[axis][linear] = Value::Scalar(vectors[axis][index[axis]]);
        }
    }

    elements
        .into_iter()
        .map(|values| {
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                dims.clone(),
                values,
            )?))
        })
        .collect()
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HistogramNormalization {
    Count,
    Probability,
    Percentage,
    CountDensity,
    Cumcount,
    Pdf,
    Cdf,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum HistogramBinMethod {
    Auto,
    Scott,
    Fd,
    Integers,
    Sturges,
    Sqrt,
}

struct HistogramCountsResult {
    counts: Vec<f64>,
    edges: Vec<f64>,
    bins: Vec<usize>,
    output_dims: Vec<usize>,
    sample_count: usize,
    normalization: HistogramNormalization,
}

struct Histogram2CountsResult {
    counts: Vec<f64>,
    x_edges: Vec<f64>,
    y_edges: Vec<f64>,
    x_bins: Vec<usize>,
    y_bins: Vec<usize>,
    output_dims: Vec<usize>,
    sample_count: usize,
    normalization: HistogramNormalization,
}

#[derive(Debug, Clone, Copy)]
struct HistogramOptions {
    normalization: HistogramNormalization,
    bin_limits: Option<(f64, f64)>,
    bin_width: Option<f64>,
    num_bins: Option<usize>,
    bin_method: Option<HistogramBinMethod>,
}

#[derive(Debug, Clone, Copy)]
struct Histogram2Options {
    normalization: HistogramNormalization,
    x_bin_limits: Option<(f64, f64)>,
    y_bin_limits: Option<(f64, f64)>,
    bin_width: Option<(f64, f64)>,
    num_bins: Option<(usize, usize)>,
    bin_method: Option<HistogramBinMethod>,
}

fn histogram_counts_and_edges(
    args: &[Value],
    builtin_name: &str,
) -> Result<HistogramCountsResult, RuntimeError> {
    let (data_value, requested_bins, options) = parse_histogram_builtin_args(args, builtin_name)?;

    let matrix = coerce_matrix(data_value)?;
    let output_dims = canonical_size_vector(&matrix.dims);
    let values = matrix
        .iter()
        .map(Value::as_scalar)
        .collect::<Result<Vec<_>, _>>()?;
    let finite_values = values
        .iter()
        .copied()
        .filter(|value| value.is_finite())
        .collect::<Vec<_>>();

    let edges = if let Some(requested) = requested_bins {
        let requested_values = meshgrid_vector(requested)?;
        if requested_values.len() > 1 {
            histogram_edges(requested, builtin_name)?
        } else if let Some(width) = options.bin_width {
            histogram_edges_from_width(&finite_values, width, options.bin_limits)
        } else if let Some(bin_count) = options.num_bins {
            uniform_histogram_edges_with_limits(&finite_values, bin_count, options.bin_limits)
        } else if let Some(method) = options.bin_method {
            histogram_edges_from_method_1d(&finite_values, method, options.bin_limits)
        } else {
            uniform_histogram_edges_with_limits(
                &finite_values,
                positive_integer_scalar(requested, builtin_name)?,
                options.bin_limits,
            )
        }
    } else if let Some(width) = options.bin_width {
        histogram_edges_from_width(&finite_values, width, options.bin_limits)
    } else if let Some(bin_count) = options.num_bins {
        uniform_histogram_edges_with_limits(&finite_values, bin_count, options.bin_limits)
    } else if let Some(method) = options.bin_method {
        histogram_edges_from_method_1d(&finite_values, method, options.bin_limits)
    } else {
        uniform_histogram_edges_with_limits(&finite_values, 10, options.bin_limits)
    };

    let (counts, bins) = histogram_counts_and_bins(&values, &edges);
    Ok(HistogramCountsResult {
        counts,
        edges,
        bins,
        output_dims,
        sample_count: values.len(),
        normalization: options.normalization,
    })
}

fn histogram2_counts_and_edges(
    args: &[Value],
    builtin_name: &str,
) -> Result<Histogram2CountsResult, RuntimeError> {
    let (x_value, y_value, requested_bins, requested_y_edges, options) =
        parse_histogram2_builtin_args(args, builtin_name)?;

    let x_matrix = coerce_matrix(x_value)?;
    let y_matrix = coerce_matrix(y_value)?;
    if x_matrix.rows != y_matrix.rows || x_matrix.cols != y_matrix.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} requires X and Y inputs with matching shapes"
        )));
    }
    let output_dims = canonical_size_vector(&x_matrix.dims);

    let pairs = x_matrix
        .iter()
        .zip(y_matrix.iter())
        .map(|(x, y)| Ok((x.as_scalar()?, y.as_scalar()?)))
        .collect::<Result<Vec<_>, RuntimeError>>()?;
    let finite_pairs = pairs
        .iter()
        .copied()
        .filter(|(x, y)| x.is_finite() && y.is_finite())
        .collect::<Vec<_>>();
    let x_values = finite_pairs.iter().map(|(x, _)| *x).collect::<Vec<_>>();
    let y_values = finite_pairs.iter().map(|(_, y)| *y).collect::<Vec<_>>();

    let (x_edges, y_edges) = if let Some(y_edges) = requested_y_edges {
        (
            histogram_edges(requested_bins.expect("x edges present"), builtin_name)?,
            histogram_edges(y_edges, builtin_name)?,
        )
    } else if let Some((x_width, y_width)) = options.bin_width {
        (
            histogram_edges_from_width(&x_values, x_width, options.x_bin_limits),
            histogram_edges_from_width(&y_values, y_width, options.y_bin_limits),
        )
    } else if let Some((x_bins, y_bins)) = options.num_bins {
        (
            uniform_histogram_edges_with_limits(&x_values, x_bins, options.x_bin_limits),
            uniform_histogram_edges_with_limits(&y_values, y_bins, options.y_bin_limits),
        )
    } else if let Some(method) = options.bin_method {
        histogram_edges_from_method_2d(
            &x_values,
            &y_values,
            method,
            options.x_bin_limits,
            options.y_bin_limits,
        )
    } else if let Some(requested) = requested_bins {
        let counts = meshgrid_vector(requested)?;
        let (x_bins, y_bins) = match counts.len() {
            1 => {
                let bins = positive_integer_scalar(requested, builtin_name)?;
                (bins, bins)
            }
            2 => {
                let bins = positive_integer_pair(requested, builtin_name)?;
                (bins[0], bins[1])
            }
            _ => {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} currently expects nbins to be a positive integer scalar or a two-element vector"
                )))
            }
        };
        (
            uniform_histogram_edges_with_limits(&x_values, x_bins, options.x_bin_limits),
            uniform_histogram_edges_with_limits(&y_values, y_bins, options.y_bin_limits),
        )
    } else {
        (
            uniform_histogram_edges_with_limits(&x_values, 10, options.x_bin_limits),
            uniform_histogram_edges_with_limits(&y_values, 10, options.y_bin_limits),
        )
    };

    let (counts, x_bins, y_bins) = histogram2_counts_and_bins(&pairs, &x_edges, &y_edges);
    Ok(Histogram2CountsResult {
        counts,
        x_edges,
        y_edges,
        x_bins,
        y_bins,
        output_dims,
        sample_count: pairs.len(),
        normalization: options.normalization,
    })
}

