fn parse_interp1_args(
    args: &[Value],
) -> Result<
    (
        Vec<f64>,
        Interp1SampleOperand,
        InterpQueryOperand,
        InterpolationMethod,
        Interp1Extrapolation,
    ),
    RuntimeError,
> {
    let (x, v, xq, method, extrapolation) = match args.len() {
        2 => {
            let [v, xq] = args else { unreachable!("length checked") };
            (None, v, xq, InterpolationMethod::Linear, Interp1Extrapolation::Nan)
        }
        3 => {
            let [first, second, third] = args else {
                unreachable!("length checked")
            };
            if is_interpolation_method_value(third)
                || matches!(third, Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("extrap"))
            {
                let method = if is_interpolation_method_value(third) {
                    parse_interpolation_method(third, "interp1")?
                } else {
                    InterpolationMethod::Linear
                };
                (
                    None,
                    first,
                    second,
                    method,
                    if is_interpolation_method_value(third) {
                        interp1_default_extrapolation_for_method(method)
                    } else {
                        parse_interp1_extrapolation(third)?
                    },
                )
            } else {
                (
                    Some(first),
                    second,
                    third,
                    InterpolationMethod::Linear,
                    Interp1Extrapolation::Nan,
                )
            }
        }
        4 => {
            let [first, second, third, fourth] = args else {
                unreachable!("length checked")
            };
            if is_interpolation_method_value(third) {
                let method = parse_interpolation_method(third, "interp1")?;
                (
                    None,
                    first,
                    second,
                    method,
                    parse_interp1_extrapolation(fourth)?,
                )
            } else {
                let method = if is_interpolation_method_value(fourth) {
                    parse_interpolation_method(fourth, "interp1")?
                } else {
                    InterpolationMethod::Linear
                };
                (
                    Some(first),
                    second,
                    third,
                    method,
                    if is_interpolation_method_value(fourth) {
                        interp1_default_extrapolation_for_method(method)
                    } else {
                        parse_interp1_extrapolation(fourth)?
                    },
                )
            }
        }
        5 => {
            let [x, v, xq, method, extrapolation] = args else {
                unreachable!("length checked")
            };
            (
                Some(x),
                v,
                xq,
                parse_interpolation_method(method, "interp1")?,
                parse_interp1_extrapolation(extrapolation)?,
            )
        }
        _ => {
            return Err(RuntimeError::Unsupported(
                "interp1 currently supports `interp1(v, xq)`, `interp1(v, xq, method)`, `interp1(v, xq, extrap)`, `interp1(v, xq, method, extrap)`, `interp1(x, v, xq)`, `interp1(x, v, xq, method)`, `interp1(x, v, xq, extrap)`, or `interp1(x, v, xq, method, extrap)`".to_string(),
            ))
        }
    };

    let v = interp1_sample_operand(v, "interp1")?;
    if interp1_sample_count(&v) < 2 {
        return Err(RuntimeError::ShapeError(
            "interp1 currently requires at least two sample values".to_string(),
        ));
    }
    let x = match x {
        Some(x) => {
            let x = meshgrid_vector(x)?;
            if x.len() != interp1_sample_count(&v) {
                return Err(RuntimeError::ShapeError(format!(
                    "interp1 requires X to match the interpolation dimension of V, found {} and {}",
                    x.len(),
                    interp1_sample_count(&v)
                )));
            }
            x
        }
        None => (1..=interp1_sample_count(&v))
            .map(|index| index as f64)
            .collect::<Vec<_>>(),
    };

    if matches!(
        method,
        InterpolationMethod::Cubic | InterpolationMethod::V5Cubic
    ) && interp1_sample_count(&v) < 3
    {
        return Err(RuntimeError::ShapeError(
            "interp1 cubic/v5cubic currently requires at least three sample points".to_string(),
        ));
    }

    Ok((
        x,
        v,
        numeric_query_operand(xq, "interp1")?,
        method,
        extrapolation,
    ))
}

fn parse_interp1_extrapolation(value: &Value) -> Result<Interp1Extrapolation, RuntimeError> {
    match value {
        Value::CharArray(text) | Value::String(text) if text.eq_ignore_ascii_case("extrap") => {
            Ok(Interp1Extrapolation::Extrapolate)
        }
        _ => Ok(Interp1Extrapolation::Fill(numeric_or_complex_scalar(
            value, "interp1",
        )?)),
    }
}

fn interp1_default_extrapolation_for_method(method: InterpolationMethod) -> Interp1Extrapolation {
    match method {
        InterpolationMethod::Pchip | InterpolationMethod::Spline | InterpolationMethod::Makima => {
            Interp1Extrapolation::Extrapolate
        }
        _ => Interp1Extrapolation::Nan,
    }
}

fn parse_interp2_args(
    args: &[Value],
) -> Result<
    (
        Vec<f64>,
        Vec<f64>,
        NumericOrComplexOperand,
        bool,
        InterpQueryOperand,
        InterpQueryOperand,
        InterpolationMethod,
        Interp2Extrapolation,
    ),
    RuntimeError,
> {
    let (x, y, v, xq, yq, method, extrapolation) = match args {
        [v, xq, yq] => (None, None, v, xq, yq, InterpolationMethod::Linear, Interp2Extrapolation::Nan),
        [v, xq, yq, method] if is_interpolation_method_value(method) => (
            None,
            None,
            v,
            xq,
            yq,
            parse_interpolation_method(method, "interp2")?,
            Interp2Extrapolation::Nan,
        ),
        [v, xq, yq, method, extrapolation] if is_interpolation_method_value(method) => (
            None,
            None,
            v,
            xq,
            yq,
            parse_interpolation_method(method, "interp2")?,
            parse_interp2_extrapolation(extrapolation)?,
        ),
        [x, y, v, xq, yq] => (
            Some(x),
            Some(y),
            v,
            xq,
            yq,
            InterpolationMethod::Linear,
            Interp2Extrapolation::Nan,
        ),
        [x, y, v, xq, yq, method] => (
            Some(x),
            Some(y),
            v,
            xq,
            yq,
            parse_interpolation_method(method, "interp2")?,
            Interp2Extrapolation::Nan,
        ),
        [x, y, v, xq, yq, method, extrapolation] => (
            Some(x),
            Some(y),
            v,
            xq,
            yq,
            parse_interpolation_method(method, "interp2")?,
            parse_interp2_extrapolation(extrapolation)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "interp2 currently supports `interp2(v, xq, yq)`, `interp2(v, xq, yq, method)`, `interp2(v, xq, yq, method, extrapval)`, `interp2(x, y, v, xq, yq)`, `interp2(x, y, v, xq, yq, method)`, or `interp2(x, y, v, xq, yq, method, extrapval)`".to_string(),
            ))
        }
    };

    let complex_output = value_has_complex_elements(v);
    let v = numeric_or_complex_operand(v, "interp2")?;
    if v.rows < 2 || v.cols < 2 {
        return Err(RuntimeError::ShapeError(
            "interp2 currently requires V to have at least two rows and two columns".to_string(),
        ));
    }

    let (x, y) = match (x, y) {
        (None, None) => (
            (1..=v.cols).map(|index| index as f64).collect::<Vec<_>>(),
            (1..=v.rows).map(|index| index as f64).collect::<Vec<_>>(),
        ),
        (Some(x), Some(y)) => interp2_grid_vectors(x, y, v.rows, v.cols)?,
        _ => unreachable!("interp2 X and Y inputs are paired"),
    };

    Ok((
        x,
        y,
        v,
        complex_output,
        numeric_query_operand(xq, "interp2")?,
        numeric_query_operand(yq, "interp2")?,
        method,
        extrapolation,
    ))
}

fn parse_interp2_extrapolation(value: &Value) -> Result<Interp2Extrapolation, RuntimeError> {
    Ok(Interp2Extrapolation::Fill(numeric_or_complex_scalar(
        value, "interp2",
    )?))
}

fn parse_interp3_args(
    args: &[Value],
) -> Result<
    (
        Vec<Vec<f64>>,
        InterpNdSampleOperand,
        Vec<InterpQueryOperand>,
        InterpolationMethod,
        Interp2Extrapolation,
    ),
    RuntimeError,
> {
    let (core_args, method, extrapolation) =
        parse_interp_nd_method_and_extrapolation(args, "interp3")?;
    let (axes, values, queries) = match core_args {
        [value, xq, yq, zq] => {
            let values = interp_nd_sample_operand(value, "interp3")?;
            if values.dims.len() != 3 {
                return Err(RuntimeError::ShapeError(
                    "interp3 currently expects V to be a 3-D array".to_string(),
                ));
            }
            (
                interp_nd_default_axes(&values.dims),
                values,
                reorder_interp3_queries(broadcast_interp_queries(
                    vec![
                        numeric_query_operand(xq, "interp3")?,
                        numeric_query_operand(yq, "interp3")?,
                        numeric_query_operand(zq, "interp3")?,
                    ],
                    InterpQueryLayout::Meshgrid,
                    "interp3",
                )?),
            )
        }
        [x, y, z, value, xq, yq, zq] => {
            let values = interp_nd_sample_operand(value, "interp3")?;
            if values.dims.len() != 3 {
                return Err(RuntimeError::ShapeError(
                    "interp3 currently expects V to be a 3-D array".to_string(),
                ));
            }
            (
                interp3_axes_from_values(x, y, z, &values)?,
                values,
                reorder_interp3_queries(broadcast_interp_queries(
                    vec![
                        numeric_query_operand(xq, "interp3")?,
                        numeric_query_operand(yq, "interp3")?,
                        numeric_query_operand(zq, "interp3")?,
                    ],
                    InterpQueryLayout::Meshgrid,
                    "interp3",
                )?),
            )
        }
        _ => {
            return Err(RuntimeError::Unsupported(
                "interp3 currently supports `interp3(V, Xq, Yq, Zq)`, `interp3(V, Xq, Yq, Zq, method)`, `interp3(V, Xq, Yq, Zq, method, extrapval)`, `interp3(X, Y, Z, V, Xq, Yq, Zq)`, and the same forms with trailing method/extrapval"
                    .to_string(),
            ))
        }
    };
    let (axes, values) = normalized_interp_nd_samples(axes, values, "interp3")?;
    Ok((axes, values, queries, method, extrapolation))
}

fn parse_interpn_args(
    args: &[Value],
) -> Result<
    (
        Vec<Vec<f64>>,
        InterpNdSampleOperand,
        Vec<InterpQueryOperand>,
        InterpolationMethod,
        Interp2Extrapolation,
    ),
    RuntimeError,
> {
    let (core_args, method, extrapolation) =
        parse_interp_nd_method_and_extrapolation(args, "interpn")?;
    if core_args.len() < 2 {
        return Err(RuntimeError::Unsupported(
            "interpn currently expects at least a value input and one query array".to_string(),
        ));
    }

    if core_args.len() % 2 == 1 && core_args.len() >= 3 {
        let axis_count = (core_args.len() - 1) / 2;
        let value = &core_args[axis_count];
        let values = interp_nd_sample_operand(&value, "interpn")?;
        if values.dims.len() == axis_count {
            if let Ok(axes) =
                interpn_axes_from_values(&core_args[..axis_count], &values.dims, "interpn")
            {
                let queries = core_args[axis_count + 1..]
                    .iter()
                    .map(|query| numeric_query_operand(query, "interpn"))
                    .collect::<Result<Vec<_>, _>>()?;
                let queries =
                    broadcast_interp_queries(queries, InterpQueryLayout::Ndgrid, "interpn")?;
                let (axes, values) = normalized_interp_nd_samples(axes, values, "interpn")?;
                return Ok((axes, values, queries, method, extrapolation));
            }
        }
    }

    let value = &core_args[0];
    let values = interp_nd_sample_operand(&value, "interpn")?;
    if core_args.len() - 1 != values.dims.len() {
        return Err(RuntimeError::Unsupported(format!(
            "interpn currently expects {} query arrays for a {}-D input",
            values.dims.len(),
            values.dims.len()
        )));
    }
    let queries = core_args[1..]
        .iter()
        .map(|query| numeric_query_operand(query, "interpn"))
        .collect::<Result<Vec<_>, _>>()?;
    let queries = broadcast_interp_queries(queries, InterpQueryLayout::Ndgrid, "interpn")?;
    let axes = interp_nd_default_axes(&values.dims);
    Ok((axes, values, queries, method, extrapolation))
}

fn parse_interp_nd_method_and_extrapolation<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a [Value], InterpolationMethod, Interp2Extrapolation), RuntimeError> {
    match args {
        [core @ .., method, extrapolation]
            if is_interpolation_method_value_for_builtin(method, builtin_name) =>
        {
            Ok((
                core,
                parse_interpolation_method(method, builtin_name)?,
                parse_interp2_extrapolation(extrapolation)?,
            ))
        }
        [core @ .., method] if is_interpolation_method_value_for_builtin(method, builtin_name) => {
            Ok((
                core,
                parse_interpolation_method(method, builtin_name)?,
                Interp2Extrapolation::Nan,
            ))
        }
        _ => Ok((args, InterpolationMethod::Linear, Interp2Extrapolation::Nan)),
    }
}

fn is_interpolation_method_value_for_builtin(value: &Value, builtin_name: &str) -> bool {
    parse_interpolation_method(value, builtin_name).is_ok()
}

fn try_nonnegative_integer_scalar(value: &Value) -> Option<usize> {
    let scalar = value.as_scalar().ok()?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return None;
    }
    Some(scalar as usize)
}

fn interp_nd_sample_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<InterpNdSampleOperand, RuntimeError> {
    Ok(InterpNdSampleOperand {
        dims: canonical_size_vector(&value_dimensions(value)),
        values: numeric_or_complex_operand(value, builtin_name)?.values,
        complex_output: value_has_complex_elements(value),
    })
}

fn interp_nd_default_axes(dims: &[usize]) -> Vec<Vec<f64>> {
    dims.iter()
        .map(|extent| (1..=*extent).map(|value| value as f64).collect::<Vec<_>>())
        .collect()
}

fn refined_interp_nd_default_axes(dims: &[usize], refinement: usize) -> Vec<Vec<f64>> {
    let subdivisions = 1usize << refinement;
    dims.iter()
        .enumerate()
        .map(|(_axis, &extent)| {
            if extent <= 1 {
                vec![1.0]
            } else {
                let count = ((extent - 1) * subdivisions) + 1;
                let step = 1.0 / subdivisions as f64;
                (0..count)
                    .map(|index| 1.0 + index as f64 * step)
                    .collect::<Vec<_>>()
            }
        })
        .collect()
}

#[derive(Debug, Clone, Copy)]
enum InterpQueryLayout {
    Ndgrid,
    Meshgrid,
}

fn broadcast_interp_queries(
    queries: Vec<InterpQueryOperand>,
    layout: InterpQueryLayout,
    builtin_name: &str,
) -> Result<Vec<InterpQueryOperand>, RuntimeError> {
    if queries.is_empty() {
        return Ok(queries);
    }
    let first_dims = queries[0].dims.clone();
    if queries.iter().all(|query| query.dims == first_dims) {
        return Ok(queries);
    }

    let nonscalar = queries
        .iter()
        .filter(|query| query.values.len() > 1)
        .collect::<Vec<_>>();
    if let Some(target) = nonscalar.first() {
        if nonscalar.iter().all(|query| query.dims == target.dims) {
            let target_dims = target.dims.clone();
            let target_len = target.values.len();
            return Ok(queries
                .into_iter()
                .map(|query| {
                    if query.values.len() == 1 {
                        InterpQueryOperand {
                            dims: target_dims.clone(),
                            values: vec![query.values[0]; target_len],
                        }
                    } else {
                        query
                    }
                })
                .collect());
        }
    }

    if queries
        .iter()
        .all(|query| is_vector_dimensions(&query.dims))
    {
        let vectors = queries
            .iter()
            .map(|query| query.values.clone())
            .collect::<Vec<_>>();
        let outputs = match layout {
            InterpQueryLayout::Ndgrid => ndgrid_outputs_nd(&vectors)?,
            InterpQueryLayout::Meshgrid => meshgrid_outputs_nd(&vectors)?,
        };
        return outputs
            .into_iter()
            .map(|value| numeric_query_operand(&value, builtin_name))
            .collect();
    }

    Err(RuntimeError::ShapeError(format!(
        "{builtin_name} currently expects query arrays with matching shapes, scalar expansion, or vector inputs that can form a grid"
    )))
}

fn reorder_interp3_queries(queries: Vec<InterpQueryOperand>) -> Vec<InterpQueryOperand> {
    vec![queries[1].clone(), queries[0].clone(), queries[2].clone()]
}

fn interpn_axes_from_values(
    axis_values: &[Value],
    sample_dims: &[usize],
    builtin_name: &str,
) -> Result<Vec<Vec<f64>>, RuntimeError> {
    axis_values
        .iter()
        .enumerate()
        .map(|(axis, value)| interp_nd_axis_values(value, sample_dims, axis, builtin_name))
        .collect()
}

fn interp3_axes_from_values(
    x_value: &Value,
    y_value: &Value,
    z_value: &Value,
    values: &InterpNdSampleOperand,
) -> Result<Vec<Vec<f64>>, RuntimeError> {
    if values.dims.len() != 3 {
        return Err(RuntimeError::ShapeError(
            "interp3 currently expects V to be a 3-D array".to_string(),
        ));
    }
    Ok(vec![
        interp_nd_axis_values(y_value, &values.dims, 0, "interp3")?,
        interp_nd_axis_values(x_value, &values.dims, 1, "interp3")?,
        interp_nd_axis_values(z_value, &values.dims, 2, "interp3")?,
    ])
}

fn interp_nd_axis_values(
    value: &Value,
    sample_dims: &[usize],
    axis: usize,
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    if is_vector_dimensions(&value_dimensions(value)) {
        let vector = meshgrid_vector(value)?;
        if vector.len() != sample_dims[axis] {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} requires axis {} to have {} sample points, found {}",
                axis + 1,
                sample_dims[axis],
                vector.len()
            )));
        }
        return Ok(vector);
    }
    interp_nd_axis_from_grid(value, sample_dims, axis, builtin_name)
}

fn interp_nd_axis_from_grid(
    value: &Value,
    sample_dims: &[usize],
    axis: usize,
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    let matrix = coerce_matrix(value)?;
    let grid_dims = canonical_size_vector(matrix.dims());
    if grid_dims != sample_dims {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects grid inputs to match V dimensions"
        )));
    }
    let elements = matrix
        .iter()
        .map(Value::as_scalar)
        .collect::<Result<Vec<_>, _>>()?;
    let axis_values = (0..sample_dims[axis])
        .map(|position| {
            let mut index = vec![0usize; sample_dims.len()];
            index[axis] = position;
            elements[row_major_linear_index(&index, sample_dims)]
        })
        .collect::<Vec<_>>();
    for linear in 0..elements.len() {
        let index = row_major_multi_index(linear, sample_dims);
        if !approx_equal(elements[linear], axis_values[index[axis]]) {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently expects grid inputs to follow ndgrid/meshgrid repetition along each axis"
            )));
        }
    }
    Ok(axis_values)
}

fn parse_interpolation_method(
    value: &Value,
    builtin_name: &str,
) -> Result<InterpolationMethod, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "linear" => Ok(InterpolationMethod::Linear),
        "nearest" => Ok(InterpolationMethod::Nearest),
        "previous" if builtin_name.eq_ignore_ascii_case("interp1") => {
            Ok(InterpolationMethod::Previous)
        }
        "next" if builtin_name.eq_ignore_ascii_case("interp1") => Ok(InterpolationMethod::Next),
        "pchip" if builtin_name.eq_ignore_ascii_case("interp1") => Ok(InterpolationMethod::Pchip),
        "cubic"
            if builtin_name.eq_ignore_ascii_case("interp1")
                || builtin_name.eq_ignore_ascii_case("interp2")
                || builtin_name.eq_ignore_ascii_case("interp3")
                || builtin_name.eq_ignore_ascii_case("interpn") =>
        {
            Ok(InterpolationMethod::Cubic)
        }
        "v5cubic" if builtin_name.eq_ignore_ascii_case("interp1") => {
            Ok(InterpolationMethod::V5Cubic)
        }
        "spline"
            if builtin_name.eq_ignore_ascii_case("interp1")
                || builtin_name.eq_ignore_ascii_case("interp2")
                || builtin_name.eq_ignore_ascii_case("interp3")
                || builtin_name.eq_ignore_ascii_case("interpn") =>
        {
            Ok(InterpolationMethod::Spline)
        }
        "makima"
            if builtin_name.eq_ignore_ascii_case("interp1")
                || builtin_name.eq_ignore_ascii_case("interp2")
                || builtin_name.eq_ignore_ascii_case("interp3")
                || builtin_name.eq_ignore_ascii_case("interpn") =>
        {
            Ok(InterpolationMethod::Makima)
        }
        _ => Err(RuntimeError::Unsupported(
            if builtin_name.eq_ignore_ascii_case("interp1") {
                format!(
                "{builtin_name} currently supports only `linear`, `nearest`, `previous`, `next`, `pchip`, `cubic`, `v5cubic`, `spline`, and `makima` methods"
            )
            } else if builtin_name.eq_ignore_ascii_case("interp2") {
                format!(
                    "{builtin_name} currently supports only `linear`, `nearest`, `cubic`, `spline`, and `makima` methods"
                )
            } else if builtin_name.eq_ignore_ascii_case("interp3")
                || builtin_name.eq_ignore_ascii_case("interpn")
            {
                format!(
                    "{builtin_name} currently supports only `linear`, `nearest`, `cubic`, `spline`, and `makima` methods"
                )
            } else {
                format!("{builtin_name} currently supports only `linear` and `nearest` methods")
            },
        )),
    }
}

fn is_interpolation_method_value(value: &Value) -> bool {
    matches!(value, Value::CharArray(_) | Value::String(_))
        && text_value(value)
            .map(|text| {
                matches!(
                    text.to_ascii_lowercase().as_str(),
                    "linear"
                        | "nearest"
                        | "previous"
                        | "next"
                        | "pchip"
                        | "cubic"
                        | "v5cubic"
                        | "spline"
                        | "makima"
                )
            })
            .unwrap_or(false)
}

fn numeric_query_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<InterpQueryOperand, RuntimeError> {
    let operand = numeric_operand(value, builtin_name)?;
    Ok(InterpQueryOperand {
        dims: canonical_size_vector(&value_dimensions(value)),
        values: operand.values,
    })
}

fn interp1_sample_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<Interp1SampleOperand, RuntimeError> {
    Ok(Interp1SampleOperand {
        dims: canonical_size_vector(&value_dimensions(value)),
        values: numeric_or_complex_operand(value, builtin_name)?.values,
        vector_input: is_vector_dimensions(&value_dimensions(value)),
        complex_output: value_has_complex_elements(value),
    })
}

fn value_has_complex_elements(value: &Value) -> bool {
    match value {
        Value::Complex(_) => true,
        Value::Matrix(matrix) => matrix
            .iter()
            .any(|element| matches!(element, Value::Complex(_))),
        _ => false,
    }
}

fn is_vector_dimensions(dims: &[usize]) -> bool {
    dims.iter().copied().filter(|&extent| extent != 1).count() <= 1
}

fn interp1_sample_count(value: &Interp1SampleOperand) -> usize {
    if value.vector_input {
        value.values.len()
    } else {
        value.dims[0]
    }
}

fn interp1_series_count(value: &Interp1SampleOperand) -> usize {
    if value.vector_input {
        1
    } else {
        value.dims.iter().copied().skip(1).product::<usize>()
    }
}

fn interp1_trailing_dims(value: &Interp1SampleOperand) -> Vec<usize> {
    if value.vector_input {
        Vec::new()
    } else {
        value.dims[1..].to_vec()
    }
}

fn interp1_query_output_dims(query: &InterpQueryOperand, series_count: usize) -> Vec<usize> {
    if series_count > 1 && is_vector_dimensions(&query.dims) {
        vec![query.values.len()]
    } else {
        query.dims.clone()
    }
}

fn interp1_series_values(
    value: &Interp1SampleOperand,
    series_index: usize,
    reverse_samples: bool,
) -> Vec<ComplexParts> {
    if value.vector_input {
        let mut values = value.values.clone();
        if reverse_samples {
            values.reverse();
        }
        return values;
    }

    let sample_count = value.dims[0];
    let trailing_dims = &value.dims[1..];
    let trailing_index = if trailing_dims.is_empty() {
        Vec::new()
    } else {
        row_major_multi_index(series_index, trailing_dims)
    };
    let mut values = Vec::with_capacity(sample_count);
    for sample_index in 0..sample_count {
        let axis_index = if reverse_samples {
            sample_count - sample_index - 1
        } else {
            sample_index
        };
        let mut full_index = Vec::with_capacity(value.dims.len());
        full_index.push(axis_index);
        full_index.extend_from_slice(&trailing_index);
        values.push(value.values[row_major_linear_index(&full_index, &value.dims)]);
    }
    values
}

fn normalized_interp2_samples(
    x: Vec<f64>,
    y: Vec<f64>,
    mut v: NumericOrComplexOperand,
) -> Result<(Vec<f64>, Vec<f64>, NumericOrComplexOperand), RuntimeError> {
    let (x, reverse_columns) = normalized_interp_axis(x, "interp2", "X")?;
    let (y, reverse_rows) = normalized_interp_axis(y, "interp2", "Y")?;

    if reverse_columns {
        v = flip_complex_operand_columns(&v);
    }
    if reverse_rows {
        v = flip_complex_operand_rows(&v);
    }

    Ok((x, y, v))
}

fn normalized_interp_nd_samples(
    mut axes: Vec<Vec<f64>>,
    mut values: InterpNdSampleOperand,
    builtin_name: &str,
) -> Result<(Vec<Vec<f64>>, InterpNdSampleOperand), RuntimeError> {
    for axis in 0..axes.len() {
        let axis_name = format!("dimension {}", axis + 1);
        let (normalized, reversed) =
            normalized_interp_axis(axes[axis].clone(), builtin_name, &axis_name)?;
        axes[axis] = normalized;
        if reversed {
            values = flip_interp_nd_sample_axis(&values, axis);
        }
    }
    Ok((axes, values))
}

fn flip_interp_nd_sample_axis(value: &InterpNdSampleOperand, axis: usize) -> InterpNdSampleOperand {
    let mut flipped = vec![ComplexParts::zero(); value.values.len()];
    for linear in 0..value.values.len() {
        let mut index = row_major_multi_index(linear, &value.dims);
        index[axis] = value.dims[axis] - index[axis] - 1;
        flipped[linear] = value.values[row_major_linear_index(&index, &value.dims)];
    }
    InterpNdSampleOperand {
        dims: value.dims.clone(),
        values: flipped,
        complex_output: value.complex_output,
    }
}

fn normalized_interp_axis(
    mut axis: Vec<f64>,
    builtin_name: &str,
    axis_name: &str,
) -> Result<(Vec<f64>, bool), RuntimeError> {
    if axis.windows(2).all(|window| window[1] > window[0]) {
        return Ok((axis, false));
    }
    if axis.windows(2).all(|window| window[1] < window[0]) {
        axis.reverse();
        return Ok((axis, true));
    }
    Err(RuntimeError::ShapeError(format!(
        "{builtin_name} currently expects {axis_name} sample points to be strictly monotonic"
    )))
}

fn interp1_value(
    query: f64,
    x: &[f64],
    v: &[ComplexParts],
    method: InterpolationMethod,
    extrapolation: Interp1Extrapolation,
    nan_output: ComplexParts,
) -> ComplexParts {
    if !query.is_finite() || x.len() < 2 {
        return nan_output;
    }
    if let Some(index) = x.iter().position(|sample| *sample == query) {
        return v[index];
    }

    let (index, weight) = if query < x[0] {
        match extrapolation {
            Interp1Extrapolation::Nan => return nan_output,
            Interp1Extrapolation::Fill(value) => return value,
            Interp1Extrapolation::Extrapolate => {
                if method == InterpolationMethod::Previous {
                    return nan_output;
                }
                (0, (query - x[0]) / (x[1] - x[0]))
            }
        }
    } else if query > x[x.len() - 1] {
        match extrapolation {
            Interp1Extrapolation::Nan => return nan_output,
            Interp1Extrapolation::Fill(value) => return value,
            Interp1Extrapolation::Extrapolate => {
                if method == InterpolationMethod::Next {
                    return nan_output;
                }
                let index = x.len() - 2;
                (index, (query - x[index]) / (x[index + 1] - x[index]))
            }
        }
    } else {
        locate_interp_interval(query, x).unwrap_or((x.len() - 2, 1.0))
    };

    interp1_interval_value(index, weight, x, v, method)
}

fn interp1_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    v: &[ComplexParts],
    method: InterpolationMethod,
) -> ComplexParts {
    let v0 = v[index];
    let v1 = v[index + 1];
    match method {
        InterpolationMethod::Linear => v0.plus(v1.minus(v0).times(ComplexParts {
            real: weight,
            imag: 0.0,
        })),
        InterpolationMethod::Nearest => {
            if weight <= 0.5 {
                v0
            } else {
                v1
            }
        }
        InterpolationMethod::Previous => v0,
        InterpolationMethod::Next => v1,
        InterpolationMethod::Pchip => interp1_pchip_interval_value(index, weight, x, v),
        InterpolationMethod::Cubic | InterpolationMethod::V5Cubic => {
            interp1_v5cubic_interval_value(index, weight, x, v)
        }
        InterpolationMethod::Spline => interp1_spline_interval_value(index, weight, x, v),
        InterpolationMethod::Makima => interp1_makima_interval_value(index, weight, x, v),
    }
}

fn interp1_pchip_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    v: &[ComplexParts],
) -> ComplexParts {
    let real_values = v.iter().map(|value| value.real).collect::<Vec<_>>();
    let imag_values = v.iter().map(|value| value.imag).collect::<Vec<_>>();
    ComplexParts {
        real: interp1_pchip_real_interval_value(index, weight, x, &real_values),
        imag: interp1_pchip_real_interval_value(index, weight, x, &imag_values),
    }
}

fn interp1_spline_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    v: &[ComplexParts],
) -> ComplexParts {
    let query = x[index] + weight * (x[index + 1] - x[index]);
    if v.len() <= 3 {
        return interp1_polynomial_fallback_value(query, x, v);
    }
    let derivatives = spline_derivatives(x, v);
    interp1_cubic_hermite_interval_value(index, weight, x, v, &derivatives)
}

fn interp1_makima_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    v: &[ComplexParts],
) -> ComplexParts {
    let derivatives = makima_derivatives(x, v);
    interp1_cubic_hermite_interval_value(index, weight, x, v, &derivatives)
}

fn interp1_v5cubic_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    v: &[ComplexParts],
) -> ComplexParts {
    if !interp_axis_is_uniform(x) {
        return interp1_spline_interval_value(index, weight, x, v);
    }
    let derivatives = v5cubic_derivatives(x, v);
    interp1_cubic_hermite_interval_value(index, weight, x, v, &derivatives)
}

fn interp1_polynomial_fallback_value(query: f64, x: &[f64], v: &[ComplexParts]) -> ComplexParts {
    let real_values = v.iter().map(|value| value.real).collect::<Vec<_>>();
    let imag_values = v.iter().map(|value| value.imag).collect::<Vec<_>>();
    ComplexParts {
        real: lagrange_polynomial_value(query, x, &real_values),
        imag: lagrange_polynomial_value(query, x, &imag_values),
    }
}

fn lagrange_polynomial_value(query: f64, x: &[f64], values: &[f64]) -> f64 {
    x.iter()
        .enumerate()
        .map(|(i, x_i)| {
            let basis = x
                .iter()
                .enumerate()
                .filter(|(j, _)| *j != i)
                .fold(1.0, |accumulator, (_, x_j)| {
                    accumulator * ((query - *x_j) / (*x_i - *x_j))
                });
            values[i] * basis
        })
        .sum()
}

fn interp1_cubic_hermite_interval_value(
    index: usize,
    weight: f64,
    x: &[f64],
    values: &[ComplexParts],
    derivatives: &[ComplexParts],
) -> ComplexParts {
    let h = x[index + 1] - x[index];
    let y0 = values[index];
    let y1 = values[index + 1];
    let d0 = derivatives[index];
    let d1 = derivatives[index + 1];
    let t2 = weight * weight;
    let t3 = t2 * weight;
    let h00 = (2.0 * t3) - (3.0 * t2) + 1.0;
    let h10 = t3 - (2.0 * t2) + weight;
    let h01 = (-2.0 * t3) + (3.0 * t2);
    let h11 = t3 - t2;
    y0.scale(h00)
        .plus(d0.scale(h * h10))
        .plus(y1.scale(h01))
        .plus(d1.scale(h * h11))
}

fn interp_axis_is_uniform(x: &[f64]) -> bool {
    if x.len() < 3 {
        return true;
    }
    let first_step = x[1] - x[0];
    let tolerance = first_step.abs().max(1.0) * 1e-9;
    x.windows(2)
        .all(|window| (window[1] - window[0] - first_step).abs() <= tolerance)
}

fn interp1_pchip_real_interval_value(index: usize, weight: f64, x: &[f64], values: &[f64]) -> f64 {
    let slopes = pchip_derivatives(x, values);
    let h = x[index + 1] - x[index];
    let y0 = values[index];
    let y1 = values[index + 1];
    let d0 = slopes[index];
    let d1 = slopes[index + 1];
    let t2 = weight * weight;
    let t3 = t2 * weight;
    let h00 = (2.0 * t3) - (3.0 * t2) + 1.0;
    let h10 = t3 - (2.0 * t2) + weight;
    let h01 = (-2.0 * t3) + (3.0 * t2);
    let h11 = t3 - t2;
    h00 * y0 + h10 * h * d0 + h01 * y1 + h11 * h * d1
}

fn pchip_derivatives(x: &[f64], values: &[f64]) -> Vec<f64> {
    if values.len() == 2 {
        let slope = (values[1] - values[0]) / (x[1] - x[0]);
        return vec![slope, slope];
    }

    let h = x
        .windows(2)
        .map(|window| window[1] - window[0])
        .collect::<Vec<_>>();
    let delta = values
        .windows(2)
        .zip(h.iter())
        .map(|(window, step)| (window[1] - window[0]) / step)
        .collect::<Vec<_>>();

    let mut derivatives = vec![0.0; values.len()];
    derivatives[0] = pchip_endpoint_derivative(h[0], h[1], delta[0], delta[1]);
    derivatives[values.len() - 1] = pchip_endpoint_derivative(
        h[h.len() - 1],
        h[h.len() - 2],
        delta[delta.len() - 1],
        delta[delta.len() - 2],
    );

    for index in 1..values.len() - 1 {
        let left = delta[index - 1];
        let right = delta[index];
        if !same_sign(left, right) {
            derivatives[index] = 0.0;
            continue;
        }
        let w1 = (2.0 * h[index]) + h[index - 1];
        let w2 = h[index] + (2.0 * h[index - 1]);
        derivatives[index] = (w1 + w2) / ((w1 / left) + (w2 / right));
    }

    derivatives
}

fn v5cubic_derivatives(x: &[f64], values: &[ComplexParts]) -> Vec<ComplexParts> {
    if values.len() == 3 {
        return vec![
            values[0]
                .scale(-1.5)
                .plus(values[1].scale(2.0))
                .minus(values[2].scale(0.5)),
            values[2].minus(values[0]).scale(0.5),
            values[2]
                .scale(1.5)
                .minus(values[1].scale(2.0))
                .plus(values[0].scale(0.5)),
        ];
    }

    let step = x[1] - x[0];
    let step_scale = 1.0 / step;
    let mut derivatives = vec![ComplexParts::zero(); values.len()];
    derivatives[0] = values[0]
        .scale(-1.5)
        .plus(values[1].scale(2.0))
        .minus(values[2].scale(0.5))
        .scale(step_scale);
    for index in 1..values.len() - 1 {
        derivatives[index] = values[index + 1]
            .minus(values[index - 1])
            .scale(0.5 * step_scale);
    }
    let last = values.len() - 1;
    derivatives[last] = values[last]
        .scale(1.5)
        .minus(values[last - 1].scale(2.0))
        .plus(values[last - 2].scale(0.5))
        .scale(step_scale);
    derivatives
}

fn spline_derivatives(x: &[f64], values: &[ComplexParts]) -> Vec<ComplexParts> {
    if values.len() == 2 {
        let slope = values[1].minus(values[0]).scale(1.0 / (x[1] - x[0]));
        return vec![slope, slope];
    }
    if values.len() == 3 {
        return (0..3)
            .map(|index| {
                let x_i = x[index];
                let mut derivative = ComplexParts::zero();
                for source in 0..3 {
                    let x_k = x[source];
                    let y_k = values[source];
                    let mut sum = 0.0;
                    for other in 0..3 {
                        if other == source {
                            continue;
                        }
                        let x_j = x[other];
                        let mut term = 1.0 / (x_k - x_j);
                        for remaining in 0..3 {
                            if remaining == source || remaining == other {
                                continue;
                            }
                            let x_m = x[remaining];
                            term *= (x_i - x_m) / (x_k - x_m);
                        }
                        sum += term;
                    }
                    derivative = derivative.plus(y_k.scale(sum));
                }
                derivative
            })
            .collect();
    }

    let h = x
        .windows(2)
        .map(|window| window[1] - window[0])
        .collect::<Vec<_>>();
    let delta = values
        .windows(2)
        .zip(h.iter())
        .map(|(window, step)| window[1].minus(window[0]).scale(1.0 / *step))
        .collect::<Vec<_>>();
    let n = values.len();
    let mut matrix = vec![vec![0.0; n]; n];
    let mut rhs = vec![ComplexParts::zero(); n];

    matrix[0][0] = 1.0 / (h[0] * h[0]);
    matrix[0][1] = (1.0 / (h[0] * h[0])) - (1.0 / (h[1] * h[1]));
    matrix[0][2] = -1.0 / (h[1] * h[1]);
    rhs[0] = delta[0]
        .scale(2.0 / (h[0] * h[0]))
        .minus(delta[1].scale(2.0 / (h[1] * h[1])));

    for row in 1..n - 1 {
        matrix[row][row - 1] = 1.0 / h[row - 1];
        matrix[row][row] = 2.0 / h[row - 1] + 2.0 / h[row];
        matrix[row][row + 1] = 1.0 / h[row];
        rhs[row] = delta[row - 1]
            .scale(3.0 / h[row - 1])
            .plus(delta[row].scale(3.0 / h[row]));
    }

    matrix[n - 1][n - 3] = 1.0 / (h[n - 3] * h[n - 3]);
    matrix[n - 1][n - 2] = (1.0 / (h[n - 3] * h[n - 3])) - (1.0 / (h[n - 2] * h[n - 2]));
    matrix[n - 1][n - 1] = -1.0 / (h[n - 2] * h[n - 2]);
    rhs[n - 1] = delta[n - 3]
        .scale(2.0 / (h[n - 3] * h[n - 3]))
        .minus(delta[n - 2].scale(2.0 / (h[n - 2] * h[n - 2])));

    solve_dense_linear_system_complex_rhs(matrix, rhs, "interp1 spline derivative system")
        .expect("strictly monotonic spline system should be nonsingular")
}

fn makima_derivatives(x: &[f64], values: &[ComplexParts]) -> Vec<ComplexParts> {
    let real_values = values.iter().map(|value| value.real).collect::<Vec<_>>();
    let imag_values = values.iter().map(|value| value.imag).collect::<Vec<_>>();
    let real_derivatives = makima_real_derivatives(x, &real_values);
    let imag_derivatives = makima_real_derivatives(x, &imag_values);
    real_derivatives
        .into_iter()
        .zip(imag_derivatives)
        .map(|(real, imag)| ComplexParts { real, imag })
        .collect()
}

fn makima_real_derivatives(x: &[f64], values: &[f64]) -> Vec<f64> {
    if values.len() == 2 {
        let slope = (values[1] - values[0]) / (x[1] - x[0]);
        return vec![slope, slope];
    }

    let slopes = x
        .windows(2)
        .zip(values.windows(2))
        .map(|(x_window, value_window)| {
            (value_window[1] - value_window[0]) / (x_window[1] - x_window[0])
        })
        .collect::<Vec<_>>();
    let extended = extended_interval_slopes(&slopes);
    (0..values.len())
        .map(|index| {
            let slope_im2 = extended[index];
            let slope_im1 = extended[index + 1];
            let slope_i = extended[index + 2];
            let slope_ip1 = extended[index + 3];
            let w1 = (slope_ip1 - slope_i).abs() + 0.5 * (slope_ip1 + slope_i).abs();
            let w2 = (slope_im1 - slope_im2).abs() + 0.5 * (slope_im1 + slope_im2).abs();
            let denominator = w1 + w2;
            if approx_equal(denominator, 0.0) {
                0.5 * (slope_im1 + slope_i)
            } else {
                ((w1 * slope_im1) + (w2 * slope_i)) / denominator
            }
        })
        .collect()
}

fn extended_interval_slopes(slopes: &[f64]) -> Vec<f64> {
    debug_assert!(slopes.len() >= 2);
    let left_one = 2.0 * slopes[0] - slopes[1];
    let left_two = 2.0 * left_one - slopes[0];
    let right_one = 2.0 * slopes[slopes.len() - 1] - slopes[slopes.len() - 2];
    let right_two = 2.0 * right_one - slopes[slopes.len() - 1];
    let mut extended = Vec::with_capacity(slopes.len() + 4);
    extended.push(left_two);
    extended.push(left_one);
    extended.extend_from_slice(slopes);
    extended.push(right_one);
    extended.push(right_two);
    extended
}

fn pchip_endpoint_derivative(h0: f64, h1: f64, delta0: f64, delta1: f64) -> f64 {
    let derivative = (((2.0 * h0) + h1) * delta0 - h0 * delta1) / (h0 + h1);
    if !same_sign(derivative, delta0) {
        0.0
    } else if !same_sign(delta0, delta1) && derivative.abs() > 3.0 * delta0.abs() {
        3.0 * delta0
    } else {
        derivative
    }
}

fn same_sign(lhs: f64, rhs: f64) -> bool {
    (lhs > 0.0 && rhs > 0.0) || (lhs < 0.0 && rhs < 0.0)
}

fn interp2_value(
    x_query: f64,
    y_query: f64,
    x: &[f64],
    y: &[f64],
    v: &NumericOrComplexOperand,
    method: InterpolationMethod,
    extrapolation: Interp2Extrapolation,
    nan_output: ComplexParts,
) -> ComplexParts {
    if !x_query.is_finite() || !y_query.is_finite() {
        return nan_output;
    }
    match method {
        InterpolationMethod::Linear => {
            let Some((x_index, x_weight)) = locate_interp_interval(x_query, x) else {
                return match extrapolation {
                    Interp2Extrapolation::Nan => nan_output,
                    Interp2Extrapolation::Fill(value) => value,
                };
            };
            let Some((y_index, y_weight)) = locate_interp_interval(y_query, y) else {
                return match extrapolation {
                    Interp2Extrapolation::Nan => nan_output,
                    Interp2Extrapolation::Fill(value) => value,
                };
            };
            let v00 = v.values[y_index * v.cols + x_index];
            let v01 = v.values[y_index * v.cols + x_index + 1];
            let v10 = v.values[(y_index + 1) * v.cols + x_index];
            let v11 = v.values[(y_index + 1) * v.cols + x_index + 1];
            let top = v00.plus(v01.minus(v00).times(ComplexParts {
                real: x_weight,
                imag: 0.0,
            }));
            let bottom = v10.plus(v11.minus(v10).times(ComplexParts {
                real: x_weight,
                imag: 0.0,
            }));
            top.plus(bottom.minus(top).times(ComplexParts {
                real: y_weight,
                imag: 0.0,
            }))
        }
        InterpolationMethod::Nearest => {
            let Some((x_index, x_weight)) = locate_interp_interval(x_query, x) else {
                return match extrapolation {
                    Interp2Extrapolation::Nan => nan_output,
                    Interp2Extrapolation::Fill(value) => value,
                };
            };
            let Some((y_index, y_weight)) = locate_interp_interval(y_query, y) else {
                return match extrapolation {
                    Interp2Extrapolation::Nan => nan_output,
                    Interp2Extrapolation::Fill(value) => value,
                };
            };
            let nearest_col = if x_weight <= 0.5 {
                x_index
            } else {
                x_index + 1
            };
            let nearest_row = if y_weight <= 0.5 {
                y_index
            } else {
                y_index + 1
            };
            v.values[nearest_row * v.cols + nearest_col]
        }
        InterpolationMethod::Cubic
        | InterpolationMethod::V5Cubic
        | InterpolationMethod::Spline
        | InterpolationMethod::Makima => interp2_tensor_product_value(
            x_query,
            y_query,
            x,
            y,
            v,
            method,
            interp_nd_extrapolation_to_interp1(method, extrapolation),
            nan_output,
        ),
        InterpolationMethod::Previous | InterpolationMethod::Next | InterpolationMethod::Pchip => {
            unreachable!(
                "interp2 method parsing rejects previous/next/pchip/cubic/v5cubic/spline/makima"
            )
        }
    }
}

fn interp_nd_extrapolation_to_interp1(
    method: InterpolationMethod,
    extrapolation: Interp2Extrapolation,
) -> Interp1Extrapolation {
    match extrapolation {
        Interp2Extrapolation::Fill(value) => Interp1Extrapolation::Fill(value),
        Interp2Extrapolation::Nan => match method {
            InterpolationMethod::Spline | InterpolationMethod::Makima => {
                Interp1Extrapolation::Extrapolate
            }
            _ => Interp1Extrapolation::Nan,
        },
    }
}

fn interpn_tensor_value(
    queries: &[f64],
    axes: &[Vec<f64>],
    values: &[ComplexParts],
    dims: &[usize],
    method: InterpolationMethod,
    extrapolation: Interp1Extrapolation,
    nan_output: ComplexParts,
) -> ComplexParts {
    debug_assert_eq!(queries.len(), axes.len());
    debug_assert_eq!(axes.len(), dims.len());
    if axes.len() == 1 {
        return interp1_value(
            queries[0],
            &axes[0],
            values,
            method,
            extrapolation,
            nan_output,
        );
    }

    let axis_len = dims[0];
    let rest_dims = &dims[1..];
    let sequence_count = rest_dims.iter().product::<usize>();
    let mut intermediate = Vec::with_capacity(sequence_count);
    for sequence in 0..sequence_count {
        let rest_index = row_major_multi_index(sequence, rest_dims);
        let mut line = Vec::with_capacity(axis_len);
        for axis_index in 0..axis_len {
            let mut full_index = Vec::with_capacity(dims.len());
            full_index.push(axis_index);
            full_index.extend_from_slice(&rest_index);
            line.push(values[row_major_linear_index(&full_index, dims)]);
        }
        intermediate.push(interp1_value(
            queries[0],
            &axes[0],
            &line,
            method,
            extrapolation,
            nan_output,
        ));
    }
    interpn_tensor_value(
        &queries[1..],
        &axes[1..],
        &intermediate,
        rest_dims,
        method,
        extrapolation,
        nan_output,
    )
}

fn interp2_tensor_product_value(
    x_query: f64,
    y_query: f64,
    x: &[f64],
    y: &[f64],
    v: &NumericOrComplexOperand,
    method: InterpolationMethod,
    extrapolation: Interp1Extrapolation,
    nan_output: ComplexParts,
) -> ComplexParts {
    let mut intermediate = Vec::with_capacity(v.cols);
    for col in 0..v.cols {
        let column = (0..v.rows)
            .map(|row| v.values[row * v.cols + col])
            .collect::<Vec<_>>();
        intermediate.push(interp1_value(
            y_query,
            y,
            &column,
            method,
            extrapolation,
            nan_output,
        ));
    }
    interp1_value(x_query, x, &intermediate, method, extrapolation, nan_output)
}

fn locate_interp_interval(query: f64, axis: &[f64]) -> Option<(usize, f64)> {
    if !query.is_finite() || axis.len() < 2 || query < axis[0] || query > axis[axis.len() - 1] {
        return None;
    }
    if (query - axis[axis.len() - 1]).abs() <= f64::EPSILON {
        return Some((axis.len() - 2, 1.0));
    }

    axis.windows(2)
        .position(|window| query >= window[0] && query < window[1])
        .map(|index| {
            let start = axis[index];
            let end = axis[index + 1];
            (index, (query - start) / (end - start))
        })
}

fn interp2_grid_vectors(
    x_value: &Value,
    y_value: &Value,
    rows: usize,
    cols: usize,
) -> Result<(Vec<f64>, Vec<f64>), RuntimeError> {
    let x = numeric_operand(x_value, "interp2")?;
    let y = numeric_operand(y_value, "interp2")?;

    if (x.rows == 1 || x.cols == 1) && (y.rows == 1 || y.cols == 1) {
        if x.values.len() != cols || y.values.len() != rows {
            return Err(RuntimeError::ShapeError(format!(
                "interp2 requires X and Y vectors with lengths matching V columns ({}) and rows ({})",
                cols, rows
            )));
        }
        return Ok((x.values, y.values));
    }

    if x.rows != rows || x.cols != cols || y.rows != rows || y.cols != cols {
        return Err(RuntimeError::ShapeError(
            "interp2 currently expects X and Y to be vectors or meshgrid-style matrices matching V"
                .to_string(),
        ));
    }

    Ok((
        interp2_grid_axis_from_matrix(&x, "X")?,
        interp2_grid_axis_from_matrix(&y, "Y")?,
    ))
}

fn interp2_grid_axis_from_matrix(
    grid: &NumericOperand,
    axis_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    match axis_name {
        "X" => {
            let axis = grid.values[..grid.cols].to_vec();
            for row in 1..grid.rows {
                for col in 0..grid.cols {
                    if !approx_equal(grid.values[row * grid.cols + col], axis[col]) {
                        return Err(RuntimeError::ShapeError(
                            "interp2 currently expects matrix X input to be meshgrid-style with constant columns"
                                .to_string(),
                        ));
                    }
                }
            }
            Ok(axis)
        }
        "Y" => {
            let axis = (0..grid.rows)
                .map(|row| grid.values[row * grid.cols])
                .collect::<Vec<_>>();
            for row in 0..grid.rows {
                for col in 1..grid.cols {
                    if !approx_equal(grid.values[row * grid.cols + col], axis[row]) {
                        return Err(RuntimeError::ShapeError(
                            "interp2 currently expects matrix Y input to be meshgrid-style with constant rows"
                                .to_string(),
                        ));
                    }
                }
            }
            Ok(axis)
        }
        _ => unreachable!("interp2 axis name is X or Y"),
    }
}

fn broadcast_interp2_queries(
    xq: InterpQueryOperand,
    yq: InterpQueryOperand,
) -> Result<(InterpQueryOperand, InterpQueryOperand), RuntimeError> {
    if xq.dims == yq.dims && xq.values.len() == yq.values.len() {
        return Ok((xq, yq));
    }
    if xq.values.len() == 1 {
        return Ok((
            scalar_expanded_query_operand(&xq, yq.dims.clone(), yq.values.len()),
            yq,
        ));
    }
    if yq.values.len() == 1 {
        let target_dims = xq.dims.clone();
        let target_len = xq.values.len();
        return Ok((
            xq,
            scalar_expanded_query_operand(&yq, target_dims, target_len),
        ));
    }
    if query_vector_orientation(&xq)
        .zip(query_vector_orientation(&yq))
        .map(|(x_orientation, y_orientation)| x_orientation != y_orientation)
        .unwrap_or(false)
    {
        return Ok(meshgrid_query_operands(xq, yq));
    }

    Err(RuntimeError::ShapeError(
        "interp2 requires XQ and YQ to have matching shapes, be scalar-expanded, or be vectors with different orientations".to_string(),
    ))
}

fn scalar_expanded_query_operand(
    value: &InterpQueryOperand,
    dims: Vec<usize>,
    count: usize,
) -> InterpQueryOperand {
    InterpQueryOperand {
        dims,
        values: vec![value.values[0]; count],
    }
}

fn query_vector_orientation(value: &InterpQueryOperand) -> Option<bool> {
    match value.dims.as_slice() {
        [1, _] => Some(true),
        [_, 1] => Some(false),
        _ => None,
    }
}

fn meshgrid_query_operands(
    xq: InterpQueryOperand,
    yq: InterpQueryOperand,
) -> (InterpQueryOperand, InterpQueryOperand) {
    let rows = yq.values.len();
    let cols = xq.values.len();
    let mut x_values = Vec::with_capacity(rows * cols);
    let mut y_values = Vec::with_capacity(rows * cols);
    for y_value in &yq.values {
        for x_value in &xq.values {
            x_values.push(*x_value);
            y_values.push(*y_value);
        }
    }
    (
        InterpQueryOperand {
            dims: vec![rows, cols],
            values: x_values,
        },
        InterpQueryOperand {
            dims: vec![rows, cols],
            values: y_values,
        },
    )
}

fn flip_complex_operand_columns(value: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for row in 0..value.rows {
        for col in (0..value.cols).rev() {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOrComplexOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    }
}

fn flip_numeric_operand_columns(value: &NumericOperand) -> NumericOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for row in 0..value.rows {
        for col in (0..value.cols).rev() {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    }
}

fn flip_complex_operand_rows(value: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for row in (0..value.rows).rev() {
        for col in 0..value.cols {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOrComplexOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    }
}

fn flip_numeric_operand_rows(value: &NumericOperand) -> NumericOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for row in (0..value.rows).rev() {
        for col in 0..value.cols {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    }
}

fn approx_equal(lhs: f64, rhs: f64) -> bool {
    (lhs - rhs).abs() <= f64::EPSILON
}

fn numeric_operand(value: &Value, builtin_name: &str) -> Result<NumericOperand, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) => Ok(NumericOperand {
            rows: 1,
            cols: 1,
            values: vec![value.as_scalar()?],
        }),
        Value::Matrix(matrix) => {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()
                .map_err(|_| {
                    RuntimeError::TypeError(format!(
                        "{builtin_name} currently expects numeric or logical scalar/matrix inputs"
                    ))
                })?;
            Ok(NumericOperand {
                rows: matrix.rows,
                cols: matrix.cols,
                values,
            })
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or logical scalar/matrix inputs"
        ))),
    }
}

fn parse_accumarray_subscripts(value: &Value) -> Result<AccumarraySubscripts, RuntimeError> {
    let matrix = coerce_matrix(value)?;
    if matrix.rows == 0 || matrix.cols == 0 {
        return Err(RuntimeError::ShapeError(
            "accumarray currently requires at least one subscript".to_string(),
        ));
    }

    if matrix.rows == 1 || matrix.cols == 1 {
        let entries = matrix
            .iter()
            .map(|element| Ok(vec![positive_integer_scalar(element, "accumarray")?]))
            .collect::<Result<Vec<_>, RuntimeError>>()?;
        return Ok(AccumarraySubscripts { dims: 1, entries });
    }

    let mut entries = Vec::with_capacity(matrix.rows);
    for row in 0..matrix.rows {
        let mut components = Vec::with_capacity(matrix.cols);
        for col in 0..matrix.cols {
            components.push(positive_integer_scalar(matrix.get(row, col), "accumarray")?);
        }
        entries.push(components);
    }
    Ok(AccumarraySubscripts {
        dims: matrix.cols,
        entries,
    })
}

fn parse_accumarray_values(value: &Value, count: usize) -> Result<Vec<f64>, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(vec![*number; count]),
        _ => {
            let values = meshgrid_vector(value)?;
            if values.len() != count {
                return Err(RuntimeError::ShapeError(format!(
                    "accumarray requires VALS to have {} element(s) or be scalar-expanded, found {}",
                    count,
                    values.len()
                )));
            }
            Ok(values)
        }
    }
}

fn parse_accumarray_args(
    args: &[Value],
) -> Result<(&Value, &Value, Option<&Value>, AccumarrayReducer, f64), RuntimeError> {
    let (subscripts, values, requested_size, reducer, fill_value) = match args {
        [subscripts, values] => (subscripts, values, None, AccumarrayReducer::Sum, 0.0),
        [subscripts, values, size] => {
            (subscripts, values, Some(size), AccumarrayReducer::Sum, 0.0)
        }
        [subscripts, values, size, reducer] => (
            subscripts,
            values,
            Some(size),
            parse_accumarray_reducer_or_default(reducer)?,
            0.0,
        ),
        [subscripts, values, size, reducer, fill_value] => (
            subscripts,
            values,
            Some(size),
            parse_accumarray_reducer_or_default(reducer)?,
            parse_accumarray_fill_value(fill_value)?,
        ),
        [subscripts, values, size, reducer, fill_value, _issparse] => (
            subscripts,
            values,
            Some(size),
            parse_accumarray_reducer_or_default(reducer)?,
            parse_accumarray_fill_value(fill_value)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(
                "accumarray currently supports `accumarray(subs, vals)`, `accumarray(subs, vals, sz)`, `accumarray(subs, vals, sz, fun)`, `accumarray(subs, vals, sz, fun, fillval)`, or those forms with a trailing issparse flag"
                    .to_string(),
            ))
        }
    };
    if args.len() == 6 {
        parse_accumarray_sparse_flag(&args[5])?;
    }

    Ok((
        subscripts,
        values,
        requested_size.filter(|size| !accumarray_omitted_size(size)),
        reducer,
        fill_value,
    ))
}

fn parse_accumarray_reducer_or_default(value: &Value) -> Result<AccumarrayReducer, RuntimeError> {
    if is_empty_matrix_placeholder(value) {
        Ok(AccumarrayReducer::Sum)
    } else {
        parse_accumarray_reducer(value)
    }
}

fn parse_accumarray_reducer(value: &Value) -> Result<AccumarrayReducer, RuntimeError> {
    let reducer_name = match value {
        Value::FunctionHandle(handle) => handle.display_name.as_str(),
        _ => text_value(value)?,
    };

    match reducer_name.to_ascii_lowercase().as_str() {
        "sum" => Ok(AccumarrayReducer::Sum),
        "max" => Ok(AccumarrayReducer::Max),
        "min" => Ok(AccumarrayReducer::Min),
        "mean" => Ok(AccumarrayReducer::Mean),
        "prod" => Ok(AccumarrayReducer::Prod),
        "any" => Ok(AccumarrayReducer::Any),
        "all" => Ok(AccumarrayReducer::All),
        "var" => Ok(AccumarrayReducer::Var),
        "std" => Ok(AccumarrayReducer::Std),
        "length" => Ok(AccumarrayReducer::Length),
        "nnz" => Ok(AccumarrayReducer::Nnz),
        "median" => Ok(AccumarrayReducer::Median),
        "mode" => Ok(AccumarrayReducer::Mode),
        other => Err(RuntimeError::Unsupported(format!(
            "accumarray currently supports only `sum`, `max`, `min`, `mean`, `prod`, `any`, `all`, `var`, `std`, `length`, `nnz`, `median`, or `mode` reducers, found `{other}`"
        ))),
    }
}

fn parse_accumarray_fill_value(value: &Value) -> Result<f64, RuntimeError> {
    if is_empty_matrix_placeholder(value) {
        Ok(0.0)
    } else {
        value.as_scalar()
    }
}

fn parse_accumarray_sparse_flag(value: &Value) -> Result<(), RuntimeError> {
    let sparse = match value {
        Value::Logical(flag) => *flag,
        _ => {
            let scalar = value.as_scalar()?;
            if !scalar.is_finite() || scalar.fract() != 0.0 || !(scalar == 0.0 || scalar == 1.0) {
                return Err(RuntimeError::TypeError(
                    "accumarray currently expects the issparse flag to be a logical or 0/1 scalar"
                        .to_string(),
                ));
            }
            scalar != 0.0
        }
    };
    if sparse {
        return Err(RuntimeError::Unsupported(
            "accumarray sparse outputs are not yet supported".to_string(),
        ));
    }
    Ok(())
}

fn accumarray_omitted_size(value: &Value) -> bool {
    matches!(value, Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0)
}

fn accumarray_size(
    subs: &AccumarraySubscripts,
    requested_size: Option<&Value>,
) -> Result<Vec<usize>, RuntimeError> {
    let mut inferred_dims = vec![1usize; subs.dims.max(1)];
    for entry in &subs.entries {
        for (axis, &component) in entry.iter().enumerate() {
            inferred_dims[axis] = inferred_dims[axis].max(component);
        }
    }

    match requested_size {
        None => {
            if subs.dims == 1 {
                Ok(vec![inferred_dims[0], 1])
            } else {
                Ok(inferred_dims)
            }
        }
        Some(size) if subs.dims == 1 => {
            let requested = meshgrid_vector(size)?;
            let rows = match requested.len() {
                1 => positive_integer_scalar(size, "accumarray")?,
                2 if positive_integer_scalar(&Value::Scalar(requested[1]), "accumarray")? == 1 => {
                    positive_integer_scalar(&Value::Scalar(requested[0]), "accumarray")?
                }
                _ => {
                    return Err(RuntimeError::ShapeError(
                        "accumarray currently expects a scalar size or [n, 1] size vector for one-dimensional subscripts".to_string(),
                    ))
                }
            };
            Ok(vec![rows, 1])
        }
        Some(size) => {
            let requested = meshgrid_vector(size)?;
            if requested.len() != subs.dims {
                return Err(RuntimeError::ShapeError(
                    format!(
                        "accumarray currently expects a {}-element size vector for {}-dimensional subscripts",
                        subs.dims, subs.dims
                    ),
                ));
            }
            requested
                .into_iter()
                .map(|dimension| positive_integer_scalar(&Value::Scalar(dimension), "accumarray"))
                .collect()
        }
    }
}

impl AccumarrayReducer {
    fn logical_output(self) -> bool {
        matches!(self, Self::Any | Self::All)
    }

    fn reduce(self, values: &[f64], fill_value: f64) -> f64 {
        if values.is_empty() {
            return fill_value;
        }

        match self {
            Self::Sum => values.iter().sum(),
            Self::Max => values.iter().copied().fold(f64::NEG_INFINITY, f64::max),
            Self::Min => values.iter().copied().fold(f64::INFINITY, f64::min),
            Self::Mean => values.iter().sum::<f64>() / values.len() as f64,
            Self::Prod => values.iter().product(),
            Self::Any => {
                if values.iter().any(|value| *value != 0.0) {
                    1.0
                } else {
                    0.0
                }
            }
            Self::All => {
                if values.iter().all(|value| *value != 0.0) {
                    1.0
                } else {
                    0.0
                }
            }
            Self::Var => variance_with_normalization(values, VarianceNormalization::Sample),
            Self::Std => variance_with_normalization(values, VarianceNormalization::Sample).sqrt(),
            Self::Length => values.len() as f64,
            Self::Nnz => values.iter().filter(|value| **value != 0.0).count() as f64,
            Self::Median => median_of_values(values),
            Self::Mode => mode_of_values(values),
        }
    }
}

fn diff_numeric_or_complex_operand_once(
    value: &NumericOrComplexOperand,
    dim: usize,
) -> NumericOrComplexOperand {
    match dim {
        1 => {
            if value.rows <= 1 {
                return NumericOrComplexOperand {
                    rows: 0,
                    cols: value.cols,
                    values: Vec::new(),
                };
            }

            let mut values = Vec::with_capacity((value.rows - 1) * value.cols);
            for row in 0..(value.rows - 1) {
                for col in 0..value.cols {
                    let lhs = value.values[row * value.cols + col];
                    let rhs = value.values[(row + 1) * value.cols + col];
                    values.push(rhs.minus(lhs));
                }
            }
            NumericOrComplexOperand {
                rows: value.rows - 1,
                cols: value.cols,
                values,
            }
        }
        2 => {
            if value.cols <= 1 {
                return NumericOrComplexOperand {
                    rows: value.rows,
                    cols: 0,
                    values: Vec::new(),
                };
            }

            let mut values = Vec::with_capacity(value.rows * (value.cols - 1));
            for row in 0..value.rows {
                for col in 0..(value.cols - 1) {
                    let lhs = value.values[row * value.cols + col];
                    let rhs = value.values[row * value.cols + col + 1];
                    values.push(rhs.minus(lhs));
                }
            }
            NumericOrComplexOperand {
                rows: value.rows,
                cols: value.cols - 1,
                values,
            }
        }
        _ => unreachable!("diff dimensions are restricted earlier"),
    }
}

fn diff_numeric_or_complex_operand_once_with_dimensions(
    value: &NumericOrComplexOperand,
    dims: &[usize],
    dim: usize,
) -> (NumericOrComplexOperand, Vec<usize>) {
    let mut input_dims = dims.to_vec();
    while input_dims.len() < dim {
        input_dims.push(1);
    }
    let axis = dim - 1;
    if input_dims[axis] <= 1 {
        let mut output_dims = input_dims;
        output_dims[axis] = 0;
        let (rows, cols) = storage_shape_from_dimensions(&output_dims);
        return (
            NumericOrComplexOperand {
                rows,
                cols,
                values: Vec::new(),
            },
            output_dims,
        );
    }

    let mut output_dims = input_dims.clone();
    output_dims[axis] -= 1;
    let output_len = output_dims.iter().product::<usize>();
    let mut values = Vec::with_capacity(output_len);
    for linear in 0..output_len {
        let mut index = row_major_multi_index(linear, &output_dims);
        let lhs = value.values[row_major_linear_index(&index, &input_dims)];
        index[axis] += 1;
        let rhs = value.values[row_major_linear_index(&index, &input_dims)];
        values.push(rhs.minus(lhs));
    }
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    (NumericOrComplexOperand { rows, cols, values }, output_dims)
}

fn parse_convolution_shape(
    value: &Value,
    builtin_name: &str,
) -> Result<ConvolutionShape, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "full" => Ok(ConvolutionShape::Full),
        "same" => Ok(ConvolutionShape::Same),
        "valid" => Ok(ConvolutionShape::Valid),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports only `full`, `same`, or `valid` shapes"
        ))),
    }
}

fn convolution_vector_operand(
    value: &Value,
    builtin_name: &str,
) -> Result<(NumericOrComplexOperand, bool), RuntimeError> {
    let operand = numeric_or_complex_operand(value, builtin_name)?;
    if operand.rows != 1 && operand.cols != 1 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or complex vector inputs"
        )));
    }
    Ok((operand.clone(), operand.rows == 1))
}

fn full_complex_convolution_vector(
    lhs: &[ComplexParts],
    rhs: &[ComplexParts],
) -> Vec<ComplexParts> {
    let mut values = vec![ComplexParts::zero(); lhs.len() + rhs.len() - 1];
    for (lhs_index, lhs_value) in lhs.iter().copied().enumerate() {
        for (rhs_index, rhs_value) in rhs.iter().copied().enumerate() {
            values[lhs_index + rhs_index] =
                values[lhs_index + rhs_index].plus(lhs_value.times(rhs_value));
        }
    }
    values.into_iter().map(normalize_complex_parts).collect()
}

fn crop_complex_convolution_vector(
    values: &[ComplexParts],
    lhs_len: usize,
    rhs_len: usize,
    shape: ConvolutionShape,
) -> Vec<ComplexParts> {
    match shape {
        ConvolutionShape::Full => values.to_vec(),
        ConvolutionShape::Same => {
            let start = (rhs_len.saturating_sub(1)) / 2;
            values[start..start + lhs_len].to_vec()
        }
        ConvolutionShape::Valid => {
            let start = lhs_len.min(rhs_len).saturating_sub(1);
            let len = lhs_len.max(rhs_len) - lhs_len.min(rhs_len) + 1;
            values[start..start + len].to_vec()
        }
    }
}

fn full_complex_convolution_matrix(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
) -> NumericOrComplexOperand {
    let rows = lhs.rows + rhs.rows - 1;
    let cols = lhs.cols + rhs.cols - 1;
    let mut values = vec![ComplexParts::zero(); rows * cols];
    for lhs_row in 0..lhs.rows {
        for lhs_col in 0..lhs.cols {
            let lhs_value = lhs.values[lhs_row * lhs.cols + lhs_col];
            for rhs_row in 0..rhs.rows {
                for rhs_col in 0..rhs.cols {
                    let offset = (lhs_row + rhs_row) * cols + (lhs_col + rhs_col);
                    values[offset] = values[offset]
                        .plus(lhs_value.times(rhs.values[rhs_row * rhs.cols + rhs_col]));
                }
            }
        }
    }
    NumericOrComplexOperand {
        rows,
        cols,
        values: values.into_iter().map(normalize_complex_parts).collect(),
    }
}

fn crop_complex_convolution_matrix(
    values: &NumericOrComplexOperand,
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    shape: ConvolutionShape,
) -> NumericOrComplexOperand {
    match shape {
        ConvolutionShape::Full => values.clone(),
        ConvolutionShape::Same => slice_numeric_or_complex_operand(
            values,
            (rhs.rows.saturating_sub(1)) / 2,
            (rhs.cols.saturating_sub(1)) / 2,
            lhs.rows,
            lhs.cols,
        ),
        ConvolutionShape::Valid => slice_numeric_or_complex_operand(
            values,
            lhs.rows.min(rhs.rows).saturating_sub(1),
            lhs.cols.min(rhs.cols).saturating_sub(1),
            lhs.rows.max(rhs.rows) - lhs.rows.min(rhs.rows) + 1,
            lhs.cols.max(rhs.cols) - lhs.cols.min(rhs.cols) + 1,
        ),
    }
}

fn full_complex_convolution_nd(
    lhs: &NumericOrComplexNdOperand,
    rhs: &NumericOrComplexNdOperand,
) -> NumericOrComplexNdOperand {
    let dims = lhs
        .dims
        .iter()
        .zip(rhs.dims.iter())
        .map(|(lhs_dim, rhs_dim)| lhs_dim + rhs_dim - 1)
        .collect::<Vec<_>>();
    let mut values = vec![ComplexParts::zero(); dims.iter().product()];
    for lhs_linear in 0..lhs.values.len() {
        let lhs_index = row_major_multi_index(lhs_linear, &lhs.dims);
        let lhs_value = lhs.values[lhs_linear];
        for rhs_linear in 0..rhs.values.len() {
            let rhs_index = row_major_multi_index(rhs_linear, &rhs.dims);
            let output_index = lhs_index
                .iter()
                .zip(rhs_index.iter())
                .map(|(lhs_axis, rhs_axis)| lhs_axis + rhs_axis)
                .collect::<Vec<_>>();
            let output_linear = row_major_linear_index(&output_index, &dims);
            values[output_linear] =
                values[output_linear].plus(lhs_value.times(rhs.values[rhs_linear]));
        }
    }
    NumericOrComplexNdOperand {
        dims,
        values: values.into_iter().map(normalize_complex_parts).collect(),
    }
}

fn crop_complex_convolution_nd(
    values: &NumericOrComplexNdOperand,
    lhs: &NumericOrComplexNdOperand,
    rhs: &NumericOrComplexNdOperand,
    shape: ConvolutionShape,
) -> NumericOrComplexNdOperand {
    match shape {
        ConvolutionShape::Full => NumericOrComplexNdOperand {
            dims: values.dims.clone(),
            values: values.values.clone(),
        },
        ConvolutionShape::Same => slice_numeric_or_complex_nd_operand(
            values,
            &rhs.dims
                .iter()
                .map(|dim| dim.saturating_sub(1) / 2)
                .collect::<Vec<_>>(),
            &lhs.dims,
        ),
        ConvolutionShape::Valid => {
            let start = lhs
                .dims
                .iter()
                .zip(rhs.dims.iter())
                .map(|(lhs_dim, rhs_dim)| lhs_dim.min(rhs_dim).saturating_sub(1))
                .collect::<Vec<_>>();
            let dims = lhs
                .dims
                .iter()
                .zip(rhs.dims.iter())
                .map(|(lhs_dim, rhs_dim)| lhs_dim.max(rhs_dim) - lhs_dim.min(rhs_dim) + 1)
                .collect::<Vec<_>>();
            slice_numeric_or_complex_nd_operand(values, &start, &dims)
        }
    }
}

fn slice_numeric_or_complex_nd_operand(
    value: &NumericOrComplexNdOperand,
    start: &[usize],
    dims: &[usize],
) -> NumericOrComplexNdOperand {
    let mut values = Vec::with_capacity(dims.iter().product());
    for linear in 0..dims.iter().product() {
        let index = row_major_multi_index(linear, dims);
        let source_index = index
            .iter()
            .enumerate()
            .map(|(axis, &value)| start[axis] + value)
            .collect::<Vec<_>>();
        values.push(value.values[row_major_linear_index(&source_index, &value.dims)]);
    }
    NumericOrComplexNdOperand {
        dims: dims.to_vec(),
        values,
    }
}

fn slice_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    start_row: usize,
    start_col: usize,
    rows: usize,
    cols: usize,
) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(rows * cols);
    for row in start_row..(start_row + rows) {
        for col in start_col..(start_col + cols) {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOrComplexOperand { rows, cols, values }
}

fn deconvolution_long_division(
    y: &[ComplexParts],
    h: &[ComplexParts],
) -> (Vec<ComplexParts>, Vec<ComplexParts>) {
    if h.len() > y.len() {
        return (vec![ComplexParts::zero()], y.to_vec());
    }

    let quotient_len = y.len() - h.len() + 1;
    let mut quotient = vec![ComplexParts::zero(); quotient_len];
    let mut remainder = y.to_vec();
    for index in 0..quotient_len {
        let value = normalize_complex_parts(remainder[index].rdivide(h[0]));
        quotient[index] = value;
        for offset in 0..h.len() {
            remainder[index + offset] =
                normalize_complex_parts(remainder[index + offset].minus(value.times(h[offset])));
        }
    }

    (
        quotient
            .into_iter()
            .map(normalize_complex_parts)
            .collect::<Vec<_>>(),
        remainder
            .into_iter()
            .map(normalize_complex_parts)
            .collect::<Vec<_>>(),
    )
}

fn complex_polynomial_compact_coefficients(values: &[ComplexParts]) -> Vec<ComplexParts> {
    let first_nonzero = values
        .iter()
        .position(|value| !value.is_approximately_zero())
        .unwrap_or(values.len().saturating_sub(1));
    let mut compact = values[first_nonzero..]
        .iter()
        .copied()
        .map(normalize_complex_parts)
        .collect::<Vec<_>>();
    if compact.is_empty() {
        compact.push(ComplexParts::zero());
    }
    compact
}

fn complex_polynomial_derivative_coefficients(values: &[ComplexParts]) -> Vec<ComplexParts> {
    let values = complex_polynomial_compact_coefficients(values);
    if values.len() <= 1 {
        return vec![ComplexParts::zero()];
    }

    let degree = values.len() - 1;
    let derivative = values
        .iter()
        .take(values.len() - 1)
        .enumerate()
        .map(|(index, coefficient)| coefficient.scale((degree - index) as f64))
        .collect::<Vec<_>>();
    complex_polynomial_compact_coefficients(&derivative)
}

fn complex_polynomial_coefficients_from_roots(roots: &[ComplexParts]) -> Vec<ComplexParts> {
    let mut coefficients = vec![ComplexParts::one()];
    for root in roots {
        coefficients = full_complex_convolution_vector(
            &coefficients,
            &[
                ComplexParts::one(),
                normalize_complex_parts(ComplexParts::zero().minus(*root)),
            ],
        );
    }
    complex_polynomial_compact_coefficients(&coefficients)
}

fn complex_polynomial_roots(coefficients: &[ComplexParts]) -> Vec<ComplexParts> {
    let coefficients = complex_polynomial_compact_coefficients(coefficients);
    if coefficients.len() <= 1 {
        return Vec::new();
    }

    let mut roots = match coefficients.len() - 1 {
        1 => vec![ComplexParts::zero()
            .minus(coefficients[1])
            .rdivide(coefficients[0])],
        2 => quadratic_polynomial_roots(&coefficients),
        _ => durand_kerner_polynomial_roots(&coefficients),
    };
    roots.sort_by(|lhs, rhs| {
        rhs.real
            .total_cmp(&lhs.real)
            .then_with(|| rhs.imag.total_cmp(&lhs.imag))
    });
    roots.into_iter().map(normalize_complex_parts).collect()
}

fn quadratic_polynomial_roots(coefficients: &[ComplexParts]) -> Vec<ComplexParts> {
    let a = coefficients[0];
    let b = coefficients[1];
    let c = coefficients[2];
    let discriminant = b.times(b).minus(a.times(c).scale(4.0)).sqrt();
    let denominator = a.scale(2.0);
    let negative_b = ComplexParts::zero().minus(b);
    vec![
        negative_b.plus(discriminant).rdivide(denominator),
        negative_b.minus(discriminant).rdivide(denominator),
    ]
}

fn durand_kerner_polynomial_roots(coefficients: &[ComplexParts]) -> Vec<ComplexParts> {
    let degree = coefficients.len() - 1;
    let leading = coefficients[0];
    let monic = coefficients
        .iter()
        .copied()
        .map(|coefficient| coefficient.rdivide(leading))
        .collect::<Vec<_>>();
    let radius = 1.0
        + monic
            .iter()
            .skip(1)
            .map(|coefficient| coefficient.magnitude())
            .fold(0.0, f64::max);
    let mut roots = (0..degree)
        .map(|index| {
            let angle = 2.0 * std::f64::consts::PI * (index as f64 + 0.25) / degree as f64;
            ComplexParts {
                real: radius * angle.cos(),
                imag: radius * angle.sin(),
            }
        })
        .collect::<Vec<_>>();

    for _ in 0..2000 {
        let previous = roots.clone();
        let mut max_delta = 0.0_f64;
        for index in 0..degree {
            let mut denominator = ComplexParts::one();
            for other in 0..degree {
                if index != other {
                    denominator = denominator.times(previous[index].minus(previous[other]));
                }
            }
            if denominator.is_approximately_zero() {
                let nudge = 1e-8 * (index + 1) as f64;
                roots[index] = previous[index].plus(ComplexParts {
                    real: nudge,
                    imag: -nudge,
                });
                max_delta = max_delta.max(nudge);
                continue;
            }
            let delta = evaluate_complex_polynomial(&monic, previous[index]).rdivide(denominator);
            roots[index] = previous[index].minus(delta);
            max_delta = max_delta.max(delta.magnitude());
        }
        if max_delta <= 1e-12 {
            break;
        }
    }

    roots
}

fn complex_characteristic_polynomial_coefficients(
    matrix: &NumericOrComplexOperand,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    if matrix.rows != matrix.cols {
        return Err(RuntimeError::ShapeError(
            "poly currently expects a square matrix when given matrix input".to_string(),
        ));
    }

    let mut b = complex_identity_operand(matrix.rows);
    let mut coefficients = vec![ComplexParts::one()];
    for k in 1..=matrix.rows {
        let ab = complex_matrix_product(matrix, &b, "poly")?;
        let coefficient = normalize_complex_parts(complex_matrix_trace(&ab).scale(-1.0 / k as f64));
        coefficients.push(coefficient);
        b = complex_add_scaled_identity(&ab, coefficient)?;
    }
    Ok(coefficients)
}

fn evaluate_complex_matrix_polynomial(
    coefficients: &[ComplexParts],
    matrix: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if matrix.rows != matrix.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a square numeric or complex matrix input"
        )));
    }

    let mut result = complex_scaled_identity_operand(matrix.rows, coefficients[0]);
    for coefficient in coefficients.iter().skip(1) {
        result = complex_matrix_product(&result, matrix, builtin_name)?;
        result = complex_add_scaled_identity(&result, *coefficient)?;
    }
    Ok(result)
}

fn polynomial_least_squares_fit(
    x: &[f64],
    y: &[ComplexParts],
    degree: usize,
) -> Result<PolynomialLeastSquaresFit, RuntimeError> {
    let column_count = degree + 1;
    let vandermonde = x
        .iter()
        .map(|value| polynomial_vandermonde_row(*value, degree))
        .collect::<Vec<_>>();
    let (q_columns, r_factor) = polynomial_qr_factor(&vandermonde)?;
    let q_transpose_y = q_columns
        .iter()
        .map(|column| {
            column
                .iter()
                .zip(y.iter())
                .fold(ComplexParts::zero(), |total, (q, y)| {
                    total.plus(y.scale(*q))
                })
        })
        .collect::<Vec<_>>();
    let coefficients =
        solve_dense_linear_system_complex_rhs(r_factor.clone(), q_transpose_y, "polyfit")?;
    let fitted = vandermonde
        .iter()
        .map(|row| {
            row.iter()
                .zip(coefficients.iter())
                .fold(ComplexParts::zero(), |total, (entry, coefficient)| {
                    total.plus(coefficient.scale(*entry))
                })
        })
        .collect::<Vec<_>>();
    let residual_norm = y
        .iter()
        .zip(fitted.iter())
        .map(|(actual, fitted)| {
            let residual = actual.minus(*fitted);
            let magnitude = residual.magnitude();
            magnitude * magnitude
        })
        .sum::<f64>()
        .sqrt();
    let mean = y
        .iter()
        .copied()
        .fold(ComplexParts::zero(), |total, value| total.plus(value))
        .scale(1.0 / y.len() as f64);
    let total_sum_squares = y
        .iter()
        .map(|value| {
            let centered = value.minus(mean);
            let magnitude = centered.magnitude();
            magnitude * magnitude
        })
        .sum::<f64>();
    let residual_sum_squares = residual_norm * residual_norm;
    let rsquared = if approx_equal(total_sum_squares, 0.0) {
        if approx_equal(residual_sum_squares, 0.0) {
            1.0
        } else {
            0.0
        }
    } else {
        1.0 - residual_sum_squares / total_sum_squares
    };

    debug_assert_eq!(r_factor.len(), column_count);
    Ok(PolynomialLeastSquaresFit {
        coefficients,
        r_factor,
        degrees_of_freedom: x.len().saturating_sub(column_count),
        residual_norm: normalize_polynomial_scalar(residual_norm),
        rsquared: normalize_polynomial_scalar(rsquared),
    })
}

fn polynomial_vandermonde_row(x: f64, degree: usize) -> Vec<f64> {
    (0..=degree)
        .map(|index| x.powi((degree - index) as i32))
        .collect()
}

fn polynomial_qr_factor(
    vandermonde: &[Vec<f64>],
) -> Result<(Vec<Vec<f64>>, Vec<Vec<f64>>), RuntimeError> {
    let row_count = vandermonde.len();
    let column_count = vandermonde.first().map(|row| row.len()).unwrap_or(0);
    let mut q_columns = vec![vec![0.0; row_count]; column_count];
    let mut r_factor = vec![vec![0.0; column_count]; column_count];

    for column in 0..column_count {
        let mut vector = vandermonde
            .iter()
            .map(|row| row[column])
            .collect::<Vec<_>>();
        for previous in 0..column {
            let projection = q_columns[previous]
                .iter()
                .zip(vector.iter())
                .map(|(q, value)| q * value)
                .sum::<f64>();
            r_factor[previous][column] = normalize_polynomial_scalar(projection);
            for row in 0..row_count {
                vector[row] -= projection * q_columns[previous][row];
            }
        }
        let norm = vector.iter().map(|value| value * value).sum::<f64>().sqrt();
        if approx_equal(norm, 0.0) {
            return Err(RuntimeError::ShapeError(
                "polyfit currently requires a full-rank fit for the requested degree".to_string(),
            ));
        }
        r_factor[column][column] = normalize_polynomial_scalar(norm);
        for row in 0..row_count {
            q_columns[column][row] = vector[row] / norm;
        }
    }

    Ok((q_columns, r_factor))
}

fn parse_polyval_error_summary(value: &Value) -> Result<Option<PolyvalErrorSummary>, RuntimeError> {
    match value {
        Value::Struct(summary) => {
            let Some(r_value) = summary.fields.get("R") else {
                return Err(RuntimeError::MissingVariable(
                    "polyval currently expects `S.R` in the fitted summary struct".to_string(),
                ));
            };
            let Some(df_value) = summary.fields.get("df") else {
                return Err(RuntimeError::MissingVariable(
                    "polyval currently expects `S.df` in the fitted summary struct".to_string(),
                ));
            };
            let Some(normr_value) = summary.fields.get("normr") else {
                return Err(RuntimeError::MissingVariable(
                    "polyval currently expects `S.normr` in the fitted summary struct".to_string(),
                ));
            };

            let r_matrix = coerce_matrix(r_value)?;
            if r_matrix.rows != r_matrix.cols {
                return Err(RuntimeError::ShapeError(
                    "polyval currently expects `S.R` to be a square numeric matrix".to_string(),
                ));
            }

            let mut r_factor = Vec::with_capacity(r_matrix.rows);
            for row in 0..r_matrix.rows {
                let mut row_values = Vec::with_capacity(r_matrix.cols);
                for col in 0..r_matrix.cols {
                    row_values.push(r_matrix.get(row, col).as_scalar()?);
                }
                r_factor.push(row_values);
            }

            let df = df_value.as_scalar()?;
            if df < 0.0 || df.fract() != 0.0 {
                return Err(RuntimeError::TypeError(
                    "polyval currently expects `S.df` to be a nonnegative integer scalar"
                        .to_string(),
                ));
            }

            Ok(Some(PolyvalErrorSummary {
                r_factor,
                degrees_of_freedom: df as usize,
                residual_norm: normr_value.as_scalar()?,
            }))
        }
        Value::Matrix(matrix) if matrix.rows == 0 && matrix.cols == 0 => Ok(None),
        _ => Err(RuntimeError::TypeError(
            "polyval currently expects the third input to be a fitted summary struct or []"
                .to_string(),
        )),
    }
}

fn evaluate_complex_polynomial(coefficients: &[ComplexParts], point: ComplexParts) -> ComplexParts {
    coefficients
        .iter()
        .copied()
        .fold(ComplexParts::zero(), |total, coefficient| {
            normalize_complex_parts(total.times(point).plus(coefficient))
        })
}

fn polynomial_error_bounds(
    summary: &PolyvalErrorSummary,
    points: &[f64],
    degree: usize,
) -> Result<Vec<f64>, RuntimeError> {
    let scale = if summary.degrees_of_freedom == 0 {
        f64::NAN
    } else {
        summary.residual_norm / (summary.degrees_of_freedom as f64).sqrt()
    };
    points
        .iter()
        .map(|point| {
            let row = polynomial_vandermonde_row(*point, degree);
            let projection = solve_transposed_upper_for_row(&summary.r_factor, &row, "polyval")?;
            let variance = 1.0 + projection.iter().map(|value| value * value).sum::<f64>();
            Ok(normalize_polynomial_scalar(scale * variance.sqrt()))
        })
        .collect()
}

fn solve_transposed_upper_for_row(
    upper: &[Vec<f64>],
    row: &[f64],
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    let size = upper.len();
    let mut solution = vec![0.0; size];
    for index in 0..size {
        let mut total = row[index];
        for previous in 0..index {
            total -= upper[previous][index] * solution[previous];
        }
        let diagonal = upper[index][index];
        if approx_equal(diagonal, 0.0) {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently expects `S.R` to be nonsingular"
            )));
        }
        solution[index] = total / diagonal;
    }
    Ok(solution)
}

fn solve_dense_linear_system_complex_rhs(
    mut matrix: Vec<Vec<f64>>,
    mut rhs: Vec<ComplexParts>,
    builtin_name: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let size = rhs.len();
    for pivot in 0..size {
        let mut pivot_row = pivot;
        let mut pivot_value = matrix[pivot][pivot].abs();
        for row in pivot + 1..size {
            let candidate = matrix[row][pivot].abs();
            if candidate > pivot_value {
                pivot_row = row;
                pivot_value = candidate;
            }
        }

        if approx_equal(pivot_value, 0.0) {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently requires a full-rank fit for the requested degree"
            )));
        }

        if pivot_row != pivot {
            matrix.swap(pivot, pivot_row);
            rhs.swap(pivot, pivot_row);
        }

        let diagonal = matrix[pivot][pivot];
        for row in pivot + 1..size {
            let factor = matrix[row][pivot] / diagonal;
            matrix[row][pivot] = 0.0;
            for col in pivot + 1..size {
                matrix[row][col] -= factor * matrix[pivot][col];
            }
            rhs[row] = rhs[row].minus(rhs[pivot].scale(factor));
        }
    }

    let mut solution = vec![ComplexParts::zero(); size];
    for row in (0..size).rev() {
        let mut total = rhs[row];
        for col in row + 1..size {
            total = total.minus(solution[col].scale(matrix[row][col]));
        }
        let diagonal = matrix[row][row];
        if approx_equal(diagonal, 0.0) {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} currently requires a full-rank fit for the requested degree"
            )));
        }
        solution[row] = normalize_complex_parts(total.scale(1.0 / diagonal));
    }
    Ok(solution)
}

fn solve_square_linear_system(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let n = lhs.rows;
    let m = rhs.cols;
    let mut a = lhs.values.clone();
    let mut b = rhs.values.clone();

    for pivot in 0..n {
        let mut pivot_row = pivot;
        let mut pivot_norm = a[pivot * n + pivot].real.abs() + a[pivot * n + pivot].imag.abs();
        for row in (pivot + 1)..n {
            let candidate = a[row * n + pivot];
            let candidate_norm = candidate.real.abs() + candidate.imag.abs();
            if candidate_norm > pivot_norm {
                pivot_row = row;
                pivot_norm = candidate_norm;
            }
        }

        if approx_equal(pivot_norm, 0.0) {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} encountered a singular matrix"
            )));
        }

        if pivot_row != pivot {
            for col in 0..n {
                a.swap(pivot * n + col, pivot_row * n + col);
            }
            for col in 0..m {
                b.swap(pivot * m + col, pivot_row * m + col);
            }
        }

        let diagonal = a[pivot * n + pivot];
        for row in (pivot + 1)..n {
            let factor = a[row * n + pivot].rdivide(diagonal);
            a[row * n + pivot] = ComplexParts::zero();
            for col in (pivot + 1)..n {
                a[row * n + col] = normalize_complex_parts(
                    a[row * n + col].minus(factor.times(a[pivot * n + col])),
                );
            }
            for col in 0..m {
                b[row * m + col] = normalize_complex_parts(
                    b[row * m + col].minus(factor.times(b[pivot * m + col])),
                );
            }
        }
    }

    let mut x = vec![ComplexParts::zero(); n * m];
    for row in (0..n).rev() {
        let diagonal = a[row * n + row];
        if diagonal.is_approximately_zero() {
            return Err(RuntimeError::ShapeError(format!(
                "{builtin_name} encountered a singular matrix"
            )));
        }
        for col in 0..m {
            let mut total = b[row * m + col];
            for inner in (row + 1)..n {
                total = total.minus(a[row * n + inner].times(x[inner * m + col]));
            }
            x[row * m + col] = normalize_linear_algebra_complex_parts(total.rdivide(diagonal));
        }
    }

    Ok(NumericOrComplexOperand {
        rows: n,
        cols: m,
        values: x,
    })
}

fn determinant_numeric_or_complex_operand(matrix: &NumericOrComplexOperand) -> ComplexParts {
    let n = matrix.rows;
    let mut a = matrix.values.clone();
    let mut sign = 1.0;
    let mut det = ComplexParts::one();

    for pivot in 0..n {
        let mut pivot_row = pivot;
        let mut pivot_norm = a[pivot * n + pivot].real.abs() + a[pivot * n + pivot].imag.abs();
        for row in (pivot + 1)..n {
            let candidate = a[row * n + pivot];
            let candidate_norm = candidate.real.abs() + candidate.imag.abs();
            if candidate_norm > pivot_norm {
                pivot_row = row;
                pivot_norm = candidate_norm;
            }
        }

        if approx_equal(pivot_norm, 0.0) {
            return ComplexParts::zero();
        }

        if pivot_row != pivot {
            sign = -sign;
            for col in 0..n {
                a.swap(pivot * n + col, pivot_row * n + col);
            }
        }

        let diagonal = a[pivot * n + pivot];
        det = det.times(diagonal);
        for row in (pivot + 1)..n {
            let factor = a[row * n + pivot].rdivide(diagonal);
            a[row * n + pivot] = ComplexParts::zero();
            for col in (pivot + 1)..n {
                a[row * n + col] = normalize_complex_parts(
                    a[row * n + col].minus(factor.times(a[pivot * n + col])),
                );
            }
        }
    }

    normalize_linear_algebra_complex_parts(det.scale(sign))
}

fn polynomial_fit_summary_output(fit: &PolynomialLeastSquaresFit) -> Result<Value, RuntimeError> {
    let mut fields = std::collections::BTreeMap::new();
    fields.insert("R".to_string(), numeric_square_matrix_value(&fit.r_factor)?);
    fields.insert(
        "df".to_string(),
        Value::Scalar(fit.degrees_of_freedom as f64),
    );
    fields.insert("normr".to_string(), Value::Scalar(fit.residual_norm));
    fields.insert("rsquared".to_string(), Value::Scalar(fit.rsquared));
    Ok(Value::Struct(StructValue::from_fields(fields)))
}

fn complex_identity_operand(size: usize) -> NumericOrComplexOperand {
    complex_scaled_identity_operand(size, ComplexParts::one())
}

fn complex_scaled_identity_operand(size: usize, scalar: ComplexParts) -> NumericOrComplexOperand {
    let mut values = vec![ComplexParts::zero(); size * size];
    for index in 0..size {
        values[index * size + index] = normalize_complex_parts(scalar);
    }
    NumericOrComplexOperand {
        rows: size,
        cols: size,
        values,
    }
}

fn complex_add_scaled_identity(
    matrix: &NumericOrComplexOperand,
    scalar: ComplexParts,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if matrix.rows != matrix.cols {
        return Err(RuntimeError::ShapeError(
            "matrix helper currently expects a square matrix".to_string(),
        ));
    }
    let mut values = matrix.values.clone();
    for index in 0..matrix.rows {
        values[index * matrix.cols + index] =
            normalize_complex_parts(values[index * matrix.cols + index].plus(scalar));
    }
    Ok(NumericOrComplexOperand {
        rows: matrix.rows,
        cols: matrix.cols,
        values,
    })
}

fn complex_matrix_product(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if lhs.cols != rhs.rows {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently requires compatible matrix dimensions for multiplication"
        )));
    }

    let mut values = vec![ComplexParts::zero(); lhs.rows * rhs.cols];
    for row in 0..lhs.rows {
        for col in 0..rhs.cols {
            let mut total = ComplexParts::zero();
            for inner in 0..lhs.cols {
                total = total.plus(
                    lhs.values[row * lhs.cols + inner].times(rhs.values[inner * rhs.cols + col]),
                );
            }
            values[row * rhs.cols + col] = normalize_complex_parts(total);
        }
    }
    Ok(NumericOrComplexOperand {
        rows: lhs.rows,
        cols: rhs.cols,
        values,
    })
}

fn complex_matrix_trace(matrix: &NumericOrComplexOperand) -> ComplexParts {
    (0..matrix.rows).fold(ComplexParts::zero(), |total, index| {
        total.plus(matrix.values[index * matrix.cols + index])
    })
}

fn matrix_multiply_operands(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if lhs.cols != rhs.rows {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently requires compatible matrix dimensions for multiplication"
        )));
    }

    let mut values = vec![ComplexParts::zero(); lhs.rows * rhs.cols];
    for row in 0..lhs.rows {
        for col in 0..rhs.cols {
            let mut total = ComplexParts::zero();
            for inner in 0..lhs.cols {
                total = total.plus(
                    lhs.values[row * lhs.cols + inner].times(rhs.values[inner * rhs.cols + col]),
                );
            }
            values[row * rhs.cols + col] = normalize_complex_parts(total);
        }
    }
    Ok(NumericOrComplexOperand {
        rows: lhs.rows,
        cols: rhs.cols,
        values,
    })
}

fn transpose_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    conjugate: bool,
) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for col in 0..value.cols {
        for row in 0..value.rows {
            values.push(value.values[row * value.cols + col].conjugate_if(conjugate));
        }
    }
    NumericOrComplexOperand {
        rows: value.cols,
        cols: value.rows,
        values,
    }
}

fn matrix_power_operand(
    base: &NumericOrComplexOperand,
    exponent: i64,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if exponent == 0 {
        return Ok(identity_numeric_or_complex_operand(base.rows));
    }

    if exponent < 0 {
        let inverse = solve_square_linear_system(
            base,
            &identity_numeric_or_complex_operand(base.rows),
            builtin_name,
        )?;
        return matrix_power_operand(&inverse, -exponent, builtin_name);
    }

    let mut result = identity_numeric_or_complex_operand(base.rows);
    let mut power = base.clone();
    let mut exponent = exponent as u64;
    while exponent > 0 {
        if exponent & 1 == 1 {
            result = matrix_multiply_operands(&result, &power, builtin_name)?;
        }
        exponent >>= 1;
        if exponent > 0 {
            power = matrix_multiply_operands(&power, &power, builtin_name)?;
        }
    }
    Ok(result)
}

fn parse_norm_kind(value: Option<&Value>, is_vector: bool) -> Result<NormKind, RuntimeError> {
    match value {
        None => Ok(NormKind::Two),
        Some(value) => match value {
            Value::Scalar(number) => {
                if approx_equal(*number, 1.0) {
                    Ok(NormKind::One)
                } else if approx_equal(*number, 2.0) {
                    Ok(NormKind::Two)
                } else {
                    Err(RuntimeError::Unsupported(
                        "norm currently supports p = 1 or 2, or text modes `inf` and `fro`"
                            .to_string(),
                    ))
                }
            }
            Value::CharArray(_) | Value::String(_) => {
                match text_value(value)?.to_ascii_lowercase().as_str() {
                    "inf" => Ok(NormKind::Infinity),
                    "fro" if !is_vector => Ok(NormKind::Frobenius),
                    "fro" => Ok(NormKind::Two),
                    _ => Err(RuntimeError::Unsupported(
                        "norm currently supports text modes `inf` and `fro`".to_string(),
                    )),
                }
            }
            _ => Err(RuntimeError::TypeError(
                "norm currently expects the second argument to be a scalar or text mode"
                    .to_string(),
            )),
        },
    }
}

fn vector_norm(values: &[ComplexParts], kind: NormKind) -> f64 {
    match kind {
        NormKind::One => values.iter().map(|value| value.magnitude()).sum::<f64>(),
        NormKind::Two | NormKind::Frobenius => values
            .iter()
            .map(|value| {
                let magnitude = value.magnitude();
                magnitude * magnitude
            })
            .sum::<f64>()
            .sqrt(),
        NormKind::Infinity => values
            .iter()
            .map(|value| value.magnitude())
            .fold(0.0, f64::max),
    }
}

fn matrix_norm(value: &NumericOrComplexOperand, kind: NormKind) -> Result<f64, RuntimeError> {
    match kind {
        NormKind::One => Ok((0..value.cols)
            .map(|col| {
                (0..value.rows)
                    .map(|row| value.values[row * value.cols + col].magnitude())
                    .sum::<f64>()
            })
            .fold(0.0, f64::max)),
        NormKind::Infinity => Ok((0..value.rows)
            .map(|row| {
                (0..value.cols)
                    .map(|col| value.values[row * value.cols + col].magnitude())
                    .sum::<f64>()
            })
            .fold(0.0, f64::max)),
        NormKind::Frobenius => Ok(value
            .values
            .iter()
            .map(|entry| {
                let magnitude = entry.magnitude();
                magnitude * magnitude
            })
            .sum::<f64>()
            .sqrt()),
        NormKind::Two => spectral_norm(value),
    }
}

fn condition_number(value: &NumericOrComplexOperand, kind: NormKind) -> Result<f64, RuntimeError> {
    if value.rows == 1 && value.cols == 1 {
        if value.values[0].is_approximately_zero() {
            return Ok(f64::INFINITY);
        }
        return Ok(1.0);
    }

    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "cond currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }

    let base_norm = matrix_norm(value, kind)?;
    let inverse = match solve_square_linear_system(
        value,
        &identity_numeric_or_complex_operand(value.rows),
        "cond",
    ) {
        Ok(inverse) => inverse,
        Err(_) => return Ok(f64::INFINITY),
    };
    let inverse_norm = matrix_norm(&inverse, kind)?;
    Ok(base_norm * inverse_norm)
}

fn reciprocal_condition_number(value: &NumericOrComplexOperand) -> Result<f64, RuntimeError> {
    if value.rows == 1 && value.cols == 1 {
        return Ok(if value.values[0].is_approximately_zero() {
            0.0
        } else {
            1.0
        });
    }

    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "rcond currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }

    let condition = condition_number(value, NormKind::One)?;
    if !condition.is_finite() || condition == 0.0 {
        Ok(0.0)
    } else {
        Ok(1.0 / condition)
    }
}

fn default_rank_tolerance(value: &NumericOrComplexOperand) -> Result<f64, RuntimeError> {
    if value.rows == 0 || value.cols == 0 {
        return Ok(0.0);
    }
    Ok((value.rows.max(value.cols) as f64) * f64::EPSILON * matrix_norm(value, NormKind::Two)?)
}

fn default_rref_tolerance(value: &NumericOrComplexOperand) -> Result<f64, RuntimeError> {
    if value.rows == 0 || value.cols == 0 {
        return Ok(0.0);
    }
    Ok(
        (value.rows.max(value.cols) as f64)
            * f64::EPSILON
            * matrix_norm(value, NormKind::Infinity)?,
    )
}

#[allow(dead_code)]
fn orthonormalize_columns(
    value: &NumericOrComplexOperand,
    tolerance: f64,
) -> NumericOrComplexOperand {
    let mut basis: Vec<Vec<ComplexParts>> = Vec::new();
    for col in 0..value.cols {
        let mut vector = (0..value.rows)
            .map(|row| value.values[row * value.cols + col])
            .collect::<Vec<_>>();
        for existing in &basis {
            let projection = existing.iter().zip(vector.iter()).fold(
                ComplexParts::zero(),
                |total: ComplexParts, (lhs, rhs): (&ComplexParts, &ComplexParts)| {
                    total.plus((*lhs).conjugate().times(*rhs))
                },
            );
            for (entry, basis_entry) in vector.iter_mut().zip(existing.iter()) {
                *entry = normalize_complex_parts((*entry).minus((*basis_entry).times(projection)));
            }
        }
        let norm = vector_norm(&vector, NormKind::Two);
        if norm <= tolerance {
            continue;
        }
        let normalized = canonicalize_basis_vector(
            vector
                .into_iter()
                .map(|entry| normalize_complex_parts(entry.scale(1.0 / norm)))
                .collect(),
            tolerance,
        );
        basis.push(normalized);
    }

    columns_to_operand(value.rows, basis)
}

#[allow(dead_code)]
fn null_space_basis(value: &NumericOrComplexOperand, tolerance: f64) -> NumericOrComplexOperand {
    let reduced = reduced_row_echelon_form(value, tolerance);
    let mut is_pivot_column = vec![false; value.cols];
    for &pivot_col in &reduced.pivot_columns {
        is_pivot_column[pivot_col] = true;
    }

    let free_columns = (0..value.cols)
        .filter(|column| !is_pivot_column[*column])
        .collect::<Vec<_>>();
    if free_columns.is_empty() {
        return NumericOrComplexOperand {
            rows: value.cols,
            cols: 0,
            values: Vec::new(),
        };
    }

    let mut basis = Vec::new();
    for &free_col in &free_columns {
        let mut vector = vec![ComplexParts::zero(); value.cols];
        vector[free_col] = ComplexParts::one();
        for (pivot_row, &pivot_col) in reduced.pivot_columns.iter().enumerate() {
            vector[pivot_col] = normalize_complex_parts(
                ComplexParts::zero().minus(reduced.values[pivot_row * value.cols + free_col]),
            );
        }
        basis.push(vector);
    }

    orthonormalize_columns(&columns_to_operand(value.cols, basis), tolerance)
}

fn qr_factorization(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<(NumericOrComplexOperand, NumericOrComplexOperand), RuntimeError> {
    if value.cols == 0 {
        return Ok((
            columns_to_operand(value.rows, Vec::new()),
            zero_numeric_or_complex_operand(0, 0),
        ));
    }
    if value.rows < value.cols {
        return Err(RuntimeError::Unsupported(
            "qr currently supports only matrices with rows greater than or equal to columns"
                .to_string(),
        ));
    }

    let tolerance = default_rank_tolerance(value)?;
    let mut q_columns: Vec<Vec<ComplexParts>> = Vec::with_capacity(value.cols);
    let mut r_values = vec![ComplexParts::zero(); value.cols * value.cols];
    for col in 0..value.cols {
        let mut vector = (0..value.rows)
            .map(|row| value.values[row * value.cols + col])
            .collect::<Vec<_>>();
        for (basis_col, existing) in q_columns.iter().enumerate() {
            let projection = existing
                .iter()
                .zip(vector.iter())
                .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
                    total.plus((*lhs).conjugate().times(*rhs))
                });
            r_values[basis_col * value.cols + col] =
                normalize_linear_algebra_complex_parts(projection);
            for (entry, basis_entry) in vector.iter_mut().zip(existing.iter()) {
                *entry = normalize_linear_algebra_complex_parts(
                    (*entry).minus((*basis_entry).times(projection)),
                );
            }
        }

        let norm = vector_norm(&vector, NormKind::Two);
        if norm <= tolerance {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports only full-column-rank numeric/complex matrices"
            )));
        }
        r_values[col * value.cols + col] = ComplexParts {
            real: normalize_linear_algebra_number(norm),
            imag: 0.0,
        };
        q_columns.push(
            vector
                .into_iter()
                .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / norm)))
                .collect(),
        );
    }

    Ok((
        columns_to_operand(value.rows, q_columns),
        NumericOrComplexOperand {
            rows: value.cols,
            cols: value.cols,
            values: r_values,
        },
    ))
}

fn pivoted_qr_factorization(
    value: &NumericOrComplexOperand,
    _builtin_name: &str,
) -> Result<(NumericOrComplexOperand, NumericOrComplexOperand, Vec<usize>), RuntimeError> {
    if value.cols == 0 {
        return Ok((
            columns_to_operand(value.rows, Vec::new()),
            zero_numeric_or_complex_operand(0, 0),
            Vec::new(),
        ));
    }

    let q_cols = value.rows.min(value.cols);
    let tolerance = default_rank_tolerance(value)?;
    let mut permutation = (0..value.cols).collect::<Vec<_>>();
    let mut columns = (0..value.cols)
        .map(|col| {
            (0..value.rows)
                .map(|row| value.values[row * value.cols + col])
                .collect::<Vec<_>>()
        })
        .collect::<Vec<_>>();
    let mut q_columns: Vec<Vec<ComplexParts>> = Vec::with_capacity(q_cols);
    let mut r_values = vec![ComplexParts::zero(); q_cols * value.cols];

    for pivot in 0..q_cols {
        let mut best_col = pivot;
        let mut best_norm = vector_norm(&columns[pivot], NormKind::Two);
        for col in (pivot + 1)..value.cols {
            let candidate = vector_norm(&columns[col], NormKind::Two);
            if candidate > best_norm {
                best_col = col;
                best_norm = candidate;
            }
        }

        if best_col != pivot {
            columns.swap(pivot, best_col);
            permutation.swap(pivot, best_col);
            for row in 0..pivot {
                r_values.swap(row * value.cols + pivot, row * value.cols + best_col);
            }
        }

        let norm = vector_norm(&columns[pivot], NormKind::Two);
        if norm <= tolerance {
            break;
        }

        r_values[pivot * value.cols + pivot] = ComplexParts {
            real: normalize_linear_algebra_number(norm),
            imag: 0.0,
        };
        let q_column = columns[pivot]
            .iter()
            .copied()
            .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / norm)))
            .collect::<Vec<_>>();
        q_columns.push(q_column.clone());
        for col in (pivot + 1)..value.cols {
            let coefficient = q_column
                .iter()
                .zip(columns[col].iter())
                .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
                    total.plus((*lhs).conjugate().times(*rhs))
                });
            r_values[pivot * value.cols + col] =
                normalize_linear_algebra_complex_parts(coefficient);
            for (entry, q_entry) in columns[col].iter_mut().zip(q_column.iter()) {
                *entry = normalize_linear_algebra_complex_parts(
                    (*entry).minus((*q_entry).times(coefficient)),
                );
            }
        }
    }

    complete_orthonormal_columns(value.rows, q_cols, &mut q_columns, tolerance);

    Ok((
        columns_to_operand(value.rows, q_columns),
        NumericOrComplexOperand {
            rows: q_cols,
            cols: value.cols,
            values: r_values,
        },
        permutation,
    ))
}

fn complete_orthonormal_columns(
    rows: usize,
    target_cols: usize,
    basis: &mut Vec<Vec<ComplexParts>>,
    tolerance: f64,
) {
    if basis.len() >= target_cols {
        return;
    }

    for axis in 0..rows {
        let mut vector = vec![ComplexParts::zero(); rows];
        vector[axis] = ComplexParts::one();
        for existing in basis.iter() {
            let projection = existing
                .iter()
                .zip(vector.iter())
                .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
                    total.plus((*lhs).conjugate().times(*rhs))
                });
            for (entry, basis_entry) in vector.iter_mut().zip(existing.iter()) {
                *entry = normalize_linear_algebra_complex_parts(
                    (*entry).minus((*basis_entry).times(projection)),
                );
            }
        }
        let norm = vector_norm(&vector, NormKind::Two);
        if norm <= tolerance {
            continue;
        }
        basis.push(canonicalize_basis_vector(
            vector
                .into_iter()
                .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / norm)))
                .collect(),
            tolerance,
        ));
        if basis.len() == target_cols {
            break;
        }
    }

    while basis.len() < target_cols {
        basis.push(vec![ComplexParts::zero(); rows]);
    }
}

fn leading_columns_operand(
    value: &NumericOrComplexOperand,
    count: usize,
) -> NumericOrComplexOperand {
    extract_column_range_operand(value, 0, count.min(value.cols))
}

fn trailing_columns_operand(
    value: &NumericOrComplexOperand,
    start: usize,
) -> NumericOrComplexOperand {
    extract_column_range_operand(value, start.min(value.cols), value.cols)
}

fn extract_column_range_operand(
    value: &NumericOrComplexOperand,
    start: usize,
    end: usize,
) -> NumericOrComplexOperand {
    let cols = end.saturating_sub(start);
    let mut values = Vec::with_capacity(value.rows * cols);
    for row in 0..value.rows {
        for col in start..end {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOrComplexOperand {
        rows: value.rows,
        cols,
        values,
    }
}

fn canonicalize_operand_columns(
    value: &NumericOrComplexOperand,
    tolerance: f64,
) -> NumericOrComplexOperand {
    let mut columns = Vec::with_capacity(value.cols);
    for col in 0..value.cols {
        columns.push(canonicalize_basis_vector(
            (0..value.rows)
                .map(|row| value.values[row * value.cols + col])
                .collect::<Vec<_>>(),
            tolerance,
        ));
    }
    columns_to_operand(value.rows, columns)
}

fn lu_factorization(
    value: &NumericOrComplexOperand,
    tolerance: f64,
) -> (
    NumericOrComplexOperand,
    NumericOrComplexOperand,
    NumericOrComplexOperand,
) {
    let size = value.rows;
    let mut u = value.values.clone();
    let mut l = identity_numeric_or_complex_operand(size).values;
    let mut permutation = (0..size).collect::<Vec<_>>();

    for pivot in 0..size {
        let mut pivot_row = pivot;
        let mut pivot_norm = u[pivot * size + pivot].magnitude();
        for row in (pivot + 1)..size {
            let candidate = u[row * size + pivot].magnitude();
            if candidate > pivot_norm {
                pivot_row = row;
                pivot_norm = candidate;
            }
        }

        if pivot_row != pivot {
            for col in 0..size {
                u.swap(pivot * size + col, pivot_row * size + col);
            }
            for col in 0..pivot {
                l.swap(pivot * size + col, pivot_row * size + col);
            }
            permutation.swap(pivot, pivot_row);
        }

        let diagonal = u[pivot * size + pivot];
        if diagonal.magnitude() <= tolerance {
            continue;
        }

        for row in (pivot + 1)..size {
            let factor =
                normalize_linear_algebra_complex_parts(u[row * size + pivot].rdivide(diagonal));
            l[row * size + pivot] = factor;
            u[row * size + pivot] = ComplexParts::zero();
            for col in (pivot + 1)..size {
                u[row * size + col] = normalize_linear_algebra_complex_parts(
                    u[row * size + col].minus(factor.times(u[pivot * size + col])),
                );
            }
        }
    }

    (
        NumericOrComplexOperand {
            rows: size,
            cols: size,
            values: l,
        },
        NumericOrComplexOperand {
            rows: size,
            cols: size,
            values: u
                .into_iter()
                .map(normalize_linear_algebra_complex_parts)
                .collect(),
        },
        permutation_operand(&permutation),
    )
}

fn packed_lu_operand(
    l: &NumericOrComplexOperand,
    u: &NumericOrComplexOperand,
) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(l.rows * l.cols);
    for row in 0..l.rows {
        for col in 0..l.cols {
            values.push(if row > col {
                l.values[row * l.cols + col]
            } else {
                u.values[row * u.cols + col]
            });
        }
    }
    NumericOrComplexOperand {
        rows: l.rows,
        cols: l.cols,
        values,
    }
}

fn cholesky_factorization(
    value: &NumericOrComplexOperand,
    lower: bool,
) -> Result<(NumericOrComplexOperand, usize), RuntimeError> {
    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "chol currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }
    if value.rows == 0 {
        return Ok((zero_numeric_or_complex_operand(0, 0), 0));
    }

    let upper_source = cholesky_source_operand(value, lower);
    let size = upper_source.rows;
    let mut r = vec![ComplexParts::zero(); size * size];
    for pivot in 0..size {
        let mut diagonal = upper_source.values[pivot * size + pivot];
        for inner in 0..pivot {
            let factor = r[inner * size + pivot];
            diagonal = diagonal.minus(factor.conjugate().times(factor));
        }

        diagonal = normalize_linear_algebra_complex_parts(diagonal);
        if diagonal.imag.abs() > 1e-12 || diagonal.real <= 1e-12 {
            let partial = if pivot == 0 {
                zero_numeric_or_complex_operand(0, 0)
            } else {
                upper_triangular_prefix_operand(&r, size, pivot)
            };
            return Ok((
                if lower {
                    transpose_numeric_or_complex_operand(&partial, true)
                } else {
                    partial
                },
                pivot + 1,
            ));
        }

        let diagonal_value = normalize_linear_algebra_number(diagonal.real.sqrt());
        r[pivot * size + pivot] = ComplexParts {
            real: diagonal_value,
            imag: 0.0,
        };
        let denominator = r[pivot * size + pivot];
        for col in (pivot + 1)..size {
            let mut total = upper_source.values[pivot * size + col];
            for inner in 0..pivot {
                total = total.minus(
                    r[inner * size + pivot]
                        .conjugate()
                        .times(r[inner * size + col]),
                );
            }
            r[pivot * size + col] =
                normalize_linear_algebra_complex_parts(total.rdivide(denominator));
        }
    }

    let factor = NumericOrComplexOperand {
        rows: size,
        cols: size,
        values: r,
    };
    Ok((
        if lower {
            transpose_numeric_or_complex_operand(&factor, true)
        } else {
            factor
        },
        0,
    ))
}

fn ldl_factorization(
    value: &NumericOrComplexOperand,
    upper: bool,
) -> Result<(NumericOrComplexOperand, NumericOrComplexOperand, Vec<usize>), RuntimeError> {
    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "ldl currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }
    if value.rows == 0 {
        return Ok((
            zero_numeric_or_complex_operand(0, 0),
            zero_numeric_or_complex_operand(0, 0),
            Vec::new(),
        ));
    }

    let source = cholesky_source_operand(value, !upper);
    let size = source.rows;
    let mut l = identity_numeric_or_complex_operand(size).values;
    let mut d = vec![ComplexParts::zero(); size];
    let tolerance = default_rank_tolerance(&source)?.max(1e-12);
    for pivot in 0..size {
        let diagonal_source = source.values[pivot * size + pivot];
        if diagonal_source.imag.abs() > tolerance {
            return Err(RuntimeError::Unsupported(
                "ldl currently expects Hermitian/symmetric inputs with real diagonal entries"
                    .to_string(),
            ));
        }

        let mut diagonal = diagonal_source;
        for inner in 0..pivot {
            let left = l[pivot * size + inner];
            diagonal = diagonal.minus(left.times(d[inner]).times(left.conjugate()));
        }
        diagonal = normalize_linear_algebra_complex_parts(diagonal);
        if diagonal.imag.abs() > tolerance || diagonal.magnitude() <= tolerance {
            return Err(RuntimeError::Unsupported(
                "ldl currently supports only dense numeric/complex matrices with nonzero 1x1 pivots"
                    .to_string(),
            ));
        }
        d[pivot] = ComplexParts {
            real: normalize_linear_algebra_number(diagonal.real),
            imag: 0.0,
        };

        for row in (pivot + 1)..size {
            let mut total = source.values[row * size + pivot];
            for inner in 0..pivot {
                total = total.minus(
                    l[row * size + inner]
                        .times(d[inner])
                        .times(l[pivot * size + inner].conjugate()),
                );
            }
            l[row * size + pivot] = normalize_linear_algebra_complex_parts(total.rdivide(d[pivot]));
        }
    }

    let lower_l = NumericOrComplexOperand {
        rows: size,
        cols: size,
        values: l,
    };
    let factor = if upper {
        transpose_numeric_or_complex_operand(&lower_l, true)
    } else {
        lower_l
    };
    Ok((
        factor,
        diagonal_numeric_or_complex_operand(&d),
        (0..size).collect::<Vec<_>>(),
    ))
}

fn solve_triangular_system(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    lower: bool,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if lhs.rows != lhs.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a square triangular system, found {}x{}",
            lhs.rows, lhs.cols
        )));
    }
    if lhs.rows != rhs.rows {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} requires matching row counts, found {}x{} and {}x{}",
            lhs.rows, lhs.cols, rhs.rows, rhs.cols
        )));
    }

    let n = lhs.rows;
    let m = rhs.cols;
    let mut x = vec![ComplexParts::zero(); n * m];
    if lower {
        for row in 0..n {
            let diagonal = lhs.values[row * n + row];
            if diagonal.is_approximately_zero() {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} encountered a singular triangular system"
                )));
            }
            for col in 0..m {
                let mut total = rhs.values[row * m + col];
                for inner in 0..row {
                    total = total.minus(lhs.values[row * n + inner].times(x[inner * m + col]));
                }
                x[row * m + col] = normalize_linear_algebra_complex_parts(total.rdivide(diagonal));
            }
        }
    } else {
        for row in (0..n).rev() {
            let diagonal = lhs.values[row * n + row];
            if diagonal.is_approximately_zero() {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} encountered a singular triangular system"
                )));
            }
            for col in 0..m {
                let mut total = rhs.values[row * m + col];
                for inner in (row + 1)..n {
                    total = total.minus(lhs.values[row * n + inner].times(x[inner * m + col]));
                }
                x[row * m + col] = normalize_linear_algebra_complex_parts(total.rdivide(diagonal));
            }
        }
    }

    Ok(NumericOrComplexOperand {
        rows: n,
        cols: m,
        values: x,
    })
}

fn solve_positive_definite_system(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let (factor, failure_flag) = cholesky_factorization(lhs, false)?;
    if failure_flag != 0 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently requires a positive definite matrix, factorization failed at pivot {failure_flag}"
        )));
    }
    let factor_conjugate_transpose = transpose_numeric_or_complex_operand(&factor, true);
    let intermediate =
        solve_triangular_system(&factor_conjugate_transpose, rhs, true, builtin_name)?;
    solve_triangular_system(&factor, &intermediate, false, builtin_name)
}

fn cholesky_source_operand(
    value: &NumericOrComplexOperand,
    lower: bool,
) -> NumericOrComplexOperand {
    let size = value.rows;
    let mut values = vec![ComplexParts::zero(); size * size];
    for row in 0..size {
        for col in row..size {
            let entry = if lower {
                value.values[col * size + row].conjugate()
            } else {
                value.values[row * size + col]
            };
            values[row * size + col] = entry;
            values[col * size + row] = entry.conjugate();
        }
    }
    NumericOrComplexOperand {
        rows: size,
        cols: size,
        values,
    }
}

fn upper_triangular_prefix_operand(
    values: &[ComplexParts],
    full_size: usize,
    prefix_size: usize,
) -> NumericOrComplexOperand {
    let mut prefix = Vec::with_capacity(prefix_size * prefix_size);
    for row in 0..prefix_size {
        for col in 0..prefix_size {
            prefix.push(values[row * full_size + col]);
        }
    }
    NumericOrComplexOperand {
        rows: prefix_size,
        cols: prefix_size,
        values: prefix,
    }
}

fn diagonal_numeric_or_complex_operand(diagonal: &[ComplexParts]) -> NumericOrComplexOperand {
    let size = diagonal.len();
    let mut values = vec![ComplexParts::zero(); size * size];
    for (index, value) in diagonal.iter().copied().enumerate() {
        values[index * size + index] = value;
    }
    NumericOrComplexOperand {
        rows: size,
        cols: size,
        values,
    }
}

fn columns_to_operand(rows: usize, columns: Vec<Vec<ComplexParts>>) -> NumericOrComplexOperand {
    let cols = columns.len();
    let mut values = Vec::with_capacity(rows * cols);
    for row in 0..rows {
        for column in &columns {
            values.push(column[row]);
        }
    }
    NumericOrComplexOperand { rows, cols, values }
}

struct ReducedRowEchelonForm {
    values: Vec<ComplexParts>,
    pivot_columns: Vec<usize>,
}

#[derive(Debug, Clone, Copy, Default)]
struct LinsolveOptions {
    lt: bool,
    ut: bool,
    uhess: bool,
    sym: bool,
    posdef: bool,
    rect: bool,
    transa: bool,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum SvdOutputForm {
    Vector,
    Matrix,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum EigOutputForm {
    Vector,
    Matrix,
}

fn reduced_row_echelon_form(
    value: &NumericOrComplexOperand,
    tolerance: f64,
) -> ReducedRowEchelonForm {
    let mut values = value.values.clone();
    let mut pivot_columns = Vec::new();
    let mut pivot_row = 0usize;

    for pivot_col in 0..value.cols {
        if pivot_row >= value.rows {
            break;
        }

        let mut best_row = pivot_row;
        let mut best_norm = values[pivot_row * value.cols + pivot_col].magnitude();
        for row in (pivot_row + 1)..value.rows {
            let candidate = values[row * value.cols + pivot_col].magnitude();
            if candidate > best_norm {
                best_row = row;
                best_norm = candidate;
            }
        }

        if best_norm <= tolerance {
            continue;
        }

        if best_row != pivot_row {
            for col in 0..value.cols {
                values.swap(pivot_row * value.cols + col, best_row * value.cols + col);
            }
        }

        let pivot = values[pivot_row * value.cols + pivot_col];
        for col in pivot_col..value.cols {
            values[pivot_row * value.cols + col] =
                normalize_complex_parts(values[pivot_row * value.cols + col].rdivide(pivot));
        }

        for row in 0..value.rows {
            if row == pivot_row {
                continue;
            }
            let factor = values[row * value.cols + pivot_col];
            if factor.magnitude() <= tolerance {
                values[row * value.cols + pivot_col] = ComplexParts::zero();
                continue;
            }
            for col in pivot_col..value.cols {
                values[row * value.cols + col] = normalize_complex_parts(
                    values[row * value.cols + col]
                        .minus(factor.times(values[pivot_row * value.cols + col])),
                );
            }
        }

        pivot_columns.push(pivot_col);
        pivot_row += 1;
    }

    ReducedRowEchelonForm {
        values,
        pivot_columns,
    }
}

fn parse_linsolve_options(value: &Value) -> Result<LinsolveOptions, RuntimeError> {
    let struct_value = match value {
        Value::Struct(struct_value) => struct_value,
        Value::Matrix(matrix)
            if matrix_is_struct(matrix) && matrix.rows == 1 && matrix.cols == 1 =>
        {
            let Some(Value::Struct(struct_value)) = matrix.elements.first() else {
                unreachable!("matrix_is_struct with 1x1 matrix should contain a struct");
            };
            struct_value
        }
        other => {
            return Err(RuntimeError::TypeError(format!(
                "linsolve currently expects opts to be a scalar struct, found {}",
                other.kind_name()
            )))
        }
    };

    let mut options = LinsolveOptions::default();
    for (name, value) in &struct_value.fields {
        let enabled = linsolve_option_flag(value, name)?;
        match name.to_ascii_uppercase().as_str() {
            "LT" => options.lt = enabled,
            "UT" => options.ut = enabled,
            "UHESS" => options.uhess = enabled,
            "SYM" => options.sym = enabled,
            "POSDEF" => options.posdef = enabled,
            "RECT" => options.rect = enabled,
            "TRANSA" => options.transa = enabled,
            other => {
                return Err(RuntimeError::Unsupported(format!(
                    "linsolve currently does not support opts field `{other}`"
                )))
            }
        }
    }
    Ok(options)
}

fn linsolve_option_flag(value: &Value, field_name: &str) -> Result<bool, RuntimeError> {
    match value {
        Value::Logical(flag) => Ok(*flag),
        Value::Scalar(number) if approx_equal(*number, 0.0) => Ok(false),
        Value::Scalar(number) if approx_equal(*number, 1.0) => Ok(true),
        _ => Err(RuntimeError::TypeError(format!(
            "linsolve opts field `{field_name}` currently expects a logical or scalar 0/1 value"
        ))),
    }
}

fn parse_svd_args<'a>(
    args: &'a [Value],
    output_arity: usize,
) -> Result<(&'a Value, bool, SvdOutputForm), RuntimeError> {
    let default_output_form = if output_arity <= 1 {
        SvdOutputForm::Vector
    } else {
        SvdOutputForm::Matrix
    };

    match args {
        [value] => Ok((value, false, default_output_form)),
        [value, mode] => {
            if let Value::Scalar(number) = mode {
                if approx_equal(*number, 0.0) {
                    return Ok((value, true, default_output_form));
                }
            }
            match text_value(mode)?.to_ascii_lowercase().as_str() {
                "econ" => Ok((value, true, default_output_form)),
                "vector" => Ok((value, false, SvdOutputForm::Vector)),
                "matrix" => Ok((value, false, SvdOutputForm::Matrix)),
                _ => Err(RuntimeError::Unsupported(
                    "svd currently supports optional mode `econ`, output form `vector`/`matrix`, or legacy economy flag 0"
                        .to_string(),
                )),
            }
        }
        [value, econ, output_form] => {
            let econ = match econ {
                Value::Scalar(number) if approx_equal(*number, 0.0) => true,
                _ => match text_value(econ)?.to_ascii_lowercase().as_str() {
                    "econ" => true,
                    _ => {
                        return Err(RuntimeError::Unsupported(
                            "svd currently expects `econ` or 0 as the second argument when three inputs are supplied"
                                .to_string(),
                        ))
                    }
                },
            };
            let output_form = match text_value(output_form)?.to_ascii_lowercase().as_str() {
                "vector" => SvdOutputForm::Vector,
                "matrix" => SvdOutputForm::Matrix,
                _ => {
                    return Err(RuntimeError::Unsupported(
                        "svd currently supports output form `vector` or `matrix`".to_string(),
                    ))
                }
            };
            Ok((value, econ, output_form))
        }
        _ => Err(RuntimeError::Unsupported(
            "svd currently supports `svd(A)`, `svd(A, mode)`, and `svd(A, \"econ\", outputForm)`"
                .to_string(),
        )),
    }
}

fn parse_eig_args<'a>(
    args: &'a [Value],
    output_arity: usize,
) -> Result<(&'a Value, EigOutputForm), RuntimeError> {
    let default_output_form = if output_arity <= 1 {
        EigOutputForm::Vector
    } else {
        EigOutputForm::Matrix
    };

    match args {
        [value] => Ok((value, default_output_form)),
        [value, mode] => match text_value(mode)?.to_ascii_lowercase().as_str() {
            "balance" | "nobalance" => Ok((value, default_output_form)),
            "vector" => Ok((value, EigOutputForm::Vector)),
            "matrix" => Ok((value, EigOutputForm::Matrix)),
            _ => Err(RuntimeError::Unsupported(
                "eig currently supports optional mode `balance`/`nobalance` or output form `vector`/`matrix`"
                    .to_string(),
            )),
        },
        [value, balance, output_form] => {
            match text_value(balance)?.to_ascii_lowercase().as_str() {
                "balance" | "nobalance" => {}
                _ => {
                    return Err(RuntimeError::Unsupported(
                        "eig currently supports `balance` or `nobalance` as the second mode argument"
                            .to_string(),
                    ))
                }
            }
            match text_value(output_form)?.to_ascii_lowercase().as_str() {
                "vector" => Ok((value, EigOutputForm::Vector)),
                "matrix" => Ok((value, EigOutputForm::Matrix)),
                _ => Err(RuntimeError::Unsupported(
                    "eig currently supports output form `vector` or `matrix`".to_string(),
                )),
            }
        }
        _ => Err(RuntimeError::Unsupported(
            "eig currently supports `eig(A)`, `eig(A, mode)`, and `eig(A, balanceOption, outputForm)`"
                .to_string(),
        )),
    }
}

fn canonicalize_basis_vector(mut vector: Vec<ComplexParts>, tolerance: f64) -> Vec<ComplexParts> {
    let Some(first) = vector
        .iter()
        .copied()
        .find(|entry| entry.magnitude() > tolerance)
    else {
        return vector;
    };
    let phase = first.scale(1.0 / first.magnitude()).conjugate();
    for entry in &mut vector {
        *entry = normalize_complex_parts(entry.times(phase));
    }
    vector
}

fn rank_numeric_or_complex_operand(value: &NumericOrComplexOperand, tolerance: f64) -> usize {
    if value.rows == 0 || value.cols == 0 {
        return 0;
    }

    let mut matrix = value.values.clone();
    let mut rank = 0usize;
    let mut pivot_row = 0usize;
    for pivot_col in 0..value.cols {
        if pivot_row >= value.rows {
            break;
        }

        let mut best_row = pivot_row;
        let mut best_norm = matrix[pivot_row * value.cols + pivot_col].magnitude();
        for row in (pivot_row + 1)..value.rows {
            let candidate = matrix[row * value.cols + pivot_col].magnitude();
            if candidate > best_norm {
                best_row = row;
                best_norm = candidate;
            }
        }

        if best_norm <= tolerance {
            continue;
        }

        if best_row != pivot_row {
            for col in 0..value.cols {
                matrix.swap(pivot_row * value.cols + col, best_row * value.cols + col);
            }
        }

        let pivot = matrix[pivot_row * value.cols + pivot_col];
        for row in (pivot_row + 1)..value.rows {
            let factor = matrix[row * value.cols + pivot_col].rdivide(pivot);
            matrix[row * value.cols + pivot_col] = ComplexParts::zero();
            for col in (pivot_col + 1)..value.cols {
                matrix[row * value.cols + col] = normalize_complex_parts(
                    matrix[row * value.cols + col]
                        .minus(factor.times(matrix[pivot_row * value.cols + col])),
                );
            }
        }

        rank += 1;
        pivot_row += 1;
    }

    rank
}

fn spectral_norm(value: &NumericOrComplexOperand) -> Result<f64, RuntimeError> {
    let ah = transpose_numeric_or_complex_operand(value, true);
    let gram = matrix_multiply_operands(&ah, value, "norm")?;
    let mut vector = NumericOrComplexOperand {
        rows: gram.cols,
        cols: 1,
        values: vec![ComplexParts::one(); gram.cols],
    };

    let mut current_norm = vector_norm(&vector.values, NormKind::Two);
    if current_norm == 0.0 {
        return Ok(0.0);
    }
    for entry in &mut vector.values {
        *entry = entry.scale(1.0 / current_norm);
    }

    for _ in 0..32 {
        let next = matrix_multiply_operands(&gram, &vector, "norm")?;
        current_norm = vector_norm(&next.values, NormKind::Two);
        if current_norm == 0.0 {
            return Ok(0.0);
        }
        vector = NumericOrComplexOperand {
            rows: next.rows,
            cols: next.cols,
            values: next
                .values
                .into_iter()
                .map(|entry| normalize_complex_parts(entry.scale(1.0 / current_norm)))
                .collect(),
        };
    }

    let projected = matrix_multiply_operands(&gram, &vector, "norm")?;
    let rayleigh = vector
        .values
        .iter()
        .zip(projected.values.iter())
        .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
            total.plus(lhs.conjugate().times(*rhs))
        });
    Ok(rayleigh.real.max(0.0).sqrt())
}

fn singular_value_decomposition(
    value: &NumericOrComplexOperand,
    econ: bool,
    output_form: SvdOutputForm,
    include_vectors: bool,
) -> Result<(Value, Value, Value), RuntimeError> {
    if value.rows == 0 || value.cols == 0 {
        let singular_output = svd_singular_values_output(
            &[],
            value.rows,
            value.cols,
            econ,
            output_form,
            include_vectors,
        )?;
        if !include_vectors {
            return Ok((Value::Scalar(0.0), singular_output, Value::Scalar(0.0)));
        }
        return Ok(empty_svd_outputs(
            value.rows,
            value.cols,
            econ,
            singular_output,
        ));
    }

    let tolerance = default_rank_tolerance(value)?.max(1e-12);
    let (u_operand, singular_scalars, v_operand) = svd_factor_operands(value, econ, tolerance)?;
    let singular_output = svd_singular_values_output(
        &singular_scalars,
        value.rows,
        value.cols,
        econ,
        output_form,
        include_vectors,
    )?;

    if !include_vectors {
        return Ok((Value::Scalar(0.0), singular_output, Value::Scalar(0.0)));
    }

    Ok((
        numeric_or_complex_operand_to_value(&u_operand)?,
        singular_output,
        numeric_or_complex_operand_to_value(&v_operand)?,
    ))
}

fn empty_svd_outputs(
    rows: usize,
    cols: usize,
    econ: bool,
    singular_output: Value,
) -> (Value, Value, Value) {
    let u = if econ && rows > cols {
        zero_numeric_or_complex_operand(rows, cols)
    } else {
        identity_numeric_or_complex_operand(rows)
    };
    let v = if econ && rows < cols {
        zero_numeric_or_complex_operand(cols, rows)
    } else {
        identity_numeric_or_complex_operand(cols)
    };
    (
        numeric_or_complex_operand_to_value(&u).expect("empty svd u"),
        singular_output,
        numeric_or_complex_operand_to_value(&v).expect("empty svd v"),
    )
}

fn eigenvalues_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    tolerance: f64,
    builtin_name: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    match value.rows {
        0 => Err(RuntimeError::Unsupported(
            "eig does not yet support empty matrices".to_string(),
        )),
        1 => Ok(vec![normalize_linear_algebra_complex_parts(value.values[0])]),
        2 => {
            let a = value.values[0];
            let b = value.values[1];
            let c = value.values[2];
            let d = value.values[3];
            let trace = a.plus(d);
            let determinant = a.times(d).minus(b.times(c));
            let discriminant = trace.times(trace).minus(determinant.scale(4.0));
            let root = discriminant.sqrt();
            Ok(vec![
                normalize_linear_algebra_complex_parts(trace.plus(root).scale(0.5)),
                normalize_linear_algebra_complex_parts(trace.minus(root).scale(0.5)),
            ])
        }
        size if matrix_is_upper_or_lower_triangular(value, tolerance) => Ok((0..size)
            .map(|index| normalize_linear_algebra_complex_parts(value.values[index * size + index]))
            .collect()),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports general 2x2 matrices and diagonal/triangular matrices"
        ))),
    }
}

fn right_eigenvectors_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    eigenvalues: &[ComplexParts],
    tolerance: f64,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let mut columns = Vec::with_capacity(eigenvalues.len());
    for &eigenvalue in eigenvalues {
        let shifted = complex_add_scaled_identity(value, eigenvalue.scale(-1.0))?;
        let basis = null_space_basis(&shifted, tolerance);
        if basis.cols == 0 {
            let mut column = vec![ComplexParts::zero(); value.rows];
            column[0] = ComplexParts::one();
            columns.push(column);
        } else {
            columns.push(
                (0..basis.rows)
                    .map(|row| basis.values[row * basis.cols])
                    .collect::<Vec<_>>(),
            );
        }
    }
    Ok(columns_to_operand(value.rows, columns))
}

fn left_eigenvectors_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    eigenvalues: &[ComplexParts],
    tolerance: f64,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let adjoint = transpose_numeric_or_complex_operand(value, true);
    let conjugated = eigenvalues
        .iter()
        .copied()
        .map(ComplexParts::conjugate)
        .collect::<Vec<_>>();
    right_eigenvectors_numeric_or_complex_operand(&adjoint, &conjugated, tolerance)
}

fn eig_eigenvalue_output(
    values: &[ComplexParts],
    output_form: EigOutputForm,
) -> Result<Value, RuntimeError> {
    match output_form {
        EigOutputForm::Vector => {
            build_numeric_or_complex_matrix_result(values.len(), 1, values.to_vec())
        }
        EigOutputForm::Matrix => {
            let size = values.len();
            let mut diagonal = vec![ComplexParts::zero(); size * size];
            for (index, value) in values.iter().copied().enumerate() {
                diagonal[index * size + index] = value;
            }
            numeric_or_complex_operand_to_value(&NumericOrComplexOperand {
                rows: size,
                cols: size,
                values: diagonal,
            })
        }
    }
}

fn matrix_is_upper_or_lower_triangular(value: &NumericOrComplexOperand, tolerance: f64) -> bool {
    let mut upper = true;
    let mut lower = true;
    for row in 0..value.rows {
        for col in 0..value.cols {
            if row < col && value.values[row * value.cols + col].magnitude() > tolerance {
                lower = false;
            }
            if row > col && value.values[row * value.cols + col].magnitude() > tolerance {
                upper = false;
            }
        }
    }
    upper || lower
}

fn matrix_exponential_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let norm = matrix_norm(value, NormKind::One)?;
    let theta13 = 5.371_920_351_148_152_f64;
    let squarings = if norm <= theta13 {
        0
    } else {
        (norm / theta13).log2().ceil().max(0.0) as u32
    };
    let scale = 2f64.powi(-(squarings as i32));
    let a = scale_numeric_or_complex_operand(value, scale);
    let a2 = matrix_multiply_operands(&a, &a, builtin_name)?;
    let a4 = matrix_multiply_operands(&a2, &a2, builtin_name)?;
    let a6 = matrix_multiply_operands(&a4, &a2, builtin_name)?;

    let b = [
        64_764_752_532_480_000.0,
        32_382_376_266_240_000.0,
        7_771_770_303_897_600.0,
        1_187_353_796_428_800.0,
        129_060_195_264_000.0,
        10_559_470_521_600.0,
        670_442_572_800.0,
        33_522_128_640.0,
        1_323_241_920.0,
        40_840_800.0,
        960_960.0,
        16_380.0,
        182.0,
        1.0,
    ];

    let inner_u = add_numeric_or_complex_operands(
        &add_numeric_or_complex_operands(
            &matrix_multiply_operands(
                &a6,
                &add_numeric_or_complex_operands(
                    &scale_numeric_or_complex_operand(&a6, b[13]),
                    &add_numeric_or_complex_operands(
                        &scale_numeric_or_complex_operand(&a4, b[11]),
                        &scale_numeric_or_complex_operand(&a2, b[9]),
                        builtin_name,
                    )?,
                    builtin_name,
                )?,
                builtin_name,
            )?,
            &scale_numeric_or_complex_operand(&a6, b[7]),
            builtin_name,
        )?,
        &add_numeric_or_complex_operands(
            &scale_numeric_or_complex_operand(&a4, b[5]),
            &add_numeric_or_complex_operands(
                &scale_numeric_or_complex_operand(&a2, b[3]),
                &complex_scaled_identity_operand(
                    a.rows,
                    ComplexParts {
                        real: b[1],
                        imag: 0.0,
                    },
                ),
                builtin_name,
            )?,
            builtin_name,
        )?,
        builtin_name,
    )?;
    let u = matrix_multiply_operands(&a, &inner_u, builtin_name)?;

    let v = add_numeric_or_complex_operands(
        &add_numeric_or_complex_operands(
            &matrix_multiply_operands(
                &a6,
                &add_numeric_or_complex_operands(
                    &scale_numeric_or_complex_operand(&a6, b[12]),
                    &add_numeric_or_complex_operands(
                        &scale_numeric_or_complex_operand(&a4, b[10]),
                        &scale_numeric_or_complex_operand(&a2, b[8]),
                        builtin_name,
                    )?,
                    builtin_name,
                )?,
                builtin_name,
            )?,
            &scale_numeric_or_complex_operand(&a6, b[6]),
            builtin_name,
        )?,
        &add_numeric_or_complex_operands(
            &scale_numeric_or_complex_operand(&a4, b[4]),
            &add_numeric_or_complex_operands(
                &scale_numeric_or_complex_operand(&a2, b[2]),
                &complex_scaled_identity_operand(
                    a.rows,
                    ComplexParts {
                        real: b[0],
                        imag: 0.0,
                    },
                ),
                builtin_name,
            )?,
            builtin_name,
        )?,
        builtin_name,
    )?;

    let numerator = add_numeric_or_complex_operands(&v, &u, builtin_name)?;
    let denominator = subtract_numeric_or_complex_operands(&v, &u, builtin_name)?;
    let mut result = solve_square_linear_system(&denominator, &numerator, builtin_name)?;
    for _ in 0..squarings {
        result = matrix_multiply_operands(&result, &result, builtin_name)?;
    }
    Ok(result)
}

fn matrix_square_root_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }
    if value.rows == 0 {
        return Ok(zero_numeric_or_complex_operand(0, 0));
    }
    if value.rows == 1 {
        return Ok(NumericOrComplexOperand {
            rows: 1,
            cols: 1,
            values: vec![normalize_linear_algebra_complex_parts(
                value.values[0].sqrt(),
            )],
        });
    }
    if matrix_is_diagonal_operand(value, 1e-12) {
        let diagonal = (0..value.rows)
            .map(|index| {
                normalize_linear_algebra_complex_parts(
                    value.values[index * value.cols + index].sqrt(),
                )
            })
            .collect::<Vec<_>>();
        return Ok(diagonal_numeric_or_complex_operand(&diagonal));
    }
    if matrix_is_upper_or_lower_triangular(value, 1e-12) {
        return matrix_square_root_triangular(value, builtin_name);
    }
    if value.rows == 2 {
        return matrix_square_root_2x2(value, builtin_name);
    }
    Err(RuntimeError::Unsupported(
        "sqrtm currently supports diagonal/triangular matrices and general 2x2 matrices"
            .to_string(),
    ))
}

fn matrix_square_root_2x2(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let tolerance = default_rank_tolerance(value)?.max(1e-12);
    let eigenvalues = eigenvalues_numeric_or_complex_operand(value, tolerance, builtin_name)?;
    let eigenvectors =
        right_eigenvectors_numeric_or_complex_operand(value, &eigenvalues, tolerance)?;
    if determinant_numeric_or_complex_operand(&eigenvectors).magnitude() > tolerance {
        let sqrt_diagonal = diagonal_numeric_or_complex_operand(
            &eigenvalues
                .iter()
                .copied()
                .map(|value| normalize_linear_algebra_complex_parts(value.sqrt()))
                .collect::<Vec<_>>(),
        );
        let inverse = solve_square_linear_system(
            &eigenvectors,
            &identity_numeric_or_complex_operand(eigenvectors.rows),
            builtin_name,
        )?;
        return matrix_multiply_operands(
            &matrix_multiply_operands(&eigenvectors, &sqrt_diagonal, builtin_name)?,
            &inverse,
            builtin_name,
        );
    }

    let lambda =
        normalize_linear_algebra_complex_parts(value.values[0].plus(value.values[3]).scale(0.5));
    let sqrt_lambda = normalize_linear_algebra_complex_parts(lambda.sqrt());
    if sqrt_lambda.is_approximately_zero() {
        return Err(RuntimeError::Unsupported(
            "sqrtm currently does not support singular defective 2x2 matrices".to_string(),
        ));
    }
    let nilpotent = complex_add_scaled_identity(value, lambda.scale(-1.0))?;
    let factor =
        normalize_linear_algebra_complex_parts(ComplexParts::one().rdivide(sqrt_lambda.scale(2.0)));
    let correction = scale_numeric_or_complex_operand_by_complex(&nilpotent, factor);
    add_numeric_or_complex_operands(
        &complex_scaled_identity_operand(value.rows, sqrt_lambda),
        &correction,
        builtin_name,
    )
}

fn matrix_square_root_residual(
    original: &NumericOrComplexOperand,
    root: &NumericOrComplexOperand,
) -> Result<f64, RuntimeError> {
    let squared = matrix_multiply_operands(root, root, "sqrtm")?;
    let difference = subtract_numeric_or_complex_operands(original, &squared, "sqrtm")?;
    let numerator = matrix_norm(&difference, NormKind::One)?;
    let denominator = matrix_norm(original, NormKind::One)?;
    Ok(if denominator == 0.0 {
        if numerator == 0.0 {
            0.0
        } else {
            f64::INFINITY
        }
    } else {
        normalize_linear_algebra_number(numerator / denominator)
    })
}

fn matrix_logarithm_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if value.rows != value.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a square matrix input, found {}x{}",
            value.rows, value.cols
        )));
    }
    if value.rows == 0 {
        return Ok(zero_numeric_or_complex_operand(0, 0));
    }
    if value.rows == 1 {
        return Ok(NumericOrComplexOperand {
            rows: 1,
            cols: 1,
            values: vec![normalize_linear_algebra_complex_parts(value.values[0].ln())],
        });
    }
    if matrix_is_diagonal_operand(value, 1e-12) {
        let diagonal = (0..value.rows)
            .map(|index| {
                normalize_linear_algebra_complex_parts(
                    value.values[index * value.cols + index].ln(),
                )
            })
            .collect::<Vec<_>>();
        return Ok(diagonal_numeric_or_complex_operand(&diagonal));
    }
    if value.rows == 2 {
        return matrix_logarithm_2x2(value, builtin_name);
    }
    if matrix_is_upper_or_lower_triangular(value, 1e-12) {
        return matrix_logarithm_triangular(value);
    }
    Err(RuntimeError::Unsupported(
        "logm currently supports diagonal/triangular matrices and general 2x2 matrices".to_string(),
    ))
}

fn matrix_logarithm_2x2(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let tolerance = default_rank_tolerance(value)?.max(1e-12);
    let eigenvalues = eigenvalues_numeric_or_complex_operand(value, tolerance, builtin_name)?;
    let eigenvectors =
        right_eigenvectors_numeric_or_complex_operand(value, &eigenvalues, tolerance)?;
    if determinant_numeric_or_complex_operand(&eigenvectors).magnitude() > tolerance {
        let log_diagonal = diagonal_numeric_or_complex_operand(
            &eigenvalues
                .iter()
                .copied()
                .map(|value| normalize_linear_algebra_complex_parts(value.ln()))
                .collect::<Vec<_>>(),
        );
        let inverse = solve_square_linear_system(
            &eigenvectors,
            &identity_numeric_or_complex_operand(eigenvectors.rows),
            builtin_name,
        )?;
        return matrix_multiply_operands(
            &matrix_multiply_operands(&eigenvectors, &log_diagonal, builtin_name)?,
            &inverse,
            builtin_name,
        );
    }

    let lambda =
        normalize_linear_algebra_complex_parts(value.values[0].plus(value.values[3]).scale(0.5));
    if lambda.is_approximately_zero() {
        return Err(RuntimeError::Unsupported(
            "logm currently does not support singular defective 2x2 matrices".to_string(),
        ));
    }
    let nilpotent = complex_add_scaled_identity(value, lambda.scale(-1.0))?;
    let factor = normalize_linear_algebra_complex_parts(ComplexParts::one().rdivide(lambda));
    let correction = scale_numeric_or_complex_operand_by_complex(&nilpotent, factor);
    add_numeric_or_complex_operands(
        &complex_scaled_identity_operand(value.rows, lambda.ln()),
        &correction,
        builtin_name,
    )
}

fn matrix_logarithm_triangular(
    value: &NumericOrComplexOperand,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if value.rows != 2 || value.cols != 2 {
        return Err(RuntimeError::Unsupported(
            "logm currently supports triangular matrices only in 2x2 form".to_string(),
        ));
    }
    matrix_logarithm_2x2(value, "logm")
}

fn matrix_function_name(value: &Value) -> Result<String, RuntimeError> {
    match value {
        Value::FunctionHandle(handle) => match &handle.target {
            FunctionHandleTarget::Named(name) => Ok(name.to_ascii_lowercase()),
            _ => Err(RuntimeError::Unsupported(
                "funm currently supports only named function handles".to_string(),
            )),
        },
        Value::CharArray(text) | Value::String(text) => Ok(text.to_ascii_lowercase()),
        other => Err(RuntimeError::TypeError(format!(
            "funm currently expects a function handle or text function name, found {}",
            other.kind_name()
        ))),
    }
}

fn apply_supported_matrix_function(
    value: &NumericOrComplexOperand,
    function_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    match function_name {
        "exp" => matrix_exponential_operand(value, "funm"),
        "log" => matrix_logarithm_operand(value, "funm"),
        "sqrt" => matrix_square_root_operand(value, "funm"),
        "asin" => matrix_inverse_sine_operand(value, "funm"),
        "acos" => matrix_inverse_cosine_operand(value, "funm"),
        "atan" => matrix_inverse_tangent_operand(value, "funm"),
        "asec" => matrix_inverse_secant_operand(value, "funm"),
        "acsc" => matrix_inverse_cosecant_operand(value, "funm"),
        "acot" => matrix_inverse_cotangent_operand(value, "funm"),
        "sin" => matrix_sine_operand(value, "funm"),
        "cos" => matrix_cosine_operand(value, "funm"),
        "tan" => matrix_tangent_operand(value, "funm"),
        "sec" => matrix_secant_operand(value, "funm"),
        "csc" => matrix_cosecant_operand(value, "funm"),
        "cot" => matrix_cotangent_operand(value, "funm"),
        "asinh" => matrix_inverse_hyperbolic_sine_operand(value, "funm"),
        "acosh" => matrix_inverse_hyperbolic_cosine_operand(value, "funm"),
        "atanh" => matrix_inverse_hyperbolic_tangent_operand(value, "funm"),
        "asech" => matrix_inverse_hyperbolic_secant_operand(value, "funm"),
        "acsch" => matrix_inverse_hyperbolic_cosecant_operand(value, "funm"),
        "acoth" => matrix_inverse_hyperbolic_cotangent_operand(value, "funm"),
        "sinh" => matrix_hyperbolic_sine_operand(value, "funm"),
        "cosh" => matrix_hyperbolic_cosine_operand(value, "funm"),
        "tanh" => matrix_hyperbolic_tangent_operand(value, "funm"),
        "sech" => matrix_hyperbolic_secant_operand(value, "funm"),
        "csch" => matrix_hyperbolic_cosecant_operand(value, "funm"),
        "coth" => matrix_hyperbolic_cotangent_operand(value, "funm"),
        other => Err(RuntimeError::Unsupported(format!(
            "funm currently supports only @exp, @log, @sqrt, @asin, @acos, @atan, @asec, @acsc, @acot, @sin, @cos, @tan, @sec, @csc, @cot, @asinh, @acosh, @atanh, @asech, @acsch, @acoth, @sinh, @cosh, @tanh, @sech, @csch, and @coth, not `{other}`"
        ))),
    }
}

fn matrix_inverse_sine_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let imaginary_unit = ComplexParts {
        real: 0.0,
        imag: 1.0,
    };
    let square = matrix_multiply_operands(value, value, builtin_name)?;
    let identity_minus_square = complex_add_scaled_identity(
        &scale_numeric_or_complex_operand(&square, -1.0),
        ComplexParts::one(),
    )?;
    let root = matrix_square_root_operand(&identity_minus_square, builtin_name)?;
    let log_argument = add_numeric_or_complex_operands(
        &scale_numeric_or_complex_operand_by_complex(value, imaginary_unit),
        &root,
        builtin_name,
    )?;
    let logarithm = matrix_logarithm_operand(&log_argument, builtin_name)?;
    Ok(scale_numeric_or_complex_operand_by_complex(
        &logarithm,
        ComplexParts {
            real: 0.0,
            imag: -1.0,
        },
    ))
}

fn matrix_inverse_cosine_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let asin = matrix_inverse_sine_operand(value, builtin_name)?;
    subtract_numeric_or_complex_operands(
        &complex_scaled_identity_operand(
            value.rows,
            ComplexParts {
                real: std::f64::consts::FRAC_PI_2,
                imag: 0.0,
            },
        ),
        &asin,
        builtin_name,
    )
}

fn matrix_inverse_tangent_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let positive = matrix_logarithm_operand(
        &complex_add_scaled_identity(
            &scale_numeric_or_complex_operand_by_complex(
                value,
                ComplexParts {
                    real: 0.0,
                    imag: 1.0,
                },
            ),
            ComplexParts::one(),
        )?,
        builtin_name,
    )?;
    let negative = matrix_logarithm_operand(
        &complex_add_scaled_identity(
            &scale_numeric_or_complex_operand_by_complex(
                value,
                ComplexParts {
                    real: 0.0,
                    imag: -1.0,
                },
            ),
            ComplexParts::one(),
        )?,
        builtin_name,
    )?;
    let difference = subtract_numeric_or_complex_operands(&negative, &positive, builtin_name)?;
    Ok(scale_numeric_or_complex_operand_by_complex(
        &difference,
        ComplexParts {
            real: 0.0,
            imag: 0.5,
        },
    ))
}

fn matrix_inverse_secant_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let reciprocal = solve_square_linear_system(
        value,
        &identity_numeric_or_complex_operand(value.rows),
        builtin_name,
    )?;
    matrix_inverse_cosine_operand(&reciprocal, builtin_name)
}

