fn matrix_inverse_hyperbolic_sine_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let square = matrix_multiply_operands(value, value, builtin_name)?;
    let square_plus_identity = complex_add_scaled_identity(&square, ComplexParts::one())?;
    let root = matrix_square_root_operand(&square_plus_identity, builtin_name)?;
    let log_argument = add_numeric_or_complex_operands(value, &root, builtin_name)?;
    matrix_logarithm_operand(&log_argument, builtin_name)
}

fn matrix_inverse_hyperbolic_cosine_operand(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let minus_identity = complex_add_scaled_identity(
        value,
        ComplexParts {
            real: -1.0,
            imag: 0.0,
        },
    )?;
    let plus_identity = complex_add_scaled_identity(value, ComplexParts::one())?;
    let left = matrix_square_root_operand(&minus_identity, builtin_name)?;
    let right = matrix_square_root_operand(&plus_identity, builtin_name)?;
    let product = matrix_multiply_operands(&left, &right, builtin_name)?;
    let log_argument = add_numeric_or_complex_operands(value, &product, builtin_name)?;
    matrix_logarithm_operand(&log_argument, builtin_name)
}

