fn matrix_square_root_triangular(
    value: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let tolerance = default_rank_tolerance(value)?.max(1e-12);
    let upper = matrix_is_upper_triangular_operand(value, tolerance);
    let triangular = if upper {
        value.clone()
    } else {
        transpose_numeric_or_complex_operand(value, false)
    };
    let root = matrix_square_root_upper_triangular(&triangular, tolerance, builtin_name)?;
    Ok(if upper {
        root
    } else {
        transpose_numeric_or_complex_operand(&root, false)
    })
}

fn matrix_square_root_upper_triangular(
    value: &NumericOrComplexOperand,
    tolerance: f64,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let size = value.rows;
    let mut root = vec![ComplexParts::zero(); size * size];
    for index in 0..size {
        root[index * size + index] =
            normalize_linear_algebra_complex_parts(value.values[index * size + index].sqrt());
    }
    for width in 1..size {
        for row in 0..(size - width) {
            let col = row + width;
            let mut total = value.values[row * size + col];
            for inner in (row + 1)..col {
                total = total.minus(root[row * size + inner].times(root[inner * size + col]));
            }
            let denominator = root[row * size + row].plus(root[col * size + col]);
            if denominator.magnitude() <= tolerance {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports triangular matrices whose principal square-root diagonal sums stay nonzero"
                )));
            }
            root[row * size + col] =
                normalize_linear_algebra_complex_parts(total.rdivide(denominator));
        }
    }
    Ok(NumericOrComplexOperand {
        rows: size,
        cols: size,
        values: root,
    })
}

fn matrix_is_upper_triangular_operand(value: &NumericOrComplexOperand, tolerance: f64) -> bool {
    for row in 0..value.rows {
        for col in 0..row.min(value.cols) {
            if value.values[row * value.cols + col].magnitude() > tolerance {
                return false;
            }
        }
    }
    true
}
fn scale_numeric_or_complex_operand(
    value: &NumericOrComplexOperand,
    factor: f64,
) -> NumericOrComplexOperand {
    NumericOrComplexOperand {
        rows: value.rows,
        cols: value.cols,
        values: value
            .values
            .iter()
            .copied()
            .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(factor)))
            .collect(),
    }
}

fn scale_numeric_or_complex_operand_by_complex(
    value: &NumericOrComplexOperand,
    factor: ComplexParts,
) -> NumericOrComplexOperand {
    NumericOrComplexOperand {
        rows: value.rows,
        cols: value.cols,
        values: value
            .values
            .iter()
            .copied()
            .map(|entry| normalize_linear_algebra_complex_parts(entry.times(factor)))
            .collect(),
    }
}

fn add_numeric_or_complex_operands(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if lhs.rows != rhs.rows || lhs.cols != rhs.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently requires matching matrix shapes"
        )));
    }
    Ok(NumericOrComplexOperand {
        rows: lhs.rows,
        cols: lhs.cols,
        values: lhs
            .values
            .iter()
            .zip(rhs.values.iter())
            .map(|(lhs, rhs)| normalize_linear_algebra_complex_parts(lhs.plus(*rhs)))
            .collect(),
    })
}

fn subtract_numeric_or_complex_operands(
    lhs: &NumericOrComplexOperand,
    rhs: &NumericOrComplexOperand,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    if lhs.rows != rhs.rows || lhs.cols != rhs.cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently requires matching matrix shapes"
        )));
    }
    Ok(NumericOrComplexOperand {
        rows: lhs.rows,
        cols: lhs.cols,
        values: lhs
            .values
            .iter()
            .zip(rhs.values.iter())
            .map(|(lhs, rhs)| normalize_linear_algebra_complex_parts(lhs.minus(*rhs)))
            .collect(),
    })
}

fn matrix_is_diagonal_operand(value: &NumericOrComplexOperand, tolerance: f64) -> bool {
    for row in 0..value.rows {
        for col in 0..value.cols {
            if row != col && value.values[row * value.cols + col].magnitude() > tolerance {
                return false;
            }
        }
    }
    true
}

fn svd_factor_operands(
    value: &NumericOrComplexOperand,
    econ: bool,
    tolerance: f64,
) -> Result<(NumericOrComplexOperand, Vec<f64>, NumericOrComplexOperand), RuntimeError> {
    let singular_values = singular_values_and_right_vectors_with_tolerance(value, tolerance)?;
    let singular_scalars = singular_values
        .iter()
        .map(|(sigma, _)| *sigma)
        .collect::<Vec<_>>();
    let k = value.rows.min(value.cols);
    let target_u_cols = if econ && value.rows > value.cols {
        k
    } else {
        value.rows
    };
    let target_v_cols = if econ && value.rows < value.cols {
        k
    } else {
        value.cols
    };

    let mut right_columns = singular_values
        .iter()
        .map(|(_, column)| canonicalize_basis_vector(column.clone(), tolerance))
        .collect::<Vec<_>>();
    complete_orthonormal_columns(value.cols, target_v_cols, &mut right_columns, tolerance);
    let v_operand = columns_to_operand(value.cols, right_columns);

    let positive_count = singular_scalars.len();
    let mut left_columns = Vec::new();
    for column in 0..positive_count {
        let v_column = (0..value.cols)
            .map(|row| v_operand.values[row * v_operand.cols + column])
            .collect::<Vec<_>>();
        let product = matrix_multiply_operands(
            value,
            &NumericOrComplexOperand {
                rows: value.cols,
                cols: 1,
                values: v_column,
            },
            "svd",
        )?;
        let sigma = singular_scalars[column];
        left_columns.push(
            product
                .values
                .into_iter()
                .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / sigma)))
                .collect::<Vec<_>>(),
        );
    }
    complete_orthonormal_columns(value.rows, target_u_cols, &mut left_columns, tolerance);
    let u_operand = columns_to_operand(value.rows, left_columns);

    Ok((u_operand, singular_scalars, v_operand))
}

#[allow(dead_code)]
fn singular_values_and_right_vectors(
    value: &NumericOrComplexOperand,
) -> Result<Vec<(f64, Vec<ComplexParts>)>, RuntimeError> {
    singular_values_and_right_vectors_with_tolerance(
        value,
        default_rank_tolerance(value)?.max(1e-12),
    )
}

fn singular_values_and_right_vectors_with_tolerance(
    value: &NumericOrComplexOperand,
    tolerance: f64,
) -> Result<Vec<(f64, Vec<ComplexParts>)>, RuntimeError> {
    let gram = matrix_multiply_operands(
        &transpose_numeric_or_complex_operand(value, true),
        value,
        "svd",
    )?;
    let k = value.rows.min(value.cols);
    let mut basis = Vec::new();
    let mut components = Vec::new();
    for component in 0..k {
        let Some(vector) = dominant_orthogonal_gram_vector(&gram, &basis, component, tolerance)?
        else {
            break;
        };
        let sigma = singular_value_from_gram_vector(&gram, &vector)?;
        if sigma <= tolerance {
            break;
        }
        basis.push(vector.clone());
        components.push((normalize_linear_algebra_number(sigma), vector));
    }
    components.sort_by(|lhs, rhs| rhs.0.total_cmp(&lhs.0));
    Ok(components)
}

fn dominant_orthogonal_gram_vector(
    gram: &NumericOrComplexOperand,
    basis: &[Vec<ComplexParts>],
    seed_offset: usize,
    tolerance: f64,
) -> Result<Option<Vec<ComplexParts>>, RuntimeError> {
    let mut vector = seed_orthogonal_vector(gram.cols, basis, seed_offset, tolerance);
    let Some(mut vector) = vector.take() else {
        return Ok(None);
    };

    for _ in 0..48 {
        let next = matrix_multiply_operands(
            gram,
            &NumericOrComplexOperand {
                rows: gram.cols,
                cols: 1,
                values: vector.clone(),
            },
            "svd",
        )?;
        let mut next_vector = next.values;
        orthogonalize_vector(&mut next_vector, basis);
        let norm = vector_norm(&next_vector, NormKind::Two);
        if norm <= tolerance {
            return Ok(None);
        }
        vector = next_vector
            .into_iter()
            .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / norm)))
            .collect();
    }

    Ok(Some(canonicalize_basis_vector(vector, tolerance)))
}

fn singular_value_from_gram_vector(
    gram: &NumericOrComplexOperand,
    vector: &[ComplexParts],
) -> Result<f64, RuntimeError> {
    let projected = matrix_multiply_operands(
        gram,
        &NumericOrComplexOperand {
            rows: gram.cols,
            cols: 1,
            values: vector.to_vec(),
        },
        "svd",
    )?;
    let rayleigh = vector
        .iter()
        .zip(projected.values.iter())
        .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
            total.plus(lhs.conjugate().times(*rhs))
        });
    Ok(rayleigh.real.max(0.0).sqrt())
}

fn seed_orthogonal_vector(
    size: usize,
    basis: &[Vec<ComplexParts>],
    seed_offset: usize,
    tolerance: f64,
) -> Option<Vec<ComplexParts>> {
    for candidate in 0..size {
        let mut vector = vec![ComplexParts::zero(); size];
        vector[(candidate + seed_offset) % size] = ComplexParts::one();
        orthogonalize_vector(&mut vector, basis);
        let norm = vector_norm(&vector, NormKind::Two);
        if norm > tolerance {
            return Some(
                vector
                    .into_iter()
                    .map(|entry| normalize_linear_algebra_complex_parts(entry.scale(1.0 / norm)))
                    .collect(),
            );
        }
    }
    None
}

fn orthogonalize_vector(vector: &mut Vec<ComplexParts>, basis: &[Vec<ComplexParts>]) {
    for existing in basis {
        let projection = existing
            .iter()
            .zip(vector.iter())
            .fold(ComplexParts::zero(), |total, (lhs, rhs)| {
                total.plus((*lhs).conjugate().times(*rhs))
            });
        for (entry, basis_entry) in vector.iter_mut().zip(existing.iter()) {
            *entry = normalize_linear_algebra_complex_parts(
                (*entry).minus((*basis_entry).times(projection)),
            );
        }
    }
}

fn svd_singular_values_output(
    singular_values: &[f64],
    rows: usize,
    cols: usize,
    econ: bool,
    output_form: SvdOutputForm,
    include_vectors: bool,
) -> Result<Value, RuntimeError> {
    match output_form {
        SvdOutputForm::Vector => numeric_values_to_column_matrix(
            singular_values
                .iter()
                .copied()
                .map(normalize_linear_algebra_number)
                .collect(),
        ),
        SvdOutputForm::Matrix => {
            let diag_size = rows.min(cols);
            let matrix_rows = if include_vectors && !econ {
                rows
            } else {
                diag_size
            };
            let matrix_cols = if include_vectors && !econ {
                cols
            } else {
                diag_size
            };
            let mut values = vec![Value::Scalar(0.0); matrix_rows * matrix_cols];
            for (index, sigma) in singular_values.iter().copied().enumerate().take(diag_size) {
                values[index * matrix_cols + index] =
                    Value::Scalar(normalize_linear_algebra_number(sigma));
            }
            Ok(Value::Matrix(MatrixValue::new(
                matrix_rows,
                matrix_cols,
                values,
            )?))
        }
    }
}

fn complex_polynomial_add(lhs: &[ComplexParts], rhs: &[ComplexParts]) -> Vec<ComplexParts> {
    let len = lhs.len().max(rhs.len());
    let lhs_offset = len - lhs.len();
    let rhs_offset = len - rhs.len();
    (0..len)
        .map(|index| {
            let lhs_value = if index >= lhs_offset {
                lhs[index - lhs_offset]
            } else {
                ComplexParts::zero()
            };
            let rhs_value = if index >= rhs_offset {
                rhs[index - rhs_offset]
            } else {
                ComplexParts::zero()
            };
            normalize_complex_parts(lhs_value.plus(rhs_value))
        })
        .collect::<Vec<_>>()
}

fn complex_polynomial_subtract(lhs: &[ComplexParts], rhs: &[ComplexParts]) -> Vec<ComplexParts> {
    let len = lhs.len().max(rhs.len());
    let lhs_offset = len - lhs.len();
    let rhs_offset = len - rhs.len();
    (0..len)
        .map(|index| {
            let lhs_value = if index >= lhs_offset {
                lhs[index - lhs_offset]
            } else {
                ComplexParts::zero()
            };
            let rhs_value = if index >= rhs_offset {
                rhs[index - rhs_offset]
            } else {
                ComplexParts::zero()
            };
            normalize_complex_parts(lhs_value.minus(rhs_value))
        })
        .collect::<Vec<_>>()
}

fn zero_small(value: f64) -> f64 {
    if value.abs() <= 1e-12 {
        0.0
    } else {
        value
    }
}

fn normalize_polynomial_scalar(value: f64) -> f64 {
    let value = zero_small(value);
    let rounded = value.round();
    if (value - rounded).abs() <= 1e-12 {
        rounded
    } else {
        value
    }
}

fn degree_special_angle_bucket(angle_degrees: f64) -> Option<i32> {
    if !angle_degrees.is_finite() {
        return None;
    }
    let rounded = angle_degrees.round();
    if (angle_degrees - rounded).abs() > 1e-12 {
        return None;
    }
    Some((rounded as i32).rem_euclid(360))
}

fn degree_special_sine(angle_degrees: f64) -> Option<f64> {
    match degree_special_angle_bucket(angle_degrees)? {
        0 | 180 => Some(0.0),
        30 | 150 => Some(0.5),
        45 | 135 => Some(std::f64::consts::FRAC_1_SQRT_2),
        60 | 120 => Some((3.0f64).sqrt() * 0.5),
        90 => Some(1.0),
        210 | 330 => Some(-0.5),
        225 | 315 => Some(-std::f64::consts::FRAC_1_SQRT_2),
        240 | 300 => Some(-(3.0f64).sqrt() * 0.5),
        270 => Some(-1.0),
        _ => None,
    }
}

fn degree_special_cosine(angle_degrees: f64) -> Option<f64> {
    match degree_special_angle_bucket(angle_degrees)? {
        90 | 270 => Some(0.0),
        60 | 300 => Some(0.5),
        45 | 315 => Some(std::f64::consts::FRAC_1_SQRT_2),
        30 | 330 => Some((3.0f64).sqrt() * 0.5),
        0 => Some(1.0),
        120 | 240 => Some(-0.5),
        135 | 225 => Some(-std::f64::consts::FRAC_1_SQRT_2),
        150 | 210 => Some(-(3.0f64).sqrt() * 0.5),
        180 => Some(-1.0),
        _ => None,
    }
}

fn degree_special_tangent(angle_degrees: f64) -> Option<f64> {
    let sine = degree_special_sine(angle_degrees)?;
    let cosine = degree_special_cosine(angle_degrees)?;
    if cosine == 0.0 {
        if sine.is_sign_negative() {
            Some(f64::NEG_INFINITY)
        } else {
            Some(f64::INFINITY)
        }
    } else {
        Some(sine / cosine)
    }
}

fn value_dimensions(value: &Value) -> Vec<usize> {
    match value {
        Value::Scalar(_)
        | Value::Int64(_)
        | Value::UInt64(_)
        | Value::Complex(_)
        | Value::Logical(_)
        | Value::FunctionHandle(_)
        | Value::Object(_) => {
            vec![1, 1]
        }
        Value::CharArray(text) => {
            let count = text.chars().count();
            if count == 0 {
                vec![0, 0]
            } else {
                vec![1, count]
            }
        }
        Value::String(_) => vec![1, 1],
        Value::Matrix(matrix) => matrix.dims().to_vec(),
        Value::Cell(cell) => cell.dims().to_vec(),
        Value::Struct(_) => vec![1, 1],
    }
}

fn single_char_text_value(value: &Value) -> Option<char> {
    let Value::CharArray(text) = value else {
        return None;
    };
    let mut chars = text.chars();
    let ch = chars.next()?;
    chars.next().is_none().then_some(ch)
}

fn char_value_with_dimensions(dims: Vec<usize>, chars: Vec<char>) -> Result<Value, RuntimeError> {
    if chars.is_empty() {
        return Ok(Value::CharArray(String::new()));
    }

    let (rows, cols) = storage_shape_from_dimensions(&dims);
    if rows == 1 && dims.iter().skip(2).all(|dim| *dim == 1) {
        return Ok(Value::CharArray(chars.into_iter().collect()));
    }

    Ok(Value::Matrix(MatrixValue::with_dimensions(
        rows,
        cols,
        dims,
        chars
            .into_iter()
            .map(|ch| Value::CharArray(ch.to_string()))
            .collect(),
    )?))
}

fn canonical_ndims(dims: &[usize]) -> usize {
    let mut count = dims.len().max(2);
    while count > 2 && dims[count - 1] == 1 {
        count -= 1;
    }
    count.max(2)
}

fn canonical_size_vector(dims: &[usize]) -> Vec<usize> {
    dims[..canonical_ndims(dims)].to_vec()
}

fn parse_size_arguments<'a>(
    args: &'a [Value],
) -> Result<Option<(&'a Value, Option<Vec<usize>>)>, RuntimeError> {
    let Some((value, query_dims)) = args.split_first() else {
        return Ok(None);
    };
    if query_dims.is_empty() {
        return Ok(Some((value, None)));
    }
    if query_dims.len() == 1 {
        return Ok(Some((value, Some(size_query_dimensions(&query_dims[0])?))));
    }

    let dims = query_dims
        .iter()
        .map(size_query_dimension_scalar)
        .collect::<Result<Vec<_>, _>>()?;
    Ok(Some((value, Some(dims))))
}

fn dimension_length(dims: &[usize], dim: usize) -> usize {
    dims.get(dim.saturating_sub(1)).copied().unwrap_or(1)
}

fn default_flip_dimension(value: &Value) -> usize {
    value_dimensions(value)
        .iter()
        .position(|&dim| dim != 1)
        .map(|index| index + 1)
        .unwrap_or(1)
}

fn default_reduction_dimension_from_dims(dims: &[usize]) -> usize {
    canonical_size_vector(dims)
        .iter()
        .position(|&dim| dim != 1)
        .map(|index| index + 1)
        .unwrap_or(1)
}

fn squeeze_dimensions(dims: &[usize]) -> Vec<usize> {
    if dims.len() <= 2 {
        return canonical_size_vector(dims);
    }

    let kept = dims
        .iter()
        .copied()
        .filter(|&dim| dim != 1)
        .collect::<Vec<_>>();
    if kept.is_empty() {
        vec![1, 1]
    } else if kept.len() == 1 {
        vec![kept[0], 1]
    } else {
        kept
    }
}

fn relabel_value_dimensions(value: &Value, dims: Vec<usize>) -> Result<Value, RuntimeError> {
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    match value {
        Value::CharArray(text) => {
            let chars = text.chars().collect::<Vec<_>>();
            let target_len = dims.iter().product::<usize>();
            if chars.len() != target_len {
                return Err(RuntimeError::ShapeError(format!(
                    "cannot relabel char array with {} element(s) as dimensions {:?}",
                    chars.len(),
                    dims
                )));
            }
            char_value_with_dimensions(dims, chars)
        }
        Value::Matrix(matrix) => Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            dims,
            matrix.elements().to_vec(),
        )?)),
        Value::Cell(cell) => Ok(Value::Cell(CellValue::with_dimensions(
            rows,
            cols,
            dims,
            cell.elements().to_vec(),
        )?)),
        _ => Ok(value.clone()),
    }
}

fn storage_shape_from_dimensions(dims: &[usize]) -> (usize, usize) {
    match dims {
        [] => (1, 1),
        [only] => (*only, 1),
        [rows, cols] => (*rows, *cols),
        [rows, rest @ ..] => (*rows, rest.iter().product()),
    }
}

fn shiftdim_remove_leading_singletons(value: &Value) -> Result<(Value, usize), RuntimeError> {
    let dims = value_dimensions(value);
    let removed = dims.iter().take_while(|&&dim| dim == 1).count();
    let stripped = dims.iter().copied().skip(removed).collect::<Vec<_>>();
    let normalized = if stripped.is_empty() {
        vec![1, 1]
    } else if stripped.len() == 1 {
        vec![stripped[0], 1]
    } else {
        stripped
    };
    Ok((relabel_value_dimensions(value, normalized)?, removed))
}

fn shiftdim_positive(value: &Value, shift: usize) -> Result<Value, RuntimeError> {
    let dims = canonical_size_vector(&value_dimensions(value));
    if dims.is_empty() {
        return Ok(value.clone());
    }
    let effective = shift % dims.len();
    if effective == 0 {
        return Ok(value.clone());
    }
    let order = (0..dims.len())
        .map(|index| ((index + effective) % dims.len()) + 1)
        .collect::<Vec<_>>();
    permute_value(value, &order, "shiftdim")
}

fn shiftdim_negative(value: &Value, shift: usize) -> Result<Value, RuntimeError> {
    if shift == 0 {
        return Ok(value.clone());
    }

    let mut dims = vec![1; shift];
    dims.extend(canonical_size_vector(&value_dimensions(value)));
    relabel_value_dimensions(value, dims)
}

fn size_query_dimensions(value: &Value) -> Result<Vec<usize>, RuntimeError> {
    match value {
        Value::Scalar(number) => positive_query_dimensions_from_scalars(&[*number]),
        Value::Logical(flag) => {
            positive_query_dimensions_from_scalars(&[if *flag { 1.0 } else { 0.0 }])
        }
        Value::Matrix(matrix) => {
            let scalars = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            positive_query_dimensions_from_scalars(&scalars)
        }
        _ => Err(RuntimeError::TypeError(
            "size dimension query currently expects a real numeric scalar or vector".to_string(),
        )),
    }
}

fn positive_query_dimensions_from_scalars(values: &[f64]) -> Result<Vec<usize>, RuntimeError> {
    values
        .iter()
        .map(|&value| {
            if !value.is_finite() || value.fract() != 0.0 || value < 1.0 {
                Err(RuntimeError::TypeError(
                    "size dimension queries must be positive integer values".to_string(),
                ))
            } else {
                Ok(value as usize)
            }
        })
        .collect()
}

fn size_query_dimension_scalar(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 || scalar < 1.0 {
        return Err(RuntimeError::TypeError(
            "size dimension queries must be positive integer values".to_string(),
        ));
    }
    Ok(scalar as usize)
}

fn parse_reshape_arguments<'a>(
    args: &'a [Value],
) -> Result<Option<(&'a Value, Vec<Option<usize>>)>, RuntimeError> {
    let Some((value, dims)) = args.split_first() else {
        return Ok(None);
    };
    if dims.is_empty() {
        return Ok(None);
    }

    if dims.len() == 1 {
        return Ok(Some((value, reshape_size_vector(&dims[0])?)));
    }

    Ok(Some((
        value,
        dims.iter()
            .map(reshape_size_argument)
            .collect::<Result<Vec<_>, _>>()?,
    )))
}

fn reshape_size_vector(value: &Value) -> Result<Vec<Option<usize>>, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) => Ok(vec![reshape_size_argument(value)?]),
        Value::Matrix(matrix) => matrix
            .iter()
            .map(reshape_size_argument)
            .collect::<Result<Vec<_>, _>>(),
        _ => Err(RuntimeError::TypeError(
            "reshape size vectors currently expect real numeric or empty-matrix entries"
                .to_string(),
        )),
    }
}

fn fill_dimensions(args: &[Value], builtin_name: &str) -> Result<Vec<usize>, RuntimeError> {
    match args {
        [size] => match size {
            Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0 => Ok(vec![0, 0]),
            Value::Matrix(matrix) => {
                let dims = matrix
                    .iter()
                    .map(|value| fill_dimension(value, builtin_name))
                    .collect::<Result<Vec<_>, _>>()?;
                Ok(if dims.len() == 1 {
                    vec![dims[0], dims[0]]
                } else {
                    dims
                })
            }
            _ => {
                let size = fill_dimension(size, builtin_name)?;
                Ok(vec![size, size])
            }
        },
        dims if !dims.is_empty() => dims
            .iter()
            .map(|value| {
                let dim = fill_dimension(value, builtin_name)?;
                Ok(dim)
            })
            .collect(),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects one size scalar/vector or multiple scalar dimensions"
        ))),
    }
}

fn fill_dimension(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects integer-valued dimension sizes"
        )));
    }
    Ok(scalar.max(0.0) as usize)
}

fn parse_repmat_arguments<'a>(
    args: &'a [Value],
) -> Result<Option<(&'a Value, Vec<usize>)>, RuntimeError> {
    let Some((value, reps)) = args.split_first() else {
        return Ok(None);
    };
    if reps.is_empty() {
        return Ok(None);
    }

    if reps.len() == 1 {
        let repetitions = match reps[0] {
            Value::Matrix(ref matrix) if matrix.rows > 0 && matrix.cols > 0 => {
                parse_repetition_vector(&reps[0])?
            }
            _ => {
                let scalar = repetition_scalar(&reps[0])?;
                vec![scalar, scalar]
            }
        };
        return Ok(Some((value, repetitions)));
    }

    Ok(Some((
        value,
        reps.iter()
            .map(repetition_scalar)
            .collect::<Result<Vec<_>, _>>()?,
    )))
}

fn parse_repetition_vector(value: &Value) -> Result<Vec<usize>, RuntimeError> {
    match value {
        Value::Matrix(matrix) => matrix
            .iter()
            .map(repetition_scalar)
            .collect::<Result<Vec<_>, _>>(),
        _ => Err(RuntimeError::TypeError(
            "repmat repetition vectors must be real numeric".to_string(),
        )),
    }
}

fn repetition_scalar(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(
            "repmat repetition counts must be integer values".to_string(),
        ));
    }
    Ok(if scalar <= 0.0 { 0 } else { scalar as usize })
}

fn reshape_size_argument(value: &Value) -> Result<Option<usize>, RuntimeError> {
    match value {
        Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0 => Ok(None),
        Value::Scalar(number) => {
            if !number.is_finite() || *number < 0.0 || number.fract() != 0.0 {
                return Err(RuntimeError::TypeError(
                    "reshape dimensions must be nonnegative integer values or []".to_string(),
                ));
            }
            Ok(Some(*number as usize))
        }
        Value::Logical(flag) => Ok(Some(if *flag { 1 } else { 0 })),
        _ => Err(RuntimeError::TypeError(
            "reshape dimensions must be real numeric values or []".to_string(),
        )),
    }
}

fn finalize_reshape_dimensions(
    value: &Value,
    dims: Vec<Option<usize>>,
) -> Result<Vec<usize>, RuntimeError> {
    if dims.is_empty() {
        return Err(RuntimeError::Unsupported(
            "reshape currently expects at least one target dimension".to_string(),
        ));
    }
    let unknown_count = dims.iter().filter(|dim| dim.is_none()).count();
    if unknown_count > 1 {
        return Err(RuntimeError::Unsupported(
            "reshape currently supports at most one inferred [] dimension".to_string(),
        ));
    }

    let element_count = match value {
        Value::Scalar(_) => 1,
        Value::Object(_) => 1,
        Value::CharArray(text) => text.chars().count(),
        Value::Matrix(matrix) => matrix.elements.len(),
        Value::Cell(cell) => cell.elements.len(),
        _ => {
            return Err(RuntimeError::TypeError(
                "reshape currently expects scalar, object, char, matrix, or cell input".to_string(),
            ))
        }
    };

    let known_product = dims
        .iter()
        .flatten()
        .copied()
        .fold(1usize, |acc, dim| acc.saturating_mul(dim));
    let finalized = if unknown_count == 0 {
        dims.into_iter()
            .map(|dim| dim.expect("known dim"))
            .collect::<Vec<_>>()
    } else {
        if known_product == 0 || element_count % known_product != 0 {
            return Err(RuntimeError::ShapeError(
                "reshape inferred [] dimension does not divide the input element count".to_string(),
            ));
        }
        let inferred = element_count / known_product;
        dims.into_iter()
            .map(|dim| dim.unwrap_or(inferred))
            .collect::<Vec<_>>()
    };
    Ok(if finalized.len() == 1 {
        vec![finalized[0], 1]
    } else {
        finalized
    })
}

fn parse_dim_order(value: &Value, builtin_name: &str) -> Result<Vec<usize>, RuntimeError> {
    let order = size_query_dimensions(value)?;
    if order.is_empty() {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects a nonempty dimension-order vector"
        )));
    }
    let mut sorted = order.clone();
    sorted.sort_unstable();
    let expected = (1..=order.len()).collect::<Vec<_>>();
    if sorted != expected {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} dimension order must be a permutation of 1:{}",
            order.len()
        )));
    }
    Ok(order)
}

fn permute_value(
    value: &Value,
    order: &[usize],
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_)
        | Value::Complex(_)
        | Value::Logical(_)
        | Value::FunctionHandle(_)
        | Value::Object(_) => {
            Ok(value.clone())
        }
        Value::CharArray(text) => {
            let dims = value_dimensions(value);
            let elements = text
                .chars()
                .map(|ch| Value::CharArray(ch.to_string()))
                .collect::<Vec<_>>();
            let (_rows, _cols, permuted_dims, permuted_elements) =
                permute_row_major_elements(&elements, &dims, order);
            let chars = permuted_elements
                .iter()
                .map(|value| {
                    single_char_text_value(value).ok_or_else(|| {
                        RuntimeError::TypeError(
                            "permute currently expects char arrays to contain single-character elements"
                                .to_string(),
                        )
                    })
                })
                .collect::<Result<Vec<_>, _>>()?;
            char_value_with_dimensions(permuted_dims, chars)
        }
        Value::Matrix(matrix) => {
            let dims = matrix.dims().to_vec();
            let (rows, cols, permuted_dims, elements) =
                permute_row_major_elements(matrix.elements(), &dims, order);
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                permuted_dims,
                elements,
            )?))
        }
        Value::Cell(cell) => {
            let dims = cell.dims().to_vec();
            let (rows, cols, permuted_dims, elements) =
                permute_row_major_elements(cell.elements(), &dims, order);
            Ok(Value::Cell(CellValue::with_dimensions(
                rows,
                cols,
                permuted_dims,
                elements,
            )?))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, object, char, matrix, cell, or function-handle input"
        ))),
    }
}

fn permute_row_major_elements<T: Clone>(
    elements: &[T],
    dims: &[usize],
    order: &[usize],
) -> (usize, usize, Vec<usize>, Vec<T>) {
    let mut source_dims = dims.to_vec();
    while source_dims.len() < order.len() {
        source_dims.push(1);
    }
    let permuted_dims = order
        .iter()
        .map(|&dim| source_dims[dim - 1])
        .collect::<Vec<_>>();
    let (rows, cols) = storage_shape_from_dimensions(&permuted_dims);
    if elements.is_empty() {
        return (rows, cols, permuted_dims, Vec::new());
    }
    let mut inverse = vec![0usize; order.len()];
    for (dest_axis, &source_axis) in order.iter().enumerate() {
        inverse[source_axis - 1] = dest_axis;
    }
    let mut output = vec![elements[0].clone(); elements.len()];
    for source_linear in 0..elements.len() {
        let source_index = row_major_multi_index(source_linear, &source_dims);
        let mut dest_index = vec![0usize; order.len()];
        for source_axis in 0..order.len() {
            dest_index[inverse[source_axis]] = source_index[source_axis];
        }
        let dest_linear = row_major_linear_index(&dest_index, &permuted_dims);
        output[dest_linear] = elements[source_linear].clone();
    }
    (rows, cols, permuted_dims, output)
}

fn reshape_elements_column_major<T: Clone>(
    elements: &[T],
    source_dims: &[usize],
    target_dims: &[usize],
) -> Vec<T> {
    if elements.is_empty() {
        return Vec::new();
    }

    let mut normalized_source_dims = source_dims.to_vec();
    while normalized_source_dims.len() < target_dims.len() {
        normalized_source_dims.push(1);
    }

    let element_count = target_dims.iter().product::<usize>();
    let mut output = vec![elements[0].clone(); element_count];
    for linear in 0..element_count {
        let source_index = column_major_multi_index(linear, &normalized_source_dims);
        let source_offset = row_major_linear_index(&source_index, &normalized_source_dims);
        let target_index = column_major_multi_index(linear, target_dims);
        let target_offset = row_major_linear_index(&target_index, target_dims);
        output[target_offset] = elements[source_offset].clone();
    }
    output
}

fn concatenated_dimensions(
    inputs: &[Vec<usize>],
    along_dim: usize,
    builtin_name: &str,
) -> Result<Vec<usize>, RuntimeError> {
    if inputs.is_empty() {
        return Ok(vec![0, 0]);
    }
    let rank = inputs
        .iter()
        .map(|dims| dims.len())
        .max()
        .unwrap_or(2)
        .max(along_dim)
        .max(2);
    let mut output = vec![1usize; rank];
    output[along_dim - 1] = 0;
    for dims in inputs {
        for axis in 0..rank {
            let value = dims.get(axis).copied().unwrap_or(1);
            if axis + 1 == along_dim {
                output[axis] += value;
            } else if output[axis] == 1 {
                output[axis] = value;
            } else if value != 1 && value != output[axis] {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} requires matching sizes in every dimension except {}",
                    along_dim
                )));
            }
        }
    }
    Ok(output)
}

fn concatenate_elements<T: Clone>(
    element_groups: &[Vec<T>],
    input_dims: &[Vec<usize>],
    output_dims: &[usize],
    along_dim: usize,
) -> Vec<T> {
    let total = output_dims.iter().product::<usize>();
    if total == 0 {
        return Vec::new();
    }

    let prototype = element_groups
        .iter()
        .find_map(|group| group.first())
        .cloned()
        .expect("nonempty concatenation output requires at least one source element");
    let mut output = vec![prototype; total];
    let mut running = 0usize;
    for (group_index, dims) in input_dims.iter().enumerate() {
        let mut normalized = dims.clone();
        while normalized.len() < output_dims.len() {
            normalized.push(1);
        }
        let block = normalized.iter().product::<usize>();
        for linear in 0..block {
            let mut dest_index = row_major_multi_index(linear, &normalized);
            dest_index[along_dim - 1] += running;
            let dest_linear = row_major_linear_index(&dest_index, output_dims);
            output[dest_linear] = element_groups[group_index][linear].clone();
        }
        running += normalized[along_dim - 1];
    }
    output
}

fn row_major_multi_index(mut linear: usize, dims: &[usize]) -> Vec<usize> {
    let mut index = vec![0usize; dims.len()];
    for axis in (0..dims.len()).rev() {
        let dim = dims[axis].max(1);
        index[axis] = linear % dim;
        linear /= dim;
    }
    index
}

fn column_major_multi_index(mut linear: usize, dims: &[usize]) -> Vec<usize> {
    let mut index = vec![0usize; dims.len()];
    for axis in 0..dims.len() {
        let dim = dims[axis].max(1);
        index[axis] = linear % dim;
        linear /= dim;
    }
    index
}

fn row_major_linear_index(index: &[usize], dims: &[usize]) -> usize {
    let mut linear = 0usize;
    for (axis, &value) in index.iter().enumerate() {
        linear = (linear * dims[axis].max(1)) + value;
    }
    linear
}

fn double_spacing_from_abs(magnitude: f64) -> f64 {
    if magnitude.is_nan() || magnitude.is_infinite() {
        return f64::NAN;
    }
    let value = magnitude.abs();
    if value == 0.0 {
        return f64::from_bits(1);
    }
    let bits = value.to_bits();
    let exponent_bits = ((bits >> 52) & 0x7ff) as i32;
    if exponent_bits == 0 {
        return f64::from_bits(1);
    }
    let unbiased = exponent_bits - 1023;
    2f64.powi(unbiased - 52)
}

fn log2_fraction_exponent(value: f64) -> (f64, i32) {
    if value == 0.0 {
        return (0.0, 0);
    }
    if !value.is_finite() {
        return (value, 0);
    }
    let sign = if value.is_sign_negative() { -1.0 } else { 1.0 };
    let bits = value.abs().to_bits();
    let exponent_bits = ((bits >> 52) & 0x7ff) as i32;
    let mantissa = bits & ((1u64 << 52) - 1);
    let (fraction, exponent) = if exponent_bits == 0 {
        let msb_pos = 63 - (mantissa.leading_zeros() as i32);
        (
            sign * ((mantissa as f64) / 2f64.powi(msb_pos + 1)),
            msb_pos - 1073,
        )
    } else {
        (
            sign * ((1.0 + (mantissa as f64) / 4_503_599_627_370_496.0) * 0.5),
            exponent_bits - 1022,
        )
    };
    (normalize_polynomial_scalar(fraction), exponent)
}

fn normalize_complex_parts(value: ComplexParts) -> ComplexParts {
    ComplexParts {
        real: normalize_polynomial_scalar(value.real),
        imag: normalize_polynomial_scalar(value.imag),
    }
}

fn normalize_linear_algebra_complex_parts(value: ComplexParts) -> ComplexParts {
    ComplexParts {
        real: normalize_linear_algebra_number(value.real),
        imag: normalize_linear_algebra_number(value.imag),
    }
}

fn normalize_linear_algebra_number(value: f64) -> f64 {
    let value = zero_small(value);
    let integer = value.round();
    if (value - integer).abs() <= 1e-12 {
        return integer;
    }

    let rounded = (value * 1e12).round() / 1e12;
    if rounded == 0.0 {
        0.0
    } else {
        rounded
    }
}

fn parse_filter_args<'a>(
    args: &'a [Value],
) -> Result<
    (
        &'a Value,
        &'a Value,
        &'a Value,
        Option<&'a Value>,
        Option<usize>,
    ),
    RuntimeError,
> {
    match args {
        [b, a, x] => Ok((b, a, x, None, None)),
        [b, a, x, zi] => Ok((b, a, x, Some(zi), None)),
        [b, a, x, zi, dim] => Ok((b, a, x, Some(zi), Some(positive_dimension(dim, "filter")?))),
        _ => Err(RuntimeError::Unsupported(
            "filter currently supports `filter(b, a, x)`, `filter(b, a, x, zi)`, or `filter(b, a, x, zi, dim)`".to_string(),
        )),
    }
}

fn normalized_filter_coefficients(
    b: &[ComplexParts],
    a: &[ComplexParts],
) -> (Vec<ComplexParts>, Vec<ComplexParts>) {
    let scale = a[0];
    (
        b.iter()
            .map(|value| normalize_complex_parts((*value).rdivide(scale)))
            .collect::<Vec<_>>(),
        a.iter()
            .map(|value| normalize_complex_parts((*value).rdivide(scale)))
            .collect::<Vec<_>>(),
    )
}

fn filter_sequence_count(dims: &[usize], dim: usize) -> usize {
    let mut normalized_dims = canonical_size_vector(dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(axis, &size)| (axis + 1 != dim).then_some(size))
        .product::<usize>()
        .max(1)
}

fn filter_has_omitted_initial_conditions(value: &Value) -> bool {
    matches!(value, Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0)
}

fn parse_filter_initial_conditions(
    zi: Option<&Value>,
    state_len: usize,
    sequence_count: usize,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let zero_state = || vec![ComplexParts::zero(); state_len * sequence_count];
    let Some(zi) = zi else {
        return Ok(zero_state());
    };
    if filter_has_omitted_initial_conditions(zi) {
        return Ok(zero_state());
    }

    if state_len == 0 {
        let operand = numeric_or_complex_operand(zi, "filter")?;
        if operand.values.is_empty() {
            return Ok(Vec::new());
        }
        return Err(RuntimeError::ShapeError(
            "filter currently expects empty initial conditions when max(length(a), length(b)) is 1"
                .to_string(),
        ));
    }

    let operand = numeric_or_complex_operand(zi, "filter")?;
    if sequence_count == 1 && (operand.rows == 1 || operand.cols == 1) {
        if operand.values.len() != state_len {
            return Err(RuntimeError::ShapeError(format!(
                "filter requires zi to have {} element(s) for the current coefficient lengths",
                state_len
            )));
        }
        return Ok(operand.values);
    }

    if operand.rows != state_len || operand.cols != sequence_count {
        return Err(RuntimeError::ShapeError(format!(
            "filter requires zi to have size {}x{} for the current input shape and dimension",
            state_len, sequence_count
        )));
    }

    Ok(operand.values)
}

fn parse_ctffilt_initial_conditions(
    zi: Option<&Value>,
    section_state_len: usize,
    section_count: usize,
    sequence_count: usize,
    state_dims: &[usize],
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let total_state_len = section_state_len * section_count;
    let zero_state = || vec![ComplexParts::zero(); total_state_len * sequence_count];
    let Some(zi) = zi else {
        return Ok(zero_state());
    };
    if filter_has_omitted_initial_conditions(zi) {
        return Ok(zero_state());
    }
    if total_state_len == 0 {
        let operand = numeric_or_complex_operand(zi, "ctffilt")?;
        if operand.values.is_empty() {
            return Ok(Vec::new());
        }
        return Err(RuntimeError::ShapeError(
            "ctffilt does not accept nonempty zi when the cascaded filter has zero state order"
                .to_string(),
        ));
    }

    let operand = numeric_or_complex_nd_operand(zi, "ctffilt")?;
    if operand.values.len() == section_state_len {
        let mut state = zero_state();
        for section in 0..section_count {
            for delay in 0..section_state_len {
                for sequence in 0..sequence_count {
                    state[(section * section_state_len + delay) * sequence_count + sequence] =
                        operand.values[delay];
                }
            }
        }
        return Ok(state);
    }
    if operand.values.len() == total_state_len {
        let mut state = zero_state();
        for section_state in 0..total_state_len {
            for sequence in 0..sequence_count {
                state[section_state * sequence_count + sequence] = operand.values[section_state];
            }
        }
        return Ok(state);
    }
    if canonical_size_vector(&operand.dims) != state_dims {
        return Err(RuntimeError::ShapeError(format!(
            "ctffilt requires zi to have size {:?}, or a vector of length {} or {}",
            state_dims, section_state_len, total_state_len
        )));
    }

    let reduced_dims = state_dims[1..].to_vec();
    let mut state = zero_state();
    for section_state in 0..total_state_len {
        for sequence in 0..sequence_count {
            let reduced_index = row_major_multi_index(sequence, &reduced_dims);
            let mut full_index = Vec::with_capacity(state_dims.len());
            full_index.push(section_state);
            full_index.extend(reduced_index);
            let linear = row_major_linear_index(&full_index, state_dims);
            state[section_state * sequence_count + sequence] = operand.values[linear];
        }
    }
    Ok(state)
}

fn ctffilt_state_dims(section_state_count: usize, input_dims: &[usize], dim: usize) -> Vec<usize> {
    let mut dims = vec![section_state_count];
    let normalized_dims = canonical_size_vector(input_dims);
    for (axis, size) in normalized_dims.iter().copied().enumerate() {
        if axis + 1 != dim {
            dims.push(size);
        }
    }
    if dims.len() == 1 {
        dims.push(1);
    }
    dims
}

fn filter_numeric_operand(
    value: &NumericOrComplexOperand,
    dims: &[usize],
    b: &[ComplexParts],
    a: &[ComplexParts],
    dim: usize,
    state: &mut [ComplexParts],
) -> NumericOrComplexOperand {
    let state_len = b.len().max(a.len()).saturating_sub(1);
    let mut b_padded = vec![ComplexParts::zero(); state_len + 1];
    let mut a_padded = vec![ComplexParts::zero(); state_len + 1];
    for (index, coefficient) in b.iter().copied().enumerate() {
        b_padded[index] = coefficient;
    }
    for (index, coefficient) in a.iter().copied().enumerate() {
        a_padded[index] = coefficient;
    }

    let mut normalized_dims = canonical_size_vector(dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    let sequence_count = filter_sequence_count(&normalized_dims, dim);
    let mut values = vec![ComplexParts::zero(); value.values.len()];
    match dim {
        1 => {
            for col in 0..value.cols {
                for row in 0..value.rows {
                    let offset = row * value.cols + col;
                    values[offset] = filter_step(
                        value.values[offset],
                        &b_padded,
                        &a_padded,
                        state,
                        state_len,
                        sequence_count,
                        col,
                    );
                }
            }
        }
        2 => {
            for row in 0..value.rows {
                for col in 0..value.cols {
                    let offset = row * value.cols + col;
                    values[offset] = filter_step(
                        value.values[offset],
                        &b_padded,
                        &a_padded,
                        state,
                        state_len,
                        sequence_count,
                        row,
                    );
                }
            }
        }
        _ => {
            let sequence_dims = normalized_dims
                .iter()
                .enumerate()
                .filter_map(|(axis, &size)| (axis + 1 != dim).then_some(size))
                .collect::<Vec<_>>();
            let axis_len = normalized_dims[dim - 1];
            for sequence_index in 0..sequence_count {
                let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
                for axis_value in 0..axis_len {
                    let mut full_index = Vec::with_capacity(normalized_dims.len());
                    let mut reduced_offset = 0usize;
                    for axis in 0..normalized_dims.len() {
                        if axis + 1 == dim {
                            full_index.push(axis_value);
                        } else {
                            full_index.push(reduced_index[reduced_offset]);
                            reduced_offset += 1;
                        }
                    }
                    let linear = row_major_linear_index(&full_index, &normalized_dims);
                    values[linear] = filter_step(
                        value.values[linear],
                        &b_padded,
                        &a_padded,
                        state,
                        state_len,
                        sequence_count,
                        sequence_index,
                    );
                }
            }
        }
    }

    NumericOrComplexOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    }
}

fn filter_step(
    sample: ComplexParts,
    b: &[ComplexParts],
    a: &[ComplexParts],
    state: &mut [ComplexParts],
    state_len: usize,
    sequence_count: usize,
    sequence_index: usize,
) -> ComplexParts {
    if state_len == 0 {
        return normalize_complex_parts(b[0].times(sample));
    }

    let state_offset = |delay: usize| delay * sequence_count + sequence_index;
    let output = normalize_complex_parts(b[0].times(sample).plus(state[state_offset(0)]));
    for delay in 0..(state_len - 1) {
        state[state_offset(delay)] = normalize_complex_parts(
            b[delay + 1]
                .times(sample)
                .plus(state[state_offset(delay + 1)])
                .minus(a[delay + 1].times(output)),
        );
    }
    state[state_offset(state_len - 1)] =
        normalize_complex_parts(b[state_len].times(sample).minus(a[state_len].times(output)));
    output
}

fn filter_state_value(
    state: &[ComplexParts],
    state_len: usize,
    sequence_count: usize,
) -> Result<Value, RuntimeError> {
    build_numeric_or_complex_matrix_result(state_len, sequence_count, state.to_vec())
}

fn filtfilt_numeric_or_complex_nd(
    input_values: &[ComplexParts],
    input_dims: &[usize],
    b: &[ComplexParts],
    a: &[ComplexParts],
    dim: usize,
    options: FiltfiltOptions,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    if input_values.is_empty() {
        return Ok(Vec::new());
    }

    let mut normalized_dims = canonical_size_vector(input_dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    let axis = dim - 1;
    let axis_len = normalized_dims[axis];
    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(position, &size)| (position != axis).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let mut output_values = vec![ComplexParts::zero(); input_values.len()];
    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let sample = (0..axis_len)
            .map(|axis_value| {
                let full_index =
                    nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
                let linear = row_major_linear_index(&full_index, &normalized_dims);
                input_values[linear]
            })
            .collect::<Vec<_>>();
        let filtered = filtfilt_sequence(&sample, b, a, options)?;
        for (axis_value, value) in filtered.into_iter().enumerate() {
            let full_index =
                nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            output_values[linear] = value;
        }
    }
    Ok(output_values)
}

fn filtfilt_sequence(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    options: FiltfiltOptions,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    if samples.is_empty() {
        return Ok(Vec::new());
    }

    if matches!(
        options.initial_states_method,
        FiltfiltInitialStatesMethod::Gustafsson
    ) {
        return filtfilt_sequence_gustafsson(samples, b, a, options);
    }

    let pad_len = resolved_filtfilt_transient_length(samples.len(), b, a, options)?;
    let extended = match options.padding_pattern {
        FiltfiltPaddingPattern::Linear => linear_filter_extension(samples, pad_len),
        FiltfiltPaddingPattern::Reflect => reflect_filter_extension(samples, pad_len),
        FiltfiltPaddingPattern::None => samples.to_vec(),
    };
    let zi = filtfilt_initial_state_template(b, a, options.initial_states_method);

    let forward_state =
        filtfilt_initial_state_values(&zi, extended[0], options.initial_states_method);
    let mut forward = filter_sequence_values(&extended, b, a, &forward_state);
    forward.reverse();

    let backward_state =
        filtfilt_initial_state_values(&zi, forward[0], options.initial_states_method);
    let mut backward = filter_sequence_values(&forward, b, a, &backward_state);
    backward.reverse();
    Ok(if pad_len == 0 {
        backward
    } else {
        backward[pad_len..pad_len + samples.len()].to_vec()
    })
}

fn filtfilt_sequence_gustafsson(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    options: FiltfiltOptions,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    let pad_len = resolved_filtfilt_transient_length(samples.len(), b, a, options)?;
    let effective = match options.padding_pattern {
        FiltfiltPaddingPattern::Linear => linear_filter_extension(samples, pad_len),
        FiltfiltPaddingPattern::Reflect => reflect_filter_extension(samples, pad_len),
        FiltfiltPaddingPattern::None => samples.to_vec(),
    };
    let state_len = b.len().max(a.len()).saturating_sub(1);
    if state_len == 0 {
        let filtered = filtfilt_process_forward_backward(&effective, b, a, &[], &[]);
        return Ok(if pad_len == 0 {
            filtered
        } else {
            filtered[pad_len..pad_len + samples.len()].to_vec()
        });
    }

    let zero_state = vec![ComplexParts::zero(); state_len];
    let y_fb_zero = filtfilt_process_forward_backward(&effective, b, a, &zero_state, &zero_state);
    let y_bf_zero = filtfilt_process_backward_forward(&effective, b, a, &zero_state, &zero_state);
    let difference_zero = y_fb_zero
        .iter()
        .zip(y_bf_zero.iter())
        .map(|(lhs, rhs)| normalize_complex_parts(lhs.minus(*rhs)))
        .collect::<Vec<_>>();

    let edge_len = gustafsson_edge_length(effective.len(), pad_len);
    if edge_len == 0 {
        return Ok(if pad_len == 0 {
            y_fb_zero
        } else {
            y_fb_zero[pad_len..pad_len + samples.len()].to_vec()
        });
    }

    let row_count = gustafsson_vector_length(effective.len(), edge_len);
    let mut design_values = vec![ComplexParts::zero(); row_count * (2 * state_len)];
    for state_index in 0..state_len {
        let mut basis = vec![ComplexParts::zero(); state_len];
        basis[state_index] = ComplexParts::one();

        let diff_forward = gustafsson_difference(
            &effective,
            b,
            a,
            &basis,
            &zero_state,
            &difference_zero,
            edge_len,
        );
        let diff_backward = gustafsson_difference(
            &effective,
            b,
            a,
            &zero_state,
            &basis,
            &difference_zero,
            edge_len,
        );
        for row in 0..row_count {
            design_values[row * (2 * state_len) + state_index] = diff_forward[row];
            design_values[row * (2 * state_len) + state_len + state_index] = diff_backward[row];
        }
    }

    let rhs_values = gustafsson_edge_extract(
        &difference_zero
            .iter()
            .copied()
            .map(|value| normalize_complex_parts(value.scale(-1.0)))
            .collect::<Vec<_>>(),
        edge_len,
    );
    let design = NumericOrComplexOperand {
        rows: row_count,
        cols: 2 * state_len,
        values: design_values,
    };
    let rhs = NumericOrComplexOperand {
        rows: row_count,
        cols: 1,
        values: rhs_values,
    };
    let solution = least_squares_basic_solution(&design, &rhs, "filtfilt")?;
    let initial_forward = (0..state_len)
        .map(|index| solution.values[index])
        .collect::<Vec<_>>();
    let initial_backward = (0..state_len)
        .map(|index| solution.values[state_len + index])
        .collect::<Vec<_>>();

    let filtered =
        filtfilt_process_forward_backward(&effective, b, a, &initial_forward, &initial_backward);
    Ok(if pad_len == 0 {
        filtered
    } else {
        filtered[pad_len..pad_len + samples.len()].to_vec()
    })
}

fn filtfilt_process_forward_backward(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    initial_forward: &[ComplexParts],
    initial_backward: &[ComplexParts],
) -> Vec<ComplexParts> {
    let forward = filter_sequence_values(samples, b, a, initial_forward);
    let mut reversed_forward = forward;
    reversed_forward.reverse();
    let backward = filter_sequence_values(&reversed_forward, b, a, initial_backward);
    let mut output = backward;
    output.reverse();
    output
}

fn filtfilt_process_backward_forward(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    initial_forward: &[ComplexParts],
    initial_backward: &[ComplexParts],
) -> Vec<ComplexParts> {
    let mut reversed_input = samples.to_vec();
    reversed_input.reverse();
    let backward = filter_sequence_values(&reversed_input, b, a, initial_backward);
    let mut reversed_backward = backward;
    reversed_backward.reverse();
    filter_sequence_values(&reversed_backward, b, a, initial_forward)
}

fn gustafsson_difference(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    initial_forward: &[ComplexParts],
    initial_backward: &[ComplexParts],
    baseline_difference: &[ComplexParts],
    edge_len: usize,
) -> Vec<ComplexParts> {
    let difference =
        filtfilt_process_forward_backward(samples, b, a, initial_forward, initial_backward)
            .into_iter()
            .zip(
                filtfilt_process_backward_forward(samples, b, a, initial_forward, initial_backward)
                    .into_iter(),
            )
            .map(|(lhs, rhs)| normalize_complex_parts(lhs.minus(rhs)))
            .collect::<Vec<_>>();
    gustafsson_edge_extract(
        &difference
            .into_iter()
            .zip(baseline_difference.iter().copied())
            .map(|(value, baseline)| normalize_complex_parts(value.minus(baseline)))
            .collect::<Vec<_>>(),
        edge_len,
    )
}

fn gustafsson_edge_length(signal_len: usize, transient_length: usize) -> usize {
    if transient_length == 0 {
        signal_len
    } else {
        transient_length.min(signal_len)
    }
}

fn gustafsson_vector_length(signal_len: usize, edge_len: usize) -> usize {
    if edge_len >= signal_len {
        signal_len
    } else {
        2 * edge_len
    }
}

fn gustafsson_edge_extract(values: &[ComplexParts], edge_len: usize) -> Vec<ComplexParts> {
    if edge_len >= values.len() {
        return values.to_vec();
    }
    let mut extracted = Vec::with_capacity(2 * edge_len);
    extracted.extend_from_slice(&values[..edge_len]);
    extracted.extend_from_slice(&values[values.len() - edge_len..]);
    extracted
}

fn linear_filter_extension(samples: &[ComplexParts], pad_len: usize) -> Vec<ComplexParts> {
    if pad_len == 0 {
        return samples.to_vec();
    }

    let first = samples[0];
    let last = samples[samples.len() - 1];
    let mut extended = Vec::with_capacity(samples.len() + 2 * pad_len);
    for offset in (1..=pad_len).rev() {
        extended.push(normalize_complex_parts(first.scale(2.0).minus(
            samples[reflect_padded_index(-(offset as isize), samples.len())],
        )));
    }
    extended.extend_from_slice(samples);
    for offset in 1..=pad_len {
        extended.push(normalize_complex_parts(last.scale(2.0).minus(
            samples
                [reflect_padded_index(samples.len() as isize - 1 + offset as isize, samples.len())],
        )));
    }
    extended
}

fn reflect_filter_extension(samples: &[ComplexParts], pad_len: usize) -> Vec<ComplexParts> {
    if pad_len == 0 {
        return samples.to_vec();
    }
    let mut extended = Vec::with_capacity(samples.len() + 2 * pad_len);
    for offset in (1..=pad_len).rev() {
        extended.push(samples[reflect_padded_index(-(offset as isize), samples.len())]);
    }
    extended.extend_from_slice(samples);
    for offset in 1..=pad_len {
        extended.push(
            samples
                [reflect_padded_index(samples.len() as isize - 1 + offset as isize, samples.len())],
        );
    }
    extended
}

fn reflect_padded_index(index: isize, len: usize) -> usize {
    if len <= 1 {
        return 0;
    }
    let period = 2 * (len as isize - 1);
    let mut reflected = index.rem_euclid(period);
    if reflected >= len as isize {
        reflected = period - reflected;
    }
    reflected as usize
}

fn filtfilt_initial_state_template(
    b: &[ComplexParts],
    a: &[ComplexParts],
    method: FiltfiltInitialStatesMethod,
) -> Vec<ComplexParts> {
    match method {
        FiltfiltInitialStatesMethod::Const => steady_state_filter_initial_conditions(b, a),
        FiltfiltInitialStatesMethod::Gustafsson => steady_state_filter_initial_conditions(b, a),
        FiltfiltInitialStatesMethod::Zero => {
            vec![ComplexParts::zero(); b.len().max(a.len()).saturating_sub(1)]
        }
    }
}

fn filtfilt_initial_state_values(
    template: &[ComplexParts],
    sample: ComplexParts,
    method: FiltfiltInitialStatesMethod,
) -> Vec<ComplexParts> {
    match method {
        FiltfiltInitialStatesMethod::Const => template
            .iter()
            .copied()
            .map(|state| normalize_complex_parts(state.times(sample)))
            .collect(),
        FiltfiltInitialStatesMethod::Gustafsson => template.to_vec(),
        FiltfiltInitialStatesMethod::Zero => vec![ComplexParts::zero(); template.len()],
    }
}

fn resolved_filtfilt_transient_length(
    sample_len: usize,
    b: &[ComplexParts],
    a: &[ComplexParts],
    options: FiltfiltOptions,
) -> Result<usize, RuntimeError> {
    if matches!(options.padding_pattern, FiltfiltPaddingPattern::None) {
        return Ok(0);
    }
    let filter_order = b.len().max(a.len()).saturating_sub(1);
    let transient = match options.transient_length {
        FiltfiltTransientLength::Filtord => 3 * filter_order,
        FiltfiltTransientLength::Stepzlen => {
            filtfilt_step_response_transient_length(sample_len, b, a)
        }
        FiltfiltTransientLength::Explicit(value) => value,
    };
    if transient > sample_len {
        return Err(RuntimeError::ShapeError(format!(
            "filtfilt currently expects TransientLength to be less than or equal to the input sequence length ({sample_len})"
        )));
    }
    Ok(transient)
}

fn filtfilt_step_response_transient_length(
    sample_len: usize,
    b: &[ComplexParts],
    a: &[ComplexParts],
) -> usize {
    if sample_len == 0 {
        return 0;
    }
    let response = filter_sequence_values(
        &vec![ComplexParts::one(); sample_len],
        b,
        a,
        &vec![ComplexParts::zero(); b.len().max(a.len()).saturating_sub(1)],
    );
    let steady_value = steady_state_filter_initial_conditions(b, a)
        .first()
        .copied()
        .map(|_| {
            let numerator_sum = b
                .iter()
                .copied()
                .fold(ComplexParts::zero(), |acc, value| acc.plus(value));
            let denominator_sum = a
                .iter()
                .copied()
                .fold(ComplexParts::zero(), |acc, value| acc.plus(value));
            if denominator_sum.magnitude() <= 1e-12 {
                response.last().copied().unwrap_or(ComplexParts::zero())
            } else {
                normalize_complex_parts(numerator_sum.rdivide(denominator_sum))
            }
        })
        .unwrap_or_else(|| response.last().copied().unwrap_or(ComplexParts::zero()));
    let deviations = response
        .iter()
        .map(|value| value.minus(steady_value).magnitude())
        .collect::<Vec<_>>();
    let max_deviation = deviations.iter().copied().fold(0.0_f64, f64::max);
    if max_deviation <= 1e-12 {
        return 0;
    }
    deviations
        .iter()
        .position(|deviation| *deviation < 0.02 * max_deviation)
        .unwrap_or(sample_len)
}

fn steady_state_filter_initial_conditions(
    b: &[ComplexParts],
    a: &[ComplexParts],
) -> Vec<ComplexParts> {
    let state_len = b.len().max(a.len()).saturating_sub(1);
    if state_len == 0 {
        return Vec::new();
    }

    let mut b_padded = vec![ComplexParts::zero(); state_len + 1];
    let mut a_padded = vec![ComplexParts::zero(); state_len + 1];
    for (index, coefficient) in b.iter().copied().enumerate() {
        b_padded[index] = coefficient;
    }
    for (index, coefficient) in a.iter().copied().enumerate() {
        a_padded[index] = coefficient;
    }

    let numerator_sum = b_padded
        .iter()
        .copied()
        .fold(ComplexParts::zero(), |accumulator, value| {
            accumulator.plus(value)
        });
    let denominator_sum = a_padded
        .iter()
        .copied()
        .fold(ComplexParts::zero(), |accumulator, value| {
            accumulator.plus(value)
        });
    if denominator_sum.magnitude() <= 1e-12 {
        return vec![ComplexParts::zero(); state_len];
    }

    let steady_output = normalize_complex_parts(numerator_sum.rdivide(denominator_sum));
    let mut suffix_b = ComplexParts::zero();
    let mut suffix_a = ComplexParts::zero();
    let mut state = vec![ComplexParts::zero(); state_len];
    for index in (0..state_len).rev() {
        suffix_b = normalize_complex_parts(b_padded[index + 1].plus(suffix_b));
        suffix_a = normalize_complex_parts(a_padded[index + 1].plus(suffix_a));
        state[index] = normalize_complex_parts(suffix_b.minus(suffix_a.times(steady_output)));
    }
    state
}

fn filter_sequence_values(
    samples: &[ComplexParts],
    b: &[ComplexParts],
    a: &[ComplexParts],
    initial_state: &[ComplexParts],
) -> Vec<ComplexParts> {
    let state_len = b.len().max(a.len()).saturating_sub(1);
    let mut b_padded = vec![ComplexParts::zero(); state_len + 1];
    let mut a_padded = vec![ComplexParts::zero(); state_len + 1];
    for (index, coefficient) in b.iter().copied().enumerate() {
        b_padded[index] = coefficient;
    }
    for (index, coefficient) in a.iter().copied().enumerate() {
        a_padded[index] = coefficient;
    }

    let mut state = initial_state.to_vec();
    if state_len > 0 && state.len() != state_len {
        state.resize(state_len, ComplexParts::zero());
    }
    samples
        .iter()
        .copied()
        .map(|sample| filter_step(sample, &b_padded, &a_padded, &mut state, state_len, 1, 0))
        .collect()
}

fn parse_del2_vector_spacing(args: &[Value]) -> Result<f64, RuntimeError> {
    match args {
        [_value] => Ok(1.0),
        [_value, spacing] => del2_spacing_scalar(spacing),
        _ => Err(RuntimeError::Unsupported(
            "del2 currently supports `del2(m)` or `del2(m, h)` for vector inputs".to_string(),
        )),
    }
}

fn parse_del2_matrix_spacing(args: &[Value]) -> Result<(f64, f64), RuntimeError> {
    match args {
        [_value] => Ok((1.0, 1.0)),
        [_value, spacing] => {
            let spacing = del2_spacing_scalar(spacing)?;
            Ok((spacing, spacing))
        }
        [_value, x_spacing, y_spacing] => {
            Ok((del2_spacing_scalar(x_spacing)?, del2_spacing_scalar(y_spacing)?))
        }
        _ => Err(RuntimeError::Unsupported(
            "del2 currently supports `del2(m)`, `del2(m, h)`, or `del2(m, hx, hy)` for matrix inputs".to_string(),
        )),
    }
}

fn del2_spacing_scalar(value: &Value) -> Result<f64, RuntimeError> {
    finite_nonzero_spacing(value.as_scalar()?, "del2")
}

fn del2_vector_values(values: &[f64], spacing: f64) -> Vec<f64> {
    second_derivative_uniform_values(values, spacing)
        .into_iter()
        .map(|value| value / 2.0)
        .collect::<Vec<_>>()
}

fn del2_matrix_result(operand: &NumericOperand, x_spacing: f64, y_spacing: f64) -> NumericOperand {
    let mut dxx_values = Vec::with_capacity(operand.values.len());
    for row in 0..operand.rows {
        let start = row * operand.cols;
        dxx_values.extend(second_derivative_uniform_values(
            &operand.values[start..start + operand.cols],
            x_spacing,
        ));
    }

    let mut dyy_values = vec![0.0; operand.values.len()];
    for col in 0..operand.cols {
        let column = (0..operand.rows)
            .map(|row| operand.values[row * operand.cols + col])
            .collect::<Vec<_>>();
        let second = second_derivative_uniform_values(&column, y_spacing);
        for (row, value) in second.into_iter().enumerate() {
            dyy_values[row * operand.cols + col] = value;
        }
    }

    let values = dxx_values
        .into_iter()
        .zip(dyy_values)
        .map(|(dxx, dyy)| (dxx + dyy) / 4.0)
        .collect::<Vec<_>>();

    NumericOperand {
        rows: operand.rows,
        cols: operand.cols,
        values,
    }
}

fn second_derivative_uniform_values(values: &[f64], spacing: f64) -> Vec<f64> {
    if values.len() <= 2 {
        return vec![0.0; values.len()];
    }

    let spacing_squared = spacing * spacing;
    let mut second = vec![0.0; values.len()];
    for index in 1..(values.len() - 1) {
        second[index] =
            (values[index - 1] - 2.0 * values[index] + values[index + 1]) / spacing_squared;
    }

    if values.len() == 3 {
        second[0] = second[1];
        second[2] = second[1];
        return second;
    }

    let last = values.len() - 1;
    second[0] = 2.0 * second[1] - second[2];
    second[last] = 2.0 * second[last - 1] - second[last - 2];
    second
}

fn parse_divergence_args(
    args: &[Value],
) -> Result<(Vec<f64>, Vec<f64>, NumericOperand, NumericOperand), RuntimeError> {
    let (x, y, u, v) = match args {
        [u, v] => (None, None, u, v),
        [x, y, u, v] => (Some(x), Some(y), u, v),
        _ => {
            return Err(RuntimeError::Unsupported(
                "divergence currently supports `divergence(u, v)` or `divergence(x, y, u, v)`"
                    .to_string(),
            ))
        }
    };

    let u = numeric_operand(u, "divergence")?;
    let v = numeric_operand(v, "divergence")?;
    if u.rows != v.rows || u.cols != v.cols {
        return Err(RuntimeError::ShapeError(format!(
            "divergence requires U and V to have matching shapes, found {}x{} and {}x{}",
            u.rows, u.cols, v.rows, v.cols
        )));
    }

    let (x, y) = match (x, y) {
        (None, None) => (
            (1..=u.cols).map(|index| index as f64).collect::<Vec<_>>(),
            (1..=u.rows).map(|index| index as f64).collect::<Vec<_>>(),
        ),
        (Some(x), Some(y)) => interp2_grid_vectors(x, y, u.rows, u.cols)?,
        _ => unreachable!("divergence X and Y inputs are paired"),
    };

    Ok((x, y, u, v))
}

fn normalized_divergence_axes(
    x: Vec<f64>,
    y: Vec<f64>,
    mut u: NumericOperand,
    mut v: NumericOperand,
) -> Result<(Vec<f64>, Vec<f64>, NumericOperand, NumericOperand), RuntimeError> {
    let (x, reverse_columns) = normalized_interp_axis(x, "divergence", "X")?;
    let (y, reverse_rows) = normalized_interp_axis(y, "divergence", "Y")?;

    if reverse_columns {
        u = flip_numeric_operand_columns(&u);
        v = flip_numeric_operand_columns(&v);
    }
    if reverse_rows {
        u = flip_numeric_operand_rows(&u);
        v = flip_numeric_operand_rows(&v);
    }

    Ok((x, y, u, v))
}

fn derivative_along_x(operand: &NumericOperand, x: &[f64]) -> NumericOperand {
    let mut values = Vec::with_capacity(operand.values.len());
    for row in 0..operand.rows {
        let start = row * operand.cols;
        values.extend(gradient_nonuniform_values(
            &operand.values[start..start + operand.cols],
            x,
        ));
    }
    NumericOperand {
        rows: operand.rows,
        cols: operand.cols,
        values,
    }
}

fn derivative_along_y(operand: &NumericOperand, y: &[f64]) -> NumericOperand {
    let mut values = vec![0.0; operand.values.len()];
    for col in 0..operand.cols {
        let column = (0..operand.rows)
            .map(|row| operand.values[row * operand.cols + col])
            .collect::<Vec<_>>();
        let derivative = gradient_nonuniform_values(&column, y);
        for (row, value) in derivative.into_iter().enumerate() {
            values[row * operand.cols + col] = value;
        }
    }

    NumericOperand {
        rows: operand.rows,
        cols: operand.cols,
        values,
    }
}

fn parse_gradient_vector_positions(
    args: &[Value],
    sample_count: usize,
) -> Result<Vec<f64>, RuntimeError> {
    match args {
        [_value] => Ok((1..=sample_count)
            .map(|index| index as f64)
            .collect::<Vec<_>>()),
        [_value, spacing] => {
            if let Ok(spacing) = spacing.as_scalar() {
                let spacing = gradient_spacing_scalar(spacing)?;
                return Ok((0..sample_count)
                    .map(|index| index as f64 * spacing)
                    .collect::<Vec<_>>());
            }

            let positions = meshgrid_vector(spacing)?;
            if positions.len() != sample_count {
                return Err(RuntimeError::ShapeError(format!(
                    "gradient requires position vectors with the same length as the input data, found {} sample(s) and {} position(s)",
                    sample_count,
                    positions.len()
                )));
            }
            Ok(positions)
        }
        _ => Err(RuntimeError::Unsupported(
            "gradient currently supports `gradient(f)` or `gradient(f, h)` / `gradient(f, x)` for vector inputs".to_string(),
        )),
    }
}

fn parse_gradient_component_spacings(
    args: &[Value],
    component_count: usize,
) -> Result<Vec<f64>, RuntimeError> {
    match args {
        [_value] => Ok(vec![1.0; component_count]),
        [_value, spacing] => {
            let spacing = gradient_spacing_scalar(spacing.as_scalar()?)?;
            Ok(vec![spacing; component_count])
        }
        [_value, spacings @ ..] if spacings.len() == component_count => spacings
            .iter()
            .map(|spacing| gradient_spacing_scalar(spacing.as_scalar()?))
            .collect(),
        _ => Err(RuntimeError::Unsupported(format!(
            "gradient currently supports `gradient(f)`, `gradient(f, h)`, or `gradient(f, h1, ..., h{component_count})` for this input shape"
        ))),
    }
}

fn gradient_spacing_scalar(spacing: f64) -> Result<f64, RuntimeError> {
    finite_nonzero_spacing(spacing, "gradient")
}

fn finite_nonzero_spacing(spacing: f64, builtin_name: &str) -> Result<f64, RuntimeError> {
    if !spacing.is_finite() || spacing == 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects finite nonzero scalar spacing values"
        )));
    }
    Ok(spacing)
}

fn gradient_vector_result(
    operand: &NumericOperand,
    positions: Vec<f64>,
) -> Result<NumericOperand, RuntimeError> {
    let (positions, reversed) = normalized_interp_axis(positions, "gradient", "X")?;
    let mut values = operand.values.clone();
    if reversed {
        values.reverse();
    }
    let mut values = gradient_nonuniform_values(&values, &positions);
    if reversed {
        values.reverse();
    }
    Ok(NumericOperand {
        rows: operand.rows,
        cols: operand.cols,
        values,
    })
}

fn gradient_component_dimensions(input_dims: &[usize]) -> Vec<usize> {
    let dims = canonical_size_vector(input_dims);
    let mut order = Vec::new();
    if dimension_length(&dims, 2) != 1 {
        order.push(2);
    }
    if dimension_length(&dims, 1) != 1 {
        order.push(1);
    }
    for dim in 3..=dims.len() {
        if dimension_length(&dims, dim) != 1 {
            order.push(dim);
        }
    }
    order
}

fn gradient_empty_outputs(
    input_dims: &[usize],
    component_count: usize,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let empty =
        numeric_matrix_result_with_dimensions(canonical_size_vector(input_dims), Vec::new())?;
    let max_outputs = component_count.max(1);
    match output_arity {
        0 | 1 => Ok(vec![empty]),
        arity if arity <= max_outputs => Ok((0..arity).map(|_| empty.clone()).collect()),
        _ => Err(RuntimeError::Unsupported(format!(
            "gradient currently supports at most {max_outputs} output(s) for this input shape"
        ))),
    }
}

fn gradient_nd_results(
    values: &[f64],
    input_dims: &[usize],
    component_dims: &[usize],
    spacings: &[f64],
) -> Result<Vec<Vec<f64>>, RuntimeError> {
    component_dims
        .iter()
        .copied()
        .zip(spacings.iter().copied())
        .map(|(dim, spacing)| gradient_values_along_dimension(values, input_dims, dim, spacing))
        .collect()
}

fn gradient_values_along_dimension(
    values: &[f64],
    input_dims: &[usize],
    dim: usize,
    spacing: f64,
) -> Result<Vec<f64>, RuntimeError> {
    if values.is_empty() {
        return Ok(Vec::new());
    }

    let normalized_dims = canonical_size_vector(input_dims);
    let axis_len = dimension_length(&normalized_dims, dim);
    if axis_len <= 1 {
        return Ok(vec![0.0; values.len()]);
    }

    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(axis, &size)| (axis + 1 != dim).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };

    let mut result = vec![0.0; values.len()];
    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let mut slice = Vec::with_capacity(axis_len);
        for axis_value in 0..axis_len {
            let full_index = gradient_full_index(&normalized_dims, dim, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            slice.push(values[linear]);
        }
        let gradient = gradient_uniform_values(&slice, spacing);
        for (axis_value, derivative) in gradient.into_iter().enumerate() {
            let full_index = gradient_full_index(&normalized_dims, dim, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            result[linear] = derivative;
        }
    }
    Ok(result)
}

fn gradient_full_index(
    dims: &[usize],
    dim: usize,
    axis_value: usize,
    reduced_index: &[usize],
) -> Vec<usize> {
    let mut full_index = Vec::with_capacity(dims.len());
    let mut reduced_offset = 0usize;
    for axis in 0..dims.len() {
        if axis + 1 == dim {
            full_index.push(axis_value);
        } else {
            full_index.push(reduced_index[reduced_offset]);
            reduced_offset += 1;
        }
    }
    full_index
}

fn gradient_uniform_values(values: &[f64], spacing: f64) -> Vec<f64> {
    if values.is_empty() {
        return Vec::new();
    }
    if values.len() == 1 {
        return vec![0.0];
    }

    let mut gradient = vec![0.0; values.len()];
    gradient[0] = (values[1] - values[0]) / spacing;
    for index in 1..(values.len() - 1) {
        gradient[index] = (values[index + 1] - values[index - 1]) / (2.0 * spacing);
    }
    let last = values.len() - 1;
    gradient[last] = (values[last] - values[last - 1]) / spacing;
    gradient
}

fn gradient_nonuniform_values(values: &[f64], positions: &[f64]) -> Vec<f64> {
    if values.is_empty() {
        return Vec::new();
    }
    if values.len() == 1 {
        return vec![0.0];
    }

    let mut gradient = vec![0.0; values.len()];
    gradient[0] = (values[1] - values[0]) / (positions[1] - positions[0]);
    for index in 1..(values.len() - 1) {
        gradient[index] =
            (values[index + 1] - values[index - 1]) / (positions[index + 1] - positions[index - 1]);
    }
    let last = values.len() - 1;
    gradient[last] = (values[last] - values[last - 1]) / (positions[last] - positions[last - 1]);
    gradient
}

fn parse_trapezoid_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(Option<&'a Value>, NumericOrComplexOperand, usize), RuntimeError> {
    let (x, y, requested_dim) = match args {
        [y] => (None, y, None),
        [y, second] if looks_like_trapezoid_dim(second) => {
            (None, y, Some(scalar_dimension(second)?))
        }
        [x, y] => (Some(x), y, None),
        [x, y, dim] => (Some(x), y, Some(scalar_dimension(dim)?)),
        _ => {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports `{builtin_name}(y)`, `{builtin_name}(y, dim)`, `{builtin_name}(x, y)`, or `{builtin_name}(x, y, dim)`"
            )))
        }
    };

    let y = numeric_or_complex_operand(y, builtin_name)?;
    let dim = requested_dim.unwrap_or_else(|| if y.rows != 1 { 1 } else { 2 });

    Ok((x, y, dim))
}

fn looks_like_trapezoid_dim(value: &Value) -> bool {
    value
        .as_scalar()
        .map(|scalar| scalar.is_finite() && scalar >= 1.0 && scalar.fract() == 0.0)
        .unwrap_or(false)
}

fn integration_axis_len(value: &NumericOrComplexOperand, dim: usize) -> usize {
    match dim {
        1 => value.rows,
        2 => value.cols,
        _ => 1,
    }
}

fn trapezoid_positions(
    x: Option<&Value>,
    len: usize,
    builtin_name: &str,
) -> Result<Vec<f64>, RuntimeError> {
    match x {
        None => Ok((1..=len).map(|index| index as f64).collect::<Vec<_>>()),
        Some(value) => {
            let positions = meshgrid_vector(value)?;
            if positions.len() != len {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} currently expects X to be a vector with {} element(s)",
                    len
                )));
            }
            if positions.iter().any(|position| !position.is_finite()) {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects finite numeric X positions"
                )));
            }
            Ok(positions)
        }
    }
}

fn integrate_trapezoid_reduction(
    value: &NumericOrComplexOperand,
    positions: &[f64],
    dim: usize,
) -> NumericOrComplexOperand {
    match dim {
        1 => {
            let mut values = Vec::with_capacity(value.cols);
            for col in 0..value.cols {
                let slice = (0..value.rows)
                    .map(|row| value.values[row * value.cols + col])
                    .collect::<Vec<_>>();
                values.push(trapezoid_integral(&slice, positions));
            }
            NumericOrComplexOperand {
                rows: 1,
                cols: value.cols,
                values,
            }
        }
        2 => {
            let mut values = Vec::with_capacity(value.rows);
            for row in 0..value.rows {
                let slice = (0..value.cols)
                    .map(|col| value.values[row * value.cols + col])
                    .collect::<Vec<_>>();
                values.push(trapezoid_integral(&slice, positions));
            }
            NumericOrComplexOperand {
                rows: value.rows,
                cols: 1,
                values,
            }
        }
        _ => NumericOrComplexOperand {
            rows: value.rows,
            cols: value.cols,
            values: vec![ComplexParts::zero(); value.rows * value.cols],
        },
    }
}

fn cumulative_trapezoid(
    value: &NumericOrComplexOperand,
    positions: &[f64],
    dim: usize,
) -> NumericOrComplexOperand {
    if value.rows == 0 || value.cols == 0 {
        return NumericOrComplexOperand {
            rows: value.rows,
            cols: value.cols,
            values: vec![ComplexParts::zero(); value.rows * value.cols],
        };
    }

    match dim {
        1 => {
            let mut values = vec![ComplexParts::zero(); value.rows * value.cols];
            for col in 0..value.cols {
                let mut accumulator = ComplexParts::zero();
                values[col] = ComplexParts::zero();
                for row in 1..value.rows {
                    let previous = value.values[(row - 1) * value.cols + col];
                    let current = value.values[row * value.cols + col];
                    accumulator = accumulator.plus(trapezoid_step(
                        previous,
                        current,
                        positions[row] - positions[row - 1],
                    ));
                    values[row * value.cols + col] = accumulator;
                }
            }
            NumericOrComplexOperand {
                rows: value.rows,
                cols: value.cols,
                values,
            }
        }
        2 => {
            let mut values = vec![ComplexParts::zero(); value.rows * value.cols];
            for row in 0..value.rows {
                let mut accumulator = ComplexParts::zero();
                values[row * value.cols] = ComplexParts::zero();
                for col in 1..value.cols {
                    let previous = value.values[row * value.cols + col - 1];
                    let current = value.values[row * value.cols + col];
                    accumulator = accumulator.plus(trapezoid_step(
                        previous,
                        current,
                        positions[col] - positions[col - 1],
                    ));
                    values[row * value.cols + col] = accumulator;
                }
            }
            NumericOrComplexOperand {
                rows: value.rows,
                cols: value.cols,
                values,
            }
        }
        _ => NumericOrComplexOperand {
            rows: value.rows,
            cols: value.cols,
            values: vec![ComplexParts::zero(); value.rows * value.cols],
        },
    }
}

fn trapezoid_integral(values: &[ComplexParts], positions: &[f64]) -> ComplexParts {
    if values.len() <= 1 {
        return ComplexParts::zero();
    }

    (1..values.len())
        .map(|index| {
            trapezoid_step(
                values[index - 1],
                values[index],
                positions[index] - positions[index - 1],
            )
        })
        .fold(ComplexParts::zero(), |accumulator, value| {
            accumulator.plus(value)
        })
}

fn trapezoid_step(previous: ComplexParts, current: ComplexParts, delta: f64) -> ComplexParts {
    previous.plus(current).scale(delta * 0.5)
}

fn builtin_flip(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, dimension) = match args {
        [value] => (value, default_flip_dimension(value)),
        [value, dim] => (value, size_query_dimension_scalar(dim)?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "flip currently supports `flip(A)` or `flip(A, dim)`".to_string(),
            ))
        }
    };

    flip_along_dimension(value, dimension, "flip")
}

fn builtin_flipud(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "flipud currently supports exactly one argument".to_string(),
        ));
    };
    flip_along_dimension(value, 1, "flipud")
}

fn builtin_fliplr(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "fliplr currently supports exactly one argument".to_string(),
        ));
    };
    flip_along_dimension(value, 2, "fliplr")
}

fn builtin_rot90(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, rotations) = match args {
        [value] => (value, 1isize),
        [value, k] => (value, k.as_scalar()? as isize),
        _ => {
            return Err(RuntimeError::Unsupported(
                "rot90 currently supports `rot90(A)` or `rot90(A, k)`".to_string(),
            ))
        }
    };
    let turns = rotations.rem_euclid(4);
    match turns {
        0 => Ok(value.clone()),
        1 => rotate_90(value, true, "rot90"),
        2 => rotate_180(value, "rot90"),
        3 => rotate_90(value, false, "rot90"),
        _ => unreachable!(),
    }
}

fn builtin_circshift(args: &[Value]) -> Result<Value, RuntimeError> {
    match args {
        [value, shift] => {
            let shifts = circshift_shifts(value, shift, None)?;
            circshift_value(value, &shifts, "circshift")
        }
        [value, shift, dim] => {
            let shifts = circshift_shifts(value, shift, Some(dim))?;
            circshift_value(value, &shifts, "circshift")
        }
        _ => Err(RuntimeError::Unsupported(
            "circshift currently supports `circshift(A, K)` or `circshift(A, K, dim)`".to_string(),
        )),
    }
}

fn builtin_fftshift(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, dim) = parse_shift_halves_args(args, "fftshift")?;
    let shifts = shift_halves_shifts(value, dim, false)?;
    circshift_value(value, &shifts, "fftshift")
}

fn builtin_ifftshift(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, dim) = parse_shift_halves_args(args, "ifftshift")?;
    let shifts = shift_halves_shifts(value, dim, true)?;
    circshift_value(value, &shifts, "ifftshift")
}

fn builtin_repelem(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((value, reps)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "repelem currently expects an input array plus repetition counts".to_string(),
        ));
    };
    if reps.is_empty() {
        return Err(RuntimeError::Unsupported(
            "repelem currently expects an input array plus repetition counts".to_string(),
        ));
    }

    match value {
        Value::CharArray(text) if reps.len() == 1 => {
            let chars = text.chars().collect::<Vec<_>>();
            let counts = repelem_vector_counts(&reps[0], chars.len(), "repelem")?;
            let mut out = String::new();
            for (ch, count) in chars.into_iter().zip(counts.into_iter()) {
                for _ in 0..count {
                    out.push(ch);
                }
            }
            Ok(Value::CharArray(out))
        }
        Value::Scalar(_)
        | Value::Logical(_)
        | Value::Complex(_)
        | Value::String(_)
        | Value::Struct(_)
        | Value::Object(_)
            if reps.len() == 1 =>
        {
            let counts = repelem_vector_counts(&reps[0], 1, "repelem")?;
            let elements = vec![value.clone(); counts.into_iter().sum()];
            let cols = elements.len();
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                1,
                cols,
                vec![1, cols],
                elements,
            )?))
        }
        Value::Matrix(matrix) if reps.len() == 1 && (matrix.rows == 1 || matrix.cols == 1) => {
            let counts = repelem_vector_counts(&reps[0], matrix.element_count(), "repelem")?;
            let mut elements = Vec::new();
            for (element, count) in matrix.elements().iter().cloned().zip(counts.into_iter()) {
                for _ in 0..count {
                    elements.push(element.clone());
                }
            }
            let (rows, cols, dims) = if matrix.rows == 1 {
                (1, elements.len(), vec![1, elements.len()])
            } else {
                (elements.len(), 1, vec![elements.len(), 1])
            };
            if matrix_is_char_matrix(matrix) {
                let chars = elements
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(
                                "repelem currently expects char matrices to contain single-character elements"
                                    .to_string(),
                            )
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(dims, chars);
            }
            Ok(Value::Matrix(MatrixValue::with_dimensions(rows, cols, dims, elements)?))
        }
        Value::Cell(cell) if reps.len() == 1 && (cell.rows == 1 || cell.cols == 1) => {
            let counts = repelem_vector_counts(&reps[0], cell.element_count(), "repelem")?;
            let mut elements = Vec::new();
            for (element, count) in cell.elements().iter().cloned().zip(counts.into_iter()) {
                for _ in 0..count {
                    elements.push(element.clone());
                }
            }
            let (rows, cols, dims) = if cell.rows == 1 {
                (1, elements.len(), vec![1, elements.len()])
            } else {
                (elements.len(), 1, vec![elements.len(), 1])
            };
            Ok(Value::Cell(CellValue::with_dimensions(
                rows, cols, dims, elements,
            )?))
        }
        Value::Matrix(matrix) => repelem_array_result(matrix.dims(), matrix.elements(), reps, false),
        Value::Cell(cell) => repelem_array_result(cell.dims(), cell.elements(), reps, true),
        other => Err(RuntimeError::TypeError(format!(
            "repelem currently expects scalar, object, vector, matrix, or cell array input, found {}",
            other.kind_name()
        ))),
    }
}

fn repelem_vector_counts(
    value: &Value,
    len: usize,
    builtin_name: &str,
) -> Result<Vec<usize>, RuntimeError> {
    match value {
        Value::Matrix(matrix) if matrix.rows == 0 || matrix.cols == 0 => Ok(vec![0; len]),
        Value::Matrix(matrix) => {
            let counts = matrix
                .iter()
                .map(repetition_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            match counts.len() {
                1 => Ok(vec![counts[0]; len]),
                count if count == len => Ok(counts),
                count => Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} vector repetition counts must be scalar or match input length {len}, found {count}"
                ))),
            }
        }
        _ => Ok(vec![repetition_scalar(value)?; len]),
    }
}

fn repelem_axis_counts(
    value: &Value,
    extent: usize,
    axis: usize,
) -> Result<Vec<usize>, RuntimeError> {
    let counts = repelem_vector_counts(value, extent, "repelem")?;
    if counts.len() != extent {
        return Err(RuntimeError::ShapeError(format!(
            "repelem counts along dimension {} must match extent {}",
            axis + 1,
            extent
        )));
    }
    Ok(counts)
}

fn repelem_array_result(
    input_dims: &[usize],
    source_elements: &[Value],
    reps: &[Value],
    cell_output: bool,
) -> Result<Value, RuntimeError> {
    let mut dims = canonical_size_vector(input_dims);
    while dims.len() < reps.len() {
        dims.push(1);
    }

    let mut axis_counts = Vec::with_capacity(dims.len());
    for (axis, &extent) in dims.iter().enumerate() {
        let counts = if let Some(rep) = reps.get(axis) {
            repelem_axis_counts(rep, extent, axis)?
        } else {
            vec![1; extent]
        };
        axis_counts.push(counts);
    }

    let output_dims = axis_counts
        .iter()
        .map(|counts| counts.iter().sum::<usize>())
        .collect::<Vec<_>>();
    let output_count = output_dims.iter().product::<usize>();
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    if output_count == 0 {
        if !cell_output
            && source_elements
                .iter()
                .all(|value| single_char_text_value(value).is_some())
        {
            return char_value_with_dimensions(output_dims, Vec::new());
        }
        return if cell_output {
            Ok(Value::Cell(CellValue::with_dimensions(
                rows,
                cols,
                output_dims,
                Vec::new(),
            )?))
        } else {
            Ok(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                output_dims,
                Vec::new(),
            )?))
        };
    }
    let mut offsets = Vec::with_capacity(axis_counts.len());
    for counts in &axis_counts {
        let mut starts = Vec::with_capacity(counts.len());
        let mut current = 0usize;
        for &count in counts {
            starts.push(current);
            current += count;
        }
        offsets.push(starts);
    }

    let prototype = source_elements
        .first()
        .cloned()
        .expect("nonempty repelem output should have a source prototype");
    let mut elements = vec![prototype; output_count];
    for (linear, source_value) in source_elements.iter().enumerate() {
        let source_index = row_major_multi_index(linear, &dims);
        let start_index = source_index
            .iter()
            .enumerate()
            .map(|(axis, &index)| offsets[axis][index])
            .collect::<Vec<_>>();
        let repeat_dims = source_index
            .iter()
            .enumerate()
            .map(|(axis, &index)| axis_counts[axis][index])
            .collect::<Vec<_>>();
        let repeat_count = repeat_dims.iter().product::<usize>();
        for repeat_linear in 0..repeat_count {
            let repeat_index = row_major_multi_index(repeat_linear, &repeat_dims);
            let destination_index = repeat_index
                .iter()
                .enumerate()
                .map(|(axis, &offset)| start_index[axis] + offset)
                .collect::<Vec<_>>();
            let destination_linear = row_major_linear_index(&destination_index, &output_dims);
            elements[destination_linear] = source_value.clone();
        }
    }

    if !cell_output
        && elements
            .iter()
            .all(|value| single_char_text_value(value).is_some())
    {
        let chars = elements
            .iter()
            .map(|value| {
                single_char_text_value(value).ok_or_else(|| {
                    RuntimeError::TypeError(
                        "repelem currently expects char matrices to contain single-character elements"
                            .to_string(),
                    )
                })
            })
            .collect::<Result<Vec<_>, _>>()?;
        return char_value_with_dimensions(output_dims, chars);
    }

    if cell_output {
        Ok(Value::Cell(CellValue::with_dimensions(
            rows,
            cols,
            output_dims,
            elements,
        )?))
    } else {
        Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            output_dims,
            elements,
        )?))
    }
}

fn builtin_shiftdim(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    match args {
        [value] => {
            let (shifted, removed) = shiftdim_remove_leading_singletons(value)?;
            let mut outputs = vec![shifted];
            if output_arity >= 2 {
                outputs.push(Value::Scalar(removed as f64));
            }
            if output_arity > 2 {
                return Err(RuntimeError::Unsupported(
                    "shiftdim currently supports one or two outputs".to_string(),
                ));
            }
            Ok(outputs)
        }
        [value, shift] => {
            if output_arity > 1 {
                return Err(RuntimeError::Unsupported(
                    "shiftdim with an explicit shift currently supports only one output"
                        .to_string(),
                ));
            }
            let shift = shift.as_scalar()?;
            if !shift.is_finite() || shift.fract() != 0.0 {
                return Err(RuntimeError::TypeError(
                    "shiftdim currently expects an integer scalar shift".to_string(),
                ));
            }
            if shift < 0.0 {
                return Ok(vec![shiftdim_negative(value, (-shift) as usize)?]);
            }
            Ok(vec![shiftdim_positive(value, shift as usize)?])
        }
        _ => Err(RuntimeError::Unsupported(
            "shiftdim currently supports `shiftdim(A)` or `shiftdim(A, n)`".to_string(),
        )),
    }
}

fn builtin_cumsum(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, dimension, missing_flag) = parse_cumulative_sumprod_args(args, "cumsum")?;
    if let Some(operand) = integer_operand(value) {
        return cumulative_integer_value(
            &operand,
            &canonical_size_vector(&value_dimensions(value)),
            dimension,
            "cumsum",
            |accumulator, value, class| saturating_integer_add(class, accumulator, value),
            0,
        );
    }
    cumulative_numeric_or_complex_value(
        value,
        dimension,
        missing_flag,
        "cumsum",
        |accumulator, value| accumulator.plus(value),
        ComplexParts::zero(),
    )
}

fn builtin_cumprod(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, dimension, missing_flag) = parse_cumulative_sumprod_args(args, "cumprod")?;
    if let Some(operand) = integer_operand(value) {
        return cumulative_integer_value(
            &operand,
            &canonical_size_vector(&value_dimensions(value)),
            dimension,
            "cumprod",
            |accumulator, value, class| saturating_integer_mul(class, accumulator, value),
            1,
        );
    }
    cumulative_numeric_or_complex_value(
        value,
        dimension,
        missing_flag,
        "cumprod",
        |accumulator, value| accumulator.times(value),
        ComplexParts::one(),
    )
}

fn builtin_cummax(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let integer_class = args.first().and_then(integer_class_from_reduction_value);
    let mut outputs = if args.iter().any(value_contains_complex_entries) {
        cumulative_extreme_outputs_complex(args, output_arity, "cummax", complex_prefers_max)
    } else {
        cumulative_extreme_outputs(args, output_arity, "cummax", |candidate, best| {
            candidate > best
        })
    }?;
    if let Some(class) = integer_class {
        let first = outputs.remove(0);
        outputs.insert(0, integerize_output_value(first, class)?);
    }
    Ok(outputs)
}

