#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum SortMissingPlacement {
    Auto,
    First,
    Last,
}

#[derive(Clone, Copy, Debug)]
struct SortOptions {
    dim: Option<usize>,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
}

#[derive(Clone, Copy, Debug, PartialEq, Eq)]
enum ComparisonMethod {
    Auto,
    Real,
    Abs,
}

fn builtin_sort(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (value, options) = parse_sort_args(args, "sort")?;
    let (sorted_value, index_value) = sorted_value_and_indices(value, options)?;
    match output_arity {
        0 | 1 => Ok(vec![sorted_value]),
        2 => Ok(vec![sorted_value, index_value]),
        _ => Err(RuntimeError::Unsupported(
            "sort currently supports one or two outputs".to_string(),
        )),
    }
}

fn parse_sort_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, SortOptions), RuntimeError> {
    let Some((value, options)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects at least one input argument"
        )));
    };

    let mut parsed = SortOptions {
        dim: None,
        descending: false,
        missing_placement: SortMissingPlacement::Auto,
        comparison_method: ComparisonMethod::Auto,
    };
    let mut seen_direction = false;
    let mut seen_missing_placement = false;
    let mut seen_comparison_method = false;
    let mut index = 0;
    while index < options.len() {
        if let Value::CharArray(text) | Value::String(text) = &options[index] {
            if text.eq_ignore_ascii_case("MissingPlacement") {
                let Some(placement) = options.get(index + 1) else {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently expects a value after the 'MissingPlacement' option"
                    )));
                };
                if seen_missing_placement {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently supports 'MissingPlacement' at most once"
                    )));
                }
                parsed.missing_placement = parse_sort_missing_placement(placement, builtin_name)?;
                seen_missing_placement = true;
                index += 2;
                continue;
            }
            if text.eq_ignore_ascii_case("ComparisonMethod") {
                let Some(method) = options.get(index + 1) else {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently expects a value after the 'ComparisonMethod' option"
                    )));
                };
                if seen_comparison_method {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently supports 'ComparisonMethod' at most once"
                    )));
                }
                parsed.comparison_method = parse_comparison_method(method, builtin_name)?;
                seen_comparison_method = true;
                index += 2;
                continue;
            }
            if seen_direction {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports a single sort direction option"
                )));
            }
            parsed.descending = parse_sort_direction(&options[index], builtin_name)?;
            seen_direction = true;
            index += 1;
            continue;
        }

        if parsed.dim.is_none() {
            parsed.dim = Some(positive_dimension(&options[index], builtin_name)?);
            index += 1;
            continue;
        }

        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(a)`, `{builtin_name}(a, dim)`, `{builtin_name}(a, direction)`, `{builtin_name}(a, dim, direction)`, and the same forms with `'MissingPlacement', placement`"
        )));
    }

    Ok((value, parsed))
}

fn parse_sort_direction(value: &Value, builtin_name: &str) -> Result<bool, RuntimeError> {
    let direction = text_value(value)?;
    if direction.eq_ignore_ascii_case("ascend") {
        return Ok(false);
    }
    if direction.eq_ignore_ascii_case("descend") {
        return Ok(true);
    }
    Err(RuntimeError::Unsupported(format!(
        "{builtin_name} direction `{direction}` is not implemented; expected ascend or descend"
    )))
}

fn parse_sort_missing_placement(
    value: &Value,
    builtin_name: &str,
) -> Result<SortMissingPlacement, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "auto" => Ok(SortMissingPlacement::Auto),
        "first" => Ok(SortMissingPlacement::First),
        "last" => Ok(SortMissingPlacement::Last),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} MissingPlacement `{other}` is not implemented; expected auto, first, or last"
        ))),
    }
}

fn parse_comparison_method(
    value: &Value,
    builtin_name: &str,
) -> Result<ComparisonMethod, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "auto" => Ok(ComparisonMethod::Auto),
        "real" => Ok(ComparisonMethod::Real),
        "abs" => Ok(ComparisonMethod::Abs),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} ComparisonMethod `{other}` is not implemented; expected auto, real, or abs"
        ))),
    }
}

fn parse_sortrows_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<
    (
        &'a Value,
        Option<&'a Value>,
        Option<bool>,
        SortMissingPlacement,
        ComparisonMethod,
    ),
    RuntimeError,
> {
    let Some((value, options)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects at least one input argument"
        )));
    };

    let mut columns = None;
    let mut direction = None;
    let mut missing_placement = SortMissingPlacement::Auto;
    let mut comparison_method = ComparisonMethod::Auto;
    let mut seen_missing_placement = false;
    let mut seen_comparison_method = false;
    let mut index = 0;
    while index < options.len() {
        if let Value::CharArray(text) | Value::String(text) = &options[index] {
            if text.eq_ignore_ascii_case("MissingPlacement") {
                let Some(placement) = options.get(index + 1) else {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently expects a value after the 'MissingPlacement' option"
                    )));
                };
                if seen_missing_placement {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently supports 'MissingPlacement' at most once"
                    )));
                }
                missing_placement = parse_sort_missing_placement(placement, builtin_name)?;
                seen_missing_placement = true;
                index += 2;
                continue;
            }
            if text.eq_ignore_ascii_case("ComparisonMethod") {
                let Some(method) = options.get(index + 1) else {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently expects a value after the 'ComparisonMethod' option"
                    )));
                };
                if seen_comparison_method {
                    return Err(RuntimeError::Unsupported(format!(
                        "{builtin_name} currently supports 'ComparisonMethod' at most once"
                    )));
                }
                comparison_method = parse_comparison_method(method, builtin_name)?;
                seen_comparison_method = true;
                index += 2;
                continue;
            }
            if direction.is_some() {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports a single sort direction option"
                )));
            }
            direction = Some(parse_sort_direction(&options[index], builtin_name)?);
            index += 1;
            continue;
        }

        if columns.is_some() {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports at most one column selector and one direction option, plus optional `'MissingPlacement', placement`"
            )));
        }
        columns = Some(&options[index]);
        index += 1;
    }

    Ok((
        value,
        columns,
        direction,
        missing_placement,
        comparison_method,
    ))
}

fn builtin_sortrows(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (value, columns, direction, missing_placement, comparison_method) =
        parse_sortrows_args(args, "sortrows")?;
    let cell_output = matches!(value, Value::Cell(_));

    let matrix = match value {
        Value::Scalar(number) => MatrixValue::new(1, 1, vec![Value::Scalar(*number)])?,
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        Value::String(text) => MatrixValue::new(1, 1, vec![Value::String(text.clone())])?,
        Value::CharArray(_) => coerce_char_matrix(value)?,
        Value::Cell(cell) => text_cell_matrix(cell, "sortrows")?,
        Value::Matrix(matrix) => matrix.clone(),
        _ => {
            return Err(RuntimeError::TypeError(
                "sortrows currently expects numeric, logical, complex, char, text, or text cell scalar/matrix input"
                    .to_string(),
            ))
        }
    };
    if !(matrix_is_numeric_or_complex(&matrix)
        || matrix_is_logical(&matrix)
        || matrix_is_text(&matrix))
    {
        return Err(RuntimeError::TypeError(
            "sortrows currently expects numeric, logical, complex, char, text, or text cell scalar/matrix input".to_string(),
        ));
    }
    let mut columns = parse_sortrows_columns(columns, matrix.cols)?;
    if let Some(descending) = direction {
        for column in &mut columns {
            column.descending = descending;
        }
    }
    let (mut sorted_value, row_indices) =
        sortrows_value_and_indices(&matrix, &columns, missing_placement, comparison_method)?;
    if cell_output {
        if let Value::Matrix(sorted_matrix) = &sorted_value {
            if matrix_is_text(sorted_matrix) {
                sorted_value = Value::Cell(CellValue::with_dimensions(
                    sorted_matrix.rows,
                    sorted_matrix.cols,
                    sorted_matrix.dims().to_vec(),
                    sorted_matrix.elements().to_vec(),
                )?);
            }
        }
    }
    match output_arity {
        0 | 1 => Ok(vec![sorted_value]),
        2 => Ok(vec![sorted_value, row_indices]),
        _ => Err(RuntimeError::Unsupported(
            "sortrows currently supports one or two outputs".to_string(),
        )),
    }
}

fn builtin_issorted(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, options) = parse_sort_args(args, "issorted")?;
    if let Value::Cell(cell) = value {
        let matrix = text_cell_matrix(cell, "issorted")?;
        let dim = options.dim.unwrap_or_else(|| {
            if matrix.rows == 1 && matrix.cols > 1 {
                2
            } else {
                1
            }
        });
        return Ok(logical_scalar(matrix_is_sorted(
            &matrix,
            dim,
            options.descending,
            options.missing_placement,
            options.comparison_method,
        )?));
    }
    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        Value::String(text) => MatrixValue::new(1, 1, vec![Value::String(text.clone())])?,
        Value::CharArray(_) => coerce_char_matrix(value)?,
        Value::Matrix(matrix) => matrix.clone(),
        _ => coerce_matrix(value).map_err(|_| {
            RuntimeError::TypeError(
                "issorted currently expects numeric, logical, complex, char, or text scalar/matrix input"
                    .to_string(),
            )
        })?,
    };
    if !(matrix_is_numeric_or_complex(&matrix)
        || matrix_is_logical(&matrix)
        || matrix_is_text(&matrix))
    {
        return Err(RuntimeError::TypeError(
            "issorted currently expects numeric, logical, complex, char, or text scalar/matrix input".to_string(),
        ));
    }

    let dim = options.dim.unwrap_or_else(|| {
        if matrix.rows == 1 && matrix.cols > 1 {
            2
        } else {
            1
        }
    });
    Ok(logical_scalar(matrix_is_sorted(
        &matrix,
        dim,
        options.descending,
        options.missing_placement,
        options.comparison_method,
    )?))
}

fn builtin_issortedrows(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, columns, direction, missing_placement, comparison_method) =
        parse_sortrows_args(args, "issortedrows")?;

    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        Value::String(text) => MatrixValue::new(1, 1, vec![Value::String(text.clone())])?,
        Value::CharArray(_) => coerce_char_matrix(value)?,
        Value::Cell(cell) => text_cell_matrix(cell, "issortedrows")?,
        Value::Matrix(matrix) => matrix.clone(),
        _ => coerce_matrix(value).map_err(|_| {
            RuntimeError::TypeError(
                "issortedrows currently expects numeric, logical, complex, char, text, or text cell scalar/matrix input"
                    .to_string(),
            )
        })?,
    };
    if !(matrix_is_numeric_or_complex(&matrix)
        || matrix_is_logical(&matrix)
        || matrix_is_text(&matrix))
    {
        return Err(RuntimeError::TypeError(
            "issortedrows currently expects numeric, logical, complex, char, text, or text cell scalar/matrix input"
                .to_string(),
        ));
    }

    let mut columns = parse_sortrows_columns(columns, matrix.cols)?;
    if let Some(descending) = direction {
        for column in &mut columns {
            column.descending = descending;
        }
    }

    Ok(logical_scalar(matrix_rows_are_sorted(
        &matrix,
        &columns,
        missing_placement,
        comparison_method,
    )))
}

fn text_cell_matrix(cell: &CellValue, builtin_name: &str) -> Result<MatrixValue, RuntimeError> {
    if canonical_size_vector(cell.dims()).len() > 2 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects text cell array input to be 2-D"
        )));
    }
    let mut elements = Vec::with_capacity(cell.element_count());
    for element in cell.elements() {
        let text = text_value(element)?.to_string();
        let prototype = text_prototype(element).ok_or_else(|| {
            RuntimeError::TypeError(format!(
                "{builtin_name} currently expects cell arrays of character vectors or strings"
            ))
        })?;
        elements.push(text_value_with_prototype(prototype, text));
    }
    MatrixValue::with_dimensions(cell.rows, cell.cols, cell.dims().to_vec(), elements)
}

fn builtin_union(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (lhs, rhs, order, rows) = parse_set_operation_args(args, "union")?;

    if rows {
        if let Ok(outputs) = union_numeric_rows_outputs(lhs, rhs, order, output_arity) {
            return Ok(outputs);
        }
        if let Ok(outputs) = union_text_rows_outputs(lhs, rhs, order, output_arity) {
            return Ok(outputs);
        }
        return Err(RuntimeError::TypeError(
            "union currently expects numeric or text matrix input when using 'rows'".to_string(),
        ));
    }

    if let (Ok((lhs_values, lhs_row, lhs_logical)), Ok((rhs_values, rhs_row, rhs_logical))) = (
        numeric_set_vector(lhs, "union"),
        numeric_set_vector(rhs, "union"),
    ) {
        return union_numeric_outputs(
            &lhs_values,
            &rhs_values,
            lhs_row && rhs_row,
            lhs_logical && rhs_logical,
            order,
            output_arity,
        );
    }

    if let (Ok((lhs_values, lhs_prototypes, lhs_row)), Ok((rhs_values, rhs_prototypes, rhs_row))) =
        (text_set_vector(lhs, "union"), text_set_vector(rhs, "union"))
    {
        return union_text_outputs(
            &lhs_values,
            &lhs_prototypes,
            &rhs_values,
            &rhs_prototypes,
            lhs_row && rhs_row,
            false,
            order,
            output_arity,
        );
    }

    if let (Ok((lhs_values, lhs_prototypes, lhs_row)), Ok((rhs_values, rhs_prototypes, rhs_row))) = (
        char_text_set_vector(lhs, "union"),
        numeric_char_text_vector(rhs, "union"),
    ) {
        return union_text_outputs(
            &lhs_values,
            &lhs_prototypes,
            &rhs_values,
            &rhs_prototypes,
            lhs_row && rhs_row,
            false,
            order,
            output_arity,
        );
    }

    if let (Ok((lhs_values, lhs_prototypes, lhs_row)), Ok((rhs_values, rhs_prototypes, rhs_row))) = (
        numeric_char_text_vector(lhs, "union"),
        char_text_set_vector(rhs, "union"),
    ) {
        return union_text_outputs(
            &lhs_values,
            &lhs_prototypes,
            &rhs_values,
            &rhs_prototypes,
            lhs_row && rhs_row,
            false,
            order,
            output_arity,
        );
    }

    if let (
        Ok((lhs_values, lhs_prototypes, lhs_row, lhs_cell)),
        Ok((rhs_values, rhs_prototypes, rhs_row, rhs_cell)),
    ) = (
        char_cell_text_set_vector(lhs, "union"),
        char_cell_text_set_vector(rhs, "union"),
    ) {
        if lhs_cell || rhs_cell {
            return union_text_outputs(
                &lhs_values,
                &lhs_prototypes,
                &rhs_values,
                &rhs_prototypes,
                lhs_row && rhs_row,
                true,
                order,
                output_arity,
            );
        }
    }

    Err(RuntimeError::TypeError(
        "union currently expects numeric or text vector inputs".to_string(),
    ))
}

