fn builtin_unique(args: &[Value], output_arity: usize) -> Result<Vec<Value>, RuntimeError> {
    let (value, options) = parse_unique_options(args)?;
    if options.rows {
        if let Ok(outputs) = unique_numeric_row_outputs(value, options, output_arity) {
            return Ok(outputs);
        }
        if let Ok(outputs) = unique_text_row_outputs(value, options, output_arity) {
            return Ok(outputs);
        }
        return Err(RuntimeError::TypeError(
            "unique(...,'rows') currently expects numeric, logical, or text matrix input"
                .to_string(),
        ));
    }
    match value {
        Value::Scalar(_) | Value::Logical(_) => {
            unique_numeric_outputs(value, options, output_arity)
        }
        Value::Matrix(matrix) if matrix_is_text(matrix) => {
            unique_text_outputs(value, options, output_arity)
        }
        Value::Matrix(_) => unique_numeric_outputs(value, options, output_arity),
        Value::CharArray(_) | Value::String(_) | Value::Cell(_) => {
            unique_text_outputs(value, options, output_arity)
        }
        _ => Err(RuntimeError::TypeError(
            "unique currently expects numeric or text vector/matrix input".to_string(),
        )),
    }
}

fn builtin_horzcat(args: &[Value]) -> Result<Value, RuntimeError> {
    concatenate_values(args, ConcatAxis::Columns)
}

fn builtin_vertcat(args: &[Value]) -> Result<Value, RuntimeError> {
    concatenate_values(args, ConcatAxis::Rows)
}

fn builtin_cat(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((dimension, rest)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "cat currently expects a dimension and at least one input".to_string(),
        ));
    };
    let dimension = scalar_dimension(dimension)?;
    concatenate_values(rest, ConcatAxis::Dimension(dimension))
}

fn builtin_blkdiag(args: &[Value]) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?));
    }

    if args.iter().all(|value| match value {
        Value::CharArray(_) => true,
        Value::Matrix(matrix) => matrix_is_char_matrix(matrix),
        _ => false,
    }) {
        let matrices = args
            .iter()
            .map(coerce_char_matrix)
            .collect::<Result<Vec<_>, _>>()?;
        let total_rows = matrices.iter().map(|matrix| matrix.rows).sum::<usize>();
        let total_cols = matrices.iter().map(|matrix| matrix.cols).sum::<usize>();
        let mut chars = vec!['\0'; total_rows * total_cols];
        let mut row_offset = 0usize;
        let mut col_offset = 0usize;
        for matrix in matrices {
            for row in 0..matrix.rows {
                for col in 0..matrix.cols {
                    let dest = (row_offset + row) * total_cols + (col_offset + col);
                    chars[dest] = single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                        RuntimeError::TypeError(
                            "blkdiag currently expects char inputs to contain single-character elements"
                                .to_string(),
                        )
                    })?;
                }
            }
            row_offset += matrix.rows;
            col_offset += matrix.cols;
        }

        return char_value_with_dimensions(vec![total_rows, total_cols], chars);
    }

    let matrices = args
        .iter()
        .map(blkdiag_operand)
        .collect::<Result<Vec<_>, _>>()?;
    let total_rows = matrices.iter().map(|matrix| matrix.rows).sum::<usize>();
    let total_cols = matrices.iter().map(|matrix| matrix.cols).sum::<usize>();
    let fill = if matrices
        .iter()
        .all(|matrix| matrix.storage_class() == ArrayStorageClass::Logical)
    {
        Value::Logical(false)
    } else {
        Value::Scalar(0.0)
    };

    let mut elements = vec![fill; total_rows * total_cols];
    let mut row_offset = 0usize;
    let mut col_offset = 0usize;
    for matrix in matrices {
        for row in 0..matrix.rows {
            for col in 0..matrix.cols {
                let dest = (row_offset + row) * total_cols + (col_offset + col);
                elements[dest] = matrix.get(row, col).clone();
            }
        }
        row_offset += matrix.rows;
        col_offset += matrix.cols;
    }

    Ok(Value::Matrix(MatrixValue::new(
        total_rows, total_cols, elements,
    )?))
}

fn blkdiag_operand(value: &Value) -> Result<MatrixValue, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(MatrixValue::new(1, 1, vec![Value::Scalar(*number)])?),
        Value::Logical(flag) => Ok(MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?),
        Value::Complex(number) => Ok(MatrixValue::new(1, 1, vec![Value::Complex(number.clone())])?),
        Value::Matrix(matrix) => {
            if canonical_size_vector(matrix.dims()).len() > 2 {
                return Err(RuntimeError::TypeError(
                    "blkdiag currently expects scalar, logical, complex, or 2-D matrix input"
                        .to_string(),
                ));
            }
            if !matrix_is_supported_structural_input(matrix) {
                return Err(RuntimeError::TypeError(
                    "blkdiag currently expects numeric, logical, or complex scalar or matrix input"
                        .to_string(),
                ));
            }
            Ok(matrix.clone())
        }
        other => Err(RuntimeError::TypeError(format!(
            "blkdiag currently expects numeric, logical, complex, or char scalar or matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_num2cell(args: &[Value]) -> Result<Value, RuntimeError> {
    let (value, kept_dims) = match args {
        [value] => (value, Vec::new()),
        [value, dims] => (value, num2cell_kept_dimensions(dims)?),
        _ => {
            return Err(RuntimeError::Unsupported(
                "num2cell currently supports `num2cell(A)` and `num2cell(A, dim)`".to_string(),
            ))
        }
    };

    match value {
        Value::Scalar(_)
        | Value::Logical(_)
        | Value::Complex(_)
        | Value::String(_)
        | Value::Struct(_)
        | Value::FunctionHandle(_) => Ok(Value::Cell(CellValue::new(1, 1, vec![value.clone()])?)),
        Value::CharArray(_) => {
            num2cell_matrix_with_kept_dimensions(&coerce_char_matrix(value)?, &kept_dims)
        }
        Value::Matrix(matrix) => num2cell_matrix_with_kept_dimensions(matrix, &kept_dims),
        _ => Err(RuntimeError::TypeError(
            "num2cell currently expects scalar or matrix-like input".to_string(),
        )),
    }
}

fn builtin_mat2cell(args: &[Value]) -> Result<Value, RuntimeError> {
    let Some((value, partitions)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "mat2cell currently expects an input array plus partition vectors".to_string(),
        ));
    };

    match value {
        Value::CharArray(_) => {
            let matrix = coerce_char_matrix(value)?;
            mat2cell_from_elements(matrix.dims(), matrix.elements(), partitions, false)
        }
        Value::Matrix(matrix) => {
            mat2cell_from_elements(matrix.dims(), matrix.elements(), partitions, false)
        }
        Value::Cell(cell) => mat2cell_from_elements(cell.dims(), cell.elements(), partitions, true),
        other => Err(RuntimeError::TypeError(format!(
            "mat2cell currently expects a matrix, char array, or cell array input, found {}",
            other.kind_name()
        ))),
    }
}

fn mat2cell_partition_vectors(
    input_dims: &[usize],
    partitions: &[Value],
) -> Result<(Vec<Vec<usize>>, Vec<usize>), RuntimeError> {
    let mut dims = canonical_size_vector(input_dims);
    if partitions.is_empty() {
        return Err(RuntimeError::Unsupported(
            "mat2cell currently expects at least one partition vector".to_string(),
        ));
    }

    if partitions.len() == 1 {
        let rows = size_query_dimensions(&partitions[0])?;
        if rows.iter().sum::<usize>() != dims.first().copied().unwrap_or(1) {
            return Err(RuntimeError::ShapeError(
                "mat2cell row partition sizes must sum to the input row count".to_string(),
            ));
        }
        let row_count = rows.len();
        let mut partition_vectors = vec![rows];
        for &dim in dims.iter().skip(1) {
            partition_vectors.push(vec![dim]);
        }
        return Ok((partition_vectors, vec![row_count, 1]));
    }

    while dims.len() < partitions.len() {
        dims.push(1);
    }

    let mut partition_vectors = Vec::with_capacity(dims.len());
    for (axis, partition) in partitions.iter().enumerate() {
        let vector = size_query_dimensions(partition)?;
        if vector.iter().sum::<usize>() != dims[axis] {
            return Err(RuntimeError::ShapeError(format!(
                "mat2cell partition sizes along dimension {} must sum to {}",
                axis + 1,
                dims[axis]
            )));
        }
        partition_vectors.push(vector);
    }
    for &dim in dims.iter().skip(partitions.len()) {
        partition_vectors.push(vec![dim]);
    }

    let output_dims = partition_vectors.iter().map(Vec::len).collect::<Vec<_>>();
    Ok((partition_vectors, output_dims))
}

fn mat2cell_from_elements(
    input_dims: &[usize],
    elements: &[Value],
    partitions: &[Value],
    nested_cell_output: bool,
) -> Result<Value, RuntimeError> {
    let input_dims = canonical_size_vector(input_dims);
    let (partition_vectors, output_dims) = mat2cell_partition_vectors(&input_dims, partitions)?;
    let mut starts = Vec::with_capacity(partition_vectors.len());
    for partition in &partition_vectors {
        let mut offsets = Vec::with_capacity(partition.len());
        let mut current = 0usize;
        for &extent in partition {
            offsets.push(current);
            current += extent;
        }
        starts.push(offsets);
    }

    let output_count = if output_dims.is_empty() {
        0
    } else {
        output_dims.iter().product::<usize>()
    };
    let mut cell_elements = Vec::with_capacity(output_count);
    for linear in 0..output_count {
        let output_index = row_major_multi_index(linear, &output_dims);
        let piece_dims = partition_vectors
            .iter()
            .enumerate()
            .map(|(axis, partition)| partition[output_index[axis]])
            .collect::<Vec<_>>();
        let piece_count = piece_dims.iter().product::<usize>();
        let start_index = starts
            .iter()
            .enumerate()
            .map(|(axis, offsets)| offsets[output_index[axis]])
            .collect::<Vec<_>>();
        let mut piece_elements = Vec::with_capacity(piece_count);
        for piece_linear in 0..piece_count {
            let piece_index = row_major_multi_index(piece_linear, &piece_dims);
            let source_index = piece_index
                .iter()
                .enumerate()
                .map(|(axis, &offset)| start_index[axis] + offset)
                .collect::<Vec<_>>();
            piece_elements
                .push(elements[row_major_linear_index(&source_index, &input_dims)].clone());
        }

        if nested_cell_output {
            let (rows, cols) = storage_shape_from_dimensions(&piece_dims);
            cell_elements.push(Value::Cell(CellValue::with_dimensions(
                rows,
                cols,
                piece_dims,
                piece_elements,
            )?));
        } else if piece_count == 1 {
            cell_elements.push(
                piece_elements
                    .into_iter()
                    .next()
                    .expect("single element piece"),
            );
        } else {
            if piece_elements
                .iter()
                .all(|value| single_char_text_value(value).is_some())
            {
                let chars = piece_elements
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(
                                "mat2cell currently expects char arrays to contain single-character elements"
                                    .to_string(),
                            )
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                cell_elements.push(char_value_with_dimensions(piece_dims, chars)?);
            } else {
                let (rows, cols) = storage_shape_from_dimensions(&piece_dims);
                cell_elements.push(Value::Matrix(MatrixValue::with_dimensions(
                    rows,
                    cols,
                    piece_dims,
                    piece_elements,
                )?));
            }
        }
    }

    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    Ok(Value::Cell(CellValue::with_dimensions(
        rows,
        cols,
        output_dims,
        cell_elements,
    )?))
}

fn num2cell_kept_dimensions(value: &Value) -> Result<Vec<usize>, RuntimeError> {
    let mut dims = size_query_dimensions(value)?;
    if dims.is_empty() {
        return Err(RuntimeError::TypeError(
            "num2cell currently expects a nonempty dimension selector".to_string(),
        ));
    }
    dims.sort_unstable();
    dims.dedup();
    Ok(dims)
}

fn num2cell_matrix_with_kept_dimensions(
    matrix: &MatrixValue,
    kept_dims: &[usize],
) -> Result<Value, RuntimeError> {
    let mut input_dims = canonical_size_vector(matrix.dims());
    let max_kept_dim = kept_dims.iter().copied().max().unwrap_or(0);
    while input_dims.len() < max_kept_dim {
        input_dims.push(1);
    }

    let mut output_dims = input_dims.clone();
    let mut cell_content_dims = vec![1usize; input_dims.len()];
    for (axis, size) in input_dims.iter().copied().enumerate() {
        if kept_dims.contains(&(axis + 1)) {
            output_dims[axis] = 1;
            cell_content_dims[axis] = size;
        }
    }

    let output_element_count = output_dims.iter().product::<usize>();
    let content_element_count = cell_content_dims.iter().product::<usize>();
    let mut cell_elements = Vec::with_capacity(output_element_count);
    for linear in 0..output_element_count {
        let output_index = row_major_multi_index(linear, &output_dims);
        if content_element_count == 1 {
            let mut source_index = output_index.clone();
            for kept_dim in kept_dims {
                source_index[*kept_dim - 1] = 0;
            }
            let source_linear = row_major_linear_index(&source_index, &input_dims);
            cell_elements.push(matrix.elements()[source_linear].clone());
            continue;
        }

        let mut elements = Vec::with_capacity(content_element_count);
        for content_linear in 0..content_element_count {
            let content_index = row_major_multi_index(content_linear, &cell_content_dims);
            let mut source_index = output_index.clone();
            for kept_dim in kept_dims {
                source_index[*kept_dim - 1] = content_index[*kept_dim - 1];
            }
            let source_linear = row_major_linear_index(&source_index, &input_dims);
            elements.push(matrix.elements()[source_linear].clone());
        }
        if matrix_is_char_matrix(matrix) {
            let chars = elements
                .iter()
                .map(|value| {
                    single_char_text_value(value).ok_or_else(|| {
                        RuntimeError::TypeError(
                            "num2cell currently expects char arrays to contain single-character elements"
                                .to_string(),
                        )
                    })
                })
                .collect::<Result<Vec<_>, _>>()?;
            cell_elements.push(char_value_with_dimensions(
                cell_content_dims.clone(),
                chars,
            )?);
        } else {
            let (rows, cols) = storage_shape_from_dimensions(&cell_content_dims);
            cell_elements.push(Value::Matrix(MatrixValue::with_dimensions(
                rows,
                cols,
                cell_content_dims.clone(),
                elements,
            )?));
        }
    }

    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    Ok(Value::Cell(CellValue::with_dimensions(
        rows,
        cols,
        output_dims,
        cell_elements,
    )?))
}

fn builtin_cell(args: &[Value]) -> Result<Value, RuntimeError> {
    let dims = match args {
        [] => vec![0, 0],
        _ => fill_dimensions(args, "cell")?,
    };
    let (rows, cols) = storage_shape_from_dimensions(&dims);
    Ok(Value::Cell(CellValue::with_dimensions(
        rows,
        cols,
        dims,
        vec![Value::Matrix(MatrixValue::new(0, 0, Vec::new())?); rows * cols],
    )?))
}

fn builtin_struct2cell(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "struct2cell currently supports exactly one argument".to_string(),
        ));
    };

    match value {
        Value::Struct(struct_value) => {
            let elements = struct_value.ordered_values().cloned().collect::<Vec<_>>();
            Ok(Value::Cell(CellValue::new(elements.len(), 1, elements)?))
        }
        Value::Matrix(matrix) if matrix_is_struct(matrix) => {
            if matrix.element_count() == 0 {
                return Ok(Value::Cell(CellValue::new(0, 0, Vec::new())?));
            }

            let Value::Struct(first) = &matrix.elements()[0] else {
                unreachable!("matrix_is_struct guard ensures struct elements");
            };
            let field_names = first.field_names().to_vec();
            let struct_dims = canonical_size_vector(matrix.dims());
            let mut output_dims = vec![field_names.len()];
            output_dims.extend(struct_dims.clone());
            let (rows, cols) = storage_shape_from_dimensions(&output_dims);
            let mut elements = Vec::with_capacity(field_names.len() * matrix.element_count());
            for linear in 0..(field_names.len() * matrix.element_count()) {
                let index = row_major_multi_index(linear, &output_dims);
                let field_name = &field_names[index[0]];
                let struct_linear = row_major_linear_index(&index[1..], &struct_dims);
                let Value::Struct(struct_value) = &matrix.elements()[struct_linear] else {
                    unreachable!("matrix_is_struct guard ensures struct elements");
                };
                let field_value = struct_value.fields.get(field_name).ok_or_else(|| {
                    RuntimeError::MissingVariable(format!(
                        "struct2cell expects consistent fields across struct arrays; missing `{field_name}`"
                    ))
                })?;
                elements.push(field_value.clone());
            }
            Ok(Value::Cell(CellValue::with_dimensions(
                rows,
                cols,
                output_dims,
                elements,
            )?))
        }
        other => Err(RuntimeError::TypeError(format!(
            "struct2cell currently expects struct or struct-array input, found {}",
            other.kind_name()
        ))),
    }
}

fn builtin_cell2struct(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value, field_names, dim] = args else {
        return Err(RuntimeError::Unsupported(
            "cell2struct currently supports exactly three arguments".to_string(),
        ));
    };
    let Value::Cell(cell) = value else {
        return Err(RuntimeError::TypeError(format!(
            "cell2struct currently expects a cell array input, found {}",
            value.kind_name()
        )));
    };

    let (field_names, _) = field_name_operand(field_names, "cell2struct")?;
    let dim = positive_dimension(dim, "cell2struct")?;
    let mut input_dims = canonical_size_vector(cell.dims());
    while input_dims.len() < dim {
        input_dims.push(1);
    }
    let field_extent = input_dims[dim - 1];
    if field_names.len() != field_extent {
        return Err(RuntimeError::ShapeError(format!(
            "cell2struct expects {} field name(s) along dimension {}, found {}",
            field_extent,
            dim,
            field_names.len()
        )));
    }

    let mut output_dims = input_dims.clone();
    output_dims[dim - 1] = 1;
    let output_element_count = output_dims.iter().product::<usize>();
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    if output_element_count == 0 {
        return Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            output_dims,
            Vec::new(),
        )?));
    }

    let mut elements = Vec::with_capacity(output_element_count);
    for linear in 0..output_element_count {
        let output_index = row_major_multi_index(linear, &output_dims);
        let mut fields = std::collections::BTreeMap::new();
        for (field_offset, field_name) in field_names.iter().enumerate() {
            let mut source_index = output_index.clone();
            source_index[dim - 1] = field_offset;
            let source_linear = row_major_linear_index(&source_index, &input_dims);
            fields.insert(field_name.clone(), cell.elements()[source_linear].clone());
        }
        elements.push(Value::Struct(StructValue::with_field_order(
            fields,
            field_names.clone(),
        )));
    }

    if output_dims.iter().all(|&size| size == 1) {
        Ok(elements.into_iter().next().expect("scalar struct result"))
    } else {
        Ok(Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            output_dims,
            elements,
        )?))
    }
}

fn builtin_cell2mat(args: &[Value]) -> Result<Value, RuntimeError> {
    let [value] = args else {
        return Err(RuntimeError::Unsupported(
            "cell2mat currently supports exactly one argument".to_string(),
        ));
    };
    let Value::Cell(cell) = value else {
        return Err(RuntimeError::TypeError(
            "cell2mat currently expects cell input".to_string(),
        ));
    };

    let cell_dims = canonical_size_vector(cell.dims());

    if cell.element_count() == 0 {
        return Ok(Value::Matrix(MatrixValue::with_dimensions(
            cell.rows,
            cell.cols,
            cell.dims().to_vec(),
            Vec::new(),
        )?));
    }

    let blocks = cell
        .elements()
        .iter()
        .map(cell2mat_operand_matrix)
        .collect::<Result<Vec<_>, _>>()?;

    let concatenated = concatenate_cell2mat_blocks(blocks, &cell_dims)?;
    if matrix_is_char_matrix(&concatenated) {
        let chars = concatenated
            .elements()
            .iter()
            .map(|value| {
                single_char_text_value(value).ok_or_else(|| {
                    RuntimeError::TypeError(
                        "cell2mat currently expects char cells to concatenate into single-character elements"
                            .to_string(),
                    )
                })
            })
            .collect::<Result<Vec<_>, _>>()?;
        return char_value_with_dimensions(concatenated.dims().to_vec(), chars);
    }

    Ok(Value::Matrix(concatenated))
}

fn cell2mat_operand_matrix(value: &Value) -> Result<MatrixValue, RuntimeError> {
    match value {
        Value::Scalar(_)
        | Value::Int64(_)
        | Value::UInt64(_)
        | Value::Logical(_)
        | Value::Complex(_)
        | Value::String(_)
        | Value::Struct(_)
        | Value::Object(_) => MatrixValue::new(1, 1, vec![value.clone()]),
        Value::CharArray(_) => coerce_char_matrix(value),
        Value::Matrix(matrix) => Ok(matrix.clone()),
        Value::Cell(_) | Value::FunctionHandle(_) => Err(RuntimeError::TypeError(
            "cell2mat currently expects each cell element to contain concatenatable arrays"
                .to_string(),
        )),
    }
}

fn concatenate_cell2mat_blocks(
    mut blocks: Vec<MatrixValue>,
    cell_dims: &[usize],
) -> Result<MatrixValue, RuntimeError> {
    if blocks.is_empty() {
        return MatrixValue::new(0, 0, Vec::new());
    }

    for (axis, axis_len) in cell_dims.iter().copied().enumerate().rev() {
        if axis_len <= 1 {
            continue;
        }

        let group_count = blocks.len() / axis_len;
        let mut reduced = Vec::with_capacity(group_count);
        for group_index in 0..group_count {
            let start = group_index * axis_len;
            let end = start + axis_len;
            reduced.push(concatenate_matrices(
                &blocks[start..end],
                ConcatAxis::Dimension(axis + 1),
            )?);
        }
        blocks = reduced;
    }

    debug_assert_eq!(blocks.len(), 1);
    Ok(blocks
        .into_iter()
        .next()
        .expect("non-empty cell2mat block reduction"))
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum ConcatAxis {
    Rows,
    Columns,
    Dimension(usize),
}

fn concatenate_values(args: &[Value], axis: ConcatAxis) -> Result<Value, RuntimeError> {
    if args.is_empty() {
        return Err(RuntimeError::Unsupported(
            "concatenation builtins currently expect at least one input".to_string(),
        ));
    }

    if args.iter().all(|value| value_is_char_concat_input(value)) {
        let matrices = args
            .iter()
            .map(coerce_char_matrix)
            .collect::<Result<Vec<_>, _>>()?;
        let concatenated = concatenate_matrices(&matrices, axis)?;
        let chars = concatenated
            .elements()
            .iter()
            .map(|value| {
                single_char_text_value(value).ok_or_else(|| {
                    RuntimeError::TypeError(
                        "concatenation builtins currently expect char inputs to contain single-character elements"
                            .to_string(),
                    )
                })
            })
            .collect::<Result<Vec<_>, _>>()?;
        return char_value_with_dimensions(concatenated.dims().to_vec(), chars);
    }

    if args.iter().all(|value| {
        matches!(
            value,
            Value::Scalar(_) | Value::Matrix(_) | Value::Object(_)
        )
    }) {
        let matrices = args
            .iter()
            .map(coerce_matrix)
            .collect::<Result<Vec<_>, _>>()?;
        return Ok(Value::Matrix(concatenate_matrices(&matrices, axis)?));
    }

    if args.iter().all(|value| matches!(value, Value::Cell(_))) {
        let cells = args
            .iter()
            .map(|value| match value {
                Value::Cell(cell) => Ok(cell.clone()),
                _ => unreachable!("cell-only guard above"),
            })
            .collect::<Result<Vec<_>, RuntimeError>>()?;
        return Ok(Value::Cell(concatenate_cells(&cells, axis)?));
    }

    Err(RuntimeError::TypeError(
        "concatenation builtins currently require all inputs to be numeric scalars/matrices or all cells".to_string(),
    ))
}

fn value_is_char_concat_input(value: &Value) -> bool {
    matches!(value, Value::CharArray(_))
        || matches!(value, Value::Matrix(matrix) if matrix_is_char_matrix(matrix))
}

fn coerce_char_matrix(value: &Value) -> Result<MatrixValue, RuntimeError> {
    match value {
        Value::CharArray(text) => {
            let dims = value_dimensions(value);
            let (rows, cols) = storage_shape_from_dimensions(&dims);
            MatrixValue::with_dimensions(
                rows,
                cols,
                dims,
                text.chars()
                    .map(|ch| Value::CharArray(ch.to_string()))
                    .collect(),
            )
        }
        Value::Matrix(matrix) if matrix_is_char_matrix(matrix) => Ok(matrix.clone()),
        _ => Err(RuntimeError::TypeError(
            "expected char vector or char matrix input".to_string(),
        )),
    }
}

fn coerce_matrix(value: &Value) -> Result<MatrixValue, RuntimeError> {
    match value {
        Value::Scalar(number) => MatrixValue::new(1, 1, vec![Value::Scalar(*number)]),
        Value::Object(object) => MatrixValue::new(1, 1, vec![Value::Object(object.clone())]),
        Value::Matrix(matrix) => Ok(matrix.clone()),
        _ => Err(RuntimeError::TypeError(
            "expected numeric scalar, object scalar, or matrix input".to_string(),
        )),
    }
}

fn concatenate_matrices(
    matrices: &[MatrixValue],
    axis: ConcatAxis,
) -> Result<MatrixValue, RuntimeError> {
    let along_dim = match axis {
        ConcatAxis::Rows => 1,
        ConcatAxis::Columns => 2,
        ConcatAxis::Dimension(dim) => dim,
    };
    let input_dims = matrices
        .iter()
        .map(|matrix| matrix.dims.clone())
        .collect::<Vec<_>>();
    let output_dims = concatenated_dimensions(&input_dims, along_dim, "cat")?;
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    let elements = concatenate_elements(
        &matrices
            .iter()
            .map(|matrix| matrix.elements.clone())
            .collect::<Vec<_>>(),
        &input_dims,
        &output_dims,
        along_dim,
    );
    MatrixValue::with_dimensions(rows, cols, output_dims, elements)
}

fn concatenate_cells(cells: &[CellValue], axis: ConcatAxis) -> Result<CellValue, RuntimeError> {
    let along_dim = match axis {
        ConcatAxis::Rows => 1,
        ConcatAxis::Columns => 2,
        ConcatAxis::Dimension(dim) => dim,
    };
    let input_dims = cells
        .iter()
        .map(|cell| cell.dims.clone())
        .collect::<Vec<_>>();
    let output_dims = concatenated_dimensions(&input_dims, along_dim, "cat")?;
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    let elements = concatenate_elements(
        &cells
            .iter()
            .map(|cell| cell.elements.clone())
            .collect::<Vec<_>>(),
        &input_dims,
        &output_dims,
        along_dim,
    );
    CellValue::with_dimensions(rows, cols, output_dims, elements)
}

fn transpose_matrix(matrix: &MatrixValue) -> Result<MatrixValue, RuntimeError> {
    ensure_transpose_supported(&matrix.dims, false)?;
    let mut elements = Vec::with_capacity(matrix.elements.len());
    for row in 0..matrix.cols {
        for col in 0..matrix.rows {
            elements.push(matrix.get(col, row).clone());
        }
    }
    MatrixValue::new(matrix.cols, matrix.rows, elements)
}

fn transpose_cell(cell: &CellValue) -> Result<CellValue, RuntimeError> {
    ensure_transpose_supported(&cell.dims, false)?;
    let mut elements = Vec::with_capacity(cell.elements.len());
    for row in 0..cell.cols {
        for col in 0..cell.rows {
            elements.push(cell.get(col, row).clone());
        }
    }
    CellValue::new(cell.cols, cell.rows, elements)
}

fn transpose_value(value: &Value, conjugate: bool) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Logical(flag) => Ok(Value::Logical(*flag)),
        Value::Complex(number) => Ok(numeric_or_complex_value(
            ComplexParts {
                real: number.real,
                imag: number.imag,
            }
            .conjugate_if(conjugate),
        )),
        Value::CharArray(text) => {
            let dims = value_dimensions(value);
            ensure_transpose_supported(&dims, conjugate)?;
            let rows = dimension_length(&dims, 1);
            let cols = dimension_length(&dims, 2);
            char_value_with_dimensions(vec![cols, rows], text.chars().collect())
        }
        Value::Object(object) => Ok(Value::Object(object.clone())),
        Value::Matrix(matrix) => {
            let transposed = if conjugate {
                transpose_matrix_with_mode(matrix, true)?
            } else {
                transpose_matrix(matrix)?
            };
            if matrix_is_char_matrix(matrix) {
                let chars = transposed
                    .elements()
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(
                                "transpose currently expects char matrices to contain single-character elements"
                                    .to_string(),
                            )
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(transposed.dims().to_vec(), chars);
            }
            Ok(Value::Matrix(transposed))
        }
        Value::Cell(cell) => Ok(Value::Cell(transpose_cell(cell)?)),
        _ => Err(RuntimeError::TypeError(if conjugate {
            "ctranspose currently expects scalar, logical, complex, object, char, matrix, or cell input"
                .to_string()
        } else {
            "transpose currently expects scalar, logical, complex, object, char, matrix, or cell input"
                .to_string()
        })),
    }
}

fn ensure_transpose_supported(dims: &[usize], conjugate: bool) -> Result<(), RuntimeError> {
    if canonical_size_vector(dims).len() > 2 {
        return Err(RuntimeError::Unsupported(if conjugate {
            "transpose does not support N-D arrays. Use pagectranspose or pagetranspose to transpose pages or permute to reorder dimensions."
                .to_string()
        } else {
            "transpose does not support N-D arrays. Use pagetranspose or pagectranspose to transpose pages or permute to reorder dimensions."
                .to_string()
        }));
    }
    Ok(())
}

fn page_transpose_value(
    value: &Value,
    conjugate: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_)
        | Value::Logical(_)
        | Value::Complex(_)
        | Value::FunctionHandle(_)
        | Value::Object(_) => {
            Ok(value.clone())
        }
        Value::CharArray(_) | Value::String(_) => transpose_value(value, conjugate),
        Value::Matrix(matrix) => {
            let transposed = page_transpose_matrix_with_mode(matrix, conjugate)?;
            if matrix_is_char_matrix(matrix) {
                let chars = transposed
                    .elements()
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(format!(
                                "{builtin_name} currently expects char matrices to contain single-character elements"
                            ))
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(transposed.dims().to_vec(), chars);
            }
            Ok(Value::Matrix(transposed))
        }
        Value::Cell(cell) => Ok(Value::Cell(page_transpose_cell(cell)?)),
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, logical, complex, object, matrix, cell, or text input"
        ))),
    }
}

fn transpose_matrix_with_mode(
    matrix: &MatrixValue,
    conjugate: bool,
) -> Result<MatrixValue, RuntimeError> {
    ensure_transpose_supported(&matrix.dims, conjugate)?;
    let mut elements = Vec::with_capacity(matrix.elements.len());
    for row in 0..matrix.cols {
        for col in 0..matrix.rows {
            elements.push(transpose_element_value(matrix.get(col, row), conjugate)?);
        }
    }
    MatrixValue::new(matrix.cols, matrix.rows, elements)
}

fn page_transpose_matrix_with_mode(
    matrix: &MatrixValue,
    conjugate: bool,
) -> Result<MatrixValue, RuntimeError> {
    let dims = canonical_size_vector(&matrix.dims);
    if dims.len() <= 2 {
        return if conjugate {
            transpose_matrix_with_mode(matrix, true)
        } else {
            transpose_matrix(matrix)
        };
    }

    let order = std::iter::once(2usize)
        .chain(std::iter::once(1usize))
        .chain(3..=dims.len())
        .collect::<Vec<_>>();
    let elements = matrix
        .elements
        .iter()
        .map(|value| transpose_element_value(value, conjugate))
        .collect::<Result<Vec<_>, _>>()?;
    let (rows, cols, permuted_dims, permuted_elements) =
        permute_row_major_elements(&elements, &dims, &order);
    MatrixValue::with_dimensions(rows, cols, permuted_dims, permuted_elements)
}

fn page_transpose_cell(cell: &CellValue) -> Result<CellValue, RuntimeError> {
    let dims = canonical_size_vector(&cell.dims);
    if dims.len() <= 2 {
        return transpose_cell(cell);
    }

    let order = std::iter::once(2usize)
        .chain(std::iter::once(1usize))
        .chain(3..=dims.len())
        .collect::<Vec<_>>();
    let (rows, cols, permuted_dims, permuted_elements) =
        permute_row_major_elements(&cell.elements, &dims, &order);
    CellValue::with_dimensions(rows, cols, permuted_dims, permuted_elements)
}

fn transpose_element_value(value: &Value, conjugate: bool) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Logical(flag) => Ok(Value::Logical(*flag)),
        Value::Complex(number) => Ok(numeric_or_complex_value(
            ComplexParts {
                real: number.real,
                imag: number.imag,
            }
            .conjugate_if(conjugate),
        )),
        other => Ok(other.clone()),
    }
}

fn diagonal_offset(value: &Value, builtin_name: &str) -> Result<isize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects an integer scalar diagonal offset"
        )));
    }
    Ok(scalar as isize)
}

fn matrix_is_supported_structural_input(matrix: &MatrixValue) -> bool {
    matrix.iter().all(|element| {
        matches!(
            element,
            Value::Scalar(_) | Value::Complex(_) | Value::Logical(_)
        )
    })
}

fn matrix_is_symmetric_like(value: &Value, conjugate: bool) -> Result<bool, RuntimeError> {
    if let Some(matrix) = coerce_char_matrix_like(value)? {
        if matrix.rows != matrix.cols {
            return Ok(false);
        }
        for row in 0..matrix.rows {
            for col in 0..matrix.cols {
                if matrix.get(row, col) != matrix.get(col, row) {
                    return Ok(false);
                }
            }
        }
        return Ok(true);
    }

    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => Ok(true),
        Value::Matrix(matrix) => {
            if !matrix_is_supported_structural_input(matrix) {
                return Err(RuntimeError::TypeError(if conjugate {
                    "ishermitian currently expects numeric, logical, complex, or char scalar or matrix input"
                            .to_string()
                } else {
                    "issymmetric currently expects numeric, logical, complex, or char scalar or matrix input"
                            .to_string()
                }));
            }
            if matrix.rows != matrix.cols {
                return Ok(false);
            }
            let operand = numeric_or_complex_operand(
                value,
                if conjugate {
                    "ishermitian"
                } else {
                    "issymmetric"
                },
            )?;
            for row in 0..operand.rows {
                for col in 0..operand.cols {
                    let lhs = operand.values[row * operand.cols + col];
                    let rhs = operand.values[col * operand.cols + row].conjugate_if(conjugate);
                    if lhs.real != rhs.real || lhs.imag != rhs.imag {
                        return Ok(false);
                    }
                }
            }
            Ok(true)
        }
        _ => Err(RuntimeError::TypeError(if conjugate {
            "ishermitian currently expects numeric, logical, complex, or char scalar or matrix input"
                .to_string()
        } else {
            "issymmetric currently expects numeric, logical, complex, or char scalar or matrix input"
                .to_string()
        })),
    }
}

fn matrix_is_triangular_like(value: &Value, upper: bool) -> Result<bool, RuntimeError> {
    if let Some(matrix) = coerce_char_matrix_like(value)? {
        for row in 0..matrix.rows {
            for col in 0..matrix.cols {
                let outside = if upper { row > col } else { col > row };
                if outside && single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                    RuntimeError::TypeError(if upper {
                        "istriu currently expects char arrays to contain single-character elements"
                            .to_string()
                    } else {
                        "istril currently expects char arrays to contain single-character elements"
                            .to_string()
                    })
                })? != '\0'
                {
                    return Ok(false);
                }
            }
        }
        return Ok(true);
    }

    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => Ok(true),
        Value::Matrix(matrix) => {
            if !matrix_is_supported_structural_input(matrix) {
                return Err(RuntimeError::TypeError(if upper {
                    "istriu currently expects numeric, logical, complex, or char scalar or matrix input"
                        .to_string()
                } else {
                    "istril currently expects numeric, logical, complex, or char scalar or matrix input"
                        .to_string()
                }));
            }
            let operand =
                numeric_or_complex_operand(value, if upper { "istriu" } else { "istril" })?;
            for row in 0..operand.rows {
                for col in 0..operand.cols {
                    let outside = if upper { row > col } else { col > row };
                    if outside && !operand.values[row * operand.cols + col].is_approximately_zero()
                    {
                        return Ok(false);
                    }
                }
            }
            Ok(true)
        }
        _ => Err(RuntimeError::TypeError(if upper {
            "istriu currently expects numeric, logical, complex, or char scalar or matrix input"
                .to_string()
        } else {
            "istril currently expects numeric, logical, complex, or char scalar or matrix input"
                .to_string()
        })),
    }
}

fn coerce_char_matrix_like(value: &Value) -> Result<Option<MatrixValue>, RuntimeError> {
    match value {
        Value::CharArray(_) => Ok(Some(coerce_char_matrix(value)?)),
        Value::Matrix(matrix) if matrix_is_char_matrix(matrix) => Ok(Some(matrix.clone())),
        Value::Matrix(matrix)
            if canonical_size_vector(matrix.dims()).len() <= 2
                && matrix.cols == 1
                && matrix
                    .iter()
                    .all(|value| matches!(value, Value::CharArray(_))) =>
        {
            let rows = matrix.rows;
            let texts = matrix
                .iter()
                .map(|value| match value {
                    Value::CharArray(text) => text.clone(),
                    _ => unreachable!("checked char-array elements"),
                })
                .collect::<Vec<_>>();
            let cols = texts
                .iter()
                .map(|text| text.chars().count())
                .max()
                .unwrap_or(0);
            let mut elements = Vec::with_capacity(rows * cols);
            for text in texts {
                let chars = text.chars().collect::<Vec<_>>();
                for col in 0..cols {
                    let ch = chars.get(col).copied().unwrap_or(' ');
                    elements.push(Value::CharArray(ch.to_string()));
                }
            }
            Ok(Some(MatrixValue::with_dimensions(
                rows,
                cols,
                vec![rows, cols],
                elements,
            )?))
        }
        _ => Ok(None),
    }
}

fn triangular_projection(
    value: &Value,
    offset: isize,
    upper: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => {
            let include = if upper {
                0isize >= offset
            } else {
                0isize <= offset
            };
            if include {
                Ok(value.clone())
            } else {
                Ok(structural_zero_value(value))
            }
        }
        Value::CharArray(_) => {
            let matrix = coerce_char_matrix(value)?;
            let mut chars = Vec::with_capacity(matrix.elements.len());
            for row in 0..matrix.rows {
                for col in 0..matrix.cols {
                    let delta = col as isize - row as isize;
                    let include = if upper {
                        delta >= offset
                    } else {
                        delta <= offset
                    };
                    chars.push(if include {
                        single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                            RuntimeError::TypeError(format!(
                                "{builtin_name} currently expects char arrays to contain single-character elements"
                            ))
                        })?
                    } else {
                        '\0'
                    });
                }
            }
            char_value_with_dimensions(matrix.dims().to_vec(), chars)
        }
        Value::Matrix(matrix) => {
            if matrix_is_char_matrix(matrix) {
                let mut chars = Vec::with_capacity(matrix.elements.len());
                for row in 0..matrix.rows {
                    for col in 0..matrix.cols {
                        let delta = col as isize - row as isize;
                        let include = if upper {
                            delta >= offset
                        } else {
                            delta <= offset
                        };
                        chars.push(if include {
                            single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                                RuntimeError::TypeError(format!(
                                    "{builtin_name} currently expects char arrays to contain single-character elements"
                                ))
                            })?
                        } else {
                            '\0'
                        });
                    }
                }
                return char_value_with_dimensions(matrix.dims().to_vec(), chars);
            }
            if !matrix_is_supported_structural_input(matrix) {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects numeric, logical, complex, or char scalar or matrix input"
                )));
            }
            let mut elements = Vec::with_capacity(matrix.elements.len());
            for row in 0..matrix.rows {
                for col in 0..matrix.cols {
                    let delta = col as isize - row as isize;
                    let include = if upper {
                        delta >= offset
                    } else {
                        delta <= offset
                    };
                    elements.push(if include {
                        matrix.get(row, col).clone()
                    } else {
                        structural_zero_value(matrix.get(row, col))
                    });
                }
            }
            Ok(Value::Matrix(MatrixValue::new(
                matrix.rows,
                matrix.cols,
                elements,
            )?))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric, logical, complex, or char scalar or matrix input"
        ))),
    }
}

fn structural_zero_value(value: &Value) -> Value {
    match value {
        Value::Logical(_) => Value::Logical(false),
        _ => Value::Scalar(0.0),
    }
}

fn flip_rows_matrix(matrix: &MatrixValue) -> Result<MatrixValue, RuntimeError> {
    let elements = flip_elements_along_dimension(matrix.elements(), matrix.dims(), 1);
    MatrixValue::with_dimensions(matrix.rows, matrix.cols, matrix.dims().to_vec(), elements)
}

fn flip_cols_matrix(matrix: &MatrixValue) -> Result<MatrixValue, RuntimeError> {
    let elements = flip_elements_along_dimension(matrix.elements(), matrix.dims(), 2);
    MatrixValue::with_dimensions(matrix.rows, matrix.cols, matrix.dims().to_vec(), elements)
}

fn flip_rows_cell(cell: &CellValue) -> Result<CellValue, RuntimeError> {
    let elements = flip_elements_along_dimension(cell.elements(), cell.dims(), 1);
    CellValue::with_dimensions(cell.rows, cell.cols, cell.dims().to_vec(), elements)
}

fn flip_cols_cell(cell: &CellValue) -> Result<CellValue, RuntimeError> {
    let elements = flip_elements_along_dimension(cell.elements(), cell.dims(), 2);
    CellValue::with_dimensions(cell.rows, cell.cols, cell.dims().to_vec(), elements)
}

fn flip_elements_along_dimension<T: Clone>(
    elements: &[T],
    dims: &[usize],
    dimension: usize,
) -> Vec<T> {
    if elements.is_empty() || dimension == 0 || dimension > dims.len() {
        return elements.to_vec();
    }

    let axis = dimension - 1;
    if dims[axis] <= 1 {
        return elements.to_vec();
    }

    let mut flipped = vec![elements[0].clone(); elements.len()];
    for (linear, element) in elements.iter().enumerate() {
        let mut index = row_major_multi_index(linear, dims);
        index[axis] = dims[axis] - 1 - index[axis];
        let flipped_linear = row_major_linear_index(&index, dims);
        flipped[flipped_linear] = element.clone();
    }
    flipped
}

fn flip_along_dimension(
    value: &Value,
    dimension: usize,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(*number)),
        Value::Logical(flag) => Ok(Value::Logical(*flag)),
        Value::Complex(number) => Ok(Value::Complex(number.clone())),
        Value::Object(object) => Ok(Value::Object(object.clone())),
        Value::CharArray(text) | Value::String(text) => {
            if dimension == 2 {
                let reversed = text.chars().rev().collect::<String>();
                Ok(match value {
                    Value::CharArray(_) => Value::CharArray(reversed),
                    Value::String(_) => Value::String(reversed),
                    _ => unreachable!(),
                })
            } else {
                Ok(value.clone())
            }
        }
        Value::Matrix(matrix) => {
            let flipped = match dimension {
                1 => flip_rows_matrix(matrix)?,
                2 => flip_cols_matrix(matrix)?,
                _ => MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    matrix.dims().to_vec(),
                    flip_elements_along_dimension(matrix.elements(), matrix.dims(), dimension),
                )?,
            };
            if matrix_is_char_matrix(matrix) {
                let chars = flipped
                    .elements()
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(format!(
                                "{builtin_name} currently expects char arrays to contain single-character elements"
                            ))
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(flipped.dims().to_vec(), chars);
            }
            Ok(Value::Matrix(flipped))
        }
        Value::Cell(cell) => Ok(Value::Cell(match dimension {
            1 => flip_rows_cell(cell)?,
            2 => flip_cols_cell(cell)?,
            _ => CellValue::with_dimensions(
                cell.rows,
                cell.cols,
                cell.dims().to_vec(),
                flip_elements_along_dimension(cell.elements(), cell.dims(), dimension),
            )?,
        })),
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, object, matrix, cell, or row-text input"
        ))),
    }
}

fn rotate_90(
    value: &Value,
    counterclockwise: bool,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) | Value::Object(_) => {
            Ok(value.clone())
        }
        Value::CharArray(text) => {
            let dims = value_dimensions(value);
            let elements = text
                .chars()
                .map(|ch| Value::CharArray(ch.to_string()))
                .collect::<Vec<_>>();
            let (_rows, _cols, rotated_dims, rotated_elements) = rotate_elements_first_two_dims(
                &elements,
                &dims,
                if counterclockwise { 1 } else { 3 },
            );
            let chars = rotated_elements
                .iter()
                .map(|value| {
                    single_char_text_value(value).ok_or_else(|| {
                        RuntimeError::TypeError(
                            "rot90 currently expects char arrays to contain single-character elements"
                                .to_string(),
                        )
                    })
                })
                .collect::<Result<Vec<_>, _>>()?;
            char_value_with_dimensions(rotated_dims, chars)
        }
        Value::Matrix(matrix) => Ok(Value::Matrix(rotate_matrix_first_two_dims(
            matrix,
            if counterclockwise { 1 } else { 3 },
        )?)),
        Value::Cell(cell) => Ok(Value::Cell(rotate_cell_first_two_dims(
            cell,
            if counterclockwise { 1 } else { 3 },
        )?)),
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, char, matrix, or cell input"
        ))),
    }
}

fn rotate_180(value: &Value, builtin_name: &str) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) | Value::Object(_) => {
            Ok(value.clone())
        }
        Value::CharArray(text) => {
            let dims = value_dimensions(value);
            let elements = text
                .chars()
                .map(|ch| Value::CharArray(ch.to_string()))
                .collect::<Vec<_>>();
            let (_rows, _cols, rotated_dims, rotated_elements) =
                rotate_elements_first_two_dims(&elements, &dims, 2);
            let chars = rotated_elements
                .iter()
                .map(|value| {
                    single_char_text_value(value).ok_or_else(|| {
                        RuntimeError::TypeError(
                            "rot90 currently expects char arrays to contain single-character elements"
                                .to_string(),
                        )
                    })
                })
                .collect::<Result<Vec<_>, _>>()?;
            char_value_with_dimensions(rotated_dims, chars)
        }
        Value::Matrix(matrix) => Ok(Value::Matrix(rotate_matrix_first_two_dims(matrix, 2)?)),
        Value::Cell(cell) => Ok(Value::Cell(rotate_cell_first_two_dims(cell, 2)?)),
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, char, matrix, or cell input"
        ))),
    }
}

fn rotate_matrix_first_two_dims(
    matrix: &MatrixValue,
    turns: usize,
) -> Result<MatrixValue, RuntimeError> {
    let (rows, cols, dims, elements) =
        rotate_elements_first_two_dims(matrix.elements(), matrix.dims(), turns % 4);
    MatrixValue::with_dimensions(rows, cols, dims, elements)
}

fn rotate_cell_first_two_dims(cell: &CellValue, turns: usize) -> Result<CellValue, RuntimeError> {
    let (rows, cols, dims, elements) =
        rotate_elements_first_two_dims(cell.elements(), cell.dims(), turns % 4);
    CellValue::with_dimensions(rows, cols, dims, elements)
}

fn rotate_elements_first_two_dims<T: Clone>(
    elements: &[T],
    dims: &[usize],
    turns: usize,
) -> (usize, usize, Vec<usize>, Vec<T>) {
    let canonical = canonical_size_vector(dims);
    let mut rotated_dims = canonical.clone();
    if turns % 2 == 1 && rotated_dims.len() >= 2 {
        rotated_dims.swap(0, 1);
    }
    let (rows, cols) = storage_shape_from_dimensions(&rotated_dims);
    if elements.is_empty() || turns == 0 {
        return (rows, cols, rotated_dims, elements.to_vec());
    }

    let mut rotated = vec![elements[0].clone(); elements.len()];
    let row_extent = canonical.first().copied().unwrap_or(1);
    let col_extent = canonical.get(1).copied().unwrap_or(1);
    for (linear, element) in elements.iter().enumerate() {
        let source_index = row_major_multi_index(linear, &canonical);
        let mut target_index = source_index.clone();
        match turns {
            1 => {
                target_index[0] = col_extent - 1 - source_index[1];
                target_index[1] = source_index[0];
            }
            2 => {
                target_index[0] = row_extent - 1 - source_index[0];
                target_index[1] = col_extent - 1 - source_index[1];
            }
            3 => {
                target_index[0] = source_index[1];
                target_index[1] = row_extent - 1 - source_index[0];
            }
            _ => {}
        }
        let target_linear = row_major_linear_index(&target_index, &rotated_dims);
        rotated[target_linear] = element.clone();
    }

    (rows, cols, rotated_dims, rotated)
}

fn circshift_shifts(
    value: &Value,
    shift: &Value,
    dim: Option<&Value>,
) -> Result<Vec<isize>, RuntimeError> {
    let dims = canonical_size_vector(&value_dimensions(value));
    if let Some(dim) = dim {
        let dim = size_query_dimension_scalar(dim)?;
        let shift = circshift_shift_scalar(shift.as_scalar()?)?;
        let mut shifts = vec![0isize; dims.len().max(dim)];
        shifts[dim - 1] = shift;
        return Ok(shifts);
    }

    match shift {
        Value::Scalar(number) => {
            let shift = circshift_shift_scalar(*number)?;
            let default_axis = if dimension_length(&dims, 1) != 1 {
                1
            } else if dimension_length(&dims, 2) != 1 {
                2
            } else {
                1
            };
            let mut shifts = vec![0isize; dims.len().max(default_axis)];
            shifts[default_axis - 1] = shift;
            Ok(shifts)
        }
        Value::Matrix(matrix) => {
            let values = matrix
                .scalar_elements()?
                .into_iter()
                .map(circshift_shift_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            if values.is_empty() {
                return Err(RuntimeError::Unsupported(
                    "circshift currently expects a nonempty real numeric scalar or vector shift"
                        .to_string(),
                ));
            }
            Ok(values)
        }
        _ => Err(RuntimeError::TypeError(
            "circshift currently expects a real numeric scalar or vector shift".to_string(),
        )),
    }
}

fn parse_shift_halves_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, Option<usize>), RuntimeError> {
    match args {
        [value] => Ok((value, None)),
        [value, dim] => Ok((value, Some(size_query_dimension_scalar(dim)?))),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(X)` and `{builtin_name}(X,dim)`"
        ))),
    }
}

fn shift_halves_shifts(
    value: &Value,
    dim: Option<usize>,
    inverse: bool,
) -> Result<Vec<isize>, RuntimeError> {
    let dims = canonical_size_vector(&value_dimensions(value));
    let mut shifts = vec![0isize; dims.len().max(dim.unwrap_or(1))];
    if let Some(dim) = dim {
        let extent = dimension_length(&dims, dim);
        shifts[dim - 1] = shift_halves_amount(extent, inverse);
    } else {
        for axis in 0..dims.len() {
            shifts[axis] = shift_halves_amount(dims[axis], inverse);
        }
    }
    Ok(shifts)
}

fn shift_halves_amount(extent: usize, inverse: bool) -> isize {
    if inverse {
        extent.div_ceil(2) as isize
    } else {
        (extent / 2) as isize
    }
}

fn circshift_shift_scalar(value: f64) -> Result<isize, RuntimeError> {
    if !value.is_finite() || value.fract() != 0.0 {
        return Err(RuntimeError::TypeError(
            "circshift shift values must be finite integers".to_string(),
        ));
    }
    Ok(value as isize)
}

fn circshift_value(
    value: &Value,
    shifts: &[isize],
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) | Value::Object(_) => {
            Ok(value.clone())
        }
        Value::CharArray(text) | Value::String(text) => {
            let chars = text.chars().collect::<Vec<_>>();
            if chars.is_empty() {
                return Ok(value.clone());
            }
            let shifted = circshift_elements(&chars, &[1, chars.len()], shifts);
            let shifted = shifted.into_iter().collect::<String>();
            Ok(match value {
                Value::CharArray(_) => Value::CharArray(shifted),
                Value::String(_) => Value::String(shifted),
                _ => unreachable!(),
            })
        }
        Value::Matrix(matrix) => {
            let shifted = circshift_matrix(matrix, shifts)?;
            if matrix_is_char_matrix(matrix) {
                let chars = shifted
                    .elements()
                    .iter()
                    .map(|value| {
                        single_char_text_value(value).ok_or_else(|| {
                            RuntimeError::TypeError(format!(
                                "{builtin_name} currently expects char arrays to contain single-character elements"
                            ))
                        })
                    })
                    .collect::<Result<Vec<_>, _>>()?;
                return char_value_with_dimensions(shifted.dims().to_vec(), chars);
            }
            Ok(Value::Matrix(shifted))
        }
        Value::Cell(cell) => Ok(Value::Cell(circshift_cell(cell, shifts)?)),
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects scalar, object, matrix, cell, or row-text input"
        ))),
    }
}

fn circshift_elements<T: Clone>(elements: &[T], dims: &[usize], shifts: &[isize]) -> Vec<T> {
    if elements.is_empty() {
        return Vec::new();
    }

    let mut shifted = vec![elements[0].clone(); elements.len()];
    for (linear, element) in elements.iter().enumerate() {
        let index = row_major_multi_index(linear, dims);
        let mut target = index.clone();
        for axis in 0..dims.len() {
            let extent = dims[axis];
            if extent <= 1 {
                continue;
            }
            let shift = shifts.get(axis).copied().unwrap_or(0);
            let offset = shift.rem_euclid(extent as isize) as usize;
            target[axis] = (target[axis] + offset) % extent;
        }
        let shifted_linear = row_major_linear_index(&target, dims);
        shifted[shifted_linear] = element.clone();
    }
    shifted
}

fn circshift_matrix(matrix: &MatrixValue, shifts: &[isize]) -> Result<MatrixValue, RuntimeError> {
    if matrix.rows == 0 || matrix.cols == 0 {
        return MatrixValue::with_dimensions(
            matrix.rows,
            matrix.cols,
            matrix.dims().to_vec(),
            matrix.elements().to_vec(),
        );
    }
    let elements = circshift_elements(matrix.elements(), matrix.dims(), shifts);
    MatrixValue::with_dimensions(matrix.rows, matrix.cols, matrix.dims().to_vec(), elements)
}

fn circshift_cell(cell: &CellValue, shifts: &[isize]) -> Result<CellValue, RuntimeError> {
    if cell.rows == 0 || cell.cols == 0 {
        return CellValue::with_dimensions(
            cell.rows,
            cell.cols,
            cell.dims().to_vec(),
            cell.elements().to_vec(),
        );
    }
    let elements = circshift_elements(cell.elements(), cell.dims(), shifts);
    CellValue::with_dimensions(cell.rows, cell.cols, cell.dims().to_vec(), elements)
}

fn cumulative_numeric_or_complex_value(
    value: &Value,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    name: &str,
    step: impl Fn(ComplexParts, ComplexParts) -> ComplexParts + Copy,
    identity: ComplexParts,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => Ok(numeric_or_complex_value(
            numeric_or_complex_scalar(value, name)?,
        )),
        Value::Matrix(matrix) => {
            let real_input = !value_contains_complex_entries(value);
            let input_dims = canonical_size_vector(matrix.dims());
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, name))
                .collect::<Result<Vec<_>, _>>()?;
            if values.is_empty() {
                return numeric_or_complex_matrix_result_with_dimensions(input_dims, values);
            }

            let dimension =
                dimension.unwrap_or_else(|| default_reduction_dimension_from_dims(&input_dims));
            if input_dims.len() > 2 || dimension > 2 {
                if dimension > input_dims.len() {
                    return numeric_or_complex_matrix_result_with_dimensions(input_dims, values);
                }
                let (output_dims, output_values) = cumulative_numeric_or_complex_slices_nd(
                    &values,
                    &input_dims,
                    dimension,
                    missing_flag,
                    real_input,
                    step,
                    identity,
                );
                return numeric_or_complex_matrix_result_with_dimensions(
                    output_dims,
                    output_values,
                );
            }

            let operand = NumericOrComplexOperand {
                rows: matrix.rows,
                cols: matrix.cols,
                values,
            };
            if operand.rows == 1 && operand.cols == 1 {
                return Ok(numeric_or_complex_value(operand.values[0]));
            }

            if dimension > 2 {
                return numeric_or_complex_operand_to_value(&operand);
            }

            let mut elements = vec![ComplexParts::zero(); operand.values.len()];
            match dimension {
                1 => {
                    for col in 0..operand.cols {
                        let mut accumulator = identity;
                        let mut has_accumulator = false;
                        for row in 0..operand.rows {
                            let offset = row * operand.cols + col;
                            let value = operand.values[offset];
                            match missing_flag {
                                StatisticMissingFlag::IncludeNan => {
                                    accumulator = step(accumulator, value);
                                    if real_input {
                                        accumulator.imag = 0.0;
                                    }
                                    has_accumulator = true;
                                    elements[offset] = accumulator;
                                }
                                StatisticMissingFlag::OmitNan => {
                                    if value.is_nan() {
                                        elements[offset] = if has_accumulator {
                                            accumulator
                                        } else {
                                            ComplexParts {
                                                real: f64::NAN,
                                                imag: 0.0,
                                            }
                                        };
                                    } else {
                                        accumulator = if has_accumulator {
                                            step(accumulator, value)
                                        } else {
                                            value
                                        };
                                        if real_input {
                                            accumulator.imag = 0.0;
                                        }
                                        has_accumulator = true;
                                        elements[offset] = accumulator;
                                    }
                                }
                            }
                        }
                    }
                }
                2 => {
                    for row in 0..operand.rows {
                        let mut accumulator = identity;
                        let mut has_accumulator = false;
                        for col in 0..operand.cols {
                            let offset = row * operand.cols + col;
                            let value = operand.values[offset];
                            match missing_flag {
                                StatisticMissingFlag::IncludeNan => {
                                    accumulator = step(accumulator, value);
                                    if real_input {
                                        accumulator.imag = 0.0;
                                    }
                                    has_accumulator = true;
                                    elements[offset] = accumulator;
                                }
                                StatisticMissingFlag::OmitNan => {
                                    if value.is_nan() {
                                        elements[offset] = if has_accumulator {
                                            accumulator
                                        } else {
                                            ComplexParts {
                                                real: f64::NAN,
                                                imag: 0.0,
                                            }
                                        };
                                    } else {
                                        accumulator = if has_accumulator {
                                            step(accumulator, value)
                                        } else {
                                            value
                                        };
                                        if real_input {
                                            accumulator.imag = 0.0;
                                        }
                                        has_accumulator = true;
                                        elements[offset] = accumulator;
                                    }
                                }
                            }
                        }
                    }
                }
                _ => unreachable!("cumulative dimensions are normalized earlier"),
            }

            build_numeric_or_complex_matrix_result(operand.rows, operand.cols, elements)
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric or complex scalar or matrix input"
        ))),
    }
}

fn cumulative_integer_value(
    operand: &IntegerOperand,
    input_dims: &[usize],
    dimension: Option<usize>,
    _builtin_name: &str,
    step: impl Fn(i128, i128, IntegerClass) -> i128 + Copy,
    identity: i128,
) -> Result<Value, RuntimeError> {
    if operand.rows == 0 || operand.cols == 0 {
        return build_integer_result_with_dimensions(
            operand.class,
            input_dims.to_vec(),
            Vec::new(),
        );
    }
    let dimension = dimension.unwrap_or_else(|| default_reduction_dimension_from_dims(input_dims));
    if input_dims.len() > 2 || dimension > 2 {
        if dimension > input_dims.len() {
            return build_integer_result_with_dimensions(
                operand.class,
                input_dims.to_vec(),
                operand.values.clone(),
            );
        }
        let (output_dims, output_values) = cumulative_integer_slices_nd(
            &operand.values,
            input_dims,
            dimension,
            operand.class,
            step,
            identity,
        );
        return build_integer_result_with_dimensions(operand.class, output_dims, output_values);
    }

    if operand.rows == 1 && operand.cols == 1 {
        return Ok(saturating_integer_value(operand.class, operand.values[0]));
    }

    if dimension > 2 {
        return build_integer_result(
            operand.class,
            operand.rows,
            operand.cols,
            operand.values.clone(),
        );
    }

    let mut elements = vec![0i128; operand.values.len()];
    match dimension {
        1 => {
            for col in 0..operand.cols {
                let mut accumulator = identity;
                for row in 0..operand.rows {
                    let offset = row * operand.cols + col;
                    accumulator = step(accumulator, operand.values[offset], operand.class);
                    elements[offset] = accumulator;
                }
            }
        }
        2 => {
            for row in 0..operand.rows {
                let mut accumulator = identity;
                for col in 0..operand.cols {
                    let offset = row * operand.cols + col;
                    accumulator = step(accumulator, operand.values[offset], operand.class);
                    elements[offset] = accumulator;
                }
            }
        }
        _ => unreachable!("cumulative integer dimensions are normalized earlier"),
    }

    build_integer_result(operand.class, operand.rows, operand.cols, elements)
}

fn reduce_integer_value(
    operand: &IntegerOperand,
    input_dims: &[usize],
    selection: &StatisticSelection,
    _builtin_name: &str,
    reducer: impl Fn(&[i128], IntegerClass) -> i128 + Copy,
    empty_output: i128,
) -> Result<Value, RuntimeError> {
    match selection {
        StatisticSelection::Default => {
            reduce_integer_value_default(operand, input_dims, reducer, empty_output)
        }
        _ => match collapsed_statistic_selection(
            selection,
            mean_default_dimension(&build_integer_result(
                operand.class,
                operand.rows,
                operand.cols,
                operand.values.clone(),
            )?)?,
        ) {
            CollapsedStatisticSelection::All => {
                reduce_integer_value_all(operand, input_dims, reducer, empty_output)
            }
            CollapsedStatisticSelection::Dim(dim) => reduce_integer_value_along_dimension(
                operand,
                input_dims,
                dim,
                reducer,
                empty_output,
            ),
        },
    }
}

fn reduce_integer_value_default(
    operand: &IntegerOperand,
    input_dims: &[usize],
    reducer: impl Fn(&[i128], IntegerClass) -> i128 + Copy,
    empty_output: i128,
) -> Result<Value, RuntimeError> {
    let dim = mean_default_dimension(&build_integer_result(
        operand.class,
        operand.rows,
        operand.cols,
        operand.values.clone(),
    )?)?;
    reduce_integer_value_along_dimension(operand, input_dims, dim, reducer, empty_output)
}

fn reduce_integer_value_all(
    operand: &IntegerOperand,
    input_dims: &[usize],
    reducer: impl Fn(&[i128], IntegerClass) -> i128 + Copy,
    empty_output: i128,
) -> Result<Value, RuntimeError> {
    if operand.values.is_empty() {
        return Ok(saturating_integer_value(operand.class, empty_output));
    }
    let value = reducer(&operand.values, operand.class);
    let output_dims = input_dims
        .iter()
        .enumerate()
        .map(|(index, _)| if index == 0 { 1 } else { 1 })
        .collect::<Vec<_>>();
    if output_dims.iter().product::<usize>() <= 1 {
        Ok(saturating_integer_value(operand.class, value))
    } else {
        build_integer_result_with_dimensions(operand.class, output_dims, vec![value])
    }
}

fn reduce_integer_value_along_dimension(
    operand: &IntegerOperand,
    input_dims: &[usize],
    dim: usize,
    reducer: impl Fn(&[i128], IntegerClass) -> i128 + Copy,
    empty_output: i128,
) -> Result<Value, RuntimeError> {
    let mut dims = canonical_size_vector(input_dims);
    while dims.len() < dim {
        dims.push(1);
    }
    if dims.iter().any(|&extent| extent == 0) {
        return build_integer_result_with_dimensions(operand.class, dims, Vec::new());
    }
    if dim > dims.len() {
        return build_integer_result_with_dimensions(operand.class, dims, operand.values.clone());
    }

    let axis = dim - 1;
    let axis_len = dims[axis];
    let mut output_dims = dims.clone();
    output_dims[axis] = 1;
    let slice_dims = {
        let mut slice = dims.clone();
        slice[axis] = 1;
        slice
    };
    let slice_count = slice_dims.iter().product::<usize>();
    let mut output_values = vec![empty_output; output_dims.iter().product::<usize>()];

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                operand.values[row_major_linear_index(&index, &dims)]
            })
            .collect::<Vec<_>>();
        index[axis] = 0;
        let destination = row_major_linear_index(&index, &output_dims);
        output_values[destination] = if values.is_empty() {
            empty_output
        } else {
            reducer(&values, operand.class)
        };
    }

    build_integer_result_with_dimensions(operand.class, output_dims, output_values)
}

fn cumulative_extreme_outputs(
    args: &[Value],
    output_arity: usize,
    builtin_name: &str,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<Vec<Value>, RuntimeError> {
    let (value, dimension, direction, missing_flag) =
        parse_cumulative_extreme_args(args, builtin_name)?;

    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports one or two outputs"
        )));
    }

    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        let dimension =
            dimension.unwrap_or_else(|| default_reduction_dimension_from_dims(&input_dims));
        if input_dims.len() > 2 || dimension > 2 {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            let logical_output = matrix_is_logical(matrix);
            if values.is_empty() {
                let empty = Value::Matrix(MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    input_dims.clone(),
                    Vec::new(),
                )?);
                let mut outputs = vec![if logical_output { empty.clone() } else { empty }];
                if output_arity == 2 {
                    outputs.push(Value::Matrix(MatrixValue::with_dimensions(
                        matrix.rows,
                        matrix.cols,
                        input_dims,
                        Vec::new(),
                    )?));
                }
                return Ok(outputs);
            }

            if dimension > input_dims.len() {
                let mut outputs = vec![extreme_matrix_value_with_dimensions(
                    input_dims.clone(),
                    values.clone(),
                    logical_output,
                )?];
                if output_arity == 2 {
                    outputs.push(numeric_matrix_result_with_dimensions(
                        input_dims,
                        vec![1.0; values.len()],
                    )?);
                }
                return Ok(outputs);
            }

            let (output_dims, reduced_values, reduced_indices) = cumulative_extreme_slices_nd(
                &values,
                &input_dims,
                dimension,
                direction,
                missing_flag,
                prefer_candidate,
            );
            let mut outputs = vec![extreme_matrix_value_with_dimensions(
                output_dims.clone(),
                reduced_values,
                logical_output,
            )?];
            if output_arity == 2 {
                outputs.push(numeric_matrix_result_with_dimensions(
                    output_dims,
                    reduced_indices,
                )?);
            }
            return Ok(outputs);
        }
    }

    let operand = numeric_operand(value, builtin_name)?;
    let dimension = cumulative_default_dimension(&operand, dimension);
    let (values, indices) = cumulative_extreme_value(
        &operand,
        dimension,
        direction,
        missing_flag,
        prefer_candidate,
    );
    let mut outputs = vec![numeric_operand_to_value(&values)?];
    if output_arity == 2 {
        outputs.push(numeric_operand_to_value(&indices)?);
    }
    Ok(outputs)
}

fn cumulative_extreme_outputs_complex(
    args: &[Value],
    output_arity: usize,
    builtin_name: &str,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<Vec<Value>, RuntimeError> {
    let (value, dimension, direction, missing_flag) =
        parse_cumulative_extreme_args(args, builtin_name)?;

    if output_arity > 2 {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports one or two outputs"
        )));
    }

    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        let dimension =
            dimension.unwrap_or_else(|| default_reduction_dimension_from_dims(&input_dims));
        if input_dims.len() > 2 || dimension > 2 {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, builtin_name))
                .collect::<Result<Vec<_>, _>>()?;
            if values.is_empty() {
                let empty = Value::Matrix(MatrixValue::with_dimensions(
                    matrix.rows,
                    matrix.cols,
                    input_dims.clone(),
                    Vec::new(),
                )?);
                let mut outputs = vec![empty.clone()];
                if output_arity == 2 {
                    outputs.push(Value::Matrix(MatrixValue::with_dimensions(
                        matrix.rows,
                        matrix.cols,
                        input_dims,
                        Vec::new(),
                    )?));
                }
                return Ok(outputs);
            }

            if dimension > input_dims.len() {
                let mut outputs = vec![extreme_matrix_value_with_dimensions_complex(
                    input_dims.clone(),
                    values.clone(),
                )?];
                if output_arity == 2 {
                    outputs.push(numeric_matrix_result_with_dimensions(
                        input_dims,
                        vec![1.0; values.len()],
                    )?);
                }
                return Ok(outputs);
            }

            let (output_dims, reduced_values, reduced_indices) =
                cumulative_extreme_slices_nd_complex(
                    &values,
                    &input_dims,
                    dimension,
                    direction,
                    missing_flag,
                    prefer_candidate,
                );
            let mut outputs = vec![extreme_matrix_value_with_dimensions_complex(
                output_dims.clone(),
                reduced_values,
            )?];
            if output_arity == 2 {
                outputs.push(numeric_matrix_result_with_dimensions(
                    output_dims,
                    reduced_indices,
                )?);
            }
            return Ok(outputs);
        }
    }

    let operand = numeric_or_complex_operand(value, builtin_name)?;
    let dimension = cumulative_default_dimension_for_shape(operand.rows, operand.cols, dimension);
    let (values, indices) = cumulative_extreme_value_complex(
        &operand,
        dimension,
        direction,
        missing_flag,
        prefer_candidate,
    );
    let mut outputs = vec![numeric_or_complex_operand_to_value(&values)?];
    if output_arity == 2 {
        outputs.push(numeric_operand_to_value(&indices)?);
    }
    Ok(outputs)
}

fn cumulative_default_dimension(value: &NumericOperand, explicit: Option<usize>) -> usize {
    cumulative_default_dimension_for_shape(value.rows, value.cols, explicit)
}

fn cumulative_default_dimension_for_shape(
    rows: usize,
    cols: usize,
    explicit: Option<usize>,
) -> usize {
    explicit.unwrap_or_else(|| {
        if rows != 1 {
            1
        } else if cols != 1 {
            2
        } else {
            1
        }
    })
}

fn parse_cumulative_extreme_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<
    (
        &'a Value,
        Option<usize>,
        CumulativeDirection,
        ExtremeMissingFlag,
    ),
    RuntimeError,
> {
    let Some((value, options)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently expects at least one input argument"
        )));
    };

    let mut dimension = None;
    let mut direction = CumulativeDirection::Forward;
    let mut missing_flag = ExtremeMissingFlag::OmitNan;
    let mut seen_direction = false;
    let mut seen_missing_flag = false;

    for option in options {
        if !seen_missing_flag {
            if let Ok(flag) = parse_extreme_missing_flag(option, builtin_name) {
                missing_flag = flag;
                seen_missing_flag = true;
                continue;
            }
        }
        if !seen_direction {
            if let Ok(parsed_direction) = parse_cumulative_direction(option, builtin_name) {
                direction = parsed_direction;
                seen_direction = true;
                continue;
            }
        }
        if dimension.is_none() {
            dimension = Some(positive_dimension(option, builtin_name)?);
            continue;
        }
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)`, `{builtin_name}(x, dim)`, `{builtin_name}(x, direction)`, `{builtin_name}(x, nanflag)`, `{builtin_name}(x, dim, direction)`, `{builtin_name}(x, dim, nanflag)`, `{builtin_name}(x, direction, nanflag)`, and those forms with the trailing options permuted once each"
        )));
    }

    Ok((value, dimension, direction, missing_flag))
}

fn parse_cumulative_sumprod_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, Option<usize>, StatisticMissingFlag), RuntimeError> {
    match args {
        [value] => Ok((value, None, StatisticMissingFlag::IncludeNan)),
        [value, second] => {
            if let Ok(flag) = parse_statistic_missing_flag(second, builtin_name) {
                Ok((value, None, flag))
            } else {
                Ok((
                    value,
                    Some(positive_dimension(second, builtin_name)?),
                    StatisticMissingFlag::IncludeNan,
                ))
            }
        }
        [value, second, third] => {
            if let Ok(flag) = parse_statistic_missing_flag(third, builtin_name) {
                Ok((value, Some(positive_dimension(second, builtin_name)?), flag))
            } else if let Ok(flag) = parse_statistic_missing_flag(second, builtin_name) {
                Ok((value, Some(positive_dimension(third, builtin_name)?), flag))
            } else {
                Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports `{builtin_name}(A)`, `{builtin_name}(A, dim)`, `{builtin_name}(A, nanflag)`, and `{builtin_name}(A, dim, nanflag)`"
                )))
            }
        }
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(A)`, `{builtin_name}(A, dim)`, `{builtin_name}(A, nanflag)`, and `{builtin_name}(A, dim, nanflag)`"
        ))),
    }
}

fn cumulative_extreme_value(
    value: &NumericOperand,
    dimension: usize,
    direction: CumulativeDirection,
    missing_flag: ExtremeMissingFlag,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> (NumericOperand, NumericOperand) {
    if value.rows == 0 || value.cols == 0 {
        return (
            NumericOperand {
                rows: value.rows,
                cols: value.cols,
                values: Vec::new(),
            },
            NumericOperand {
                rows: value.rows,
                cols: value.cols,
                values: Vec::new(),
            },
        );
    }

    if dimension > 2 {
        return (
            value.clone(),
            NumericOperand {
                rows: value.rows,
                cols: value.cols,
                values: vec![1.0; value.values.len()],
            },
        );
    }

    let mut result_values = vec![0.0; value.values.len()];
    let mut result_indices = vec![0.0; value.values.len()];
    match dimension {
        1 => {
            for col in 0..value.cols {
                let mut best = f64::NAN;
                let mut best_index = 1usize;
                let mut has_best = false;
                let row_iter: Box<dyn Iterator<Item = usize>> = match direction {
                    CumulativeDirection::Forward => Box::new(0..value.rows),
                    CumulativeDirection::Reverse => Box::new((0..value.rows).rev()),
                };
                for row in row_iter {
                    let offset = row * value.cols + col;
                    let candidate = value.values[offset];
                    match missing_flag {
                        ExtremeMissingFlag::IncludeNan => {
                            if row == 0 || candidate.is_nan() {
                                best = candidate;
                                best_index = row + 1;
                                has_best = true;
                            } else if !best.is_nan() && prefer_candidate(candidate, best) {
                                best = candidate;
                                best_index = row + 1;
                            }
                        }
                        ExtremeMissingFlag::OmitNan => {
                            if !candidate.is_nan() {
                                if !has_best || prefer_candidate(candidate, best) {
                                    best = candidate;
                                    best_index = row + 1;
                                }
                                has_best = true;
                            }
                        }
                    }
                    if has_best {
                        result_values[offset] = best;
                        result_indices[offset] = best_index as f64;
                    } else {
                        result_values[offset] = f64::NAN;
                        result_indices[offset] = (row + 1) as f64;
                    }
                }
            }
        }
        2 => {
            for row in 0..value.rows {
                let mut best = f64::NAN;
                let mut best_index = 1usize;
                let mut has_best = false;
                let col_iter: Box<dyn Iterator<Item = usize>> = match direction {
                    CumulativeDirection::Forward => Box::new(0..value.cols),
                    CumulativeDirection::Reverse => Box::new((0..value.cols).rev()),
                };
                for col in col_iter {
                    let offset = row * value.cols + col;
                    let candidate = value.values[offset];
                    match missing_flag {
                        ExtremeMissingFlag::IncludeNan => {
                            if col == 0 || candidate.is_nan() {
                                best = candidate;
                                best_index = col + 1;
                                has_best = true;
                            } else if !best.is_nan() && prefer_candidate(candidate, best) {
                                best = candidate;
                                best_index = col + 1;
                            }
                        }
                        ExtremeMissingFlag::OmitNan => {
                            if !candidate.is_nan() {
                                if !has_best || prefer_candidate(candidate, best) {
                                    best = candidate;
                                    best_index = col + 1;
                                }
                                has_best = true;
                            }
                        }
                    }
                    if has_best {
                        result_values[offset] = best;
                        result_indices[offset] = best_index as f64;
                    } else {
                        result_values[offset] = f64::NAN;
                        result_indices[offset] = (col + 1) as f64;
                    }
                }
            }
        }
        _ => unreachable!("cumulative extreme dimensions are normalized"),
    }

    (
        NumericOperand {
            rows: value.rows,
            cols: value.cols,
            values: result_values,
        },
        NumericOperand {
            rows: value.rows,
            cols: value.cols,
            values: result_indices,
        },
    )
}

fn cumulative_extreme_value_complex(
    value: &NumericOrComplexOperand,
    dimension: usize,
    direction: CumulativeDirection,
    missing_flag: ExtremeMissingFlag,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> (NumericOrComplexOperand, NumericOperand) {
    if value.rows == 0 || value.cols == 0 {
        return (
            NumericOrComplexOperand {
                rows: value.rows,
                cols: value.cols,
                values: Vec::new(),
            },
            NumericOperand {
                rows: value.rows,
                cols: value.cols,
                values: Vec::new(),
            },
        );
    }

    if dimension > 2 {
        return (
            value.clone(),
            NumericOperand {
                rows: value.rows,
                cols: value.cols,
                values: vec![1.0; value.values.len()],
            },
        );
    }

    let mut result_values = vec![ComplexParts::nan(); value.values.len()];
    let mut result_indices = vec![0.0; value.values.len()];
    match dimension {
        1 => {
            for col in 0..value.cols {
                let mut best = ComplexParts::nan();
                let mut best_index = 1usize;
                let mut has_best = false;
                let row_iter: Box<dyn Iterator<Item = usize>> = match direction {
                    CumulativeDirection::Forward => Box::new(0..value.rows),
                    CumulativeDirection::Reverse => Box::new((0..value.rows).rev()),
                };
                for row in row_iter {
                    let offset = row * value.cols + col;
                    let candidate = value.values[offset];
                    match missing_flag {
                        ExtremeMissingFlag::IncludeNan => {
                            if row == 0 || candidate.is_nan() {
                                best = candidate;
                                best_index = row + 1;
                                has_best = true;
                            } else if !best.is_nan() && prefer_candidate(candidate, best) {
                                best = candidate;
                                best_index = row + 1;
                            }
                        }
                        ExtremeMissingFlag::OmitNan => {
                            if !candidate.is_nan() {
                                if !has_best || prefer_candidate(candidate, best) {
                                    best = candidate;
                                    best_index = row + 1;
                                }
                                has_best = true;
                            }
                        }
                    }
                    if has_best {
                        result_values[offset] = best;
                        result_indices[offset] = best_index as f64;
                    } else {
                        result_values[offset] = ComplexParts::nan();
                        result_indices[offset] = (row + 1) as f64;
                    }
                }
            }
        }
        2 => {
            for row in 0..value.rows {
                let mut best = ComplexParts::nan();
                let mut best_index = 1usize;
                let mut has_best = false;
                let col_iter: Box<dyn Iterator<Item = usize>> = match direction {
                    CumulativeDirection::Forward => Box::new(0..value.cols),
                    CumulativeDirection::Reverse => Box::new((0..value.cols).rev()),
                };
                for col in col_iter {
                    let offset = row * value.cols + col;
                    let candidate = value.values[offset];
                    match missing_flag {
                        ExtremeMissingFlag::IncludeNan => {
                            if col == 0 || candidate.is_nan() {
                                best = candidate;
                                best_index = col + 1;
                                has_best = true;
                            } else if !best.is_nan() && prefer_candidate(candidate, best) {
                                best = candidate;
                                best_index = col + 1;
                            }
                        }
                        ExtremeMissingFlag::OmitNan => {
                            if !candidate.is_nan() {
                                if !has_best || prefer_candidate(candidate, best) {
                                    best = candidate;
                                    best_index = col + 1;
                                }
                                has_best = true;
                            }
                        }
                    }
                    if has_best {
                        result_values[offset] = best;
                        result_indices[offset] = best_index as f64;
                    } else {
                        result_values[offset] = ComplexParts::nan();
                        result_indices[offset] = (col + 1) as f64;
                    }
                }
            }
        }
        _ => unreachable!("cumulative extreme dimensions are normalized"),
    }

    (
        NumericOrComplexOperand {
            rows: value.rows,
            cols: value.cols,
            values: result_values,
        },
        NumericOperand {
            rows: value.rows,
            cols: value.cols,
            values: result_indices,
        },
    )
}

fn parse_moving_numeric_window_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
    default_missing_flag: StatisticMissingFlag,
) -> Result<
    (
        &'a Value,
        MovingWindowDefinition,
        Option<usize>,
        StatisticMissingFlag,
        MovingEndpoints,
    ),
    RuntimeError,
> {
    let (args, endpoints, sample_points) = parse_trailing_moving_options(args, builtin_name)?;
    let (value, window, dimension, missing_flag) = match args {
        [value, window] => (value, window, None, default_missing_flag),
        [value, window, third] => {
            if let Ok(missing_flag) = parse_statistic_missing_flag(third, builtin_name) {
                (value, window, None, missing_flag)
            } else {
                (
                    value,
                    window,
                    Some(positive_dimension(third, builtin_name)?),
                    default_missing_flag,
                )
            }
        }
        [value, window, third, fourth] => {
            if let Ok(missing_flag) = parse_statistic_missing_flag(fourth, builtin_name) {
                (
                    value,
                    window,
                    Some(positive_dimension(third, builtin_name)?),
                    missing_flag,
                )
            } else if let Ok(missing_flag) = parse_statistic_missing_flag(third, builtin_name) {
                (
                    value,
                    window,
                    Some(positive_dimension(fourth, builtin_name)?),
                    missing_flag,
                )
            } else {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports `{builtin_name}(x, k)`, `{builtin_name}(x, [kb kf])`, the same forms with an explicit dimension, the same forms with a nanflag, the same forms with `dim, nanflag`, and any of those forms followed by `\"Endpoints\", mode` and/or `\"SamplePoints\", points`"
                )));
            }
        }
        _ => {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports `{builtin_name}(x, k)`, `{builtin_name}(x, [kb kf])`, the same forms with an explicit dimension, the same forms with a nanflag, the same forms with `dim, nanflag`, and any of those forms followed by `\"Endpoints\", mode` and/or `\"SamplePoints\", points`"
            )))
        }
    };
    let window = if let Some(points) = sample_points {
        parse_moving_sample_points_window(window, points, builtin_name)?
    } else {
        let (backward, forward) = parse_moving_window(window, builtin_name)?;
        MovingWindowDefinition::Count { backward, forward }
    };
    Ok((value, window, dimension, missing_flag, endpoints))
}

fn parse_moving_variance_window_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<
    (
        &'a Value,
        MovingWindowDefinition,
        VarianceNormalization,
        Option<usize>,
        StatisticMissingFlag,
        MovingEndpoints,
    ),
    RuntimeError,
> {
    let (args, endpoints, sample_points) = parse_trailing_moving_options(args, builtin_name)?;
    let (value, window, normalization, dimension, missing_flag) = match args {
        [value, window] => (
            value,
            window,
            VarianceNormalization::Sample,
            None,
            StatisticMissingFlag::IncludeNan,
        ),
        [value, window, third] => {
            if let Ok(missing_flag) = parse_statistic_missing_flag(third, builtin_name) {
                (
                    value,
                    window,
                    VarianceNormalization::Sample,
                    None,
                    missing_flag,
                )
            } else {
                (
                    value,
                    window,
                    if is_empty_matrix_placeholder(third) {
                        VarianceNormalization::Sample
                    } else {
                        parse_variance_normalization(third, builtin_name)?
                    },
                    None,
                    StatisticMissingFlag::IncludeNan,
                )
            }
        }
        [value, window, third, fourth] => {
            if let Ok(missing_flag) = parse_statistic_missing_flag(fourth, builtin_name) {
                (
                    value,
                    window,
                    if is_empty_matrix_placeholder(third) {
                        VarianceNormalization::Sample
                    } else {
                        parse_variance_normalization(third, builtin_name)?
                    },
                    None,
                    missing_flag,
                )
            } else if let Ok(missing_flag) = parse_statistic_missing_flag(third, builtin_name) {
                (
                    value,
                    window,
                    VarianceNormalization::Sample,
                    Some(positive_dimension(fourth, builtin_name)?),
                    missing_flag,
                )
            } else {
                (
                    value,
                    window,
                    if is_empty_matrix_placeholder(third) {
                        VarianceNormalization::Sample
                    } else {
                        parse_variance_normalization(third, builtin_name)?
                    },
                    Some(positive_dimension(fourth, builtin_name)?),
                    StatisticMissingFlag::IncludeNan,
                )
            }
        }
        [value, window, normalization, dimension, missing_flag] => (
            value,
            window,
            if is_empty_matrix_placeholder(normalization) {
                VarianceNormalization::Sample
            } else {
                parse_variance_normalization(normalization, builtin_name)?
            },
            Some(positive_dimension(dimension, builtin_name)?),
            parse_statistic_missing_flag(missing_flag, builtin_name)?,
        ),
        _ => {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports `{builtin_name}(x, k)`, `{builtin_name}(x, [kb kf])`, the same forms with a normalization flag `w`, the same forms with `w, dim`, the same forms with a nanflag, the same forms with `w, dim, nanflag`, and any of those forms followed by `\"Endpoints\", mode` and/or `\"SamplePoints\", points`"
            )))
        }
    };
    let window = if let Some(points) = sample_points {
        parse_moving_sample_points_window(window, points, builtin_name)?
    } else {
        let (backward, forward) = parse_moving_window(window, builtin_name)?;
        MovingWindowDefinition::Count { backward, forward }
    };
    Ok((
        value,
        window,
        normalization,
        dimension,
        missing_flag,
        endpoints,
    ))
}

fn parse_trailing_moving_options<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a [Value], MovingEndpoints, Option<&'a Value>), RuntimeError> {
    let mut rest = args;
    let mut endpoints = MovingEndpoints::Shrink;
    let mut sample_points = None;
    while rest.len() >= 2 {
        let name = &rest[rest.len() - 2];
        let value = &rest[rest.len() - 1];
        let is_name = matches!(name, Value::CharArray(_) | Value::String(_));
        if !is_name {
            break;
        }
        let key = text_value(name)?.to_ascii_lowercase();
        match key.as_str() {
            "endpoints" => {
                endpoints = parse_moving_endpoints(value, builtin_name)?;
                rest = &rest[..rest.len() - 2];
            }
            "samplepoints" => {
                sample_points = Some(value);
                rest = &rest[..rest.len() - 2];
            }
            _ => break,
        }
    }
    Ok((rest, endpoints, sample_points))
}

fn parse_moving_endpoints(
    value: &Value,
    builtin_name: &str,
) -> Result<MovingEndpoints, RuntimeError> {
    match value {
        Value::Scalar(number) => return Ok(MovingEndpoints::FillScalar(*number)),
        Value::Logical(flag) => {
            return Ok(MovingEndpoints::FillScalar(if *flag { 1.0 } else { 0.0 }))
        }
        _ => {}
    }

    match text_value(value)?.to_ascii_lowercase().as_str() {
        "shrink" => Ok(MovingEndpoints::Shrink),
        "discard" => Ok(MovingEndpoints::Discard),
        "fill" => Ok(MovingEndpoints::FillNan),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports only `\"Endpoints\", \"shrink\"`, `\"discard\"`, `\"fill\"`, or a numeric/logical scalar, not `{other}`"
        ))),
    }
}

fn parse_moving_window(value: &Value, builtin_name: &str) -> Result<(usize, usize), RuntimeError> {
    let matrix = coerce_matrix(value).map_err(|_| {
        RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a positive integer scalar window or a two-element [kb kf] vector"
        ))
    })?;

    if matrix.rows == 1 && matrix.cols == 1 {
        let length = positive_integer_scalar_with_label(
            matrix.get(0, 0),
            builtin_name,
            "a positive integer scalar window length",
        )?;
        return Ok((length / 2, (length - 1) / 2));
    }

    if matrix.rows != 1 && matrix.cols != 1 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a scalar window or a two-element [kb kf] vector"
        )));
    }

    let offsets = matrix
        .iter()
        .map(|element| {
            nonnegative_integer_scalar_with_label(
                element,
                builtin_name,
                "a two-element [kb kf] window vector of nonnegative integers",
            )
        })
        .collect::<Result<Vec<_>, _>>()?;
    if offsets.len() != 2 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a two-element [kb kf] window vector"
        )));
    }

    Ok((offsets[0], offsets[1]))
}

fn parse_moving_sample_points_window(
    window: &Value,
    sample_points: &Value,
    builtin_name: &str,
) -> Result<MovingWindowDefinition, RuntimeError> {
    let points = parse_sample_points_vector(sample_points, builtin_name)?;
    let matrix = coerce_matrix(window).map_err(|_| {
        RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a positive numeric scalar window or a two-element [kb kf] vector when using \"SamplePoints\""
        ))
    })?;
    if matrix.rows == 1 && matrix.cols == 1 {
        let width = positive_finite_scalar_with_label(
            matrix.get(0, 0),
            builtin_name,
            "a positive numeric scalar window length",
        )?;
        return Ok(MovingWindowDefinition::SamplePoints {
            backward: width / 2.0,
            forward: width / 2.0,
            upper_inclusive: false,
            points,
        });
    }
    if matrix.rows != 1 && matrix.cols != 1 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a scalar window or a two-element [kb kf] vector when using \"SamplePoints\""
        )));
    }
    let offsets = matrix
        .iter()
        .map(|element| {
            nonnegative_finite_scalar_with_label(
                element,
                builtin_name,
                "a two-element [kb kf] window vector of nonnegative numeric values",
            )
        })
        .collect::<Result<Vec<_>, _>>()?;
    if offsets.len() != 2 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a scalar window or a two-element [kb kf] vector when using \"SamplePoints\""
        )));
    }
    Ok(MovingWindowDefinition::SamplePoints {
        backward: offsets[0],
        forward: offsets[1],
        upper_inclusive: true,
        points,
    })
}

fn parse_sample_points_vector(value: &Value, builtin_name: &str) -> Result<Vec<f64>, RuntimeError> {
    let matrix = coerce_matrix(value).map_err(|_| {
        RuntimeError::TypeError(format!(
            "{builtin_name} currently expects \"SamplePoints\" to be a numeric vector"
        ))
    })?;
    if matrix.rows != 1 && matrix.cols != 1 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects \"SamplePoints\" to be a vector"
        )));
    }
    let points = matrix
        .iter()
        .map(|element| real_numeric_scalar(element, builtin_name))
        .collect::<Result<Vec<_>, _>>()?;
    if points
        .windows(2)
        .any(|pair| !pair[0].is_finite() || !pair[1].is_finite())
        || points.iter().any(|point| !point.is_finite())
    {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects \"SamplePoints\" to contain finite numeric values"
        )));
    }
    if points.windows(2).any(|pair| pair[0] >= pair[1]) {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects \"SamplePoints\" to be sorted with unique values"
        )));
    }
    Ok(points)
}

fn uniform_sample_points_step(points: &[f64]) -> Option<f64> {
    if points.len() < 2 {
        return Some(1.0);
    }
    let step = points[1] - points[0];
    let tolerance = step.abs().max(1.0) * 1e-9;
    points
        .windows(2)
        .all(|pair| ((pair[1] - pair[0]) - step).abs() <= tolerance)
        .then_some(step)
}

fn sample_points_window_counts(
    backward: f64,
    forward: f64,
    upper_inclusive: bool,
    step: f64,
) -> (usize, usize) {
    let step = step.abs();
    let tolerance = step.max(1.0) * 1e-9;
    let mut backward_count = 0usize;
    loop {
        let next = (backward_count + 1) as f64 * step;
        if next <= backward + tolerance {
            backward_count += 1;
        } else {
            break;
        }
    }
    let mut forward_count = 0usize;
    loop {
        let next = (forward_count + 1) as f64 * step;
        let include = if upper_inclusive {
            next <= forward + tolerance
        } else {
            next < forward - tolerance
        };
        if include {
            forward_count += 1;
        } else {
            break;
        }
    }
    (backward_count, forward_count)
}

fn positive_finite_scalar_with_label(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<f64, RuntimeError> {
    let scalar = real_numeric_scalar(value, builtin_name)?;
    if !scalar.is_finite() || scalar <= 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} requires {label}"
        )));
    }
    Ok(scalar)
}

fn nonnegative_finite_scalar_with_label(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<f64, RuntimeError> {
    let scalar = real_numeric_scalar(value, builtin_name)?;
    if !scalar.is_finite() || scalar < 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} requires {label}"
        )));
    }
    Ok(scalar)
}

fn moving_numeric_value(
    value: &Value,
    name: &str,
    backward: usize,
    forward: usize,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    empty_value: f64,
    reducer: impl Fn(&[f64]) -> f64 + Copy,
) -> Result<Value, RuntimeError> {
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let operand = numeric_operand(value, name)?;
    let dimension = moving_default_dimension_from_dims(&input_dims, dimension);
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(value.clone());
    }
    if input_dims.len() > 2 || dimension > 2 {
        return moving_numeric_value_nd(
            &operand,
            &input_dims,
            dimension,
            backward,
            forward,
            missing_flag,
            endpoints,
            empty_value,
            reducer,
        );
    }

    match endpoints {
        MovingEndpoints::Discard => {
            return moving_numeric_value_discard(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::FillNan | MovingEndpoints::FillScalar(_) => {
            return moving_numeric_value_fill(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                moving_fill_value_numeric(endpoints).expect("numeric fill endpoint"),
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::Shrink => {}
    }

    let mut result = vec![Value::Scalar(0.0); operand.rows * operand.cols];
    match dimension {
        1 => {
            for col in 0..operand.cols {
                let column = (0..operand.rows)
                    .map(|row| operand.values[row * operand.cols + col])
                    .collect::<Vec<_>>();
                for row in 0..operand.rows {
                    let start = row.saturating_sub(backward);
                    let end = usize::min(operand.rows - 1, row + forward);
                    result[row * operand.cols + col] = Value::Scalar(reduce_moving_numeric_window(
                        &column[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                    ));
                }
            }
        }
        2 => {
            for row in 0..operand.rows {
                let row_start = row * operand.cols;
                let row_values = &operand.values[row_start..row_start + operand.cols];
                for col in 0..operand.cols {
                    let start = col.saturating_sub(backward);
                    let end = usize::min(operand.cols - 1, col + forward);
                    result[row_start + col] = Value::Scalar(reduce_moving_numeric_window(
                        &row_values[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                    ));
                }
            }
        }
        _ => unreachable!(),
    }

    build_scalar_matrix_result(operand.rows, operand.cols, result)
}

fn moving_numeric_value_with_window(
    value: &Value,
    builtin_name: &str,
    window: &MovingWindowDefinition,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    empty_value: f64,
    reducer: impl Fn(&[f64]) -> f64 + Copy,
) -> Result<Value, RuntimeError> {
    match window {
        MovingWindowDefinition::Count { backward, forward } => moving_numeric_value(
            value,
            builtin_name,
            *backward,
            *forward,
            dimension,
            missing_flag,
            endpoints,
            empty_value,
            reducer,
        ),
        MovingWindowDefinition::SamplePoints {
            backward,
            forward,
            upper_inclusive,
            points,
        } => {
            if endpoints != MovingEndpoints::Shrink {
                if let Some(step) = uniform_sample_points_step(points) {
                    let (backward_count, forward_count) =
                        sample_points_window_counts(*backward, *forward, *upper_inclusive, step);
                    return moving_numeric_value(
                        value,
                        builtin_name,
                        backward_count,
                        forward_count,
                        dimension,
                        missing_flag,
                        endpoints,
                        empty_value,
                        reducer,
                    );
                }
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports only `\"Endpoints\", \"shrink\"` when using `\"SamplePoints\"`"
                )));
            }
            let operand = numeric_operand(value, builtin_name)?;
            let input_dims = canonical_size_vector(&value_dimensions(value));
            let dimension = moving_default_dimension_from_dims(&input_dims, dimension);
            let axis = dimension - 1;
            if axis >= input_dims.len() || points.len() != input_dims[axis] {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} requires `\"SamplePoints\"` to have {} element(s) along dimension {}",
                    input_dims.get(axis).copied().unwrap_or(1),
                    dimension
                )));
            }
            moving_numeric_value_sample_points_nd(
                &operand,
                &input_dims,
                dimension,
                points,
                *backward,
                *forward,
                *upper_inclusive,
                missing_flag,
                empty_value,
                reducer,
            )
        }
    }
}

fn moving_integer_extreme_value(
    operand: &IntegerOperand,
    input_dims: &[usize],
    dimension: Option<usize>,
    backward: usize,
    forward: usize,
    endpoints: MovingEndpoints,
    prefer_candidate: impl Fn(i128, i128) -> bool + Copy,
) -> Result<Value, RuntimeError> {
    let dimension = moving_default_dimension_from_dims(input_dims, dimension);
    if operand.rows == 0 || operand.cols == 0 {
        return build_integer_result_with_dimensions(
            operand.class,
            input_dims.to_vec(),
            Vec::new(),
        );
    }

    let fill_value = moving_fill_value_integer(endpoints);
    let (output_dims, values) = moving_nd_reduce(
        &operand.values,
        input_dims,
        dimension,
        backward,
        forward,
        StatisticMissingFlag::OmitNan,
        endpoints,
        fill_value,
        0i128,
        |window| {
            let mut best = window[0];
            for candidate in window.iter().copied().skip(1) {
                if prefer_candidate(candidate, best) {
                    best = candidate;
                }
            }
            best
        },
        |_value: i128| false,
        None::<fn() -> i128>,
    );
    build_integer_result_with_dimensions(operand.class, output_dims, values)
}

fn moving_integer_extreme_value_with_window(
    operand: &IntegerOperand,
    input_dims: &[usize],
    window: &MovingWindowDefinition,
    dimension: Option<usize>,
    endpoints: MovingEndpoints,
    prefer_candidate: impl Fn(i128, i128) -> bool + Copy,
    builtin_name: &str,
) -> Result<Value, RuntimeError> {
    match window {
        MovingWindowDefinition::Count { backward, forward } => {
            if !matches!(endpoints, MovingEndpoints::FillNan) {
                moving_integer_extreme_value(
                    operand,
                    input_dims,
                    dimension,
                    *backward,
                    *forward,
                    endpoints,
                    prefer_candidate,
                )
            } else {
                let result = moving_numeric_value(
                    &build_integer_result_with_dimensions(
                        operand.class,
                        input_dims.to_vec(),
                        operand.values.clone(),
                    )?,
                    builtin_name,
                    *backward,
                    *forward,
                    dimension,
                    StatisticMissingFlag::OmitNan,
                    endpoints,
                    f64::NAN,
                    |window| {
                        builtin_extreme_value_from_slice(window, |candidate, best| {
                            if prefer_candidate(candidate as i128, best as i128) {
                                true
                            } else {
                                false
                            }
                        })
                        .0
                    },
                )?;
                integerize_output_value(result, operand.class)
            }
        }
        MovingWindowDefinition::SamplePoints {
            backward,
            forward,
            upper_inclusive,
            points,
        } => {
            if endpoints != MovingEndpoints::Shrink {
                if let Some(step) = uniform_sample_points_step(points) {
                    let (backward_count, forward_count) =
                        sample_points_window_counts(*backward, *forward, *upper_inclusive, step);
                    return moving_integer_extreme_value(
                        operand,
                        input_dims,
                        dimension,
                        backward_count,
                        forward_count,
                        endpoints,
                        prefer_candidate,
                    );
                }
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports only `\"Endpoints\", \"shrink\"` when using `\"SamplePoints\"`"
                )));
            }
            let dimension = moving_default_dimension_from_dims(input_dims, dimension);
            let axis = dimension - 1;
            if axis >= input_dims.len() || points.len() != input_dims[axis] {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} requires `\"SamplePoints\"` to have {} element(s) along dimension {}",
                    input_dims.get(axis).copied().unwrap_or(1),
                    dimension
                )));
            }
            let (output_dims, values) = moving_nd_reduce_sample_points(
                &operand.values,
                input_dims,
                dimension,
                points,
                *backward,
                *forward,
                *upper_inclusive,
                StatisticMissingFlag::OmitNan,
                0i128,
                |window| {
                    let mut best = window[0];
                    for candidate in window.iter().copied().skip(1) {
                        if prefer_candidate(candidate, best) {
                            best = candidate;
                        }
                    }
                    best
                },
                |_value: i128| false,
                None::<fn() -> i128>,
            );
            build_integer_result_with_dimensions(operand.class, output_dims, values)
        }
    }
}

fn moving_numeric_or_complex_value(
    value: &Value,
    name: &str,
    backward: usize,
    forward: usize,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    empty_value: ComplexParts,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts + Copy,
) -> Result<Value, RuntimeError> {
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let operand = numeric_or_complex_operand(value, name)?;
    let dimension = moving_default_dimension_from_dims(&input_dims, dimension);
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(value.clone());
    }
    if input_dims.len() > 2 || dimension > 2 {
        return moving_numeric_or_complex_value_nd(
            &operand,
            &input_dims,
            dimension,
            backward,
            forward,
            missing_flag,
            endpoints,
            empty_value,
            reducer,
        );
    }

    match endpoints {
        MovingEndpoints::Discard => {
            return moving_numeric_or_complex_value_discard(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::FillNan | MovingEndpoints::FillScalar(_) => {
            return moving_numeric_or_complex_value_fill(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                moving_fill_value_complex(endpoints).expect("complex fill endpoint"),
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::Shrink => {}
    }

    let mut result = vec![ComplexParts::zero(); operand.rows * operand.cols];
    match dimension {
        1 => {
            for col in 0..operand.cols {
                let column = (0..operand.rows)
                    .map(|row| operand.values[row * operand.cols + col])
                    .collect::<Vec<_>>();
                for row in 0..operand.rows {
                    let start = row.saturating_sub(backward);
                    let end = usize::min(operand.rows - 1, row + forward);
                    result[row * operand.cols + col] = reduce_moving_complex_window(
                        &column[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                    );
                }
            }
        }
        2 => {
            for row in 0..operand.rows {
                let row_start = row * operand.cols;
                let row_values = &operand.values[row_start..row_start + operand.cols];
                for col in 0..operand.cols {
                    let start = col.saturating_sub(backward);
                    let end = usize::min(operand.cols - 1, col + forward);
                    result[row_start + col] = reduce_moving_complex_window(
                        &row_values[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                    );
                }
            }
        }
        _ => unreachable!(),
    }

    build_numeric_or_complex_matrix_result(operand.rows, operand.cols, result)
}

fn moving_numeric_or_complex_value_with_window(
    value: &Value,
    builtin_name: &str,
    window: &MovingWindowDefinition,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    empty_value: ComplexParts,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts + Copy,
) -> Result<Value, RuntimeError> {
    match window {
        MovingWindowDefinition::Count { backward, forward } => moving_numeric_or_complex_value(
            value,
            builtin_name,
            *backward,
            *forward,
            dimension,
            missing_flag,
            endpoints,
            empty_value,
            reducer,
        ),
        MovingWindowDefinition::SamplePoints {
            backward,
            forward,
            upper_inclusive,
            points,
        } => {
            if endpoints != MovingEndpoints::Shrink {
                if let Some(step) = uniform_sample_points_step(points) {
                    let (backward_count, forward_count) =
                        sample_points_window_counts(*backward, *forward, *upper_inclusive, step);
                    return moving_numeric_or_complex_value(
                        value,
                        builtin_name,
                        backward_count,
                        forward_count,
                        dimension,
                        missing_flag,
                        endpoints,
                        empty_value,
                        reducer,
                    );
                }
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports only `\"Endpoints\", \"shrink\"` when using `\"SamplePoints\"`"
                )));
            }
            let operand = numeric_or_complex_operand(value, builtin_name)?;
            let input_dims = canonical_size_vector(&value_dimensions(value));
            let dimension = moving_default_dimension_from_dims(&input_dims, dimension);
            let axis = dimension - 1;
            if axis >= input_dims.len() || points.len() != input_dims[axis] {
                return Err(RuntimeError::ShapeError(format!(
                    "{builtin_name} requires `\"SamplePoints\"` to have {} element(s) along dimension {}",
                    input_dims.get(axis).copied().unwrap_or(1),
                    dimension
                )));
            }
            moving_numeric_or_complex_value_sample_points_nd(
                &operand,
                &input_dims,
                dimension,
                points,
                *backward,
                *forward,
                *upper_inclusive,
                missing_flag,
                empty_value,
                reducer,
            )
        }
    }
}

fn moving_numeric_from_complex_value(
    value: &Value,
    name: &str,
    backward: usize,
    forward: usize,
    dimension: Option<usize>,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    empty_value: f64,
    reducer: impl Fn(&[ComplexParts]) -> f64 + Copy,
) -> Result<Value, RuntimeError> {
    let input_dims = canonical_size_vector(&value_dimensions(value));
    let operand = numeric_or_complex_operand(value, name)?;
    let dimension = moving_default_dimension_from_dims(&input_dims, dimension);
    if operand.rows == 0 || operand.cols == 0 {
        return numeric_matrix_result_with_dimensions(input_dims, Vec::new());
    }
    if input_dims.len() > 2 || dimension > 2 {
        return moving_complex_to_numeric_value_nd(
            &operand,
            &input_dims,
            dimension,
            backward,
            forward,
            missing_flag,
            endpoints,
            empty_value,
            reducer,
        );
    }

    match endpoints {
        MovingEndpoints::Discard => {
            return moving_numeric_from_complex_value_discard(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::FillNan | MovingEndpoints::FillScalar(_) => {
            return moving_numeric_from_complex_value_fill(
                &operand,
                dimension,
                backward,
                forward,
                missing_flag,
                moving_fill_value_complex(endpoints).expect("complex fill endpoint"),
                empty_value,
                reducer,
            );
        }
        MovingEndpoints::Shrink => {}
    }

    let mut result = vec![Value::Scalar(0.0); operand.rows * operand.cols];
    match dimension {
        1 => {
            for col in 0..operand.cols {
                let column = (0..operand.rows)
                    .map(|row| operand.values[row * operand.cols + col])
                    .collect::<Vec<_>>();
                for row in 0..operand.rows {
                    let start = row.saturating_sub(backward);
                    let end = usize::min(operand.rows - 1, row + forward);
                    result[row * operand.cols + col] = Value::Scalar(reduce_moving_window_generic(
                        &column[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                        |value: ComplexParts| value.is_nan(),
                        Some(|| f64::NAN),
                    ));
                }
            }
        }
        2 => {
            for row in 0..operand.rows {
                let row_start = row * operand.cols;
                let row_values = &operand.values[row_start..row_start + operand.cols];
                for col in 0..operand.cols {
                    let start = col.saturating_sub(backward);
                    let end = usize::min(operand.cols - 1, col + forward);
                    result[row_start + col] = Value::Scalar(reduce_moving_window_generic(
                        &row_values[start..=end],
                        missing_flag,
                        empty_value,
                        reducer,
                        |value: ComplexParts| value.is_nan(),
                        Some(|| f64::NAN),
                    ));
                }
            }
        }
        _ => unreachable!(),
    }

    build_scalar_matrix_result(operand.rows, operand.cols, result)
}

