fn moving_nd_reduce<T: Copy, U: Copy>(
    elements: &[T],
    input_dims: &[usize],
    dimension: usize,
    backward: usize,
    forward: usize,
    missing_flag: StatisticMissingFlag,
    endpoints: MovingEndpoints,
    fill_value: Option<T>,
    empty_output: U,
    reducer: impl Fn(&[T]) -> U + Copy,
    is_nan: impl Fn(T) -> bool + Copy,
    include_nan_output: Option<impl Fn() -> U + Copy>,
) -> (Vec<usize>, Vec<U>) {
    let mut normalized_input_dims = input_dims.to_vec();
    while normalized_input_dims.len() < dimension {
        normalized_input_dims.push(1);
    }
    let axis = dimension - 1;
    let extent = normalized_input_dims[axis];
    let mut output_dims = normalized_input_dims.clone();
    if endpoints == MovingEndpoints::Discard {
        output_dims[axis] = extent.saturating_sub(backward + forward);
    }
    let output_len = output_dims.iter().product::<usize>();
    if output_len == 0 {
        return (output_dims, Vec::new());
    }

    let mut values = Vec::with_capacity(output_len);
    for linear in 0..output_len {
        let mut output_index = row_major_multi_index(linear, &output_dims);
        let center = if endpoints == MovingEndpoints::Discard {
            output_index[axis] + backward
        } else {
            output_index[axis]
        };
        let mut window = Vec::with_capacity(backward + forward + 1);
        for offset in 0..=(backward + forward) {
            let position = center as isize + offset as isize - backward as isize;
            if position < 0 || position >= extent as isize {
                if let Some(fill_value) = fill_value {
                    window.push(fill_value);
                }
                continue;
            }
            output_index[axis] = position as usize;
            window.push(elements[row_major_linear_index(&output_index, &normalized_input_dims)]);
        }
        values.push(reduce_moving_window_generic(
            &window,
            missing_flag,
            empty_output,
            reducer,
            is_nan,
            include_nan_output,
        ));
    }
    (output_dims, values)
}

fn moving_nd_reduce_sample_points<T: Copy, U: Copy>(
    elements: &[T],
    input_dims: &[usize],
    dimension: usize,
    points: &[f64],
    backward: f64,
    forward: f64,
    upper_inclusive: bool,
    missing_flag: StatisticMissingFlag,
    empty_output: U,
    reducer: impl Fn(&[T]) -> U + Copy,
    is_nan: impl Fn(T) -> bool + Copy,
    include_nan_output: Option<impl Fn() -> U + Copy>,
) -> (Vec<usize>, Vec<U>) {
    let mut normalized_input_dims = input_dims.to_vec();
    while normalized_input_dims.len() < dimension {
        normalized_input_dims.push(1);
    }
    let axis = dimension - 1;
    let extent = normalized_input_dims[axis];
    let output_dims = normalized_input_dims.clone();
    let output_len = output_dims.iter().product::<usize>();
    if output_len == 0 {
        return (output_dims, Vec::new());
    }

    let mut values = Vec::with_capacity(output_len);
    for linear in 0..output_len {
        let mut output_index = row_major_multi_index(linear, &output_dims);
        let center = output_index[axis];
        let lower = points[center] - backward;
        let upper = points[center] + forward;
        let mut window = Vec::new();
        for position in 0..extent {
            let point = points[position];
            let include = point >= lower
                && if upper_inclusive {
                    point <= upper
                } else {
                    point < upper
                };
            if !include {
                continue;
            }
            output_index[axis] = position;
            window.push(elements[row_major_linear_index(&output_index, &normalized_input_dims)]);
        }
        values.push(reduce_moving_window_generic(
            &window,
            missing_flag,
            empty_output,
            reducer,
            is_nan,
            include_nan_output,
        ));
    }
    (output_dims, values)
}

fn reduce_moving_numeric_window(
    values: &[f64],
    missing_flag: StatisticMissingFlag,
    empty_output: f64,
    reducer: impl Fn(&[f64]) -> f64,
) -> f64 {
    reduce_moving_window_generic(
        values,
        missing_flag,
        empty_output,
        reducer,
        |value| value.is_nan(),
        Some(|| f64::NAN),
    )
}

fn reduce_moving_complex_window(
    values: &[ComplexParts],
    missing_flag: StatisticMissingFlag,
    empty_output: ComplexParts,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts,
) -> ComplexParts {
    reduce_moving_window_generic(
        values,
        missing_flag,
        empty_output,
        reducer,
        |value| value.is_nan(),
        None::<fn() -> ComplexParts>,
    )
}

fn reduce_moving_window_generic<T: Copy, U: Copy>(
    values: &[T],
    missing_flag: StatisticMissingFlag,
    empty_output: U,
    reducer: impl Fn(&[T]) -> U,
    is_nan: impl Fn(T) -> bool,
    include_nan_output: Option<impl Fn() -> U>,
) -> U {
    match missing_flag {
        StatisticMissingFlag::IncludeNan => {
            if values.iter().copied().any(is_nan) {
                include_nan_output
                    .map(|output| output())
                    .unwrap_or_else(|| reducer(values))
            } else {
                reducer(values)
            }
        }
        StatisticMissingFlag::OmitNan => {
            let filtered = values
                .iter()
                .copied()
                .filter(|value| !is_nan(*value))
                .collect::<Vec<_>>();
            if filtered.is_empty() {
                empty_output
            } else {
                reducer(&filtered)
            }
        }
    }
}

fn moving_fill_value_numeric(endpoints: MovingEndpoints) -> Option<f64> {
    match endpoints {
        MovingEndpoints::FillNan => Some(f64::NAN),
        MovingEndpoints::FillScalar(value) => Some(value),
        _ => None,
    }
}

fn moving_fill_value_integer(endpoints: MovingEndpoints) -> Option<i128> {
    match endpoints {
        MovingEndpoints::FillScalar(value) => Some(value.round() as i128),
        _ => None,
    }
}

fn moving_fill_value_complex(endpoints: MovingEndpoints) -> Option<ComplexParts> {
    moving_fill_value_numeric(endpoints).map(|real| ComplexParts { real, imag: 0.0 })
}

fn moving_default_dimension_from_dims(dims: &[usize], explicit: Option<usize>) -> usize {
    explicit.unwrap_or_else(|| {
        dims.iter()
            .position(|&extent| extent != 1)
            .map(|index| index + 1)
            .unwrap_or(1)
    })
}

fn builtin_extreme_value_from_slice(
    values: &[f64],
    prefer_candidate: impl Fn(f64, f64) -> bool,
) -> (f64, usize) {
    let mut best = values[0];
    let mut best_index = 1usize;
    for (offset, candidate) in values.iter().copied().enumerate().skip(1) {
        if prefer_candidate(candidate, best) {
            best = candidate;
            best_index = offset + 1;
        }
    }
    (best, best_index)
}

fn builtin_extreme_value_from_complex_slice(
    values: &[ComplexParts],
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool,
) -> (ComplexParts, usize) {
    let mut best = values[0];
    let mut best_index = 1usize;
    for (offset, candidate) in values.iter().copied().enumerate().skip(1) {
        if prefer_candidate(candidate, best) {
            best = candidate;
            best_index = offset + 1;
        }
    }
    (best, best_index)
}

fn column_major_linear_index_one_based(index: &[usize], dims: &[usize]) -> usize {
    let mut stride = 1usize;
    let mut linear = 1usize;
    for (axis, &value) in index.iter().enumerate() {
        linear += value * stride;
        stride *= dims.get(axis).copied().unwrap_or(1).max(1);
    }
    linear
}

fn extreme_scalar_value(best: f64, logical_output: bool) -> Value {
    if logical_output {
        Value::Logical(best != 0.0)
    } else {
        Value::Scalar(best)
    }
}

fn extreme_matrix_value(
    rows: usize,
    cols: usize,
    values: Vec<f64>,
    logical_output: bool,
) -> Result<Value, RuntimeError> {
    let elements = if logical_output {
        values
            .into_iter()
            .map(|value| Value::Logical(value != 0.0))
            .collect::<Vec<_>>()
    } else {
        values.into_iter().map(Value::Scalar).collect::<Vec<_>>()
    };
    build_scalar_matrix_result(rows, cols, elements)
}

fn extreme_matrix_value_with_dimensions(
    dims: Vec<usize>,
    values: Vec<f64>,
    logical_output: bool,
) -> Result<Value, RuntimeError> {
    let elements = if logical_output {
        values
            .into_iter()
            .map(|value| Value::Logical(value != 0.0))
            .collect::<Vec<_>>()
    } else {
        values.into_iter().map(Value::Scalar).collect::<Vec<_>>()
    };
    build_scalar_matrix_result_with_dimensions(dims, elements)
}

fn extreme_matrix_value_complex(
    rows: usize,
    cols: usize,
    values: Vec<ComplexParts>,
) -> Result<Value, RuntimeError> {
    build_numeric_or_complex_matrix_result(rows, cols, values)
}

fn extreme_matrix_value_with_dimensions_complex(
    dims: Vec<usize>,
    values: Vec<ComplexParts>,
) -> Result<Value, RuntimeError> {
    build_numeric_or_complex_matrix_result_with_dimensions(dims, values)
}

fn extreme_value_all(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<Value, RuntimeError> {
    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let (best, _) = builtin_extreme_value_from_slice(&operand.values, prefer_candidate);
    let logical_output = matches!(value, Value::Logical(_))
        || matches!(value, Value::Matrix(matrix) if matrix_is_logical(matrix));
    Ok(extreme_scalar_value(best, logical_output))
}

fn extreme_value_all_complex(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<Value, RuntimeError> {
    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let (best, _) = builtin_extreme_value_from_complex_slice(&operand.values, prefer_candidate);
    Ok(numeric_or_complex_value(best))
}

fn extreme_linear_index_all(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<Value, RuntimeError> {
    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let (_, row_major_index) = builtin_extreme_value_from_slice(&operand.values, prefer_candidate);
    let row = (row_major_index - 1) / operand.cols;
    let col = (row_major_index - 1) % operand.cols;
    Ok(Value::Scalar(
        column_major_linear_index_one_based(&[row, col], &[operand.rows, operand.cols]) as f64,
    ))
}

fn extreme_linear_index_all_complex(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<Value, RuntimeError> {
    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let (_, row_major_index) =
        builtin_extreme_value_from_complex_slice(&operand.values, prefer_candidate);
    let row = (row_major_index - 1) / operand.cols;
    let col = (row_major_index - 1) % operand.cols;
    Ok(Value::Scalar(
        column_major_linear_index_one_based(&[row, col], &[operand.rows, operand.cols]) as f64,
    ))
}

fn extreme_value_and_index(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<(Value, Value), RuntimeError> {
    match value {
        Value::Scalar(number) => Ok((Value::Scalar(*number), Value::Scalar(1.0))),
        Value::Logical(flag) => Ok((Value::Logical(*flag), Value::Scalar(1.0))),
        Value::Matrix(matrix) => {
            if matrix.rows == 0 || matrix.cols == 0 {
                return Err(RuntimeError::Unsupported(format!(
                    "{name} does not yet support empty matrices"
                )));
            }
            if canonical_size_vector(matrix.dims()).len() > 2 {
                return extreme_value_and_index_along_dimension(
                    value,
                    name,
                    default_reduction_dimension_from_dims(matrix.dims()),
                    prefer_candidate,
                );
            }
            let logical_output = matrix_is_logical(matrix);

            if matrix.rows == 1 || matrix.cols == 1 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                let (best, index) = builtin_extreme_value_from_slice(&values, prefer_candidate);
                return Ok((
                    extreme_scalar_value(best, logical_output),
                    Value::Scalar(index as f64),
                ));
            }

            let mut best_values = Vec::with_capacity(matrix.cols);
            let mut index_values = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let values = (0..matrix.rows)
                    .map(|row| matrix.get(row, col).as_scalar())
                    .collect::<Result<Vec<_>, _>>()?;
                let (best, index) = builtin_extreme_value_from_slice(&values, prefer_candidate);
                best_values.push(extreme_scalar_value(best, logical_output));
                index_values.push(Value::Scalar(index as f64));
            }

            Ok((
                build_scalar_matrix_result(1, matrix.cols, best_values)?,
                Value::Matrix(MatrixValue::new(1, matrix.cols, index_values)?),
            ))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric or logical scalar/matrix input"
        ))),
    }
}

fn extreme_value_and_index_complex(
    value: &Value,
    name: &str,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<(Value, Value), RuntimeError> {
    if !matches!(value, Value::Matrix(_)) {
        return Ok((
            numeric_or_complex_value(numeric_or_complex_scalar(value, name)?),
            Value::Scalar(1.0),
        ));
    }

    match value {
        Value::Matrix(matrix) => {
            if matrix.rows == 0 || matrix.cols == 0 {
                return Err(RuntimeError::Unsupported(format!(
                    "{name} does not yet support empty matrices"
                )));
            }
            if canonical_size_vector(matrix.dims()).len() > 2 {
                return extreme_value_and_index_along_dimension_complex(
                    value,
                    name,
                    default_reduction_dimension_from_dims(matrix.dims()),
                    prefer_candidate,
                );
            }

            if matrix.rows == 1 || matrix.cols == 1 {
                let values = matrix
                    .iter()
                    .map(|element| numeric_or_complex_scalar(element, name))
                    .collect::<Result<Vec<_>, _>>()?;
                let (best, index) =
                    builtin_extreme_value_from_complex_slice(&values, prefer_candidate);
                return Ok((numeric_or_complex_value(best), Value::Scalar(index as f64)));
            }

            let mut best_values = Vec::with_capacity(matrix.cols);
            let mut index_values = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let values = (0..matrix.rows)
                    .map(|row| numeric_or_complex_scalar(matrix.get(row, col), name))
                    .collect::<Result<Vec<_>, _>>()?;
                let (best, index) =
                    builtin_extreme_value_from_complex_slice(&values, prefer_candidate);
                best_values.push(numeric_or_complex_value(best));
                index_values.push(Value::Scalar(index as f64));
            }

            Ok((
                build_scalar_matrix_result(1, matrix.cols, best_values)?,
                Value::Matrix(MatrixValue::new(1, matrix.cols, index_values)?),
            ))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric, logical, or complex scalar/matrix input"
        ))),
    }
}

fn extreme_value_and_index_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<(Value, Value), RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && (input_dims.len() > 2 || dim > 2) {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            let logical_output = matrix_is_logical(matrix);
            if dim > input_dims.len() {
                return Ok((
                    extreme_matrix_value_with_dimensions(
                        input_dims.clone(),
                        values.clone(),
                        logical_output,
                    )?,
                    numeric_matrix_result_with_dimensions(input_dims, vec![1.0; values.len()])?,
                ));
            }

            let (output_dims, reduced_values, reduced_indices) =
                extreme_slices_nd(&values, &input_dims, dim, prefer_candidate, false);
            return Ok((
                extreme_matrix_value_with_dimensions(
                    output_dims.clone(),
                    reduced_values,
                    logical_output,
                )?,
                numeric_matrix_result_with_dimensions(output_dims, reduced_indices)?,
            ));
        }
    }

    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let logical_output = matches!(value, Value::Logical(_))
        || matches!(value, Value::Matrix(matrix) if matrix_is_logical(matrix));

    if dim > 2 {
        return Ok((
            if logical_output {
                build_scalar_matrix_result(
                    operand.rows,
                    operand.cols,
                    operand
                        .values
                        .iter()
                        .copied()
                        .map(|value| Value::Logical(value != 0.0))
                        .collect(),
                )?
            } else {
                numeric_operand_to_value(&operand)?
            },
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: operand.cols,
                values: vec![1.0; operand.values.len()],
            })?,
        ));
    }

    match dim {
        1 => {
            let mut best_values = Vec::with_capacity(operand.cols);
            let mut index_values = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                let (best, index) = builtin_extreme_value_from_slice(&values, prefer_candidate);
                best_values.push(best);
                index_values.push(index as f64);
            }
            Ok((
                extreme_matrix_value(1, operand.cols, best_values, logical_output)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: 1,
                    cols: operand.cols,
                    values: index_values,
                })?,
            ))
        }
        2 => {
            let mut best_values = Vec::with_capacity(operand.rows);
            let mut index_values = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                let (best, index) = builtin_extreme_value_from_slice(
                    &operand.values[start..start + operand.cols],
                    prefer_candidate,
                );
                best_values.push(best);
                index_values.push(index as f64);
            }
            Ok((
                extreme_matrix_value(operand.rows, 1, best_values, logical_output)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: operand.rows,
                    cols: 1,
                    values: index_values,
                })?,
            ))
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn extreme_value_and_index_along_dimension_complex(
    value: &Value,
    name: &str,
    dim: usize,
    prefer_candidate: impl Fn(ComplexParts, ComplexParts) -> bool + Copy,
) -> Result<(Value, Value), RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && (input_dims.len() > 2 || dim > 2) {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, name))
                .collect::<Result<Vec<_>, _>>()?;
            if dim > input_dims.len() {
                return Ok((
                    extreme_matrix_value_with_dimensions_complex(
                        input_dims.clone(),
                        values.clone(),
                    )?,
                    numeric_matrix_result_with_dimensions(input_dims, vec![1.0; values.len()])?,
                ));
            }

            let (output_dims, reduced_values, reduced_indices) =
                extreme_slices_nd_complex(&values, &input_dims, dim, prefer_candidate, false);
            return Ok((
                extreme_matrix_value_with_dimensions_complex(output_dims.clone(), reduced_values)?,
                numeric_matrix_result_with_dimensions(output_dims, reduced_indices)?,
            ));
        }
    }

    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }

    if dim > 2 {
        return Ok((
            numeric_or_complex_operand_to_value(&operand)?,
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: operand.cols,
                values: vec![1.0; operand.values.len()],
            })?,
        ));
    }

    match dim {
        1 => {
            let mut best_values = Vec::with_capacity(operand.cols);
            let mut index_values = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                let (best, index) =
                    builtin_extreme_value_from_complex_slice(&values, prefer_candidate);
                best_values.push(best);
                index_values.push(index as f64);
            }
            Ok((
                extreme_matrix_value_complex(1, operand.cols, best_values)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: 1,
                    cols: operand.cols,
                    values: index_values,
                })?,
            ))
        }
        2 => {
            let mut best_values = Vec::with_capacity(operand.rows);
            let mut index_values = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                let (best, index) = builtin_extreme_value_from_complex_slice(
                    &operand.values[start..start + operand.cols],
                    prefer_candidate,
                );
                best_values.push(best);
                index_values.push(index as f64);
            }
            Ok((
                extreme_matrix_value_complex(operand.rows, 1, best_values)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: operand.rows,
                    cols: 1,
                    values: index_values,
                })?,
            ))
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn extreme_value_and_linear_index_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> Result<(Value, Value), RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && (input_dims.len() > 2 || dim > 2) {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            let logical_output = matrix_is_logical(matrix);
            if dim > input_dims.len() {
                let linear_indices = (0..values.len())
                    .map(|linear| {
                        let index = row_major_multi_index(linear, &input_dims);
                        column_major_linear_index_one_based(&index, &input_dims) as f64
                    })
                    .collect::<Vec<_>>();
                return Ok((
                    extreme_matrix_value_with_dimensions(
                        input_dims.clone(),
                        values,
                        logical_output,
                    )?,
                    numeric_matrix_result_with_dimensions(input_dims, linear_indices)?,
                ));
            }

            let (output_dims, reduced_values, reduced_indices) =
                extreme_slices_nd(&values, &input_dims, dim, prefer_candidate, true);
            return Ok((
                extreme_matrix_value_with_dimensions(
                    output_dims.clone(),
                    reduced_values,
                    logical_output,
                )?,
                numeric_matrix_result_with_dimensions(output_dims, reduced_indices)?,
            ));
        }
    }

    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Err(RuntimeError::Unsupported(format!(
            "{name} does not yet support empty matrices"
        )));
    }
    let dims = [operand.rows, operand.cols];
    let logical_output = matches!(value, Value::Logical(_))
        || matches!(value, Value::Matrix(matrix) if matrix_is_logical(matrix));

    if dim > 2 {
        let values = (0..operand.rows)
            .flat_map(|row| {
                (0..operand.cols)
                    .map(move |col| column_major_linear_index_one_based(&[row, col], &dims) as f64)
            })
            .collect::<Vec<_>>();
        return Ok((
            if logical_output {
                build_scalar_matrix_result(
                    operand.rows,
                    operand.cols,
                    operand
                        .values
                        .iter()
                        .copied()
                        .map(|value| Value::Logical(value != 0.0))
                        .collect(),
                )?
            } else {
                numeric_operand_to_value(&operand)?
            },
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: operand.cols,
                values,
            })?,
        ));
    }

    match dim {
        1 => {
            let mut best_values = Vec::with_capacity(operand.cols);
            let mut index_values = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                let (best, index) = builtin_extreme_value_from_slice(&values, prefer_candidate);
                best_values.push(best);
                index_values
                    .push(column_major_linear_index_one_based(&[index - 1, col], &dims) as f64);
            }
            Ok((
                extreme_matrix_value(1, operand.cols, best_values, logical_output)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: 1,
                    cols: operand.cols,
                    values: index_values,
                })?,
            ))
        }
        2 => {
            let mut best_values = Vec::with_capacity(operand.rows);
            let mut index_values = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                let (best, index) = builtin_extreme_value_from_slice(
                    &operand.values[start..start + operand.cols],
                    prefer_candidate,
                );
                best_values.push(best);
                index_values
                    .push(column_major_linear_index_one_based(&[row, index - 1], &dims) as f64);
            }
            Ok((
                extreme_matrix_value(operand.rows, 1, best_values, logical_output)?,
                numeric_operand_to_value(&NumericOperand {
                    rows: operand.rows,
                    cols: 1,
                    values: index_values,
                })?,
            ))
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

