fn reduce_numeric_value(
    value: &Value,
    name: &str,
    empty_value: Value,
    reducer: impl Fn(&[f64]) -> f64,
) -> Result<Value, RuntimeError> {
    reduce_numeric_value_with_scalar(value, name, empty_value, |scalar| scalar, reducer)
}

fn reduce_numeric_or_complex_value(
    value: &Value,
    name: &str,
    empty_value: Value,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts,
) -> Result<Value, RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && input_dims.len() > 2 {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, name))
                .collect::<Result<Vec<_>, _>>()?;
            let dimension = default_reduction_dimension_from_dims(&input_dims);
            let (output_dims, reduced_values) = reduce_numeric_or_complex_slices_nd_values(
                &values,
                &input_dims,
                dimension,
                reducer,
            );
            return numeric_or_complex_matrix_result_with_dimensions(output_dims, reduced_values);
        }
    }

    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return empty_default_reduction_result(operand.rows, operand.cols, empty_value);
    }

    if operand.rows == 1 && operand.cols == 1 {
        return Ok(numeric_or_complex_value(operand.values[0]));
    }

    if operand.rows == 1 || operand.cols == 1 {
        return Ok(numeric_or_complex_value(reducer(&operand.values)));
    }

    let mut cols = Vec::with_capacity(operand.cols);
    for col in 0..operand.cols {
        let mut values = Vec::with_capacity(operand.rows);
        for row in 0..operand.rows {
            values.push(operand.values[row * operand.cols + col]);
        }
        cols.push(reducer(&values));
    }

    build_numeric_or_complex_matrix_result(1, operand.cols, cols)
}

fn reduce_numeric_or_complex_value_all(
    value: &Value,
    name: &str,
    empty_value: Value,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts,
) -> Result<Value, RuntimeError> {
    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(empty_value);
    }
    Ok(numeric_or_complex_value(reducer(&operand.values)))
}

fn reduce_numeric_or_complex_value_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    empty_value: Value,
    reducer: impl Fn(&[ComplexParts]) -> ComplexParts,
) -> Result<Value, RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && (input_dims.len() > 2 || dim > 2) {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, name))
                .collect::<Result<Vec<_>, _>>()?;
            if dim > input_dims.len() {
                return numeric_or_complex_matrix_result_with_dimensions(input_dims, values);
            }
            let (output_dims, reduced_values) =
                reduce_numeric_or_complex_slices_nd_values(&values, &input_dims, dim, reducer);
            return numeric_or_complex_matrix_result_with_dimensions(output_dims, reduced_values);
        }
    }

    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return empty_reduction_result_along_dimension(
            operand.rows,
            operand.cols,
            dim,
            empty_value,
        );
    }

    if dim > 2 {
        return build_numeric_or_complex_matrix_result(operand.rows, operand.cols, operand.values);
    }

    match dim {
        1 => {
            let mut cols = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                cols.push(reducer(&values));
            }
            build_numeric_or_complex_matrix_result(1, operand.cols, cols)
        }
        2 => {
            let mut rows = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                rows.push(reducer(&operand.values[start..start + operand.cols]));
            }
            build_numeric_or_complex_matrix_result(operand.rows, 1, rows)
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn reduce_numeric_value_with_scalar(
    value: &Value,
    name: &str,
    empty_value: Value,
    scalar_reducer: impl Fn(f64) -> f64,
    reducer: impl Fn(&[f64]) -> f64,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(scalar_reducer(*number))),
        Value::Logical(flag) => Ok(Value::Scalar(scalar_reducer(if *flag { 1.0 } else { 0.0 }))),
        Value::Matrix(matrix) => {
            let input_dims = canonical_size_vector(matrix.dims());
            if matrix.rows != 0 && matrix.cols != 0 && input_dims.len() > 2 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                let dimension = default_reduction_dimension_from_dims(&input_dims);
                let (output_dims, reduced_values) =
                    reduce_numeric_slices_nd_values(&values, &input_dims, dimension, reducer);
                return numeric_matrix_result_with_dimensions(output_dims, reduced_values);
            }

            if matrix.rows == 0 || matrix.cols == 0 {
                return empty_default_reduction_result(matrix.rows, matrix.cols, empty_value);
            }

            if matrix.rows == 1 || matrix.cols == 1 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                return Ok(Value::Scalar(reducer(&values)));
            }

            let mut cols = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let mut values = Vec::with_capacity(matrix.rows);
                for row in 0..matrix.rows {
                    values.push(matrix.get(row, col).as_scalar()?);
                }
                cols.push(Value::Scalar(reducer(&values)));
            }
            Ok(Value::Matrix(MatrixValue::new(1, matrix.cols, cols)?))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric scalar or matrix input"
        ))),
    }
}

fn reduce_numeric_value_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    empty_value: Value,
    reducer: impl Fn(&[f64]) -> f64,
) -> Result<Value, RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if matrix.rows != 0 && matrix.cols != 0 && (input_dims.len() > 2 || dim > 2) {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            if dim > input_dims.len() {
                return numeric_matrix_result_with_dimensions(input_dims, values);
            }
            let (output_dims, reduced_values) =
                reduce_numeric_slices_nd_values(&values, &input_dims, dim, reducer);
            return numeric_matrix_result_with_dimensions(output_dims, reduced_values);
        }
    }

    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return empty_reduction_result_along_dimension(
            operand.rows,
            operand.cols,
            dim,
            empty_value,
        );
    }

    if dim > 2 {
        return numeric_operand_to_value(&operand);
    }

    match dim {
        1 => {
            let mut cols = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                cols.push(reducer(&values));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: 1,
                cols: operand.cols,
                values: cols,
            })
        }
        2 => {
            let mut rows = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                rows.push(reducer(&operand.values[start..start + operand.cols]));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: 1,
                values: rows,
            })
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn reduce_numeric_value_all(
    value: &Value,
    name: &str,
    empty_value: Value,
    reducer: impl Fn(&[f64]) -> f64,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(Value::Scalar(reducer(&[*number]))),
        Value::Logical(flag) => Ok(Value::Scalar(reducer(&[if *flag { 1.0 } else { 0.0 }]))),
        Value::Matrix(matrix) => {
            if matrix.rows == 0 || matrix.cols == 0 {
                return Ok(empty_value);
            }
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            Ok(Value::Scalar(reducer(&values)))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric scalar or matrix input"
        ))),
    }
}

fn mean_default_dimension(value: &Value) -> Result<usize, RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Complex(_) => Ok(1),
        Value::Matrix(matrix) => Ok(default_reduction_dimension_from_dims(matrix.dims())),
        _ => Ok(1),
    }
}

fn variance_default_dimension(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    match value {
        Value::Scalar(_) => Ok(1),
        Value::Matrix(matrix) => Ok(default_reduction_dimension_from_dims(matrix.dims())),
        _ => Ok(default_statistic_dimension(&numeric_operand(
            value,
            builtin_name,
        )?)),
    }
}

fn median_of_values(values: &[f64]) -> f64 {
    let mut sorted = values.to_vec();
    sorted.sort_by(|left, right| left.partial_cmp(right).unwrap_or(std::cmp::Ordering::Equal));
    let middle = sorted.len() / 2;
    if sorted.len() % 2 == 1 {
        sorted[middle]
    } else {
        (sorted[middle - 1] + sorted[middle]) * 0.5
    }
}

fn mad_of_values(values: &[f64]) -> f64 {
    let median = median_of_values(values);
    let deviations = values
        .iter()
        .map(|value| (value - median).abs())
        .collect::<Vec<_>>();
    median_of_values(&deviations)
}

fn mad_of_values_with_flag(values: &[f64], flag: MadFlag) -> f64 {
    let filtered = values
        .iter()
        .copied()
        .filter(|value| !value.is_nan())
        .collect::<Vec<_>>();
    if filtered.is_empty() {
        return f64::NAN;
    }
    match flag {
        MadFlag::Mean => {
            let center = filtered.iter().sum::<f64>() / filtered.len() as f64;
            filtered
                .iter()
                .map(|value| (value - center).abs())
                .sum::<f64>()
                / filtered.len() as f64
        }
        MadFlag::Median => mad_of_values(&filtered),
    }
}

fn mode_of_values(values: &[f64]) -> f64 {
    mode_summary_of_values(values).mode
}

fn mode_summary_of_values(values: &[f64]) -> ModeSummary {
    let mut sorted = values
        .iter()
        .copied()
        .filter(|value| !value.is_nan())
        .collect::<Vec<_>>();
    if sorted.is_empty() {
        return ModeSummary {
            mode: f64::NAN,
            frequency: f64::NAN,
            ties: Vec::new(),
        };
    }
    sorted.sort_by(|left, right| left.total_cmp(right));

    let mut best_value = sorted[0];
    let mut best_count = 1usize;
    let mut ties = vec![sorted[0]];
    let mut current_value = sorted[0];
    let mut current_count = 1usize;
    for value in sorted.into_iter().skip(1) {
        if (value - current_value).abs() <= f64::EPSILON {
            current_count += 1;
            continue;
        }
        if current_count > best_count {
            best_value = current_value;
            best_count = current_count;
            ties.clear();
            ties.push(current_value);
        } else if current_count == best_count {
            ties.push(current_value);
        }
        current_value = value;
        current_count = 1;
    }
    if current_count > best_count {
        best_value = current_value;
        best_count = current_count;
        ties.clear();
        ties.push(current_value);
    } else {
        if current_count == best_count {
            ties.push(current_value);
        }
    }
    ModeSummary {
        mode: best_value,
        frequency: best_count as f64,
        ties,
    }
}

fn mode_tie_cell_value(values: &[f64]) -> Result<Value, RuntimeError> {
    let elements = values
        .iter()
        .copied()
        .map(Value::Scalar)
        .collect::<Vec<_>>();
    Ok(Value::Matrix(MatrixValue::new(values.len(), 1, elements)?))
}

fn mode_preserve_input_type(value: Value, input: &Value) -> Result<Value, RuntimeError> {
    if let Some(class) = integer_class_from_reduction_value(input) {
        integerize_output_value(value, class)
    } else if value_is_logical_like(input) {
        logicalize_numeric_result(value)
    } else {
        Ok(value)
    }
}

fn mode_summaries_for_selection(
    input_values: &[f64],
    input_dims: &[usize],
    selection: &StatisticSelection,
    default_dim: usize,
) -> Result<(Vec<usize>, Vec<ModeSummary>), RuntimeError> {
    if input_values.is_empty() {
        return Ok((
            vec![1, 1],
            vec![ModeSummary {
                mode: f64::NAN,
                frequency: f64::NAN,
                ties: Vec::new(),
            }],
        ));
    }
    match selection {
        StatisticSelection::All => Ok((vec![1, 1], vec![mode_summary_of_values(input_values)])),
        StatisticSelection::VecDim(dims) => {
            let reduce_dims = normalized_vecdim_reduce_dims(dims);
            let rank = input_dims
                .len()
                .max(reduce_dims.iter().copied().max().unwrap_or(0));
            if reduce_dims == (1..=rank).collect::<Vec<_>>() {
                return Ok((vec![1, 1], vec![mode_summary_of_values(input_values)]));
            }
            let layout = nd_vecdim_reduction_layout(input_dims, &reduce_dims);
            let output_dims = nd_vecdim_output_dims(&layout, 1);
            let output_count = output_dims.iter().product::<usize>();
            let mut summaries = vec![
                ModeSummary {
                    mode: f64::NAN,
                    frequency: f64::NAN,
                    ties: Vec::new(),
                };
                output_count
            ];
            for sequence_index in 0..nd_vecdim_sequence_count(&layout) {
                let sample_positions = nd_vecdim_sample_positions(&layout, sequence_index);
                let sample = sample_positions
                    .iter()
                    .map(|position| input_values[*position])
                    .collect::<Vec<_>>();
                let output_position =
                    nd_vecdim_output_position(&layout, sequence_index, 0, &output_dims);
                summaries[output_position] = mode_summary_of_values(&sample);
            }
            Ok((output_dims, summaries))
        }
        _ => {
            let dim = match collapsed_statistic_selection(selection, default_dim) {
                CollapsedStatisticSelection::All => {
                    return Ok((vec![1, 1], vec![mode_summary_of_values(input_values)]))
                }
                CollapsedStatisticSelection::Dim(dim) => dim,
            };
            mode_summaries_along_dimension(input_values, input_dims, dim)
        }
    }
}

fn mode_summaries_along_dimension(
    input_values: &[f64],
    input_dims: &[usize],
    dim: usize,
) -> Result<(Vec<usize>, Vec<ModeSummary>), RuntimeError> {
    let mut normalized_dims = canonical_size_vector(input_dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    if input_values.is_empty() {
        let axis = dim.saturating_sub(1);
        if axis < normalized_dims.len() {
            normalized_dims[axis] = if normalized_dims[axis] == 0 { 0 } else { 1 };
        }
        return Ok((normalized_dims, Vec::new()));
    }
    if dim > input_dims.len() {
        return Ok((
            canonical_size_vector(input_dims),
            input_values
                .iter()
                .copied()
                .map(|value| ModeSummary {
                    mode: value,
                    frequency: 1.0,
                    ties: vec![value],
                })
                .collect(),
        ));
    }

    let axis = dim - 1;
    let axis_len = normalized_dims[axis];
    let mut output_dims = normalized_dims.clone();
    output_dims[axis] = if axis_len == 0 { 0 } else { 1 };
    if normalized_dims.iter().any(|&size| size == 0) {
        return Ok((output_dims, Vec::new()));
    }

    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(position, &size)| (position != axis).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let output_count = output_dims.iter().product::<usize>();
    let mut summaries = vec![
        ModeSummary {
            mode: f64::NAN,
            frequency: f64::NAN,
            ties: Vec::new(),
        };
        output_count
    ];
    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let sample = (0..axis_len)
            .map(|axis_value| {
                let full_index =
                    nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
                let linear = row_major_linear_index(&full_index, &normalized_dims);
                input_values[linear]
            })
            .collect::<Vec<_>>();
        let full_output_index = nd_reduction_full_index(&output_dims, axis, 0, &reduced_index);
        let linear = row_major_linear_index(&full_output_index, &output_dims);
        summaries[linear] = mode_summary_of_values(&sample);
    }
    Ok((output_dims, summaries))
}

fn sample_variance(values: &[f64]) -> f64 {
    variance_with_normalization(values, VarianceNormalization::Sample)
}

fn variance_with_normalization(values: &[f64], normalization: VarianceNormalization) -> f64 {
    if values.len() <= 1 {
        return 0.0;
    }

    let mean = values.iter().sum::<f64>() / values.len() as f64;
    let squared_sum = values
        .iter()
        .map(|value| {
            let centered = *value - mean;
            centered * centered
        })
        .sum::<f64>();
    let denominator = match normalization {
        VarianceNormalization::Sample => (values.len() - 1) as f64,
        VarianceNormalization::Population => values.len() as f64,
    };
    squared_sum / denominator
}

fn complex_variance_with_normalization(
    values: &[ComplexParts],
    normalization: VarianceNormalization,
) -> f64 {
    if values.len() <= 1 {
        return 0.0;
    }

    let mean = complex_parts_mean(values);
    let squared_sum = values
        .iter()
        .map(|value| {
            let centered = value.minus(mean);
            centered.real * centered.real + centered.imag * centered.imag
        })
        .sum::<f64>();
    let denominator = match normalization {
        VarianceNormalization::Sample => (values.len() - 1) as f64,
        VarianceNormalization::Population => values.len() as f64,
    };
    squared_sum / denominator
}

fn complex_variance_or_std_with_missing(
    values: &[ComplexParts],
    normalization: VarianceNormalization,
    missing_flag: StatisticMissingFlag,
    standard_deviation: bool,
) -> f64 {
    let filtered = match missing_flag {
        StatisticMissingFlag::IncludeNan => {
            if values.iter().any(|value| value.is_nan()) {
                return f64::NAN;
            }
            values.to_vec()
        }
        StatisticMissingFlag::OmitNan => values
            .iter()
            .copied()
            .filter(|value| !value.is_nan())
            .collect::<Vec<_>>(),
    };
    if filtered.is_empty() {
        return f64::NAN;
    }
    let variance = complex_variance_with_normalization(&filtered, normalization);
    if standard_deviation {
        variance.sqrt()
    } else {
        variance
    }
}

fn variance_or_std_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    normalization: VarianceNormalization,
    missing_flag: StatisticMissingFlag,
    standard_deviation: bool,
) -> Result<Value, RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if input_dims.len() > 2 || dim > 2 {
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            if dim > input_dims.len() {
                return numeric_matrix_result_with_dimensions(input_dims, vec![0.0; values.len()]);
            }

            let reducer = |sample: &[f64]| {
                let variance =
                    numeric_reduce_with_missing(sample, missing_flag, f64::NAN, |filtered| {
                        variance_with_normalization(filtered, normalization)
                    });
                if standard_deviation {
                    variance.sqrt()
                } else {
                    variance
                }
            };
            let (output_dims, reduced_values) =
                reduce_numeric_slices_nd_values(&values, &input_dims, dim, reducer);
            return numeric_matrix_result_with_dimensions(output_dims, reduced_values);
        }
    }

    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        if dim > 2 {
            return numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: operand.cols,
                values: vec![0.0; operand.values.len()],
            });
        }
        return empty_reduction_result_along_dimension(
            operand.rows,
            operand.cols,
            dim,
            Value::Scalar(f64::NAN),
        );
    }

    let reducer = |values: &[f64]| {
        let variance = numeric_reduce_with_missing(values, missing_flag, f64::NAN, |filtered| {
            variance_with_normalization(filtered, normalization)
        });
        if standard_deviation {
            variance.sqrt()
        } else {
            variance
        }
    };

    if dim > 2 {
        return numeric_operand_to_value(&NumericOperand {
            rows: operand.rows,
            cols: operand.cols,
            values: vec![0.0; operand.values.len()],
        });
    }

    match dim {
        1 => {
            let mut cols = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                cols.push(reducer(&values));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: 1,
                cols: operand.cols,
                values: cols,
            })
        }
        2 => {
            let mut rows = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                rows.push(reducer(&operand.values[start..start + operand.cols]));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: 1,
                values: rows,
            })
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn variance_or_std_along_dimension_complex(
    value: &Value,
    name: &str,
    dim: usize,
    normalization: VarianceNormalization,
    missing_flag: StatisticMissingFlag,
    standard_deviation: bool,
) -> Result<Value, RuntimeError> {
    if let Value::Matrix(matrix) = value {
        let input_dims = canonical_size_vector(matrix.dims());
        if input_dims.len() > 2 || dim > 2 {
            let values = matrix
                .iter()
                .map(|element| numeric_or_complex_scalar(element, name))
                .collect::<Result<Vec<_>, _>>()?;
            if dim > input_dims.len() {
                return numeric_matrix_result_with_dimensions(input_dims, vec![0.0; values.len()]);
            }

            let reducer = |sample: &[ComplexParts]| {
                complex_variance_or_std_with_missing(
                    sample,
                    normalization,
                    missing_flag,
                    standard_deviation,
                )
            };
            let (output_dims, reduced_values) =
                reduce_complex_slices_nd_to_numeric_values(&values, &input_dims, dim, reducer);
            return numeric_matrix_result_with_dimensions(output_dims, reduced_values);
        }
    }

    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        if dim > 2 {
            return numeric_matrix_result_with_dimensions(
                canonical_size_vector(&value_dimensions(value)),
                vec![0.0; operand.values.len()],
            );
        }
        return empty_reduction_result_along_dimension(
            operand.rows,
            operand.cols,
            dim,
            Value::Scalar(f64::NAN),
        );
    }

    let reducer = |values: &[ComplexParts]| {
        complex_variance_or_std_with_missing(
            values,
            normalization,
            missing_flag,
            standard_deviation,
        )
    };

    if dim > 2 {
        return numeric_matrix_result_with_dimensions(
            canonical_size_vector(&value_dimensions(value)),
            vec![0.0; operand.values.len()],
        );
    }

    match dim {
        1 => {
            let mut cols = Vec::with_capacity(operand.cols);
            for col in 0..operand.cols {
                let mut values = Vec::with_capacity(operand.rows);
                for row in 0..operand.rows {
                    values.push(operand.values[row * operand.cols + col]);
                }
                cols.push(reducer(&values));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: 1,
                cols: operand.cols,
                values: cols,
            })
        }
        2 => {
            let mut rows = Vec::with_capacity(operand.rows);
            for row in 0..operand.rows {
                let start = row * operand.cols;
                rows.push(reducer(&operand.values[start..start + operand.cols]));
            }
            numeric_operand_to_value(&NumericOperand {
                rows: operand.rows,
                cols: 1,
                values: rows,
            })
        }
        _ => unreachable!("dim > 2 handled above"),
    }
}

fn variance_or_std_all(
    value: &Value,
    name: &str,
    normalization: VarianceNormalization,
    missing_flag: StatisticMissingFlag,
    standard_deviation: bool,
) -> Result<Value, RuntimeError> {
    let operand = numeric_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(Value::Scalar(f64::NAN));
    }
    let variance =
        numeric_reduce_with_missing(&operand.values, missing_flag, f64::NAN, |filtered| {
            variance_with_normalization(filtered, normalization)
        });
    Ok(Value::Scalar(if standard_deviation {
        variance.sqrt()
    } else {
        variance
    }))
}

fn variance_or_std_all_complex(
    value: &Value,
    name: &str,
    normalization: VarianceNormalization,
    missing_flag: StatisticMissingFlag,
    standard_deviation: bool,
) -> Result<Value, RuntimeError> {
    let operand = numeric_or_complex_operand(value, name)?;
    if operand.rows == 0 || operand.cols == 0 {
        return Ok(Value::Scalar(f64::NAN));
    }
    Ok(Value::Scalar(complex_variance_or_std_with_missing(
        &operand.values,
        normalization,
        missing_flag,
        standard_deviation,
    )))
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CovarianceNanFlag {
    IncludeNan,
    OmitRows,
    PartialRows,
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CovarianceResultKind {
    Scalar,
    SquareMatrix(usize),
}

struct CovarianceInputs {
    dataset: NumericOperand,
    normalization: VarianceNormalization,
    nanflag: CovarianceNanFlag,
    result_kind: CovarianceResultKind,
}

struct ComplexCovarianceInputs {
    dataset: NumericOrComplexOperand,
    normalization: VarianceNormalization,
    nanflag: CovarianceNanFlag,
    result_kind: CovarianceResultKind,
}

fn parse_covariance_inputs(
    args: &[Value],
    builtin_name: &str,
) -> Result<CovarianceInputs, RuntimeError> {
    match args {
        [value] => Ok(CovarianceInputs {
            result_kind: covariance_result_kind_from_value(value, builtin_name)?,
            dataset: covariance_dataset_from_value(value, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [value, maybe_weight] if is_variance_normalization_value(maybe_weight) => Ok(CovarianceInputs {
            result_kind: covariance_result_kind_from_value(value, builtin_name)?,
            dataset: covariance_dataset_from_value(value, builtin_name)?,
            normalization: parse_variance_normalization(maybe_weight, builtin_name)?,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [value, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => Ok(CovarianceInputs {
            result_kind: covariance_result_kind_from_value(value, builtin_name)?,
            dataset: covariance_dataset_from_value(value, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
        }),
        [value, weight, nanflag]
            if parse_covariance_nanflag(nanflag, builtin_name).is_ok()
                && is_variance_normalization_value(weight) =>
        {
            Ok(CovarianceInputs {
                result_kind: covariance_result_kind_from_value(value, builtin_name)?,
                dataset: covariance_dataset_from_value(value, builtin_name)?,
                normalization: parse_variance_normalization(weight, builtin_name)?,
                nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
            })
        }
        [lhs, rhs] => Ok(CovarianceInputs {
            result_kind: CovarianceResultKind::SquareMatrix(2),
            dataset: covariance_pair_dataset(lhs, rhs, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [lhs, rhs, weight] if is_variance_normalization_value(weight) => Ok(CovarianceInputs {
            result_kind: CovarianceResultKind::SquareMatrix(2),
            dataset: covariance_pair_dataset(lhs, rhs, builtin_name)?,
            normalization: parse_variance_normalization(weight, builtin_name)?,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [lhs, rhs, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => Ok(CovarianceInputs {
            result_kind: CovarianceResultKind::SquareMatrix(2),
            dataset: covariance_pair_dataset(lhs, rhs, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
        }),
        [lhs, rhs, weight, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => Ok(CovarianceInputs {
            result_kind: CovarianceResultKind::SquareMatrix(2),
            dataset: covariance_pair_dataset(lhs, rhs, builtin_name)?,
            normalization: parse_variance_normalization(weight, builtin_name)?,
            nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
        }),
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)`, `{builtin_name}(x, w)`, `{builtin_name}(x, nanflag)`, `{builtin_name}(x, w, nanflag)`, `{builtin_name}(x, y)`, `{builtin_name}(x, y, w)`, `{builtin_name}(x, y, nanflag)`, or `{builtin_name}(x, y, w, nanflag)`"
        ))),
    }
}

fn parse_covariance_inputs_complex(
    args: &[Value],
    builtin_name: &str,
) -> Result<ComplexCovarianceInputs, RuntimeError> {
    match args {
        [value] => Ok(ComplexCovarianceInputs {
            result_kind: covariance_result_kind_from_complex_value(value, builtin_name)?,
            dataset: covariance_dataset_from_complex_value(value, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [value, maybe_weight] if is_variance_normalization_value(maybe_weight) => {
            Ok(ComplexCovarianceInputs {
                result_kind: covariance_result_kind_from_complex_value(value, builtin_name)?,
                dataset: covariance_dataset_from_complex_value(value, builtin_name)?,
                normalization: parse_variance_normalization(maybe_weight, builtin_name)?,
                nanflag: CovarianceNanFlag::IncludeNan,
            })
        }
        [value, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => {
            Ok(ComplexCovarianceInputs {
                result_kind: covariance_result_kind_from_complex_value(value, builtin_name)?,
                dataset: covariance_dataset_from_complex_value(value, builtin_name)?,
                normalization: VarianceNormalization::Sample,
                nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
            })
        }
        [value, weight, nanflag]
            if parse_covariance_nanflag(nanflag, builtin_name).is_ok()
                && is_variance_normalization_value(weight) =>
        {
            Ok(ComplexCovarianceInputs {
                result_kind: covariance_result_kind_from_complex_value(value, builtin_name)?,
                dataset: covariance_dataset_from_complex_value(value, builtin_name)?,
                normalization: parse_variance_normalization(weight, builtin_name)?,
                nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
            })
        }
        [lhs, rhs] => Ok(ComplexCovarianceInputs {
            result_kind: CovarianceResultKind::SquareMatrix(2),
            dataset: covariance_pair_dataset_complex(lhs, rhs, builtin_name)?,
            normalization: VarianceNormalization::Sample,
            nanflag: CovarianceNanFlag::IncludeNan,
        }),
        [lhs, rhs, weight] if is_variance_normalization_value(weight) => Ok(
            ComplexCovarianceInputs {
                result_kind: CovarianceResultKind::SquareMatrix(2),
                dataset: covariance_pair_dataset_complex(lhs, rhs, builtin_name)?,
                normalization: parse_variance_normalization(weight, builtin_name)?,
                nanflag: CovarianceNanFlag::IncludeNan,
            },
        ),
        [lhs, rhs, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => Ok(
            ComplexCovarianceInputs {
                result_kind: CovarianceResultKind::SquareMatrix(2),
                dataset: covariance_pair_dataset_complex(lhs, rhs, builtin_name)?,
                normalization: VarianceNormalization::Sample,
                nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
            },
        ),
        [lhs, rhs, weight, nanflag] if parse_covariance_nanflag(nanflag, builtin_name).is_ok() => {
            Ok(ComplexCovarianceInputs {
                result_kind: CovarianceResultKind::SquareMatrix(2),
                dataset: covariance_pair_dataset_complex(lhs, rhs, builtin_name)?,
                normalization: parse_variance_normalization(weight, builtin_name)?,
                nanflag: parse_covariance_nanflag(nanflag, builtin_name)?,
            })
        }
        _ => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(x)`, `{builtin_name}(x, w)`, `{builtin_name}(x, nanflag)`, `{builtin_name}(x, w, nanflag)`, `{builtin_name}(x, y)`, `{builtin_name}(x, y, w)`, `{builtin_name}(x, y, nanflag)`, or `{builtin_name}(x, y, w, nanflag)`"
        ))),
    }
}

fn parse_covariance_nanflag(
    value: &Value,
    builtin_name: &str,
) -> Result<CovarianceNanFlag, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "includemissing" | "includenan" => Ok(CovarianceNanFlag::IncludeNan),
        "omitrows" => Ok(CovarianceNanFlag::OmitRows),
        "partialrows" => Ok(CovarianceNanFlag::PartialRows),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} nanflag `{other}` is not implemented; expected includenan/includemissing, omitrows, or partialrows"
        ))),
    }
}

fn covariance_result_kind_from_value(
    value: &Value,
    builtin_name: &str,
) -> Result<CovarianceResultKind, RuntimeError> {
    let operand = numeric_operand(value, builtin_name)?;
    Ok(if operand.rows == 1 || operand.cols == 1 {
        CovarianceResultKind::Scalar
    } else {
        CovarianceResultKind::SquareMatrix(operand.cols)
    })
}

fn covariance_result_kind_from_complex_value(
    value: &Value,
    builtin_name: &str,
) -> Result<CovarianceResultKind, RuntimeError> {
    let operand = numeric_or_complex_operand(value, builtin_name)?;
    Ok(if operand.rows == 1 || operand.cols == 1 {
        CovarianceResultKind::Scalar
    } else {
        CovarianceResultKind::SquareMatrix(operand.cols)
    })
}

fn omit_nan_covariance_rows(dataset: &NumericOperand) -> NumericOperand {
    let mut values = Vec::new();
    for row in 0..dataset.rows {
        let start = row * dataset.cols;
        let row_values = &dataset.values[start..start + dataset.cols];
        if row_values.iter().all(|value| !value.is_nan()) {
            values.extend_from_slice(row_values);
        }
    }
    NumericOperand {
        rows: if dataset.cols == 0 {
            0
        } else {
            values.len() / dataset.cols
        },
        cols: dataset.cols,
        values,
    }
}

fn omit_nan_covariance_rows_complex(dataset: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = Vec::new();
    for row in 0..dataset.rows {
        let start = row * dataset.cols;
        let row_values = &dataset.values[start..start + dataset.cols];
        if row_values.iter().all(|value| !value.is_nan()) {
            values.extend_from_slice(row_values);
        }
    }
    NumericOrComplexOperand {
        rows: if dataset.cols == 0 {
            0
        } else {
            values.len() / dataset.cols
        },
        cols: dataset.cols,
        values,
    }
}

fn covariance_nan_result(kind: CovarianceResultKind) -> Result<Value, RuntimeError> {
    match kind {
        CovarianceResultKind::Scalar => Ok(Value::Scalar(f64::NAN)),
        CovarianceResultKind::SquareMatrix(size) => nan_matrix(size, size),
    }
}

#[derive(Debug, Clone, Copy, PartialEq, Eq)]
enum CorrcoefRowsFlag {
    All,
    Complete,
    Pairwise,
}

#[derive(Debug, Clone, Copy)]
struct CorrcoefOptions {
    rows_flag: CorrcoefRowsFlag,
    alpha: f64,
}

#[derive(Debug, Clone)]
struct CorrcoefInputs {
    dataset: NumericOperand,
    options: CorrcoefOptions,
}

#[derive(Debug, Clone)]
struct ComplexCorrcoefInputs {
    dataset: NumericOrComplexOperand,
    options: CorrcoefOptions,
}

#[derive(Debug, Clone)]
struct PartialcorrInputs {
    x: NumericOperand,
    y: Option<NumericOperand>,
    z: Option<NumericOperand>,
    options: CorrOptions,
}

fn parse_correlation_inputs(args: &[Value]) -> Result<CorrcoefInputs, RuntimeError> {
    let Some(first) = args.first() else {
        return Err(RuntimeError::Unsupported(
            "corrcoef currently expects at least one input argument".to_string(),
        ));
    };
    let (dataset, tail) = match args.get(1) {
        Some(second) if !matches!(second, Value::CharArray(_) | Value::String(_)) => (
            covariance_pair_dataset(first, second, "corrcoef")?,
            &args[2..],
        ),
        _ => (
            covariance_dataset_from_value(first, "corrcoef")?,
            &args[1..],
        ),
    };
    if tail.len() % 2 != 0 {
        return Err(RuntimeError::Unsupported(
            "corrcoef currently expects trailing options as name/value pairs".to_string(),
        ));
    }

    let mut options = CorrcoefOptions {
        rows_flag: CorrcoefRowsFlag::All,
        alpha: 0.05,
    };
    for pair in tail.chunks_exact(2) {
        let name = text_value(&pair[0])?;
        if name.eq_ignore_ascii_case("Rows") {
            options.rows_flag = parse_corrcoef_rows_flag(&pair[1])?;
            continue;
        }
        if name.eq_ignore_ascii_case("Alpha") {
            options.alpha = parse_corrcoef_alpha_value(&pair[1])?;
            continue;
        }
        return Err(RuntimeError::Unsupported(format!(
            "corrcoef name-value `{name}` is not implemented; expected \"Rows\" or \"Alpha\""
        )));
    }

    Ok(CorrcoefInputs { dataset, options })
}

