fn cumulative_numeric_or_complex_slices_nd(
    input_values: &[ComplexParts],
    input_dims: &[usize],
    dim: usize,
    missing_flag: StatisticMissingFlag,
    real_input: bool,
    step: impl Fn(ComplexParts, ComplexParts) -> ComplexParts + Copy,
    identity: ComplexParts,
) -> (Vec<usize>, Vec<ComplexParts>) {
    let normalized_dims = canonical_size_vector(input_dims);
    let axis = dim - 1;
    let axis_len = normalized_dims[axis];
    if normalized_dims.iter().any(|&size| size == 0) {
        return (normalized_dims, Vec::new());
    }

    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(position, &size)| (position != axis).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let mut output_values = vec![ComplexParts::zero(); input_values.len()];

    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let mut accumulator = identity;
        let mut has_accumulator = false;
        for axis_value in 0..axis_len {
            let full_index =
                nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            let value = input_values[linear];
            match missing_flag {
                StatisticMissingFlag::IncludeNan => {
                    accumulator = step(accumulator, value);
                    if real_input {
                        accumulator.imag = 0.0;
                    }
                    has_accumulator = true;
                    output_values[linear] = accumulator;
                }
                StatisticMissingFlag::OmitNan => {
                    if value.is_nan() {
                        output_values[linear] = if has_accumulator {
                            accumulator
                        } else {
                            ComplexParts {
                                real: f64::NAN,
                                imag: 0.0,
                            }
                        };
                    } else {
                        accumulator = if has_accumulator {
                            step(accumulator, value)
                        } else {
                            value
                        };
                        if real_input {
                            accumulator.imag = 0.0;
                        }
                        has_accumulator = true;
                        output_values[linear] = accumulator;
                    }
                }
            }
        }
    }

    (normalized_dims, output_values)
}

fn cumulative_integer_slices_nd(
    input_values: &[i128],
    input_dims: &[usize],
    dim: usize,
    class: IntegerClass,
    step: impl Fn(i128, i128, IntegerClass) -> i128 + Copy,
    identity: i128,
) -> (Vec<usize>, Vec<i128>) {
    let normalized_dims = canonical_size_vector(input_dims);
    let axis = dim - 1;
    let axis_len = normalized_dims[axis];
    if normalized_dims.iter().any(|&size| size == 0) {
        return (normalized_dims, Vec::new());
    }

    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(position, &size)| (position != axis).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let mut output_values = vec![0i128; input_values.len()];

    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let mut accumulator = identity;
        for axis_value in 0..axis_len {
            let full_index =
                nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            accumulator = step(accumulator, input_values[linear], class);
            output_values[linear] = accumulator;
        }
    }

    (normalized_dims, output_values)
}

fn cumulative_extreme_slices_nd(
    input_values: &[f64],
    input_dims: &[usize],
    dim: usize,
    direction: CumulativeDirection,
    missing_flag: ExtremeMissingFlag,
    prefer_candidate: impl Fn(f64, f64) -> bool + Copy,
) -> (Vec<usize>, Vec<f64>, Vec<f64>) {
    let normalized_dims = canonical_size_vector(input_dims);
    let axis = dim - 1;
    let axis_len = normalized_dims[axis];
    if normalized_dims.iter().any(|&size| size == 0) {
        return (normalized_dims, Vec::new(), Vec::new());
    }

    let sequence_dims = normalized_dims
        .iter()
        .enumerate()
        .filter_map(|(position, &size)| (position != axis).then_some(size))
        .collect::<Vec<_>>();
    let sequence_count = if sequence_dims.is_empty() {
        1
    } else {
        sequence_dims.iter().product::<usize>()
    };
    let mut output_values = vec![0.0; input_values.len()];
    let mut output_indices = vec![1.0; input_values.len()];

    for sequence_index in 0..sequence_count {
        let reduced_index = row_major_multi_index(sequence_index, &sequence_dims);
        let mut best = f64::NAN;
        let mut best_index = 1usize;
        let mut has_best = false;
        let axis_iter: Box<dyn Iterator<Item = usize>> = match direction {
            CumulativeDirection::Forward => Box::new(0..axis_len),
            CumulativeDirection::Reverse => Box::new((0..axis_len).rev()),
        };
        for axis_value in axis_iter {
            let full_index =
                nd_reduction_full_index(&normalized_dims, axis, axis_value, &reduced_index);
            let linear = row_major_linear_index(&full_index, &normalized_dims);
            let candidate = input_values[linear];
            match missing_flag {
                ExtremeMissingFlag::IncludeNan => {
                    if axis_value == 0 || candidate.is_nan() {
                        best = candidate;
                        best_index = axis_value + 1;
                        has_best = true;
                    } else if !best.is_nan() && prefer_candidate(candidate, best) {
                        best = candidate;
                        best_index = axis_value + 1;
                    }
                }
                ExtremeMissingFlag::OmitNan => {
                    if !candidate.is_nan() {
                        if !has_best || prefer_candidate(candidate, best) {
                            best = candidate;
                            best_index = axis_value + 1;
                        }
                        has_best = true;
                    }
                }
            }
            if has_best {
                output_values[linear] = best;
                output_indices[linear] = best_index as f64;
            } else {
                output_values[linear] = f64::NAN;
                output_indices[linear] = (axis_value + 1) as f64;
            }
        }
    }

    (normalized_dims, output_values, output_indices)
}

