fn central_moment_numeric_value_with_dimensions(
    input_values: &[f64],
    input_dims: &[usize],
    dim: usize,
    order: usize,
) -> Result<Value, RuntimeError> {
    let mut normalized_dims = canonical_size_vector(input_dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    if dim > input_dims.len() || normalized_dims[dim - 1] == 1 {
        let values = if normalized_dims.iter().any(|&size| size == 0) {
            Vec::new()
        } else {
            vec![0.0; input_values.len()]
        };
        return numeric_matrix_result_with_dimensions(input_dims.to_vec(), values);
    }
    let axis = dim - 1;
    let mut output_dims = normalized_dims.clone();
    output_dims[axis] = 1;
    if normalized_dims.iter().any(|&size| size == 0) {
        let output_count = output_dims.iter().product::<usize>();
        return numeric_matrix_result_with_dimensions(output_dims, vec![f64::NAN; output_count]);
    }
    let (output_dims, values) =
        reduce_numeric_slices_nd(input_values, input_dims, dim, 1, |sample| {
            vec![moment_of_values(sample, order)]
        });
    numeric_matrix_result_with_dimensions(output_dims, values)
}

fn rms_numeric_value_with_dimensions(
    input_values: &[ComplexParts],
    input_dims: &[usize],
    dim: usize,
    missing_flag: StatisticMissingFlag,
) -> Result<Value, RuntimeError> {
    let mut normalized_dims = canonical_size_vector(input_dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    if dim > input_dims.len() {
        if normalized_dims.iter().any(|&size| size == 0) {
            return numeric_matrix_result_with_dimensions(input_dims.to_vec(), Vec::new());
        }
        let values = input_values
            .iter()
            .map(|value| value.magnitude())
            .collect::<Vec<_>>();
        return numeric_matrix_result_with_dimensions(input_dims.to_vec(), values);
    }
    let axis = dim - 1;
    let mut output_dims = normalized_dims.clone();
    output_dims[axis] = 1;
    if normalized_dims.iter().any(|&size| size == 0) {
        let output_count = output_dims.iter().product::<usize>();
        return numeric_matrix_result_with_dimensions(output_dims, vec![f64::NAN; output_count]);
    }
    let squared = input_values
        .iter()
        .map(|value| (value.real * value.real) + (value.imag * value.imag))
        .collect::<Vec<_>>();
    let (output_dims, values) = reduce_numeric_slices_nd(&squared, input_dims, dim, 1, |sample| {
        vec![rms_of_squared_values(sample, missing_flag)]
    });
    numeric_matrix_result_with_dimensions(output_dims, values)
}

fn iqr_nd_outputs(
    input_values: &[f64],
    input_dims: &[usize],
    dim: usize,
    output_arity: usize,
    missing_flag: StatisticMissingFlag,
) -> Result<Vec<Value>, RuntimeError> {
    let mut normalized_dims = canonical_size_vector(input_dims);
    while normalized_dims.len() < dim {
        normalized_dims.push(1);
    }
    let axis_len = normalized_dims[dim - 1];
    if axis_len == 0 {
        let mut outputs = vec![empty_iqr_nd_value_with_dimensions(input_dims, dim, 1)?];
        if output_arity == 2 {
            outputs.push(empty_iqr_nd_value_with_dimensions(input_dims, dim, 2)?);
        }
        return Ok(outputs);
    }

    let quartile_probabilities = [0.25, 0.75];
    let (quartile_dims, quartile_values) =
        reduce_numeric_slices_nd(input_values, input_dims, dim, 2, |sample| {
            quantiles_for_sample_with_missing(sample, &quartile_probabilities, missing_flag)
        });
    let (spread_dims, spread_values) =
        reduce_numeric_slices_nd(input_values, input_dims, dim, 1, |sample| {
            vec![iqr_quartiles_and_spread(sample, missing_flag).1]
        });
    let mut outputs = vec![numeric_matrix_result_with_dimensions(
        spread_dims,
        spread_values,
    )?];
    if output_arity == 2 {
        outputs.push(numeric_matrix_result_with_dimensions(
            quartile_dims,
            quartile_values,
        )?);
    }
    Ok(outputs)
}

fn empty_iqr_nd_value_with_dimensions(
    input_dims: &[usize],
    dim: usize,
    axis_output_len: usize,
) -> Result<Value, RuntimeError> {
    let mut output_dims = canonical_size_vector(input_dims);
    while output_dims.len() < dim {
        output_dims.push(1);
    }
    output_dims[dim - 1] = axis_output_len;
    let output_len = output_dims.iter().product::<usize>();
    numeric_matrix_result_with_dimensions(output_dims, vec![f64::NAN; output_len])
}

fn range_numeric_result(
    data: &NumericOperand,
    dim: usize,
    missing_flag: StatisticMissingFlag,
) -> NumericOperand {
    if data.rows == 0 || data.cols == 0 {
        return empty_range_numeric_result(data.rows, data.cols, dim);
    }

    if data.rows == 1 || data.cols == 1 {
        if (data.rows == 1 && data.cols > 1 && (dim == 1 || dim > 2))
            || (data.cols == 1 && data.rows > 1 && (dim == 2 || dim > 2))
        {
            return NumericOperand {
                rows: data.rows,
                cols: data.cols,
                values: vec![0.0; data.rows * data.cols],
            };
        }
        return NumericOperand {
            rows: 1,
            cols: 1,
            values: vec![sample_range_with_missing(&data.values, missing_flag)],
        };
    }

    match dim {
        1 => NumericOperand {
            rows: 1,
            cols: data.cols,
            values: (0..data.cols)
                .map(|col| {
                    sample_range_with_missing(
                        &(0..data.rows)
                            .map(|row| data.values[row * data.cols + col])
                            .collect::<Vec<_>>(),
                        missing_flag,
                    )
                })
                .collect(),
        },
        2 => NumericOperand {
            rows: data.rows,
            cols: 1,
            values: (0..data.rows)
                .map(|row| {
                    sample_range_with_missing(
                        &(0..data.cols)
                            .map(|col| data.values[row * data.cols + col])
                            .collect::<Vec<_>>(),
                        missing_flag,
                    )
                })
                .collect(),
        },
        _ => NumericOperand {
            rows: data.rows,
            cols: data.cols,
            values: vec![0.0; data.rows * data.cols],
        },
    }
}

fn empty_range_numeric_result(rows: usize, cols: usize, dim: usize) -> NumericOperand {
    match dim {
        1 if rows == 0 => NumericOperand {
            rows,
            cols,
            values: Vec::new(),
        },
        1 => NumericOperand {
            rows: 1,
            cols,
            values: Vec::new(),
        },
        2 if cols == 0 => NumericOperand {
            rows,
            cols,
            values: Vec::new(),
        },
        2 => NumericOperand {
            rows,
            cols: 1,
            values: Vec::new(),
        },
        _ => NumericOperand {
            rows,
            cols,
            values: Vec::new(),
        },
    }
}

fn sample_range_with_missing(sample: &[f64], missing_flag: StatisticMissingFlag) -> f64 {
    let filtered = match missing_flag {
        StatisticMissingFlag::IncludeNan => {
            if sample.iter().any(|value| value.is_nan()) {
                return f64::NAN;
            }
            sample.to_vec()
        }
        StatisticMissingFlag::OmitNan => sample
            .iter()
            .copied()
            .filter(|value| !value.is_nan())
            .collect::<Vec<_>>(),
    };
    if filtered.is_empty() {
        return f64::NAN;
    }
    let min = filtered
        .iter()
        .copied()
        .min_by(f64::total_cmp)
        .unwrap_or(f64::NAN);
    let max = filtered
        .iter()
        .copied()
        .max_by(f64::total_cmp)
        .unwrap_or(f64::NAN);
    zero_small(max - min)
}

fn zscore_numeric_outputs(
    data: &NumericOperand,
    normalization: VarianceNormalization,
    selection: &StatisticSelection,
) -> Result<(NumericOperand, NumericOperand, NumericOperand), RuntimeError> {
    match selection {
        StatisticSelection::Default => {
            return zscore_numeric_outputs_for_dim(
                data,
                normalization,
                default_statistic_dimension(data),
            );
        }
        StatisticSelection::Dim(dim) => {
            return zscore_numeric_outputs_for_dim(data, normalization, *dim);
        }
        StatisticSelection::All => {
            let (zs, mean, sigma) = zscore_sample(&data.values, normalization);
            return Ok((
                NumericOperand {
                    rows: data.rows,
                    cols: data.cols,
                    values: zs,
                },
                NumericOperand {
                    rows: 1,
                    cols: 1,
                    values: vec![mean],
                },
                NumericOperand {
                    rows: 1,
                    cols: 1,
                    values: vec![sigma],
                },
            ));
        }
        StatisticSelection::VecDim(dims) => {
            let reduces_rows = dims.contains(&1);
            let reduces_cols = dims.contains(&2);
            return match (reduces_rows, reduces_cols) {
                (true, true) => {
                    let (zs, mean, sigma) = zscore_sample(&data.values, normalization);
                    Ok((
                        NumericOperand {
                            rows: data.rows,
                            cols: data.cols,
                            values: zs,
                        },
                        NumericOperand {
                            rows: 1,
                            cols: 1,
                            values: vec![mean],
                        },
                        NumericOperand {
                            rows: 1,
                            cols: 1,
                            values: vec![sigma],
                        },
                    ))
                }
                (true, false) => zscore_numeric_outputs_for_dim(data, normalization, 1),
                (false, true) => zscore_numeric_outputs_for_dim(data, normalization, 2),
                (false, false) => Err(RuntimeError::Unsupported(
                    "zscore currently expects vecdim to include dimension 1 and/or 2 in the current 2-D runtime"
                        .to_string(),
                )),
            };
        }
    }
}

fn zscore_numeric_outputs_for_dim(
    data: &NumericOperand,
    normalization: VarianceNormalization,
    dim: usize,
) -> Result<(NumericOperand, NumericOperand, NumericOperand), RuntimeError> {
    match dim {
        1 => {
            let mut z_values = Vec::with_capacity(data.values.len());
            let mut means = Vec::with_capacity(data.cols);
            let mut sigmas = Vec::with_capacity(data.cols);
            for col in 0..data.cols {
                let sample = (0..data.rows)
                    .map(|row| data.values[row * data.cols + col])
                    .collect::<Vec<_>>();
                let (zs, mean, sigma) = zscore_sample(&sample, normalization);
                z_values.extend(zs);
                means.push(mean);
                sigmas.push(sigma);
            }

            let z = transpose_numeric_operand(&NumericOperand {
                rows: data.cols,
                cols: data.rows,
                values: z_values,
            });
            Ok((
                z,
                NumericOperand {
                    rows: 1,
                    cols: data.cols,
                    values: means,
                },
                NumericOperand {
                    rows: 1,
                    cols: data.cols,
                    values: sigmas,
                },
            ))
        }
        2 => {
            let mut z_values = Vec::with_capacity(data.values.len());
            let mut means = Vec::with_capacity(data.rows);
            let mut sigmas = Vec::with_capacity(data.rows);
            for row in 0..data.rows {
                let sample = (0..data.cols)
                    .map(|col| data.values[row * data.cols + col])
                    .collect::<Vec<_>>();
                let (zs, mean, sigma) = zscore_sample(&sample, normalization);
                z_values.extend(zs);
                means.push(mean);
                sigmas.push(sigma);
            }

            Ok((
                NumericOperand {
                    rows: data.rows,
                    cols: data.cols,
                    values: z_values,
                },
                NumericOperand {
                    rows: data.rows,
                    cols: 1,
                    values: means,
                },
                NumericOperand {
                    rows: data.rows,
                    cols: 1,
                    values: sigmas,
                },
            ))
        }
        _ => Ok((
            NumericOperand {
                rows: data.rows,
                cols: data.cols,
                values: vec![0.0; data.values.len()],
            },
            data.clone(),
            NumericOperand {
                rows: data.rows,
                cols: data.cols,
                values: vec![0.0; data.values.len()],
            },
        )),
    }
}

fn zscore_sample(sample: &[f64], normalization: VarianceNormalization) -> (Vec<f64>, f64, f64) {
    if sample.is_empty() {
        return (Vec::new(), f64::NAN, f64::NAN);
    }
    if sample.iter().any(|value| value.is_nan()) {
        return (vec![f64::NAN; sample.len()], f64::NAN, f64::NAN);
    }

    let mean = sample.iter().sum::<f64>() / sample.len() as f64;
    let sigma = variance_with_normalization(sample, normalization).sqrt();
    if sigma.abs() <= 1e-12 {
        return (vec![0.0; sample.len()], mean, 0.0);
    }

    (
        sample
            .iter()
            .map(|value| zero_small((*value - mean) / sigma))
            .collect::<Vec<_>>(),
        mean,
        sigma,
    )
}

fn transpose_numeric_operand(value: &NumericOperand) -> NumericOperand {
    let mut values = Vec::with_capacity(value.values.len());
    for col in 0..value.cols {
        for row in 0..value.rows {
            values.push(value.values[row * value.cols + col]);
        }
    }
    NumericOperand {
        rows: value.cols,
        cols: value.rows,
        values,
    }
}

fn covariance_dataset_from_value(
    value: &Value,
    builtin_name: &str,
) -> Result<NumericOperand, RuntimeError> {
    let operand = numeric_operand(value, builtin_name)?;
    if operand.rows == 1 || operand.cols == 1 {
        return Ok(NumericOperand {
            rows: operand.values.len(),
            cols: 1,
            values: operand.values,
        });
    }

    Ok(operand)
}

fn covariance_dataset_from_complex_value(
    value: &Value,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let operand = numeric_or_complex_operand(value, builtin_name)?;
    if operand.rows == 1 || operand.cols == 1 {
        return Ok(NumericOrComplexOperand {
            rows: operand.values.len(),
            cols: 1,
            values: operand.values,
        });
    }

    Ok(operand)
}

fn covariance_pair_dataset(
    lhs: &Value,
    rhs: &Value,
    builtin_name: &str,
) -> Result<NumericOperand, RuntimeError> {
    let lhs = numeric_operand(lhs, builtin_name)?;
    let rhs = numeric_operand(rhs, builtin_name)?;
    if lhs.values.len() != rhs.values.len() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects paired inputs with matching element counts"
        )));
    }

    let mut values = Vec::with_capacity(lhs.values.len() * 2);
    for index in 0..lhs.values.len() {
        values.push(lhs.values[index]);
        values.push(rhs.values[index]);
    }
    Ok(NumericOperand {
        rows: lhs.values.len(),
        cols: 2,
        values,
    })
}

fn covariance_pair_dataset_complex(
    lhs: &Value,
    rhs: &Value,
    builtin_name: &str,
) -> Result<NumericOrComplexOperand, RuntimeError> {
    let lhs = numeric_or_complex_operand(lhs, builtin_name)?;
    let rhs = numeric_or_complex_operand(rhs, builtin_name)?;
    if lhs.values.len() != rhs.values.len() {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects paired inputs with matching element counts"
        )));
    }

    let mut values = Vec::with_capacity(lhs.values.len() * 2);
    for index in 0..lhs.values.len() {
        values.push(lhs.values[index]);
        values.push(rhs.values[index]);
    }
    Ok(NumericOrComplexOperand {
        rows: lhs.values.len(),
        cols: 2,
        values,
    })
}

fn covariance_matrix(
    dataset: &NumericOperand,
    normalization: VarianceNormalization,
) -> NumericOperand {
    let observations = dataset.rows;
    let variables = dataset.cols;
    let mut means = vec![0.0; variables];
    for row in 0..observations {
        for (col, mean) in means.iter_mut().enumerate() {
            *mean += dataset.values[row * variables + col];
        }
    }
    for mean in &mut means {
        *mean /= observations as f64;
    }

    let denominator = match normalization {
        VarianceNormalization::Sample if observations <= 1 => 1.0,
        VarianceNormalization::Sample => (observations - 1) as f64,
        VarianceNormalization::Population => observations as f64,
    };

    let mut values = vec![0.0; variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let covariance = if observations <= 1 {
                0.0
            } else {
                let mut total = 0.0;
                for row in 0..observations {
                    let lhs = dataset.values[row * variables + lhs_col] - means[lhs_col];
                    let rhs = dataset.values[row * variables + rhs_col] - means[rhs_col];
                    total += lhs * rhs;
                }
                total / denominator
            };
            values[lhs_col * variables + rhs_col] = zero_small(covariance);
        }
    }

    NumericOperand {
        rows: variables,
        cols: variables,
        values,
    }
}

fn covariance_matrix_complex(
    dataset: &NumericOrComplexOperand,
    normalization: VarianceNormalization,
) -> NumericOrComplexOperand {
    let observations = dataset.rows;
    let variables = dataset.cols;
    let mut means = vec![ComplexParts::zero(); variables];
    for row in 0..observations {
        for (col, mean) in means.iter_mut().enumerate() {
            *mean = mean.plus(dataset.values[row * variables + col]);
        }
    }
    for mean in &mut means {
        *mean = mean.scale(1.0 / observations as f64);
    }

    let denominator = match normalization {
        VarianceNormalization::Sample if observations <= 1 => 1.0,
        VarianceNormalization::Sample => (observations - 1) as f64,
        VarianceNormalization::Population => observations as f64,
    };

    let mut values = vec![ComplexParts::zero(); variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let covariance = if observations <= 1 {
                ComplexParts::zero()
            } else {
                let mut total = ComplexParts::zero();
                for row in 0..observations {
                    let lhs = dataset.values[row * variables + lhs_col].minus(means[lhs_col]);
                    let rhs = dataset.values[row * variables + rhs_col].minus(means[rhs_col]);
                    total = total.plus(lhs.conjugate().times(rhs));
                }
                total.scale(1.0 / denominator)
            };
            values[lhs_col * variables + rhs_col] = normalize_complex_parts(covariance);
        }
    }

    NumericOrComplexOperand {
        rows: variables,
        cols: variables,
        values,
    }
}

fn covariance_matrix_pairwise(
    dataset: &NumericOperand,
    normalization: VarianceNormalization,
) -> NumericOperand {
    let variables = dataset.cols;
    let mut values = vec![0.0; variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let mut lhs_values = Vec::new();
            let mut rhs_values = Vec::new();
            for row in 0..dataset.rows {
                let lhs = dataset.values[row * variables + lhs_col];
                let rhs = dataset.values[row * variables + rhs_col];
                if lhs.is_nan() || rhs.is_nan() {
                    continue;
                }
                lhs_values.push(lhs);
                rhs_values.push(rhs);
            }
            values[lhs_col * variables + rhs_col] = if lhs_values.is_empty() {
                f64::NAN
            } else {
                covariance_of_samples(&lhs_values, &rhs_values, normalization)
            };
        }
    }
    NumericOperand {
        rows: variables,
        cols: variables,
        values,
    }
}

fn covariance_matrix_pairwise_complex(
    dataset: &NumericOrComplexOperand,
    normalization: VarianceNormalization,
) -> NumericOrComplexOperand {
    let variables = dataset.cols;
    let mut values = vec![ComplexParts::zero(); variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let mut lhs_values = Vec::new();
            let mut rhs_values = Vec::new();
            for row in 0..dataset.rows {
                let lhs = dataset.values[row * variables + lhs_col];
                let rhs = dataset.values[row * variables + rhs_col];
                if lhs.is_nan() || rhs.is_nan() {
                    continue;
                }
                lhs_values.push(lhs);
                rhs_values.push(rhs);
            }
            values[lhs_col * variables + rhs_col] = if lhs_values.is_empty() {
                ComplexParts::nan()
            } else {
                covariance_of_complex_samples(&lhs_values, &rhs_values, normalization)
            };
        }
    }
    NumericOrComplexOperand {
        rows: variables,
        cols: variables,
        values,
    }
}

fn covariance_of_samples(lhs: &[f64], rhs: &[f64], normalization: VarianceNormalization) -> f64 {
    let observations = lhs.len();
    let lhs_mean = lhs.iter().sum::<f64>() / observations as f64;
    let rhs_mean = rhs.iter().sum::<f64>() / observations as f64;
    let denominator = match normalization {
        VarianceNormalization::Sample if observations <= 1 => 1.0,
        VarianceNormalization::Sample => (observations - 1) as f64,
        VarianceNormalization::Population => observations as f64,
    };
    let total = lhs
        .iter()
        .zip(rhs.iter())
        .map(|(lhs, rhs)| (lhs - lhs_mean) * (rhs - rhs_mean))
        .sum::<f64>();
    zero_small(total / denominator)
}

fn covariance_of_complex_samples(
    lhs: &[ComplexParts],
    rhs: &[ComplexParts],
    normalization: VarianceNormalization,
) -> ComplexParts {
    let observations = lhs.len();
    let lhs_mean = complex_parts_mean(lhs);
    let rhs_mean = complex_parts_mean(rhs);
    let denominator = match normalization {
        VarianceNormalization::Sample if observations <= 1 => 1.0,
        VarianceNormalization::Sample => (observations - 1) as f64,
        VarianceNormalization::Population => observations as f64,
    };
    let total = lhs
        .iter()
        .zip(rhs.iter())
        .fold(ComplexParts::zero(), |accumulator, (lhs, rhs)| {
            accumulator.plus(lhs.minus(lhs_mean).conjugate().times(rhs.minus(rhs_mean)))
        });
    normalize_complex_parts(total.scale(1.0 / denominator))
}

fn correlation_matrix(covariance: &NumericOperand) -> NumericOperand {
    let mut values = vec![0.0; covariance.values.len()];
    for row in 0..covariance.rows {
        let row_variance = covariance.values[row * covariance.cols + row];
        for col in 0..covariance.cols {
            let col_variance = covariance.values[col * covariance.cols + col];
            let denominator = (row_variance * col_variance).sqrt();
            let value = if !denominator.is_finite() || denominator.abs() <= 1e-12 {
                f64::NAN
            } else if row == col {
                1.0
            } else {
                zero_small(covariance.values[row * covariance.cols + col] / denominator)
            };
            values[row * covariance.cols + col] = value;
        }
    }

    NumericOperand {
        rows: covariance.rows,
        cols: covariance.cols,
        values,
    }
}

fn correlation_matrix_complex(covariance: &NumericOrComplexOperand) -> NumericOrComplexOperand {
    let mut values = vec![ComplexParts::zero(); covariance.values.len()];
    for row in 0..covariance.rows {
        let row_variance = covariance.values[row * covariance.cols + row].real;
        for col in 0..covariance.cols {
            let col_variance = covariance.values[col * covariance.cols + col].real;
            let denominator = (row_variance * col_variance).sqrt();
            let value = if !denominator.is_finite() || denominator.abs() <= 1e-12 {
                ComplexParts {
                    real: f64::NAN,
                    imag: 0.0,
                }
            } else if row == col {
                ComplexParts::one()
            } else {
                normalize_complex_parts(
                    covariance.values[row * covariance.cols + col].scale(1.0 / denominator),
                )
            };
            values[row * covariance.cols + col] = value;
        }
    }

    NumericOrComplexOperand {
        rows: covariance.rows,
        cols: covariance.cols,
        values,
    }
}

fn try_numeric_operand_from_complex(value: &NumericOrComplexOperand) -> Option<NumericOperand> {
    let mut values = Vec::with_capacity(value.values.len());
    for element in &value.values {
        if element.imag.abs() > 1e-12 && !element.imag.is_nan() {
            return None;
        }
        values.push(element.real);
    }
    Some(NumericOperand {
        rows: value.rows,
        cols: value.cols,
        values,
    })
}

fn corrcoef_pairwise_outputs(dataset: &NumericOperand) -> (NumericOperand, NumericOperand) {
    let variables = dataset.cols;
    let mut correlations = vec![0.0; variables * variables];
    let mut p_values = vec![f64::NAN; variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let mut lhs_values = Vec::new();
            let mut rhs_values = Vec::new();
            for row in 0..dataset.rows {
                let lhs = dataset.values[row * variables + lhs_col];
                let rhs = dataset.values[row * variables + rhs_col];
                if lhs.is_nan() || rhs.is_nan() {
                    continue;
                }
                lhs_values.push(lhs);
                rhs_values.push(rhs);
            }
            let offset = lhs_col * variables + rhs_col;
            correlations[offset] = if lhs_values.len() <= 1 {
                f64::NAN
            } else {
                let covariance =
                    covariance_of_samples(&lhs_values, &rhs_values, VarianceNormalization::Sample);
                let lhs_variance =
                    covariance_of_samples(&lhs_values, &lhs_values, VarianceNormalization::Sample);
                let rhs_variance =
                    covariance_of_samples(&rhs_values, &rhs_values, VarianceNormalization::Sample);
                let denominator = (lhs_variance * rhs_variance).sqrt();
                if !denominator.is_finite() || denominator.abs() <= 1e-12 {
                    f64::NAN
                } else if lhs_col == rhs_col {
                    1.0
                } else {
                    zero_small(covariance / denominator)
                }
            };
            p_values[offset] =
                corrcoef_probability(correlations[offset], lhs_values.len(), lhs_col == rhs_col);
        }
    }
    (
        NumericOperand {
            rows: variables,
            cols: variables,
            values: correlations,
        },
        NumericOperand {
            rows: variables,
            cols: variables,
            values: p_values,
        },
    )
}

fn corrcoef_confidence_bounds(
    correlation: &NumericOperand,
    dataset: &NumericOperand,
    options: CorrcoefOptions,
) -> (NumericOperand, NumericOperand) {
    match options.rows_flag {
        CorrcoefRowsFlag::Pairwise => corrcoef_pairwise_confidence_bounds(dataset, options.alpha),
        CorrcoefRowsFlag::All => {
            corrcoef_confidence_bounds_for_matrix(correlation, dataset.rows, options.alpha)
        }
        CorrcoefRowsFlag::Complete => {
            let filtered = omit_nan_covariance_rows(dataset);
            if filtered.rows == 0 {
                let nans = nan_numeric_operand(dataset.cols);
                (nans.clone(), nans)
            } else {
                corrcoef_confidence_bounds_for_matrix(correlation, filtered.rows, options.alpha)
            }
        }
    }
}

fn corrcoef_p_values_for_matrix(
    correlation: &NumericOperand,
    observations: usize,
) -> NumericOperand {
    let mut values = Vec::with_capacity(correlation.values.len());
    for row in 0..correlation.rows {
        for col in 0..correlation.cols {
            values.push(corrcoef_probability(
                correlation.values[row * correlation.cols + col],
                observations,
                row == col,
            ));
        }
    }
    NumericOperand {
        rows: correlation.rows,
        cols: correlation.cols,
        values,
    }
}

fn corrcoef_confidence_bounds_for_matrix(
    correlation: &NumericOperand,
    observations: usize,
    alpha: f64,
) -> (NumericOperand, NumericOperand) {
    let mut lower = Vec::with_capacity(correlation.values.len());
    let mut upper = Vec::with_capacity(correlation.values.len());
    for row in 0..correlation.rows {
        for col in 0..correlation.cols {
            let (lo, hi) = corrcoef_confidence_interval(
                correlation.values[row * correlation.cols + col],
                observations,
                row == col,
                alpha,
            );
            lower.push(lo);
            upper.push(hi);
        }
    }
    (
        NumericOperand {
            rows: correlation.rows,
            cols: correlation.cols,
            values: lower,
        },
        NumericOperand {
            rows: correlation.rows,
            cols: correlation.cols,
            values: upper,
        },
    )
}

fn corrcoef_pairwise_confidence_bounds(
    dataset: &NumericOperand,
    alpha: f64,
) -> (NumericOperand, NumericOperand) {
    let variables = dataset.cols;
    let mut lower = vec![f64::NAN; variables * variables];
    let mut upper = vec![f64::NAN; variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let mut lhs_values = Vec::new();
            let mut rhs_values = Vec::new();
            for row in 0..dataset.rows {
                let lhs = dataset.values[row * variables + lhs_col];
                let rhs = dataset.values[row * variables + rhs_col];
                if lhs.is_nan() || rhs.is_nan() {
                    continue;
                }
                lhs_values.push(lhs);
                rhs_values.push(rhs);
            }
            let correlation = if lhs_values.len() <= 1 {
                f64::NAN
            } else {
                let covariance =
                    covariance_of_samples(&lhs_values, &rhs_values, VarianceNormalization::Sample);
                let lhs_variance =
                    covariance_of_samples(&lhs_values, &lhs_values, VarianceNormalization::Sample);
                let rhs_variance =
                    covariance_of_samples(&rhs_values, &rhs_values, VarianceNormalization::Sample);
                let denominator = (lhs_variance * rhs_variance).sqrt();
                if !denominator.is_finite() || denominator.abs() <= 1e-12 {
                    f64::NAN
                } else if lhs_col == rhs_col {
                    1.0
                } else {
                    zero_small(covariance / denominator)
                }
            };
            let (lo, hi) = corrcoef_confidence_interval(
                correlation,
                lhs_values.len(),
                lhs_col == rhs_col,
                alpha,
            );
            let offset = lhs_col * variables + rhs_col;
            lower[offset] = lo;
            upper[offset] = hi;
        }
    }
    (
        NumericOperand {
            rows: variables,
            cols: variables,
            values: lower,
        },
        NumericOperand {
            rows: variables,
            cols: variables,
            values: upper,
        },
    )
}

fn corrcoef_pairwise_p_values_complex(
    dataset: &NumericOrComplexOperand,
    correlation: &NumericOperand,
) -> NumericOperand {
    let variables = dataset.cols;
    let mut values = vec![f64::NAN; variables * variables];
    for lhs_col in 0..variables {
        for rhs_col in 0..variables {
            let mut observations = 0usize;
            for row in 0..dataset.rows {
                let lhs = dataset.values[row * variables + lhs_col];
                let rhs = dataset.values[row * variables + rhs_col];
                if lhs.is_nan() || rhs.is_nan() {
                    continue;
                }
                observations += 1;
            }
            let offset = lhs_col * variables + rhs_col;
            values[offset] =
                corrcoef_probability(correlation.values[offset], observations, lhs_col == rhs_col);
        }
    }
    NumericOperand {
        rows: variables,
        cols: variables,
        values,
    }
}

