fn corr_pairwise_p_values_complex(
    inputs: &ComplexCorrInputs,
    correlation: &NumericOperand,
) -> NumericOperand {
    let rhs = inputs.rhs.as_ref().unwrap_or(&inputs.lhs);
    let cols_lhs = inputs.lhs.cols;
    let cols_rhs = rhs.cols;
    let mut p_values = vec![f64::NAN; cols_lhs * cols_rhs];
    for lhs_col in 0..cols_lhs {
        for rhs_col in 0..cols_rhs {
            let mut observations = 0usize;
            for row in 0..inputs.lhs.rows {
                let lhs = inputs.lhs.values[row * inputs.lhs.cols + lhs_col];
                let rhs_value = rhs.values[row * rhs.cols + rhs_col];
                if lhs.is_nan() || rhs_value.is_nan() {
                    continue;
                }
                observations += 1;
            }
            let offset = lhs_col * cols_rhs + rhs_col;
            p_values[offset] = corr_probability(
                correlation.values[offset],
                observations,
                inputs.options.tail,
            );
        }
    }
    NumericOperand {
        rows: cols_lhs,
        cols: cols_rhs,
        values: p_values,
    }
}

fn column_values(operand: &NumericOperand, column: usize) -> Vec<f64> {
    (0..operand.rows)
        .map(|row| operand.values[row * operand.cols + column])
        .collect()
}

fn pairwise_column_values(
    lhs: &NumericOperand,
    lhs_col: usize,
    rhs: &NumericOperand,
    rhs_col: usize,
) -> (Vec<f64>, Vec<f64>) {
    let mut lhs_values = Vec::new();
    let mut rhs_values = Vec::new();
    for row in 0..lhs.rows {
        let lhs_value = lhs.values[row * lhs.cols + lhs_col];
        let rhs_value = rhs.values[row * rhs.cols + rhs_col];
        if lhs_value.is_nan() || rhs_value.is_nan() {
            continue;
        }
        lhs_values.push(lhs_value);
        rhs_values.push(rhs_value);
    }
    (lhs_values, rhs_values)
}

fn column_values_complex(operand: &NumericOrComplexOperand, column: usize) -> Vec<ComplexParts> {
    (0..operand.rows)
        .map(|row| operand.values[row * operand.cols + column])
        .collect()
}

fn pairwise_column_values_complex(
    lhs: &NumericOrComplexOperand,
    lhs_col: usize,
    rhs: &NumericOrComplexOperand,
    rhs_col: usize,
) -> (Vec<ComplexParts>, Vec<ComplexParts>) {
    let mut lhs_values = Vec::new();
    let mut rhs_values = Vec::new();
    for row in 0..lhs.rows {
        let lhs_value = lhs.values[row * lhs.cols + lhs_col];
        let rhs_value = rhs.values[row * rhs.cols + rhs_col];
        if lhs_value.is_nan() || rhs_value.is_nan() {
            continue;
        }
        lhs_values.push(lhs_value);
        rhs_values.push(rhs_value);
    }
    (lhs_values, rhs_values)
}

fn filter_numeric_operand_rows(operand: &NumericOperand, rows: &[usize]) -> NumericOperand {
    let mut values = Vec::with_capacity(rows.len() * operand.cols);
    for row in rows {
        let start = row * operand.cols;
        values.extend_from_slice(&operand.values[start..start + operand.cols]);
    }
    NumericOperand {
        rows: rows.len(),
        cols: operand.cols,
        values,
    }
}

fn filter_numeric_or_complex_operand_rows(
    operand: &NumericOrComplexOperand,
    rows: &[usize],
) -> NumericOrComplexOperand {
    let mut values = Vec::with_capacity(rows.len() * operand.cols);
    for row in rows {
        let start = row * operand.cols;
        values.extend_from_slice(&operand.values[start..start + operand.cols]);
    }
    NumericOrComplexOperand {
        rows: rows.len(),
        cols: operand.cols,
        values,
    }
}

fn corr_of_samples(lhs: &[f64], rhs: &[f64]) -> f64 {
    if lhs.len() <= 1 {
        return f64::NAN;
    }
    let covariance = covariance_of_samples(lhs, rhs, VarianceNormalization::Sample);
    let lhs_variance = covariance_of_samples(lhs, lhs, VarianceNormalization::Sample);
    let rhs_variance = covariance_of_samples(rhs, rhs, VarianceNormalization::Sample);
    let denominator = (lhs_variance * rhs_variance).sqrt();
    if !denominator.is_finite() || denominator.abs() <= 1e-12 {
        f64::NAN
    } else {
        zero_small(covariance / denominator)
    }
}

fn corr_of_samples_with_type(lhs: &[f64], rhs: &[f64], corr_type: CorrType) -> f64 {
    match corr_type {
        CorrType::Pearson => corr_of_samples(lhs, rhs),
        CorrType::Spearman => {
            let lhs_ranks = tied_ranks(lhs);
            let rhs_ranks = tied_ranks(rhs);
            corr_of_samples(&lhs_ranks, &rhs_ranks)
        }
        CorrType::Kendall => kendall_tau_b(lhs, rhs),
    }
}

fn corr_of_complex_samples(lhs: &[ComplexParts], rhs: &[ComplexParts]) -> ComplexParts {
    if lhs.len() <= 1 {
        return ComplexParts::nan();
    }
    let covariance = covariance_of_complex_samples(lhs, rhs, VarianceNormalization::Sample);
    let lhs_variance = covariance_of_complex_samples(lhs, lhs, VarianceNormalization::Sample).real;
    let rhs_variance = covariance_of_complex_samples(rhs, rhs, VarianceNormalization::Sample).real;
    let denominator = (lhs_variance * rhs_variance).sqrt();
    if !denominator.is_finite() || denominator.abs() <= 1e-12 {
        ComplexParts::nan()
    } else {
        normalize_complex_parts(covariance.scale(1.0 / denominator))
    }
}

fn tied_ranks(values: &[f64]) -> Vec<f64> {
    let mut indexed = values.iter().copied().enumerate().collect::<Vec<_>>();
    indexed.sort_by(|lhs, rhs| lhs.1.total_cmp(&rhs.1));
    let mut ranks = vec![0.0; values.len()];
    let mut start = 0usize;
    while start < indexed.len() {
        let mut end = start + 1;
        while end < indexed.len() && approx_equal(indexed[end].1, indexed[start].1) {
            end += 1;
        }
        let average_rank = (start + 1 + end) as f64 / 2.0;
        for (original_index, _) in &indexed[start..end] {
            ranks[*original_index] = average_rank;
        }
        start = end;
    }
    ranks
}

fn kendall_tau_b(lhs: &[f64], rhs: &[f64]) -> f64 {
    if lhs.len() <= 1 {
        return f64::NAN;
    }
    let mut concordant: f64 = 0.0;
    let mut discordant: f64 = 0.0;
    let mut tied_lhs: f64 = 0.0;
    let mut tied_rhs: f64 = 0.0;
    for i in 0..lhs.len() {
        for j in (i + 1)..lhs.len() {
            let lhs_order = lhs[i].total_cmp(&lhs[j]);
            let rhs_order = rhs[i].total_cmp(&rhs[j]);
            match (lhs_order, rhs_order) {
                (std::cmp::Ordering::Equal, std::cmp::Ordering::Equal) => {}
                (std::cmp::Ordering::Equal, _) => tied_lhs += 1.0,
                (_, std::cmp::Ordering::Equal) => tied_rhs += 1.0,
                _ if lhs_order == rhs_order => concordant += 1.0,
                _ => discordant += 1.0,
            }
        }
    }
    let denominator =
        ((concordant + discordant + tied_lhs) * (concordant + discordant + tied_rhs)).sqrt();
    if denominator <= f64::EPSILON {
        f64::NAN
    } else {
        zero_small((concordant - discordant) / denominator)
    }
}

fn corr_probability_with_type(
    correlation: f64,
    observations: usize,
    tail: CorrTail,
    corr_type: CorrType,
) -> f64 {
    match corr_type {
        CorrType::Pearson | CorrType::Spearman => corr_probability(correlation, observations, tail),
        CorrType::Kendall => kendall_probability(correlation, observations, tail),
    }
}

fn corr_probability(correlation: f64, observations: usize, tail: CorrTail) -> f64 {
    if !correlation.is_finite() || observations <= 2 {
        return f64::NAN;
    }
    let denominator = 1.0 - correlation * correlation;
    if denominator <= 1e-12 {
        return match tail {
            CorrTail::Both => 0.0,
            CorrTail::Right => {
                if correlation >= 0.0 {
                    0.0
                } else {
                    1.0
                }
            }
            CorrTail::Left => {
                if correlation <= 0.0 {
                    0.0
                } else {
                    1.0
                }
            }
        };
    }
    let dof = (observations - 2) as f64;
    let t_statistic = correlation * (dof / denominator).sqrt();
    let distribution = match StudentsT::new(0.0, 1.0, dof) {
        Ok(distribution) => distribution,
        Err(_) => return f64::NAN,
    };
    match tail {
        CorrTail::Both => (2.0 * (1.0 - distribution.cdf(t_statistic.abs()))).clamp(0.0, 1.0),
        CorrTail::Right => (1.0 - distribution.cdf(t_statistic)).clamp(0.0, 1.0),
        CorrTail::Left => distribution.cdf(t_statistic).clamp(0.0, 1.0),
    }
}

fn kendall_probability(correlation: f64, observations: usize, tail: CorrTail) -> f64 {
    if !correlation.is_finite() || observations <= 1 {
        return f64::NAN;
    }
    let variance = (2.0 * (2 * observations + 5) as f64)
        / (9.0 * observations as f64 * (observations - 1) as f64);
    let z = correlation / variance.sqrt();
    let distribution = match Normal::new(0.0, 1.0) {
        Ok(distribution) => distribution,
        Err(_) => return f64::NAN,
    };
    match tail {
        CorrTail::Both => (2.0 * (1.0 - distribution.cdf(z.abs()))).clamp(0.0, 1.0),
        CorrTail::Right => (1.0 - distribution.cdf(z)).clamp(0.0, 1.0),
        CorrTail::Left => distribution.cdf(z).clamp(0.0, 1.0),
    }
}

fn partialcorr_outputs(
    inputs: &PartialcorrInputs,
) -> Result<(NumericOperand, NumericOperand), RuntimeError> {
    let prepared = if matches!(inputs.options.rows_flag, CorrcoefRowsFlag::Complete) {
        partialcorr_filter_complete_rows(inputs)
    } else {
        inputs.clone()
    };
    let rows = prepared.x.cols;
    let cols = prepared
        .y
        .as_ref()
        .map(|y| y.cols)
        .unwrap_or(prepared.x.cols);
    let mut rho = vec![f64::NAN; rows * cols];
    let mut p = vec![f64::NAN; rows * cols];
    for lhs_col in 0..rows {
        for rhs_col in 0..cols {
            let offset = lhs_col * cols + rhs_col;
            if prepared.y.is_none() && lhs_col == rhs_col {
                rho[offset] = 1.0;
                p[offset] = 0.0;
                continue;
            }
            let pair = match partialcorr_pair_data(&prepared, lhs_col, rhs_col) {
                Some(pair) => pair,
                None => continue,
            };
            let control_count = pair.controls.len();
            let (lhs_values, rhs_values, controls) =
                if matches!(prepared.options.corr_type, CorrType::Spearman) {
                    (
                        tied_ranks(&pair.lhs),
                        tied_ranks(&pair.rhs),
                        pair.controls
                            .into_iter()
                            .map(|values| tied_ranks(&values))
                            .collect::<Vec<_>>(),
                    )
                } else {
                    (pair.lhs, pair.rhs, pair.controls)
                };
            let lhs_residuals = partialcorr_residuals(&lhs_values, &controls)?;
            let rhs_residuals = partialcorr_residuals(&rhs_values, &controls)?;
            let correlation = corr_of_samples(&lhs_residuals, &rhs_residuals);
            rho[offset] = correlation;
            p[offset] = if lhs_residuals.len() <= control_count {
                f64::NAN
            } else {
                corr_probability(
                    correlation,
                    lhs_residuals.len().saturating_sub(control_count),
                    prepared.options.tail,
                )
            };
        }
    }
    Ok((
        NumericOperand {
            rows,
            cols,
            values: rho,
        },
        NumericOperand {
            rows,
            cols,
            values: p,
        },
    ))
}

#[derive(Debug, Clone)]
struct PartialcorrPairData {
    lhs: Vec<f64>,
    rhs: Vec<f64>,
    controls: Vec<Vec<f64>>,
}

fn partialcorr_filter_complete_rows(inputs: &PartialcorrInputs) -> PartialcorrInputs {
    let rows = (0..inputs.x.rows)
        .filter(|row| {
            (0..inputs.x.cols).all(|col| !inputs.x.values[row * inputs.x.cols + col].is_nan())
                && inputs
                    .y
                    .as_ref()
                    .map(|operand| {
                        (0..operand.cols)
                            .all(|col| !operand.values[row * operand.cols + col].is_nan())
                    })
                    .unwrap_or(true)
                && inputs
                    .z
                    .as_ref()
                    .map(|operand| {
                        (0..operand.cols)
                            .all(|col| !operand.values[row * operand.cols + col].is_nan())
                    })
                    .unwrap_or(true)
        })
        .collect::<Vec<_>>();
    PartialcorrInputs {
        x: filter_numeric_operand_rows(&inputs.x, &rows),
        y: inputs
            .y
            .as_ref()
            .map(|operand| filter_numeric_operand_rows(operand, &rows)),
        z: inputs
            .z
            .as_ref()
            .map(|operand| filter_numeric_operand_rows(operand, &rows)),
        options: inputs.options,
    }
}

fn partialcorr_pair_data(
    inputs: &PartialcorrInputs,
    lhs_col: usize,
    rhs_col: usize,
) -> Option<PartialcorrPairData> {
    let rhs_operand = inputs.y.as_ref().unwrap_or(&inputs.x);
    let controls = partialcorr_control_columns(inputs, lhs_col, rhs_col);
    let mut lhs = Vec::new();
    let mut rhs = Vec::new();
    let mut control_values = vec![Vec::new(); controls.len()];
    for row in 0..inputs.x.rows {
        let lhs_value = inputs.x.values[row * inputs.x.cols + lhs_col];
        let rhs_value = rhs_operand.values[row * rhs_operand.cols + rhs_col];
        let mut values = vec![lhs_value, rhs_value];
        values.extend(
            controls
                .iter()
                .map(|(operand, col)| operand.values[row * operand.cols + col]),
        );
        if values.iter().any(|value| value.is_nan()) {
            if matches!(inputs.options.rows_flag, CorrcoefRowsFlag::All) {
                return None;
            }
            continue;
        }
        lhs.push(lhs_value);
        rhs.push(rhs_value);
        for (index, (operand, col)) in controls.iter().enumerate() {
            control_values[index].push(operand.values[row * operand.cols + col]);
        }
    }
    Some(PartialcorrPairData {
        lhs,
        rhs,
        controls: control_values,
    })
}

fn partialcorr_control_columns(
    inputs: &PartialcorrInputs,
    lhs_col: usize,
    rhs_col: usize,
) -> Vec<(&NumericOperand, usize)> {
    let mut controls = Vec::new();
    if inputs.y.is_none() && inputs.z.is_none() {
        for col in 0..inputs.x.cols {
            if col != lhs_col && col != rhs_col {
                controls.push((&inputs.x, col));
            }
        }
    }
    if let Some(z) = &inputs.z {
        for col in 0..z.cols {
            controls.push((z, col));
        }
    }
    controls
}

fn partialcorr_residuals(target: &[f64], controls: &[Vec<f64>]) -> Result<Vec<f64>, RuntimeError> {
    if controls.is_empty() {
        return Ok(target.to_vec());
    }
    let rows = target.len();
    let cols = controls.len() + 1;
    let mut design_values = Vec::with_capacity(rows * cols);
    for row in 0..rows {
        design_values.push(ComplexParts::one());
        for control in controls {
            design_values.push(ComplexParts {
                real: control[row],
                imag: 0.0,
            });
        }
    }
    let design = NumericOrComplexOperand {
        rows,
        cols,
        values: design_values,
    };
    let target_operand = NumericOrComplexOperand {
        rows,
        cols: 1,
        values: target
            .iter()
            .copied()
            .map(|value| ComplexParts {
                real: value,
                imag: 0.0,
            })
            .collect(),
    };
    let tolerance = default_rank_tolerance(&design)?.max(1e-12);
    let pseudoinverse =
        pseudoinverse_numeric_or_complex_operand(&design, tolerance, "partialcorr")?;
    let coefficients = matrix_multiply_operands(&pseudoinverse, &target_operand, "partialcorr")?;
    let fitted = matrix_multiply_operands(&design, &coefficients, "partialcorr")?;
    Ok(target
        .iter()
        .zip(fitted.values.iter())
        .map(|(observed, fitted)| observed - fitted.real)
        .collect())
}

fn nan_numeric_operand(size: usize) -> NumericOperand {
    NumericOperand {
        rows: size,
        cols: size,
        values: vec![f64::NAN; size * size],
    }
}

fn reduce_truth_value(
    value: &Value,
    name: &str,
    reducer: impl Fn(&[f64]) -> bool,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(logical_scalar(*number != 0.0)),
        Value::Logical(flag) => Ok(logical_scalar(*flag)),
        Value::Matrix(matrix) => {
            let input_dims = canonical_size_vector(matrix.dims());
            if matrix.rows != 0 && matrix.cols != 0 && input_dims.len() > 2 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                let dimension = default_reduction_dimension_from_dims(&input_dims);
                let (output_dims, reduced_values) =
                    reduce_numeric_slices_nd_values(&values, &input_dims, dimension, |sample| {
                        if reducer(sample) {
                            1.0
                        } else {
                            0.0
                        }
                    });
                return logical_matrix_result_with_dimensions(
                    output_dims,
                    reduced_values
                        .into_iter()
                        .map(|value| value != 0.0)
                        .collect(),
                );
            }

            if matrix.rows == 0 || matrix.cols == 0 {
                return Ok(logical_scalar(false));
            }

            if matrix.rows == 1 || matrix.cols == 1 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                return Ok(logical_scalar(reducer(&values)));
            }

            let mut cols = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let mut values = Vec::with_capacity(matrix.rows);
                for row in 0..matrix.rows {
                    values.push(matrix.get(row, col).as_scalar()?);
                }
                cols.push(logical_scalar(reducer(&values)));
            }
            Ok(Value::Matrix(MatrixValue::new(1, matrix.cols, cols)?))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric scalar or matrix input"
        ))),
    }
}

fn reduce_truth_value_along_dimension(
    value: &Value,
    name: &str,
    dim: usize,
    reducer: impl Fn(&[f64]) -> bool,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(logical_scalar(*number != 0.0)),
        Value::Logical(flag) => Ok(logical_scalar(*flag)),
        Value::Matrix(matrix) => {
            let input_dims = canonical_size_vector(matrix.dims());
            if input_dims.len() > 2 || dim > 2 {
                let values = matrix
                    .iter()
                    .map(Value::as_scalar)
                    .collect::<Result<Vec<_>, _>>()?;
                if dim > input_dims.len() {
                    return logical_matrix_result_with_dimensions(
                        input_dims,
                        values.into_iter().map(|value| value != 0.0).collect(),
                    );
                }
                let (output_dims, reduced_values) =
                    reduce_numeric_slices_nd_values(&values, &input_dims, dim, |sample| {
                        if reducer(sample) {
                            1.0
                        } else {
                            0.0
                        }
                    });
                return logical_matrix_result_with_dimensions(
                    output_dims,
                    reduced_values
                        .into_iter()
                        .map(|value| value != 0.0)
                        .collect(),
                );
            }

            if matrix.rows == 0 || matrix.cols == 0 {
                return Ok(logical_scalar(false));
            }

            if dim > 2 {
                return build_scalar_matrix_result(
                    matrix.rows,
                    matrix.cols,
                    matrix
                        .iter()
                        .map(|value| Ok(logical_scalar(value.as_scalar()? != 0.0)))
                        .collect::<Result<Vec<_>, RuntimeError>>()?,
                );
            }

            match dim {
                1 => {
                    let mut cols = Vec::with_capacity(matrix.cols);
                    for col in 0..matrix.cols {
                        let mut values = Vec::with_capacity(matrix.rows);
                        for row in 0..matrix.rows {
                            values.push(matrix.get(row, col).as_scalar()?);
                        }
                        cols.push(logical_scalar(reducer(&values)));
                    }
                    Ok(Value::Matrix(MatrixValue::new(1, matrix.cols, cols)?))
                }
                2 => {
                    let mut rows = Vec::with_capacity(matrix.rows);
                    for row in 0..matrix.rows {
                        let mut values = Vec::with_capacity(matrix.cols);
                        for col in 0..matrix.cols {
                            values.push(matrix.get(row, col).as_scalar()?);
                        }
                        rows.push(logical_scalar(reducer(&values)));
                    }
                    Ok(Value::Matrix(MatrixValue::new(matrix.rows, 1, rows)?))
                }
                _ => unreachable!("dim > 2 handled above"),
            }
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric scalar or matrix input"
        ))),
    }
}

fn reduce_truth_value_all(
    value: &Value,
    name: &str,
    reducer: impl Fn(&[f64]) -> bool,
) -> Result<Value, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(logical_scalar(*number != 0.0)),
        Value::Logical(flag) => Ok(logical_scalar(*flag)),
        Value::Matrix(matrix) => {
            if matrix.rows == 0 || matrix.cols == 0 {
                return Ok(logical_scalar(false));
            }
            let values = matrix
                .iter()
                .map(Value::as_scalar)
                .collect::<Result<Vec<_>, _>>()?;
            Ok(logical_scalar(reducer(&values)))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{name} currently expects numeric scalar or matrix input"
        ))),
    }
}

#[derive(Clone)]
struct FindMatchEntry {
    row: usize,
    col: usize,
    linear_index: usize,
    value: Value,
}

struct FindMatches {
    row_output: bool,
    empty_matrix_input: bool,
    entries: Vec<FindMatchEntry>,
}

#[derive(Clone, Copy)]
enum FindDirection {
    First,
    Last,
}

fn find_matches(value: &Value) -> Result<FindMatches, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(FindMatches {
            row_output: false,
            empty_matrix_input: false,
            entries: if *number != 0.0 {
                vec![FindMatchEntry {
                    row: 1,
                    col: 1,
                    linear_index: 1,
                    value: Value::Scalar(*number),
                }]
            } else {
                Vec::new()
            },
        }),
        Value::Logical(flag) => Ok(FindMatches {
            row_output: false,
            empty_matrix_input: false,
            entries: if *flag {
                vec![FindMatchEntry {
                    row: 1,
                    col: 1,
                    linear_index: 1,
                    value: Value::Logical(*flag),
                }]
            } else {
                Vec::new()
            },
        }),
        Value::Complex(number) => Ok(FindMatches {
            row_output: false,
            empty_matrix_input: false,
            entries: if number.real != 0.0 || number.imag != 0.0 {
                vec![FindMatchEntry {
                    row: 1,
                    col: 1,
                    linear_index: 1,
                    value: Value::Complex(number.clone()),
                }]
            } else {
                Vec::new()
            },
        }),
        Value::Matrix(matrix) => {
            let mut entries = Vec::new();
            for (position, element) in matrix.elements().iter().enumerate() {
                if find_value_is_nonzero(element)? {
                    let row = position / matrix.cols;
                    let col = position % matrix.cols;
                    let index = row_major_multi_index(position, matrix.dims());
                    entries.push(FindMatchEntry {
                        row: row + 1,
                        col: col + 1,
                        linear_index: column_major_linear_index_one_based(&index, matrix.dims()),
                        value: element.clone(),
                    });
                }
            }
            entries.sort_by_key(|entry| entry.linear_index);
            Ok(FindMatches {
                row_output: matrix.rows == 1 && canonical_size_vector(&matrix.dims).len() <= 2,
                empty_matrix_input: matrix.rows == 0 && matrix.cols == 0,
                entries,
            })
        }
        Value::CharArray(text) => Ok(FindMatches {
            row_output: true,
            empty_matrix_input: false,
            entries: text
                .chars()
                .enumerate()
                .map(|(offset, ch)| FindMatchEntry {
                    row: 1,
                    col: offset + 1,
                    linear_index: offset + 1,
                    value: Value::CharArray(ch.to_string()),
                })
                .collect(),
        }),
        _ => Err(RuntimeError::TypeError(
            "find currently expects scalar, matrix, or char array input".to_string(),
        )),
    }
}

fn matrix_is_numeric_like(matrix: &MatrixValue) -> bool {
    matrix.iter().all(|element| {
        matches!(
            element,
            Value::Scalar(_) | Value::Logical(_) | Value::Complex(_)
        )
    })
}

fn parse_find_arguments(
    args: &[Value],
) -> Result<(&Value, Option<usize>, FindDirection), RuntimeError> {
    match args {
        [value] => Ok((value, None, FindDirection::First)),
        [value, count] => Ok((value, Some(scalar_dimension(count)?), FindDirection::First)),
        [value, count, direction] => Ok((
            value,
            Some(scalar_dimension(count)?),
            parse_find_direction(direction)?,
        )),
        _ => Err(RuntimeError::Unsupported(
            "find currently supports `find(x)`, `find(x, n)`, or `find(x, n, direction)`"
                .to_string(),
        )),
    }
}

fn parse_find_direction(value: &Value) -> Result<FindDirection, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "first" => Ok(FindDirection::First),
        "last" => Ok(FindDirection::Last),
        other => Err(RuntimeError::Unsupported(format!(
            "find direction `{other}` is not implemented; expected first or last"
        ))),
    }
}

fn select_find_matches(
    matches: &FindMatches,
    count: Option<usize>,
    direction: FindDirection,
) -> Vec<FindMatchEntry> {
    let count = count
        .unwrap_or(matches.entries.len())
        .min(matches.entries.len());
    match direction {
        FindDirection::First => matches.entries.iter().take(count).cloned().collect(),
        FindDirection::Last => matches
            .entries
            .iter()
            .skip(matches.entries.len().saturating_sub(count))
            .cloned()
            .collect(),
    }
}

fn find_value_is_nonzero(value: &Value) -> Result<bool, RuntimeError> {
    match value {
        Value::Scalar(number) => Ok(*number != 0.0),
        Value::Logical(flag) => Ok(*flag),
        Value::Complex(number) => Ok(number.real != 0.0 || number.imag != 0.0),
        Value::CharArray(text) => Ok(!text.is_empty()),
        other => Ok(other.as_scalar()? != 0.0),
    }
}

fn find_empty_result(row_output: bool, empty_matrix_input: bool) -> Result<Value, RuntimeError> {
    if empty_matrix_input {
        return Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?));
    }
    Ok(Value::Matrix(MatrixValue::new(
        if row_output { 1 } else { 0 },
        if row_output { 0 } else { 1 },
        Vec::new(),
    )?))
}

fn find_indices_to_value(
    indices: Vec<usize>,
    row_output: bool,
    empty_matrix_input: bool,
) -> Result<Value, RuntimeError> {
    match indices.len() {
        0 => find_empty_result(row_output, empty_matrix_input),
        1 => Ok(Value::Scalar(indices[0] as f64)),
        count => Ok(Value::Matrix(MatrixValue::new(
            if row_output { 1 } else { count },
            if row_output { count } else { 1 },
            indices
                .into_iter()
                .map(|index| Value::Scalar(index as f64))
                .collect(),
        )?)),
    }
}

fn indices_to_value(indices: Vec<usize>, row_output: bool) -> Result<Value, RuntimeError> {
    match indices.len() {
        0 => Ok(Value::Matrix(MatrixValue::new(0, 0, Vec::new())?)),
        1 => Ok(Value::Scalar(indices[0] as f64)),
        count => Ok(Value::Matrix(MatrixValue::new(
            if row_output { 1 } else { count },
            if row_output { count } else { 1 },
            indices
                .into_iter()
                .map(|index| Value::Scalar(index as f64))
                .collect(),
        )?)),
    }
}

fn find_values_to_value(
    values: Vec<Value>,
    row_output: bool,
    empty_matrix_input: bool,
) -> Result<Value, RuntimeError> {
    match values.len() {
        0 => find_empty_result(row_output, empty_matrix_input),
        1 => Ok(values.into_iter().next().expect("single find value")),
        _ if values
            .iter()
            .all(|value| matches!(value, Value::CharArray(text) if text.chars().count() == 1))
            && row_output =>
        {
            Ok(Value::CharArray(
                values
                    .into_iter()
                    .map(|value| match value {
                        Value::CharArray(text) => text,
                        _ => unreachable!("checked char scalar values"),
                    })
                    .collect::<String>(),
            ))
        }
        count => Ok(Value::Matrix(MatrixValue::new(
            if row_output { 1 } else { count },
            if row_output { count } else { 1 },
            values,
        )?)),
    }
}

fn scalar_dimension(value: &Value) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::InvalidIndex(format!(
            "expected positive integer dimension, found {scalar}"
        )));
    }
    Ok(scalar as usize)
}

fn positive_integer_scalar(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 1.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a positive integer scalar bin count"
        )));
    }
    Ok(scalar as usize)
}

fn positive_integer_scalar_with_label(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 1.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects {label}"
        )));
    }
    Ok(scalar as usize)
}

fn nonzero_integer_scalar_with_label(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<isize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar == 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects {label}"
        )));
    }
    Ok(scalar as isize)
}

fn nonnegative_integer_scalar_with_label(
    value: &Value,
    builtin_name: &str,
    label: &str,
) -> Result<usize, RuntimeError> {
    let scalar = value.as_scalar()?;
    if !scalar.is_finite() || scalar < 0.0 || scalar.fract() != 0.0 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects {label}"
        )));
    }
    Ok(scalar as usize)
}

fn positive_dimension(value: &Value, builtin_name: &str) -> Result<usize, RuntimeError> {
    let dimension = scalar_dimension(value)?;
    if dimension < 1 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects a positive integer dimension"
        )));
    }
    Ok(dimension)
}

fn parse_variance_normalization(
    value: &Value,
    builtin_name: &str,
) -> Result<VarianceNormalization, RuntimeError> {
    let scalar = value.as_scalar()?;
    if approx_equal(scalar, 0.0) {
        return Ok(VarianceNormalization::Sample);
    }
    if approx_equal(scalar, 1.0) {
        return Ok(VarianceNormalization::Population);
    }
    Err(RuntimeError::TypeError(format!(
        "{builtin_name} currently expects normalization flag w = 0 or 1"
    )))
}

fn positive_integer_pair(value: &Value, builtin_name: &str) -> Result<[usize; 2], RuntimeError> {
    let values = meshgrid_vector(value)?;
    if values.len() != 2 {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects a two-element positive integer vector"
        )));
    }
    let rows = positive_integer_scalar(&Value::Scalar(values[0]), builtin_name)?;
    let cols = positive_integer_scalar(&Value::Scalar(values[1]), builtin_name)?;
    Ok([rows, cols])
}

fn tile_matrix_nd(
    matrix: &MatrixValue,
    repetitions: &[usize],
) -> Result<MatrixValue, RuntimeError> {
    let output_dims = repeated_dimensions(&matrix.dims, repetitions);
    let elements = tile_elements_nd(&matrix.elements, &matrix.dims, repetitions);
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    MatrixValue::with_dimensions(rows, cols, output_dims, elements)
}

fn tile_cell_nd(cell: &CellValue, repetitions: &[usize]) -> Result<CellValue, RuntimeError> {
    let output_dims = repeated_dimensions(&cell.dims, repetitions);
    let elements = tile_elements_nd(&cell.elements, &cell.dims, repetitions);
    let (rows, cols) = storage_shape_from_dimensions(&output_dims);
    CellValue::with_dimensions(rows, cols, output_dims, elements)
}

fn repeated_dimensions(input_dims: &[usize], repetitions: &[usize]) -> Vec<usize> {
    let rank = input_dims.len().max(repetitions.len()).max(2);
    (0..rank)
        .map(|axis| {
            let dim = input_dims.get(axis).copied().unwrap_or(1);
            let rep = repetitions.get(axis).copied().unwrap_or(1);
            dim * rep
        })
        .collect()
}

fn tile_elements_nd<T: Clone>(
    elements: &[T],
    input_dims: &[usize],
    repetitions: &[usize],
) -> Vec<T> {
    let output_dims = repeated_dimensions(input_dims, repetitions);
    let output_len = output_dims.iter().product::<usize>();
    if output_len == 0 {
        return Vec::new();
    }
    let mut normalized_input_dims = input_dims.to_vec();
    while normalized_input_dims.len() < output_dims.len() {
        normalized_input_dims.push(1);
    }
    let mut output = vec![elements[0].clone(); output_len];
    for linear in 0..output_len {
        let output_index = row_major_multi_index(linear, &output_dims);
        let input_index = output_index
            .iter()
            .enumerate()
            .map(|(axis, &value)| value % normalized_input_dims[axis])
            .collect::<Vec<_>>();
        let input_linear = row_major_linear_index(&input_index, &normalized_input_dims);
        output[linear] = elements[input_linear].clone();
    }
    output
}

fn tile_char_array(text: &str, repetitions: &[usize]) -> Result<Value, RuntimeError> {
    let input_dims = value_dimensions(&Value::CharArray(text.to_string()));
    let output_dims = repeated_dimensions(&input_dims, repetitions);
    let elements = tile_elements_nd(&text.chars().collect::<Vec<_>>(), &input_dims, repetitions);
    char_value_with_dimensions(output_dims, elements)
}

fn sorted_value_and_indices(
    value: &Value,
    options: SortOptions,
) -> Result<(Value, Value), RuntimeError> {
    match value {
        Value::Scalar(number) => Ok((Value::Scalar(*number), Value::Scalar(1.0))),
        Value::Logical(flag) => Ok((Value::Logical(*flag), Value::Scalar(1.0))),
        Value::String(text) => Ok((Value::String(text.clone()), Value::Scalar(1.0))),
        Value::CharArray(_) => {
            sorted_value_and_indices(&Value::Matrix(coerce_char_matrix(value)?), options)
        }
        Value::Cell(cell) => {
            let matrix = text_cell_matrix(cell, "sort")?;
            let (sorted_value, indices) =
                sorted_value_and_indices(&Value::Matrix(matrix), options)?;
            let sorted_value = match sorted_value {
                Value::Matrix(matrix) if matrix_is_text(&matrix) => {
                    Value::Cell(CellValue::with_dimensions(
                        matrix.rows,
                        matrix.cols,
                        matrix.dims().to_vec(),
                        matrix.elements().to_vec(),
                    )?)
                }
                other => other,
            };
            return Ok((sorted_value, indices));
        }
        Value::Matrix(matrix) => {
            if matrix.rows == 0 || matrix.cols == 0 {
                let empty = MatrixValue::new(matrix.rows, matrix.cols, Vec::new())?;
                return Ok((Value::Matrix(empty.clone()), Value::Matrix(empty)));
            }

            let input_dims = canonical_size_vector(matrix.dims());
            let dim = options
                .dim
                .unwrap_or_else(|| default_reduction_dimension_from_dims(&input_dims));

            if matrix_is_text(matrix) {
                if input_dims.len() > 2 || dim > 2 {
                    return sort_text_matrix_nd(matrix, &input_dims, dim, options.descending);
                }
            } else {
                let logical = matrix_is_logical(matrix);
                let complex = matrix_is_numeric_or_complex(matrix) && !matrix_is_numeric(matrix);
                if !(matrix_is_numeric(matrix) || logical || complex) {
                    return Err(RuntimeError::TypeError(
                        "sort currently expects numeric, logical, or complex scalar/matrix input"
                            .to_string(),
                    ));
                }
                if complex && (input_dims.len() > 2 || dim > 2) {
                    return sort_complex_matrix_nd(
                        matrix,
                        &input_dims,
                        dim,
                        options.descending,
                        options.missing_placement,
                        options.comparison_method,
                    );
                }
                if !complex && (input_dims.len() > 2 || dim > 2) {
                    return sort_numeric_matrix_nd(
                        matrix,
                        &input_dims,
                        dim,
                        options.descending,
                        options.missing_placement,
                        options.comparison_method,
                    );
                }
            }

            if matrix_is_text(matrix) {
                let operand = text_operand(value)?;
                let mut sorted_values = operand.values.clone();
                let mut sorted_prototypes = operand.prototypes.clone();
                let mut index_elements = vec![Value::Scalar(0.0); matrix.rows * matrix.cols];
                match dim {
                    1 => {
                        for col in 0..matrix.cols {
                            let values = (0..matrix.rows)
                                .map(|row| operand.values[row * matrix.cols + col].clone())
                                .collect::<Vec<_>>();
                            let prototypes = (0..matrix.rows)
                                .map(|row| operand.prototypes[row * matrix.cols + col])
                                .collect::<Vec<_>>();
                            let (sorted, sorted_proto, indices) =
                                sorted_text_with_indices(&values, &prototypes, options.descending);
                            for row in 0..matrix.rows {
                                sorted_values[row * matrix.cols + col] = sorted[row].clone();
                                sorted_prototypes[row * matrix.cols + col] = sorted_proto[row];
                                index_elements[row * matrix.cols + col] =
                                    Value::Scalar(indices[row] as f64);
                            }
                        }
                    }
                    2 => {
                        for row in 0..matrix.rows {
                            let row_start = row * matrix.cols;
                            let values =
                                operand.values[row_start..row_start + matrix.cols].to_vec();
                            let prototypes =
                                operand.prototypes[row_start..row_start + matrix.cols].to_vec();
                            let (sorted, sorted_proto, indices) =
                                sorted_text_with_indices(&values, &prototypes, options.descending);
                            for col in 0..matrix.cols {
                                sorted_values[row_start + col] = sorted[col].clone();
                                sorted_prototypes[row_start + col] = sorted_proto[col];
                                index_elements[row_start + col] =
                                    Value::Scalar(indices[col] as f64);
                            }
                        }
                    }
                    _ => {
                        index_elements = vec![Value::Scalar(1.0); matrix.rows * matrix.cols];
                    }
                }
                return Ok((
                    build_text_result_preserving_char_identity(
                        matrix.rows,
                        matrix.cols,
                        sorted_values,
                        sorted_prototypes,
                    )?,
                    build_scalar_matrix_result(matrix.rows, matrix.cols, index_elements)?,
                ));
            }

            let logical = matrix_is_logical(matrix);
            let complex = matrix_is_numeric_or_complex(matrix) && !matrix_is_numeric(matrix);
            if complex {
                let mut sorted_values = vec![ComplexParts::zero(); matrix.rows * matrix.cols];
                let mut index_elements = vec![Value::Scalar(0.0); matrix.rows * matrix.cols];
                match dim {
                    1 => {
                        for col in 0..matrix.cols {
                            let values = (0..matrix.rows)
                                .map(|row| numeric_or_complex_scalar(matrix.get(row, col), "sort"))
                                .collect::<Result<Vec<_>, _>>()?;
                            let (sorted, indices) = sorted_complex_with_indices(
                                &values,
                                options.descending,
                                options.missing_placement,
                                options.comparison_method,
                                true,
                            );
                            for row in 0..matrix.rows {
                                sorted_values[row * matrix.cols + col] = sorted[row];
                                index_elements[row * matrix.cols + col] =
                                    Value::Scalar(indices[row] as f64);
                            }
                        }
                    }
                    2 => {
                        for row in 0..matrix.rows {
                            let values = (0..matrix.cols)
                                .map(|col| numeric_or_complex_scalar(matrix.get(row, col), "sort"))
                                .collect::<Result<Vec<_>, _>>()?;
                            let (sorted, indices) = sorted_complex_with_indices(
                                &values,
                                options.descending,
                                options.missing_placement,
                                options.comparison_method,
                                true,
                            );
                            for col in 0..matrix.cols {
                                sorted_values[row * matrix.cols + col] = sorted[col];
                                index_elements[row * matrix.cols + col] =
                                    Value::Scalar(indices[col] as f64);
                            }
                        }
                    }
                    _ => {
                        sorted_values = matrix
                            .iter()
                            .map(|element| numeric_or_complex_scalar(element, "sort"))
                            .collect::<Result<Vec<_>, _>>()?;
                        index_elements = vec![Value::Scalar(1.0); matrix.rows * matrix.cols];
                    }
                }
                return Ok((
                    build_numeric_or_complex_matrix_result(
                        matrix.rows,
                        matrix.cols,
                        sorted_values,
                    )?,
                    build_scalar_matrix_result(matrix.rows, matrix.cols, index_elements)?,
                ));
            }

            let mut sorted_elements = vec![
                if logical {
                    Value::Logical(false)
                } else {
                    Value::Scalar(0.0)
                };
                matrix.rows * matrix.cols
            ];
            let mut index_elements = vec![Value::Scalar(0.0); matrix.rows * matrix.cols];
            match dim {
                1 => {
                    for col in 0..matrix.cols {
                        let values = (0..matrix.rows)
                            .map(|row| matrix.get(row, col).as_scalar())
                            .collect::<Result<Vec<_>, _>>()?;
                        let (sorted, indices) = sorted_numeric_with_indices(
                            &values,
                            options.descending,
                            options.missing_placement,
                            options.comparison_method,
                        );
                        for row in 0..matrix.rows {
                            sorted_elements[row * matrix.cols + col] = if logical {
                                Value::Logical(sorted[row] != 0.0)
                            } else {
                                Value::Scalar(sorted[row])
                            };
                            index_elements[row * matrix.cols + col] =
                                Value::Scalar(indices[row] as f64);
                        }
                    }
                }
                2 => {
                    for row in 0..matrix.rows {
                        let values = (0..matrix.cols)
                            .map(|col| matrix.get(row, col).as_scalar())
                            .collect::<Result<Vec<_>, _>>()?;
                        let (sorted, indices) = sorted_numeric_with_indices(
                            &values,
                            options.descending,
                            options.missing_placement,
                            options.comparison_method,
                        );
                        for col in 0..matrix.cols {
                            sorted_elements[row * matrix.cols + col] = if logical {
                                Value::Logical(sorted[col] != 0.0)
                            } else {
                                Value::Scalar(sorted[col])
                            };
                            index_elements[row * matrix.cols + col] =
                                Value::Scalar(indices[col] as f64);
                        }
                    }
                }
                _ => {
                    sorted_elements = matrix.iter().cloned().collect::<Vec<_>>();
                    index_elements = vec![Value::Scalar(1.0); matrix.rows * matrix.cols];
                }
            }
            Ok((
                build_scalar_matrix_result(matrix.rows, matrix.cols, sorted_elements)?,
                build_scalar_matrix_result(matrix.rows, matrix.cols, index_elements)?,
            ))
        }
        _ => Err(RuntimeError::TypeError(
            "sort currently expects numeric, logical, or complex scalar/matrix input".to_string(),
        )),
    }
}

fn sort_text_matrix_nd(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
) -> Result<(Value, Value), RuntimeError> {
    let operand = text_operand(&Value::Matrix(matrix.clone()))?;
    if dim > input_dims.len() {
        return Ok((
            build_text_result_with_dimensions(
                input_dims.to_vec(),
                operand.values.clone(),
                operand.prototypes.clone(),
                false,
            )?,
            build_scalar_matrix_result_with_dimensions(
                input_dims.to_vec(),
                vec![Value::Scalar(1.0); operand.values.len()],
            )?,
        ));
    }

    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();
    let mut sorted_values = vec![String::new(); operand.values.len()];
    let mut sorted_prototypes = vec![TextPrototype::String; operand.values.len()];
    let mut index_values = vec![Value::Scalar(0.0); operand.values.len()];

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let mut values = Vec::with_capacity(axis_len);
        let mut prototypes = Vec::with_capacity(axis_len);
        for axis_index in 0..axis_len {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            values.push(operand.values[offset].clone());
            prototypes.push(operand.prototypes[offset]);
        }
        let (sorted, sorted_proto, indices) =
            sorted_text_with_indices(&values, &prototypes, descending);
        for axis_index in 0..axis_len {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            sorted_values[offset] = sorted[axis_index].clone();
            sorted_prototypes[offset] = sorted_proto[axis_index];
            index_values[offset] = Value::Scalar(indices[axis_index] as f64);
        }
    }

    Ok((
        build_text_result_with_dimensions(
            input_dims.to_vec(),
            sorted_values,
            sorted_prototypes,
            false,
        )?,
        build_scalar_matrix_result_with_dimensions(input_dims.to_vec(), index_values)?,
    ))
}

fn sort_numeric_matrix_nd(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<(Value, Value), RuntimeError> {
    let logical = matrix_is_logical(matrix);
    if dim > input_dims.len() {
        return Ok((
            build_scalar_matrix_result_with_dimensions(
                input_dims.to_vec(),
                matrix.elements().to_vec(),
            )?,
            build_scalar_matrix_result_with_dimensions(
                input_dims.to_vec(),
                vec![Value::Scalar(1.0); matrix.element_count()],
            )?,
        ));
    }

    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();
    let mut sorted_elements = vec![
        if logical {
            Value::Logical(false)
        } else {
            Value::Scalar(0.0)
        };
        matrix.element_count()
    ];
    let mut index_values = vec![Value::Scalar(0.0); matrix.element_count()];

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                matrix.elements[row_major_linear_index(&index, input_dims)].as_scalar()
            })
            .collect::<Result<Vec<_>, _>>()?;
        let (sorted, indices) =
            sorted_numeric_with_indices(&values, descending, missing_placement, comparison_method);
        for axis_index in 0..axis_len {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            sorted_elements[offset] = if logical {
                Value::Logical(sorted[axis_index] != 0.0)
            } else {
                Value::Scalar(sorted[axis_index])
            };
            index_values[offset] = Value::Scalar(indices[axis_index] as f64);
        }
    }

    Ok((
        build_scalar_matrix_result_with_dimensions(input_dims.to_vec(), sorted_elements)?,
        build_scalar_matrix_result_with_dimensions(input_dims.to_vec(), index_values)?,
    ))
}

fn sort_complex_matrix_nd(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<(Value, Value), RuntimeError> {
    if dim > input_dims.len() {
        return Ok((
            build_numeric_or_complex_matrix_result_with_dimensions(
                input_dims.to_vec(),
                matrix
                    .iter()
                    .map(|element| numeric_or_complex_scalar(element, "sort"))
                    .collect::<Result<Vec<_>, _>>()?,
            )?,
            build_scalar_matrix_result_with_dimensions(
                input_dims.to_vec(),
                vec![Value::Scalar(1.0); matrix.element_count()],
            )?,
        ));
    }

    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();
    let mut sorted_values = vec![ComplexParts::zero(); matrix.element_count()];
    let mut index_values = vec![Value::Scalar(0.0); matrix.element_count()];

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                numeric_or_complex_scalar(
                    &matrix.elements[row_major_linear_index(&index, input_dims)],
                    "sort",
                )
            })
            .collect::<Result<Vec<_>, _>>()?;
        let (sorted, indices) = sorted_complex_with_indices(
            &values,
            descending,
            missing_placement,
            comparison_method,
            true,
        );
        for axis_index in 0..axis_len {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            sorted_values[offset] = sorted[axis_index];
            index_values[offset] = Value::Scalar(indices[axis_index] as f64);
        }
    }

    Ok((
        build_numeric_or_complex_matrix_result_with_dimensions(input_dims.to_vec(), sorted_values)?,
        build_scalar_matrix_result_with_dimensions(input_dims.to_vec(), index_values)?,
    ))
}

fn bounds_value_and_range(
    matrix: &MatrixValue,
    dim: usize,
    missing_flag: BoundsMissingFlag,
) -> Result<(Value, Value), RuntimeError> {
    if matrix.rows == 1 && matrix.cols == 1 {
        let scalar = matrix.get(0, 0).as_scalar()?;
        return Ok((Value::Scalar(scalar), Value::Scalar(scalar)));
    }

    match dim {
        1 => {
            let mut lower = Vec::with_capacity(matrix.cols);
            let mut upper = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let values = (0..matrix.rows)
                    .map(|row| matrix.get(row, col).as_scalar())
                    .collect::<Result<Vec<_>, _>>()?;
                let (min_value, max_value) = bounds_min_max(&values, missing_flag);
                lower.push(Value::Scalar(min_value));
                upper.push(Value::Scalar(max_value));
            }
            if matrix.cols == 1 {
                return Ok((lower[0].clone(), upper[0].clone()));
            }
            Ok((
                Value::Matrix(MatrixValue::new(1, matrix.cols, lower)?),
                Value::Matrix(MatrixValue::new(1, matrix.cols, upper)?),
            ))
        }
        2 => {
            let mut lower = Vec::with_capacity(matrix.rows);
            let mut upper = Vec::with_capacity(matrix.rows);
            for row in 0..matrix.rows {
                let values = (0..matrix.cols)
                    .map(|col| matrix.get(row, col).as_scalar())
                    .collect::<Result<Vec<_>, _>>()?;
                let (min_value, max_value) = bounds_min_max(&values, missing_flag);
                lower.push(Value::Scalar(min_value));
                upper.push(Value::Scalar(max_value));
            }
            if matrix.rows == 1 {
                return Ok((lower[0].clone(), upper[0].clone()));
            }
            Ok((
                Value::Matrix(MatrixValue::new(matrix.rows, 1, lower)?),
                Value::Matrix(MatrixValue::new(matrix.rows, 1, upper)?),
            ))
        }
        _ => {
            let values = matrix.iter().cloned().collect::<Vec<_>>();
            let result = build_scalar_matrix_result(matrix.rows, matrix.cols, values)?;
            Ok((result.clone(), result))
        }
    }
}

fn bounds_value_and_range_complex(
    matrix: &MatrixValue,
    dim: usize,
    missing_flag: BoundsMissingFlag,
) -> Result<(Value, Value), RuntimeError> {
    if matrix.rows == 1 && matrix.cols == 1 {
        let scalar = numeric_or_complex_scalar(matrix.get(0, 0), "bounds")?;
        return Ok((
            numeric_or_complex_value(scalar),
            numeric_or_complex_value(scalar),
        ));
    }

    match dim {
        1 => {
            let mut lower = Vec::with_capacity(matrix.cols);
            let mut upper = Vec::with_capacity(matrix.cols);
            for col in 0..matrix.cols {
                let values = (0..matrix.rows)
                    .map(|row| numeric_or_complex_scalar(matrix.get(row, col), "bounds"))
                    .collect::<Result<Vec<_>, _>>()?;
                let (min_value, max_value) = bounds_complex_min_max(&values, missing_flag);
                lower.push(numeric_or_complex_value(min_value));
                upper.push(numeric_or_complex_value(max_value));
            }
            if matrix.cols == 1 {
                return Ok((lower[0].clone(), upper[0].clone()));
            }
            Ok((
                Value::Matrix(MatrixValue::new(1, matrix.cols, lower)?),
                Value::Matrix(MatrixValue::new(1, matrix.cols, upper)?),
            ))
        }
        2 => {
            let mut lower = Vec::with_capacity(matrix.rows);
            let mut upper = Vec::with_capacity(matrix.rows);
            for row in 0..matrix.rows {
                let values = (0..matrix.cols)
                    .map(|col| numeric_or_complex_scalar(matrix.get(row, col), "bounds"))
                    .collect::<Result<Vec<_>, _>>()?;
                let (min_value, max_value) = bounds_complex_min_max(&values, missing_flag);
                lower.push(numeric_or_complex_value(min_value));
                upper.push(numeric_or_complex_value(max_value));
            }
            if matrix.rows == 1 {
                return Ok((lower[0].clone(), upper[0].clone()));
            }
            Ok((
                Value::Matrix(MatrixValue::new(matrix.rows, 1, lower)?),
                Value::Matrix(MatrixValue::new(matrix.rows, 1, upper)?),
            ))
        }
        _ => {
            let values = matrix.iter().cloned().collect::<Vec<_>>();
            let result = build_scalar_matrix_result(matrix.rows, matrix.cols, values)?;
            Ok((result.clone(), result))
        }
    }
}

fn bounds_value_and_range_over_dimensions(
    matrix: &MatrixValue,
    operating_dims: &[usize],
    missing_flag: BoundsMissingFlag,
) -> Result<(Value, Value), RuntimeError> {
    let mut input_dims = canonical_size_vector(&matrix.dims);
    let required_rank = input_dims
        .len()
        .max(operating_dims.iter().copied().max().unwrap_or(1))
        .max(2);
    while input_dims.len() < required_rank {
        input_dims.push(1);
    }

    let mut output_dims = input_dims.clone();
    for &dim in operating_dims {
        output_dims[dim - 1] = 1;
    }
    let render_dims = canonical_size_vector(&output_dims);
    let output_len = output_dims.iter().product::<usize>();
    let mut accumulators = vec![BoundsAccumulator::default(); output_len];

    for (input_linear, element) in matrix.elements.iter().enumerate() {
        let mut output_index = row_major_multi_index(input_linear, &input_dims);
        for &dim in operating_dims {
            output_index[dim - 1] = 0;
        }
        let output_linear = row_major_linear_index(&output_index, &output_dims);
        let value = element.as_scalar()?;
        accumulators[output_linear].observe(value, missing_flag);
    }

    let lower_values = accumulators
        .iter()
        .map(|accumulator| Value::Scalar(accumulator.lower(missing_flag)))
        .collect::<Vec<_>>();
    let upper_values = accumulators
        .iter()
        .map(|accumulator| Value::Scalar(accumulator.upper(missing_flag)))
        .collect::<Vec<_>>();

    if output_dims.iter().all(|&dim| dim == 1) {
        return Ok((lower_values[0].clone(), upper_values[0].clone()));
    }

    let (rows, cols) = storage_shape_from_dimensions(&render_dims);
    Ok((
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            render_dims.clone(),
            lower_values,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            render_dims,
            upper_values,
        )?),
    ))
}

fn bounds_value_and_range_over_dimensions_complex(
    matrix: &MatrixValue,
    operating_dims: &[usize],
    missing_flag: BoundsMissingFlag,
) -> Result<(Value, Value), RuntimeError> {
    let mut input_dims = canonical_size_vector(&matrix.dims);
    let required_rank = input_dims
        .len()
        .max(operating_dims.iter().copied().max().unwrap_or(1))
        .max(2);
    while input_dims.len() < required_rank {
        input_dims.push(1);
    }

    let mut output_dims = input_dims.clone();
    for &dim in operating_dims {
        output_dims[dim - 1] = 1;
    }
    let render_dims = canonical_size_vector(&output_dims);
    let output_len = output_dims.iter().product::<usize>();
    let mut accumulators = vec![BoundsComplexAccumulator::default(); output_len];

    for (input_linear, element) in matrix.elements.iter().enumerate() {
        let mut output_index = row_major_multi_index(input_linear, &input_dims);
        for &dim in operating_dims {
            output_index[dim - 1] = 0;
        }
        let output_linear = row_major_linear_index(&output_index, &output_dims);
        let value = numeric_or_complex_scalar(element, "bounds")?;
        accumulators[output_linear].observe(value, missing_flag);
    }

    let lower_values = accumulators
        .iter()
        .map(|accumulator| numeric_or_complex_value(accumulator.lower(missing_flag)))
        .collect::<Vec<_>>();
    let upper_values = accumulators
        .iter()
        .map(|accumulator| numeric_or_complex_value(accumulator.upper(missing_flag)))
        .collect::<Vec<_>>();

    if output_dims.iter().all(|&dim| dim == 1) {
        return Ok((lower_values[0].clone(), upper_values[0].clone()));
    }

    let (rows, cols) = storage_shape_from_dimensions(&render_dims);
    Ok((
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            render_dims.clone(),
            lower_values,
        )?),
        Value::Matrix(MatrixValue::with_dimensions(
            rows,
            cols,
            render_dims,
            upper_values,
        )?),
    ))
}

#[derive(Clone, Copy, Default)]
struct BoundsAccumulator {
    lower: f64,
    upper: f64,
    has_non_nan: bool,
    has_nan: bool,
}

impl BoundsAccumulator {
    fn observe(&mut self, value: f64, missing_flag: BoundsMissingFlag) {
        if value.is_nan() {
            if matches!(missing_flag, BoundsMissingFlag::IncludeNan) {
                self.has_nan = true;
            }
            return;
        }

        if !self.has_non_nan {
            self.lower = value;
            self.upper = value;
            self.has_non_nan = true;
            return;
        }

        self.lower = self.lower.min(value);
        self.upper = self.upper.max(value);
    }

    fn lower(&self, missing_flag: BoundsMissingFlag) -> f64 {
        if matches!(missing_flag, BoundsMissingFlag::IncludeNan) && self.has_nan {
            f64::NAN
        } else if self.has_non_nan {
            self.lower
        } else {
            f64::NAN
        }
    }

    fn upper(&self, missing_flag: BoundsMissingFlag) -> f64 {
        if matches!(missing_flag, BoundsMissingFlag::IncludeNan) && self.has_nan {
            f64::NAN
        } else if self.has_non_nan {
            self.upper
        } else {
            f64::NAN
        }
    }
}

#[derive(Clone, Copy)]
struct BoundsComplexAccumulator {
    lower: ComplexParts,
    upper: ComplexParts,
    has_non_nan: bool,
    has_nan: bool,
}

impl Default for BoundsComplexAccumulator {
    fn default() -> Self {
        Self {
            lower: ComplexParts::zero(),
            upper: ComplexParts::zero(),
            has_non_nan: false,
            has_nan: false,
        }
    }
}

impl BoundsComplexAccumulator {
    fn observe(&mut self, value: ComplexParts, missing_flag: BoundsMissingFlag) {
        if value.is_nan() {
            if matches!(missing_flag, BoundsMissingFlag::IncludeNan) {
                self.has_nan = true;
            }
            return;
        }

        if !self.has_non_nan {
            self.lower = value;
            self.upper = value;
            self.has_non_nan = true;
            return;
        }

        if complex_prefers_min(value, self.lower) {
            self.lower = value;
        }
        if complex_prefers_max(value, self.upper) {
            self.upper = value;
        }
    }

    fn lower(&self, missing_flag: BoundsMissingFlag) -> ComplexParts {
        if matches!(missing_flag, BoundsMissingFlag::IncludeNan) && self.has_nan {
            ComplexParts::nan()
        } else if self.has_non_nan {
            self.lower
        } else {
            ComplexParts::nan()
        }
    }

    fn upper(&self, missing_flag: BoundsMissingFlag) -> ComplexParts {
        if matches!(missing_flag, BoundsMissingFlag::IncludeNan) && self.has_nan {
            ComplexParts::nan()
        } else if self.has_non_nan {
            self.upper
        } else {
            ComplexParts::nan()
        }
    }
}

fn bounds_min_max(values: &[f64], missing_flag: BoundsMissingFlag) -> (f64, f64) {
    let mut accumulator = BoundsAccumulator::default();
    for value in values {
        accumulator.observe(*value, missing_flag);
    }
    (
        accumulator.lower(missing_flag),
        accumulator.upper(missing_flag),
    )
}

fn bounds_complex_min_max(
    values: &[ComplexParts],
    missing_flag: BoundsMissingFlag,
) -> (ComplexParts, ComplexParts) {
    let mut accumulator = BoundsComplexAccumulator::default();
    for value in values {
        accumulator.observe(*value, missing_flag);
    }
    (
        accumulator.lower(missing_flag),
        accumulator.upper(missing_flag),
    )
}

fn complex_prefers_min(candidate: ComplexParts, best: ComplexParts) -> bool {
    let candidate_magnitude = candidate.magnitude();
    let best_magnitude = best.magnitude();
    match candidate_magnitude.total_cmp(&best_magnitude) {
        std::cmp::Ordering::Less => true,
        std::cmp::Ordering::Greater => false,
        std::cmp::Ordering::Equal => candidate.argument().total_cmp(&best.argument()).is_lt(),
    }
}

fn complex_prefers_max(candidate: ComplexParts, best: ComplexParts) -> bool {
    let candidate_magnitude = candidate.magnitude();
    let best_magnitude = best.magnitude();
    match candidate_magnitude.total_cmp(&best_magnitude) {
        std::cmp::Ordering::Greater => true,
        std::cmp::Ordering::Less => false,
        std::cmp::Ordering::Equal => candidate.argument().total_cmp(&best.argument()).is_gt(),
    }
}

fn topk_value_and_indices(
    matrix: &MatrixValue,
    count: usize,
    dim: usize,
    descending: bool,
    comparison_method: ComparisonMethod,
) -> Result<(Value, Value), RuntimeError> {
    if count == 0 {
        let mut output_dims = canonical_size_vector(&matrix.dims);
        if output_dims.len() < dim {
            output_dims.resize(dim, 1);
        }
        output_dims[dim - 1] = 0;
        let output_dims = canonical_size_vector(&output_dims);
        let empty = build_scalar_matrix_result_with_dimensions(output_dims.clone(), Vec::new())?;
        return Ok((empty.clone(), empty));
    }

    if matrix.rows == 1 && matrix.cols == 1 && count == 1 {
        return Ok((matrix.get(0, 0).clone(), Value::Scalar(1.0)));
    }

    let mut input_dims = canonical_size_vector(&matrix.dims);
    if input_dims.len() < dim {
        input_dims.resize(dim, 1);
    }
    let axis = dim - 1;
    let mut output_dims = input_dims.clone();
    output_dims[axis] = count;
    let slice_dims = {
        let mut dims = input_dims.clone();
        dims[axis] = 1;
        dims
    };
    let slice_count = slice_dims.iter().product::<usize>();
    let axis_len = input_dims[axis];
    let output_len = output_dims.iter().product::<usize>();
    let logical_values = matrix_is_logical(matrix);
    let complex_values = matrix_is_numeric_or_complex(matrix) && !matrix_is_numeric(matrix);

    if complex_values {
        let mut top_values = vec![ComplexParts::zero(); output_len];
        let mut top_indices = vec![Value::Scalar(0.0); output_len];

        for slice_linear in 0..slice_count {
            let mut index = row_major_multi_index(slice_linear, &slice_dims);
            let values = (0..axis_len)
                .map(|axis_index| {
                    index[axis] = axis_index;
                    numeric_or_complex_scalar(
                        &matrix.elements[row_major_linear_index(&index, &input_dims)],
                        if descending { "maxk" } else { "mink" },
                    )
                })
                .collect::<Result<Vec<_>, _>>()?;
            let (top, indices) =
                topk_complex_with_indices(&values, count, descending, comparison_method, true);
            for out_index in 0..count {
                index[axis] = out_index;
                let destination = row_major_linear_index(&index, &output_dims);
                top_values[destination] = top[out_index];
                top_indices[destination] = Value::Scalar(indices[out_index] as f64);
            }
        }

        let rendered_dims = canonical_size_vector(&output_dims);
        return Ok((
            build_numeric_or_complex_matrix_result_with_dimensions(
                rendered_dims.clone(),
                top_values,
            )?,
            build_scalar_matrix_result_with_dimensions(rendered_dims, top_indices)?,
        ));
    }

    let mut top_values = vec![
        if logical_values {
            Value::Logical(false)
        } else {
            Value::Scalar(0.0)
        };
        output_len
    ];
    let mut top_indices = vec![Value::Scalar(0.0); output_len];

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                matrix.elements[row_major_linear_index(&index, &input_dims)].as_scalar()
            })
            .collect::<Result<Vec<_>, _>>()?;
        let (top, indices) =
            topk_numeric_with_indices(&values, count, descending, comparison_method);
        for out_index in 0..count {
            index[axis] = out_index;
            let destination = row_major_linear_index(&index, &output_dims);
            top_values[destination] = if logical_values {
                Value::Logical(top[out_index] != 0.0)
            } else {
                Value::Scalar(top[out_index])
            };
            top_indices[destination] = Value::Scalar(indices[out_index] as f64);
        }
    }

    let rendered_dims = canonical_size_vector(&output_dims);
    Ok((
        build_scalar_matrix_result_with_dimensions(rendered_dims.clone(), top_values)?,
        build_scalar_matrix_result_with_dimensions(rendered_dims, top_indices)?,
    ))
}

fn topk_numeric_with_indices(
    values: &[f64],
    count: usize,
    descending: bool,
    comparison_method: ComparisonMethod,
) -> (Vec<f64>, Vec<usize>) {
    let mut tagged = values
        .iter()
        .copied()
        .enumerate()
        .map(|(offset, value)| (value, offset + 1))
        .collect::<Vec<_>>();
    tagged.sort_by(|lhs, rhs| {
        let value_order = compare_sorted_numeric_values(
            lhs.0,
            rhs.0,
            descending,
            SortMissingPlacement::Auto,
            comparison_method,
        );
        value_order.then(lhs.1.cmp(&rhs.1))
    });
    let selected = tagged.into_iter().take(count).collect::<Vec<_>>();
    (
        selected.iter().map(|(value, _)| *value).collect(),
        selected.iter().map(|(_, index)| *index).collect(),
    )
}

fn topk_complex_with_indices(
    values: &[ComplexParts],
    count: usize,
    descending: bool,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> (Vec<ComplexParts>, Vec<usize>) {
    let mut tagged = values
        .iter()
        .copied()
        .enumerate()
        .map(|(offset, value)| (value, offset + 1))
        .collect::<Vec<_>>();
    tagged.sort_by(|lhs, rhs| {
        let value_order = compare_sorted_complex_values(
            lhs.0,
            rhs.0,
            descending,
            SortMissingPlacement::Auto,
            comparison_method,
            auto_complex,
        );
        value_order.then(lhs.1.cmp(&rhs.1))
    });
    let selected = tagged.into_iter().take(count).collect::<Vec<_>>();
    (
        selected.iter().map(|(value, _)| *value).collect(),
        selected.iter().map(|(_, index)| *index).collect(),
    )
}

fn compare_sorted_numeric_values(
    lhs: f64,
    rhs: f64,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> std::cmp::Ordering {
    compare_sorted_value_parts(
        ComplexParts {
            real: lhs,
            imag: 0.0,
        },
        ComplexParts {
            real: rhs,
            imag: 0.0,
        },
        descending,
        missing_placement,
        comparison_method,
        false,
    )
}

fn compare_sorted_complex_values(
    lhs: ComplexParts,
    rhs: ComplexParts,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> std::cmp::Ordering {
    compare_sorted_value_parts(
        lhs,
        rhs,
        descending,
        missing_placement,
        comparison_method,
        auto_complex,
    )
}

fn compare_sorted_value_parts(
    lhs: ComplexParts,
    rhs: ComplexParts,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> std::cmp::Ordering {
    let lhs_missing = lhs.is_nan();
    let rhs_missing = rhs.is_nan();
    if lhs_missing || rhs_missing {
        if lhs_missing && rhs_missing {
            return std::cmp::Ordering::Equal;
        }
        let missing_first = match missing_placement {
            SortMissingPlacement::Auto => descending,
            SortMissingPlacement::First => true,
            SortMissingPlacement::Last => false,
        };
        return match (lhs_missing, rhs_missing, missing_first) {
            (true, false, true) | (false, true, false) => std::cmp::Ordering::Less,
            (true, false, false) | (false, true, true) => std::cmp::Ordering::Greater,
            _ => std::cmp::Ordering::Equal,
        };
    }

    let resolved_method = match comparison_method {
        ComparisonMethod::Auto if auto_complex => ComparisonMethod::Abs,
        ComparisonMethod::Auto => ComparisonMethod::Real,
        method => method,
    };
    let ascending = match resolved_method {
        ComparisonMethod::Real | ComparisonMethod::Auto => lhs
            .real
            .total_cmp(&rhs.real)
            .then(lhs.imag.total_cmp(&rhs.imag)),
        ComparisonMethod::Abs => lhs
            .magnitude()
            .total_cmp(&rhs.magnitude())
            .then(lhs.argument().total_cmp(&rhs.argument())),
    };
    if descending {
        ascending.reverse()
    } else {
        ascending
    }
}

fn sorted_numeric_with_indices(
    values: &[f64],
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> (Vec<f64>, Vec<usize>) {
    let mut tagged = values
        .iter()
        .copied()
        .enumerate()
        .map(|(offset, value)| (value, offset + 1))
        .collect::<Vec<_>>();
    tagged.sort_by(|lhs, rhs| {
        let value_order = compare_sorted_numeric_values(
            lhs.0,
            rhs.0,
            descending,
            missing_placement,
            comparison_method,
        );
        value_order.then(lhs.1.cmp(&rhs.1))
    });
    (
        tagged.iter().map(|(value, _)| *value).collect(),
        tagged.iter().map(|(_, index)| *index).collect(),
    )
}

fn sorted_complex_with_indices(
    values: &[ComplexParts],
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> (Vec<ComplexParts>, Vec<usize>) {
    let mut tagged = values
        .iter()
        .copied()
        .enumerate()
        .map(|(offset, value)| (value, offset + 1))
        .collect::<Vec<_>>();
    tagged.sort_by(|lhs, rhs| {
        let value_order = compare_sorted_complex_values(
            lhs.0,
            rhs.0,
            descending,
            missing_placement,
            comparison_method,
            auto_complex,
        );
        value_order.then(lhs.1.cmp(&rhs.1))
    });
    (
        tagged.iter().map(|(value, _)| *value).collect(),
        tagged.iter().map(|(_, index)| *index).collect(),
    )
}

fn slice_is_sorted_numeric(
    values: &[f64],
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> bool {
    values.windows(2).all(|pair| {
        compare_sorted_numeric_values(
            pair[0],
            pair[1],
            descending,
            missing_placement,
            comparison_method,
        ) != std::cmp::Ordering::Greater
    })
}

fn slice_is_sorted_complex(
    values: &[ComplexParts],
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
    auto_complex: bool,
) -> bool {
    values.windows(2).all(|pair| {
        compare_sorted_complex_values(
            pair[0],
            pair[1],
            descending,
            missing_placement,
            comparison_method,
            auto_complex,
        ) != std::cmp::Ordering::Greater
    })
}

fn matrix_is_sorted(
    matrix: &MatrixValue,
    dim: usize,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<bool, RuntimeError> {
    if matrix.rows == 0 || matrix.cols == 0 {
        return Ok(true);
    }

    let input_dims = canonical_size_vector(matrix.dims());
    if matrix_is_text(matrix) {
        if input_dims.len() > 2 || dim > 2 {
            return matrix_is_sorted_nd_text(matrix, &input_dims, dim, descending);
        }
        return match dim {
            1 => {
                for col in 0..matrix.cols {
                    let values = (0..matrix.rows)
                        .map(|row| text_value(matrix.get(row, col)).map(str::to_string))
                        .collect::<Result<Vec<_>, _>>()?;
                    if !slice_is_sorted_text(&values, descending) {
                        return Ok(false);
                    }
                }
                Ok(true)
            }
            2 => {
                for row in 0..matrix.rows {
                    let values = (0..matrix.cols)
                        .map(|col| text_value(matrix.get(row, col)).map(str::to_string))
                        .collect::<Result<Vec<_>, _>>()?;
                    if !slice_is_sorted_text(&values, descending) {
                        return Ok(false);
                    }
                }
                Ok(true)
            }
            _ => Ok(true),
        };
    }

    let complex = matrix_is_numeric_or_complex(matrix) && !matrix_is_numeric(matrix);
    if complex {
        if input_dims.len() > 2 || dim > 2 {
            return matrix_is_sorted_nd_complex(
                matrix,
                &input_dims,
                dim,
                descending,
                missing_placement,
                comparison_method,
            );
        }
        return match dim {
            1 => {
                for col in 0..matrix.cols {
                    let values = (0..matrix.rows)
                        .map(|row| numeric_or_complex_scalar(matrix.get(row, col), "issorted"))
                        .collect::<Result<Vec<_>, _>>()?;
                    if !slice_is_sorted_complex(
                        &values,
                        descending,
                        missing_placement,
                        comparison_method,
                        true,
                    ) {
                        return Ok(false);
                    }
                }
                Ok(true)
            }
            2 => {
                for row in 0..matrix.rows {
                    let values = (0..matrix.cols)
                        .map(|col| numeric_or_complex_scalar(matrix.get(row, col), "issorted"))
                        .collect::<Result<Vec<_>, _>>()?;
                    if !slice_is_sorted_complex(
                        &values,
                        descending,
                        missing_placement,
                        comparison_method,
                        true,
                    ) {
                        return Ok(false);
                    }
                }
                Ok(true)
            }
            _ => Ok(true),
        };
    }

    if input_dims.len() > 2 || dim > 2 {
        return matrix_is_sorted_nd_numeric(
            matrix,
            &input_dims,
            dim,
            descending,
            missing_placement,
            comparison_method,
        );
    }

    match dim {
        1 => {
            for col in 0..matrix.cols {
                let values = (0..matrix.rows)
                    .map(|row| matrix.get(row, col).as_scalar())
                    .collect::<Result<Vec<_>, _>>()?;
                if !slice_is_sorted_numeric(
                    &values,
                    descending,
                    missing_placement,
                    comparison_method,
                ) {
                    return Ok(false);
                }
            }
            Ok(true)
        }
        2 => {
            for row in 0..matrix.rows {
                let values = (0..matrix.cols)
                    .map(|col| matrix.get(row, col).as_scalar())
                    .collect::<Result<Vec<_>, _>>()?;
                if !slice_is_sorted_numeric(
                    &values,
                    descending,
                    missing_placement,
                    comparison_method,
                ) {
                    return Ok(false);
                }
            }
            Ok(true)
        }
        _ => Ok(true),
    }
}

fn matrix_is_sorted_nd_complex(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<bool, RuntimeError> {
    if dim > input_dims.len() {
        return Ok(true);
    }
    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                numeric_or_complex_scalar(
                    &matrix.elements[row_major_linear_index(&index, input_dims)],
                    "issorted",
                )
            })
            .collect::<Result<Vec<_>, _>>()?;
        if !slice_is_sorted_complex(
            &values,
            descending,
            missing_placement,
            comparison_method,
            true,
        ) {
            return Ok(false);
        }
    }
    Ok(true)
}

fn matrix_is_sorted_nd_text(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
) -> Result<bool, RuntimeError> {
    if dim > input_dims.len() {
        return Ok(true);
    }
    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let mut values = Vec::with_capacity(axis_len);
        for axis_index in 0..axis_len {
            index[axis] = axis_index;
            let offset = row_major_linear_index(&index, input_dims);
            values.push(text_value(&matrix.elements[offset])?.to_string());
        }
        if !slice_is_sorted_text(&values, descending) {
            return Ok(false);
        }
    }
    Ok(true)
}

fn matrix_is_sorted_nd_numeric(
    matrix: &MatrixValue,
    input_dims: &[usize],
    dim: usize,
    descending: bool,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<bool, RuntimeError> {
    if dim > input_dims.len() {
        return Ok(true);
    }
    let axis = dim - 1;
    let mut slice_dims = input_dims.to_vec();
    let axis_len = slice_dims[axis];
    slice_dims[axis] = 1;
    let slice_count = slice_dims.iter().product::<usize>();

    for slice_linear in 0..slice_count {
        let mut index = row_major_multi_index(slice_linear, &slice_dims);
        let values = (0..axis_len)
            .map(|axis_index| {
                index[axis] = axis_index;
                matrix.elements[row_major_linear_index(&index, input_dims)].as_scalar()
            })
            .collect::<Result<Vec<_>, _>>()?;
        if !slice_is_sorted_numeric(&values, descending, missing_placement, comparison_method) {
            return Ok(false);
        }
    }
    Ok(true)
}

#[derive(Clone, Copy)]
struct SortrowsColumn {
    index: usize,
    descending: bool,
}

fn parse_sortrows_columns(
    value: Option<&Value>,
    matrix_cols: usize,
) -> Result<Vec<SortrowsColumn>, RuntimeError> {
    match value {
        None => Ok((1..=matrix_cols)
            .map(|column| SortrowsColumn {
                index: column,
                descending: false,
            })
            .collect()),
        Some(value) => {
            let matrix = coerce_matrix(value)?;
            if matrix.rows != 1 && matrix.cols != 1 {
                return Err(RuntimeError::ShapeError(
                    "sortrows currently expects a scalar column or a vector of nonzero integer column indices".to_string(),
                ));
            }

            let mut columns = Vec::with_capacity(matrix.rows * matrix.cols);
            for element in matrix.iter() {
                let column = nonzero_integer_scalar_with_label(
                    element,
                    "sortrows",
                    "a nonzero integer column index or vector of column indices",
                )?;
                let descending = column < 0;
                let index = column.unsigned_abs();
                if index > matrix_cols {
                    return Err(RuntimeError::InvalidIndex(format!(
                        "sortrows column index {} exceeds matrix column count {matrix_cols}",
                        column.abs()
                    )));
                }
                columns.push(SortrowsColumn { index, descending });
            }
            if columns.is_empty() {
                return Err(RuntimeError::ShapeError(
                    "sortrows currently expects at least one column index".to_string(),
                ));
            }
            Ok(columns)
        }
    }
}

fn sortrows_value_and_indices(
    matrix: &MatrixValue,
    columns: &[SortrowsColumn],
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> Result<(Value, Value), RuntimeError> {
    if matrix.rows == 0 || matrix.cols == 0 {
        let sorted = Value::Matrix(MatrixValue::new(matrix.rows, matrix.cols, Vec::new())?);
        let indices = Value::Matrix(MatrixValue::new(0, 1, Vec::new())?);
        return Ok((sorted, indices));
    }

    let mut row_indices = (0..matrix.rows).collect::<Vec<_>>();
    row_indices.sort_by(|lhs, rhs| {
        compare_sortrows_rows(
            matrix,
            columns,
            *lhs,
            *rhs,
            missing_placement,
            comparison_method,
        )
    });

    let mut permutation = Vec::with_capacity(matrix.rows);
    if matrix_is_text(matrix) {
        let operand = text_operand(&Value::Matrix(matrix.clone()))?;
        let mut sorted_values = Vec::with_capacity(matrix.rows * matrix.cols);
        let mut sorted_prototypes = Vec::with_capacity(matrix.rows * matrix.cols);
        for row_index in &row_indices {
            let row_start = row_index * matrix.cols;
            sorted_values.extend_from_slice(&operand.values[row_start..row_start + matrix.cols]);
            sorted_prototypes
                .extend_from_slice(&operand.prototypes[row_start..row_start + matrix.cols]);
            permutation.push(Value::Scalar((*row_index + 1) as f64));
        }
        return Ok((
            build_text_result_preserving_char_identity(
                matrix.rows,
                matrix.cols,
                sorted_values,
                sorted_prototypes,
            )?,
            build_scalar_matrix_result(matrix.rows, 1, permutation)?,
        ));
    }

    let mut sorted_elements = Vec::with_capacity(matrix.rows * matrix.cols);
    for row_index in &row_indices {
        for col in 0..matrix.cols {
            sorted_elements.push(matrix.get(*row_index, col).clone());
        }
        permutation.push(Value::Scalar((*row_index + 1) as f64));
    }

    Ok((
        Value::Matrix(MatrixValue::new(matrix.rows, matrix.cols, sorted_elements)?),
        build_scalar_matrix_result(matrix.rows, 1, permutation)?,
    ))
}

fn compare_sortrows_rows(
    matrix: &MatrixValue,
    columns: &[SortrowsColumn],
    lhs: usize,
    rhs: usize,
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> std::cmp::Ordering {
    if matrix_is_text(matrix) {
        for column in columns {
            let lhs_value = text_value(matrix.get(lhs, column.index - 1))
                .expect("text sortrows should only receive text elements");
            let rhs_value = text_value(matrix.get(rhs, column.index - 1))
                .expect("text sortrows should only receive text elements");
            let ordering = if column.descending {
                rhs_value.cmp(lhs_value)
            } else {
                lhs_value.cmp(rhs_value)
            };
            if ordering != std::cmp::Ordering::Equal {
                return ordering;
            }
        }
        return lhs.cmp(&rhs);
    }

    for column in columns {
        let ordering = if matrix_is_numeric_or_complex(matrix) && !matrix_is_numeric(matrix) {
            let lhs_value =
                numeric_or_complex_scalar(matrix.get(lhs, column.index - 1), "sortrows")
                    .unwrap_or(ComplexParts::nan());
            let rhs_value =
                numeric_or_complex_scalar(matrix.get(rhs, column.index - 1), "sortrows")
                    .unwrap_or(ComplexParts::nan());
            compare_sorted_complex_values(
                lhs_value,
                rhs_value,
                column.descending,
                missing_placement,
                comparison_method,
                true,
            )
        } else {
            let lhs_value = matrix
                .get(lhs, column.index - 1)
                .as_scalar()
                .unwrap_or(f64::NAN);
            let rhs_value = matrix
                .get(rhs, column.index - 1)
                .as_scalar()
                .unwrap_or(f64::NAN);
            compare_sorted_numeric_values(
                lhs_value,
                rhs_value,
                column.descending,
                missing_placement,
                comparison_method,
            )
        };
        if ordering != std::cmp::Ordering::Equal {
            return ordering;
        }
    }
    lhs.cmp(&rhs)
}

fn matrix_rows_are_sorted(
    matrix: &MatrixValue,
    columns: &[SortrowsColumn],
    missing_placement: SortMissingPlacement,
    comparison_method: ComparisonMethod,
) -> bool {
    if matrix.rows <= 1 || matrix.cols == 0 {
        return true;
    }

    (0..(matrix.rows - 1)).all(|row| {
        compare_sortrows_rows(
            matrix,
            columns,
            row,
            row + 1,
            missing_placement,
            comparison_method,
        ) != std::cmp::Ordering::Greater
    })
}

fn sorted_text_with_indices(
    values: &[String],
    prototypes: &[TextPrototype],
    descending: bool,
) -> (Vec<String>, Vec<TextPrototype>, Vec<usize>) {
    let mut entries = values
        .iter()
        .cloned()
        .zip(prototypes.iter().copied())
        .enumerate()
        .map(|(index, (value, prototype))| (value, prototype, index + 1))
        .collect::<Vec<_>>();
    entries.sort_by(|lhs, rhs| {
        if descending {
            rhs.0.cmp(&lhs.0)
        } else {
            lhs.0.cmp(&rhs.0)
        }
    });
    (
        entries.iter().map(|(value, _, _)| value.clone()).collect(),
        entries.iter().map(|(_, prototype, _)| *prototype).collect(),
        entries.iter().map(|(_, _, index)| *index).collect(),
    )
}

fn build_text_result_preserving_char_identity(
    rows: usize,
    cols: usize,
    values: Vec<String>,
    prototypes: Vec<TextPrototype>,
) -> Result<Value, RuntimeError> {
    if prototypes
        .iter()
        .all(|prototype| *prototype == TextPrototype::Char)
        && values.iter().all(|value| value.chars().count() <= 1)
    {
        let chars = values
            .into_iter()
            .filter_map(|value| value.chars().next())
            .collect::<Vec<_>>();
        return char_value_with_dimensions(vec![rows, cols], chars);
    }

    build_text_result(rows, cols, values, prototypes)
}

fn slice_is_sorted_text(values: &[String], descending: bool) -> bool {
    values.windows(2).all(|pair| {
        if descending {
            pair[0] >= pair[1]
        } else {
            pair[0] <= pair[1]
        }
    })
}

fn numeric_set_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<f64>, bool, bool), RuntimeError> {
    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        _ => coerce_matrix(value)?,
    };
    if matrix.rows != 1 && matrix.cols != 1 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or logical scalar/vector inputs"
        )));
    }
    Ok((
        matrix
            .iter()
            .map(Value::as_scalar)
            .collect::<Result<Vec<_>, _>>()?,
        matrix.rows == 1 && matrix.cols != 1,
        matrix_is_logical(&matrix),
    ))
}

fn numeric_or_complex_set_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<ComplexParts>, bool), RuntimeError> {
    match value {
        Value::Scalar(_) | Value::Logical(_) | Value::Complex(_) => {
            Ok((vec![numeric_or_complex_scalar(value, builtin_name)?], false))
        }
        Value::Matrix(matrix) => {
            if matrix.rows != 1 && matrix.cols != 1 {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects numeric or complex scalar or vector inputs"
                )));
            }
            Ok((
                matrix
                    .iter()
                    .map(|element| numeric_or_complex_scalar(element, builtin_name))
                    .collect::<Result<Vec<_>, _>>()?,
                matrix.rows == 1 && matrix.cols != 1,
            ))
        }
        _ => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or complex scalar or vector inputs"
        ))),
    }
}

fn numeric_or_complex_vector_allow_empty(
    value: &Value,
    builtin_name: &str,
) -> Result<Vec<ComplexParts>, RuntimeError> {
    match value {
        Value::Matrix(matrix) if matrix.element_count() == 0 => Ok(Vec::new()),
        _ => numeric_or_complex_set_vector(value, builtin_name).map(|(values, _is_row)| values),
    }
}

fn text_set_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<String>, Vec<TextPrototype>, bool), RuntimeError> {
    let operand = set_operation_text_operand(value)?;
    if operand.rows != 1 && operand.cols != 1 {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects text scalar or vector inputs"
        )));
    }
    Ok((
        operand.values,
        operand.prototypes,
        operand.rows == 1 && operand.cols != 1,
    ))
}

fn char_text_set_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<String>, Vec<TextPrototype>, bool), RuntimeError> {
    let (values, prototypes, row_output) = text_set_vector(value, builtin_name)?;
    if prototypes
        .iter()
        .all(|prototype| *prototype == TextPrototype::Char)
    {
        Ok((values, prototypes, row_output))
    } else {
        Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects char-compatible text input"
        )))
    }
}

fn numeric_char_text_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<String>, Vec<TextPrototype>, bool), RuntimeError> {
    match value {
        Value::Scalar(number) => Ok((
            vec![char_code_text(std::iter::once(*number), builtin_name)?],
            vec![TextPrototype::Char],
            false,
        )),
        Value::Matrix(matrix) if matrix_is_numeric(matrix) => {
            let values = linearized_numeric_with_indices(matrix)?
                .into_iter()
                .map(|(value, _)| char_code_text(std::iter::once(value), builtin_name))
                .collect::<Result<Vec<_>, _>>()?;
            let count = values.len();
            Ok((
                values,
                vec![TextPrototype::Char; count],
                matrix.rows == 1 && matrix.cols != 1,
            ))
        }
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric code-point vector or matrix input, found {}",
            other.kind_name()
        ))),
    }
}

fn char_cell_text_set_vector(
    value: &Value,
    builtin_name: &str,
) -> Result<(Vec<String>, Vec<TextPrototype>, bool, bool), RuntimeError> {
    match value {
        Value::Cell(cell) => {
            if cell.rows != 1 && cell.cols != 1 {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects text scalar or vector inputs"
                )));
            }
            let mut values = Vec::with_capacity(cell.elements.len());
            let mut prototypes = Vec::with_capacity(cell.elements.len());
            for element in &cell.elements {
                let Value::CharArray(text) = element else {
                    return Err(RuntimeError::TypeError(format!(
                        "{builtin_name} currently expects cell arrays of character vectors when mixing cell and char inputs"
                    )));
                };
                values.push(text.clone());
                prototypes.push(TextPrototype::Char);
            }
            Ok((values, prototypes, cell.rows == 1 && cell.cols != 1, true))
        }
        Value::CharArray(text) => Ok((
            vec![text.clone()],
            vec![TextPrototype::Char],
            true,
            false,
        )),
        Value::Matrix(matrix)
            if matrix_is_char_matrix(matrix)
                || matrix
                    .iter()
                    .all(|value| matches!(value, Value::CharArray(_))) =>
        {
            if matrix_is_char_matrix(matrix) {
                let mut values = Vec::with_capacity(matrix.rows);
                for row in 0..matrix.rows {
                    let text = (0..matrix.cols)
                        .map(|col| {
                            single_char_text_value(matrix.get(row, col)).ok_or_else(|| {
                                RuntimeError::TypeError(format!(
                                    "{builtin_name} currently expects char matrices to contain single-character elements"
                                ))
                            })
                        })
                        .collect::<Result<String, _>>()?;
                    values.push(text);
                }
                return Ok((
                    values,
                    vec![TextPrototype::Char; matrix.rows],
                    matrix.rows == 1,
                    false,
                ));
            }

            if matrix.rows != 1 && matrix.cols != 1 {
                return Err(RuntimeError::TypeError(format!(
                    "{builtin_name} currently expects char arrays or cell arrays of character vectors"
                )));
            }

            Ok((
                matrix
                    .iter()
                    .map(|value| match value {
                        Value::CharArray(text) => Ok(text.clone()),
                        _ => unreachable!("checked char-array elements"),
                    })
                    .collect::<Result<Vec<_>, RuntimeError>>()?,
                vec![TextPrototype::Char; matrix.element_count()],
                matrix.rows == 1 && matrix.cols != 1,
                false,
            ))
        }
        other => Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects char arrays or cell arrays of character vectors, found {}",
            other.kind_name()
        ))),
    }
}

fn set_operation_text_operand(value: &Value) -> Result<TextOperand, RuntimeError> {
    match value {
        Value::CharArray(text) => {
            let cols = text.chars().count();
            Ok(TextOperand {
                rows: 1,
                cols,
                values: text.chars().map(|ch| ch.to_string()).collect(),
                prototypes: vec![TextPrototype::Char; cols],
            })
        }
        _ => text_operand(value),
    }
}

#[derive(Clone, Copy)]
enum UniqueOrder {
    Sorted,
    Stable,
}

#[derive(Clone, Copy)]
enum SetOrder {
    Sorted,
    Stable,
}

#[derive(Clone, Copy)]
enum UniqueOccurrence {
    First,
    Last,
}

fn parse_unique_order(value: &Value) -> Result<UniqueOrder, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "sorted" => Ok(UniqueOrder::Sorted),
        "stable" => Ok(UniqueOrder::Stable),
        other => Err(RuntimeError::Unsupported(format!(
            "unique setOrder `{other}` is not implemented; expected sorted or stable"
        ))),
    }
}

fn parse_set_order(value: &Value, builtin_name: &str) -> Result<SetOrder, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "sorted" => Ok(SetOrder::Sorted),
        "stable" => Ok(SetOrder::Stable),
        other => Err(RuntimeError::Unsupported(format!(
            "{builtin_name} setOrder `{other}` is not implemented; expected sorted or stable"
        ))),
    }
}

fn parse_set_operation_args<'a>(
    args: &'a [Value],
    builtin_name: &str,
) -> Result<(&'a Value, &'a Value, SetOrder, bool), RuntimeError> {
    let [lhs, rhs, options @ ..] = args else {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports `{builtin_name}(a, b)`, `{builtin_name}(a, b, setOrder)`, `{builtin_name}(a, b, 'rows')`, and `{builtin_name}(a, b, setOrder, 'rows')`"
        )));
    };
    if options.len() > 2 {
        return Err(RuntimeError::Unsupported(format!(
            "{builtin_name} currently supports at most two trailing options (`setOrder` and `'rows'`)"
        )));
    }

    let mut order = SetOrder::Sorted;
    let mut rows = false;
    let mut seen_order = false;
    for option in options {
        let text = text_value(option)?;
        if text.eq_ignore_ascii_case("rows") {
            if rows {
                return Err(RuntimeError::Unsupported(format!(
                    "{builtin_name} currently supports `'rows'` at most once"
                )));
            }
            rows = true;
            continue;
        }
        if seen_order {
            return Err(RuntimeError::Unsupported(format!(
                "{builtin_name} currently supports a single setOrder option"
            )));
        }
        order = parse_set_order(option, builtin_name)?;
        seen_order = true;
    }

    Ok((lhs, rhs, order, rows))
}

fn parse_unique_occurrence(value: &Value) -> Result<UniqueOccurrence, RuntimeError> {
    match text_value(value)?.to_ascii_lowercase().as_str() {
        "first" => Ok(UniqueOccurrence::First),
        "last" => Ok(UniqueOccurrence::Last),
        other => Err(RuntimeError::Unsupported(format!(
            "unique occurrence `{other}` is not implemented; expected first or last"
        ))),
    }
}

fn parse_unique_options(args: &[Value]) -> Result<(&Value, UniqueOptions), RuntimeError> {
    let Some((value, options)) = args.split_first() else {
        return Err(RuntimeError::Unsupported(
            "unique currently expects at least one argument".to_string(),
        ));
    };

    let mut parsed = UniqueOptions {
        order: UniqueOrder::Sorted,
        occurrence: UniqueOccurrence::First,
        rows: false,
    };
    for option in options {
        let text = text_value(option)?;
        if text.eq_ignore_ascii_case("rows") {
            parsed.rows = true;
            continue;
        }
        if let Ok(order) = parse_unique_order(option) {
            parsed.order = order;
            continue;
        }
        if let Ok(occurrence) = parse_unique_occurrence(option) {
            parsed.occurrence = occurrence;
            continue;
        }
        return Err(RuntimeError::Unsupported(format!(
            "unique option `{text}` is not implemented; expected rows, sorted, stable, first, or last"
        )));
    }
    Ok((value, parsed))
}

struct UniqueTextInput {
    values: Vec<String>,
    prototypes: Vec<TextPrototype>,
    row_output: bool,
    cell_output: bool,
    char_vector_output: bool,
}

#[derive(Clone, Copy)]
struct UniqueOptions {
    order: UniqueOrder,
    occurrence: UniqueOccurrence,
    rows: bool,
}

fn unique_numeric_outputs(
    value: &Value,
    options: UniqueOptions,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (tagged, row_output, logical_output) = match value {
        Value::Scalar(number) => (vec![(*number, 1usize)], false, false),
        Value::Logical(flag) => (vec![(if *flag { 1.0 } else { 0.0 }, 1usize)], false, true),
        Value::Matrix(matrix) => (
            linearized_numeric_with_indices(matrix)?,
            matrix.rows == 1 && matrix.cols != 1,
            matrix_is_logical(matrix),
        ),
        _ => {
            return Err(RuntimeError::TypeError(
                "unique currently expects numeric or logical scalar/matrix input".to_string(),
            ))
        }
    };

    let (unique_values, unique_indices) = match options.order {
        UniqueOrder::Sorted => {
            let mut unique = Vec::<(f64, usize, usize)>::new();
            for (value, index) in &tagged {
                if let Some((_, first, last)) = unique
                    .iter_mut()
                    .find(|(existing, _, _)| *existing == *value)
                {
                    *first = (*first).min(*index);
                    *last = (*last).max(*index);
                } else {
                    unique.push((*value, *index, *index));
                }
            }
            unique.sort_by(|lhs, rhs| lhs.0.total_cmp(&rhs.0).then(lhs.1.cmp(&rhs.1)));
            (
                unique
                    .iter()
                    .map(|(value, _, _)| *value)
                    .collect::<Vec<_>>(),
                unique
                    .iter()
                    .map(|(_, first, last)| match options.occurrence {
                        UniqueOccurrence::First => *first,
                        UniqueOccurrence::Last => *last,
                    })
                    .collect::<Vec<_>>(),
            )
        }
        UniqueOrder::Stable => {
            let mut unique_values = Vec::new();
            let mut unique_indices = Vec::new();
            for (value, index) in &tagged {
                if let Some(position) = unique_values
                    .iter()
                    .position(|existing| *existing == *value)
                {
                    if matches!(options.occurrence, UniqueOccurrence::Last) {
                        unique_indices[position] = *index;
                    }
                    continue;
                }
                unique_values.push(*value);
                unique_indices.push(*index);
            }
            (unique_values, unique_indices)
        }
    };

    let unique_value = numeric_set_output(unique_values.clone(), row_output, logical_output)?;
    let inverse_indices = tagged
        .iter()
        .map(|(value, _)| {
            unique_values
                .iter()
                .position(|candidate| *candidate == *value)
                .expect("unique value present")
                + 1
        })
        .collect::<Vec<_>>();

    match output_arity {
        0 | 1 => Ok(vec![unique_value]),
        2 => Ok(vec![unique_value, indices_to_value(unique_indices, false)?]),
        3 => Ok(vec![
            unique_value,
            indices_to_value(unique_indices, false)?,
            indices_to_value(inverse_indices, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "unique currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn unique_text_input(value: &Value) -> Result<UniqueTextInput, RuntimeError> {
    match value {
        Value::CharArray(text) => Ok(UniqueTextInput {
            values: text.chars().map(|ch| ch.to_string()).collect(),
            prototypes: vec![TextPrototype::Char; text.chars().count()],
            row_output: true,
            cell_output: false,
            char_vector_output: true,
        }),
        Value::Cell(cell) => {
            if cell.rows != 1 && cell.cols != 1 {
                return Err(RuntimeError::TypeError(
                    "unique currently expects text cell array inputs to be vectors".to_string(),
                ));
            }
            let mut values = Vec::with_capacity(cell.elements.len());
            let mut prototypes = Vec::with_capacity(cell.elements.len());
            for element in &cell.elements {
                values.push(text_value(element)?.to_string());
                prototypes.push(text_prototype(element).ok_or_else(|| {
                    RuntimeError::TypeError(
                        "unique currently expects text cell array elements to be char or string values"
                            .to_string(),
                    )
                })?);
            }
            Ok(UniqueTextInput {
                values,
                prototypes,
                row_output: cell.rows == 1 && cell.cols != 1,
                cell_output: true,
                char_vector_output: false,
            })
        }
        _ => {
            let (values, prototypes, row_output) = text_set_vector(value, "unique")?;
            Ok(UniqueTextInput {
                values,
                prototypes,
                row_output,
                cell_output: false,
                char_vector_output: false,
            })
        }
    }
}

fn unique_text_outputs(
    value: &Value,
    options: UniqueOptions,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let input = unique_text_input(value)?;
    let tagged = input
        .values
        .iter()
        .cloned()
        .zip(input.prototypes.iter().copied())
        .enumerate()
        .map(|(offset, (value, prototype))| (value, prototype, offset + 1))
        .collect::<Vec<_>>();

    let (unique_values, unique_prototypes, unique_indices) = match options.order {
        UniqueOrder::Sorted => {
            let mut unique = Vec::<(String, TextPrototype, usize, usize)>::new();
            for (value, prototype, index) in &tagged {
                if let Some((_, existing_prototype, first, last)) = unique
                    .iter_mut()
                    .find(|(existing, _, _, _)| *existing == *value)
                {
                    if matches!(options.occurrence, UniqueOccurrence::Last) {
                        *existing_prototype = *prototype;
                    }
                    *first = (*first).min(*index);
                    *last = (*last).max(*index);
                } else {
                    unique.push((value.clone(), *prototype, *index, *index));
                }
            }
            unique.sort_by(|lhs, rhs| lhs.0.cmp(&rhs.0).then(lhs.2.cmp(&rhs.2)));
            (
                unique
                    .iter()
                    .map(|(value, _, _, _)| value.clone())
                    .collect::<Vec<_>>(),
                unique
                    .iter()
                    .map(|(_, prototype, _, _)| *prototype)
                    .collect::<Vec<_>>(),
                unique
                    .iter()
                    .map(|(_, _, first, last)| match options.occurrence {
                        UniqueOccurrence::First => *first,
                        UniqueOccurrence::Last => *last,
                    })
                    .collect::<Vec<_>>(),
            )
        }
        UniqueOrder::Stable => {
            let mut unique_values = Vec::new();
            let mut unique_prototypes = Vec::new();
            let mut unique_indices = Vec::new();
            for (value, prototype, index) in &tagged {
                if let Some(position) = unique_values
                    .iter()
                    .position(|existing| *existing == *value)
                {
                    if matches!(options.occurrence, UniqueOccurrence::Last) {
                        unique_indices[position] = *index;
                        unique_prototypes[position] = *prototype;
                    }
                    continue;
                }
                unique_values.push(value.clone());
                unique_prototypes.push(*prototype);
                unique_indices.push(*index);
            }
            (unique_values, unique_prototypes, unique_indices)
        }
    };

    let unique_value = unique_text_output(&input, unique_values.clone(), unique_prototypes)?;
    let inverse_indices = tagged
        .iter()
        .map(|(value, _, _)| {
            unique_values
                .iter()
                .position(|candidate| candidate == value)
                .expect("unique text value present")
                + 1
        })
        .collect::<Vec<_>>();

    match output_arity {
        0 | 1 => Ok(vec![unique_value]),
        2 => Ok(vec![unique_value, indices_to_value(unique_indices, false)?]),
        3 => Ok(vec![
            unique_value,
            indices_to_value(unique_indices, false)?,
            indices_to_value(inverse_indices, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "unique currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn unique_text_output(
    input: &UniqueTextInput,
    values: Vec<String>,
    prototypes: Vec<TextPrototype>,
) -> Result<Value, RuntimeError> {
    if input.char_vector_output {
        return Ok(Value::CharArray(values.concat()));
    }
    if input.cell_output {
        let count = values.len();
        return Ok(Value::Cell(CellValue::new(
            if input.row_output { 1 } else { count },
            if input.row_output { count } else { 1 },
            values
                .into_iter()
                .zip(prototypes)
                .map(|(text, prototype)| text_value_with_prototype(prototype, text))
                .collect(),
        )?));
    }
    text_set_output(values, prototypes, input.row_output)
}

fn unique_numeric_row_outputs(
    value: &Value,
    options: UniqueOptions,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let matrix = match value {
        Value::Scalar(number) => MatrixValue::new(1, 1, vec![Value::Scalar(*number)])?,
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        Value::Matrix(matrix) => {
            if !(matrix_is_numeric(matrix) || matrix_is_logical(matrix)) {
                return Err(RuntimeError::TypeError(
                    "unique(...,'rows') currently expects numeric or logical matrix input"
                        .to_string(),
                ));
            }
            matrix.clone()
        }
        _ => {
            return Err(RuntimeError::TypeError(
                "unique(...,'rows') currently expects numeric or logical matrix input".to_string(),
            ))
        }
    };
    let logical_output = matrix_is_logical(&matrix);

    let row_keys = (0..matrix.rows)
        .map(|row| {
            (0..matrix.cols)
                .map(|col| matrix.get(row, col).as_scalar())
                .collect::<Result<Vec<_>, _>>()
        })
        .collect::<Result<Vec<_>, _>>()?;

    let mut unique_rows = Vec::<(Vec<f64>, usize, usize)>::new();
    for (row_index, key) in row_keys.iter().cloned().enumerate() {
        if let Some((_, first, last)) = unique_rows
            .iter_mut()
            .find(|(existing, _, _)| *existing == key)
        {
            *first = (*first).min(row_index);
            *last = (*last).max(row_index);
        } else {
            unique_rows.push((key, row_index, row_index));
        }
    }

    if matches!(options.order, UniqueOrder::Sorted) {
        unique_rows
            .sort_by(|lhs, rhs| compare_numeric_row_keys(&lhs.0, &rhs.0).then(lhs.1.cmp(&rhs.1)));
    }

    let mut elements = Vec::with_capacity(unique_rows.len() * matrix.cols);
    let ia = unique_rows
        .iter()
        .map(|(_, first, last)| match options.occurrence {
            UniqueOccurrence::First => first + 1,
            UniqueOccurrence::Last => last + 1,
        })
        .collect::<Vec<_>>();
    for (_, first, _) in &unique_rows {
        for col in 0..matrix.cols {
            elements.push(matrix.get(*first, col).clone());
        }
    }

    let ic = row_keys
        .iter()
        .map(|key| {
            unique_rows
                .iter()
                .position(|(candidate, _, _)| candidate == key)
                .expect("unique row present")
                + 1
        })
        .collect::<Vec<_>>();

    let unique_value = if logical_output {
        Value::Matrix(MatrixValue::new(
            unique_rows.len(),
            matrix.cols,
            elements
                .into_iter()
                .map(|value| Value::Logical(value.as_scalar().unwrap_or(0.0) != 0.0))
                .collect(),
        )?)
    } else {
        Value::Matrix(MatrixValue::new(unique_rows.len(), matrix.cols, elements)?)
    };
    match output_arity {
        0 | 1 => Ok(vec![unique_value]),
        2 => Ok(vec![unique_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            unique_value,
            indices_to_value(ia, false)?,
            indices_to_value(ic, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "unique currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn unique_text_row_outputs(
    value: &Value,
    options: UniqueOptions,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (cols, rows) = text_row_entries(value, "unique")?;

    let mut unique_rows = Vec::<TextRowEntry>::new();
    for entry in &rows {
        if let Some(existing) = unique_rows
            .iter_mut()
            .find(|existing| existing.key == entry.key)
        {
            if matches!(options.occurrence, UniqueOccurrence::Last) {
                existing.index = entry.index;
                existing.prototypes = entry.prototypes.clone();
            }
        } else {
            unique_rows.push(entry.clone());
        }
    }

    if matches!(options.order, UniqueOrder::Sorted) {
        unique_rows.sort_by(|lhs, rhs| {
            compare_text_row_keys(&lhs.key, &rhs.key).then(lhs.index.cmp(&rhs.index))
        });
    }

    let ia = unique_rows
        .iter()
        .map(|entry| entry.index)
        .collect::<Vec<_>>();
    let ic = rows
        .iter()
        .map(|entry| {
            unique_rows
                .iter()
                .position(|candidate| candidate.key == entry.key)
                .expect("unique text row present")
                + 1
        })
        .collect::<Vec<_>>();
    let unique_value = text_row_entries_output(&unique_rows, cols)?;

    match output_arity {
        0 | 1 => Ok(vec![unique_value]),
        2 => Ok(vec![unique_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            unique_value,
            indices_to_value(ia, false)?,
            indices_to_value(ic, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "unique currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn compare_numeric_row_keys(lhs: &[f64], rhs: &[f64]) -> std::cmp::Ordering {
    for (lhs_value, rhs_value) in lhs.iter().zip(rhs.iter()) {
        let ordering = lhs_value.total_cmp(rhs_value);
        if ordering != std::cmp::Ordering::Equal {
            return ordering;
        }
    }
    lhs.len().cmp(&rhs.len())
}

fn compare_text_row_keys(lhs: &[String], rhs: &[String]) -> std::cmp::Ordering {
    for (lhs_value, rhs_value) in lhs.iter().zip(rhs.iter()) {
        let ordering = lhs_value.cmp(rhs_value);
        if ordering != std::cmp::Ordering::Equal {
            return ordering;
        }
    }
    lhs.len().cmp(&rhs.len())
}

#[derive(Clone)]
struct NumericRowEntry {
    key: Vec<f64>,
    index: usize,
}

#[derive(Clone)]
struct TextRowEntry {
    key: Vec<String>,
    prototypes: Vec<TextPrototype>,
    index: usize,
}

fn numeric_row_entries(
    value: &Value,
    builtin_name: &str,
) -> Result<(usize, Vec<NumericRowEntry>, bool), RuntimeError> {
    let matrix = match value {
        Value::Logical(flag) => MatrixValue::new(1, 1, vec![Value::Logical(*flag)])?,
        _ => coerce_matrix(value)?,
    };
    let logical_output = matrix_is_logical(&matrix);
    if !(matrix_is_numeric(&matrix) || logical_output) {
        return Err(RuntimeError::TypeError(format!(
            "{builtin_name} currently expects numeric or logical matrix input when using `'rows'`"
        )));
    }
    let entries = (0..matrix.rows)
        .map(|row| {
            let key = (0..matrix.cols)
                .map(|col| matrix.get(row, col).as_scalar())
                .collect::<Result<Vec<_>, _>>()?;
            Ok(NumericRowEntry {
                key,
                index: row + 1,
            })
        })
        .collect::<Result<Vec<_>, RuntimeError>>()?;
    Ok((matrix.cols, entries, logical_output))
}

fn text_row_entries(
    value: &Value,
    builtin_name: &str,
) -> Result<(usize, Vec<TextRowEntry>), RuntimeError> {
    if let Some(matrix) = coerce_char_matrix_like(value)? {
        let entries = (0..matrix.rows)
            .map(|row| {
                let key = (0..matrix.cols)
                    .map(|col| {
                        single_char_text_value(matrix.get(row, col))
                            .expect("coerced char matrix exposes single-character elements")
                            .to_string()
                    })
                    .collect::<Vec<_>>();
                TextRowEntry {
                    key,
                    prototypes: vec![TextPrototype::Char; matrix.cols],
                    index: row + 1,
                }
            })
            .collect::<Vec<_>>();
        return Ok((matrix.cols, entries));
    }

    let operand = text_operand(value).map_err(|_| {
        RuntimeError::TypeError(format!(
            "{builtin_name} currently expects text matrix input when using `'rows'`"
        ))
    })?;
    let entries = (0..operand.rows)
        .map(|row| {
            let start = row * operand.cols;
            let end = start + operand.cols;
            TextRowEntry {
                key: operand.values[start..end].to_vec(),
                prototypes: operand.prototypes[start..end].to_vec(),
                index: row + 1,
            }
        })
        .collect::<Vec<_>>();
    Ok((operand.cols, entries))
}

fn ensure_row_operation_compatible_columns(
    lhs_cols: usize,
    rhs_cols: usize,
    builtin_name: &str,
) -> Result<(), RuntimeError> {
    if lhs_cols != rhs_cols {
        return Err(RuntimeError::ShapeError(format!(
            "{builtin_name} currently expects matrices with the same number of columns when using `'rows'`"
        )));
    }
    Ok(())
}

fn row_entries_output(
    entries: &[NumericRowEntry],
    cols: usize,
    logical_output: bool,
) -> Result<Value, RuntimeError> {
    let elements = entries
        .iter()
        .flat_map(|entry| {
            entry.key.iter().copied().map(move |value| {
                if logical_output {
                    Value::Logical(value != 0.0)
                } else {
                    Value::Scalar(value)
                }
            })
        })
        .collect::<Vec<_>>();
    Ok(Value::Matrix(MatrixValue::new(
        entries.len(),
        cols,
        elements,
    )?))
}

fn text_row_entries_output(entries: &[TextRowEntry], cols: usize) -> Result<Value, RuntimeError> {
    let values = entries
        .iter()
        .flat_map(|entry| entry.key.iter().cloned())
        .collect::<Vec<_>>();
    let prototypes = entries
        .iter()
        .flat_map(|entry| entry.prototypes.iter().copied())
        .collect::<Vec<_>>();
    build_text_result(entries.len(), cols, values, prototypes)
}

fn unique_row_first_occurrences(entries: &[NumericRowEntry]) -> Vec<NumericRowEntry> {
    let mut unique = Vec::new();
    for entry in entries {
        if unique
            .iter()
            .any(|existing: &NumericRowEntry| existing.key == entry.key)
        {
            continue;
        }
        unique.push(entry.clone());
    }
    unique
}

fn unique_text_row_first_occurrences(entries: &[TextRowEntry]) -> Vec<TextRowEntry> {
    let mut unique = Vec::new();
    for entry in entries {
        if unique
            .iter()
            .any(|existing: &TextRowEntry| existing.key == entry.key)
        {
            continue;
        }
        unique.push(entry.clone());
    }
    unique
}

fn union_numeric_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows, lhs_logical) = numeric_row_entries(lhs, "union")?;
    let (rhs_cols, rhs_rows, rhs_logical) = numeric_row_entries(rhs, "union")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "union")?;

    let lhs_unique = unique_row_first_occurrences(&lhs_rows);
    let mut combined = lhs_unique
        .iter()
        .cloned()
        .map(|entry| (entry, true))
        .collect::<Vec<_>>();
    for entry in unique_row_first_occurrences(&rhs_rows) {
        if lhs_unique
            .iter()
            .any(|lhs_entry| lhs_entry.key == entry.key)
        {
            continue;
        }
        combined.push((entry, false));
    }
    if matches!(order, SetOrder::Sorted) {
        combined.sort_by(|lhs, rhs| compare_numeric_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = combined
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = combined
        .iter()
        .filter_map(|(entry, from_lhs)| (*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();
    let ib = combined
        .iter()
        .filter_map(|(entry, from_lhs)| (!*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();

    let union_value = row_entries_output(&values, lhs_cols, lhs_logical && rhs_logical)?;
    match output_arity {
        0 | 1 => Ok(vec![union_value]),
        2 => Ok(vec![union_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            union_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "union currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn intersect_numeric_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows, lhs_logical) = numeric_row_entries(lhs, "intersect")?;
    let (rhs_cols, rhs_rows, rhs_logical) = numeric_row_entries(rhs, "intersect")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "intersect")?;

    let lhs_unique = unique_row_first_occurrences(&lhs_rows);
    let rhs_unique = unique_row_first_occurrences(&rhs_rows);
    let mut common = Vec::<(NumericRowEntry, usize)>::new();
    for lhs_entry in lhs_unique {
        if let Some(rhs_entry) = rhs_unique
            .iter()
            .find(|rhs_entry| rhs_entry.key == lhs_entry.key)
        {
            common.push((lhs_entry, rhs_entry.index));
        }
    }
    if matches!(order, SetOrder::Sorted) {
        common.sort_by(|lhs, rhs| compare_numeric_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = common
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = common
        .iter()
        .map(|(entry, _)| entry.index)
        .collect::<Vec<_>>();
    let ib = common
        .iter()
        .map(|(_, rhs_index)| *rhs_index)
        .collect::<Vec<_>>();

    let intersect_value = row_entries_output(&values, lhs_cols, lhs_logical && rhs_logical)?;
    match output_arity {
        0 | 1 => Ok(vec![intersect_value]),
        2 => Ok(vec![intersect_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            intersect_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "intersect currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn setdiff_numeric_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows, lhs_logical) = numeric_row_entries(lhs, "setdiff")?;
    let (rhs_cols, rhs_rows, rhs_logical) = numeric_row_entries(rhs, "setdiff")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "setdiff")?;

    let rhs_unique = unique_row_first_occurrences(&rhs_rows);
    let mut difference = unique_row_first_occurrences(&lhs_rows)
        .into_iter()
        .filter(|entry| {
            !rhs_unique
                .iter()
                .any(|rhs_entry| rhs_entry.key == entry.key)
        })
        .collect::<Vec<_>>();
    if matches!(order, SetOrder::Sorted) {
        difference.sort_by(|lhs, rhs| compare_numeric_row_keys(&lhs.key, &rhs.key));
    }

    let ia = difference
        .iter()
        .map(|entry| entry.index)
        .collect::<Vec<_>>();
    let difference_value = row_entries_output(&difference, lhs_cols, lhs_logical && rhs_logical)?;
    match output_arity {
        0 | 1 => Ok(vec![difference_value]),
        2 => Ok(vec![difference_value, indices_to_value(ia, false)?]),
        _ => Err(RuntimeError::Unsupported(
            "setdiff currently supports one or two outputs".to_string(),
        )),
    }
}

fn setxor_numeric_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows, lhs_logical) = numeric_row_entries(lhs, "setxor")?;
    let (rhs_cols, rhs_rows, rhs_logical) = numeric_row_entries(rhs, "setxor")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "setxor")?;

    let lhs_unique = unique_row_first_occurrences(&lhs_rows);
    let rhs_unique = unique_row_first_occurrences(&rhs_rows);
    let mut exclusive = lhs_unique
        .iter()
        .filter(|entry| {
            !rhs_unique
                .iter()
                .any(|rhs_entry| rhs_entry.key == entry.key)
        })
        .cloned()
        .map(|entry| (entry, true))
        .collect::<Vec<_>>();
    exclusive.extend(
        rhs_unique
            .iter()
            .filter(|entry| {
                !lhs_unique
                    .iter()
                    .any(|lhs_entry| lhs_entry.key == entry.key)
            })
            .cloned()
            .map(|entry| (entry, false)),
    );
    if matches!(order, SetOrder::Sorted) {
        exclusive.sort_by(|lhs, rhs| compare_numeric_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = exclusive
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = exclusive
        .iter()
        .filter_map(|(entry, from_lhs)| (*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();
    let ib = exclusive
        .iter()
        .filter_map(|(entry, from_lhs)| (!*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();

    let setxor_value = row_entries_output(&values, lhs_cols, lhs_logical && rhs_logical)?;
    match output_arity {
        0 | 1 => Ok(vec![setxor_value]),
        2 => Ok(vec![setxor_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            setxor_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "setxor currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn union_text_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows) = text_row_entries(lhs, "union")?;
    let (rhs_cols, rhs_rows) = text_row_entries(rhs, "union")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "union")?;

    let lhs_unique = unique_text_row_first_occurrences(&lhs_rows);
    let mut combined = lhs_unique
        .iter()
        .cloned()
        .map(|entry| (entry, true))
        .collect::<Vec<_>>();
    for entry in unique_text_row_first_occurrences(&rhs_rows) {
        if lhs_unique
            .iter()
            .any(|lhs_entry| lhs_entry.key == entry.key)
        {
            continue;
        }
        combined.push((entry, false));
    }
    if matches!(order, SetOrder::Sorted) {
        combined.sort_by(|lhs, rhs| compare_text_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = combined
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = combined
        .iter()
        .filter_map(|(entry, from_lhs)| (*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();
    let ib = combined
        .iter()
        .filter_map(|(entry, from_lhs)| (!*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();

    let union_value = text_row_entries_output(&values, lhs_cols)?;
    match output_arity {
        0 | 1 => Ok(vec![union_value]),
        2 => Ok(vec![union_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            union_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "union currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn intersect_text_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows) = text_row_entries(lhs, "intersect")?;
    let (rhs_cols, rhs_rows) = text_row_entries(rhs, "intersect")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "intersect")?;

    let lhs_unique = unique_text_row_first_occurrences(&lhs_rows);
    let rhs_unique = unique_text_row_first_occurrences(&rhs_rows);
    let mut common = Vec::<(TextRowEntry, usize)>::new();
    for lhs_entry in lhs_unique {
        if let Some(rhs_entry) = rhs_unique
            .iter()
            .find(|rhs_entry| rhs_entry.key == lhs_entry.key)
        {
            common.push((lhs_entry, rhs_entry.index));
        }
    }
    if matches!(order, SetOrder::Sorted) {
        common.sort_by(|lhs, rhs| compare_text_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = common
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = common
        .iter()
        .map(|(entry, _)| entry.index)
        .collect::<Vec<_>>();
    let ib = common
        .iter()
        .map(|(_, rhs_index)| *rhs_index)
        .collect::<Vec<_>>();

    let intersect_value = text_row_entries_output(&values, lhs_cols)?;
    match output_arity {
        0 | 1 => Ok(vec![intersect_value]),
        2 => Ok(vec![intersect_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            intersect_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "intersect currently supports one, two, or three outputs".to_string(),
        )),
    }
}

