fn setxor_text_rows_outputs(
    lhs: &Value,
    rhs: &Value,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let (lhs_cols, lhs_rows) = text_row_entries(lhs, "setxor")?;
    let (rhs_cols, rhs_rows) = text_row_entries(rhs, "setxor")?;
    ensure_row_operation_compatible_columns(lhs_cols, rhs_cols, "setxor")?;

    let lhs_unique = unique_text_row_first_occurrences(&lhs_rows);
    let rhs_unique = unique_text_row_first_occurrences(&rhs_rows);
    let mut exclusive = lhs_unique
        .iter()
        .filter(|entry| {
            !rhs_unique
                .iter()
                .any(|rhs_entry| rhs_entry.key == entry.key)
        })
        .cloned()
        .map(|entry| (entry, true))
        .collect::<Vec<_>>();
    exclusive.extend(
        rhs_unique
            .iter()
            .filter(|entry| {
                !lhs_unique
                    .iter()
                    .any(|lhs_entry| lhs_entry.key == entry.key)
            })
            .cloned()
            .map(|entry| (entry, false)),
    );
    if matches!(order, SetOrder::Sorted) {
        exclusive.sort_by(|lhs, rhs| compare_text_row_keys(&lhs.0.key, &rhs.0.key));
    }

    let values = exclusive
        .iter()
        .map(|(entry, _)| entry.clone())
        .collect::<Vec<_>>();
    let ia = exclusive
        .iter()
        .filter_map(|(entry, from_lhs)| (*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();
    let ib = exclusive
        .iter()
        .filter_map(|(entry, from_lhs)| (!*from_lhs).then_some(entry.index))
        .collect::<Vec<_>>();

    let setxor_value = text_row_entries_output(&values, lhs_cols)?;
    match output_arity {
        0 | 1 => Ok(vec![setxor_value]),
        2 => Ok(vec![setxor_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            setxor_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "setxor currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn ismember_numeric_outputs(
    lhs: &NumericOperand,
    rhs: &NumericOperand,
    lhs_dims: Vec<usize>,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let rhs_entries = numeric_membership_entries(rhs);
    let mut members = Vec::with_capacity(lhs.values.len());
    let mut locations = Vec::with_capacity(lhs.values.len());
    for value in &lhs.values {
        let location = rhs_entries
            .iter()
            .find_map(|(candidate, index)| (*candidate == *value).then_some(*index))
            .unwrap_or(0usize);
        members.push(logical_scalar(location != 0));
        locations.push(Value::Scalar(location as f64));
    }

    let member_value = build_scalar_matrix_result_with_dimensions(lhs_dims.clone(), members)?;
    match output_arity {
        0 | 1 => Ok(vec![member_value]),
        2 => Ok(vec![
            member_value,
            build_scalar_matrix_result_with_dimensions(lhs_dims, locations)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "ismember currently supports one or two outputs".to_string(),
        )),
    }
}

