fn union_numeric_outputs(
    lhs: &[f64],
    rhs: &[f64],
    row_output: bool,
    logical_output: bool,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let lhs_unique = numeric_first_occurrences(lhs);
    let rhs_unique = numeric_first_occurrences(rhs);
    let mut combined = lhs_unique
        .iter()
        .map(|(value, index)| (*value, true, *index))
        .collect::<Vec<_>>();
    for (value, index) in rhs_unique {
        if lhs_unique.iter().any(|(lhs_value, _)| *lhs_value == value) {
            continue;
        }
        combined.push((value, false, index));
    }
    if matches!(order, SetOrder::Sorted) {
        combined.sort_by(|lhs, rhs| lhs.0.total_cmp(&rhs.0));
    }

    let values = combined
        .iter()
        .map(|(value, _, _)| *value)
        .collect::<Vec<_>>();
    let ia = combined
        .iter()
        .filter_map(|(_, from_lhs, index)| (*from_lhs).then_some(*index))
        .collect::<Vec<_>>();
    let ib = combined
        .iter()
        .filter_map(|(_, from_lhs, index)| (!*from_lhs).then_some(*index))
        .collect::<Vec<_>>();

    let union_value = numeric_set_output(values, row_output, logical_output)?;
    match output_arity {
        0 | 1 => Ok(vec![union_value]),
        2 => Ok(vec![union_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            union_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "union currently supports one, two, or three outputs".to_string(),
        )),
    }
}

fn intersect_numeric_outputs(
    lhs: &[f64],
    rhs: &[f64],
    row_output: bool,
    logical_output: bool,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let lhs_unique = numeric_first_occurrences(lhs);
    let rhs_unique = numeric_first_occurrences(rhs);
    let mut common = Vec::new();
    for (value, lhs_index) in lhs_unique {
        if let Some((_, rhs_index)) = rhs_unique.iter().find(|(rhs_value, _)| *rhs_value == value) {
            common.push((value, lhs_index, *rhs_index));
        }
    }
    if matches!(order, SetOrder::Sorted) {
        common.sort_by(|lhs, rhs| lhs.0.total_cmp(&rhs.0));
    }

    let values = common
        .iter()
        .map(|(value, _, _)| *value)
        .collect::<Vec<_>>();
    let ia = common
        .iter()
        .map(|(_, index, _)| *index)
        .collect::<Vec<_>>();
    let ib = common
        .iter()
        .map(|(_, _, index)| *index)
        .collect::<Vec<_>>();
    let intersect_value = numeric_set_output(values, row_output, logical_output)?;
    match output_arity {
        0 | 1 => Ok(vec![intersect_value]),
        2 => Ok(vec![intersect_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            intersect_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "intersect currently supports one, two, or three outputs".to_string(),
        )),
    }
}

