fn union_text_outputs(
    lhs_values: &[String],
    lhs_prototypes: &[TextPrototype],
    rhs_values: &[String],
    rhs_prototypes: &[TextPrototype],
    row_output: bool,
    cell_output: bool,
    order: SetOrder,
    output_arity: usize,
) -> Result<Vec<Value>, RuntimeError> {
    let lhs_unique = text_first_occurrences(lhs_values, lhs_prototypes);
    let rhs_unique = text_first_occurrences(rhs_values, rhs_prototypes);
    let mut combined = lhs_unique
        .iter()
        .map(|(value, prototype, index)| (value.clone(), *prototype, true, *index))
        .collect::<Vec<_>>();
    for (value, prototype, index) in rhs_unique {
        if lhs_unique
            .iter()
            .any(|(lhs_value, _, _)| *lhs_value == value)
        {
            continue;
        }
        combined.push((value, prototype, false, index));
    }
    if matches!(order, SetOrder::Sorted) {
        combined.sort_by(|lhs, rhs| lhs.0.cmp(&rhs.0));
    }

    let values = combined
        .iter()
        .map(|(value, _, _, _)| value.clone())
        .collect::<Vec<_>>();
    let prototypes = combined
        .iter()
        .map(|(_, prototype, _, _)| *prototype)
        .collect::<Vec<_>>();
    let ia = combined
        .iter()
        .filter_map(|(_, _, from_lhs, index)| (*from_lhs).then_some(*index))
        .collect::<Vec<_>>();
    let ib = combined
        .iter()
        .filter_map(|(_, _, from_lhs, index)| (!*from_lhs).then_some(*index))
        .collect::<Vec<_>>();

    let union_value = text_set_output_with_mode(values, prototypes, row_output, cell_output)?;
    match output_arity {
        0 | 1 => Ok(vec![union_value]),
        2 => Ok(vec![union_value, indices_to_value(ia, false)?]),
        3 => Ok(vec![
            union_value,
            indices_to_value(ia, false)?,
            indices_to_value(ib, false)?,
        ]),
        _ => Err(RuntimeError::Unsupported(
            "union currently supports one, two, or three outputs".to_string(),
        )),
    }
}

