    #[test]
    fn cell_constructor_supports_empty_scalar_and_size_vector_forms() {
        let empty = Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty matrix"));
        assert_eq!(
            builtin_cell(&[]).expect("cell"),
            Value::Cell(CellValue::new(0, 0, Vec::new()).expect("empty cell"))
        );
        assert_eq!(
            builtin_cell(&[Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(4.0)])
                    .expect("cell size vector"),
            )])
            .expect("cell size vector"),
            Value::Cell(
                CellValue::new(
                    1,
                    4,
                    vec![empty.clone(), empty.clone(), empty.clone(), empty.clone()],
                )
                .expect("cell size vector result"),
            )
        );
        assert_eq!(
            builtin_cell(&[Value::Scalar(-2.0), Value::Scalar(3.0)]).expect("negative cell size"),
            Value::Cell(CellValue::new(0, 3, Vec::new()).expect("empty shaped cell"))
        );
    }

    #[test]
    fn string_and_char_builtins_roundtrip_text_values() {
        let char_value = builtin_char(&[Value::String("alpha".to_string())]).expect("char");
        let string_value = builtin_string(&[Value::CharArray("beta".to_string())]).expect("string");

        assert_eq!(char_value, Value::CharArray("alpha".to_string()));
        assert_eq!(
            builtin_char(&[Value::Scalar(65.0)]).expect("scalar char code"),
            Value::CharArray("A".to_string())
        );
        assert_eq!(
            builtin_char(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(65.0),
                        Value::Scalar(66.0),
                        Value::Scalar(67.0)
                    ],
                )
                .expect("char code row"),
            )])
            .expect("row char codes"),
            Value::CharArray("ABC".to_string())
        );
        assert_eq!(
            builtin_double(&[Value::Logical(true)]).expect("double logical"),
            Value::Scalar(1.0)
        );
        assert_eq!(
            builtin_double(&[Value::CharArray("AB".to_string())]).expect("double char"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(65.0), Value::Scalar(66.0)])
                    .expect("double char result"),
            )
        );
        assert_eq!(
            builtin_double(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Logical(true),
                        Value::Logical(false),
                        Value::Logical(false),
                        Value::Logical(true),
                    ],
                )
                .expect("double logical matrix"),
            )])
            .expect("double logical matrix"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                    ],
                )
                .expect("double logical matrix result"),
            )
        );
        assert_eq!(
            builtin_str2double(&[Value::String("12.5".to_string())]).expect("str2double real"),
            Value::Scalar(12.5)
        );
        assert_eq!(
            builtin_str2double(&[Value::CharArray("1+2i".to_string())])
                .expect("str2double complex"),
            Value::Complex(ComplexValue {
                real: 1.0,
                imag: 2.0,
            })
        );
        assert_eq!(
            builtin_str2double(&[Value::CharArray("1 + 2i".to_string())])
                .expect("str2double spaced complex"),
            Value::Complex(ComplexValue {
                real: 1.0,
                imag: 2.0,
            })
        );
        assert_eq!(
            builtin_str2double(&[Value::CharArray("1 - i".to_string())])
                .expect("str2double unit imaginary"),
            Value::Complex(ComplexValue {
                real: 1.0,
                imag: -1.0,
            })
        );
        assert!(builtin_str2double(&[Value::CharArray("1 2".to_string())])
            .expect("str2double invalid spaced real")
            .as_scalar()
            .expect("str2double invalid scalar")
            .is_nan());
        let Value::Matrix(str2double_cell) = builtin_str2double(&[Value::Cell(
            CellValue::new(
                1,
                2,
                vec![
                    Value::CharArray("bad".to_string()),
                    Value::CharArray("-3i".to_string()),
                ],
            )
            .expect("str2double cell"),
        )])
        .expect("str2double cell") else {
            panic!("str2double cell should return a matrix");
        };
        assert!(str2double_cell
            .get(0, 0)
            .as_scalar()
            .expect("nan result")
            .is_nan());
        assert_eq!(
            str2double_cell.get(0, 1),
            &Value::Complex(ComplexValue {
                real: 0.0,
                imag: -3.0,
            })
        );
        assert_eq!(
            builtin_mat2str(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Scalar(4.0),
                    ],
                )
                .expect("mat2str matrix"),
            )])
            .expect("mat2str matrix"),
            Value::CharArray("[1 2;3 4]".to_string())
        );
        assert_eq!(
            builtin_mat2str(&[
                Value::Complex(ComplexValue {
                    real: 1.0,
                    imag: 2.0,
                }),
                Value::Scalar(4.0),
            ])
            .expect("mat2str complex precision"),
            Value::CharArray("1+2i".to_string())
        );
        assert_eq!(
            builtin_mat2str(&[Value::Matrix(
                MatrixValue::new(1, 0, Vec::new()).expect("mat2str empty"),
            )])
            .expect("mat2str empty"),
            Value::CharArray("[]".to_string())
        );
        assert_eq!(
            builtin_int2str(&[Value::Scalar(42.5)]).expect("int2str scalar"),
            Value::CharArray("43".to_string())
        );
        assert_eq!(
            builtin_int2str(&[Value::Logical(true)]).expect("int2str logical"),
            Value::CharArray("1".to_string())
        );
        assert_eq!(
            builtin_int2str(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(1.0), Value::Scalar(20.0), Value::Scalar(-3.0),],
                )
                .expect("int2str row vector"),
            )])
            .expect("int2str row vector"),
            Value::CharArray("1 20 -3".to_string())
        );
        assert_eq!(
            builtin_hex2dec(&[Value::String("3FF".to_string())]).expect("hex2dec"),
            Value::Scalar(1023.0)
        );
        assert_eq!(
            builtin_bin2dec(&[Value::String("0b11111111s8".to_string())]).expect("bin2dec signed"),
            Value::Scalar(-1.0)
        );
        assert_eq!(
            builtin_base2dec(&[Value::String("ZZ".to_string()), Value::Scalar(36.0)])
                .expect("base2dec"),
            Value::Scalar(1295.0)
        );
        assert_eq!(
            builtin_dec2hex(&[
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(15.0), Value::Scalar(16.0)])
                        .expect("dec2hex input"),
                ),
                Value::Scalar(2.0),
            ])
            .expect("dec2hex"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::String("0F".to_string()),
                        Value::String("10".to_string()),
                    ],
                )
                .expect("dec2hex output"),
            )
        );
        assert_eq!(
            builtin_dec2base(&[Value::Scalar(0.0), Value::Scalar(2.0), Value::Scalar(3.0),])
                .expect("dec2base"),
            Value::CharArray("000".to_string())
        );
        assert_eq!(
            builtin_str2func(&[Value::String("@sin".to_string())]).expect("str2func"),
            Value::FunctionHandle(FunctionHandleValue {
                display_name: "sin".to_string(),
                target: FunctionHandleTarget::Named("sin".to_string()),
            })
        );
        assert_eq!(
            builtin_func2str(&[Value::FunctionHandle(FunctionHandleValue {
                display_name: "helper".to_string(),
                target: FunctionHandleTarget::Named("helper".to_string()),
            })])
            .expect("func2str"),
            Value::CharArray("helper".to_string())
        );
        assert_eq!(string_value, Value::String("beta".to_string()));
        assert_eq!(
            builtin_strcmp(&[
                Value::CharArray("alpha".to_string()),
                Value::String("alpha".to_string()),
            ])
            .expect("strcmp"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_string(&[Value::Cell(
                CellValue::new(
                    1,
                    2,
                    vec![Value::CharArray("alpha".to_string()), Value::Logical(true),],
                )
                .expect("string cell"),
            )])
            .expect("string cell"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::String("alpha".to_string()),
                        Value::String("true".to_string()),
                    ],
                )
                .expect("string cell result"),
            )
        );
    }

    #[test]
    fn text_comparison_helpers_cover_case_and_prefix_forms() {
        assert_eq!(
            builtin_strcmpi(&[
                Value::CharArray("Alpha".to_string()),
                Value::String("alpha".to_string()),
            ])
            .expect("strcmpi"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_strncmp(&[
                Value::CharArray("alphabet".to_string()),
                Value::String("alpha".to_string()),
                Value::Scalar(5.0),
            ])
            .expect("strncmp"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_strncmp(&[
                Value::CharArray("ab".to_string()),
                Value::String("abc".to_string()),
                Value::Scalar(3.0),
            ])
            .expect("strncmp mismatch"),
            Value::Logical(false)
        );
        assert_eq!(
            builtin_strncmpi(&[
                Value::Cell(
                    CellValue::new(
                        1,
                        2,
                        vec![
                            Value::CharArray("Alpha".to_string()),
                            Value::CharArray("beta".to_string()),
                        ],
                    )
                    .expect("lhs cell"),
                ),
                Value::Cell(
                    CellValue::new(
                        1,
                        2,
                        vec![
                            Value::String("alpha".to_string()),
                            Value::String("BETa".to_string()),
                        ],
                    )
                    .expect("rhs cell"),
                ),
                Value::Scalar(4.0),
            ])
            .expect("strncmpi cell"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Logical(true), Value::Logical(true)],)
                    .expect("strncmpi cell result"),
            )
        );
    }

    #[test]
    fn iscellstr_reports_char_cell_identity() {
        assert_eq!(
            builtin_iscellstr(&[Value::Cell(
                CellValue::new(
                    1,
                    2,
                    vec![
                        Value::CharArray("alpha".to_string()),
                        Value::CharArray("beta".to_string()),
                    ],
                )
                .expect("char cell"),
            )])
            .expect("iscellstr char cell"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_iscellstr(&[Value::Cell(
                CellValue::new(
                    1,
                    2,
                    vec![
                        Value::CharArray("alpha".to_string()),
                        Value::String("beta".to_string()),
                    ],
                )
                .expect("mixed text cell"),
            )])
            .expect("iscellstr mixed cell"),
            Value::Logical(false)
        );
        assert_eq!(
            builtin_iscellstr(&[Value::Cell(
                CellValue::new(0, 0, Vec::new()).expect("empty cell")
            )])
            .expect("iscellstr empty cell"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_iscellstr(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::String("alpha".to_string()),
                        Value::String("beta".to_string()),
                    ],
                )
                .expect("string matrix"),
            )])
            .expect("iscellstr matrix"),
            Value::Logical(false)
        );
    }

    #[test]
    fn cellstr_converts_text_scalars_and_matrices_to_char_cells() {
        assert_eq!(
            builtin_cellstr(&[Value::String("alpha".to_string())]).expect("cellstr scalar"),
            Value::Cell(
                CellValue::new(1, 1, vec![Value::CharArray("alpha".to_string())])
                    .expect("cellstr scalar result"),
            )
        );

        assert_eq!(
            builtin_cellstr(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::String("alpha".to_string()),
                        Value::String("beta".to_string()),
                        Value::CharArray("gamma".to_string()),
                        Value::CharArray("delta".to_string()),
                    ],
                )
                .expect("text matrix"),
            )])
            .expect("cellstr matrix"),
            Value::Cell(
                CellValue::new(
                    2,
                    2,
                    vec![
                        Value::CharArray("alpha".to_string()),
                        Value::CharArray("beta".to_string()),
                        Value::CharArray("gamma".to_string()),
                        Value::CharArray("delta".to_string()),
                    ],
                )
                .expect("cellstr matrix result"),
            )
        );

        assert_eq!(
            builtin_cellstr(&[Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty")
            )])
            .expect("cellstr empty"),
            Value::Cell(CellValue::new(0, 0, Vec::new()).expect("empty cellstr")),
        );

        assert_eq!(
            builtin_cellstr(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    3,
                    vec![
                        Value::CharArray("a".to_string()),
                        Value::CharArray("b".to_string()),
                        Value::CharArray(" ".to_string()),
                        Value::CharArray("c".to_string()),
                        Value::CharArray("d".to_string()),
                        Value::CharArray("e".to_string()),
                    ],
                )
                .expect("char matrix"),
            )])
            .expect("cellstr char matrix"),
            Value::Cell(
                CellValue::new(
                    2,
                    1,
                    vec![
                        Value::CharArray("ab".to_string()),
                        Value::CharArray("cde".to_string()),
                    ],
                )
                .expect("cellstr char matrix result"),
            )
        );
    }

