    #[test]
    fn complex_diff_and_integration_helpers_support_current_numeric_forms() {
        assert_eq!(
            builtin_diff(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 4.0,
                            imag: 3.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 9.0,
                            imag: 6.0
                        }),
                    ],
                )
                .expect("complex diff row"),
            )])
            .expect("complex diff"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 3.0,
                            imag: 2.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 5.0,
                            imag: 3.0
                        }),
                    ],
                )
                .expect("complex diff result"),
            )
        );
        assert_eq!(
            builtin_trapz(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 3.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 5.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex trapz row"),
            )])
            .expect("complex trapz"),
            Value::Complex(ComplexValue {
                real: 6.0,
                imag: 1.0
            })
        );
        assert_eq!(
            builtin_cumtrapz(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 3.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 5.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex cumtrapz row"),
            )])
            .expect("complex cumtrapz"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 2.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 6.0,
                            imag: 1.0
                        }),
                    ],
                )
                .expect("complex cumtrapz result"),
            )
        );
    }

    #[test]
    fn shape_helpers_cover_diag_prod_and_repmat() {
        assert_eq!(
            builtin_prod(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    4,
                    vec![
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Scalar(4.0),
                        Value::Scalar(5.0),
                    ],
                )
                .expect("vector"),
            )])
            .expect("prod"),
            Value::Scalar(120.0)
        );
        assert_eq!(
            builtin_diag(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(5.0), Value::Scalar(6.0), Value::Scalar(7.0),],
                )
                .expect("vector"),
            )])
            .expect("diag vector"),
            Value::Matrix(
                MatrixValue::new(
                    3,
                    3,
                    vec![
                        Value::Scalar(5.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(6.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(7.0),
                    ],
                )
                .expect("diag matrix"),
            )
        );
        assert_eq!(
            builtin_diag(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(5.0), Value::Scalar(6.0), Value::Scalar(7.0),],
                    )
                    .expect("vector"),
                ),
                Value::Scalar(1.0),
            ])
            .expect("diag vector offset"),
            Value::Matrix(
                MatrixValue::new(
                    4,
                    4,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(5.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(6.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(7.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("diag matrix offset"),
            )
        );
        assert_eq!(
            builtin_diag(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(4.0),
                            Value::Scalar(5.0),
                            Value::Scalar(6.0),
                        ],
                    )
                    .expect("matrix"),
                ),
                Value::Scalar(1.0),
            ])
            .expect("diag matrix positive offset"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(2.0), Value::Scalar(6.0)])
                    .expect("diag extracted positive offset"),
            )
        );
        assert_eq!(
            builtin_repmat(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("matrix"),
                ),
                Value::Scalar(2.0),
                Value::Scalar(1.0),
            ])
            .expect("repmat"),
            Value::Matrix(
                MatrixValue::new(
                    4,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Scalar(4.0),
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Scalar(4.0),
                    ],
                )
                .expect("repmat matrix"),
            )
        );
    }

    #[test]
    fn matrix_operator_aliases_support_current_numeric_forms() {
        assert_eq!(
            builtin_mtimes(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("lhs"),
                ),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(5.0), Value::Scalar(6.0)])
                        .expect("rhs"),
                ),
            ])
            .expect("mtimes"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(17.0), Value::Scalar(39.0)])
                    .expect("mtimes result"),
            )
        );
        assert_eq!(
            builtin_mldivide(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("lhs"),
                ),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(5.0), Value::Scalar(11.0)])
                        .expect("rhs"),
                ),
            ])
            .expect("mldivide"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                    .expect("mldivide result"),
            )
        );
        assert_eq!(
            builtin_mrdivide(&[
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(5.0), Value::Scalar(11.0)])
                        .expect("lhs"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("rhs"),
                ),
            ])
            .expect("mrdivide"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(6.5), Value::Scalar(-0.5)])
                    .expect("mrdivide result"),
            )
        );
        assert_eq!(
            builtin_mpower(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(-1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("base"),
                ),
                Value::Scalar(2.0),
            ])
            .expect("mpower"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(-1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(-1.0),
                    ],
                )
                .expect("mpower result"),
            )
        );
        assert_eq!(
            builtin_ctranspose(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Complex(ComplexValue {
                            real: 4.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex matrix"),
            )])
            .expect("ctranspose"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: -1.0
                        }),
                        Value::Scalar(3.0),
                        Value::Scalar(2.0),
                        Value::Complex(ComplexValue {
                            real: 4.0,
                            imag: 1.0
                        }),
                    ],
                )
                .expect("ctranspose result"),
            )
        );
    }

    #[test]
    fn diag_supports_current_complex_forms() {
        assert_eq!(
            builtin_diag(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("complex vector"),
            )])
            .expect("diag complex vector"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("diag complex vector result"),
            )
        );
        assert_eq!(
            builtin_diag(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 1.0
                            }),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("complex vector"),
                ),
                Value::Scalar(1.0),
            ])
            .expect("diag complex vector offset"),
            Value::Matrix(
                MatrixValue::new(
                    3,
                    3,
                    vec![
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("diag complex vector offset result"),
            )
        );
        assert_eq!(
            builtin_diag(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Complex(ComplexValue {
                            real: 4.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex matrix"),
            )])
            .expect("diag complex matrix"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    1,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 4.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("diag complex matrix result"),
            )
        );
    }

