    #[test]
    fn det_and_inv_support_current_complex_forms() {
        assert_eq!(
            builtin_det(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(3.0),
                        Value::Scalar(2.0),
                        Value::Scalar(4.0),
                    ],
                )
                .expect("matrix"),
            )])
            .expect("det real"),
            Value::Scalar(-2.0)
        );
        assert_eq!(
            builtin_det(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 2.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex matrix"),
            )])
            .expect("det complex"),
            Value::Complex(ComplexValue {
                real: 3.0,
                imag: 1.0
            })
        );
        assert_eq!(
            builtin_inv(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                        Value::Scalar(3.0),
                        Value::Scalar(4.0),
                    ],
                )
                .expect("matrix"),
            )])
            .expect("inv real"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(-2.0),
                        Value::Scalar(1.0),
                        Value::Scalar(1.5),
                        Value::Scalar(-0.5),
                    ],
                )
                .expect("inv real result"),
            )
        );
        assert_eq!(
            builtin_inv(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 2.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex matrix"),
            )])
            .expect("inv complex"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.5,
                            imag: -0.5
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 0.4,
                            imag: 0.2
                        }),
                    ],
                )
                .expect("inv complex result"),
            )
        );
    }

    #[test]
    fn rectangular_division_and_pinv_support_current_full_rank_forms() {
        assert_eq!(
            builtin_mldivide(&[
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("tall matrix"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        1,
                        vec![Value::Scalar(1.0), Value::Scalar(2.0), Value::Scalar(3.0)],
                    )
                    .expect("rhs"),
                ),
            ])
            .expect("mldivide tall"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                    .expect("tall solution"),
            )
        );
        assert_eq!(
            builtin_mldivide(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("wide matrix"),
                ),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                        .expect("wide rhs"),
                ),
            ])
            .expect("mldivide wide"),
            Value::Matrix(
                MatrixValue::new(
                    3,
                    1,
                    vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(1.0)],
                )
                .expect("wide solution"),
            )
        );
        assert_eq!(
            builtin_mrdivide(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(1.0), Value::Scalar(2.0), Value::Scalar(3.0)],
                    )
                    .expect("lhs row"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("rhs wide"),
                ),
            ])
            .expect("mrdivide wide"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                    .expect("mrdivide solution"),
            )
        );
        assert_eq!(
            builtin_mldivide(&[
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 0.0
                            }),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 0.0
                            }),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 1.0
                            }),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: -1.0
                            }),
                        ],
                    )
                    .expect("complex tall matrix"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        1,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Complex(ComplexValue {
                                real: 3.0,
                                imag: -1.0
                            }),
                        ],
                    )
                    .expect("complex rhs"),
                ),
            ])
            .expect("mldivide complex"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                    .expect("complex solution"),
            )
        );
        assert_eq!(
            builtin_pinv(&[Value::Matrix(
                MatrixValue::new(
                    3,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                        Value::Scalar(1.0),
                        Value::Scalar(1.0),
                    ],
                )
                .expect("tall matrix"),
            )])
            .expect("pinv tall"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    3,
                    vec![
                        Value::Scalar(0.666_666_666_666),
                        Value::Scalar(-0.333_333_333_333),
                        Value::Scalar(0.333_333_333_334),
                        Value::Scalar(-0.333_333_333_333),
                        Value::Scalar(0.666_666_666_668),
                        Value::Scalar(0.333_333_333_333),
                    ],
                )
                .expect("pinv tall result"),
            )
        );
        assert_eq!(
            builtin_pinv(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    3,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                        Value::Scalar(1.0),
                    ],
                )
                .expect("wide matrix"),
            )])
            .expect("pinv wide"),
            Value::Matrix(
                MatrixValue::new(
                    3,
                    2,
                    vec![
                        Value::Scalar(0.666_666_666_668),
                        Value::Scalar(-0.333_333_333_334),
                        Value::Scalar(-0.333_333_333_334),
                        Value::Scalar(0.666_666_666_668),
                        Value::Scalar(0.333_333_333_334),
                        Value::Scalar(0.333_333_333_334),
                    ],
                )
                .expect("pinv wide result"),
            )
        );
        assert_eq!(
            builtin_pinv(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    3,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("zero matrix"),
            )])
            .expect("pinv zero matrix"),
            Value::Matrix(
                MatrixValue::new(
                    3,
                    2,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("zero pinv"),
            )
        );
        assert_eq!(
            builtin_pinv(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                        Value::Scalar(2.0),
                        Value::Scalar(4.0),
                    ],
                )
                .expect("rank deficient matrix"),
            )])
            .expect("pinv rank deficient"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.04),
                        Value::Scalar(0.08),
                        Value::Scalar(0.08),
                        Value::Scalar(0.16),
                    ],
                )
                .expect("rank deficient pinv"),
            )
        );
        assert_eq!(
            builtin_pinv(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1e-14),
                        ],
                    )
                    .expect("small singular value matrix"),
                ),
                Value::Scalar(1e-12),
            ])
            .expect("pinv tolerance"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("pinv tolerance result"),
            )
        );
        assert_eq!(
            builtin_pinv(&[Value::Matrix(
                MatrixValue::new(
                    3,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 0.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 0.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: 1.0
                        }),
                        Value::Complex(ComplexValue {
                            real: 1.0,
                            imag: -1.0
                        }),
                    ],
                )
                .expect("complex matrix"),
            )])
            .expect("pinv complex"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    3,
                    vec![
                        Value::Scalar(0.599_999_999_999),
                        Value::Complex(ComplexValue {
                            real: 0.0,
                            imag: 0.4
                        }),
                        Value::Complex(ComplexValue {
                            real: 0.2,
                            imag: -0.2
                        }),
                        Value::Complex(ComplexValue {
                            real: 0.0,
                            imag: -0.4
                        }),
                        Value::Scalar(0.600_000_000_001),
                        Value::Complex(ComplexValue {
                            real: 0.2,
                            imag: 0.2
                        }),
                    ],
                )
                .expect("pinv complex result"),
            )
        );
    }

    #[test]
    fn qr_and_lu_support_current_factorization_forms() {
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(-1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("qr matrix"),
                )],
                1,
            )
            .expect("qr one output"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.414_213_562_373),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.414_213_562_373),
                    ],
                )
                .expect("qr r"),
            )]
        );
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty qr")
                )],
                1
            )
            .expect("empty qr one output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty qr r")
            )]
        );
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 0.0
                            }),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 1.0
                            }),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 0.0
                            }),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("complex qr matrix"),
                )],
                2,
            )
            .expect("qr two outputs"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(0.707_106_781_187),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Complex(ComplexValue {
                                real: 0.707_106_781_187,
                                imag: 0.707_106_781_187,
                            }),
                            Value::Scalar(0.707_106_781_187),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("qr q"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.414_213_562_373),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.414_213_562_373),
                        ],
                    )
                    .expect("qr r"),
                ),
            ]
        );
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty qr factors")
                )],
                2,
            )
            .expect("empty qr two outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty qr q")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty qr r two")),
            ]
        );
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(10.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr matrix"),
                )],
                3,
            )
            .expect("qr three outputs"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr q"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(10.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr r"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr p"),
                ),
            ]
        );
        assert_eq!(
            builtin_qr(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            3,
                            2,
                            vec![
                                Value::Scalar(1.0),
                                Value::Scalar(10.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                            ],
                        )
                        .expect("pivoted qr vector matrix"),
                    ),
                    Value::CharArray("vector".to_string()),
                ],
                3,
            )
            .expect("qr vector output"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr q"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(10.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("pivoted qr r"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(2.0), Value::Scalar(1.0)])
                        .expect("pivoted qr p vector"),
                ),
            ]
        );
        assert_eq!(
            builtin_qr(
                &[
                    Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty qr vector")),
                    Value::CharArray("vector".to_string()),
                ],
                3,
            )
            .expect("empty qr vector outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty qr vector q")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty qr vector r")),
                Value::Matrix(MatrixValue::new(1, 0, Vec::new()).expect("empty qr vector p")),
            ]
        );
        assert_eq!(
            builtin_qr(
                &[Value::Matrix(
                    MatrixValue::new(3, 0, Vec::new()).expect("tall empty qr")
                )],
                2,
            )
            .expect("tall empty qr factors"),
            vec![
                Value::Matrix(MatrixValue::new(3, 0, Vec::new()).expect("tall empty qr q")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("tall empty qr r")),
            ]
        );
        assert_eq!(
            builtin_lu(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(4.0),
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("lu matrix"),
                )],
                1,
            )
            .expect("lu one output"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(4.0),
                        Value::Scalar(1.0),
                        Value::Scalar(0.5),
                        Value::Scalar(2.5),
                    ],
                )
                .expect("packed lu"),
            )]
        );
        assert_eq!(
            builtin_lu(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 0.0
                            }),
                            Value::Scalar(1.0),
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 1.0
                            }),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("complex lu matrix"),
                )],
                3,
            )
            .expect("lu three outputs"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("lu l"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 1.0,
                                imag: 1.0
                            }),
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("lu u"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("lu p"),
                ),
            ]
        );
    }

    #[test]
    fn svd_supports_current_dense_forms() {
        assert_eq!(
            builtin_svd(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("square matrix"),
                )],
                1,
            )
            .expect("svd one output"),
            vec![Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(3.0), Value::Scalar(2.0)])
                    .expect("svd vector"),
            )]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            2,
                            2,
                            vec![
                                Value::Scalar(0.0),
                                Value::Scalar(2.0),
                                Value::Scalar(3.0),
                                Value::Scalar(0.0),
                            ],
                        )
                        .expect("square matrix"),
                    ),
                    Value::CharArray("matrix".to_string()),
                ],
                1,
            )
            .expect("svd matrix output"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(3.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("svd matrix"),
            )]
        );
        assert_eq!(
            builtin_svd(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("rectangular matrix"),
                )],
                3,
            )
            .expect("svd full outputs"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("svd u"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("svd s"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("svd v"),
                ),
            ]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            3,
                            2,
                            vec![
                                Value::Scalar(0.0),
                                Value::Scalar(2.0),
                                Value::Scalar(3.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                            ],
                        )
                        .expect("rectangular matrix"),
                    ),
                    Value::CharArray("econ".to_string()),
                ],
                3,
            )
            .expect("svd econ outputs"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("svd econ u"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("svd econ s"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("svd econ v"),
                ),
            ]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            2,
                            2,
                            vec![
                                Value::Complex(ComplexValue {
                                    real: 0.0,
                                    imag: 2.0
                                }),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(1.0),
                            ],
                        )
                        .expect("complex matrix"),
                    ),
                    Value::CharArray("vector".to_string()),
                ],
                3,
            )
            .expect("svd complex"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 1.0
                            }),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("complex u"),
                ),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(2.0), Value::Scalar(1.0)])
                        .expect("complex singular values"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("complex v"),
                ),
            ]
        );
    }

    #[test]
    fn eig_supports_current_square_matrix_forms() {
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("symmetric matrix"),
                )],
                1,
            )
            .expect("eig vector"),
            vec![Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(2.0), Value::Scalar(-2.0)])
                    .expect("eigenvalue vector"),
            )]
        );
        assert_eq!(
            builtin_eig(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            3,
                            3,
                            vec![
                                Value::Scalar(1.0),
                                Value::Scalar(2.0),
                                Value::Scalar(3.0),
                                Value::Scalar(0.0),
                                Value::Scalar(4.0),
                                Value::Scalar(5.0),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(6.0),
                            ],
                        )
                        .expect("triangular matrix"),
                    ),
                    Value::CharArray("matrix".to_string()),
                ],
                1,
            )
            .expect("eig matrix output"),
            vec![Value::Matrix(
                MatrixValue::new(
                    3,
                    3,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(4.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(6.0),
                    ],
                )
                .expect("eigenvalue matrix"),
            )]
        );
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("symmetric matrix"),
                )],
                2,
            )
            .expect("eig vectors"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(-0.707_106_781_186_547_5),
                        ],
                    )
                    .expect("eig vectors"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(-2.0),
                        ],
                    )
                    .expect("eig values"),
                ),
            ]
        );
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("nonsymmetric diagonalizable"),
                )],
                3,
            )
            .expect("eig left vectors"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(1.0),
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("right eigenvectors"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("eigenvalues"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(0.707_106_781_186_547_5),
                            Value::Scalar(1.0),
                            Value::Scalar(-0.707_106_781_186_547_5),
                        ],
                    )
                    .expect("left eigenvectors"),
                ),
            ]
        );
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("defective matrix"),
                )],
                2,
            )
            .expect("eig defective"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("defective vectors"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("defective values"),
                ),
            ]
        );
        assert_eq!(
            builtin_eig(
                &[
                    Value::Matrix(
                        MatrixValue::new(
                            2,
                            2,
                            vec![
                                Value::Complex(ComplexValue {
                                    real: 0.0,
                                    imag: 1.0
                                }),
                                Value::Scalar(0.0),
                                Value::Scalar(0.0),
                                Value::Scalar(1.0),
                            ],
                        )
                        .expect("complex diagonal"),
                    ),
                    Value::CharArray("vector".to_string()),
                ],
                2,
            )
            .expect("eig complex"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("complex eigenvectors"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        1,
                        vec![
                            Value::Scalar(1.0),
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 1.0
                            }),
                        ],
                    )
                    .expect("complex eigenvalues"),
                ),
            ]
        );
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty eig")
                )],
                1
            )
            .expect("empty eig vector output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 1, Vec::new()).expect("empty eig values")
            )]
        );
        assert_eq!(
            builtin_eig(
                &[
                    Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty eig matrix")),
                    Value::CharArray("matrix".to_string()),
                ],
                1,
            )
            .expect("empty eig matrix output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty eig diagonal")
            )]
        );
        assert_eq!(
            builtin_eig(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty eig vectors")
                )],
                2
            )
            .expect("empty eig two outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty eig right vectors")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty eig values matrix")),
            ]
        );
    }

    #[test]
    fn expm_supports_current_dense_square_forms() {
        assert_eq!(
            builtin_expm(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("diagonal matrix"),
            )])
            .expect("expm diagonal"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(2.718_281_828_459),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(7.389_056_098_931),
                    ],
                )
                .expect("diagonal expm"),
            )
        );
        assert_eq!(
            builtin_expm(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                        Value::Scalar(-1.0),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("rotation generator"),
            )])
            .expect("expm rotation"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.540_302_305_868),
                        Value::Scalar(0.841_470_984_808),
                        Value::Scalar(-0.841_470_984_808),
                        Value::Scalar(0.540_302_305_868),
                    ],
                )
                .expect("rotation expm"),
            )
        );
        assert_eq!(
            builtin_expm(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                    ],
                )
                .expect("jordan block"),
            )])
            .expect("expm jordan"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(2.718_281_828_459),
                        Value::Scalar(2.718_281_828_459),
                        Value::Scalar(0.0),
                        Value::Scalar(2.718_281_828_459),
                    ],
                )
                .expect("jordan expm"),
            )
        );
        assert_eq!(
            builtin_expm(&[Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.0,
                            imag: 1.0
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.0),
                    ],
                )
                .expect("complex diagonal"),
            )])
            .expect("expm complex"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.540_302_305_868,
                            imag: 0.841_470_984_808,
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.718_281_828_459),
                    ],
                )
                .expect("complex expm"),
            )
        );
    }

    #[test]
    fn sqrtm_supports_current_dense_square_forms() {
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("diagonal matrix"),
                )],
                1,
            )
            .expect("sqrtm diagonal"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("sqrtm diagonal result"),
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(7.0),
                            Value::Scalar(10.0),
                            Value::Scalar(15.0),
                            Value::Scalar(22.0),
                        ],
                    )
                    .expect("general matrix"),
                )],
                1,
            )
            .expect("sqrtm general"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.566_698_903_601_856_4),
                        Value::Scalar(1.740_776_559_557_101),
                        Value::Scalar(2.611_164_839_336_919),
                        Value::Scalar(4.177_863_742_936_759),
                    ],
                )
                .expect("sqrtm general result"),
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("jordan matrix"),
                )],
                2,
            )
            .expect("sqrtm jordan"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.5),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("sqrtm jordan result"),
                ),
                Value::Scalar(0.0),
            ]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 1.0
                            }),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("complex diagonal"),
                )],
                1,
            )
            .expect("sqrtm complex"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.707_106_781_187,
                            imag: 0.707_106_781_187,
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("sqrtm complex result"),
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        3,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(4.0),
                            Value::Scalar(2.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(9.0),
                        ],
                    )
                    .expect("upper triangular"),
                )],
                1,
            )
            .expect("sqrtm upper triangular"),
            vec![Value::Matrix(
                MatrixValue::new(
                    3,
                    3,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.333_333_333_333),
                        Value::Scalar(0.716_666_666_667),
                        Value::Scalar(0.0),
                        Value::Scalar(2.0),
                        Value::Scalar(0.4),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(3.0),
                    ],
                )
                .expect("sqrtm upper triangular result"),
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(
                        3,
                        3,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(4.0),
                            Value::Scalar(0.0),
                            Value::Scalar(3.0),
                            Value::Scalar(2.0),
                            Value::Scalar(9.0),
                        ],
                    )
                    .expect("lower triangular"),
                )],
                1,
            )
            .expect("sqrtm lower triangular"),
            vec![Value::Matrix(
                MatrixValue::new(
                    3,
                    3,
                    vec![
                        Value::Scalar(1.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.333_333_333_333),
                        Value::Scalar(2.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.716_666_666_667),
                        Value::Scalar(0.4),
                        Value::Scalar(3.0),
                    ],
                )
                .expect("sqrtm lower triangular result"),
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty sqrtm")
                )],
                1,
            )
            .expect("empty sqrtm one output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty sqrtm result")
            )]
        );
        assert_eq!(
            builtin_sqrtm(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty sqrtm residual")
                )],
                2,
            )
            .expect("empty sqrtm two outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty sqrtm matrix")),
                Value::Scalar(0.0),
            ]
        );
    }

    #[test]
    fn svd_supports_empty_matrix_outputs() {
        assert_eq!(
            builtin_svd(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty svd")
                )],
                1,
            )
            .expect("empty svd one output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 1, Vec::new()).expect("empty svd vector")
            )]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(MatrixValue::new(0, 3, Vec::new()).expect("empty wide svd")),
                    Value::CharArray("matrix".to_string()),
                ],
                1,
            )
            .expect("empty svd matrix output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty svd matrix")
            )]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty full svd")),
                    Value::CharArray("vector".to_string()),
                ],
                3,
            )
            .expect("empty full svd outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty full u")),
                Value::Matrix(MatrixValue::new(0, 1, Vec::new()).expect("empty full s")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty full v")),
            ]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(MatrixValue::new(0, 3, Vec::new()).expect("empty econ wide svd")),
                    Value::CharArray("econ".to_string()),
                ],
                3,
            )
            .expect("empty econ wide svd outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty econ wide u")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty econ wide s")),
                Value::Matrix(MatrixValue::new(3, 0, Vec::new()).expect("empty econ wide v")),
            ]
        );
        assert_eq!(
            builtin_svd(
                &[
                    Value::Matrix(MatrixValue::new(3, 0, Vec::new()).expect("empty econ tall svd")),
                    Value::CharArray("econ".to_string()),
                ],
                3,
            )
            .expect("empty econ tall svd outputs"),
            vec![
                Value::Matrix(MatrixValue::new(3, 0, Vec::new()).expect("empty econ tall u")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty econ tall s")),
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty econ tall v")),
            ]
        );
    }

    #[test]
    fn logm_supports_current_dense_square_forms() {
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("diagonal matrix"),
                )],
                1,
            )
            .expect("logm diagonal"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.386_294_361_12),
                    ],
                )
                .expect("logm diagonal result"),
            )]
        );
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                        ],
                    )
                    .expect("jordan block"),
                )],
                2,
            )
            .expect("logm jordan"),
            vec![
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("logm jordan result"),
                ),
                Value::Scalar(0.0),
            ]
        );
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("scalar multiple of identity"),
                )],
                1,
            )
            .expect("logm identity multiple"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.098_612_288_668),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.098_612_288_668),
                    ],
                )
                .expect("logm scalar multiple"),
            )]
        );
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 1.0
                            }),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("complex diagonal"),
                )],
                1,
            )
            .expect("logm complex"),
            vec![Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.0,
                            imag: 1.570_796_326_795,
                        }),
                        Value::Scalar(0.0),
                        Value::Scalar(0.0),
                        Value::Scalar(1.386_294_361_12),
                    ],
                )
                .expect("logm complex result"),
            )]
        );
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty logm")
                )],
                1,
            )
            .expect("empty logm one output"),
            vec![Value::Matrix(
                MatrixValue::new(0, 0, Vec::new()).expect("empty logm result")
            )]
        );
        assert_eq!(
            builtin_logm(
                &[Value::Matrix(
                    MatrixValue::new(0, 0, Vec::new()).expect("empty logm residual")
                )],
                2,
            )
            .expect("empty logm two outputs"),
            vec![
                Value::Matrix(MatrixValue::new(0, 0, Vec::new()).expect("empty logm matrix")),
                Value::Scalar(0.0),
            ]
        );
    }

