    #[test]
    fn degree_angle_helpers_support_current_numeric_forms() {
        assert_eq!(
            builtin_deg2rad(&[Value::Scalar(180.0)]).expect("deg2rad scalar"),
            Value::Scalar(std::f64::consts::PI)
        );
        assert_eq!(
            builtin_rad2deg(&[Value::Scalar(std::f64::consts::PI)]).expect("rad2deg scalar"),
            Value::Scalar(180.0)
        );
        assert_eq!(
            builtin_unwrap(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(3.5), Value::Scalar(0.0),]
                )
                .expect("unwrap row input"),
            )])
            .expect("unwrap row"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(3.5 - 2.0 * std::f64::consts::PI),
                        Value::Scalar(0.0),
                    ],
                )
                .expect("unwrap row output")
            )
        );
        assert_eq!(
            builtin_mag2db(&[Value::Scalar(10.0)]).expect("mag2db"),
            Value::Scalar(20.0)
        );
        assert_eq!(
            builtin_db2mag(&[Value::Scalar(20.0)]).expect("db2mag"),
            Value::Scalar(10.0)
        );
        assert_eq!(
            builtin_pow2db(&[Value::Scalar(100.0)]).expect("pow2db"),
            Value::Scalar(20.0)
        );
        assert_eq!(
            builtin_db2pow(&[Value::Scalar(20.0)]).expect("db2pow"),
            Value::Scalar(100.0)
        );
        assert_eq!(
            builtin_sind(&[Value::Scalar(30.0)]).expect("sind scalar"),
            Value::Scalar(0.5)
        );
        assert_eq!(
            builtin_cosd(&[Value::Scalar(60.0)]).expect("cosd scalar"),
            Value::Scalar(0.5)
        );
        assert_eq!(
            builtin_tand(&[Value::Scalar(45.0)]).expect("tand scalar"),
            Value::Scalar(1.0)
        );
        assert_eq!(
            builtin_asind(&[Value::Scalar(0.5)]).expect("asind scalar"),
            Value::Scalar(30.0)
        );
        assert_eq!(
            builtin_acosd(&[Value::Scalar(0.5)]).expect("acosd scalar"),
            Value::Scalar(60.0)
        );
        assert_eq!(
            builtin_atand(&[Value::Scalar(1.0)]).expect("atand scalar"),
            Value::Scalar(45.0)
        );
        assert_eq!(
            builtin_atan2(&[Value::Scalar(1.0), Value::Scalar(1.0)]).expect("atan2 scalar"),
            Value::Scalar(std::f64::consts::FRAC_PI_4)
        );
        assert_eq!(
            builtin_atan2d(&[Value::Scalar(1.0), Value::Scalar(1.0)]).expect("atan2d scalar"),
            Value::Scalar(45.0)
        );
        assert_eq!(
            builtin_rad2deg(&[Value::Complex(ComplexValue {
                real: 0.0,
                imag: std::f64::consts::PI,
            })])
            .expect("rad2deg complex"),
            Value::Complex(ComplexValue {
                real: 0.0,
                imag: 180.0,
            })
        );
        assert_eq!(
            builtin_sind(&[Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(30.0), Value::Scalar(90.0)],
                )
                .expect("row"),
            )])
            .expect("sind matrix"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(0.5), Value::Scalar(1.0)],
                )
                .expect("sind matrix result"),
            )
        );
        assert_eq!(
            builtin_atan2(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(-1.0)],
                    )
                    .expect("y row"),
                ),
                Value::Scalar(1.0),
            ])
            .expect("atan2 scalar expansion"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(std::f64::consts::FRAC_PI_4),
                        Value::Scalar(-std::f64::consts::FRAC_PI_4),
                    ],
                )
                .expect("atan2 result"),
            )
        );
    }

    #[test]
    fn rounding_and_remainder_helpers_support_current_numeric_forms() {
        assert_eq!(
            builtin_floor(&[Value::Scalar(-1.9)]).expect("floor scalar"),
            Value::Scalar(-2.0)
        );
        assert_eq!(
            builtin_ceil(&[Value::Scalar(-1.9)]).expect("ceil scalar"),
            Value::Scalar(-1.0)
        );
        assert_eq!(
            builtin_fix(&[Value::Complex(ComplexValue {
                real: 1.4,
                imag: 2.3
            })])
            .expect("fix complex"),
            Value::Complex(ComplexValue {
                real: 1.0,
                imag: 2.0
            })
        );
        assert_eq!(
            builtin_round(&[Value::Scalar(-3.5)]).expect("round scalar"),
            Value::Scalar(-4.0)
        );
        assert_eq!(
            builtin_sign(&[Value::Complex(ComplexValue {
                real: 4.0,
                imag: -3.0
            })])
            .expect("sign complex"),
            Value::Complex(ComplexValue {
                real: 0.8,
                imag: -0.6,
            })
        );
        assert_eq!(
            builtin_mod(&[Value::Scalar(-4.0), Value::Scalar(3.0)]).expect("mod scalar"),
            Value::Scalar(2.0)
        );
        assert_eq!(
            builtin_rem(&[Value::Scalar(-4.0), Value::Scalar(3.0)]).expect("rem scalar"),
            Value::Scalar(-1.0)
        );
        assert_eq!(
            builtin_hypot(&[Value::Scalar(3.0), Value::Scalar(4.0)]).expect("hypot scalar"),
            Value::Scalar(5.0)
        );
        assert_eq!(
            builtin_hypot(&[
                Value::Complex(ComplexValue {
                    real: 3.0,
                    imag: 4.0
                }),
                Value::Scalar(4.0),
            ])
            .expect("hypot complex"),
            Value::Scalar(6.403_124_237_432_848_5)
        );
    }

    #[test]
    fn floating_point_helpers_support_current_numeric_forms() {
        assert_eq!(
            builtin_isfinite(&[Value::Complex(ComplexValue {
                real: 1.0,
                imag: 2.0
            })])
            .expect("isfinite complex"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_isinf(&[Value::Scalar(f64::INFINITY)]).expect("isinf scalar"),
            Value::Logical(true)
        );
        assert_eq!(
            builtin_isnan(&[Value::Scalar(f64::NAN)]).expect("isnan scalar"),
            Value::Logical(true)
        );
        assert_eq!(builtin_eps(&[]).expect("eps"), Value::Scalar(f64::EPSILON));
        assert_eq!(
            builtin_eps(&[Value::Scalar(10.0)]).expect("eps scalar"),
            Value::Scalar(0.000_000_000_000_001_776_356_839_400_250_5)
        );
        assert_eq!(
            builtin_log10(&[Value::Scalar(100.0)]).expect("log10 scalar"),
            Value::Scalar(2.0)
        );
        assert_eq!(
            builtin_log2(&[Value::Scalar(8.0)], 1).expect("log2 scalar"),
            vec![Value::Scalar(3.0)]
        );
        assert_eq!(
            builtin_log2(&[Value::Scalar(3.0)], 2).expect("log2 two outputs"),
            vec![Value::Scalar(0.75), Value::Scalar(2.0)]
        );
        assert_eq!(
            builtin_pow2(&[Value::Scalar(4.0)]).expect("pow2 exponent"),
            Value::Scalar(16.0)
        );
        assert_eq!(
            builtin_pow2(&[Value::Scalar(0.75), Value::Scalar(2.0)]).expect("pow2 two args"),
            Value::Scalar(3.0)
        );
    }

