    #[test]
    fn interp1_supports_current_linear_and_nearest_forms() {
        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(0.5), Value::Scalar(1.5), Value::Scalar(2.5),],
                    )
                    .expect("xq"),
                ),
            ])
            .expect("linear interp1"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(5.0), Value::Scalar(15.0), Value::Scalar(25.0),],
                )
                .expect("linear result"),
            )
        );

        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.5), Value::Scalar(2.5)])
                        .expect("xq"),
                ),
            ])
            .expect("default x interp1"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(5.0), Value::Scalar(15.0)])
                    .expect("default x result"),
            )
        );

        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.49),
                            Value::Scalar(0.51),
                            Value::Scalar(2.49),
                            Value::Scalar(2.51),
                        ],
                    )
                    .expect("xq"),
                ),
                Value::String("nearest".to_string()),
            ])
            .expect("nearest interp1"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    4,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(10.0),
                        Value::Scalar(20.0),
                        Value::Scalar(30.0),
                    ],
                )
                .expect("nearest result"),
            )
        );

        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(3.0),
                            Value::Scalar(2.0),
                            Value::Scalar(1.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("descending x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(30.0),
                            Value::Scalar(20.0),
                            Value::Scalar(10.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("descending v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(2.5), Value::Scalar(0.5)])
                        .expect("descending xq"),
                ),
            ])
            .expect("descending interp1"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(25.0), Value::Scalar(5.0)])
                    .expect("descending result"),
            )
        );
        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(-1.0), Value::Scalar(0.5), Value::Scalar(3.5)],
                    )
                    .expect("xq"),
                ),
                Value::String("linear".to_string()),
                Value::String("extrap".to_string()),
            ])
            .expect("linear extrap interp1"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(-10.0),
                        Value::Scalar(5.0),
                        Value::Scalar(35.0)
                    ],
                )
                .expect("linear extrap result"),
            )
        );
        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("default-x v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(0.5), Value::Scalar(3.5)])
                        .expect("default-x xq"),
                ),
                Value::String("extrap".to_string()),
            ])
            .expect("default x extrap interp1"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(-5.0), Value::Scalar(25.0)])
                    .expect("default x extrap result"),
            )
        );
        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(1.0),
                            Value::Scalar(2.0),
                            Value::Scalar(3.0),
                        ],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        4,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(-1.0), Value::Scalar(0.5), Value::Scalar(3.5)],
                    )
                    .expect("xq"),
                ),
                Value::String("nearest".to_string()),
                Value::Scalar(-99.0),
            ])
            .expect("nearest fill interp1"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![
                        Value::Scalar(-99.0),
                        Value::Scalar(0.0),
                        Value::Scalar(-99.0)
                    ],
                )
                .expect("nearest fill result"),
            )
        );
    }

    #[test]
    fn interp1_preserves_query_shape_and_returns_nan_outside_range() {
        let result = builtin_interp1(&[
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(2.0)],
                )
                .expect("x"),
            ),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(4.0)],
                )
                .expect("v"),
            ),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(-1.0),
                        Value::Scalar(0.5),
                        Value::Scalar(1.5),
                        Value::Scalar(3.0),
                    ],
                )
                .expect("xq"),
            ),
        ])
        .expect("shape interp1");

        let Value::Matrix(matrix) = result else {
            panic!("expected matrix result");
        };
        assert_eq!(matrix.rows, 2);
        assert_eq!(matrix.cols, 2);
        assert!(matrix.elements[0].as_scalar().expect("nan slot").is_nan());
        assert_eq!(matrix.elements[1].as_scalar().expect("second slot"), 0.5);
        assert_eq!(matrix.elements[2].as_scalar().expect("third slot"), 2.5);
        assert!(matrix.elements[3].as_scalar().expect("nan slot").is_nan());
    }

    #[test]
    fn interp1_supports_multiseries_complex_and_nd_queries() {
        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        3,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(100.0),
                            Value::Scalar(10.0),
                            Value::Scalar(110.0),
                            Value::Scalar(20.0),
                            Value::Scalar(120.0),
                        ],
                    )
                    .expect("interp1 multiseries v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.5), Value::Scalar(2.5)])
                        .expect("interp1 multiseries xq"),
                ),
            ])
            .expect("interp1 multiseries"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(5.0),
                        Value::Scalar(105.0),
                        Value::Scalar(15.0),
                        Value::Scalar(115.0),
                    ],
                )
                .expect("interp1 multiseries result"),
            )
        );

        assert_eq!(
            builtin_interp1(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(2.0)],
                    )
                    .expect("interp1 complex x"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![
                            Value::Complex(ComplexValue {
                                real: 0.0,
                                imag: 1.0,
                            }),
                            Value::Complex(ComplexValue {
                                real: 10.0,
                                imag: 2.0,
                            }),
                            Value::Complex(ComplexValue {
                                real: 20.0,
                                imag: 4.0,
                            }),
                        ],
                    )
                    .expect("interp1 complex v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(0.5), Value::Scalar(1.5)])
                        .expect("interp1 complex xq"),
                ),
            ])
            .expect("interp1 complex"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 5.0,
                            imag: 1.5,
                        }),
                        Value::Complex(ComplexValue {
                            real: 15.0,
                            imag: 3.0,
                        }),
                    ],
                )
                .expect("interp1 complex result"),
            )
        );

        let result = builtin_interp1(&[
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(1.0), Value::Scalar(2.0)],
                )
                .expect("interp1 nd x"),
            ),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(10.0), Value::Scalar(20.0)],
                )
                .expect("interp1 nd v"),
            ),
            Value::Matrix(
                MatrixValue::with_dimensions(
                    2,
                    2,
                    vec![2, 1, 2],
                    vec![
                        Value::Scalar(0.5),
                        Value::Scalar(1.5),
                        Value::Scalar(0.25),
                        Value::Scalar(1.75),
                    ],
                )
                .expect("interp1 nd xq"),
            ),
        ])
        .expect("interp1 nd query shape");

        let Value::Matrix(matrix) = result else {
            panic!("expected matrix result");
        };
        assert_eq!(matrix.dims(), &[2, 1, 2]);
        assert_eq!(matrix.elements[0].as_scalar().expect("first nd slot"), 5.0);
        assert_eq!(
            matrix.elements[1].as_scalar().expect("second nd slot"),
            15.0
        );
        assert_eq!(matrix.elements[2].as_scalar().expect("third nd slot"), 2.5);
        assert_eq!(
            matrix.elements[3].as_scalar().expect("fourth nd slot"),
            17.5
        );
    }

    #[test]
    fn interp2_supports_current_linear_and_nearest_forms() {
        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.5),
                            Value::Scalar(2.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.25),
                        ],
                    )
                    .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.5),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("yq"),
                ),
            ])
            .expect("default-grid interp2"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(5.0),
                        Value::Scalar(10.0),
                        Value::Scalar(10.0),
                        Value::Scalar(22.5),
                    ],
                )
                .expect("default-grid result"),
            )
        );

        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(0.0), Value::Scalar(2.0), Value::Scalar(4.0),],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(0.0), Value::Scalar(10.0)])
                        .expect("y"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(100.0),
                            Value::Scalar(110.0),
                            Value::Scalar(120.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(3.0)])
                        .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(5.0), Value::Scalar(5.0)])
                        .expect("yq"),
                ),
            ])
            .expect("vector-grid interp2"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(55.0), Value::Scalar(65.0)])
                    .expect("vector-grid result"),
            )
        );

        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(4.0), Value::Scalar(2.0), Value::Scalar(0.0),],
                    )
                    .expect("x"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(10.0), Value::Scalar(0.0)])
                        .expect("y"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(120.0),
                            Value::Scalar(110.0),
                            Value::Scalar(100.0),
                            Value::Scalar(20.0),
                            Value::Scalar(10.0),
                            Value::Scalar(0.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(3.0)])
                        .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(5.0), Value::Scalar(5.0)])
                        .expect("yq"),
                ),
            ])
            .expect("descending-grid interp2"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(55.0), Value::Scalar(65.0)])
                    .expect("descending-grid result"),
            )
        );

        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(1.49), Value::Scalar(1.51), Value::Scalar(2.0),],
                    )
                    .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        1,
                        3,
                        vec![Value::Scalar(1.49), Value::Scalar(1.51), Value::Scalar(2.0),],
                    )
                    .expect("yq"),
                ),
                Value::String("nearest".to_string()),
            ])
            .expect("nearest interp2"),
            Value::Matrix(
                MatrixValue::new(
                    1,
                    3,
                    vec![Value::Scalar(0.0), Value::Scalar(30.0), Value::Scalar(30.0),],
                )
                .expect("nearest result"),
            )
        );
        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.5),
                            Value::Scalar(1.5),
                            Value::Scalar(2.0),
                            Value::Scalar(2.5),
                        ],
                    )
                    .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(1.0),
                            Value::Scalar(1.0),
                            Value::Scalar(1.5),
                            Value::Scalar(2.0),
                        ],
                    )
                    .expect("yq"),
                ),
                Value::String("linear".to_string()),
                Value::Scalar(-1.0),
            ])
            .expect("interp2 fill extrapolation"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(-1.0),
                        Value::Scalar(5.0),
                        Value::Scalar(20.0),
                        Value::Scalar(-1.0),
                    ],
                )
                .expect("interp2 fill result"),
            )
        );
    }

    #[test]
    fn interp2_supports_matrix_grids_scalar_expansion_and_nan_outside_range() {
        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(4.0),
                            Value::Scalar(0.0),
                            Value::Scalar(2.0),
                            Value::Scalar(4.0),
                        ],
                    )
                    .expect("x grid"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(10.0),
                            Value::Scalar(10.0),
                        ],
                    )
                    .expect("y grid"),
                ),
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(100.0),
                            Value::Scalar(110.0),
                            Value::Scalar(120.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(3.0)])
                        .expect("xq"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(5.0), Value::Scalar(5.0)])
                        .expect("yq"),
                ),
            ])
            .expect("matrix-grid interp2"),
            Value::Matrix(
                MatrixValue::new(1, 2, vec![Value::Scalar(55.0), Value::Scalar(65.0)])
                    .expect("matrix-grid result"),
            )
        );

        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        2,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(30.0),
                        ],
                    )
                    .expect("v"),
                ),
                Value::Scalar(1.5),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                        .expect("yq"),
                ),
            ])
            .expect("scalar-expanded interp2"),
            Value::Matrix(
                MatrixValue::new(2, 1, vec![Value::Scalar(5.0), Value::Scalar(25.0)])
                    .expect("scalar-expanded result"),
            )
        );

        let result = builtin_interp2(&[
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(10.0),
                        Value::Scalar(20.0),
                        Value::Scalar(30.0),
                    ],
                )
                .expect("v"),
            ),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.5),
                        Value::Scalar(3.0),
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("xq"),
            ),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(1.5),
                        Value::Scalar(1.0),
                        Value::Scalar(3.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("yq"),
            ),
        ])
        .expect("nan interp2");

        let Value::Matrix(matrix) = result else {
            panic!("expected matrix result");
        };
        assert_eq!(matrix.rows, 2);
        assert_eq!(matrix.cols, 2);
        assert_eq!(matrix.get(0, 0).as_scalar().expect("first slot"), 15.0);
        assert!(matrix.get(0, 1).as_scalar().expect("nan slot").is_nan());
        assert!(matrix.get(1, 0).as_scalar().expect("nan slot").is_nan());
        assert_eq!(matrix.get(1, 1).as_scalar().expect("last slot"), 30.0);
    }

    #[test]
    fn interp2_supports_grid_vector_queries_complex_values_and_nd_shapes() {
        assert_eq!(
            builtin_interp2(&[
                Value::Matrix(
                    MatrixValue::new(
                        2,
                        3,
                        vec![
                            Value::Scalar(0.0),
                            Value::Scalar(10.0),
                            Value::Scalar(20.0),
                            Value::Scalar(100.0),
                            Value::Scalar(110.0),
                            Value::Scalar(120.0),
                        ],
                    )
                    .expect("interp2 grid-vector v"),
                ),
                Value::Matrix(
                    MatrixValue::new(1, 2, vec![Value::Scalar(1.0), Value::Scalar(3.0)])
                        .expect("interp2 xq row"),
                ),
                Value::Matrix(
                    MatrixValue::new(2, 1, vec![Value::Scalar(1.0), Value::Scalar(2.0)])
                        .expect("interp2 yq col"),
                ),
            ])
            .expect("interp2 grid-vector queries"),
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Scalar(0.0),
                        Value::Scalar(20.0),
                        Value::Scalar(100.0),
                        Value::Scalar(120.0),
                    ],
                )
                .expect("interp2 grid-vector result"),
            )
        );

        let result = builtin_interp2(&[
            Value::Matrix(
                MatrixValue::new(
                    2,
                    2,
                    vec![
                        Value::Complex(ComplexValue {
                            real: 0.0,
                            imag: 0.0,
                        }),
                        Value::Complex(ComplexValue {
                            real: 10.0,
                            imag: 10.0,
                        }),
                        Value::Complex(ComplexValue {
                            real: 20.0,
                            imag: 20.0,
                        }),
                        Value::Complex(ComplexValue {
                            real: 30.0,
                            imag: 30.0,
                        }),
                    ],
                )
                .expect("interp2 complex v"),
            ),
            Value::Matrix(
                MatrixValue::with_dimensions(
                    2,
                    2,
                    vec![2, 1, 2],
                    vec![
                        Value::Scalar(1.5),
                        Value::Scalar(3.0),
                        Value::Scalar(1.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("interp2 complex xq"),
            ),
            Value::Matrix(
                MatrixValue::with_dimensions(
                    2,
                    2,
                    vec![2, 1, 2],
                    vec![
                        Value::Scalar(1.5),
                        Value::Scalar(1.0),
                        Value::Scalar(3.0),
                        Value::Scalar(2.0),
                    ],
                )
                .expect("interp2 complex yq"),
            ),
            Value::String("linear".to_string()),
            Value::Complex(ComplexValue {
                real: 9.0,
                imag: 4.0,
            }),
        ])
        .expect("interp2 complex nd queries");

        let Value::Matrix(matrix) = result else {
            panic!("expected matrix result");
        };
        assert_eq!(matrix.dims(), &[2, 1, 2]);
        assert_eq!(
            matrix.elements[0],
            Value::Complex(ComplexValue {
                real: 15.0,
                imag: 15.0,
            })
        );
        assert_eq!(
            matrix.elements[1],
            Value::Complex(ComplexValue {
                real: 9.0,
                imag: 4.0,
            })
        );
        assert_eq!(
            matrix.elements[2],
            Value::Complex(ComplexValue {
                real: 9.0,
                imag: 4.0,
            })
        );
        assert_eq!(
            matrix.elements[3],
            Value::Complex(ComplexValue {
                real: 30.0,
                imag: 30.0,
            })
        );
    }

